  FUNCTION F_EXISTEICMSPARTILHA(pi_nCodCli      IN NUMBER,
                                pi_vCodFilial   IN VARCHAR2,
                                pi_vCodFilialNf IN VARCHAR2,
                                pi_vEstEnt      IN VARCHAR2) -- DDVENDAS-33718
  RETURN BOOLEAN IS
    vvCodFilial       PCFILIAL.CODIGO%TYPE;
    vvPartilha        VARCHAR2(1);
  BEGIN

    -- Código Filial
    IF (pi_vCodFilialNf IS NOT NULL) THEN
      vvCodFilial := pi_vCodFilialNf;
    ELSE
      vvCodFilial := pi_vCodFilial;
    END IF;

    -- Pesquisa Dados do Cliente e Filial
    BEGIN
      SELECT CASE WHEN (NVL(PCCLIENT.CONSUMIDORFINAL,'N') = 'S')                          AND
                       (NVL(PCCLIENT.CONTRIBUINTE,'N')    = 'N')                          AND
                       (NVL(NVL(pi_vEstEnt,PCCLIENT.ESTENT),' ') <> NVL(PCFILIAL.UF,' ')) THEN -- DDVENDAS-33718
                'S'
              ELSE
                'N'
              END PARTILHA
        INTO vvPartilha
        FROM PCCLIENT
           , PCFILIAL
       WHERE (PCCLIENT.CODCLI = pi_nCodCli)
         AND (PCFILIAL.CODIGO = vvCodFilial);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvPartilha := 'N';
    END;

    -- Retorno
    RETURN (NVL(vvPartilha,'N') = 'S');

  END F_EXISTEICMSPARTILHA;

  ------------------------------------------------------------------------------
  -- Função para Verificar se Usa Regra Específica de Medicamentos --
  -- 4348.097738.2015
  -------------------------------------------------------------------
  FUNCTION FUSA_REGRA_MEDICAMENTOS(pi_vCodFilial IN VARCHAR2,
                                   pi_vNome      IN VARCHAR2)
  RETURN VARCHAR2 IS
    vvRetUsaRegraMedicamentos VARCHAR2(1);
  BEGIN
    -- Verifica se usa regra
    BEGIN
      EXECUTE IMMEDIATE ' SELECT VALOR FROM PCREGRASEXCECAOMED WHERE NOME = ' || '''' || pi_vNome || '''' || ' AND CODFILIAL = ' || '''' || pi_vCodFilial || ''''
                   INTO vvRetUsaRegraMedicamentos;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvRetUsaRegraMedicamentos := 'N';
      WHEN OTHERS THEN
        vvRetUsaRegraMedicamentos := 'N';
    END;
    -- Retorno
    RETURN vvRetUsaRegraMedicamentos;
  END FUSA_REGRA_MEDICAMENTOS;

  ------------------------------------------------------------------------------
  -- Função para retornar o Parâmetro da Integradora
  -- MED-861
  -------------------------------------------------------------------
  FUNCTION FOBTEM_PARAM_INTEGRADORA(pi_nIntegradora  IN NUMBER,
                                    pi_vNome         IN VARCHAR2,
                                    pi_vValorDefault IN VARCHAR2)
  RETURN VARCHAR2 IS
    vvRetParamIntegradora PCPARAMINTEGRADORAMED.VALOR%TYPE;
  BEGIN

    -- Pesquisa Parâmetro
    BEGIN
      SELECT NVL(PCPARAMINTEGRADORAMED.VALOR,pi_vValorDefault)
        INTO vvRetParamIntegradora
        FROM PCPARAMINTEGRADORAMED
       WHERE (PCPARAMINTEGRADORAMED.NOME        = pi_vNome)
         AND (PCPARAMINTEGRADORAMED.INTEGRADORA = pi_nIntegradora);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vvRetParamIntegradora := pi_vValorDefault;
    END;

    -- Retorno
    RETURN vvRetParamIntegradora;

  END FOBTEM_PARAM_INTEGRADORA;

  ------------------------------------------------------------------------------
  -- Função para retornar o Tipo de Importação Venda para Alvará
  -- DDVENDAS-37313
  --------------------------------------------------------------
  FUNCTION F_SOBREPOSICAOBLOQUEIOALVARA(p_TIPOIMPORTACAOVENDA          IN VARCHAR2,
                                        p_SOBREPOSICAOBLOQUEIOALVARA IN VARCHAR2)
  RETURN VARCHAR2 IS
    vvRetNovoTipoImportacaoVenda PCPARAMINTEGRADORAMED.VALOR%TYPE;
  BEGIN
      
    vvRetNovoTipoImportacaoVenda := p_TIPOIMPORTACAOVENDA;
    
    IF (p_TIPOIMPORTACAOVENDA= 'BP') AND
       (p_SOBREPOSICAOBLOQUEIOALVARA IN ('RP','RI')) THEN
    
      vvRetNovoTipoImportacaoVenda := p_SOBREPOSICAOBLOQUEIOALVARA;
    
    END IF;

    RETURN vvRetNovoTipoImportacaoVenda;

  END F_SOBREPOSICAOBLOQUEIOALVARA;

  procedure proc_registralog(p_numped        in pcpedc.numped%type,
                             p_numpedrca     in pcpedc.numpedrca%type,
                             p_codprod       in pcprodut.codprod%type,
                             p_codauxiliar   in pcpedi.codauxiliar%type,
                             p_cgcent        in pcclient.cgcent%type,
                             p_codigocotacao in pccota.codcotacao%type,
                             p_numrecadofv   in pcrecfunc.numrecadofv%type,
                             p_numcontagem   in pcgondolac.numcontagem%type,
                             p_codusur       in pcpedc.codusur%type,
                             p_data          in date,
                             p_cancelada     in varchar2,
                             p_tiporeg       in varchar2,
                            -- 1 = generico / -1 = Clientes /2 = cabecalho / 3 = itens /4 = Contatos
                             p_erro          in varchar2,
                             p_linhareg      in number,
                             p_numseqifv     in number) is -- DDMEDICA-198
  begin
    vngcontador := vngcontador + 1;
    gvetregistralog(vngcontador).numped        := p_numped;
    gvetregistralog(vngcontador).numpedrca     := p_numpedrca;
    gvetregistralog(vngcontador).codprod       := p_codprod;
    gvetregistralog(vngcontador).codauxiliar   := p_codauxiliar;
    gvetregistralog(vngcontador).cgcent        := p_cgcent;
    gvetregistralog(vngcontador).codigocotacao := p_codigocotacao;
    gvetregistralog(vngcontador).numrecadofv   := p_numrecadofv;
    gvetregistralog(vngcontador).numcontagem   := p_numcontagem;
    gvetregistralog(vngcontador).codusur       := p_codusur;
    gvetregistralog(vngcontador).data          := p_data;
    gvetregistralog(vngcontador).cancelada     := p_cancelada;
    gvetregistralog(vngcontador).tiporeg       := p_tiporeg;
    gvetregistralog(vngcontador).erro          := p_erro;
    gvetregistralog(vngcontador).linhareg      := p_linhareg;
    gvetregistralog(vngcontador).numseqifv     := p_numseqifv;

  end proc_registralog;

  procedure proc_registralogbloqueio(p_numpedrca         in pcpedcfv.numpedrca%type,
                                     p_codusur           in pcpedcfv.codusur%type,
                                     p_cgccli            in pcpedcfv.cgccli%type,
                                     p_dtaberturapedpalm in pcpedcfv.dtaberturapedpalm%type,
                                     p_codmotivo         in pcbloqueiospedido.codmotivo%type,
                                     p_codmotbloqueio    in pcbloqueiospedido.codmotivo%type,
                                     p_motivo            in pcbloqueiospedido.motivo%type) is
    idxBloqueio INTEGER;
  begin
    idxBloqueio := NVL(gvetregistrabloqueio.COUNT,0) + 1;
    gvetregistrabloqueio(idxBloqueio).numpedrca         := p_numpedrca;
    gvetregistrabloqueio(idxBloqueio).codusur           := p_codusur;
    gvetregistrabloqueio(idxBloqueio).cgccli            := p_cgccli;
    gvetregistrabloqueio(idxBloqueio).dtaberturapedpalm := p_dtaberturapedpalm;
    gvetregistrabloqueio(idxBloqueio).codmotivo         := p_codmotivo;
    gvetregistrabloqueio(idxBloqueio).codmotbloqueio    := p_codmotbloqueio;
    gvetregistrabloqueio(idxBloqueio).motivo            := p_motivo;
  end proc_registralogbloqueio;

  procedure proc_lerparametros(p_existerro in out boolean) is

  begin
    select * into gregpcconsum from pcconsum;
    gregpcconsum.codfilialfv      := NVL(gregpcconsum.codfilialfv, '1');
    gregpcconsum.numcasasdecvenda := NVL(gregpcconsum.numcasasdecvenda, 2);


  exception
    when others then
      p_existerro := true;
      proc_registralog(null,
                       null,
                       null,
                       null,
                       null,
                       null,
                       null,
                       null,
                       null,
                       null,
                       null,
                       '1',
                       'Erro ao ler parametros#;' || sqlcode || '-' ||
                       DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';',
                       null,
                       null);


  end proc_lerparametros;

PROCEDURE proc_processarleitura(p_existerro   IN OUT BOOLEAN,
                                p_tipoleitura IN NUMBER,
                                p_tipofv      IN VARCHAR2,
                                p_datainicial IN DATE,
                                p_datafinal   IN DATE,
                                p_codfilial   IN VARCHAR2,
                                p_codusur     IN NUMBER default null,
                                p_numpedrca   IN NUMBER default null,
                                p_integradora IN NUMBER default null -- DDMEDICA-585
                                ) IS
    vblercabok         boolean;
    vbleritemok        boolean;
    vblerindcok        boolean;
    vblerindiok        boolean;
    vncontped          integer;
    vncontitem         integer;
    vncontcombo        integer; -- HIS.03536.2016
    vncontorigempreco  integer;
    vncontindc         integer;
    vncontindi         integer;
    vncontorigemcomiss integer;
    vncontorigemdesc   integer;

    vddatainicial      date;
    vddatafinal        date;

    vvExistePedPCPEDC  VARCHAR2(200); -- 4348.097738.2015

    TYPE TRecPromocaoCab         IS RECORD(
         vbPesquisarPromocao      BOOLEAN,
         vvTipoPromocao           PCPROMOCAOMED.TIPOPROMOCAO%TYPE,
         vnCodPromocaoTipoCliente PCPROMOCAOMED.CODPROMOCAOMED%TYPE,
         vnCodPromocaoOutrosTipos PCPROMOCAOMED.CODPROMOCAOMED%TYPE);
    vrPromocaoCab                 TRecPromocaoCab;
    vrLimpaPromocaoCab            TRecPromocaoCab;

    -- MED-1600
    vbUsaSemaforoImportacaoFv     BOOLEAN;
    vbPodeImportarPedido          BOOLEAN;
    vvMsgLogProc                  VARCHAR2(2000);
    -- DDMEDICA-585
    vnIntegradora                 PCINTEGRADORA.INTEGRADORA%TYPE;

    -- DDMEDICA-198
    TYPE TTListaProdutosRepetidos IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
    vtListaProdutosRepetidos      TTListaProdutosRepetidos;
    
    vvVersionamentoPkg            VARCHAR2(20);

  BEGIN
  
    vvVersionamentoPkg := F_OBTER_VERSIONAMENTO;
  
    /*
       Campo IMPORTADO:
       Valor 0 = registro bloqueado.
       Valor 1 = registro liberado para leitura.
       Valor 2 = registro lido.
       Valor 3 = registro liberado para leitura novamente (rejeitado anteriormente).
    */

    -- Ajusta a faixa de datas conforme parametro.
    IF p_tipoleitura = 1
    THEN
      vddatainicial := TRUNC(SYSDATE) - 365;
      vddatafinal   := TRUNC(SYSDATE);
    ELSE
      vddatainicial := p_datainicial;
      vddatafinal   := p_datafinal;
    END IF;

    vncontped         := 0;
    vncontitem        := 0;
    vncontcombo       := 0; -- HIS.03536.2016
    vncontorigempreco := 0;
    vncontindc        := 0;
    vncontindi        := 0;
    vncontorigemcomiss := 0;
    vncontorigemdesc   := 0;


    vngdatainicio     := vddatainicial;
    vngdatafim        := vddatafinal;


    -- Semáforo na Importação do Força de Vendas - MED-1600
    vbUsaSemaforoImportacaoFv := FALSE;
    IF (FUSA_REGRA_MEDICAMENTOS('99','USASEMAFOROIMPORTACAOFV') = 'S') THEN
      vbUsaSemaforoImportacaoFv := TRUE;
    END IF;


   --Pedidos
    FOR cr_pedcab IN (SELECT  numpedrca,
                              codusur,
                              cgccli,
                              dtaberturapedpalm,
                              dtfechamentopedpalm,
                              numpedcli,
                              dtentrega,
                              codfilial,
                              codfilialnf,
                              codfilialretira,
                              vlfrete,
                              codcob,
                              codplpag,
                              condvenda,
                              obs1,
                              obs2,
                              obsentrega1,
                              obsentrega2,
                              obsentrega3,
                              obsentrega4,
                              fretedespacho,
                              freteredespacho,
                              codfornecfrete,
                              prazo1  parcela1,
                              prazo2  parcela2,
                              prazo3  parcela3,
                              prazo4  parcela4,
                              prazo5  parcela5,
                              prazo6  parcela6,
                              prazo7  parcela7,
                              prazo8  parcela8,
                              prazo9  parcela9,
                              prazo10 parcela10,
                              prazo11 parcela11,
                              prazo12 parcela12,
                              origemped,
                              numpedorigem,
                              codclinf,
                              tipodocumento,
                              contaordem,
                              codcli,
                              codclitv8,
                              codplpagetico,
                              codplpaggenerico,
                              tipofv,
                              tipoprioridadeentrega,
                              localdesembaraco,
                              ufdesembaraco,
                              numpedtv1,
                              agrupamento,
                              codbnf,
                              custobonificacao,
                              codfornecbonific,
                              vlentrada,
                              orcamento,
                              numpedvanxml,
                              codendentcli,
                              codclirecebedor,
                              numregiaobroker,
                              codusur2,
                              codusur3,
                              codusur4,
                              codpromocaomed,
                              aplicarperredcomiss,
                              gravarpedidocomobloqueado,
                              ROWNUM AS linha,
                              -- INICIO: HIS.04557.2015 - ICMS Partilha
                              NVL(precocompartilha, 'N') precocompartilha,
                              -- FIM: HIS.04557.2015 - ICMS Partilha
                              NVL(restringirpromocaomed,'N') restringirpromocaomed,
                              vlfreteoutrasdesp,
                              codemitente --DDMEDICA-4173
                            , descintermediador -- DDMEDICA-6201  
                            , cnpjintermediador -- DDMEDICA-6201  
                        FROM pcpedcfv
                       WHERE importado = p_tipoleitura
                         AND (NVL(trunc(dtinclusao),TRUNC(SYSDATE)) BETWEEN vddatainicial AND vddatafinal)
                         AND  nvl(tipofv,'FV' ) = p_tipofv
                         AND ((nvl(codfilial,'99') = nvl(p_codfilial,'99') or nvl(codfilial,'99') = '99') or (p_codfilial = '99'))
                         AND  (codusur = p_codusur or p_codusur is null)
                         AND (numpedrca = p_numpedrca or p_numpedrca is null ) ) LOOP

      BEGIN

        vblercabok := FALSE;

        --------------------------------------------------------------------------------
        -- MED-1600 - SEMÁFORO DE IMPORTAÇÃO DO PEDIDO DO FORÇA DE VENDAS
        --------------------------------------------------------------------------------
        vbPodeImportarPedido := TRUE;
        vvMsgLogProc         := ' ';
        IF (vbUsaSemaforoImportacaoFv) THEN
          -- Se não permite importar o Pedido neste momento
          IF (INTEGRADORACOMPLE_MED.PERMITE_IMPORTAR_PEDIDO_FV(cr_pedcab.numpedrca,
                                                               cr_pedcab.codusur,
                                                               cr_pedcab.cgccli,
                                                               cr_pedcab.dtaberturapedpalm) = 'N') THEN
            vbPodeImportarPedido := FALSE;
            vvMsgLogProc         := vvMsgLogProc || ' Validação FV: Não pode importar pedido';
          ELSE
            vvMsgLogProc         := vvMsgLogProc || ' Validação FV: Pode importar pedido';
          END IF;
        ELSE
          vvMsgLogProc := vvMsgLogProc || ' Sem Validação FV';
        END IF;
        -- Atualiza LOG PCPEDCFV
        UPDATE PCPEDCFV
           SET LOGPROCMED = LOGPROCMED || CHR(13) || 'PROCESSAMENTO EM: ' || TO_CHAR(SYSDATE,'DD/MM/YYYY HH24:MI:SS') || ' - ' || vvVersionamentoPkg || ' ####################################################################################################'
                                       || CHR(13) || CHR(13) -- MED-1895
                                       || vvMsgLogProc
             , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
         WHERE cgccli            = cr_pedcab.cgccli
           AND numpedrca         = cr_pedcab.numpedrca
           AND dtaberturapedpalm = cr_pedcab.dtaberturapedpalm
           AND codusur           = cr_pedcab.codusur;
        -- DDMEDICA-585 - Filtro de Integradora
        --------------------------------------------------------------------------------
        IF (NVL(p_integradora,0) > 0) THEN
          BEGIN
            SELECT INTEGRADORA
              INTO vnIntegradora
              FROM PCPEDRETORNO
             WHERE (NUMPEDRCA         = cr_pedcab.numpedrca)
               AND (CODUSUR           = cr_pedcab.codusur)
               AND (CGCCLI            = cr_pedcab.cgccli)
               AND (DTABERTURAPEDPALM = cr_pedcab.dtaberturapedpalm)
               AND (ROWNUM            = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vnIntegradora := NULL;
          END;
          -- Se não for a mesma integradora
          IF (NVL(p_integradora,0) <> NVL(vnIntegradora,0)) THEN
            vbPodeImportarPedido := FALSE;
          END IF;
        END IF;

        --------------------------------------------------------------------------------

        -- MED-1600 - SE PODE IMPORTAR O PEDIDO NESTE MOMENTO
        --------------------------------------------------------------------------------
        IF (vbPodeImportarPedido) THEN

          ------------------------------------------------------------------------------
          -- Função para Verificar se Usa Regra Específica de Medicamentos --
          -- 4348.097738.2015
          -------------------------------------------------------------------
          IF (NVL(p_tipofv,' ') IN ('OL','PE')) THEN
            vvExistePedPCPEDC := INTEGRADORACOMPLE_MED.FPEDIDO_EXISTE_PCPEDC(cr_pedcab.cgccli,
                                                                             cr_pedcab.numpedrca,
                                                                             cr_pedcab.dtaberturapedpalm,
                                                                             cr_pedcab.codusur);
          ELSE
            vvExistePedPCPEDC := 'N';
          END IF;

          -- Se o Pedido existe na PCPEDC
          IF (SUBSTR(vvExistePedPCPEDC,1,1) = 'S') THEN

            -- Atualiza PCPEDCFV para ignorar processamento já que Pedido existe na PCPEDC
            UPDATE PCPEDCFV
               SET IMPORTADO = 2
                 , OBSERVACAO_PC = OBSERVACAO_PC || '; ' || SUBSTR(vvExistePedPCPEDC,3,LENGTH(vvExistePedPCPEDC)-2)
                 , LOGPROCMED = LOGPROCMED || CHR(13) || 'PROCESSAMENTO EM: ' || TO_CHAR(SYSDATE,'DD/MM/YYYY HH24:MI:SS') || ' - ' || vvVersionamentoPkg || ' ####################################################################################################'
                                           || CHR(13) || CHR(13) -- MED-1895
                                           || SUBSTR(vvExistePedPCPEDC,3,LENGTH(vvExistePedPCPEDC)-2)
                 , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
             WHERE cgccli            = cr_pedcab.cgccli
               AND numpedrca         = cr_pedcab.numpedrca
               AND dtaberturapedpalm = cr_pedcab.dtaberturapedpalm
               AND codusur           = cr_pedcab.codusur;

          ------------------------------------------------------------------------------
          -- Se o Pedido não existe na PCPEDC
          ELSE

            gregpedido.numpedrca            := cr_pedcab.numpedrca;
            gregpedido.codusur              := cr_pedcab.codusur;
            gregpedido.cgccli               := cr_pedcab.cgccli;
            gregpedido.dtaberturapedpalm    := cr_pedcab.dtaberturapedpalm;
            gregpedido.dtfechamentopedpalm  := cr_pedcab.dtfechamentopedpalm;
            gregpedido.numpedcli            := cr_pedcab.numpedcli;
            gregpedido.dtentrega            := cr_pedcab.dtentrega;
            gregpedido.codfilial            := nvl(cr_pedcab.codfilial, gregpcconsum.codfilialfv);
            gregpedido.codfilialnf          := cr_pedcab.codfilialnf;
            gregpedido.codfilialretira      := cr_pedcab.codfilialretira;
            gregpedido.vlfrete              := cr_pedcab.vlfrete ;
            gregpedido.codcob               := UPPER(cr_pedcab.codcob);
            gregpedido.codplpag             := cr_pedcab.codplpag;
            gregpedido.condvenda            := cr_pedcab.condvenda;
            gregpedido.obs1                 := cr_pedcab.obs1;
            gregpedido.obs2                 := cr_pedcab.obs2;
            gregpedido.obsentrega1          := cr_pedcab.obsentrega1;
            gregpedido.obsentrega2          := cr_pedcab.obsentrega2;
            gregpedido.obsentrega3          := cr_pedcab.obsentrega3;
            gregpedido.obsentrega4          := cr_pedcab.obsentrega4;
            gregpedido.fretedespacho        := cr_pedcab.fretedespacho ;
            gregpedido.freteredespacho      := cr_pedcab.freteredespacho ;
            gregpedido.codfornecfrete       := cr_pedcab.codfornecfrete ;
            gregpedido.parcela1             := cr_pedcab.parcela1;
            gregpedido.parcela2             := cr_pedcab.parcela2;
            gregpedido.parcela3             := cr_pedcab.parcela3;
            gregpedido.parcela4             := cr_pedcab.parcela4;
            gregpedido.parcela5             := cr_pedcab.parcela5;
            gregpedido.parcela6             := cr_pedcab.parcela6;
            gregpedido.parcela7             := cr_pedcab.parcela7;
            gregpedido.parcela8             := cr_pedcab.parcela8;
            gregpedido.parcela9             := cr_pedcab.parcela9;
            gregpedido.parcela10            := cr_pedcab.parcela10;
            gregpedido.parcela11            := cr_pedcab.parcela11;
            gregpedido.parcela12            := cr_pedcab.parcela12;
            gregpedido.origemped            := nvl(cr_pedcab.origemped,'F');
            gregpedido.numpedorig           := cr_pedcab.numpedorigem;
            gregpedido.DATA                 := TRUNC(SYSDATE);
            gregpedido.codclinf             := cr_pedcab.codclinf;
            gregpedido.tipodocumento        := cr_pedcab.tipodocumento;
            gregpedido.contaordem           := cr_pedcab.contaordem;
            gregpedido.codcli               := cr_pedcab.codcli;
            gregpedido.codclitv8            := cr_pedcab.codclitv8;
            gregpedido.codplpagetico        := cr_pedcab.codplpagetico;
            gregpedido.codplpaggenerico     := cr_pedcab.codplpaggenerico;
            gregpedido.tipofv               := cr_pedcab.tipofv;
            gregpedido.codmotivonaoatend    := null;
            gregpedido.tipoprioridadeentrega := cr_pedcab.tipoprioridadeentrega;
            gregpedido.localdesembaraco      := cr_pedcab.localdesembaraco;
            gregpedido.ufdesembaraco         := cr_pedcab.ufdesembaraco;
            gregpedido.numpedtv1             := cr_pedcab.numpedtv1;
            gregpedido.agrupamento           := cr_pedcab.agrupamento;
            gregpedido.codbnf                := cr_pedcab.codbnf;
            gregpedido.custobonificacao      := upper(cr_pedcab.custobonificacao);
            gregpedido.codfornecbonific      := cr_pedcab.codfornecbonific;
            gregpedido.vlentrada             := cr_pedcab.vlentrada;
            gregpedido.orcamento             := nvl(cr_pedcab.orcamento,'N');
            gregpedido.numpedvanxml          := cr_pedcab.numpedvanxml;
            gregpedido.codendentcli          := cr_pedcab.codendentcli;
            gregpedido.codclirecebedor       := cr_pedcab.codclirecebedor;
            gregpedido.numregiaobroker       := cr_pedcab.numregiaobroker;
            gregpedido.codusur2              := cr_pedcab.codusur2;
            gregpedido.codusur3              := cr_pedcab.codusur3;
            gregpedido.codusur4              := cr_pedcab.codusur4;
            gregpedido.aplicarperredcomiss   := cr_pedcab.aplicarperredcomiss;
            gregpedido.descintermediador     := cr_pedcab.descintermediador; -- DDMEDICA-6201  
            gregpedido.cnpjintermediador     := cr_pedcab.cnpjintermediador; -- DDMEDICA-6201  
            --DDMEDICA-4173

            IF (NVL(FUSA_REGRA_MEDICAMENTOS('99','CODEMITENTEECOMMERCE'),'N') = 'S') AND
              gregpedido.origemped = 'W' THEN
              gregpedido.codemitente    := NVL(cr_pedcab.codemitente,8888);

              --DDMEDICA-4932 - Aproveitando para ter certeza de que se estiver vazio preencher da forma que era antes
              IF TRIM(gregpedido.codemitente) = '' THEN
                gregpedido.codemitente  := 8888;
              END IF;

            ELSE
              gregpedido.codemitente    := 8888;
            END IF;

            --
            gregpedido.codpromocaomed        := cr_pedcab.codpromocaomed;
            IF (FUSA_REGRA_MEDICAMENTOS('99','USAREGRAPROMOCABECALHO99FV') = 'S') AND
               (NVL(cr_pedcab.codpromocaomed,0) = 0) THEN
              gregpedido.codpromocaomed := 999999999;
            END IF;
            --
            gregpedido.gravarpedidocomobloqueado := cr_pedcab.gravarpedidocomobloqueado;
            -- INICIO: HIS.04557.2015 - ICMS Partilha
            gregpedido.precocompartilha      := cr_pedcab.precocompartilha;
            -- FIM: HIS.04557.2015 - ICMS Partilha
            gregpedido.restringirpromocaomed := cr_pedcab.restringirpromocaomed;
            -- Taxa Frete
            gregpedido.vlfreteoutrasdesp     := cr_pedcab.vlfreteoutrasdesp;

            -- Verifica se o Pedido foi recebido por Integração de OL via Banco de Dados - HIS.03889.2014
            BEGIN
              SELECT 'S' ACHOU
                   , PCPEDCOPERLOG.TIPODEFORIGEMPEDIDO -- HIS.01025.2015
                   , PCPEDCOPERLOG.ORIGEMPEDIDO        -- HIS.01025.2015
                INTO gregpedido.integracaopedoperlog
                   , gregpedido.tipodeforigempedidooperlog -- HIS.01025.2015
                   , gregpedido.origempedidooperlog        -- HIS.01025.2015
                FROM PCPEDCOPERLOG
                   , PCPEDRETORNO
                   , PCCLIENT
               WHERE (PCPEDRETORNO.NUMPEDRCA         = gregpedido.numpedrca)
                 AND (PCPEDRETORNO.CODUSUR           = gregpedido.codusur)
                 AND (PCPEDRETORNO.CGCCLI            = gregpedido.cgccli)
                 AND (PCPEDRETORNO.DTABERTURAPEDPALM = gregpedido.dtaberturapedpalm)
                 AND (PCPEDCOPERLOG.INTEGRADORA      = PCPEDRETORNO.INTEGRADORA)
                 AND (PCPEDCOPERLOG.CGCCLI           = PCPEDRETORNO.CGCCLI)
                 AND (PCPEDCOPERLOG.NUMPEDVAN        = PCPEDRETORNO.NUMPEDVAN)
                 AND (PCPEDCOPERLOG.DTINCLUSAO       = PCPEDRETORNO.DTINCLUSAOPEDOPERLOG)
                 AND (PCCLIENT.CODCLI                = PCPEDRETORNO.CODCLI);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                gregpedido.integracaopedoperlog       := 'N';
                gregpedido.tipodeforigempedidooperlog := NULL;
                gregpedido.origempedidooperlog        := NULL;
              WHEN OTHERS THEN
                gregpedido.integracaopedoperlog       := 'N';
                gregpedido.tipodeforigempedidooperlog := NULL;
                gregpedido.origempedidooperlog        := NULL;
            END;

            -- Verifica se Pedido ECommerce - HIS.02854.2015
            IF ((NVL(cr_pedcab.origemped,'F') = 'W') AND
                (NVL(cr_pedcab.OBS1,' ')      = 'PEDIDO ECOMMERCE')) THEN
              gregpedido.pedidoecommerce := 'S';
            ELSE
              gregpedido.pedidoecommerce := 'N';
            END IF;

            IF NVL(gregpedido.dtentrega, TRUNC(SYSDATE)) < TRUNC(SYSDATE)
            THEN
              gregpedido.dtentrega := TRUNC(SYSDATE);
            END IF;

            vblercabok := TRUE;

            IF vblercabok = TRUE
            THEN
              vncontped := vncontped + 1;
              gvet_regpedido(vncontped) := gregpedido;
            END IF;

            IF vblercabok = TRUE and gregpedido.tipofv in ('OL','PE') then

              begin

               select p.integradora,p.codcondicaovenda, p.numpedvan,
                      p.numquebra, -- 156777
                      p.codigoprojeto, -- 158742
                      p.faturamentointegral, -- HIS.00301.2015
                      p.arquivoped, -- MED-1468
                      p.prazo,      -- MED-1503
                      p.tipoprazo,  -- MED-1503
                      p.codprazo,   -- MED-1503
                      p.codcli,     -- MED-1503
                      p.codvendedorpedol
               into   gvet_regpedido(vncontped).integradora,gvet_regpedido(vncontped).codcondicaovenda, gvet_regpedido(vncontped).numpedvan,
                      gvet_regpedido(vncontped).numquebra, -- 156777
                      gvet_regpedido(vncontped).codigoprojeto, -- 158742
                      gvet_regpedido(vncontped).faturamentointegral, -- HIS.00301.2015
                      gvet_regpedido(vncontped).arquivoped,               -- MED-1468
                      gvet_regpedido(vncontped).prazo_pcpedretorno,       -- MED-1503
                      gvet_regpedido(vncontped).tipoprazo_pcpedretorno,   -- MED-1503
                      gvet_regpedido(vncontped).codigoprazo_pcpedretorno, -- MED-1503
                      gvet_regpedido(vncontped).codcli_pcpedretorno,
                      gvet_regpedido(vncontped).codvendedorpedol
               from pcpedretorno p
               WHERE numpedrca         = gvet_regpedido(vncontped).numpedrca
               and   cgccli            = gvet_regpedido(vncontped).cgccli
               and   codusur           = gvet_regpedido(vncontped).codusur
               and   dtaberturapedpalm = gvet_regpedido(vncontped).dtaberturapedpalm;

               exception when others then
               proc_registralog(NULL,
                               cr_pedcab.numpedrca,
                               null,
                               null,
                               cr_pedcab.cgccli,
                               NULL,
                               NULL,
                               NULL,
                               cr_pedcab.codusur,
                               cr_pedcab.dtaberturapedpalm,
                               null,
                               '2',
                               'ERRO AO LER PCPEDRETORNO#' || SQLCODE || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';',
                               cr_pedcab.linha,
                               null);

                  if gregpedido.codmotivonaoatend is null then
                     gregpedido.codmotivonaoatend := 3;
                  end if;


              end;

            END IF;

          END IF; -- Fim Condição Pedido existe na PCPEDC

          IF vblercabok = TRUE
          THEN

            -- Controle de Pesquisa de Promoção
            vrPromocaoCab := vrLimpaPromocaoCab; -- Inicializa Record
            IF (NVL(gvet_regpedido(vncontped).codpromocaomed,0) = 0) THEN
              vrPromocaoCab.vbPesquisarPromocao := TRUE;
            ELSE
              vrPromocaoCab.vbPesquisarPromocao := FALSE;
            END IF;

            -- DDMEDICA-198 - Inicializa Lista de Indicativo de pedido com produtos repetidos
            vtListaProdutosRepetidos.DELETE;

            -- Laço de Itens do Pedd
            FOR cr_pedcorp IN (SELECT   numpedrca,
                                        cgccli,
                                        codusur,
                                        dtaberturapedpalm,
                                        codprod,
                                        qt,
                                        pvenda,
                                        codauxiliar,
                                        codfilialretira,
                                        unidade_frios,
                                        politicaprioritaria,
                                        codcombo,
                                        nvl(percdescedi,0) perdescedi,
                                        perdescboleto,
                                        ROWNUM AS linha,
                                        -- INICIO: HIS.04557.2015 - ICMS Partilha
                                        vlbasepartdest,
                                        aliqfcp,
                                        aliqinternadest,
                                        vlfcppart,
                                        vlicmspartdest,
                                        vlicmspart,
                                        -- FIM: HIS.04557.2015 - ICMS Partilha
                                        codpromocaomed,
                                        PERREDCOMISS,
                                        percacrescoperlog, -- HIS.00262.2018
                                        bonific, -- MED-2521
                                        numseq as numseqifv, -- DDMEDICA-198
                                        numlotepromocaomed,
                                        coddescontomed, -- DDMEDICA-7478
                                        usacashback,  --DDVENDAS-35840
                                        numitemped -- DDVENDAS-44985
                                 FROM pcpedifv
                                WHERE numpedrca         = cr_pedcab.numpedrca
                                and   cgccli            = cr_pedcab.cgccli
                                and   codusur           = cr_pedcab.codusur
                                and   dtaberturapedpalm = cr_pedcab.dtaberturapedpalm) LOOP
              BEGIN
                vbleritemok                := FALSE;

                gregitem.numpedrca         := cr_pedcorp.numpedrca;
                gregitem.codusur           := cr_pedcorp.codusur;
                gregitem.cgccli            := cr_pedcorp.cgccli;
                gregitem.dtaberturapedpalm := cr_pedcorp.dtaberturapedpalm;
                gregitem.codprod           := cr_pedcorp.codprod;
                gregitem.qt                := cr_pedcorp.qt;
                gregitem.pvenda            := cr_pedcorp.pvenda;
                gregitem.pvendaanterior    := cr_pedcorp.pvenda;
                gregitem.codfilialretira   := cr_pedcorp.codfilialretira;
                gregitem.codauxiliar       := cr_pedcorp.codauxiliar;
                gregitem.numpedorig        := gregpedido.numpedorig;
                gregitem.unidadevenda      := upper(trim(cr_pedcorp.unidade_frios));
                gregitem.prioritaria       := nvl(cr_pedcorp.politicaprioritaria,'N');
                gregitem.codcombo          := cr_pedcorp.codcombo;
                gregitem.percdescedi       := cr_pedcorp.perdescedi;
                gregitem.precoedi          := cr_pedcorp.pvenda;
                gregitem.perdescboleto     := cr_pedcorp.perdescboleto;
                gregitem.codmotivonaoatend := null;
                -- INICIO: HIS.04557.2015 - ICMS Partilha
                gregitem.vlbasepartdest    := nvl(cr_pedcorp.vlbasepartdest,0);
                gregitem.aliqfcp           := nvl(cr_pedcorp.aliqfcp,0);
                gregitem.aliqinternadest   := nvl(cr_pedcorp.aliqinternadest,0);
                gregitem.vlfcppart         := nvl(cr_pedcorp.vlfcppart,0);
                gregitem.vlicmspartdest    := nvl(cr_pedcorp.vlicmspartdest,0);
                gregitem.vlicmspart        := nvl(cr_pedcorp.vlicmspart,0);
                -- FIM: HIS.04557.2015 - ICMS Partilha
                gregitem.codpromocaomed    := cr_pedcorp.codpromocaomed;
                gregitem.percacrescoperlog := cr_pedcorp.percacrescoperlog; -- HIS.00262.2018
                gregitem.bonific           := cr_pedcorp.bonific; -- MED-2521
                gregitem.numseqifv         := cr_pedcorp.numseqifv; -- DDMEDICA-198
                gregitem.PERREDCOMISS      := cr_pedcorp.perredcomiss;
                gregitem.numlotepromocaomed:= cr_pedcorp.numlotepromocaomed;
                gregitem.coddescontomed    := cr_pedcorp.coddescontomed; -- DDMEDICA-7478
                gregitem.USACASHBACK       := cr_pedcorp.usacashback;
                gregitem.numitemped        := cr_pedcorp.numitemped;
        
                -- DDMEDICA-198 - Indicativo de pedido com produtos repetidos
                IF (cr_pedcorp.codprod > 0) THEN
                  IF (vtListaProdutosRepetidos.EXISTS(cr_pedcorp.codprod)) THEN
                    gvet_regpedido(vncontped).existemprodutosrepetidos := 'S';
                  END IF;
                  vtListaProdutosRepetidos(cr_pedcorp.codprod) := 1;
                END IF;

                vbleritemok                := TRUE;

                -- Se não informou a Promoção no Cabeçalho mas tem no Item do Pedido, preenche a Promoção do Cabeçalho
                -- para que o o Sistema passe a usar as Regras da Promoção
                IF (vrPromocaoCab.vbPesquisarPromocao) AND
                   (NVL(gregitem.codpromocaomed,0) > 0) THEN
                  -- Pesquisa o Tipo de Promoção
                  BEGIN
                    SELECT TIPOPROMOCAO
                      INTO vrPromocaoCab.vvTipoPromocao
                      FROM PCPROMOCAOMED
                     WHERE (CODPROMOCAOMED = gregitem.codpromocaomed);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      vrPromocaoCab.vvTipoPromocao := NULL;
                  END;
                  -- Se Promoção de Cliente
                  IF (vrPromocaoCab.vvTipoPromocao = 'C') THEN
                    vrPromocaoCab.vnCodPromocaoTipoCliente := gregitem.codpromocaomed;
                  ELSE
                    vrPromocaoCab.vnCodPromocaoOutrosTipos := gregitem.codpromocaomed;
                  END IF;
                END IF;
                
                -- DDVENDAS-33961 - Oferta no Operador Logístico
                gregitem.restringirpromocaomed := NULL;
                IF (gregpedido.tipofv = 'OL') AND
                   (gregitem.codpromocaomed > 0) AND
                   (gregitem.precoedi > 0) THEN
                  IF (FOBTEM_PARAM_INTEGRADORA(gvet_regpedido(vncontped).integradora,
                                               'CONCEDENTEFERTA',
                                               'N') IN ('D','I')) THEN
                    gregitem.restringirpromocaomed := 'S';
                  END IF;                                                
                END IF;   
                 
                IF vbleritemok = TRUE
                THEN
                  vncontitem := vncontitem + 1;
                  gvet_regitem(vncontitem) := gregitem;
                  -- incrementar contador de itens do pedido atual
                  gvet_regpedido(vncontped).numitens := NVL(gvet_regpedido(vncontped)
                                                            .numitens,
                                                            0) + 1;
                  -- incrementar contador de unidades do pedido atual - DDMEDICA-6533
                  gvet_regpedido(vncontped).totunidades := NVL(gvet_regpedido(vncontped)
                                                               .totunidades,
                                                               0) + NVL(gregitem.qt,0);

                --origempreco
                vncontorigempreco := vncontorigempreco + 1;
                gvet_regorigempreco(vncontorigempreco).codprod        := gregitem.codprod;
                gvet_regorigempreco(vncontorigempreco).data           := gvet_regpedido(vncontped).data;
                gvet_regorigempreco(vncontorigempreco).origemped      := gvet_regpedido(vncontped).origemped;

                --DDMEDICA-4173
                IF (NVL(FUSA_REGRA_MEDICAMENTOS('99','CODEMITENTEECOMMERCE'),'N') = 'S') AND
                  gvet_regpedido(vncontped).origemped = 'W' THEN
                  gvet_regorigempreco(vncontorigempreco).codemitente    := gvet_regpedido(vncontped).codemitente;
                ELSE
                  gvet_regorigempreco(vncontorigempreco).codemitente    := 8888;
                END IF;

                gvet_regorigempreco(vncontorigempreco).codfilial      := gvet_regpedido(vncontped).codfilial;
                gvet_regorigempreco(vncontorigempreco).usatributporuf := 'N';


                --origemcomiss
                vncontorigemcomiss := vncontorigemcomiss + 1;
                gvet_regorigemcomiss(vncontorigemcomiss).codprod        := gregitem.codprod;
                gvet_regorigemcomiss(vncontorigemcomiss).origemped      := gvet_regpedido(vncontped).origemped;
                gvet_regorigemcomiss(vncontorigemcomiss).codauxiliar    := gregitem.codauxiliar;
                gvet_regorigemcomiss(vncontorigemcomiss).codfilial      := gvet_regpedido(vncontped).codfilial;
                gvet_regorigemcomiss(vncontorigemcomiss).codusur        := gvet_regpedido(vncontped).codusur;

                --origemdesc
                vncontorigemdesc := vncontorigemdesc + 1;
                gvet_regorigemdesc(vncontorigemdesc).codprod        := gregitem.codprod;
                gvet_regorigemdesc(vncontorigemdesc).origemped      := gvet_regpedido(vncontped).origemped;
                gvet_regorigemdesc(vncontorigemdesc).codauxiliar    := gregitem.codauxiliar;


                END IF;
              EXCEPTION
                WHEN OTHERS THEN
                  proc_registralog(NULL,
                                   cr_pedcorp.numpedrca,
                                   cr_pedcorp.codprod,
                                   cr_pedcorp.codauxiliar,
                                   cr_pedcorp.cgccli,
                                   NULL,
                                   NULL,
                                   null,
                                   cr_pedcorp.codusur,
                                   cr_pedcorp.dtaberturapedpalm,
                                   null,
                                   '3',
                                   'ERRO AO LER ITEM DO PEDIDO#' || SQLCODE || '-' ||';'||
                                   DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';',
                                   cr_pedcorp.linha,
                                   cr_pedcorp.numseqifv);

                if gregitem.codmotivonaoatend is null then
                   gregitem.codmotivonaoatend := 1;
                end if;



              END;

            END LOOP; -- Fim Laço de Itens do Pedido

            -- Preenche a Promoção do Cabeçalho a partir da Promoção dos Itens
            IF (vrPromocaoCab.vbPesquisarPromocao) THEN
              -- Se achou Promoção de Cliente
              IF    (NVL(vrPromocaoCab.vnCodPromocaoTipoCliente,0) > 0) THEN
                gvet_regpedido(vncontped).codpromocaomed := vrPromocaoCab.vnCodPromocaoTipoCliente;
              -- Se achou outro Tipo de Promoção
              ELSIF (NVL(vrPromocaoCab.vnCodPromocaoOutrosTipos,0) > 0) THEN
                gvet_regpedido(vncontped).codpromocaomed := vrPromocaoCab.vnCodPromocaoOutrosTipos;
              END IF;
            END IF;

            -- Laço de Combos do Pedido - HIS.03536.2016
            FOR cr_combo IN (SELECT numpedrca,
                                    cgccli,
                                    codusur,
                                    dtaberturapedpalm,
                                    codpromocaomed,
                                    qtcombo,
                                    rejeitapedcomboinvalido,
                                    ROWNUM AS linha
                               FROM pcpedcombopromocaomedfv
                              WHERE numpedrca         = cr_pedcab.numpedrca
                              and   cgccli            = cr_pedcab.cgccli
                              and   codusur           = cr_pedcab.codusur
                              and   dtaberturapedpalm = cr_pedcab.dtaberturapedpalm) LOOP
              BEGIN
                gregcombo.numpedrca               := cr_combo.numpedrca;
                gregcombo.codusur                 := cr_combo.codusur;
                gregcombo.cgccli                  := cr_combo.cgccli;
                gregcombo.dtaberturapedpalm       := cr_combo.dtaberturapedpalm;
                gregcombo.qtcombo                 := cr_combo.qtcombo;
                gregcombo.codpromocaomed          := cr_combo.codpromocaomed;
                gregcombo.rejeitapedcomboinvalido := cr_combo.rejeitapedcomboinvalido;

                -- Grava record do combo em Array
                vncontcombo := vncontcombo + 1;
                gvet_regcombo(vncontcombo) := gregcombo;
              EXCEPTION
                WHEN OTHERS THEN
                  -- Qualquer erro ao ler o Combo (não é processamento ainda) será tratado como erro do Pedido
                  proc_registralog(NULL,
                                   cr_combo.numpedrca,
                                   null,
                                   null,
                                   cr_combo.cgccli,
                                   NULL,
                                   NULL,
                                   NULL,
                                   cr_combo.codusur,
                                   cr_combo.dtaberturapedpalm,
                                   null,
                                   '2',
                                   'ERRO AO LER COMBO [' || cr_combo.codpromocaomed || '] DO PEDIDO#' || SQLCODE || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';',
                                   cr_combo.linha,
                                   null);
                  if gregpedido.codmotivonaoatend is null then
                     gregpedido.codmotivonaoatend := 3;
                  end if;
              END;
            END LOOP; -- Fim Laço de Combos

          END IF; -- Fim: IF vblercabok = TRUE

        END IF; -- FIM CONDIÇÃO: Se pode Importar o Pedido neste momento - MED-1600

      EXCEPTION
        WHEN OTHERS THEN
          proc_registralog(NULL,
                           cr_pedcab.numpedrca,
                           null,
                           null,
                           cr_pedcab.cgccli,
                           NULL,
                           NULL,
                           NULL,
                           cr_pedcab.codusur,
                           cr_pedcab.dtaberturapedpalm,
                           null,
                           '2',
                           'ERRO AO LER PEDIDO#' || SQLCODE || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';',
                           cr_pedcab.linha,
                           null);

              if gregpedido.codmotivonaoatend is null then
                gregpedido.codmotivonaoatend := 2;
              end if;
      END;

    END LOOP;
    --fim pedidos

  EXCEPTION
    WHEN OTHERS THEN
      p_existerro := TRUE;
      proc_registralog(NULL,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       NULL,
                       null,
                       null,
                       null,
                       null,
                       '1',
                       'ERRO AO LER PEDIDOS;' || SQLCODE || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';',
                       NULL,
                       null);
  END proc_processarleitura;









  FUNCTION retorna_prazomedido_plpagfixo(pcodplpag IN pcplpag.codplpag%TYPE)
    RETURN NUMBER IS
    vidatavenc          INT;
    pcarencia           pcplpag.diascarencia%TYPE;
    diafixo             pcplpag.diafixo%TYPE;
    pnumparcelas        pcplpag.numeroparcelasdiafixo%TYPE;
    vddata_vencimento   DATE;
    vddata_venc_inicial DATE;
  BEGIN
    SELECT NVL(pcplpag.diascarencia, 0),
           NVL(pcplpag.diafixo, 1),
           NVL(pcplpag.numeroparcelasdiafixo, 1)
      INTO pcarencia, diafixo, pnumparcelas
      FROM pcplpag
     WHERE pcplpag.codplpag = pcodplpag;

    vidatavenc := 0;

    FOR vi IN 1 .. pnumparcelas LOOP
      SELECT TO_DATE(TO_CHAR(diafixo) || '/' ||
                     TO_CHAR(ADD_MONTHS(TRUNC(SYSDATE), vidatavenc),
                             'MM/YYYY'),
                     'DD/MM/YYYY')
        INTO vddata_vencimento
        FROM DUAL;

      IF vi = 1 THEN
        IF (TRUNC(SYSDATE) + pcarencia) >= vddata_vencimento THEN
          vddata_vencimento := ADD_MONTHS(vddata_vencimento, 1);
          vidatavenc        := vidatavenc + 2;
        ELSE
          vidatavenc := vidatavenc + 1;
        END IF;
      ELSE
        vidatavenc := vidatavenc + 1;
      END IF;

      IF vi = 1 THEN
        vddata_venc_inicial := vddata_vencimento;
      END IF;
    END LOOP;

    RETURN TRUNC((vddata_vencimento - TRUNC(SYSDATE)) / pnumparcelas);
  END;

  function func_calcularperdescitem(p_ptabela    in pcpedi.ptabela%type,
                                    p_pvenda     in pcpedi.pvenda%type,
                                    p_codmotivonaoatend in out pcpedifv.codmotivonaoatend%type ) return number is
    vnperdesc number;
  begin

    vnperdesc := ((p_ptabela - p_pvenda) /
                 p_ptabela) * 100;
    vnperdesc := ROUND(vnperdesc, gregpcconsum.numcasasdecvenda);

    return vnperdesc;
  exception
    when others then

      if p_codmotivonaoatend is null then
         p_codmotivonaoatend := 26 ;
      end if;

      return 0;

  end func_calcularperdescitem;

  /*    PROCEDURE gerarcarregbalcaoreserva
          Gerar registro de carregamento e atualiza pedido e itens do pedido
  */
  procedure gerarcarregbalcaoreserva(p_numped            in  pcpedc.numped%type,
                                     p_numpedrca         in  pcpedc.numpedrca%type,
                                     p_codusur           in  pcpedc.codusur%type,
                                     p_cgccli            in  pcclient.cgcent%type,
                                     p_dtaberturapedpalm in pcpedc.dtaberturapedpalm%type,
                                     p_cancelada         in varchar2,
                                     p_numcar            out pcpedc.numcar%type ) is

    pncaregamento  number;
    vnvlatendped   pcpedc.vlatend%type;
    vntotpesoped   pcpedc.totpeso%type;
    vntotvolumeped pcpedc.totvolume%type;

  begin
    begin

      select proxnumcar into pncaregamento from pcconsum for update;

      update pcconsum set proxnumcar = NVL(proxnumcar, 0) + 1;

      update pcpedc
         set numcar = pncaregamento, posicao = 'M', tipocarga = 'R'
       where numped in (select numped from pcpedc
                        where numpedrca =  p_numpedrca
                        and nvl(pcpedc.restricaotransp,'N') = 'N'
                        and codusur = p_codusur
                        and (dtaberturapedpalm = p_dtaberturapedpalm  or dtaberturapedpalm is null));

      update pcpedi
         set numcar = pncaregamento, posicao = 'M'
       where numped in (select numped from pcpedc
                        where numpedrca =  p_numpedrca
                        and nvl(pcpedc.restricaotransp,'N') = 'N'
                        and codusur = p_codusur
                        and (dtaberturapedpalm = dtaberturapedpalm or dtaberturapedpalm is null ));


        SELECT SUM(pcpedi.qt * pcpedi.pvenda),
               SUM(NVL(pcpedi.qt, 0) * NVL(pcprodut.pesobruto, 0)) totpeso,
               SUM(NVL(pcpedi.qt, 0) * NVL(pcprodut.volume, 0)) totvolume
          INTO  vnvlatendped,
                vntotpesoped,
                vntotvolumeped
          FROM pcpedi,pcprodut
         WHERE pcpedi.codprod = pcprodut.codprod
         and   numped in (select numped from pcpedc
                          where numpedrca =  p_numpedrca
                          and nvl(pcpedc.restricaotransp,'N') = 'N'
                          and codusur = p_codusur
                          and (dtaberturapedpalm = p_dtaberturapedpalm or dtaberturapedpalm is null));



      insert into pccarreg
        (numcar,
         dtsaida,
         totpeso,
         totvolume,
         vltotal,
         destino,
         datamon,
         codveiculo,
         codfuncmon,
         dtfecha)
      values
        (pncaregamento,
         TRUNC(sysdate),
         vntotpesoped,
         vntotvolumeped,
         vnvlatendped,
         'VENDA BALCAO',
         TRUNC(sysdate),
         0,
         0,
         TRUNC(sysdate));

      commit;

      proc_registralog(p_numped,
                       p_numpedrca,
                       null,
                       null,
                       p_cgccli,
                       null,
                       null,
                       null,
                       p_codusur,
                       p_dtaberturapedpalm,
                       p_cancelada,
                       '2',
                       'CARREGAMENTO CRIADO PARA PEDIDO BALCAO RESERVA. NUMCAR = ' ||
                       TO_CHAR(pncaregamento, '000000') || ';',
                       null,
                       null);


       p_numcar := pncaregamento;

    exception
      when others then
        proc_registralog(p_numped,
                         p_numpedrca,
                         null,
                         null,
                         p_cgccli,
                         null,
                         null,
                         null,
                         p_codusur,
                         p_dtaberturapedpalm,
                         p_cancelada,
                         '2',
                         'ERRO: NAO GEROU/ATUALIZOU CARREGAMENTO. NUMCAR = ' ||
                         TO_CHAR(pncaregamento, '000000') || ';',
                         null,
                         null);
        rollback;
    end;
  end gerarcarregbalcaoreserva;


   procedure proc_validaplanosmed (p_regpedido in out t_cabped,
                                 p_regcliente in t_clientepedido,
                                 p_regfilial in t_filial, -- DDMEDICA-675
                                 p_regplpag   out t_planodepagamento,
                                 p_regplpagetico out t_plpagetico,
                                 p_regplpaggenerico out t_plpaggenerico) is


    vicontador         number;
    vsmensagem         varchar2(32767):= null;
    vschar             varchar2(1) default '#';
    vbvalidacob        boolean;
    vsprazos           varchar2(50);
    vicont             number;
    vnprazototal       number;
    vsboleto           pccob.boleto%type;
    vnprazomaximovenda pccob.prazomaximovenda%type;

    -- MED-869 - Informações de Cadastro do Plano Ético e Genérico do Cliente
    vrDadosPlPagEticoCli    PCPLPAG%ROWTYPE;
    vrDadosPlPagGenericoCli PCPLPAG%ROWTYPE;

    -- Record de Retorno das Validações - DDMEDICA-675
    TYPE TRecRetValidacao      IS RECORD(
         vvRejeitado           VARCHAR2(1),
         vvMotivoRejeitado     VARCHAR2(255),
         vvObservacao          VARCHAR2(32000),
         vvRetJson             VARCHAR2(32000),
         vvGravarComoBloqueado VARCHAR2(1),
         vnCodMotivoNaoAtend   NUMBER);
    vrRetValidacao             TRecRetValidacao;

   begin

       -- Se Pedidos do Força de Vendas usando Promoção, o Plano Genérico será o recebido no Pedido como CODPLPAG,
       -- e o Ético será o CODPLPAGETICO do Cliente
       IF (NVL(p_regpedido.codpromocaomed,0) > 0) AND
          (NVL(p_regpedido.tipofv,'FV') = 'FV')   THEN

         -- Se a Rotina de Importação já estiver preenhendo o Plano Ético ou Genérico no Pedido, usa valores do Pedido
         IF (NVL(p_regpedido.codplpagetico,0)    > 0) OR
            (NVL(p_regpedido.codplpaggenerico,0) > 0) THEN
           -- Se não vier Plano Ético no Pedido, pega do Cliente
           IF (NVL(p_regpedido.codplpagetico,0) = 0) THEN
             p_regpedido.codplpagetico := p_regcliente.codplpagetico;
           END IF;
           -- Se não vier Plano Genérico no Pedido, pega do Cliente
           IF (NVL(p_regpedido.codplpaggenerico,0) = 0) THEN
             p_regpedido.codplpagetico := p_regcliente.codplpaggenerico;
           END IF;
         -- Senão regra anterior
         ELSE
           p_regpedido.codplpagetico    := nvl(p_regpedido.codplpagetico,p_regcliente.codplpagetico);
           p_regpedido.codplpaggenerico := nvl(p_regpedido.codplpag,p_regcliente.codplpaggenerico);   -->> Plano Genérico recebe o passado no Pedido no campo CODPLPAG
         END IF;

         p_regpedido.codplpag               := 99; -->> Quando usa Plano Ético e Genérico, CODPLPAG tem que ser '99'

         --MED-2390--p_regpedido.aplicataxaplpagprecofv := 'S'; -->> Aplica Taxa do Plano de Pagamento no Preço do FV

       -- Demais casos, mantém regra anterior
       ELSE

         p_regpedido.codplpag         := 99;

         p_regpedido.codplpagetico    := nvl(p_regpedido.codplpagetico,p_regcliente.codplpagetico);
         p_regpedido.codplpaggenerico := nvl(p_regpedido.codplpaggenerico,p_regcliente.codplpaggenerico);

       END IF;

       select boleto,prazomaximovenda
       into vsboleto,vnprazomaximovenda
       from pccob
       where codcob = p_regpedido.codcob;

       -- MED-869 - Informações de Cadastro do Plano Ético e Genérico do Cliente
       BEGIN
         SELECT PCPLPAG.*
           INTO vrDadosPlPagEticoCli
           FROM PCPLPAG
          WHERE (PCPLPAG.CODPLPAG = p_regcliente.codplpagetico);
       EXCEPTION
         WHEN NO_DATA_FOUND THEN
           NULL;
       END;
       BEGIN
         SELECT PCPLPAG.*
           INTO vrDadosPlPagGenericoCli
           FROM PCPLPAG
          WHERE (PCPLPAG.CODPLPAG = p_regcliente.codplpaggenerico);
       EXCEPTION
         WHEN NO_DATA_FOUND THEN
           NULL;
       END;

       if p_regpedido.codplpagetico = 99 or p_regpedido.codplpagetico is null then

         if vsmensagem is not null then
                vschar := '#';
         else
                vschar := null;
          end if;
              vsmensagem         := vsmensagem || vschar ||
                                    'PLANO DE PAGAMENTO ETICO NAO PODE SER NULO nem 99 ;';
              p_regpedido.valido := false;

       end if;

       if p_regpedido.codplpaggenerico = 99 or p_regpedido.codplpaggenerico is null then
         if vsmensagem is not null then
                vschar := '#';
         else
                vschar := null;
          end if;
              vsmensagem         := vsmensagem || vschar ||
                                    'PLANO DE PAGAMENTO GENERICO  NAO PODE SER NULO nem 99 ;';
              p_regpedido.valido := false;

       end if;

       --valida plano de pagamento etico
          select count(*)
          into vicontador
          from pcplpag
          where codplpag = p_regpedido.codplpagetico;

            if vicontador = 0 then
              if vsmensagem is not null then
                vschar := '#';
              else
                vschar := null;
              end if;
              vsmensagem         := vsmensagem || vschar ||
                                    'PLANO DE PAGAMENTO ETICO :' ||
                                    p_regpedido.codplpagetico || ' NAO CADASTRADO ;';
              p_regpedido.valido := false;
            else

              select codplpag,
                     nvl(numdias,0),
                     NVL(numitensminimo, 0),
                     NVL(numpr, 1) numpr,
                     obs,
                     NVL(pertxfim, 0),
                     prazo1,
                     prazo2,
                     prazo3,
                     prazo4,
                     prazo5,
                     prazo6,
                     prazo7,
                     prazo8,
                     prazo9,
                     prazo10,
                     prazo11,
                     prazo12,
                     NVL(tipoprazo, 'N'),
                     tipovenda,
                     NVL(vlminpedido, 0),
                     NVL(pcplpag.vendabk, 'N'),
                     NVL(tiporestricao, 'NR'),
                     codrestricao,
                     trim(codfilial),
                     pcplpag.formaparcelamento
                into p_regplpagetico
                from pcplpag
               where codplpag = p_regpedido.codplpagetico;

            end if;


           if (p_regplpagetico.formaparcelamento <> 'C') and
              (p_regplpagetico.formaparcelamento <> 'M') then

             if vsmensagem is not null then
                    vschar := '#';
             else
                    vschar := null;
              end if;
                  vsmensagem         := vsmensagem || vschar ||
                                        'PLANO DE PAGAMENTO ETICO SÓ ACEITA PLANO TIPO CUSTOMIZADO/MENSAL ;';
                  p_regpedido.valido := false;

           end if;


                vbvalidacob := true;

                --tarefa 125968
                    select count(*)
                    into vicontador
                    from pccobplpag p
                    where p.codcob   = p_Regpedido.codcob;


                       if vicontador <> 0 then

                        select count(*)
                        into vicontador
                        from pccobplpag p
                        where p.codplpag = p_Regpedido.codplpagetico
                        and   p.codcob   = p_Regpedido.codcob;


                        if vicontador = 0 then

                            if vsmensagem is not null then
                              vschar := '#';
                            else
                              vschar := null;
                            end if;
                            vsmensagem         := vsmensagem || vschar ||
                                                  'RELACIONAMENTO ENTRE PLANO DE PAGAMENTO ETICO ' ||
                                                  p_regpedido.codplpagetico ||
                                                  ' E COBRANCA '|| p_regpedido.codcob ||
                                                  ' NAO CADASTRADO;';
                            p_regpedido.valido := false;


                        else

                          vbvalidacob := false;

                        end if;
                      end if;



                if vbvalidacob = true then

                --12 Plano de Pagamento Restritivo do cliente
                select count(*)
                  into vicontador
                  from pcplpagcli
                 where codcli = p_regpedido.codcli;

                if vicontador <> 0 then

                  select count(*)
                    into vicontador
                    from pcplpagcli
                   where codcli = p_regpedido.codcli
                     and codplpag = p_regpedido.codplpagetico;

                  if vicontador = 0 then
                    if vsmensagem is not null then
                      vschar := '#';
                    else
                      vschar := null;
                    end if;
                    vsmensagem         := vsmensagem || vschar ||
                                          'PLANO DE PAGAMENTO ETICO ' ||
                                          p_regpedido.codplpagetico ||
                                          ' NAO CADASTRADO PARA ESTE CLIENTE;';
                    p_regpedido.valido := false;

                  end if;


                end if;

               end if;

               /* -- DDMEDICA-675 - SUBSTITUIIDO POR NOVA FUNÇÃO ---------------------------
                if p_regplpagetico.codfilial is not null and
                   p_regplpagetico.codfilial <> '99' and
                   p_regplpagetico.codfilial <> p_regpedido.codfilial then

                  IF vsmensagem IS NOT NULL THEN
                    vschar := '#';
                  ELSE
                    vschar := NULL;
                  END IF;

                  vsmensagem         := vsmensagem || vschar ||
                                        'PLANO DE PAGAMENTO ETICO' ||
                                        p_regpedido.codplpagetico ||
                                        ' NAO EXISTE PARA A FILIAL ' ||
                                        p_regpedido.codfilial || ';';

                  p_regpedido.valido := FALSE;

                end if;
                -- DDMEDICA-675 - SUBSTITUIIDO POR NOVA FUNÇÃO ---------------------------*/

                -- INICIO: DDMEDICA-675 - Validação da Filial do Plano de Pagamento
                -------------------------------------------------------------------
                BEGIN
                  INTEGRADORACOMPLE_MED.proc_validamarfilialplano(p_regpedido.origemped,
                                                                  p_regpedido.tipofv,
                                                                  p_regpedido.codfilial,
                                                                  p_regplpagetico.codplpag, -->> Plano Ético
                                                                  'E',
                                                                  p_regfilial.tipoimportacaovenda,
                                                                  vrRetValidacao.vvRejeitado,
                                                                  vrRetValidacao.vvMotivoRejeitado,
                                                                  vrRetValidacao.vvObservacao,
                                                                  vrRetValidacao.vvRetJson,
                                                                  vrRetValidacao.vvGravarComoBloqueado,
                                                                  vrRetValidacao.vnCodMotivoNaoAtend);
                  IF (vrRetValidacao.vvRejeitado = 'S') THEN

                    -- Se grava o Pedido como Bloqueado
                    IF (NVL(vrRetValidacao.vvGravarComoBloqueado,'N') = 'S') THEN
                       p_regpedido.posicao       := 'B';
                       p_regpedido.motivoposicao := vrRetValidacao.vvMotivoRejeitado;
                       p_regpedido.log           := p_regpedido.log || CHR(13) || vrRetValidacao.vvMotivoRejeitado;
                       -- Não tinha implementação para p_regpedido.codmotivo
                       -- Atualiza Mensagem
                       P_ADD_MENSAGEM('Bloqueio ' || vrRetValidacao.vnCodMotivoNaoAtend || ': ' || vrRetValidacao.vvObservacao,
                                      NULL, -->> Não altera a variável p_regpedido.codmotivonaoatend
                                      vsmensagem,
                                      p_regpedido.codmotivonaoatend);
                    -- Se Rejeita o Pedido
                    ELSE
                      -- Não é mais Válido
                      p_regpedido.valido := False;
                      -- Atualiza Mensagem
                      P_ADD_MENSAGEM('Rejeição ' || vrRetValidacao.vnCodMotivoNaoAtend || ': ' || vrRetValidacao.vvObservacao,
                                     vrRetValidacao.vnCodMotivoNaoAtend,
                                     vsmensagem,
                                     p_regpedido.codmotivonaoatend);
                    END IF;

                  END IF;

                EXCEPTION
                  WHEN OTHERS THEN
                    -- Não é mais Válido
                    p_regpedido.valido := False;
                    -- Atualiza Mensagem
                    P_ADD_MENSAGEM('Erro ao validar filial do plano de pagamento ético do pedido. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                                   vrRetValidacao.vnCodMotivoNaoAtend,
                                   vsmensagem,
                                   p_regpedido.codmotivonaoatend);
                END;
                -- FIM: DDMEDICA-675 - Validação da Filial do Plano de Pagamento
                ----------------------------------------------------------------

                if p_regplpagetico.tiporestricao = 'OP' and p_regplpagetico.codrestricao <> 4 then
                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem         := vsmensagem || vschar ||
                                        'PLANO DE PAGAMENTO ETICO ' ||
                                        p_regpedido.codplpagetico ||
                                        ' COM RESTRICAO POR ORIGEM DE PEDIDO NAO ACEITA FORCA DE VENDAS ;';

                  p_regpedido.valido := false;

                end if;

                if p_regplpagetico.tiporestricao = 'RA' and
                   p_regplpagetico.codrestricao <> p_regcliente.codatv1 then

                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;

                  vsmensagem         := vsmensagem || vschar ||
                                        'PLANO DE PAGAMENTO ETICO ' ||
                                        p_regpedido.codplpagetico ||
                                        ' COM RESTRICAO POR RAMO DE ATIVIDADE NAO ACEITA CODIGO ATIVIDADE: ' ||
                                        p_regcliente.codatv1 || ';';

                  p_regpedido.valido := false;

                end if;

               /* MED-1499  Melhora Mensagens - Passado para a procedure de gravação do pedido
                if vbvalidacob = true then


                  -- verifica prazo do plano de pagamento
                  if p_regcliente.codplpag > 0 and p_regplpag.formaparcelamento <> 'V' then

                    -- MED-869 - Validar Cadastro do Plano Ético do Cliente
                    --if p_regplpagetico.numdias > p_regcliente.numdias then
                    if p_regplpagetico.numdias > vrDadosPlPagEticoCli.numdias then

                      if NVL(gregpcconsum.bloqprazomdvenda, 'N') = 'S' then

                        if vsmensagem is not null then
                          vschar := '#';
                        else
                          vschar := null;
                        end if;
                        vsmensagem         := vsmensagem || vschar ||
                                              'PRAZO DO PLANO DE PAGAMENTO ETICO DO PEDIDO ' || p_regpedido.codplpagetico || ' #' || -- MED-869
                                              'SUPERIOR AO PRAZO DO PLANO DE PAGAMENTO ETICO DO CLIENTE ' || p_regcliente.codplpagetico || ' #' || -- MED-869
                                              'PRAZO DO PEDIDO ' ||
                                              p_regplpagetico.numdias ||';'||
                                              ' PRAZO DO CLIENTE ' ||
                                              vrDadosPlPagEticoCli.numdias || ';'; -- MED-869

                        p_regpedido.valido := false;

                      end if;
                    end if;
                  end if;

                    if (vnprazomaximovenda < p_regplpagetico.numdias) then

                          if vsmensagem is not null then
                            vschar := '#';
                          else
                            vschar := null;
                          end if;

                          vsmensagem         := vsmensagem || vschar ||
                                                'PRAZO MAXIMO DA COBRANCA #' ||
                                                'INFERIOR AO PRAZO DO PLANO ETICO. #' ||
                                                'PRAZO MAXIMO DA COBRANCA: ' ||
                                                vnprazomaximovenda ||';'||
                                                'PRAZO DO PLANO ETICO: ' || p_regplpagetico.numdias || ';';

                          p_regpedido.valido := false;

                    end if;


                  if vsboleto = 'S' or p_regpedido.codcob = 'BK' then

                    if p_regplpagetico.vendabk = 'N' then

                      if vsmensagem is not null then
                        vschar := '#';
                      else
                        vschar := null;
                      end if;
                      vsmensagem         := vsmensagem || vschar ||
                                            'PLANO DE PAGAMENTO ETICO NAO ACEITA COBRANCA BK ' || ';';
                      p_regpedido.valido := false;

                    end if;

                  end if;


               end if;
               */

       -------------------------------------------------------------------------------------------------------------------------------------
       --valida plano de pagamento generico
          select count(*)
          into vicontador
          from pcplpag
          where codplpag = p_regpedido.codplpaggenerico;

            if vicontador = 0 then
              if vsmensagem is not null then
                vschar := '#';
              else
                vschar := null;
              end if;
              vsmensagem         := vsmensagem || vschar ||
                                    'PLANO DE PAGAMENTO GENERICO ' ||
                                    p_regpedido.codplpaggenerico || ' NAO CADASTRADO ;';
              p_regpedido.valido := false;
            else

              select codplpag,
                     nvl(numdias,0),
                     NVL(numitensminimo, 0),
                     NVL(numpr, 1) numpr,
                     obs,
                     NVL(pertxfim, 0),
                     prazo1,
                     prazo2,
                     prazo3,
                     prazo4,
                     prazo5,
                     prazo6,
                     prazo7,
                     prazo8,
                     prazo9,
                     prazo10,
                     prazo11,
                     prazo12,
                     NVL(tipoprazo, 'N'),
                     tipovenda,
                     NVL(vlminpedido, 0),
                     NVL(pcplpag.vendabk, 'N'),
                     NVL(tiporestricao, 'NR'),
                     codrestricao,
                     trim(codfilial),
                     pcplpag.formaparcelamento

                into p_regplpaggenerico
                from pcplpag
               where codplpag = p_regpedido.codplpaggenerico;

            end if;


           if (p_regplpaggenerico.formaparcelamento <> 'C') and
              (p_regplpaggenerico.formaparcelamento <> 'M') then

             if vsmensagem is not null then
                    vschar := '#';
             else
                    vschar := null;
              end if;
                  vsmensagem         := vsmensagem || vschar ||
                                        'PLANO DE PAGAMENTO GENERICO SÓ ACEITA PLANO TIPO CUSTOMIZADO/MENSAL ;';
                  p_regpedido.valido := false;

           end if;


                vbvalidacob := true;

                --tarefa 125968

                    select count(*)
                    into vicontador
                    from pccobplpag p
                    where p.codcob   = p_Regpedido.codcob;


                       if vicontador <> 0 then

                        select count(*)
                        into vicontador
                        from pccobplpag p
                        where p.codplpag = p_Regpedido.codplpaggenerico
                        and   p.codcob   = p_Regpedido.codcob;


                        if vicontador = 0 then

                            if vsmensagem is not null then
                              vschar := '#';
                            else
                              vschar := null;
                            end if;
                            vsmensagem         := vsmensagem || vschar ||
                                                  'RELACIONAMENTO ENTRE PLANO DE PAGAMENTO GENERICO ' ||
                                                  p_regpedido.codplpaggenerico ||
                                                  ' E COBRANCA '|| p_regpedido.codcob ||
                                                  ' NAO CADASTRADO;';
                            p_regpedido.valido := false;


                        else

                          vbvalidacob := false;

                        end if;
                      end if;



                if vbvalidacob = true then

                --12 Plano de Pagamento Restritivo do cliente
                select count(*)
                  into vicontador
                  from pcplpagcli
                 where codcli = p_regpedido.codcli;

                if vicontador <> 0 then

                  select count(*)
                    into vicontador
                    from pcplpagcli
                   where codcli = p_regpedido.codcli
                     and codplpag = p_regpedido.codplpaggenerico;

                  if vicontador = 0 then
                    if vsmensagem is not null then
                      vschar := '#';
                    else
                      vschar := null;
                    end if;
                    vsmensagem         := vsmensagem || vschar ||
                                          'PLANO DE PAGAMENTO GENERICO ' ||
                                          p_regpedido.codplpaggenerico ||
                                          ' NAO CADASTRADO PARA ESTE CLIENTE ;';
                    p_regpedido.valido := false;

                  end if;


                end if;

               end if;

               /* -- DDMEDICA-675 - SUBSTITUIIDO POR NOVA FUNÇÃO ---------------------------
                if p_regplpaggenerico.codfilial is not null and
                   p_regplpaggenerico.codfilial <> '99' and
                   p_regplpaggenerico.codfilial <> p_regpedido.codfilial then

                  IF vsmensagem IS NOT NULL THEN
                    vschar := '#';
                  ELSE
                    vschar := NULL;
                  END IF;

                  vsmensagem         := vsmensagem || vschar ||
                                        'PLANO DE PAGAMENTO GENERICO ' ||
                                        p_regpedido.codplpaggenerico ||
                                        ' NAO EXISTE PARA A FILIAL ' ||
                                        p_regpedido.codfilial || ';';

                  p_regpedido.valido := FALSE;

                end if;
                -- DDMEDICA-675 - SUBSTITUIIDO POR NOVA FUNÇÃO ---------------------------*/
                -- INICIO: DDMEDICA-675 - Validação da Filial do Plano de Pagamento
                -------------------------------------------------------------------
                BEGIN
                  INTEGRADORACOMPLE_MED.proc_validamarfilialplano(p_regpedido.origemped,
                                                                  p_regpedido.tipofv,
                                                                  p_regpedido.codfilial,
                                                                  p_regplpaggenerico.codplpag, -->> Plano Genérico
                                                                  'G',
                                                                  p_regfilial.tipoimportacaovenda,
                                                                  vrRetValidacao.vvRejeitado,
                                                                  vrRetValidacao.vvMotivoRejeitado,
                                                                  vrRetValidacao.vvObservacao,
                                                                  vrRetValidacao.vvRetJson,
                                                                  vrRetValidacao.vvGravarComoBloqueado,
                                                                  vrRetValidacao.vnCodMotivoNaoAtend);
                  IF (vrRetValidacao.vvRejeitado = 'S') THEN

                    -- Se grava o Pedido como Bloqueado
                    IF (NVL(vrRetValidacao.vvGravarComoBloqueado,'N') = 'S') THEN
                       p_regpedido.posicao       := 'B';
                       p_regpedido.motivoposicao := vrRetValidacao.vvMotivoRejeitado;
                       p_regpedido.log           := p_regpedido.log || CHR(13) || vrRetValidacao.vvMotivoRejeitado;
                       -- Não tinha implementação para p_regpedido.codmotivo
                       -- Atualiza Mensagem
                       P_ADD_MENSAGEM('Bloqueio ' || vrRetValidacao.vnCodMotivoNaoAtend || ': ' || vrRetValidacao.vvObservacao,
                                      NULL, -->> Não altera a variável p_regpedido.codmotivonaoatend
                                      vsmensagem,
                                      p_regpedido.codmotivonaoatend);
                    -- Se Rejeita o Pedido
                    ELSE
                      -- Não é mais Válido
                      p_regpedido.valido := False;
                      -- Atualiza Mensagem
                      P_ADD_MENSAGEM('Rejeição ' || vrRetValidacao.vnCodMotivoNaoAtend || ': ' || vrRetValidacao.vvObservacao,
                                     vrRetValidacao.vnCodMotivoNaoAtend,
                                     vsmensagem,
                                     p_regpedido.codmotivonaoatend);
                    END IF;

                  END IF;

                EXCEPTION
                  WHEN OTHERS THEN
                    -- Não é mais Válido
                    p_regpedido.valido := False;
                    -- Atualiza Mensagem
                    P_ADD_MENSAGEM('Erro ao validar filial do plano de pagamento genérico do pedido. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                                   vrRetValidacao.vnCodMotivoNaoAtend,
                                   vsmensagem,
                                   p_regpedido.codmotivonaoatend);
                END;
                -- FIM: DDMEDICA-675 - Validação da Filial do Plano de Pagamento
                ----------------------------------------------------------------

                if p_regplpaggenerico.tiporestricao = 'OP' and p_regplpaggenerico.codrestricao <> 4 then
                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem         := vsmensagem || vschar ||
                                        'PLANO DE PAGAMENTO GENERICO ' ||
                                        p_regpedido.codplpaggenerico ||
                                        ' COM RESTRICAO POR ORIGEM DE PEDIDO NAO ACEITA FORCA DE VENDAS ;';

                  p_regpedido.valido := false;

                end if;

                if p_regplpaggenerico.tiporestricao = 'RA' and
                   p_regplpaggenerico.codrestricao <> p_regcliente.codatv1 then

                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;

                  vsmensagem         := vsmensagem || vschar ||
                                        'PLANO DE PAGAMENTO GENERICO ' ||
                                        p_regpedido.codplpaggenerico ||
                                        ' COM RESTRICAO POR RAMO DE ATIVIDADE NAO ACEITA CODIGO ATIVIDADE : ' ||
                                        p_regcliente.codatv1 || ';';

                  p_regpedido.valido := false;

                end if;

               /* MED-1499  Melhora Mensagens - Passado para a procedure de gravação do pedido
                if vbvalidacob = true then


                  -- verifica prazo do plano de pagamento
                  if p_regcliente.codplpag > 0 then

                    -- MED-869 - Validar Cadastro do Plano Ético do Cliente
                    --if p_regplpaggenerico.numdias > p_regcliente.numdias then
                    if p_regplpaggenerico.numdias > vrDadosPlPagGenericoCli.numdias then

                      if NVL(gregpcconsum.bloqprazomdvenda, 'N') = 'S' then

                        if vsmensagem is not null then
                          vschar := '#';
                        else
                          vschar := null;
                        end if;
                        vsmensagem         := vsmensagem || vschar ||
                                              'PRAZO DO PLANO DE PAGAMENTO GENERICO DO PEDIDO ' || p_regpedido.codplpaggenerico || ' #' || -- MED-869
                                              'SUPERIOR AO PRAZO DO PLANO DE PAGAMENTO GENERICO DO CLIENTE ' || p_regcliente.codplpaggenerico || ' #' || -- MED-869
                                              'PRAZO DO PEDIDO ' ||
                                              p_regplpaggenerico.numdias ||';'||
                                              'PRAZO DO CLIENTE ' ||
                                              vrDadosPlPagGenericoCli.numdias || ';';

                        p_regpedido.valido := false;

                      end if;
                    end if;
                  end if;


                    if (vnprazomaximovenda < p_regplpaggenerico.numdias) then

                          if vsmensagem is not null then
                            vschar := '#';
                          else
                            vschar := null;
                          end if;

                          vsmensagem         := vsmensagem || vschar ||
                                                'PRAZO MAXIMO DA COBRANCA #' ||
                                                'INFERIOR AO PRAZO DO PLANO GENERICO. #' ||
                                                'PRAZO MAXIMO DA COBRANCA: ' ||
                                                vnprazomaximovenda ||';'||
                                                'PRAZO DO PLANO GENERICO: ' || p_regplpaggenerico.numdias || ';';

                          p_regpedido.valido := false;

                    end if;


                  if vsboleto = 'S' or p_regpedido.codcob = 'BK' then

                    if p_regplpaggenerico.vendabk = 'N' then

                      if vsmensagem is not null then
                        vschar := '#';
                      else
                        vschar := null;
                      end if;
                      vsmensagem         := vsmensagem || vschar ||
                                            'PLANO DE PAGAMENTO GENERICO NAO ACEITA COBRANCA BK' || ';';
                      p_regpedido.valido := false;

                    end if;

                  end if;


               end if;
               */


      if p_regpedido.valido = true then

             vsprazos := null;
             vicont   := 0;
             vnprazototal := 0;

              for reg in (   select prazo
                            from ( select p.prazo1 prazo
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union
                                   select p.prazo2
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union
                                   select p.prazo3
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union
                                   select p.prazo4
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union
                                   select p.prazo5
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union
                                   select p.prazo6
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union
                                   select p.prazo7
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union
                                   select p.prazo8
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union
                                   select p.prazo9
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union
                                   select p.prazo10
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union
                                   select p.prazo11
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union
                                   select p.prazo12
                                   from pcplpag p
                                   where codplpag = p_regplpagetico.codplpag
                                   union

                                   select p.prazo1
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag
                                   union
                                   select p.prazo2
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag
                                   union
                                   select p.prazo3
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag
                                   union
                                   select p.prazo4
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag
                                   union
                                   select p.prazo5
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag
                                   union
                                   select p.prazo6
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag
                                   union
                                   select p.prazo7
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag
                                   union
                                   select p.prazo8
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag
                                   union
                                   select p.prazo9
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag
                                   union
                                   select p.prazo10
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag
                                   union
                                   select p.prazo11
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag
                                   union
                                   select p.prazo12
                                   from pcplpag p
                                   where codplpag = p_regplpaggenerico.codplpag)
                            where rownum < 13 ) loop

                vicont := vicont + 1;
                vnprazototal := vnprazototal + reg.prazo;

              if vsprazos is null then
                 vsprazos := reg.prazo;
              else
                 vsprazos := vsprazos||';'||reg.prazo  ;
              end if;

            end loop;


           p_regplpag.prazo1 := substr(vsprazos,1,instr(vsprazos,';',1)-1);
           vsprazos := substr(vsprazos,instr(vsprazos,';',1) + 1,35);
           p_regplpag.prazo2 := substr(vsprazos,1,instr(vsprazos,';',1)-1);
           vsprazos := substr(vsprazos,instr(vsprazos,';',1) + 1,33);
           p_regplpag.prazo3 := substr(vsprazos,1,instr(vsprazos,';',1)-1);
           vsprazos := substr(vsprazos,instr(vsprazos,';',1) + 1,31);
           p_regplpag.prazo4 := substr(vsprazos,1,instr(vsprazos,';',1)-1);
           vsprazos := substr(vsprazos,instr(vsprazos,';',1) + 1,29);
           p_regplpag.prazo5 := substr(vsprazos,1,instr(vsprazos,';',1)-1);
           vsprazos := substr(vsprazos,instr(vsprazos,';',1) + 1,27);
           p_regplpag.prazo6 := substr(vsprazos,1,instr(vsprazos,';',1)-1);
           vsprazos := substr(vsprazos,instr(vsprazos,';',1) + 1,25);
           p_regplpag.prazo7 := substr(vsprazos,1,instr(vsprazos,';',1)-1);
           vsprazos := substr(vsprazos,instr(vsprazos,';',1) + 1,23);
           p_regplpag.prazo8 := substr(vsprazos,1,instr(vsprazos,';',1)-1);
           vsprazos := substr(vsprazos,instr(vsprazos,';',1) + 1,21);
           p_regplpag.prazo9 := substr(vsprazos,1,instr(vsprazos,';',1)-1);
           vsprazos := substr(vsprazos,instr(vsprazos,';',1) + 1,19);
           p_regplpag.prazo10 := substr(vsprazos,1,instr(vsprazos,';',1)-1);
           vsprazos := substr(vsprazos,instr(vsprazos,';',1) + 1,17);
           p_regplpag.prazo11 := substr(vsprazos,1,instr(vsprazos,';',1)-1);
           vsprazos := substr(vsprazos,instr(vsprazos,';',1) + 1,15);
           p_regplpag.prazo12 := substr(vsprazos,1,3);

           p_regpedido.prazomedio := vnprazototal / vicont;


      end if;


       if (vsmensagem is not null) then
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       null,
                       null,
                       p_regpedido.cgccli,
                       null,
                       null,
                       null,
                       p_regpedido.codusur,
                       p_regpedido.dtaberturapedpalm,
                       null,
                       '2',
                       vsmensagem||';',
                       null,
                       null);

    end if;

   exception
    when others then
      p_regpedido.valido := false;
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       null,
                       null,
                       p_regpedido.cgccli,
                       null,
                       null,
                       null,
                       p_regpedido.codusur,
                       p_regpedido.dtaberturapedpalm,
                       null,
                       '2',
                       'Erro ao validar planos de pagto Medicamentos : '||sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM ||';',
                       null,
                       null);

   end proc_validaplanosmed;


procedure proc_validavenctos(p_regpedido in out t_cabped,
                              p_regplpag  in out t_planodepagamento,
                              p_regcliente in t_clientepedido,
                              p_regfilial  in t_filial,
                              p_mensagem  out varchar2) is

   vicont      number;
   vbvalido    boolean;
   vsmensagem  varchar2(1000);
   vicontparc  number;
   viparcela   number;
   vddatainicio date;
   vddataaux    date;
   vndif       number;
   vndiftot    number;
   vicontador  number;
   vnprazomedio number;
   vddtvenc     date;

 begin

     vsmensagem := null;
     vicont := 0;
     vbvalido := true;

     select count(*)
     into vicont
     from pcpedcvctofv p
     where p.numpedrca  = p_regpedido.numpedrca
     and   p.codusur    = p_Regpedido.codusur
     and   p.cgccli     = p_regpedido.cgccli
     and   p.dtaberturapedpalm = p_regpedido.dtaberturapedpalm;




     if vicont > 0 then



          if vicont > p_regplpag.numparcelas    then

                vbvalido := false;

                   vsmensagem := 'Numero de parcelas enviadas é maior que o número de parcelas permitidas';

          end if;



        if vbvalido = true then

         viparcela := 0;

         for reg in ( select p.numparcela,p.dtvenc
                       from pcpedcvctofv p
                       where p.numpedrca  = p_regpedido.numpedrca
                       and   p.codusur    = p_Regpedido.codusur
                       and   p.cgccli     = p_regpedido.cgccli
                       and   p.dtaberturapedpalm = p_regpedido.dtaberturapedpalm
                       order by numparcela  ) loop

                viparcela := viparcela + 1;

              if viparcela = 1 then

                vddatainicio := trunc(sysdate);
              else

                vddatainicio :=  vddataaux;

              end if;

          if vicont = 1 then --parcela unica



                    if reg.dtvenc > (vddatainicio + p_regplpag.numdias)  then
                       vbvalido := false;


                          if vsmensagem is null then

                            vsmensagem := 'Parcela : '||reg.numparcela||' enviada está com data de vencimento maior que o permitido : '|| to_date(vddatainicio + p_regplpag.numdias,'dd/mm/yyyy');

                          else

                            vsmensagem := vsmensagem||CHR(13)||' Parcela : '||reg.numparcela||' enviada está com data de vencimento maior que o permitido : '|| to_date(vddatainicio + p_regplpag.numdias,'dd/mm/yyyy');

                          end if;


                    end if;



              else


              if reg.dtvenc < (vddatainicio + p_regplpag.diasminparcela)  then

                  vbvalido := false;

                    if vsmensagem is null then

                      vsmensagem := 'Parcela : '||reg.numparcela||' enviada está com data de vencimento menor que o permitido : '|| to_date(vddatainicio + p_regplpag.diasminparcela,'dd/mm/yyyy');

                    else

                      vsmensagem := vsmensagem||CHR(13)||' Parcela : '||reg.numparcela||' enviada está com data de vencimento menor que o permitido : '|| to_date(vddatainicio + p_regplpag.diasminparcela,'dd/mm/yyyy');

                    end if;

              end if;

              if reg.dtvenc > (vddatainicio + p_regplpag.diasmaxparcela)  then
                 vbvalido := false;


                    if vsmensagem is null then

                      vsmensagem := 'Parcela : '||reg.numparcela||' enviada está com data de vencimento maior que o permitido : '|| to_date(vddatainicio + p_regplpag.diasmaxparcela,'dd/mm/yyyy');

                    else

                      vsmensagem := vsmensagem||CHR(13)||' Parcela : '||reg.numparcela||' enviada está com data de vencimento maior que o permitido : '|| to_date(vddatainicio + p_regplpag.diasmaxparcela,'dd/mm/yyyy');

                    end if;


              end if;
            end if;

              if reg.numparcela <= 0 then
                 vbvalido := false;


                    if vsmensagem is null then

                      vsmensagem := 'Parcela : '||reg.numparcela||' enviada está com numero inválido !';

                    else

                      vsmensagem := vsmensagem||CHR(13)||' Parcela : '||reg.numparcela||' enviada está com numero inválido !';

                    end if;


              end if;



             vddataaux := reg.dtvenc;

         end loop;

         if vbvalido = true then

            begin

             insert into pcpedcvcto (numped,numparcela,dtvenc)
             select p_regpedido.numped,p.numparcela,p.dtvenc
             from pcpedcvctofv p
             where p.numpedrca  = p_regpedido.numpedrca
               and   p.codusur    = p_Regpedido.codusur
               and   p.cgccli     = p_regpedido.cgccli
               and   p.dtaberturapedpalm = p_regpedido.dtaberturapedpalm
             order by numparcela ;
            exception when others then

               vbvalido := false;

                    if vsmensagem is null then

                      vsmensagem := 'Erro ao inserir na tabela pcpedcvcto '||SQLCODE||' - '||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM ;

                    else

                      vsmensagem := vsmensagem||CHR(13)||'Erro ao inserir na tabela pcpedcvcto '||SQLCODE||' - '||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM ;

                    end if;


            end;


         end if;


        end if;

     --não foi enviado registro na pcpedcvctofv

     else

        if p_regfilial.aceitavendasemdtvencfv = 'S' then

           viparcela := 0;

           for reg in 1 .. p_regplpag.numparcelas loop

               viparcela := viparcela + 1;

                if viparcela = 1 then

                  vddatainicio := trunc(sysdate);
                else

                  vddatainicio :=  vddataaux;

                end if;

                  vddtvenc := vddatainicio + p_regplpag.diasminparcela;

                 begin

                  insert into pcpedcvcto (numped,numparcela,dtvenc)
                  values (p_regpedido.numped, viparcela,vddtvenc);
                 exception when others then

                     vbvalido := false;

                      if vsmensagem is null then

                        vsmensagem := 'Erro ao inserir na tabela pcpedcvcto '||SQLCODE||' - '||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM ;

                      else

                        vsmensagem := vsmensagem||CHR(13)||'Erro ao inserir na tabela pcpedcvcto '||SQLCODE||' - '||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM ;

                      end if;


                 end;


                   vddataaux := vddtvenc;

               end loop;

            else

                 vbvalido := false;

                    if vsmensagem is null then

                      vsmensagem := 'De acordo com parâmetro aceitavendasemdtvencfv é ncessário o envio de dados pcpedcvctoFV ';

                    else

                      vsmensagem := vsmensagem||CHR(13)||'De acordo com parâmetro aceitavendasemdtvencfv é ncessário o envio de dados pcpedcvctoFV ' ;

                    end if;



            end if;




     end if;


      if vbvalido = true then

     --prazo medio



       vndif := 0;
       vndiftot := 0;
       vicontparc := 0;

           for regprazo in (select numparcela,dtvenc
                            from pcpedcvcto
                            where numped = p_regpedido.numped) loop

                vndif := regprazo.dtvenc - trunc(sysdate);

                vndiftot := vndiftot + vndif;

                vicontparc := vicontparc + 1;

           end loop;

          vnprazomedio := trunc(vndiftot/ vicontparc);

        if vnprazomedio > p_regplpag.numdias then

           vbvalido := false;

          if vsmensagem is null then

            vsmensagem := 'Prazo medio: '||vnprazomedio||' maior que o permitido : '|| p_regplpag.numdias;

          else

            vsmensagem := vsmensagem||CHR(13)||'Prazo medio: '||vnprazomedio||' maior que o permitido : '|| p_regplpag.numdias;

          end if;

        else
          p_regpedido.prazomedio := vnprazomedio;
        end if;

        p_regpedido.percplpag := null;


         select count(*)
         into vicontador
         from PCPLPAGVARIAVELJUROS p
         where p.codplpag = p_regplpag.codplpag
         and   p.prazomedioinicial <= p_regpedido.prazomedio
         and   p.prazomediofinal   >= p_regpedido.prazomedio;

         if vicontador = 1 then

           select nvl(p.percdesc,0)
           into p_regpedido.percplpag
           from PCPLPAGVARIAVELJUROS p
           where p.codplpag = p_regplpag.codplpag
           and   p.prazomedioinicial <= p_regpedido.prazomedio
           and   p.prazomediofinal   >= p_regpedido.prazomedio;

         end if;



        select count(*)
        into vicontador
        from pcplpag p
        where codplpag = 99;

        if vicontador = 1 then

            select p.prazo1,p.prazo2,p.prazo3,p.prazo4,p.prazo5,p.prazo6,p.prazo7,p.prazo8,p.prazo9,p.prazo10,p.prazo11,p.prazo12
            into p_regplpag.prazo1,p_regplpag.prazo2,p_regplpag.prazo3,p_regplpag.prazo4,p_regplpag.prazo5,p_regplpag.prazo6,
                 p_regplpag.prazo7,p_regplpag.prazo8,p_regplpag.prazo9,p_regplpag.prazo10,p_regplpag.prazo11,p_regplpag.prazo12
            from pcplpag p
            where codplpag =99;
        end if;


   end if;

   if vbvalido = false then

      p_regpedido.valido := false;
      p_mensagem := vsmensagem;

   end if;



 end proc_validavenctos;

procedure proc_pcparamfilial (p_codfilial in pcfilial.codigo%type,
                              p_nome       in pcparamfilial.nome%type,
                              p_padrao     in pcparamfilial.valor%type,
                              p_valor      out pcparamfilial.valor%type) is

  vsnome      pcparamfilial.nome%type;

 begin

   vsnome := upper(trim(p_nome));


      begin
      select nvl(p.valor,p_padrao)
      into p_valor
      from pcparamfilial p
      where upper(trim(p.nome)) = vsnome
      and  p.codfilial = p_codfilial;
      exception

      when no_Data_found then

        BEGIN

          select nvl(p.valor,p_padrao)
          into p_valor
          from pcparamfilial p
          where upper(trim(p.nome)) = vsnome
          and  p.codfilial = '99';
        exception
          when no_data_found then

             p_valor := p_padrao;

        end;

      when others then
       p_valor  := p_padrao;

      end;



 end proc_pcparamfilial ;

-- DDMEDICA-4610
procedure proc_pcparamfilial_number (p_codfilial in pcfilial.codigo%type,
                                     p_nome       in pcparamfilial.nome%type,
                                     p_padrao     in pcparamfilial.valor%type,
                                     p_valor      out pcparamfilial.valor%type) is

  vsnome      pcparamfilial.nome%type;
  vnvalornum  number;

 begin

   vsnome := upper(trim(p_nome));


      begin
      select nvl(p.valor,p_padrao)
      into p_valor
      from pcparamfilial p
      where upper(trim(p.nome)) = vsnome
      and  p.codfilial = p_codfilial;
      exception

      when no_Data_found then

        BEGIN

          select nvl(p.valor,p_padrao)
          into p_valor
          from pcparamfilial p
          where upper(trim(p.nome)) = vsnome
          and  p.codfilial = '99';
        exception
          when no_data_found then

             p_valor := p_padrao;

        end;

      when others then
       p_valor  := p_padrao;

      end;
      
      begin
        vnvalornum := p_valor;
      exception
        when others then
          p_valor := REPLACE(NVL(p_valor,'0'),'.',',');
      end;

 end proc_pcparamfilial_number ;

  function func_HoraDigitacaoPedido(p_Regfilial in t_filial,
                                 p_mensagem  out varchar2 ) return Boolean is



  vbresult              boolean  := true;
  vdhorainicialimportacao date;
  vdhorafinalimportacao   date;

begin


  SELECT TO_DATE(
                 TO_CHAR( TRUNC( SYSDATE ), 'dd/mm/yyyy' )
              || TO_CHAR( horainicialimportacaoped, 'hh24:mi' )
             ,'dd/mm/yyyy hh24:mi'
               ) HoraInicialDigitacaoPed
        ,CASE GREATEST(
                TO_DATE(
                      TO_CHAR( TRUNC( SYSDATE ), 'dd/mm/yyyy' )
                   || TO_CHAR( horainicialimportacaoped, 'hh24:mi' )
                  ,'dd/mm/yyyy hh24:mi'
                      )
                     ,TO_DATE(
                            TO_CHAR( TRUNC( SYSDATE ), 'dd/mm/yyyy' )
                         || TO_CHAR( horafinalimportacaoped, 'hh24:mi' )
                        ,'dd/mm/yyyy hh24:mi'
                      )
                   )
                  WHEN TO_DATE(
                            TO_CHAR( TRUNC( SYSDATE ), 'dd/mm/yyyy' )
                         || TO_CHAR( horainicialimportacaoped, 'hh24:mi' )
                        ,'dd/mm/yyyy hh24:mi'
                      ) THEN TO_DATE(
                                  TO_CHAR( (  TRUNC( SYSDATE )
                                            + 1 ), 'dd/mm/yyyy' )
                               || TO_CHAR( horafinalimportacaoped, 'hh24:mi' )
                              ,'dd/mm/yyyy hh24:mi'
                            )
                  ELSE TO_DATE(
                            TO_CHAR( TRUNC( SYSDATE ), 'dd/mm/yyyy' )
                         || TO_CHAR( horafinalimportacaoped, 'hh24:mi' )
                        ,'dd/mm/yyyy hh24:mi'
                      )
               END HoraFinalDigitacaoPed
    into vdhorainicialimportacao,vdhorafinalimportacao
    FROM PCFILIAL
   WHERE CODIGO = p_Regfilial.codigo;

  p_mensagem := null;

  vbResult := (sysdate >= vdHoraInicialimportacao) and (sysdate <= vdHoraFinalimportacao);

   if vbresult = false then
      p_mensagem := 'Horário limite para digitação do pedido ultrapassado.#'||
      'Verifique rotina 535.';
   end if;

  return vbresult;

end func_HoraDigitacaoPedido;

