     IF (NVL(p_regfilial.tipocriticarestricaovendamed,'NA') = 'NA') THEN
       -- Se não existir exceção para tratar as restrições da 391, obedece o parâmetro antigo
       p_regfilial.tipocriticarestricaovendamed   := p_regfilial.tipoimportacaovenda;
       p_regfilial.r_tipocriticarestricaovendamed := p_regfilial.r_tipoimportacaovenda; -- MED-1499
     END IF;

     proc_pcparamfilial('99',
                        'MEDDIFACEITEPRECOMINIMOFV',
                        'N',
                         vvMedDifAceitePrecoMinimoFv);
     BEGIN
       p_regfilial.meddifaceiteprecominimofv := TO_NUMBER(REPLACE(NVL(vvMedDifAceitePrecoMinimoFv,'0'),',','.'));
     EXCEPTION
       WHEN OTHERS THEN
         p_regfilial.meddifaceiteprecominimofv := 0.01;
     END;

     -- DESC_BASE_RCA_PRM
     proc_pcparamfilial('99',
                        'TIPOCONFIGDEBCREDRCAPROMOMED',
                        'N',
                         p_regfilial.tipoconfigdebcredrcapromomed);

     -- REGRA EXCEÇÃO MED
     p_regfilial.usaregramanterdscpromodescfv := FUSA_REGRA_MEDICAMENTOS('99','USAREGRAMANTERDSCPROMODESCFV');

     -- HIS.00182.2016
     proc_pcparamfilial('99',
                        'MEDAPLICARDESCOMCLIPTABELA',
                        'N',
                         p_regfilial.medaplicardescomcliptabela);

     -- PCNIL
     proc_pcparamfilial(p_regpedido.codfilial,
                        'USADESCSIMPLESNAC',
                        'N',
                         p_regfilial.usadescsimplesnac);

     -- 5685.084449.2016
     proc_pcparamfilial('99',
                        'RESTRINGIRPROMOCAOFVMED',
                        'N',
                         p_regfilial.restringirpromocaofvmed);

     -- HIS.02787.2016
     proc_pcparamfilial(p_regpedido.codfilial,
                        'TRIBUTSAIDAORIGEMNACIMP',
                        'N',
                         p_regfilial.tributsaidaorigemnacimp);

     -- HIS.03831.2017 - Merge Acordo Preço
     proc_pcparamfilial('99',
                        'USARACRESCDESCACORDOPARCERIA',
                        'N',
                         p_regfilial.usaracrescdescacordoparceria);
     IF (FUSA_REGRA_MEDICAMENTOS('99','USAREGRAACRESCDESCACORDOPARC') = 'S') THEN
       p_regfilial.usaracrescdescacordoparceria := 'S';
     END IF;

     -- E-Commerce - MED-1822
     p_regfilial.ignpoliticaverbacmvecommerce := FUSA_REGRA_MEDICAMENTOS('99','IGNPOLITICAVERBACMVECOMMERCE');
     p_regfilial.somarrepasseprecoeccommerce  := FUSA_REGRA_MEDICAMENTOS('99','SOMARREPASSEPRECOECCOMMERCE');
     proc_pcparamfilial(p_regpedido.codfilial,
                        'TIPOCALCSTFONTE',
                        '2', -- Default 2 - Pelo Valor Líquido
                         p_regfilial.tipocalcstfonte);

     -- Parâmetro da Integradora para Rejeitar Itens Fora de Linha Sem Estoque
     vrParamIntegradoraMed.REJEITARITENSFORALINHASEMEST := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                                                    'REJEITARITENSFORALINHASEMEST',
                                                                                    'N');
     p_regfilial.rejeitaritensforalinhasemest := vrParamIntegradoraMed.REJEITARITENSFORALINHASEMEST;

     -- Parâmetro da Integradora para Validar Margem Mínima - MED-2079
     vrParamIntegradoraMed.VALIDARMARGEMMINIMA := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                                           'VALIDARMARGEMMINIMA',
                                                                           'N');
     p_regfilial.validarmargemminimaolpe := NVL(vrParamIntegradoraMed.VALIDARMARGEMMINIMA,'N');

     -- Parâmetros de Margem - MED-2079
     proc_pcparamfilial(p_regpedido.codfilial,
                        'PERCMARGEMMINVENDAMED',
                        'N',
                         p_regfilial.percmargemminvendamed);
     proc_pcparamfilial(p_regpedido.codfilial,
                        'TIPOVALIDMARGEMMINVENDAMED',
                        'N',
                         p_regfilial.tipovalidmargemminvendamed);

     -- Parâmetro da Integradora para aplicar Taxa do Plano de Pagamento nos Pedidos OL - MED-1613
     vrParamIntegradoraMed.APLICARTAXAPLPAGPEDIDOSOL := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                                                 'APLICARTAXAPLPAGPEDIDOSOL',
                                                                                 'N');
     p_regfilial.aplicartaxaplpagpedidosol := NVL(vrParamIntegradoraMed.APLICARTAXAPLPAGPEDIDOSOL,'N');

     -- Região Diferenciada da Integradora - MED-2371
     vrParamIntegradoraMed.REGIAODIFERENCIADATABPR := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                                               'REGIAODIFERENCIADATABPR',
                                                                               '0');
     BEGIN
       p_regfilial.regiaodiferenciadatabpr := TO_NUMBER(vrParamIntegradoraMed.REGIAODIFERENCIADATABPR);
     EXCEPTION
       WHEN OTHERS THEN
         p_regfilial.regiaodiferenciadatabpr := NULL;
     END;

     p_regfilial.precosemrepassefv          := FUSA_REGRA_MEDICAMENTOS('99','PRECOSEMREPASSEFV');
     p_regfilial.rejeitarpedpromoinvalidafv := FUSA_REGRA_MEDICAMENTOS('99','REJEITARPEDPROMOINVALIDAFV');

     -- DDMEDICA-2832
     proc_pcparamfilial('99',
                        'CON_UTILIZACONTROLEMEDICAMENTOS',
                        'N',
                         p_regfilial.con_utilizacontrolemedicamen);

     p_regfilial.utilizacalculostpacote := FUSA_REGRA_MEDICAMENTOS('99','UTILIZACALCULOSTPACOTE');


     vrParamIntegradoraMed.IGNORARPRAZOMEDIOCLIENTE := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                                               'IGNORARPRAZOMEDIOCLIENTE',
                                                                               'N');
     p_regfilial.IGNORARPRAZOMEDIOCLIENTE := NVL(vrParamIntegradoraMed.IGNORARPRAZOMEDIOCLIENTE,'N');
     
     -- DDMEDICA-6036
     proc_pcparamfilial('99',
                        'MEDPERMITEDISTRIBDIFRCA',
                        'N',
                         p_regfilial.medpermitedistribdifrca);     

     -- DDMEDICA-6049
     p_regfilial.usararredondamentodifprecost := FUSA_REGRA_MEDICAMENTOS('99','USARARREDONDAMENTODIFPRECOST');
     
     -- DDMEDICA-6666
     proc_pcparamfilial('99',
                        'CON_GERARBRINDEPEDBONIFIC',
                        'N',
                         p_regfilial.gerarbrindepedbonific);          
                         
     -- DDMEDICA-6900
     proc_pcparamfilial(p_regpedido.codfilial,
                        'CUSTO_PROM_MARKUP_ST',
                        'N',
                        p_regfilial.custo_prom_markup_st);

     -- DDMEDICA-6929                    
     vrParamIntegradoraMed.IGNORARACRESCIMOPFTRIBUT := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                                               'IGNORARACRESCIMOPFTRIBUT',
                                                                               'N');
     p_regfilial.IGNORARACRESCIMOPFTRIBUT := NVL(vrParamIntegradoraMed.IGNORARACRESCIMOPFTRIBUT,'N');
     
     -- DDMEDICA-7688              
     proc_pcparamfilial('99',
                        'PERMITEVENDACIMAPF',
                        'S',
                         p_regfilial.permitevendacimapf);
             
     -- DDVENDAS-33718
     proc_pcparamfilial(p_regpedido.codfilial,
                        'UTILIZATRIBENDENT',
                        'N',
                         p_regfilial.utilizatribendent);
                         
     -- Parâmetro da Integradora para Utilizar Venda por Embalagem - DDVENDAS-33713
     vrParamIntegradoraMed.VENDAPOREMBALAGEMINTEGRADORA := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                                                    'VENDAPOREMBALAGEMINTEGRADORA',
                                                                                    'N');
     p_regfilial.vendaporembalagemintegradora := NVL(vrParamIntegradoraMed.VENDAPOREMBALAGEMINTEGRADORA,'N');                         
     
     -- Parâmetro da Integradora CONCEDENTEFERTAdo Concedente da Oferta - DDVENDAS-33961
     IF (p_regpedido.integradora > 0) THEN
       vrParamIntegradoraMed.CONCEDENTEFERTA := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                                         'CONCEDENTEFERTA',
                                                                         'N');
       p_regfilial.concedenteferta := NVL(vrParamIntegradoraMed.CONCEDENTEFERTA,'N');
     END IF;    
     
     -- Parâmetro da Integradora de Sobreposição do Tipo Importação Vendas para Alvará Vencido - DDVENDAS-37313
     IF (p_regpedido.integradora > 0) THEN
       vrParamIntegradoraMed.SOBREPOSICAOBLOQUEIOALVARA := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                                                    'SOBREPOSICAOBLOQUEIOALVARA',
                                                                                    'NA');
       p_regfilial.sobreposicaobloqueioalvara := NVL(vrParamIntegradoraMed.SOBREPOSICAOBLOQUEIOALVARA,'NA');
     END IF;    

     proc_pcparamfilial(p_regpedido.codfilial,
                        'USARCACLIENTELINHAPORFILIALMED',
                        'N',
                         p_regfilial.usarcaclientelinhaporfilialmed);

  end proc_parametros;

  procedure proc_validarcabped(p_regpedido  in out t_cabped,
                               p_regcliente out t_clientepedido,
                               p_regrca     out t_rca,
                               p_regregiao  out t_regiaocliente,
                               p_regplpag   out t_planodepagamento,
                               p_regplpagetico out t_plpagetico,
                               p_regplpaggenerico out t_plpaggenerico,
                               p_Regcob     out t_pccob,
                               p_regfilial  out t_filial) is

    vicontador                 number;
    vsmensagem                 varchar2(32767):= null;
    vschar                     varchar2(1) default '#';
    vnnivelvendacli            pccob.nivelvenda%type;
    vsnumregiao                pcregiao.numregiao%type;
    vscodfilialnf              pcfilial.codigo%type;
    vbvalidacob                boolean    ;
    vbvalidanivelcob           boolean;
    vbexistepcplpagrestricao   boolean;
    vsmensagempcplpagrestricao varchar2(1000);
    vbexisteplpagcli           boolean;
    vsmensagemprazovariavel    varchar2(1000);
    --DDMEDICA-7385
    vsvlatend                  number;

    vstipo                     varchar2(20);
    vnnumregiaoclinf           pcregiao.numregiao%type;
    vncodcliprinc              pcclient.codcli%type;
    vddtwms                    pcpedc.dtwms%type;
    vnnumviasmapasep           pcpedc.numviasmapasep%type;

    vbhoraimportacaovalida  boolean;
    vsmensagemhora varchar2(300);
    vsacesso   pccontroi.acesso%type;

    -- HIS.01334.2014
    vvPodeComprarProduto       VARCHAR2(1);
    vvMotivoNaoPodeComprar     VARCHAR2(32000);
    vnQtdeLimiteAlvara         pcpedi.qt%type;

    -- 2438.022821.2017
    vnNumPedExistente          NUMBER;

    vnCodFreqEntrega           NUMBER;
  
  vvRetParamHrIntegradora PCPARAMINTEGRADORAMED.VALOR%TYPE;

    -- Array para Armazenar o JSON da Importação do Pedido - MED-1503
    TYPE TTJsonImportacaoPed   IS TABLE OF VARCHAR2(32000) INDEX BY BINARY_INTEGER;
    vtJsonImportacaoPed        TTJsonImportacaoPed;

    -- Record de Retorno das Validações - MED-1503
    TYPE TRecRetValidacao      IS RECORD(
         vvRejeitado           VARCHAR2(1),
         vvMotivoRejeitado     VARCHAR2(255),
         vvObservacao          VARCHAR2(32000),
         vvRetJson             VARCHAR2(32000),
         vvGravarComoBloqueado VARCHAR2(1),
         vnValorRetorno        NUMBER,
         vnCodMotivoNaoAtend   NUMBER);
    vrRetValidacao             TRecRetValidacao;

    -- Array para Armazenar o LOG da Importação do Pedido - MED-1895
    TYPE TTLogImportacaoPed    IS TABLE OF VARCHAR2(32000) INDEX BY BINARY_INTEGER;
    vtLogImportacaoPed         TTLogImportacaoPed;

    -- PROCEDIMENTO PARA GRAVAÇÃO DO JSON DE VALOR GERAL DO PEDIDO - MED-1503
    PROCEDURE PGRAVA_JSON_PED(pi_vMensagem IN VARCHAR2) IS
      viIdxJsonImpPed INTEGER;
    BEGIN
      viIdxJsonImpPed := NVL(vtJsonImportacaoPed.COUNT,0) + 1;

      vtJsonImportacaoPed(viIdxJsonImpPed) := pi_vMensagem;
    END PGRAVA_JSON_PED;

    -- PROCEDIMENTO PARA GRAVAÇÃO DO LOG DE VALOR GERAL DO ITEM - MED-1895
    PROCEDURE PGRAVA_LOG(pi_vMensagem IN VARCHAR2) IS
      vvMensagemLogImportacaoPed VARCHAR2(32000);
      viIdxLogImpPed             INTEGER;
    BEGIN
      viIdxLogImpPed := NVL(vtLogImportacaoPed.COUNT,0) + 1;

      vvMensagemLogImportacaoPed := '[' || TRIM(TO_CHAR(viIdxLogImpPed,'0000')) || '] ' || pi_vMensagem;

      vtLogImportacaoPed(viIdxLogImpPed) := vvMensagemLogImportacaoPed;
    END PGRAVA_LOG;

  begin

    p_regpedido.valido := true;
    p_regpedido.vbexisteitemcomdesc := false;

    vsmensagem         := null;

    if p_regpedido.orcamento = 'S' then
      vstipo := 'ORCAMENTO';

    elsif p_regpedido.orcamento = 'N' then
       vstipo := 'PEDIDO';

    else

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem         := vsmensagem || vschar ||
                                'VALOR INVALIDO PARA CAMPO ORCAMENTO, ACEITA APENAS S OU N;';

          p_regpedido.valido := false;
          p_regpedido.numpedorig := 0;


    end if;


    p_regpedido.posicao := 'P';


        if p_regpedido.orcamento = 'S' and p_regpedido.condvenda not in (1,10,13) then

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem         := vsmensagem || vschar ||
                                'PEDIDO MARCADO COMO ORCAMENTO SO ACEITA TIPO DE VENDA 1,10 ou 13 ;';

          p_regpedido.valido := false;
          p_regpedido.numpedorig := 0;


    end if;


      if p_regpedido.orcamento = 'S' and nvl(p_regpedido.numpedorig,0) <>  0 then

              if vsmensagem is not null then
                vschar := '#';
              else
                vschar := null;
              end if;
              vsmensagem         := vsmensagem || vschar ||
                                    'PEDIDO  ORCAMENTO NÃO PODE SER COMPLEMENTADO ;';
              p_regpedido.valido := false;
              p_regpedido.numpedorig := 0;



      end if;


    --01 Tratar complemento de pedido
    if (nvl(p_regpedido.numpedorig, 0) <> 0) then
      -- Verificar se pedido original existe
      select count(*)
        into vicontador
        from pcpedc,pcclient
       where numpedrca = p_regpedido.numpedorig
         and pcpedc.codusur = p_regpedido.codusur
         and nvl(pcpedc.brinde,'N') <> 'S'
         and pcpedc.numpedorigem is null
         and pcpedc.codcli     = pcclient.codcli
         and pcpedc.dtaberturapedpalm = p_Regpedido.dtaberturapedpalm
         and trim(replace(replace(replace(replace(replace(replace(pcclient.cgcent,' ',''), '.', ''),
                                                    ',',
                                                    ''),
                                            '-',
                                            ''),
                                    '/',
                                    ''),
                            '\',
                            '')) =  trim(replace(replace(replace(replace(replace(replace(p_regpedido.cgccli,' ',''), '.', ''),
                                                    ',',
                                                    ''),
                                            '-',
                                            ''),
                                    '/',
                                    ''),
                            '\',
                            ''))
      and pcclient.dtexclusao is null ;


      if vicontador <> 0 then
        select pcpedc.numped,
               pcpedc.codusur,
               pcpedc.codcli,
               pcpedc.DATA,
               pcpedc.codplpag,
               pcpedc.codcob,
               pcpedc.condvenda,
               pcpedc.posicao,
               pcpedc.dtwms,
               pcpedc.numviasmapasep,
               pcpedc.vlatend             --DDMEDICA-7385
          into p_regpedido.numped,
               p_regpedido.codusur,
               p_regpedido.codcli,
               p_regpedido.data,
               p_regpedido.codplpag,
               p_regpedido.codcob,
               p_regpedido.condvenda,
               p_regpedido.posicao,
               vddtwms,
               vnnumviasmapasep,
               vsvlatend                 --DDMEDICA-7385
        from pcpedc,pcclient
       where numpedrca = p_regpedido.numpedorig
         and pcpedc.codusur = p_regpedido.codusur
         and nvl(pcpedc.brinde,'N') <> 'S'
         and pcpedc.numpedorigem is null
         and pcpedc.codcli     = pcclient.codcli
         and pcpedc.dtaberturapedpalm = p_Regpedido.dtaberturapedpalm
         and trim(replace(replace(replace(replace(replace(replace(pcclient.cgcent,' ',''), '.', ''),
                                                    ',',
                                                    ''),
                                            '-',
                                            ''),
                                    '/',
                                    ''),
                            '\',
                            '')) =  trim(replace(replace(replace(replace(replace(replace(p_regpedido.cgccli,' ',''), '.', ''),
                                                    ',',
                                                    ''),
                                            '-',
                                            ''),
                                    '/',
                                    ''),
                            '\',
                            ''))
      and pcclient.dtexclusao is null ;

        if p_regpedido.posicao not in ('L', 'B', 'P') then
          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem         := vsmensagem || vschar ||
                                'PEDIDO ORIGINAL NAO PODE SER ALTERADO (POSICAO = ' ||
                                p_regpedido.posicao || ');';
          p_regpedido.valido := false;
          p_regpedido.numpedorig := 0;

          if p_Regpedido.codmotivonaoatend is null then
             p_Regpedido.codmotivonaoatend := 4;

          end if;


        else

          if gregpcconsum.montando = 'S' and p_Regpedido.posicao = 'L' then

            if vsmensagem is not null then
              vschar := '#';
            else
              vschar := null;
            end if;
            vsmensagem             := vsmensagem || vschar ||
                                      'SISTEMA WINTHOR ESTA ALOCADO PARA MONTAGEM DE CARGA;
                            Pedido ' ||
                                      p_regpedido.numpedorig ||
                                      ' NAO PODEM SER ALTERADO;';
            p_regpedido.numpedorig := 0;
            p_regpedido.valido := false;

          if p_Regpedido.codmotivonaoatend is null then
             p_Regpedido.codmotivonaoatend := 4;

          end if;


          end if;


          if trim(vddtwms) is not null or nvl(vnnumviasmapasep,0) > 0  then

            if vsmensagem is not null then
              vschar := '#';
            else
              vschar := null;
            end if;
            vsmensagem             := vsmensagem || vschar ||
                                      'Pedido em processo de WMS' ||
                                      p_regpedido.numpedorig ||
                                      ' NAO PODEM SER ALTERADO;';
            p_regpedido.numpedorig := 0;
            p_regpedido.valido := false;

          if p_Regpedido.codmotivonaoatend is null then
             p_Regpedido.codmotivonaoatend := 4;

          end if;


          end if;


        end if;

      else

        vsmensagem := vsmensagem || vschar ||
                      'PEDIDO ORIGINAL NAO EXISTENTE;PEDIDO ' ||
                      p_regpedido.numpedorig || ' NAO PODEM SER ALTERADO;';

        p_regpedido.numpedorig := 0;
        p_regpedido.valido     := false;

          if p_Regpedido.codmotivonaoatend is null then
             p_Regpedido.codmotivonaoatend := 4;

          end if;


      end if;

    else
      p_regpedido.numpedorig := 0;
    end if;

    -- Gravar Pedido como Bloqueado - Pedidos com Promoção
    IF (NVL(p_regpedido.codpromocaomed,0) > 0) AND
       (NVL(p_regpedido.gravarpedidocomobloqueado,'N') = 'S') THEN
      p_regpedido.posicao       := 'B';
      p_regpedido.motivoposicao := 'Pedido marcado - gravar como bloqueado';
      --p_regpedido.codmotivo     := ;
      p_regpedido.log           := p_regpedido.log || CHR(13) ||'Pedido marcado - gravar como bloqueado';
    END IF;


    -- MED-869
    RECOMPILAR_DEPENDENCIAS;


    -- Inicializa GERACP = 'N' = Não Gera Contas a Pagar
    p_regpedido.geracp := 'N';

    if p_regpedido.valido = true then

      if nvl(p_regpedido.numpedorig, 0) <> 0 then

        if p_regpedido.condvenda = 1 then
          p_regpedido.percvenda := 100;
          --> bonificacao
        elsif p_regpedido.condvenda = 5 then
          p_regpedido.percvenda := 100;
        elsif p_regpedido.condvenda = 7 then
          p_regpedido.percvenda := 100;
          p_Regpedido.posicao := 'L';
        -- Tipo Venda 9 existe no Módulo 23 - DDVENDAS-31111  
        elsif p_regpedido.condvenda = 9 then
          p_regpedido.percvenda := 100;
        elsif p_regpedido.condvenda = 10 then
          p_regpedido.percvenda := 100;
          -- Pesquisa GERACP dos Parâmetros se Transferência
          p_regpedido.geracp := FUNCOES_MED.func_ObterGeraCp(p_regpedido.codcli);

        elsif p_regpedido.condvenda = 13
        then
          p_regpedido.percvenda := 100;

         elsif p_regpedido.condvenda = 20
        then
          p_regpedido.percvenda := 100;


        else
          p_regpedido.condvenda := 1;
          p_regpedido.percvenda := 100;
        end if;

      else
        if p_regpedido.condvenda = 1 then
          p_regpedido.percvenda := 100;
          --> bonificacao
        elsif p_regpedido.condvenda = 5 then

              if gregpcconsum.bloquearpedbonific = 'S' then
                p_regpedido.posicao   := 'B';
              end if;

          p_regpedido.percvenda := 100;

          p_regpedido.motivoposicao := 'Pedido Bonificado';
          p_regpedido.codmotivo     := 7;
          p_regpedido.log           := p_regpedido.log || CHR(13) ||'Pedido Bonificado';

        elsif p_regpedido.condvenda = 7 then
          p_regpedido.percvenda := 100;
          p_Regpedido.posicao := 'L';

        -- Tipo Venda 9 existe no Módulo 23 - DDVENDAS-31111  
        elsif p_regpedido.condvenda = 9 then
          p_regpedido.percvenda := 100;

        elsif p_regpedido.condvenda = 10 then
          p_regpedido.percvenda := 100;
          -- Pesquisa GERACP dos Parâmetros se Transferência
          p_regpedido.geracp := FUNCOES_MED.func_ObterGeraCp(p_regpedido.codcli);

        elsif p_regpedido.condvenda = 13
        then
          p_regpedido.percvenda := 100;

        elsif p_regpedido.condvenda = 20
        then
          p_regpedido.percvenda := 100;


        else
          p_regpedido.posicao   := 'B';

          p_regpedido.motivoposicao := 'Pedido com tipo de venda não identificado,alterado para TV1';
          p_regpedido.log           := p_regpedido.log || CHR(13) ||'Pedido com tipo de venda não identificado,alterado para TV1';

          p_regpedido.condvenda := 1;
          p_regpedido.percvenda := 100;
        end if;

      end if;

     --Verifica existência da Condição de Venda para pedidos OL e PE
     if p_regpedido.codcondicaovenda is null and p_regpedido.tipofv in ( 'OL','PE') then

        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;
        vsmensagem         := vsmensagem || vschar ||
                              'CONDICAO DE VENDA NULA NAO PERMITIDA;';
