                   nvl(pcclient.bloqueiosefaz,'N'),
                   pcclient.usadebcredrca,
                   pcclient.codfornecfrete,
                   pcclient.participafarmaciapopular
                into p_regcliente
                from pcclient, pcpraca, pcplpag
               where pcclient.codpraca = pcpraca.codpraca
                 and pcclient.codplpag = pcplpag.codplpag(+)
                 and trim(replace(replace(replace(replace(replace(replace(cgcent,' ',''), '.', ''),
                                                        ',',
                                                        ''),
                                                '-',
                                                ''),
                                        '/',
                                        ''),
                                '\',
                                '')) =  trim(replace(replace(replace(replace(replace(replace(p_regpedido.cgccli,' ',''), '.', ''),
                                                        ',',
                                                        ''),
                                                '-',
                                                ''),
                                        '/',
                                        ''),
                                '\',
                                ''))
          and dtexclusao is  null
          and pcclient.codcli = p_Regpedido.codcli   ;

         -- Tributação por Endereço de Entrega - DDVENDAS-33718          
         IF (p_regfilial.utilizatribendent = 'S') THEN
           p_regcliente.estent := PKG_MEDICAMENTOS.F_DEFINIRUFDESTINOPEDIDO(p_regPedido.codcli,
                                                                            p_regfilial.utilizatribendent,
                                                                            p_regPedido.codendentcli,
                                                                            p_regcliente.estent);
           PGRAVA_LOG('UF Entrega: ' || p_regcliente.estent);
         END IF;

         --Seleciona dados da tabela de ClienteFilialMed Med [HIS.02655.2014]
         BEGIN
            SELECT 'S' AS ACHOU
                  ,NVL(CLIENTEFONTEST,'N') CLIENTEFONTEST
                  ,NVL(REPASSE,'N')        REPASSE
                  ,CODCOB
              INTO vvAchouClienteFilialMed
                  ,vvClienteFonteST
                  ,vvRepasse
                  ,vvCodCob
              FROM PCCLIENTFILIALMED
             WHERE CODCLI    = p_regPedido.codcli
               AND CODFILIAL = p_regPedido.codfilial;

         EXCEPTION WHEN NO_DATA_FOUND THEN
            vvAchouClienteFilialMed := 'N';

         END;

         --Se encontrou dados na tabela de ClienteFilialMed, substitui no Record
          if vvAchouClienteFilialMed = 'S' then
             p_regcliente.clientefontest := vvClienteFonteST;
             p_regcliente.repasse        := vvRepasse;
             if (TRIM(vvCodCob) IS NOT NULL) then
               p_regcliente.codcob := vvCodCob;
             end if;
          end if;

          exception when others then

            if vsmensagem is not null then
              vschar := '#';
            else
              vschar := null;
            end if;
            vsmensagem           := vsmensagem || vschar ||
                                    'ERRO AO BUSCAR CLIENTE DO PEDIDO;';
            p_regpedido.valido := false;

            if p_Regpedido.codmotivonaoatend is null then
               p_regpedido.codmotivonaoatend := 4;


            end if;


          end;

         end if;


      end if;

  END IF;
