                             vrRetValidacao.vnCodMotivoNaoAtend,
                             vsmensagem,
                             p_regpedido.codmotivonaoatend);
            END IF;

            -- Grava Json
            PGRAVA_JSON_PED(vrRetValidacao.vvRetJson);

          END IF;

        EXCEPTION
