            p_regpedido.valido := False;
            -- Atualiza Mensagem
            P_ADD_MENSAGEM('Erro ao validar filial do plano de pagamento do pedido. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                           vrRetValidacao.vnCodMotivoNaoAtend,
