                                                                         null);




        if vbexistepcplpagrestricao = true
        then
          if vsmensagem is not null
          then
            vschar := '#';
          else
            vschar := null;
          end if;

          vsmensagem         := vsmensagem || vschar || vsmensagempcplpagrestricao||' ;';

          if p_regfilial.tipoimportacaovenda = 'BP'  then
               p_Regpedido.posicao := 'B';

               p_regpedido.log       := p_regpedido.log || CHR(13) ||'Plano de Pagamento com restricao para esta venda';

               p_regpedido.motivoposicao := 'Plano de Pagamento com restricao para esta venda';
           else

              p_regpedido.valido := false;

                  if p_Regpedido.codmotivonaoatend is null then
                     p_regpedido.codmotivonaoatend := 6;


                  end if;

             end if;

        end if;

        if vbvalidacob = true then

        if nvl(p_regpedido.numpedorig, 0) = 0 then

          -- verifica prazo do plano de pagamento
          if p_regcliente.codplpag > 0 then

            /* MED-1499 - Usar nova Função
            if p_regpedido.prazomedio > p_regcliente.numdias and vbexisteplpagcli = false and p_regplpag.formaparcelamento <> 'V' then

              if NVL(gregpcconsum.bloqprazomdvenda, 'N') = 'S' then

