                   if gregpcconsum.aceitavendabloq = 'S' then
                      p_regpedido.posicao := 'B';
                      p_regpedido.motivoposicao := 'Prazo do plano superior ao prazo do cliente.';
                      p_regpedido.codmotivo := 13;
                   else
                     p_regpedido.valido := false;

                     if p_Regpedido.codmotivonaoatend is null then
                       p_regpedido.codmotivonaoatend := 7;
                     end if;
                   end if;


              end if;
            end if;
            */

            --------------------------------------------------------
            -- INICIO: MED-1499 - Validação do Prazo Médio do Pedido
            /*
