                   p_regpedido.posicao       := 'B';
                   p_regpedido.motivoposicao := 'Prazo do plano superior ao prazo do cliente.';
                   p_regpedido.codmotivo     := 13;
                   -- Atualiza Mensagem
                   P_ADD_MENSAGEM('Bloqueio 7: ' || vrRetValidacao.vvObservacao,
