                p_regpedido.valido := False;
                -- Atualiza Mensagem
                P_ADD_MENSAGEM('Erro ao validar prazo médio do pedido. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
