            ------------------------------------------------------

          end if;
        end if;
       end if;


     else

        if p_regpedido.codplpag <> 99 then

         if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;

          vsmensagem         := vsmensagem || vschar ||
                                'CLIENTE PARAMETRIZADO PARA UTILIZAR PLANO DE PAGAMENTO POR MEDICAMENTO;';


           p_regpedido.valido := false;

            if p_Regpedido.codmotivonaoatend is null then
               p_regpedido.codmotivonaoatend :=12 ;


            end if;
          end if;

     end if; -- FIM: nvl(p_regcliente.utilizaplpagmedicamento,'N') = 'N'


      -- 14 verificar tipo de cobranca do pedido

      select count(*)
        into vicontador
        from pccob
       where UPPER(trim(codcob)) = p_regpedido.codcob
       AND decode(p_regfilial.broker, 'S', nvl(cobrancabroker, 'N'), 'S') = 'S';


     if vbvalidacob = false then

      if vicontador = 0 then
        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;

        vsmensagem := vsmensagem || vschar || 'COBRANCA ' ||
                      p_regpedido.codcob || ' NAO CADASTRADA;';


        if p_Regpedido.codmotivonaoatend is null then
           p_regpedido.codmotivonaoatend := 12;


        end if;


      else

       -- busca nivel da cobranca do pedido
          select NVL(nivelvenda, 0),
                 NVL(prazomaximovenda, 0),
                 NVL(pccob.boleto, 'N'),
                 trim(codfilial),
                 nvl(pccob.cartao,'N')
            into p_Regcob
            from pccob
           where UPPER(trim(codcob)) = p_regpedido.codcob
           AND decode(p_regfilial.broker, 'S', nvl(cobrancabroker, 'N'), 'S') = 'S';
        end if;


     else


      if vicontador = 0 then
        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;

        vsmensagem := vsmensagem || vschar || 'COBRANCA ' ||
                      p_regpedido.codcob || ' NAO CADASTRADA;';

        -- verifica cobranca do cliente
        select count(*)
          into vicontador
          from pccob
         where UPPER(trim(codcob)) = p_regcliente.codcob
         ;

        if vicontador = 0 then
          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem         := vsmensagem || vschar || 'COBRANCA ' ||
                                p_regcliente.codcob || ' NAO CADASTRADA;';

          p_regpedido.valido := false;

          if p_Regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 12;


          end if;


        else

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;

          vsmensagem         := vsmensagem || vschar || 'COBRANCA ' ||
                                p_regpedido.codcob ||
                                ' NAO CADASTRADA#ALTERADA PARA ' ||
                                p_regcliente.codcob || ';';
          p_regpedido.codcob := p_regcliente.codcob;

        end if;

      else

        -- busca nivel da cobranca do pedido
        select NVL(nivelvenda, 0),
               NVL(prazomaximovenda, 0),
               NVL(pccob.boleto, 'N'),
               trim(codfilial),
               nvl(pccob.cartao,'N')
          into p_Regcob
          from pccob
         where UPPER(trim(codcob)) = p_regpedido.codcob
         AND decode(p_regfilial.broker, 'S', nvl(cobrancabroker, 'N'), 'S') = 'S';

        -- busca nivel da cobranca do cliente
        select count(*)
          into vicontador
          from pccob
         where UPPER(trim(codcob)) = p_regcliente.codcob
         ;

        if vicontador > 0 then

          select NVL(nivelvenda, 0)
            into vnnivelvendacli
            from pccob
           where UPPER(trim(codcob)) = p_regcliente.codcob
           ;

        else

          vnnivelvendacli := 0;
          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem         := vsmensagem || vschar ||
                                'NIVEL DA COBRANCA DO CLIENTE (' ||
                                p_regcliente.codcob || ') NAO LOCALIZADA;';

          p_regpedido.valido := false;

        if p_Regpedido.codmotivonaoatend is null then
           p_regpedido.codmotivonaoatend := 12;


        end if;


        end if;

       /* MED-1499 - Usar nova Função
        if (p_Regcob.nivelvenda < vnnivelvendacli) and vbvalidanivelcob = true then

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem         := vsmensagem || vschar ||
                                'NIVEL DE VENDA INFERIOR#' ||
                                'AO NIVEL DE VENDA DO CLIENTE#' ||
                                'NIVEL DA COBRANCA#' || p_Regcob.nivelvenda ||';'||
                                'NIVEL DO CLIENTE ' || vnnivelvendacli || ';';

          p_regpedido.valido := false;

            if p_Regpedido.codmotivonaoatend is null then
               p_regpedido.codmotivonaoatend :=12 ;


            end if;

        end if;
        */

        -------------------------------------------------------------
        -- INICIO: MED-1499 - Validação do Nível de Venda da Cobrança
        BEGIN
          INTEGRADORACOMPLE_MED.proc_validanivelcobranca(p_regcliente.codcob,
                                                         p_regpedido.codcob,
                                                         vbvalidanivelcob,
                                                         vrRetValidacao.vvRejeitado,
                                                         vrRetValidacao.vvMotivoRejeitado,
                                                         vrRetValidacao.vvObservacao,
                                                         vrRetValidacao.vvRetJson);
          IF (vrRetValidacao.vvRejeitado = 'S') THEN

            -- Não é mais Válido
            p_regpedido.valido := False;
            -- Atualiza Mensagem
            P_ADD_MENSAGEM('Rejeição 12: ' || vrRetValidacao.vvObservacao,
                           12,
                           vsmensagem,
                           p_regpedido.codmotivonaoatend);

            -- Grava Json
            PGRAVA_JSON_PED(vrRetValidacao.vvRetJson);

          END IF;

        EXCEPTION
          WHEN OTHERS THEN
            -- Não é mais Válido
            p_regpedido.valido := False;
            -- Atualiza Mensagem
            P_ADD_MENSAGEM('Erro ao validar nível de venda da cobrança. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                           12,
                           vsmensagem,
                           p_regpedido.codmotivonaoatend);
        END;
        -- FIM:  MED-1499 - Validação do Nível de Venda da Cobrança
        -----------------------------------------------------------

       /* MED-1499 - Usar nova Função
        if (p_regcob.prazomaximovenda < p_regplpag.numdias) and vbvalidanivelcob = true then

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;

          vsmensagem         := vsmensagem || vschar ||
                                'PRAZO MAXIMO DA COBRANCA#' ||
                                'INFERIOR AO PRAZO DO PLANO.#' ||
                                'PRAZO MAXIMO DA COBRANCA: ' ||
                                p_Regcob.prazomaximovenda ||';'||
                                'PRAZO DO PLANO: ' || p_regplpag.numdias || ';';

          p_regpedido.valido := false;

          if p_Regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 15;


          end if;


        end if;
        */

        -----------------------------------------------------------
        -- INICIO: MED-1499 - Validação do Prazo Máximo da Cobrança
        BEGIN
          INTEGRADORACOMPLE_MED.proc_validaprazomaxcobranca(p_regpedido.codcob,
                                                            p_regpedido.codplpag,
                                                            vbvalidanivelcob,
                                                            vrRetValidacao.vvRejeitado,
                                                            vrRetValidacao.vvMotivoRejeitado,
                                                            vrRetValidacao.vvObservacao,
                                                            vrRetValidacao.vvRetJson);
          IF (vrRetValidacao.vvRejeitado = 'S') THEN

            -- Não é mais Válido
            p_regpedido.valido := False;
            -- Atualiza Mensagem
            P_ADD_MENSAGEM('Rejeição 15: ' || vrRetValidacao.vvObservacao,
                           15,
                           vsmensagem,
                           p_regpedido.codmotivonaoatend);

            -- Grava Json
            PGRAVA_JSON_PED(vrRetValidacao.vvRetJson);

          END IF;

        EXCEPTION
          WHEN OTHERS THEN
            -- Não é mais Válido
            p_regpedido.valido := False;
            -- Atualiza Mensagem
            P_ADD_MENSAGEM('Erro ao validar prazo máximo da cobrança. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                           15,
                           vsmensagem,
                           p_regpedido.codmotivonaoatend);
        END;
        -- FIM:  MED-1499 - Validação do Prazo Máximo da Cobrança
        ---------------------------------------------------------

      end if;

    end if;

      if p_regcob.codfilial is not null and
         p_regcob.codfilial <> '99' and
         p_regcob.codfilial <> p_regpedido.codfilial then

        IF vsmensagem IS NOT NULL THEN
          vschar := '#';
        ELSE
          vschar := NULL;
        END IF;

        vsmensagem         := vsmensagem || vschar || 'COBRANCA ' ||
                              p_regpedido.codcob ||
                              ' NAO EXISTE PARA A FILIAL ' ||
                              p_regpedido.codfilial || ';';

                if p_regfilial.tipoimportacaovenda = 'BP'  then
                   p_Regpedido.posicao := 'B';

                   p_regpedido.log       := p_regpedido.log || CHR(13) ||'Cobranca nao existe para esta filial';

                   p_regpedido.motivoposicao := 'Cobranca nao existe para esta filial';
                else

                  p_regpedido.valido := false;

                  if p_Regpedido.codmotivonaoatend is null then
                     p_regpedido.codmotivonaoatend := 12;


                  end if;


                end if;


      end if;

     if vbvalidacob = true and vbvalidanivelcob = true then

      if p_Regcob.boleto = 'S' or p_regpedido.codcob = 'BK' then

        if p_regplpag.vendabk = 'N' then

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem         := vsmensagem || vschar ||
                                'PLANO DE PAGAMENTO NAO ACEITA COBRANCA BK' || ';';
          p_regpedido.valido := false;

        if p_Regpedido.codmotivonaoatend is null then
           p_regpedido.codmotivonaoatend := 15;


        end if;


        end if;

      end if;

     end if;



      -- 15verifica permissao para o CONDVENDA
      if p_regpedido.condvenda = 1 then

        if p_regcliente.condvenda1 = 'N' then

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;

          end if;
          vsmensagem         := vsmensagem || vschar ||
                                'TIPO DE VENDA 1 NAO PERMITIDA PARA ESTE CLIENTE;';
          p_regpedido.valido := false;

            if p_Regpedido.codmotivonaoatend is null then
               p_regpedido.codmotivonaoatend := 16;


            end if;


        end if;

      end if;

      if p_regpedido.condvenda = 5 then

        if p_regcliente.condvenda5 = 'N' then

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem         := vsmensagem || vschar ||
                                'TIPO DE VENDA 5 NAO PERMITIDA PARA ESTE CLIENTE;';
          p_regpedido.valido := false;

        if p_Regpedido.codmotivonaoatend is null then
           p_regpedido.codmotivonaoatend :=16 ;


        end if;

        end if;

      end if;

       IF p_regpedido.condvenda = 10
          THEN
            IF p_regcliente.condvenda10 = 'N'
            THEN
              IF vsmensagem IS NOT NULL
              THEN
                vschar := '#';
              ELSE
                vschar := NULL;
              END IF;

              vsmensagem         := vsmensagem || vschar ||
                                    'Tipo de Venda 10 nao permitida;';
              p_regpedido.valido := FALSE;
            END IF;
          END IF;


      -- verifica tipo de venda relacionada a cobranca.
      if p_regpedido.condvenda = 5 then

        if p_regpedido.codcob not in ('BNF', 'BNFT', 'BNFR', 'BNTR') then

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem         := vsmensagem || vschar || 'COBRANCA ' ||
                                p_regpedido.codcob ||
                                ' NAO PERMITIDA PARA O TIPO DE VENDA;';
          p_regpedido.valido := false;

        if p_Regpedido.codmotivonaoatend is null then
           p_regpedido.codmotivonaoatend := 15 ;


        end if;


        end if;

      end if;

      if p_regpedido.condvenda <> 5 then

        if p_regpedido.codcob in ('BNF', 'BNFT', 'BNFR', 'BNTR') then

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem         := vsmensagem || vschar || 'COBRANCA ' ||
                                p_regpedido.codcob ||
                                ' NAO PERMITIDA PARA O TIPO DE VENDA;';

          p_regpedido.valido := false;

        if p_Regpedido.codmotivonaoatend is null then
           p_regpedido.codmotivonaoatend := 15;


        end if;


        end if;
      end if;

     --tarefa 132020

     if nvl(p_Regpedido.codclinf,0) <> 0 then
         select count(*)
         into vicontador
         from pcclient
         where codcli = p_Regpedido.codclinf;

         if vicontador = 0 then

           p_Regpedido.codclinf := null;

         end if;
      end if;

    end if;
    end if;

    end if;

    -- Já foi definido mais acima, olhando se o RCA e Cliente movimentam Conta Corrente (Refatoração do Estoque)
    --p_regpedido.usacredrca           := gregpcconsum.usacredrca;

    p_regpedido.bonificaltdebcredrca := gregpcconsum.bonificaltdebcredrca;

    -- REGRA DE C/C DA BONIFICAÇÃO -- PCNIL
    IF (p_regpedido.condvenda = 5) AND
       (p_regpedido.codbnf    > 0) THEN
      IF (NVL(gregpcconsum.usacredrca,'N') = 'S') THEN
        BEGIN
          SELECT NVL(PCTIPOBONIFIC.MOVIMENTACCRCA,'N')
               , NVL(PCTIPOBONIFIC.MOVIMENTACCRCA,'N')
            INTO p_regpedido.usacredrca
               , p_regpedido.bonificaltdebcredrca
            FROM PCTIPOBONIFIC
           WHERE (PCTIPOBONIFIC.CODBNF = p_regpedido.codbnf);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            p_regpedido.bonificaltdebcredrca := gregpcconsum.bonificaltdebcredrca; -->> Mantém da 132
        END;
      END IF;
    END IF;

    p_regpedido.trocaaltdebcredrca   := gregpcconsum.trocaaltdebcredrca;
    p_Regpedido.crmaltdebcredrca     := gregpcconsum.crmaltdebcredrca;
    p_Regpedido.brokeraltdebcredrca  := gregpcconsum.brokeraltdebcredrca;
    p_Regpedido.tipomovccrca         := gregpcconsum.tipomovccrca;

    -- Se Pedido de OL ou PE pesquisa acordo de parceria
    p_regpedido.codacordoparceria := NULL;
    IF (p_regpedido.tipofv IN ('OL','PE')) THEN
      BEGIN
        SELECT A.CODACORDO
          INTO p_regpedido.codacordoparceria
          FROM PCACORDOPARCERIA A
             , PCACORDOPARCERIACLI AC
             , PCACORDOPARCERIAORIG AG
             , PCACORDOPARCERIAINTEGRADORA AI
         WHERE A.CODACORDO    = AC.CODACORDO
           AND A.CODACORDO    = AG.CODACORDO
           AND A.CODACORDO    = AI.CODACORDO
           AND AC.CODCLI      = p_regpedido.codcli                        -->> Acordo Restrito para o Cliente
           AND A.STATUS       IN ('L')                                    -->> Acordo Liberado
           AND AG.CODORIG     IN ('L','E')                                -->> Acordo Restrito para o Operador Logístico e Pedido Eletrônico
           AND AI.INTEGRADORA = p_regpedido.integradora                   -->> Acordo Restrito para a Integradora
           AND TRUNC(SYSDATE) BETWEEN A.DTVIGENCIAINI AND A.DTVIGENCIAFIN -->> Acordo Vigente
           AND ROWNUM = 1; -->> Caso tenha mais de um válido, pega o primeiro que achar
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          p_regpedido.codacordoparceria := NULL;
      END;
    END IF; -- Fim Condição Pedido OL e PE para Verificação de Acordo de Parceria

   /************************************
    -- Passado para a Gravação do Pedido
    ************************************
    -- Se Pedido de OL ou PE
    -- e a Integradora está configurada para gerar Pedidos sempre Bloqueados
    if (p_regpedido.tipofv IN ('OL','PE')) and
       (p_regpedido.gerapedbloq = 'S') then

      -- Registra Bloqueio Anterior
      IF (p_regpedido.posicao = 'B') AND
         (p_regpedido.codmotivo > 0) THEN
        proc_registralogbloqueio(p_regpedido.numpedrca,
                                 p_regpedido.codusur,
                                 p_regpedido.cgccli,
                                 p_regpedido.dtaberturapedpalm,
                                 p_regpedido.codmotivo,
                                 NULL,
                                 p_regpedido.motivoposicao);
      END IF;

      -- Altera posição do Pedido para Bloqueado
      p_regpedido.posicao := 'B';

      -- MED-861 - Gravar Motivo Fixo 704
      p_regpedido.codmotivo     := 704;
      p_regpedido.motivoposicao := 'Integradora configurada para gerar pedido bloqueado';
      p_regpedido.log           := p_regpedido.log || CHR(13) ||'Integradora configurada para gerar pedido bloqueado';

      -- Registra novo Motivo
      proc_registralogbloqueio(p_regpedido.numpedrca,
                               p_regpedido.codusur,
                               p_regpedido.cgccli,
                               p_regpedido.dtaberturapedpalm,
                               p_regpedido.codmotivo,
                               NULL,
                               p_regpedido.motivoposicao);
    end if;
    ************************************/

    -- Se Gravou Array de Log Específico - MED-2371
    IF (vtLogImportacaoPed.COUNT > 0) THEN
      FOR viIdxImportacaoPed IN vtLogImportacaoPed.FIRST..vtLogImportacaoPed.LAST LOOP
        -- Log Específico
        p_regpedido.logprocmed := p_regpedido.logprocmed || vtLogImportacaoPed(viIdxImportacaoPed) || CHR(13);
      END LOOP;
    END IF;

    -- Se Gravou Array de Log Específico - MED-1499
    IF (vtJsonImportacaoPed.COUNT > 0) THEN
      FOR viIdxImportacaoPed IN vtJsonImportacaoPed.FIRST..vtJsonImportacaoPed.LAST LOOP
        -- Log Específico
        p_regpedido.jsonprocmed := p_regpedido.jsonprocmed || vtJsonImportacaoPed(viIdxImportacaoPed) || CHR(13);
      END LOOP;
    END IF;

    -- registra log
    if (vsmensagem is not null) then
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       null,
                       null,
                       p_regpedido.cgccli,
                       null,
                       null,
                       null,
                       p_regpedido.codusur,
                       p_regpedido.dtaberturapedpalm,
                       null,
                       '2',
                       vsmensagem||';',
                       null,
                       null);

    end if;
  exception
    when others then
      p_regpedido.valido := false;
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       null,
                       null,
                       p_regpedido.cgccli,
                       null,
                       null,
                       null,
                       p_regpedido.codusur,
                       p_regpedido.dtaberturapedpalm,
                       null,
                       '2',
                       sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->001->' || SQLERRM ||';',
                       null,
                       null);

        if p_Regpedido.codmotivonaoatend is null then
           p_regpedido.codmotivonaoatend := 17;


        end if;


  end proc_validarcabped;


 /******************************************************************************
  INICIO: PACOTE MEDICAMENTOS NÃO USA CESTA BÁSICA - proc_verificaprecofixocesta
  ******************************************************************************
  procedure proc_verificaprecofixocesta (p_regitem    in out  t_itemped,
                                         p_regproduto in out  t_produto,
                                         p_regpedido  in      t_cabped,
                                         p_regcliente in      t_clientepedido,
                                         p_mensagem   out     varchar2,
                                         p_valido     out     boolean) is

      vicontador             number;
      vsutilizaprecofixorede pcprecocestac.utilizaprecofixorede%type;
      vncountitenscesta      number;
      vntotalcesta           number;
      vntotalcestatemp       number;
      vncodprecocesta        pcprecocestac.codprecocesta%type;


  begin

     p_mensagem := null;
     p_valido := false;

     select count(*)
     into vicontador
     from PCPRECOCESTAC p
     where p.dtexclusao is null
     and   p.dtinicio <= trunc(sysdate)
     and   p.dtfim    >= trunc(sysdate)
     and   p.codprodacab = p_regitem.codprod
     and   (p.codfilial   = p_regpedido.codfilial or p.codfilial is null)
     and   (p.numregiao   = p_regcliente.numregiao or p.numregiao is null)
     and   (p.codplpag    = p_regpedido.codplpag or p.codplpag is null)
     and   ( p.codcli      = decode(p.utilizaprecofixorede,'S',p_regcliente.codcliprinc,p_regpedido.codcli) or p.codcli is null);


     if vicontador > 0 then

         if vicontador > 1 then

             vntotalcesta := 0;

         -- verificar qual cesta utilizar ( buscando a que tem o menor preço fixo)
                 for reg in (select p.codprecocesta
                             from PCPRECOCESTAC p
                             where p.dtexclusao is null
                             and   p.dtinicio <= trunc(sysdate)
                             and   p.dtfim    >= trunc(sysdate)
                             and   p.codprodacab = p_regitem.codprod
                             and   (p.codfilial   = p_regpedido.codfilial or p.codfilial is null)
                             and   (p.numregiao   = p_regcliente.numregiao or p.numregiao is null)
                             and   (p.codplpag    = p_regpedido.codplpag or p.codplpag is null)
                             and   ( p.codcli      = decode(p.utilizaprecofixorede,'S',p_regcliente.codcliprinc,p_regpedido.codcli) or p.codcli is null)
                             ) loop



                --verifica se tem algum item da cesta que está sem preco fixo
                 select count(*)
                 into vicontador
                 from pcformprod f
                 where f.codprodacab   = p_regitem.codprod
                 and   not exists (select 'x' from pcprecocestai i
                                   where  i.codprodmp = f.codprodmp
                                   and i.codprecocesta = reg.codprecocesta);



                  --todos os itens da cesta estão com preço fixo
                 if vicontador = 0 then

                     vncountitenscesta := gvet_regitenscesta.count;

                     vntotalcestatemp := 0;

                        for i in 1 .. vncountitenscesta
                        loop

                          if p_regpedido.numped = gvet_regitenscesta(i).numped
                             and p_regitem.codprod = gvet_regitenscesta(i).codprodcesta
                          then




                                 for regi in ( select i.precofixo , p.qtprodmp
                                                        from pcprecocestai i,pcformprod p
                                                        where i.codprecocesta = reg.codprecocesta
                                                        and   i.codprodacab   = p_regitem.codprod
                                                        and   i.codprodmp     = gvet_regitenscesta(i).codprodmp
                                                        and   i.codprodacab   = p.codprodacab
                                                        and   i.codprodmp     = p.codprodmp ) loop



                                         vntotalcestatemp := nvl(vntotalcestatemp,0) + (regi.precofixo * regi.qtprodmp);

                                    end loop;
                               end if;

                           end loop;


                          if vntotalcestatemp < vntotalcesta or vntotalcesta = 0 then

                             vntotalcesta := vntotalcestatemp;
                             vncodprecocesta := reg.codprecocesta;

                          end if;

                     end if;

                 end loop;


          else --tem apenas 1 campanha de preço fixo de cesta

               select p.codprecocesta
               into vncodprecocesta
               from PCPRECOCESTAC p
               where p.dtexclusao is null
               and   p.dtinicio <= trunc(sysdate)
               and   p.dtfim    >= trunc(sysdate)
               and   p.codprodacab = p_regitem.codprod
               and   (p.codfilial   = p_regpedido.codfilial or p.codfilial is null)
               and   (p.numregiao   = p_regcliente.numregiao or p.numregiao is null)
               and   (p.codplpag    = p_regpedido.codplpag or p.codplpag is null)
               and   ( p.codcli      = decode(p.utilizaprecofixorede,'S',p_regcliente.codcliprinc,p_regpedido.codcli) or p.codcli is null)  ;

            end if;


             vntotalcesta := 0;

                --verifica se tem algum item da cesta que está sem preco fixo
                 select count(*)
                 into vicontador
                 from pcformprod f
                 where f.codprodacab   = p_regitem.codprod
                 and   not exists (select 'x' from pcprecocestai i
                                   where  i.codprodmp = f.codprodmp
                                   and i.codprecocesta = vncodprecocesta);



                  --todos os itens da cesta estão com preço fixo
                 if vicontador = 0 then

                     vncountitenscesta := gvet_regitenscesta.count;


                        for i in 1 .. vncountitenscesta
                        loop

                          if p_regpedido.numped = gvet_regitenscesta(i).numped
                             and p_regitem.codprod = gvet_regitenscesta(i).codprodcesta
                          then

                              for regi in ( select i.precofixo , p.qtprodmp
                                                  from pcprecocestai i,pcformprod p
                                                  where i.codprecocesta = vncodprecocesta
                                                  and   i.codprodacab   = p_regitem.codprod
                                                  and   i.codprodmp     = gvet_regitenscesta(i).codprodmp
                                                  and   i.codprodacab   = p.codprodacab
                                                  and   i.codprodmp     = p.codprodmp ) loop



                                   gvet_regitenscesta(i).ptabela := regi.precofixo;
                                   gvet_regitenscesta(i).pvenda  := regi.precofixo;

                                   vntotalcesta := nvl(vntotalcesta,0) + (regi.precofixo * regi.qtprodmp);

                              end loop;


                         end if;
                        end loop;

                        p_Regitem.pbaserca := nvl(vntotalcesta,p_regitem.pbaserca);
                        p_regproduto.ptabela := nvl(vntotalcesta,p_regproduto.ptabela);

                         if nvl(vntotalcesta,0) > 0 then
                          p_valido := true;
                         end if;

                 else
                 p_mensagem := 'Preço Fixo da cesta inválida. Será o utilizado o preço de tabela.';

                 end if;

     end if;

  end proc_verificaprecofixocesta;
 /******************************************************************************
  FIM: PACOTE MEDICAMENTOS NÃO USA CESTA BÁSICA - proc_verificaprecofixocesta
  ******************************************************************************/

 /************************************************************************
  INICIO: PACOTE MEDICAMENTOS NÃO USA CESTA BÁSICA - proc_validaitenscesta
  ************************************************************************
  procedure proc_validaitenscesta (p_regitem        in out  t_itemped,
                                   p_regorigempreco in out  t_origempreco,
                                   p_regproduto     in out  t_produto,
                                   p_regpedido      in t_cabped,
                                   p_regfilial      in t_filial,
                                   p_regregiao      in t_regiaocliente,
                                   p_regcliente     in t_clientepedido,
                                   p_regplpag       in t_planodepagamento,
                                   p_mensagem       out varchar2,
                                   p_validoprecofixocesta out boolean) is

    vnqtde                       number;
    vbecesta                     boolean;
    vnptabelacesta               number;
    vsmensagemcesta              varchar2(300);
    vnsubtotal                   number;
    vnperdesccesta               number := 0;
    vncount                      number := 0;


    vniva                        pcpedi.iva%type;
    vnptabela                    pcpedi.ptabela%type;
    vnpauta                      pcpedi.pauta%type;
    vnaliqicms1                  pcpedi.aliqicms1%type;
    vnaliqicms2                  pcpedi.aliqicms2%type;
    vnivafonte                   pctribut.ivafonte%type;
    vnaliqicms1fonte             pctribut.aliqicms1fonte%type;
    vnaliqicms2fonte             pctribut.aliqicms2fonte%type;
    vnpercbaseredst              pctribut.percbaseredst%type;
    vnpercbasered                pctribut.percbasered%type;
    vsusavalorultentbasest       pctribut.usavalorultentbasest%type;
    vsusavalorultentbasest2      pctribut.usavalorultentbasest2%type;
    vnvalorultent                pcest.valorultent%type;
    vnpercbaseredconsumidor      pctribut.percbaseredconsumidor%type;
    vsutilizapercbaseredpf       pctribut.utilizapercbaseredpf%type;
    vnpercbaseredstfonte         pctribut.percbaseredstfonte%type;

    vnperdesccusto               pctribut.perdesccusto%Type;
    vncustocont                  pcest.custocont%type;
    vncustorep                   pcest.custorep%type;
    vncodicmtab                  pctribut.codicmtab%type;


    vnvlcustofin                 pcpedi.vlcustofin%type;
    vnvlcustoreal                pcpedi.vlcustoreal%type;
    vnpvenda                     number;

    vnpcomint1                   pcprodut.pcomint1%type;
    vnpcomext1                   pcprodut.pcomext1%type;
    vnpcomrep1                   pcprodut.pcomrep1%type;
    vncodlinhaprod               pcprodut.codlinhaprod%type;
    vncodsec                     pcprodut.codsec%type;
    vncodepto                    pcprodut.codepto%type;
    vncodicmtabpf                pctribut.codicmtabpf%type;
    vnfreteespecial              pcprodut.freteespecial%type;
    vnpvendamaior                number;
    vnreg                        number;
    vndif                        number;
    vsmostrarpvendasemst         pctribut.mostrarpvendasemst%type;

    vsmensagemprecofixocesta     varchar2(32767);
    vbvalidoprecofixocesta       boolean;

    vsusapmcbasest               pctribut.usapmcbasest%type;
    vnprecomaxconsum             pcprodut.precomaxconsum%type;
    vncustonfsemst               pcest.custonfsemst%type;

    vsusabaseicmsreduzida        pctribut.usabaseicmsreduzida%type;
    vsisencaostorgaopub          pctribut.isencaostorgaopub%type;
    vsusabcrultent               pctribut.usabcrultent%type;
    vnbasebcr                    pcest.basebcr%type;
    vnstbcr                      pcest.stbcr%type;
    vnpautafonte                 pctribut.pautafonte%type;
    vvfarmaciapopular            pcprodut.farmaciapopular%type;
    vvusaptabelabasest           pctribut.usaptabelabasest%type;
    vncodmarca                   pcprodut.codmarca%type;
    vvutilizaprecofabrica        pcprodut.utilizaprecofabrica%type;

    vscodfilialnf                pcpedc.codfilialnf%type;
    vicontador                   number;
    vsmensagem                   varchar2(300);
    vschar                       varchar2(3);
    vncodst                      pctribut.codst%type;
    vnperacrescismopf            pctribut.peracrescismopf%type;
    vsAPLICAACRESCPJISENTA       pctribut.aplicaacrescpjisenta%type;

    vnqtminimaatacado            pcembalagem.qtminimaatacado%type;
    vnqtunit                     pcembalagem.qtunit%type;
    vnpvendaatac                 pcembalagem.pvendaatac%type;
    vnpvendaemb                  pcembalagem.pvenda%type;
    vnpoferta                    pcembalagem.poferta%type;
    vddtofertaini                pcembalagem.dtofertaini%type;
    vddtofertafim                pcembalagem.dtofertafim%type;
    vddtofertaatacini            pcembalagem.dtofertaatacini%type;
    vddtofertaatacfim            pcembalagem.dtofertaatacfim%type;
    vnpofertaatac                pcembalagem.pofertaatac%type;
    vstipocomissao               pcprodut.tipocomissao%type;
    vsclasse                     pcprodut.classe%type;
    vsusavlultentmediobasest     pctribut.usavlultentmediobasest%type;
    vnvlultentmes                pctabpr.vlultentmes%type;
    vsimportado                  pcprodut.importado%type;
    vsAGREGARIPICALCULOST        pctribut.agregaripicalculost%type;

   begin


         vncount := 0;

          for reg_itenscesta in (select p.codprodmp,
                                        p.qtprodmp,
                                        p.codauxiliarmp
                                 from pcformprod p
                                 where p.codprodacab = p_regitem.codprod)
          loop

            vncount := vncount + 1;

           if gregpcconsum.usatributacaoporuf = 'S' then

               if p_regpedido.codfilialnf is null then

                   if p_regcliente.codfilialnf is null then

                      vscodfilialnf := p_regpedido.codfilial;
                   else

                      vscodfilialnf := p_regcliente.codfilialnf;
                   end if;
                else

                  vscodfilialnf := p_regpedido.codfilialnf;
                end if;



                 select count(*)
                into vicontador
                from pctabtrib p
                where p.codprod     = reg_itenscesta.codprodmp
                and   p.codfilialnf = vscodfilialnf
                and   p.ufdestino   = p_Regcliente.estent;

                if vicontador = 0 then

                    if vsmensagem is not null then
                      vschar := '#';
                    else
                      vschar := null;
                    end if;

                    vsmensagem       := vsmensagem || vschar || 'Não encontrada tributação por estado para item da cesta';
                    p_regitem.valido := false;
                    p_regorigempreco.valido := false;

                else

                    select p.codst
                    into vncodst
                    from pctabtrib p
                    where p.codprod     = reg_itenscesta.codprodmp
                    and   p.codfilialnf = vscodfilialnf
                    and   p.ufdestino   = p_Regcliente.estent
                    and   rownum = 1;

                begin

                select decode(p_regitem.numpr
                                     ,1
                                     ,pctabpr.pvenda1
                                     ,2
                                     ,pctabpr.pvenda2
                                     ,3
                                     ,pctabpr.pvenda3
                                     ,4
                                     ,pctabpr.pvenda4
                                     ,5
                                     ,pctabpr.pvenda5
                                     ,6
                                     ,pctabpr.pvenda6
                                     ,7
                                     ,pctabpr.pvenda7
                                     ,0),
                               nvl(pctribut.pauta,0),
                               nvl(pctribut.aliqicms1,0),
                               nvl(pctribut.aliqicms2,0),
                               nvl(pcest.custofin,0),
                               nvl(pcest.custoreal,0),
                               nvl(pctribut.iva,0),
                               nvl(pctribut.aliqicms1fonte,0),
                               nvl(pctribut.aliqicms2fonte,0),
                               nvl(pctribut.percbaseredst,0),
                               nvl(pctribut.percbasered,0),
                               pctribut.usavalorultentbasest,
                               pctribut.usavalorultentbasest2,
                               nvl(pcest.valorultent,0),
                               nvl(pctribut.percbaseredconsumidor,0),
                               pctribut.utilizapercbaseredpf,
                               nvl(pctribut.percbaseredstfonte,0),
                               pctribut.codst,
                               nvl(pctribut.perdesccusto,0),
                               nvl(pcest.custocont,0),
                               nvl(pcest.custorep,0),
                               pctribut.codicmtab,
                               pcprodut.pcomint1,
                               pcprodut.pcomext1,
                               pcprodut.pcomrep1,
                               pcprodut.codlinhaprod,
                               pcprodut.codsec,
                               pcprodut.codepto,
                               NVL(pctribut.codicmtabpf, 0),
                               pcprodut.freteespecial,
                               nvl(pctribut.mostrarpvendasemst,nvl(gregpcconsum.mostrarpvendasemst,'N')),
                               nvl(pctribut.usapmcbasest,'N'),
                               nvl(pcprodut.precomaxconsum,0),
                               nvl(pcest.custonfsemst,pcest.valorultent),
                               nvl(pctribut.peracrescismopf,0),
                               nvl(pctribut.aplicaacrescpjisenta,'N') ,
                               pcprodut.tipocomissao,
                               pcprodut.classe ,
                               nvl(pctribut.usavlultentmediobasest, 'N'),
                               nvl(pctabpr.vlultentmes,0) ,
                               pcprodut.importado,
                               nvl(pctribut.agregaripicalculost, 'N'),
                               nvl(pctribut.usabaseicmsreduzida,'N'),
                               nvl(pctribut.isencaostorgaopub,'N'),
                               nvl(pctribut.usabcrultent,'N'),
                               nvl(pcest.basebcr,0),
                               nvl(pcest.stbcr,0),
                               nvl(pctribut.pautafonte,0),
                               nvl(pcprodut.farmaciapopular,'N'),
                               nvl(pctribut.usaptabelabasest,'N'),
                               pcprodut.codmarca,
                               nvl(pcprodut.utilizaprecofabrica,'N')
                        into vnptabela,
                             vnpauta,
                             vnaliqicms1,
                             vnaliqicms2,
                             vnvlcustofin,
                             vnvlcustoreal,
                             vniva,
                             vnaliqicms1fonte,
                             vnaliqicms2fonte,
                             vnpercbaseredst,
                             vnpercbasered,
                             vsusavalorultentbasest,
                             vsusavalorultentbasest2,
                             vnvalorultent,
                             vnpercbaseredconsumidor,
                             vsutilizapercbaseredpf,
                             vnPERCBASEREDSTFONTE,
                             vncodst,
                             vnperdesccusto,
                             vncustocont,
                             vncustorep,
                             vncodicmtab,
                             vnpcomint1,
                             vnpcomext1,
                             vnpcomrep1,
                             vncodlinhaprod,
                             vncodsec,
                             vncodepto,
                             vncodicmtabpf,
                             vnfreteespecial,
                             vsmostrarpvendasemst,
                             vsusapmcbasest,
                             vnprecomaxconsum,
                             vncustonfsemst,
                             vnperacrescismopf,
                             vsAPLICAACRESCPJISENTA,
                             vstipocomissao,
                             vsclasse,
                             vsusavlultentmediobasest,
                             vnvlultentmes,
                             vsimportado,
                             vsagregaripicalculost,
                             vsusabaseicmsreduzida,
                             vsisencaostorgaopub,
                             vsusabcrultent,
                             vnbasebcr,
                             vnstbcr,
                             vnpautafonte,
                             vvfarmaciapopular,
                             vvusaptabelabasest,
                             vncodmarca,
                             vvutilizaprecofabrica
                        from pctabpr,
                             pctribut,
                             pcest,
                             pcprodut
                        where pctribut.codst = vncodst
                              and pctabpr.codprod = reg_itenscesta.codprodmp
                              and pcest.codprod = reg_itenscesta.codprodmp
                              and pctabpr.numregiao = p_regregiao.numregiao
                              and pcest.codfilial = p_regpedido.codfilial
                              and pctabpr.codprod = pcprodut.codprod;
                         exception when others then

                         if vsmensagem is not null then
                            vschar := '#';
                          else
                            vschar := null;
                          end if;

                          vsmensagem       := vsmensagem || vschar || 'Erro ao buscar preço do item da cesta : '||reg_itenscesta.codprodmp;
                          p_regitem.valido := false;
                          p_regorigempreco.valido := false;

                        end;
               end if;


           else

            begin
            select decode(p_regitem.numpr
                         ,1
                         ,pctabpr.pvenda1
                         ,2
                         ,pctabpr.pvenda2
                         ,3
                         ,pctabpr.pvenda3
                         ,4
                         ,pctabpr.pvenda4
                         ,5
                         ,pctabpr.pvenda5
                         ,6
                         ,pctabpr.pvenda6
                         ,7
                         ,pctabpr.pvenda7
                         ,0),
                   nvl(pctribut.pauta,0),
                   nvl(pctribut.aliqicms1,0),
                   nvl(pctribut.aliqicms2,0),
                   nvl(pcest.custofin,0),
                   nvl(pcest.custoreal,0),
                   nvl(pctribut.iva,0),
                   nvl(pctribut.aliqicms1fonte,0),
                   nvl(pctribut.aliqicms2fonte,0),
                   nvl(pctribut.percbaseredst,0),
                   nvl(pctribut.percbasered,0),
                   pctribut.usavalorultentbasest,
                   pctribut.usavalorultentbasest2,
                   nvl(pcest.valorultent,0),
                   nvl(pctribut.percbaseredconsumidor,0),
                   pctribut.utilizapercbaseredpf,
                   nvl(pctribut.percbaseredstfonte,0),
                   pctabpr.codst,
                   nvl(pctribut.perdesccusto,0),
                   nvl(pcest.custocont,0),
                   nvl(pcest.custorep,0),
                   pctribut.codicmtab,
                   pcprodut.pcomint1,
                   pcprodut.pcomext1,
                   pcprodut.pcomrep1,
                   pcprodut.codlinhaprod,
                   pcprodut.codsec,
                   pcprodut.codepto,
                   NVL(pctribut.codicmtabpf, 0),
                   pcprodut.freteespecial,
                   nvl(pctribut.mostrarpvendasemst,nvl(gregpcconsum.mostrarpvendasemst,'N')),
                   nvl(pctribut.usapmcbasest,'N'),
                   nvl(pcprodut.precomaxconsum,0) ,
                   nvl(pcest.custonfsemst,pcest.valorultent),
                   nvl(pctribut.peracrescismopf,0),
                   nvl(pctribut.aplicaacrescpjisenta,'N' ),
                   pcprodut.tipocomissao,
                   pcprodut.classe,
                   nvl(pctribut.usavlultentmediobasest, 'N'),
                   nvl(pctabpr.vlultentmes,0),
                   pcprodut.importado,
                   nvl(pctribut.agregaripicalculost, 'N'),
                   nvl(pctribut.usabaseicmsreduzida,'N'),
                   nvl(pctribut.isencaostorgaopub,'N'),
                   nvl(pctribut.usabcrultent,'N'),
                   nvl(pcest.basebcr,0),
                   nvl(pcest.stbcr,0),
                   nvl(pctribut.pautafonte,0),
                   nvl(pcprodut.farmaciapopular,'N'),
                   nvl(pctribut.usaptabelabasest,'N'),
                   pcprodut.codmarca,
                   nvl(pcprodut.utilizaprecofabrica,'N')
            into vnptabela,
                 vnpauta,
                 vnaliqicms1,
                 vnaliqicms2,
                 vnvlcustofin,
                 vnvlcustoreal,
                 vniva,
                 vnaliqicms1fonte,
                 vnaliqicms2fonte,
                 vnpercbaseredst,
                 vnpercbasered,
                 vsusavalorultentbasest,
                 vsusavalorultentbasest2,
                 vnvalorultent,
                 vnpercbaseredconsumidor,
                 vsutilizapercbaseredpf,
                 vnPERCBASEREDSTFONTE,
                 vncodst,
                 vnperdesccusto,
                 vncustocont,
                 vncustorep,
                 vncodicmtab,
                 vnpcomint1,
                 vnpcomext1,
                 vnpcomrep1,
                 vncodlinhaprod,
                 vncodsec,
                 vncodepto,
                 vncodicmtabpf,
                 vnfreteespecial,
                 vsmostrarpvendasemst,
                 vsusapmcbasest,
                 vnprecomaxconsum,
                 vncustonfsemst,
                 vnperacrescismopf,
                 vsAPLICAACRESCPJISENTA,
                 vstipocomissao,
                 vsclasse,
                 vsusavlultentmediobasest,
                 vnvlultentmes,
                 vsimportado,
                 vsagregaripicalculost,
                 vsusabaseicmsreduzida,
                 vsisencaostorgaopub,
                 vsusabcrultent,
                 vnbasebcr,
                 vnstbcr,
                 vnpautafonte,
                 vvfarmaciapopular,
                 vvusaptabelabasest,
                 vncodmarca,
                 vvutilizaprecofabrica
            from pctabpr,
                 pctribut,
                 pcest,
                 pcprodut
            where pctabpr.codst = pctribut.codst
                  and pctabpr.codprod = reg_itenscesta.codprodmp
                  and pcest.codprod = reg_itenscesta.codprodmp
                  and pctabpr.numregiao = p_regregiao.numregiao
                  and pcest.codfilial = p_regpedido.codfilial
                  and pctabpr.codprod = pcprodut.codprod;


            exception when others then

             if vsmensagem is not null then
                vschar := '#';
              else
                vschar := null;
              end if;

              vsmensagem       := vsmensagem || vschar || 'Erro ao buscar preço do item da cesta : '||reg_itenscesta.codprodmp;
              p_regitem.valido := false;
              p_regorigempreco.valido := false;

             end;

              end if;



                if nvl(vnptabela,0) = 0 then

                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem              := vsmensagem || vschar ||
                                             'Item da cesta '|| reg_itenscesta.codprodmp ||' com preço de tabela zerado.';

                  p_regitem.valido        := false;
                  p_regorigempreco.valido := false;
                end if;

                --tarefa 169083

                if p_regfilial.utilizacontrolemedicamentos = 'N' then
                   -- aplica taxa financeira do plano de pagamento
                   vnptabela := vnptabela * (1 + (p_regitem.pertxfim / 100));
                end if;

                IF (p_regpedido.condvenda <> 3 AND p_regpedido.condvenda <> 6 AND
                   p_regpedido.condvenda <> 12) OR gregpcconsum.aplicaacrescpftv3 = 'S'
                THEN
                  IF gregpcconsum.acrescimopfcomie = 'S'
                  THEN
                    if ((((vsAPLICAACRESCPJISENTA = 'S')
                        and ((p_regcliente.IEENT = 'ISENTA')
                        or (p_regcliente.IEENT = 'ISENTO')))
                        or ((p_regcliente.TIPOFJ = 'F')
                        or (p_regcliente.CONSUMIDORFINAL = 'S')))
                        and (p_regcliente.Contribuinte = 'N')) THEN

                      vnptabela := (vnptabela + (vnptabela * vnperacrescismopf / 100));


                    END IF;
                  ELSE
                    if ((((vsAPLICAACRESCPJISENTA = 'S')
                        and ((p_regcliente.IEENT = 'ISENTA')
                        or (p_regcliente.IEENT = 'ISENTO')))
                        or (((p_regcliente.TIPOFJ = 'F')
                        or (p_regcliente.CONSUMIDORFINAL = 'S'))
                        and (Trim(p_regcliente.IEENT) = '')))
                        and (p_regcliente.Contribuinte = 'N')) then

                      vnptabela := (vnptabela + (vnptabela * vnperacrescismopf / 100));


                    END IF;
                  END IF;
                END IF;



            gvet_regitenscesta(vncount).numped := p_regpedido.numped;
            gvet_regitenscesta(vncount).codprodcesta := p_regitem.codprod;
            gvet_regitenscesta(vncount).codprodmp := reg_itenscesta.codprodmp;
            gvet_regitenscesta(vncount).codauxiliar := reg_itenscesta.codauxiliarmp;
            gvet_regitenscesta(vncount).pvenda := vnptabela;
            gvet_regitenscesta(vncount).ptabela := vnptabela;
            gvet_regitenscesta(vncount).qt := reg_itenscesta.qtprodmp;
            gvet_regitenscesta(vncount).pauta := vnpauta;
            gvet_regitenscesta(vncount).iva := vniva;
            gvet_regitenscesta(vncount).aliqicms1 := vnaliqicms1;
            gvet_regitenscesta(vncount).aliqicms2 := vnaliqicms2;
            gvet_regitenscesta(vncount).vlcustofin := vnvlcustofin;
            gvet_regitenscesta(vncount).vlcustoreal := vnvlcustoreal;
            gvet_regitenscesta(vncount).ivafonte := vnivafonte;
            gvet_regitenscesta(vncount).aliqicms1fonte := vnaliqicms1fonte;
            gvet_regitenscesta(vncount).aliqicms2fonte := vnaliqicms2fonte;
            gvet_regitenscesta(vncount).percbaseredst := vnpercbaseredst;
            gvet_regitenscesta(vncount).percbasered := vnpercbasered;
            gvet_regitenscesta(vncount).usavalorultentbasest := vsusavalorultentbasest;
            gvet_regitenscesta(vncount).usavalorultentbasest2 := vsusavalorultentbasest2;
            gvet_regitenscesta(vncount).valorultent := vnvalorultent;
            gvet_regitenscesta(vncount).utilizapercbaseredpf := vsutilizapercbaseredpf;
            gvet_regitenscesta(vncount).PERCBASEREDSTFONTE := vnPERCBASEREDSTFONTE;
            gvet_regitenscesta(vncount).codst := vncodst;
            gvet_regitenscesta(vncount).perdesccusto :=  vnperdesccusto;
            gvet_regitenscesta(vncount).custocont :=    vncustocont;
            gvet_regitenscesta(vncount).custorep :=    vncustorep;
            gvet_regitenscesta(vncount).codicmtab :=  vncodicmtab;
            gvet_regitenscesta(vncount).pcomint1  := vnpcomint1;
            gvet_regitenscesta(vncount).pcomext1   := vnpcomext1;
            gvet_regitenscesta(vncount).pcomrep1   := vnpcomrep1;
            gvet_regitenscesta(vncount).codlinhaprod := vncodlinhaprod;
            gvet_regitenscesta(vncount).codsec := vncodsec;
            gvet_regitenscesta(vncount).codepto := vncodepto;
            gvet_regitenscesta(vncount).codicmtabpf :=  vncodicmtabpf;
            gvet_regitenscesta(vncount).freteespecial := vnfreteespecial;
            gvet_regitenscesta(vncount).mostrarpvendasemst := vsmostrarpvendasemst;
            gvet_regitenscesta(vncount).usapmcbasest := vsusapmcbasest;
            gvet_regitenscesta(vncount).precomaxconsum := vnprecomaxconsum;
            gvet_regitenscesta(vncount).custonfsemst := vncustonfsemst;
            gvet_regitenscesta(vncount).tipocomissao := vstipocomissao;
            gvet_regitenscesta(vncount).classe := vsclasse;
            gvet_regitenscesta(vncount).usavlultentmediobasest := vsusavlultentmediobasest;
            gvet_regitenscesta(vncount).vlultentmes := vnvlultentmes;
            gvet_regitenscesta(vncount).importado := vsimportado;
            gvet_regitenscesta(vncount).agregaripicalculost := vsagregaripicalculost;
            gvet_regitenscesta(vncount).usabaseicmsreduzida := vsusabaseicmsreduzida;
            gvet_regitenscesta(vncount).isencaostorgaopub := vsisencaostorgaopub;
            gvet_regitenscesta(vncount).usabcrultent := vsusabcrultent;
            gvet_regitenscesta(vncount).basebcr := vnbasebcr;
            gvet_regitenscesta(vncount).stbcr := vnstbcr;
            gvet_regitenscesta(vncount).pautafonte := vnpautafonte;
            gvet_regitenscesta(vncount).farmaciapopular := vvfarmaciapopular;
            gvet_regitenscesta(vncount).usaptabelabasest := vvusaptabelabasest;
            gvet_regitenscesta(vncount).codmarca := vncodmarca;
            gvet_regitenscesta(vncount).utilizaprecofabrica := vvutilizaprecofabrica;

          end loop;

          --preco fixo cesta básica
          proc_verificaprecofixocesta(p_regitem,
                                      p_regproduto,
                                      p_regpedido,
                                      p_regcliente,
                                      vsmensagemprecofixocesta,
                                      vbvalidoprecofixocesta);


      if vsmensagemprecofixocesta is not null then

        if vsmensagem is not null then

          vsmensagem := vsmensagem ||';'|| vsmensagemprecofixocesta;

        else
          vsmensagem := vsmensagemprecofixocesta;

        end if;
      end if;

     p_mensagem := vsmensagem;
     p_validoprecofixocesta := vbvalidoprecofixocesta;

   end proc_validaitenscesta;
