 /************************************************************
  Função para Retornar se Isento Rebaixa CMV
  ***********************************************************/
  FUNCTION F_ISENTOREBAIXACMV(pi_nCodPromocaoMed IN NUMBER) RETURN BOOLEAN IS
    vISENTOREBAIXACMV PCPROMOCAOMED.ISENTOREBAIXACMV%TYPE;
  BEGIN

    BEGIN
      SELECT NVL(ISENTOREBAIXACMV,'N') ISENTOREBAIXACMV
        INTO vISENTOREBAIXACMV
        FROM PCPROMOCAOMED
       WHERE (CODPROMOCAOMED = pi_nCodPromocaoMed);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        vISENTOREBAIXACMV := 'N';
    END;

    RETURN (NVL(vISENTOREBAIXACMV,'N') = 'S');

  END F_ISENTOREBAIXACMV;

  -----------------------------------------------------------------
  -- Função para verificar se Valida Preço Fábrica - DDVENDAS-31641
  -----------------------------------------------------------------
  FUNCTION FUNC_VALIDA_PRECO_ACIMAFABRICA(pi_vTipoMerc            IN VARCHAR2,
                                          pi_vUtilizaPrecoFabrica IN VARCHAR2,
                                          pi_vTipoFv              IN VARCHAR2) 
  RETURN BOOLEAN IS
    vbRetUtilizaPrecoFabrica BOOLEAN;
  BEGIN
  
    -- Inicializa Indicando que não controla Preço Fábrica
    vbRetUtilizaPrecoFabrica := FALSE;
    
    -- Se Regra Mandatória
    IF (NVL(pi_vUtilizaPrecoFabrica,'N') = 'S') THEN
    
      vbRetUtilizaPrecoFabrica := TRUE;
    
    -- Se Regra Anterior
    ELSE
    
      -- OL e PE
      IF (NVL(pi_vTipoFv,'FV') IN ('OL','PE')) THEN
      
        -- Somente M e MA entram como Preço Fábrica
        IF (pi_vTipoMerc in ('M','MA')) THEN
          vbRetUtilizaPrecoFabrica := TRUE;
        END IF;
        
      -- Força de Vendas
      ELSE
      
        -- Somente M, MA entram como Preço Fábrica 
        -- (Pra ficar igual à 2316 na Validação de Preço Acima do Fábrica - DDVENDAS-31641) 
        IF (pi_vTipoMerc in ('M','MA')) THEN
          vbRetUtilizaPrecoFabrica := TRUE;
        END IF;
      
      END IF;      
      
    END IF; -- Fim Condição: pi_vUtilizaPrecoFabrica
    
    -- Retorno
    RETURN vbRetUtilizaPrecoFabrica;    
  
  END FUNC_VALIDA_PRECO_ACIMAFABRICA;

  ------------------------------------------------------
  -- Validação de Preço Acima do Fábrica - DDMEDICA-7688
  ------------------------------------------------------
  FUNCTION F_PRECO_ACIMA_FABRICA(pi_vPermiteVendaAcimaPf IN VARCHAR2,
                                 pi_nPrecoFabrica        IN NUMBER,
                                 pi_nPVenda              IN NUMBER)
  RETURN BOOLEAN IS
    vbRetPrecoAcimaFabrica BOOLEAN;  
  BEGIN
    vbRetPrecoAcimaFabrica := FALSE;
    IF (NVL(pi_vPermiteVendaAcimaPf,'S') = 'N') THEN
      IF (NVL(pi_nPrecoFabrica,0) > 0) THEN
        IF (NVL(pi_nPVenda,0) > NVL(pi_nPrecoFabrica,0)) THEN
          vbRetPrecoAcimaFabrica := TRUE;
        END IF; 
      END IF;
    END IF;
    RETURN vbRetPrecoAcimaFabrica;  
  END F_PRECO_ACIMA_FABRICA; 

  ------------------------------------------------------
  -- Validação de Preço da Oferta - DDVENDAS-33961
  ------------------------------------------------------
  FUNCTION F_PRECO_INVALIDO_OFERTA(pi_vOrigemPed             IN VARCHAR2,
                                   pi_nNumCasasDecVenda      IN NUMBER,
                                   pi_nDifAceitePrecoMinimo  IN VARCHAR2,
                                   pi_vRestringirPromocaoMed IN VARCHAR2,
                                   pi_nCodProd               IN NUMBER,
                                   pi_nCodPromocaoMed        IN VARCHAR2,
                                   pi_vTipoPrecoDesconto     IN VARCHAR2,
                                   pi_vTipoPromocao          IN VARCHAR2,
                                   pi_nPtabela               IN NUMBER,
                                   pi_nPercDesc              IN NUMBER,                                   
                                   pi_nPrecoOferta           IN NUMBER,
                                   pi_nQtde                  IN NUMBER,
                                   po_vMensagemInvalida      OUT VARCHAR2)
  RETURN VARCHAR2 IS
    vvRetInvalido        VARCHAR2(1);  
    vnPrecoMinimo        NUMBER;
    vvTipoPromocao       VARCHAR2(255);
    vvPermiteAumentarKit PCDESCONTO.PERMITIRAUMENTARQTDEKITMED%TYPE;
    vnQtKit              PCDESCONTO.INICIOINTERVALOPROMOCAOMED%TYPE;
  BEGIN
  
    vvRetInvalido        := 'N';
    po_vMensagemInvalida := NULL;
    
    IF (pi_vOrigemPed = 'OL') AND
       (pi_vRestringirPromocaoMed = 'S') THEN
       
      IF    (pi_vTipoPrecoDesconto = 'P') THEN
        vvTipoPromocao := 'Preço Fixo';
      ELSIF (pi_vTipoPrecoDesconto = 'D') THEN
        vvTipoPromocao := 'de Desconto';
      ELSE
        vvTipoPromocao := ' ';
      END IF;
       
      -- Cálculo do preco mínimo
      vnPrecoMinimo := (ROUND(pi_nPtabela, pi_nNumCasasDecVenda)) *
                       (1 - (pi_nPercDesc / 100));
      vnPrecoMinimo := ROUND(vnPrecoMinimo, gregpcconsum.numcasasdecvenda);    

      IF (NVL(pi_nPrecoOferta,0) < NVL(vnPrecoMinimo,0)) THEN
      
        vvRetInvalido        := 'S';
        po_vMensagemInvalida := 'Preço da Oferta igual a ' || pi_nPrecoOferta || ' abaixo do preço permitido igual a ' || vnPrecoMinimo ||
                                ' conforme condição comercial definida no código de promoção ' || vvTipoPromocao || ' igual a "' || pi_nCodPromocaoMed || '"';
        IF    (pi_vTipoPrecoDesconto = 'D') THEN
          po_vMensagemInvalida := po_vMensagemInvalida || ' (PTabela = ' || pi_nPtabela || ' e desc. = ' || pi_nPercDesc || '%)';
        ELSIF (pi_vTipoPrecoDesconto = 'P') THEN
          po_vMensagemInvalida := po_vMensagemInvalida || ' (Preço Fixo = ' || pi_nPtabela || ')';
        END IF;                                
      
        IF (NVL(pi_nDifAceitePrecoMinimo,0) > 0) THEN
          IF (ABS(NVL(pi_nPrecoOferta,0) - NVL(vnPrecoMinimo,0)) <= NVL(pi_nDifAceitePrecoMinimo,0)) THEN
            vvRetInvalido        := 'N';
            po_vMensagemInvalida := NULL;
          END IF;
        END IF;
        
      END IF;
      
      -- Validação Qt. Combo
      IF (vvRetInvalido = 'N') AND
         (pi_vTipoPromocao = 'K') THEN
        
        BEGIN
          SELECT PERMITIRAUMENTARQTDEKITMED
               , INICIOINTERVALOPROMOCAOMED
            INTO vvPermiteAumentarKit
               , vnQtKit
            FROM PCDESCONTO
           WHERE (CODPROMOCAOMED = pi_nCodPromocaoMed)
             AND (CODPROD        = pi_nCodProd)
             AND (ROWNUM         = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvPermiteAumentarKit := 'N';
            vnQtKit              := 0;
        END;
        
        IF (NVL(vnQtKit,0) = 0) THEN
          vvRetInvalido        := 'S';
          po_vMensagemInvalida := 'Quantidade do combo não encontrada no código de promoção igual a "' || pi_nCodPromocaoMed || '"';
        ELSE
          IF     (NVL(pi_nQtde,0) < NVL(vnQtKit,0)) THEN
            vvRetInvalido        := 'S';
            po_vMensagemInvalida := 'Quantidade vendida ' || NVL(pi_nQtde,0) || ' inferior à quantidade ' || NVL(vnQtKit,0) || '  presente no combo com código de promoção igual a "' || pi_nCodPromocaoMed || '"';
          ELSIF (NVL(pi_nQtde,0) > NVL(vnQtKit,0)) AND
                (NVL(vvPermiteAumentarKit,'N') <> 'S') THEN
            vvRetInvalido        := 'S';
            po_vMensagemInvalida := 'Quantidade vendida ' || NVL(pi_nQtde,0) || ' superior à quantidade ' || NVL(vnQtKit,0) || '  presente no combo com código de promoção igual a "' || pi_nCodPromocaoMed || '"';
          END IF;
        END IF;
        
      END IF;
      
    END IF;
              
    RETURN vvRetInvalido;  
    
  END F_PRECO_INVALIDO_OFERTA; 

  procedure proc_validaritemped(p_regitem        in out t_itemped,
                                p_regorigempreco in out t_origempreco,
                                p_regorigemcomiss in out t_origemcomiss,
                                p_regorigemdesc   in out t_origemdesc,
                                p_regpedido      in out t_cabped,
                                p_regcliente     in t_clientepedido,
                                p_regrca         in t_rca,
                                p_regregiao      in t_regiaocliente,
                                p_regplpag       in t_planodepagamento,
                                p_regplpagetico  in t_plpagetico,
                                p_regplpaggenerico  in t_plpaggenerico,
                                p_regfilial      in t_filial,
                                p_regproduto     out t_produto,
                                p_regprecos      out t_precosetributacao,
                                vscoddistrib     in pcprodut.coddistrib%type) is

    vicontador                   number;
    vsmensagem                   varchar2(32767) := null;
    vsmensagempolitica           varchar2(32767);
    vschar                       varchar2(1) default '#';
    vnpermaxdesc                 number;
    vnpvendamin                  number;
    vnpvendamax                  number;
    vbexistepolitica             boolean;
    vnpercdescquant              pcdescquant.percdesc%type;
    vnpercdescpolitica           pcdesconto.percdesc%type;
    vsbasecreddebrca             pcdesconto.basecreddebrca%type;
    vndesconto                   number;
    vnpvenda_autori              number;
    vbvalidoprecofixo            boolean := true;
    vnprecofixo                  number;
    vnperdescativ                number;
    vnptabela_ant                number;
    vnppolitica                  number;
    vnptabeladescquant           number;
    vsmensagemdescquant          varchar2(32767);
    vddtfim                      date;
    vbvalidodescquant            boolean := false;
    vsmensagemprecofixo          varchar2(32767);
    vnpermaxvenda                number;
    vsmensagempolitica_acres     varchar2(32767);
    vbexistepolitica_acres       boolean;
    vnpercdescpolitica_acres     pcdesconto.percdesc%type;
    vsmensagem_rest              varchar2(32767);
    vscreditasobrepolitica       varchar2(1);
    vnpercaux                    number;
    vnpercquantflex              number;
    vscreditasobreptabela        varchar2(1);
    vsmensagemautori             varchar2(1000);
    vbvalido_autori              boolean;
    vnpercdescpolitica_acres_aux pcdesconto.percdesc%type;
    vnnrautorizacao              number;
    vnpercdescautor              number;
    vddataautori                 date;
    vniniciointervalo            number;
    vnfimintervalo               number;
    vncodst                      pctribut.codst%type;
    vsbasecreddebrca_quant       pcdescquant.basecreddebrca%type;
    vnpercbaserca_quant          pcdescquant.percdesc%type;
    vnptabelaaux                 pcpedi.ptabela%type;

    vsalteraptabela              pcdesconto.alteraptabela%type;
    vnpercpbaserca               pcdesconto.percdesc%type;
    vnqt                         number;


    vbecesta                     boolean;
    vsmensagemcesta              varchar2(300);
    vsmensagemitenscesta         varchar2(300);
    vnptabelacesta               number;
    vbvalidoprecofixocesta       boolean;
    vnsubtotal                   number;
    vnperdesccesta               number := 0;
    vnpvendamaior                number;
    vnreg                        number;
    vndif                        number;
    vncount                      number ;
    vnmultiplo                   pcprodfilial.multiplo%type;

    vscodfilialnf                pcfilial.codigo%type;
   vbcalculosemimposto           boolean;
    vnpvendasemimposto           pcpedi.pvenda%type;
    vnptabelasemimposto          pcpedi.ptabela%type;
