    -- PROCEDIMENTO PARA GRAVAÇÃO DO LOG DO PTABELA DO ITEM
    PROCEDURE PGRAVA_LOG_PTABELA(pi_nPTabela               IN NUMBER,
                                 pi_vCampoIncidencia1      IN VARCHAR2,
                                 pi_nValorCampoIncidencia1 IN NUMBER,
                                 pi_vCampoIncidencia2      IN VARCHAR2,
                                 pi_nValorCampoIncidencia2 IN NUMBER,
                                 pi_vEPtabela              IN VARCHAR2 DEFAULT 'S',
                                 pi_vNomeCampo             IN VARCHAR2 DEFAULT NULL) IS
      vvMensagemLogImportacaoItem VARCHAR2(2000);
      viIdxLogImpItem             INTEGER;
    BEGIN
      viIdxLogImpItem := NVL(vtLogImportacaoItem.COUNT,0) + 1;

      IF (pi_vEPtabela = 'S') THEN
        vvMensagemLogImportacaoItem := '[' || TRIM(TO_CHAR(viIdxLogImpItem,'0000')) || '] PTabela: ' || NVL(pi_nPTabela,0);
      ELSE
        vvMensagemLogImportacaoItem := '[' || TRIM(TO_CHAR(viIdxLogImpItem,'0000')) || '] ' || pi_vNomeCampo || ': ' || NVL(pi_nPTabela,0);
      END IF;
      IF (pi_vCampoIncidencia1 IS NOT NULL) THEN
        vvMensagemLogImportacaoItem := vvMensagemLogImportacaoItem || CHR(13) ||
                                       pi_vCampoIncidencia1 || ': ' || NVL(pi_nValorCampoIncidencia1,0);
      END IF;
      IF (pi_vCampoIncidencia2 IS NOT NULL) THEN
        vvMensagemLogImportacaoItem := vvMensagemLogImportacaoItem || CHR(13) ||
                                       pi_vCampoIncidencia2 || ': ' || NVL(pi_nValorCampoIncidencia2,0);
      END IF;

      vtLogImportacaoItem(viIdxLogImpItem) := SUBSTR(vvMensagemLogImportacaoItem,1,2000);
    END PGRAVA_LOG_PTABELA;

    -- PROCEDIMENTO PARA GRAVAÇÃO DO LOG DE VALOR GERAL DO ITEM
    PROCEDURE PGRAVA_LOG_VALOR(pi_vMensagem IN VARCHAR2,
                               pi_nValor    IN NUMBER) IS
      vvMensagemLogImportacaoItem VARCHAR2(2000);
      viIdxLogImpItem             INTEGER;
    BEGIN
      viIdxLogImpItem := NVL(vtLogImportacaoItem.COUNT,0) + 1;

      vvMensagemLogImportacaoItem := '[' || TRIM(TO_CHAR(viIdxLogImpItem,'0000')) || '] ' || pi_vMensagem || ': ' || NVL(pi_nValor,0);

      vtLogImportacaoItem(viIdxLogImpItem) := SUBSTR(vvMensagemLogImportacaoItem,1,2000);
    END PGRAVA_LOG_VALOR;

    -- PROCEDIMENTO PARA GRAVAÇÃO DO LOG DE TEXO GERAL DO ITEM
    PROCEDURE PGRAVA_LOG_TEXTO(pi_vMensagem IN VARCHAR2,
                               pi_vValor    IN VARCHAR2) IS
      vvMensagemLogImportacaoItem VARCHAR2(2000);
      viIdxLogImpItem             INTEGER;
    BEGIN
      viIdxLogImpItem := NVL(vtLogImportacaoItem.COUNT,0) + 1;

      vvMensagemLogImportacaoItem := '[' || TRIM(TO_CHAR(viIdxLogImpItem,'0000')) || '] ' || pi_vMensagem || ': ' || NVL(pi_vValor,' ');

      vtLogImportacaoItem(viIdxLogImpItem) := SUBSTR(vvMensagemLogImportacaoItem,1,2000);
    END PGRAVA_LOG_TEXTO;

  begin

    -- Inicializa Log do Item
    vtLogImportacaoItem.DELETE;

    p_regitem.valido        := true;

    vsmensagem              := null;

    p_regorigempreco.valido := true;
    p_regorigempreco.numped := p_regpedido.numped;
    p_regitem.codcli        := p_regpedido.codcli;

    p_regorigemcomiss.numped                 := p_regpedido.numped;
    p_regorigemcomiss.codcli                 := p_regpedido.codcli;
    p_regorigemcomiss.codcob                 := p_regpedido.codcob;
    p_regorigemcomiss.tipovend               := p_regrca.tipovend;
    p_regorigemcomiss.tipoavaliacaocomissao  := p_regfilial.tipoavaliacaocomissao;
    p_regorigemcomiss.considerarcomissaozero := p_regfilial.considerarcomissaozero;


    p_regorigemdesc.numped   := p_regpedido.numped;
    p_regorigemdesc.pembalagem := 'N';
--    p_regorigemdesc.validarpoliticasdescclibloq := p_regfilial.validarpoliticasdescclibloq;
    p_regorigemdesc.PRECOFIXO := 'N';
    p_regorigemdesc.prioritariageral := 'N';


    -- APLICAR TAXA DO PLANO DE PAGAMENTO NO PREÇO DO FV
    IF (p_regpedido.aplicataxaplpagprecofv = 'S') THEN

      -- Pesquisa Taxa Plano Ético
      BEGIN
        SELECT NVL(PERTXFIM,0)
          INTO vrTaxasGrupoFat.vnTaxaPlPagEtico
          FROM PCPLPAG
         WHERE (CODPLPAG = p_regpedido.codplpagetico);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrTaxasGrupoFat.vnTaxaPlPagEtico := 0;
      END;

      -- Pesquisa Taxa Plano Genérico
      BEGIN
        SELECT NVL(PERTXFIM,0)
          INTO vrTaxasGrupoFat.vnTaxaPlPagGenerico
          FROM PCPLPAG
         WHERE (CODPLPAG = p_regpedido.codplpaggenerico);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrTaxasGrupoFat.vnTaxaPlPagGenerico := 0;
      END;

      -- Pesquisa Grupo Faturamento Produto
      BEGIN
        SELECT GRUPOFATURAMENTO
          INTO vrTaxasGrupoFat.vvGrupoFaturamento
          FROM PCPRODUT
         WHERE (CODPROD = p_regitem.codprod);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vrTaxasGrupoFat.vvGrupoFaturamento := NULL;
      END;

      -- Se Produto Ético
      IF (NVL(vrTaxasGrupoFat.vvGrupoFaturamento,' ') = 'E') THEN
        p_regitem.pvenda := p_regitem.pvenda * (1 + (NVL(vrTaxasGrupoFat.vnTaxaPlPagEtico,0) / 100));
      -- Se Produto Genérico ou Demais
      ELSE
        p_regitem.pvenda := p_regitem.pvenda * (1 + (NVL(vrTaxasGrupoFat.vnTaxaPlPagGenerico,0) / 100));
      END IF;

    END IF;


    if gregpcconsum.usachavetriplapcpedi = 'N' then

      if p_regpedido.orcamento = 'S' then
         select count(*)
          into vicontador
          from pcorcavendai
         where numorca = p_regpedido.numped
           and codprod       = p_regitem.codprod;

        if vicontador <> 0 then
          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem              := vsmensagem || vschar ||
                                     'PRODUTO JA INCLUIDO NO ORCAMENTO;';
          p_regitem.valido        := false;
          p_regorigempreco.valido := false;
        end if;

       else

        select count(*)
          into vicontador
          from pcpedi
         where pcpedi.numped = p_regpedido.numped
           and codprod       = p_regitem.codprod;

        if vicontador <> 0 then
          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem              := vsmensagem || vschar ||
                                     'PRODUTO JA INCLUIDO NO PEDIDO;';
          p_regitem.valido        := false;
          p_regorigempreco.valido := false;

        if p_Regitem.codmotivonaoatend is null then
           p_regitem.codmotivonaoatend := 5;

        end if;

        end if;

      end if;
      end if;

    -- verificar se o produto esta cadastrado
    select count(*)
      into vicontador
      from pcprodut
     where codprod = p_regitem.codprod;

    if vicontador = 0 then
      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem              := vsmensagem || vschar ||
                                 'PRODUTO NAO CADASTRADO;';
      p_regitem.valido        := false;
      p_regorigempreco.valido := false;

        if p_Regitem.codmotivonaoatend is null then
           p_regitem.codmotivonaoatend := 18;

        end if;


    else
      select codcategoria,
             codepto,
             pcprodut.codfornec,
             codprod,
             codsec,
             descricao,
             embalagem,
             pcprodut.obs,
             pcprodut.obs2,
             pcomext1,
             pcomint1,
             pcomrep1,
             NVL(pesobruto, 0),
             0,
             qtunit,
             NVL(volume, 0),
             codprodprinc,
             pcprodut.perindeniz,
             codlinhaprod,
             nvl(pcprodut.coddistrib, nvl(pcfornec.coddistrib, '')) coddistrib,
             pcprodut.freteespecial,
             pcprodut.classe,
             pcprodut.percipivenda,
             nvl(pcprodut.prazomediovenda, 0),
             pcprodut.importado,
             nvl(pcprodut.percipivendatab, 0),
             nvl(pcprodut.vlpautaipivenda, 0),
             nvl(pcprodut.vlpautaipivendatab, 0),
             nvl(pcprodut.vlipiporkgvenda, 0),
             nvl(pcprodut.vlipiporkgvendatab, 0),
             nvl(pcprodut.prazomaxindenizacao,0),
             pcprodut.pesobrutomaster,
             pcprodut.pesopeca,
             pcprodut.tipoestoque,
             pcprodut.tipomerc,
             nvl(pcprodut.custorep,0),
             pcprodut.psicotropico,
             nvl(pcprodut.percbonificvenda,0),
             nvl(pcprodut.utilizaprecomaxconsumidor,'N'),
             nvl(pcprodut.precomaxconsum,0),
             pcprodut.unidademaster,
             nvl(pcprodut.multiplo,0) ,
             pcprodut.checarmultiplovendabnf,
             pcprodut.codfilialretira,
             pcprodut.tipocomissao,
             nvl(pcprodut.grupofaturamento,'N'),
             pcprodut.codlinhaprazo,
             pcprodut.codsubcategoria,
             pcprodut.retinoico,
             pcprodut.aceitavendafracao,
             pcprodut.farmaciapopular,
             pcprodut.codmarca,
             nvl(pcprodut.utilizaprecofabrica,'N'),
             pcprodut.classevenda -- DDMEDICA-5086
        into p_regproduto
        from pcprodut, pcfornec
       where codprod = p_regitem.codprod
         and pcprodut.codfornec = pcfornec.codfornec;

    end if;

    -- HIS.04408.2015 - Passou a ser usada tanto para o PMC como para o Preço Fábrica
    -- obter o preço máximo consumidor por uf
    --if (p_regfilial.utilizapmcuf = 'S') then
    -- DDVENDAS-33718
    PKG_MEDICAMENTOS.P_OBTEM_PMC_PRODUTO(p_regpedido.codfilial,
                                         p_regitem.codprod,
                                         p_regcliente.estent,
                                         p_regregiao.numregiao,
                                         p_regproduto.precomaxconsum, -->> Substitui o Preço Máximo Consumidor
                                         p_regproduto.custorep,       -->> Substitui o Preço Fábrica
                                         vvMsgPmcUf,
                                         p_regpedido.codcli);         -->> DDVENDAS-35830 
    --end if;
    -- LOG - DDVENDAS-33718
    PGRAVA_LOG_TEXTO('ABCFARMA','-----------------');
    PGRAVA_LOG_TEXTO('UF',p_regcliente.estent);
    PGRAVA_LOG_TEXTO('REGIAO',p_regregiao.numregiao);
    PGRAVA_LOG_TEXTO('PMC',p_regproduto.precomaxconsum);
    PGRAVA_LOG_TEXTO('PF',p_regproduto.custorep);
    
     --tarefa 199697
      begin
          select nvl(p.multiplo,0),nvl(QTMAXPEDVENDA ,0),nvl(p.proibidavenda,'N'),p.revenda,p.checarmultiplovendabnf,
                 p.aceitavendafracao,p.classe,
                 p.classevenda -- DDMEDICA-5086                           
           into vnmultiplo,vnQTMAXPEDVENDA,vsproibidavenda,vsrevenda,vschecarmultiplovendabnf,vsaceitavendafracao,vsclasse,
                p_regitem.classevenda -- DDMEDICA-5086
           from pcprodfilial p
           where codfilial = p_regpedido.codfilial
           and   codprod = p_regitem.codprod;
           exception when others then
           vnmultiplo               := 0;
           vnQTMAXPEDVENDA          := 0;
           vsproibidavenda          := 'N';
           vsrevenda                := null;
           vschecarmultiplovendabnf := null;
           vsclasse                 := null;
           -- DDMEDICA-5086 - Se não existir registro na PCPRODFILIAL, assume valor da PCPRODUT
           p_regitem.classevenda    := p_regproduto.classevenda;
       end;

     -- Regra Específica para Ignorar Múltiplo no FV
     IF (p_regpedido.origemped = 'F') AND
        (NVL(p_regpedido.tipofv,'FV') NOT IN ('OL','PE')) THEN
       IF (FUSA_REGRA_MEDICAMENTOS('99','IGNORAMULTIPLOPRODFV') = 'S') THEN
         vnmultiplo := 1;
       END IF;
     END IF;

       if vnmultiplo <> 0 then
          p_regproduto.multiplo := vnmultiplo;
       end if;

     --  p_regproduto.revenda := nvl(vsrevenda,p_regproduto.revenda);
       p_regproduto.checarmultiplovendabnf := nvl(vschecarmultiplovendabnf,p_regproduto.checarmultiplovendabnf);
       p_regproduto.aceitavendafracao      := nvl(vsaceitavendafracao,p_regproduto.aceitavendafracao);
       p_regproduto.classe                  := nvl(vsclasse,p_regproduto.classe);


    if p_regfilial.utilizacontrolemedicamentos = 'S' and p_regcliente.utilizaplpagmedicamento = 'S' then

       if p_regproduto.grupofaturamento = 'E' then

         p_regitem.pertxfim      := p_regplpagetico.pertxfim;
         p_regitem.numdias       := p_regplpagetico.numdias;
         p_regitem.numpr         := p_regplpagetico.numpr;
         p_regitem.tiporestricao := p_regplpagetico.tiporestricao;
         p_regitem.codrestricao  := p_regplpagetico.codrestricao;
         p_regitem.codplpag      := p_regplpagetico.codplpag;
         p_Regitem.tipovenda     := p_regplpagetico.tipovenda;

       elsif p_regproduto.grupofaturamento in ('G','S') then

         p_regitem.pertxfim      := p_regplpaggenerico.pertxfim;
         p_regitem.numdias       := p_regplpaggenerico.numdias;
         p_regitem.numpr         := p_regplpaggenerico.numpr;
         p_regitem.tiporestricao := p_regplpaggenerico.tiporestricao;
         p_regitem.codrestricao  := p_regplpaggenerico.codrestricao;
         p_regitem.codplpag      := p_regplpaggenerico.codplpag;
         p_Regitem.tipovenda     := p_regplpaggenerico.tipovenda;


       else

          if p_regplpagetico.numdias <= p_regplpaggenerico.numdias then

             p_regitem.pertxfim      := p_regplpagetico.pertxfim;
             p_regitem.numdias       := p_regplpagetico.numdias;
             p_regitem.numpr         := p_regplpagetico.numpr;
             p_regitem.tiporestricao := p_regplpagetico.tiporestricao;
             p_regitem.codrestricao  := p_regplpagetico.codrestricao;
             p_regitem.codplpag      := p_regplpagetico.codplpag;
             p_Regitem.tipovenda     := p_regplpagetico.tipovenda;


          else
             p_regitem.pertxfim      := p_regplpaggenerico.pertxfim;
             p_regitem.numdias       := p_regplpaggenerico.numdias;
             p_regitem.numpr         := p_regplpaggenerico.numpr;
             p_regitem.tiporestricao := p_regplpaggenerico.tiporestricao;
             p_regitem.codrestricao  := p_regplpaggenerico.codrestricao;
             p_regitem.codplpag      := p_regplpaggenerico.codplpag;
             p_Regitem.tipovenda     := p_regplpaggenerico.tipovenda;


          end if;



       end if;
    else

       p_regitem.pertxfim      := p_regplpag.pertxfim;
       p_regitem.numdias       := p_regplpag.numdias;
       p_regitem.numpr         := p_regplpag.numpr;
       p_regitem.tiporestricao := p_regplpag.tiporestricao;
       p_regitem.codrestricao  := p_regplpag.codrestricao;
       p_regitem.codplpag      := p_regplpag.codplpag;
       p_Regitem.tipovenda     := p_regplpag.tipovenda;


    end if;



    --if nvl(p_regitem.pertxfim, 0) > 0 then
      p_regorigempreco.percplpag := p_regitem.pertxfim;
      p_regorigemdesc.pertxfim   := p_regitem.pertxfim;
    --end if;

    p_regorigempreco.numregiao   := p_regregiao.numregiao;
