             and (((p_regpedido.CONDVENDA <> 5 ))
               or ((p_regpedido.CONDVENDA = 5 )
        and (p_regproduto.ChecarMultiploVendaBNF = 'S'))) then

           if nvl(vnmultiplo,0) <> 0 then

             p_regproduto.multiplo := vnmultiplo;

           end if;


           if p_regproduto.multiplo <> 0
           then

             if (p_regitem.qt / p_regproduto.multiplo) <>
                trunc(p_regitem.qt / p_regproduto.multiplo)
             then

               if vsmensagem is not null
               then
                 vschar := '#';
               else
                 vschar := null;
               end if;

                 p_regitem.qt := trunc(p_regitem.qt/p_regproduto.multiplo) * p_regproduto.multiplo;

                 if p_regitem.qt > 0 then

                   vsmensagem       := vsmensagem || vschar ||
                                       'Produto so pode ser vendido multiplo de : ' || p_regproduto.multiplo || CHR(13)||
                                       'Quantidade pedida alterada para :'|| p_regitem.qt||';';
