             NVL(pctribut.codicmtabpf, 0),
             nvl(pctribut.perdescsuframa, 0),
             nvl(pctribut.perdescicmisencao, 0),
             pctabpr.descontafrete,
             nvl(pctribut.percdescpis, 0),
             nvl(pctribut.percdesccofins, 0),
             nvl(pctribut.perdescrepasse,0),
             nvl(pctabpr.precomaxconsum,0),
             1,--nvl(pcembalagem.qtunit,1),
             1,--nvl(pcembalagem.fatorpreco,1),
             (select pcprodfilial.qtminimaatacado
                from pcprodfilial
               where pcprodfilial.codprod   = p_regitem.codprod
                 and pcprodfilial.codfilial = p_regpedido.codfilial) qtminimaatacado, --PCNIL 0,--nvl(pcembalagem.qtminimaatacado,0),
             0, --(pcembalagem.pvendaatac,0),
             0, --nvl(pcembalagem.pvenda,0),
             0, --nvl(pcembalagem.poferta,0),
             CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
               ROUND(PCTABPR.PVENDAATACSEMIMPOSTO1  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
             ELSE
               round(NVL(pctabpr.pvendaatac1, 0),gregpcconsum.numcasasdecvenda)
             END,
             CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
               ROUND(PCTABPR.PVENDAATACSEMIMPOSTO2  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
             ELSE
               round(NVL(pctabpr.pvendaatac2, 0),gregpcconsum.numcasasdecvenda)
             END,
             CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
               ROUND(PCTABPR.PVENDAATACSEMIMPOSTO3  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
             ELSE
               round(NVL(pctabpr.pvendaatac3, 0),gregpcconsum.numcasasdecvenda)
             END,
             CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
               ROUND(PCTABPR.PVENDAATACSEMIMPOSTO4  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
             ELSE
               round(NVL(pctabpr.pvendaatac4, 0),gregpcconsum.numcasasdecvenda)
             END,
             CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
               ROUND(PCTABPR.PVENDAATACSEMIMPOSTO5  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
             ELSE
               round(NVL(pctabpr.pvendaatac5, 0),gregpcconsum.numcasasdecvenda)
             END,
             CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
               ROUND(PCTABPR.PVENDAATACSEMIMPOSTO6  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
             ELSE
               round(NVL(pctabpr.pvendaatac6, 0),gregpcconsum.numcasasdecvenda)
             END,
             CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
               ROUND(PCTABPR.PVENDAATACSEMIMPOSTO7  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
             ELSE
               round(NVL(pctabpr.pvendaatac7, 0),gregpcconsum.numcasasdecvenda)
             END,
             null,--pcembalagem.dtofertaini,
             null,--pcembalagem.dtofertafim,
             null,--pcembalagem.dtofertaatacini,
             null,--pcembalagem.dtofertaatacfim,
             0, --nvl(pcembalagem.pofertaatac,0),
             nvl(pctribut.mostrarpvendasemst,gregpcconsum.mostrarpvendasemst),
             nvl(pctribut.usapmcbasest,'N'),
             nvl(pcest.custonfsemst,nvl(pcest.valorultent,0)),
             nvl(pctribut.percredpvendasimplesnac,0),
             nvl(pcest.vlstultent,0),
             nvl(pctribut.percdifaliquotas,0),
             nvl(pcest.custonfsemstguiaultent,0),
             nvl(pcest.ivaultent,0),
             nvl(pcest.aliqicms1ultent,0),
             nvl(pcest.aliqicms2ultent,0),
             nvl(pcest.redbaseivaultent,100),
             nvl(pcest.percicmsfretefobstultent,0),
             nvl(pcest.vlfreteconhecultent,0),
             nvl(pcest.percaliqextguiaultent,0),
             nvl(pcest.baseicmsultent,0),
             nvl(pcest.vlstguiaultent,0),
             nvl(pctribut.usaisencaoicmsvp,'S'),
             nvl(pctribut.isencaostorgaopub,'N'),
             pctribut.pagtonomedocliente,
             nvl(pctabpr.perdescmaxbalcao,0) ,
             pctabpr.precofab,
             null,
             null,
             null,
             nvl(pctribut.usavlultentmediobasest, 'N'),
             nvl(pctabpr.vlultentmes,0),
             nvl(pctribut.usabaseicmsreduzida,'N'),
             nvl(pctribut.usabcrultent,'N'),
             nvl(pcest.basebcr,0),
             nvl(pcest.stbcr,0),
             nvl(pctribut.pautafonte,0),
             nvl(pctribut.aplicadescisencaomed,'N'), --HIS.02613.2014
             nvl(pctribut.usaptabelabasest,'N'),
             nvl(pctribut.regimeespisenstfonte,'N'),
             nvl(pctabpr.percdescsimplesnac,0),
             NVL(pctribut.codicmtabinternac, 0), -- HIS.02787.2016
             nvl(pctabpr.vlst,0), -- MED-1510
             nvl(pctabpr.vlipi,0), -- MED-1510
             nvl(pctribut.destacdescicmisencaocomercial,'N') -- DDMEDICA-3065
      into p_regprecos
      from pctabpr,
           pctribut,
           pcest,
           pcprodut
      where  pctabpr.codst = pctribut.codst(+)
        and  pcest.codprod = pctabpr.codprod(+)
        and pcest.codprod = p_regitem.codprod
        and p_regregiao.numregiao = pctabpr.numregiao(+)
        and pcest.codfilial = decode(p_regfilial.origemcustofilialretira,'V',p_regpedido.codfilial,p_regitem.codfilialretira)
        and pcprodut.codprod = p_regitem.codprod;
    exception
      when no_data_found then
        if vsmensagem is not null
        then
          vschar := '#';
        else
          vschar := null;
        end if;

        vsmensagem       := vsmensagem || vschar || 'preco do produto não encontrado (P1)#;';
        p_regitem.valido := false;


        if p_Regitem.codmotivonaoatend is null then
           p_regitem.codmotivonaoatend := 21;

        end if;

      when others then
        if vsmensagem is not null
        then
          vschar := '#';
        else
          vschar := null;
        end if;

        vsmensagem       := vsmensagem || vschar || 'Erro ao buscar preco do produto#;' ||
                            sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';';
        p_regitem.valido := false;


        if p_Regitem.codmotivonaoatend is null then
           p_regitem.codmotivonaoatend := 21;

        end if;

    end;



   else --não é cesta



        IF p_regfilial.utilizavendaporembalagem = 'S' then


            --tributacao por estado
              if nvl(gregpcconsum.usatributacaoporuf, 'N') = 'S' then

                 p_regorigempreco.usatributporuf := 'S';


                if p_regpedido.codfilialnf is null then

                   if p_regcliente.codfilialnf is null then

                      vscodfilialnf := p_regpedido.codfilial;
                   else

                      vscodfilialnf := p_regcliente.codfilialnf;
                   end if;
                else

                  vscodfilialnf := p_regpedido.codfilialnf;
                end if;


                select count(*)
                  into vicontador
                  from pctabtrib p
                 where p.codprod = p_Regitem.codprod
                   and p.codfilialnf = vscodfilialnf
                   and p.ufdestino = p_Regcliente.estent;

                if vicontador = 0 then
                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem              := vsmensagem || vschar ||
                                             'NÃO ENCONTRADA TRIBUTAÇÃO POR ESTADO;';

                  p_regitem.valido        := false;
                  p_regorigempreco.valido := false;

                  if p_Regitem.codmotivonaoatend is null then
                     p_regitem.codmotivonaoatend := 22;

                  end if;


                else

                  select p.codst
                    into vncodst
                    from pctabtrib p
                   where p.codprod = p_Regitem.codprod
                     and p.codfilialnf = vscodfilialnf
                     and p.ufdestino = p_Regcliente.estent
                     and rownum = 1;

                  -- busca as informacoes da tabela de preco.

                  begin
                    select nvl(pctribut.aliqicms1, 0),
                           nvl(pctribut.aliqicms2, 0),
                           nvl(pctribut.codicmtab, 0),
                           pctribut.codst,
                           nvl(pcest.custocont, 0),
                           nvl(pcest.custofin, 0),
                           nvl(pcest.custoreal, 0),
                           nvl(pcest.custorep, 0),
                           nvl(pcest.custoultent, 0),
                           nvl(pctabpr.excluido, 'N'),
                           nvl(pctribut.iva, 0),
                           nvl(pctribut.pauta, 0),
                           nvl(pctribut.peracrescismopf, 0),
                           nvl(pctabpr.perdescautor, 0),
                           nvl(pctribut.perdesccusto, 0),
                           nvl(pctabpr.perdescmax, 0),
                           nvl(pctabpr.perdescmaxesp, 0),
                           pctribut.perdestab,
                           nvl(pctabpr.precominimovenda, 0),
                           (round(nvl(pctabpr.pvenda, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                           (round(nvl(pctabpr.pvenda1, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                           (round(nvl(pctabpr.pvenda2, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                           (round(nvl(pctabpr.pvenda3, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                           (round(nvl(pctabpr.pvenda4, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                           (round(nvl(pctabpr.pvenda5, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                           (round(nvl(pctabpr.pvenda6, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                           (round(nvl(pctabpr.pvenda7, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                           nvl(pctabpr.qtdescautor, 0),
                           nvl(pctribut.aplicaacrescpjisenta, 'N'),
                           nvl(pctribut.percbaseredst, 0),
                           nvl(pctribut.tipocalculognre, 'P'),
                           NVL(pctribut.ivafonte, 0),
                           NVL(pctribut.aliqicms1fonte, 0),
                           NVL(pctribut.aliqicms2fonte, 0),
                           NVL(pctribut.percbaseredstfonte, 0),
                           nvl(pctribut.percbasered, 0),
                           nvl(pctribut.perbaserednrpa, 0),
                           nvl(pctribut.percbaseredconsumidor, 0),
                           nvl(utilizapercbaseredpf, 'N'),
                           nvl(pcest.valorultent,0),
                           nvl(pctribut.usavalorultentbasest, 'N'),
                           nvl(pctribut.usavalorultentbasest2, 'N'),
                           NVL(pctribut.codicmtabpf, 0),
                           nvl(pctribut.perdescsuframa, 0),
                           nvl(pctribut.perdescicmisencao, 0),
                           pctabpr.descontafrete,
                           nvl(pctribut.percdescpis, 0),
                           nvl(pctribut.percdesccofins, 0),
                           nvl(pctribut.perdescrepasse,0),
                           nvl(pctabpr.precomaxconsum,0),
                           nvl(pcembalagem.qtunit,1),
                           decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1)),
                           nvl(pcembalagem.qtminimaatacado,0),
                           (decode(nvl(pcembalagem.pvendaatac,0),0,nvl(pcembalagem.pvenda,0),nvl(pcembalagem.pvendaatac,0)) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                           (nvl(pcembalagem.pvenda,0) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                           (nvl(pcembalagem.poferta,0) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                           round(NVL(pctabpr.pvendaatac1, 0),gregpcconsum.numcasasdecvenda),
                           round(NVL(pctabpr.pvendaatac2, 0),gregpcconsum.numcasasdecvenda),
                           round(NVL(pctabpr.pvendaatac3, 0),gregpcconsum.numcasasdecvenda),
                           round(NVL(pctabpr.pvendaatac4, 0),gregpcconsum.numcasasdecvenda),
                           round(NVL(pctabpr.pvendaatac5, 0),gregpcconsum.numcasasdecvenda),
                           round(NVL(pctabpr.pvendaatac6, 0),gregpcconsum.numcasasdecvenda),
                           round(NVL(pctabpr.pvendaatac7, 0),gregpcconsum.numcasasdecvenda),
                           pcembalagem.dtofertaini,
                           pcembalagem.dtofertafim,
                           pcembalagem.dtofertaatacini,
                           pcembalagem.dtofertaatacfim,
                           nvl(pcembalagem.pofertaatac,0),
                           nvl(pctribut.mostrarpvendasemst,gregpcconsum.mostrarpvendasemst),
                           nvl(pctribut.usapmcbasest,'N'),
                           nvl(pcest.custonfsemst,nvl(pcest.valorultent,0)),
                           nvl(pctribut.percredpvendasimplesnac,0),
                           nvl(pcest.vlstultent,0),
                           nvl(pctribut.percdifaliquotas,0),
                           nvl(pcest.custonfsemstguiaultent,0),
                           nvl(pcest.ivaultent,0),
                           nvl(pcest.aliqicms1ultent,0),
                           nvl(pcest.aliqicms2ultent,0),
                           nvl(pcest.redbaseivaultent,100),
                           nvl(pcest.percicmsfretefobstultent,0),
                           nvl(pcest.vlfreteconhecultent,0),
                           nvl(pcest.percaliqextguiaultent,0),
                           nvl(pcest.baseicmsultent,0),
                           nvl(pcest.vlstguiaultent,0),
                           nvl(pctribut.usaisencaoicmsvp,'S'),
                           nvl(pctribut.isencaostorgaopub,'N') ,
                           pctribut.pagtonomedocliente,
                           nvl(pctabpr.perdescmaxbalcao,0),
                           pctabpr.precofab,
                           pcembalagem.pcomint1,
                           pcembalagem.pcomext1,
                           pcembalagem.pcomrep1,
                           nvl(pctribut.usavlultentmediobasest, 'N'),
                           nvl(pctabpr.vlultentmes,0),
                           nvl(pctribut.usabaseicmsreduzida,'N'),
                           NVL(pctribut.usabcrultent,'N'),
                           nvl(pcest.basebcr,0),
                           nvl(pcest.stbcr,0),
                           nvl(pctribut.pautafonte,0),
                           nvl(pctribut.aplicadescisencaomed,'N'), --HIS.02613.2014
                           nvl(pctribut.usaptabelabasest,'N'),
                           nvl(pctribut.regimeespisenstfonte,'N'),
                           nvl(pctabpr.percdescsimplesnac,0),
                           NVL(pctribut.codicmtabinternac, 0), -- HIS.02787.2016
                           nvl(pctabpr.vlst,0), -- MED-1510
                           nvl(pctabpr.vlipi,0), -- MED-1510
                           nvl(pctribut.destacdescicmisencaocomercial,'N') -- DDMEDICA-3065
                      into p_regprecos
                      from pctabpr, pctribut, pcest,pcembalagem
                     where pctribut.codst = vncodst
                       and pctabpr.codprod = p_regitem.codprod
                       and pcest.codprod = p_regitem.codprod
                       and pctabpr.numregiao = p_regregiao.numregiao
                       and pcest.codfilial = decode(p_regfilial.origemcustofilialretira,'V',p_regpedido.codfilial,p_regitem.codfilialretira)
                       and pcembalagem.codprod = p_regitem.codprod
                       and pcembalagem.codauxiliar = p_regitem.codauxiliar
                       and pcembalagem.codfilial = p_regpedido.codfilial;
                  exception
                    when no_data_found then
                      if vsmensagem is not null
                      then
                        vschar := '#';
                      else
                        vschar := null;
                      end if;

                      vsmensagem       := vsmensagem || vschar || 'preco do produto não encontrado (P2)#;';
                      p_regitem.valido        := false;
                      p_regorigempreco.valido := false;

                      if p_Regitem.codmotivonaoatend is null then
                         p_regitem.codmotivonaoatend := 21;

                      end if;


                    when others then
                      if vsmensagem is not null then
                        vschar := '#';
                      else
                        vschar := null;
                      end if;
                      vsmensagem              := vsmensagem || vschar ||
                                                 'ERRO AO BUSCAR PRECO DO PRODUTO#;' ||
                                                 'Verifique preços registrados pelo UF do cliente nas rotinas 201 e ou 2301#;' ||
                                                 sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';';
                      p_regitem.valido        := false;
                      p_regorigempreco.valido := false;

                      if p_Regitem.codmotivonaoatend is null then
                         p_regitem.codmotivonaoatend := 21;

                      end if;

                  end;




                              p_regitem.pvenda := round(p_regitem.pvenda / p_regprecos.qtunit,
                                          gregpcconsum.numcasasdecvenda);

                              p_regitem.qt := p_regitem.qt * p_regprecos.qtunit;


                end if;


           --não usa tributação por estado
          else
                -- busca as informacoes da tabela de preco.
                begin
                  select NVL(pctribut.aliqicms1, 0),
                         NVL(pctribut.aliqicms2, 0),
                         NVL(pctribut.codicmtab, 0),
                         pctabpr.codst,
                         NVL(pcest.custocont, 0),
                         NVL(pcest.custofin, 0),
                         NVL(pcest.custoreal, 0),
                         NVL(pcest.custorep, 0),
                         NVL(pcest.custoultent, 0),
                         NVL(pctabpr.excluido, 'N'),
                         NVL(pctribut.iva, 0),
                         NVL(pctribut.pauta, 0),
                         NVL(pctribut.peracrescismopf, 0),
                         NVL(pctabpr.perdescautor, 0),
                         NVL(pctribut.perdesccusto, 0),
                         NVL(pctabpr.perdescmax, 0),
                         NVL(pctabpr.perdescmaxesp, 0),
                         pctribut.perdestab,
                         NVL(pctabpr.precominimovenda, 0),
                         (round(nvl(pctabpr.pvenda, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                         (round(nvl(pctabpr.pvenda1, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                         (round(nvl(pctabpr.pvenda2, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                         (round(nvl(pctabpr.pvenda3, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                         (round(nvl(pctabpr.pvenda4, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                         (round(nvl(pctabpr.pvenda5, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                         (round(nvl(pctabpr.pvenda6, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                         (round(nvl(pctabpr.pvenda7, 0),gregpcconsum.numcasasdecvenda) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                         NVL(pctabpr.qtdescautor, 0),
                         NVL(pctribut.aplicaacrescpjisenta, 'N'),
                         NVL(percbaseredst, 0),
                         nvl(pctribut.tipocalculognre, 'P'),
                         NVL(pctribut.ivafonte, 0),
                         NVL(pctribut.aliqicms1fonte, 0),
                         NVL(pctribut.aliqicms2fonte, 0),
                         NVL(pctribut.percbaseredstfonte, 0),
                         nvl(pctribut.percbasered, 0),
                         nvl(pctribut.perbaserednrpa, 0),
                         nvl(pctribut.percbaseredconsumidor, 0),
                         nvl(utilizapercbaseredpf, 'N'),
                         nvl(pcest.valorultent,0),
                         nvl(pctribut.usavalorultentbasest, 'N'),
                         nvl(pctribut.usavalorultentbasest2, 'N'),
                         NVL(pctribut.codicmtabpf, 0),
                         nvl(pctribut.perdescsuframa, 0),
                         nvl(pctribut.perdescicmisencao, 0),
                         pctabpr.descontafrete,
                         nvl(pctribut.percdescpis, 0),
                         nvl(pctribut.percdesccofins, 0),
                         nvl(pctribut.perdescrepasse,0),
                         nvl(pctabpr.precomaxconsum,0),
                         nvl(pcembalagem.qtunit,1),
                         decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1)),
                         nvl(pcembalagem.qtminimaatacado,0),
                        (decode(nvl(pcembalagem.pvendaatac,0),0,nvl(pcembalagem.pvenda,0),nvl(pcembalagem.pvendaatac,0)) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                         (nvl(pcembalagem.pvenda,0) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                         (nvl(pcembalagem.poferta,0) * decode(nvl(pcembalagem.fatorpreco, 1),0,1,nvl(pcembalagem.fatorpreco, 1))),
                         round(NVL(pctabpr.pvendaatac1, 0),gregpcconsum.numcasasdecvenda),
                         round(NVL(pctabpr.pvendaatac2, 0),gregpcconsum.numcasasdecvenda),
                         round(NVL(pctabpr.pvendaatac3, 0),gregpcconsum.numcasasdecvenda),
                         round(NVL(pctabpr.pvendaatac4, 0),gregpcconsum.numcasasdecvenda),
                         round(NVL(pctabpr.pvendaatac5, 0),gregpcconsum.numcasasdecvenda),
                         round(NVL(pctabpr.pvendaatac6, 0),gregpcconsum.numcasasdecvenda),
                         round(NVL(pctabpr.pvendaatac7, 0),gregpcconsum.numcasasdecvenda),
                         pcembalagem.dtofertaini,
                         pcembalagem.dtofertafim,
                         pcembalagem.dtofertaatacini,
                         pcembalagem.dtofertaatacfim,
                         nvl(pcembalagem.pofertaatac,0),
                         nvl(pctribut.mostrarpvendasemst,gregpcconsum.mostrarpvendasemst),
                         nvl(pctribut.usapmcbasest,'N'),
                         nvl(pcest.custonfsemst,nvl(pcest.valorultent,0)),
                         nvl(pctribut.percredpvendasimplesnac,0),
                         nvl(pcest.vlstultent,0),
                         nvl(pctribut.percdifaliquotas,0),
                         nvl(pcest.custonfsemstguiaultent,0),
                         nvl(pcest.ivaultent,0),
                         nvl(pcest.aliqicms1ultent,0),
                         nvl(pcest.aliqicms2ultent,0),
                         nvl(pcest.redbaseivaultent,100),
                         nvl(pcest.percicmsfretefobstultent,0),
                         nvl(pcest.vlfreteconhecultent,0),
                         nvl(pcest.percaliqextguiaultent,0),
                         nvl(pcest.baseicmsultent,0),
                         nvl(pcest.vlstguiaultent,0),
                         nvl(pctribut.usaisencaoicmsvp,'S'),
                         nvl(pctribut.isencaostorgaopub,'N')  ,
                         pctribut.pagtonomedocliente   ,
                         nvl(pctabpr.perdescmaxbalcao,0)  ,
                         pctabpr.precofab ,
                         pcembalagem.pcomint1,
                         pcembalagem.pcomext1,
                         pcembalagem.pcomrep1,
                         nvl(pctribut.usavlultentmediobasest, 'N'),
                         nvl(pctabpr.vlultentmes,0),
                         nvl(pctribut.usabaseicmsreduzida,'N'),
                         nvl(pctribut.usabcrultent,'N'),
                         nvl(pcest.basebcr,0),
                         nvl(pcest.stbcr,0),
                         nvl(pctribut.pautafonte,0),
                         nvl(pctribut.aplicadescisencaomed,'N'), --HIS.02613.2014
                         nvl(pctribut.usaptabelabasest,'N'),
                         nvl(pctribut.regimeespisenstfonte,'N'),
                         nvl(pctabpr.percdescsimplesnac,0),
                         NVL(pctribut.codicmtabinternac, 0), -- HIS.02787.2016
                         nvl(pctabpr.vlst,0), -- MED-1510
                         nvl(pctabpr.vlipi,0), -- MED-1510
                         nvl(pctribut.destacdescicmisencaocomercial,'N') -- DDMEDICA-3065
                    into p_regprecos
                    from pctabpr, pctribut, pcest,pcembalagem
                   where pctabpr.codst = pctribut.codst
                     and pctabpr.codprod = p_regitem.codprod
                     and pcest.codprod = p_regitem.codprod
                     and pctabpr.numregiao = p_regregiao.numregiao
                     and pcest.codfilial = decode(p_regfilial.origemcustofilialretira,'V',p_regpedido.codfilial,p_regitem.codfilialretira)
                     and pcembalagem.codprod = p_regitem.codprod
                     and pcembalagem.codauxiliar = p_regitem.codauxiliar
                     and pcembalagem.codfilial = p_regpedido.codfilial;

                exception
                  when no_data_found then
                    if vsmensagem is not null
                    then
                      vschar := '#';
                    else
                      vschar := null;
                    end if;

                    vsmensagem       := vsmensagem || vschar || 'preco do produto não encontrado (P3)#;';
                    p_regitem.valido        := false;
                    p_regorigempreco.valido := false;


                    if p_Regitem.codmotivonaoatend is null then
                       p_regitem.codmotivonaoatend := 21;

                    end if;

                  when others then
                    if vsmensagem is not null then
                      vschar := '#';
                    else
                      vschar := null;
                    end if;
                    vsmensagem              := vsmensagem || vschar ||
                                               'ERRO AO BUSCAR PRECO DO PRODUTO#;' ||
                                               'Verifique preços registrados pelo UF do cliente nas rotinas 201 e ou 2301#;' ||
                                               sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';';
                    p_regitem.valido        := false;
                    p_regorigempreco.valido := false;

                      if p_Regitem.codmotivonaoatend is null then
                         p_regitem.codmotivonaoatend := 21;

                      end if;


                end;


                              p_regitem.pvenda := round(p_regitem.pvenda / p_regprecos.qtunit,
                                          gregpcconsum.numcasasdecvenda);

                              p_regitem.qt := p_regitem.qt * p_regprecos.qtunit;



          end if;


        --não usa venda por embalagem
        ELSE

          --tributacao por estado
          if nvl(gregpcconsum.usatributacaoporuf, 'N') = 'S' then

                p_regorigempreco.usatributporuf := 'S';

                if p_regpedido.codfilialnf is null then

                   if p_regcliente.codfilialnf is null then

                      vscodfilialnf := p_regpedido.codfilial;
                   else

                      vscodfilialnf := p_regcliente.codfilialnf;
                   end if;
                else

                  vscodfilialnf := p_regpedido.codfilialnf;
                end if;


            select count(*)
              into vicontador
              from pctabtrib p
             where p.codprod = p_Regitem.codprod
               and p.codfilialnf = vscodfilialnf
               and p.ufdestino = p_Regcliente.estent;

            if vicontador = 0 then
              if vsmensagem is not null then
                vschar := '#';
              else
                vschar := null;
              end if;
              vsmensagem              := vsmensagem || vschar ||
                                         'NÃO ENCONTRADA TRIBUTAÇÃO POR ESTADO;';

              p_regitem.valido        := false;
              p_regorigempreco.valido := false;

                if p_Regitem.codmotivonaoatend is null then
                   p_regitem.codmotivonaoatend := 22;

                end if;


            else

              select p.codst
                into vncodst
                from pctabtrib p
               where p.codprod = p_Regitem.codprod
                 and p.codfilialnf = vscodfilialnf
                 and p.ufdestino = p_Regcliente.estent
                 and rownum = 1;

              -- busca as informacoes da tabela de preco.

              begin
                select nvl(pctribut.aliqicms1, 0),
                       nvl(pctribut.aliqicms2, 0),
                       nvl(pctribut.codicmtab, 0),
                       pctribut.codst,
                       nvl(pcest.custocont, 0),
                       nvl(pcest.custofin, 0),
                       nvl(pcest.custoreal, 0),
                       nvl(pcest.custorep, 0),
                       nvl(pcest.custoultent, 0),
                       nvl(pctabpr.excluido, 'N'),
                       nvl(pctribut.iva, 0),
                       nvl(pctribut.pauta, 0),
                       nvl(pctribut.peracrescismopf, 0),
                       nvl(pctabpr.perdescautor, 0),
                       nvl(pctribut.perdesccusto, 0),
                       nvl(pctabpr.perdescmax, 0),
                       nvl(pctabpr.perdescmaxesp, 0),
                       pctribut.perdestab,
                       nvl(pctabpr.precominimovenda, 0),
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDASEMIMPOSTO1 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvenda, 0),gregpcconsum.numcasasdecvenda)
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDASEMIMPOSTO1 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvenda1, 0),gregpcconsum.numcasasdecvenda)
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDASEMIMPOSTO2 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvenda2, 0),gregpcconsum.numcasasdecvenda)
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDASEMIMPOSTO3 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvenda3, 0),gregpcconsum.numcasasdecvenda)
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDASEMIMPOSTO4 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvenda4, 0),gregpcconsum.numcasasdecvenda)
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDASEMIMPOSTO5 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvenda5, 0),gregpcconsum.numcasasdecvenda)
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDASEMIMPOSTO6 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvenda6, 0),gregpcconsum.numcasasdecvenda)
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDASEMIMPOSTO7 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvenda7, 0),gregpcconsum.numcasasdecvenda)
                       END,
                       nvl(pctabpr.qtdescautor, 0),
                       nvl(pctribut.aplicaacrescpjisenta, 'N'),
                       nvl(pctribut.percbaseredst, 0),
                       nvl(pctribut.tipocalculognre, 'P'),
                       NVL(pctribut.ivafonte, 0),
                       NVL(pctribut.aliqicms1fonte, 0),
                       NVL(pctribut.aliqicms2fonte, 0),
                       NVL(pctribut.percbaseredstfonte, 0),
                       nvl(pctribut.percbasered, 0),
                       nvl(pctribut.perbaserednrpa, 0),
                       nvl(pctribut.percbaseredconsumidor, 0),
                       nvl(utilizapercbaseredpf, 'N'),
                       nvl(pcest.valorultent,0),
                       nvl(pctribut.usavalorultentbasest, 'N'),
                       nvl(pctribut.usavalorultentbasest2, 'N'),
                       NVL(pctribut.codicmtabpf, 0),
                       nvl(pctribut.perdescsuframa, 0),
                       nvl(pctribut.perdescicmisencao, 0),
                       pctabpr.descontafrete,
                       nvl(pctribut.percdescpis, 0),
                       nvl(pctribut.percdesccofins, 0),
                       nvl(pctribut.perdescrepasse,0),
                       nvl(pctabpr.precomaxconsum,0),
                       1,
                       1,
                       (select pcprodfilial.qtminimaatacado
                          from pcprodfilial
                         where pcprodfilial.codprod   = p_regitem.codprod
                           and pcprodfilial.codfilial = p_regpedido.codfilial) qtminimaatacado, --PCNIL 0,--nvl(pcembalagem.qtminimaatacado,0),
                       nvl(pctabpr.pvendaatac,0),--PCNIL 0,
                       0,
                       0,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDAATACSEMIMPOSTO1  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvendaatac1, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDAATACSEMIMPOSTO2  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvendaatac2, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDAATACSEMIMPOSTO3  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvendaatac3, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDAATACSEMIMPOSTO4  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvendaatac4, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDAATACSEMIMPOSTO5  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvendaatac5, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDAATACSEMIMPOSTO6  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvendaatac6, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                       END,
                       CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                         ROUND(PCTABPR.PVENDAATACSEMIMPOSTO7  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                       ELSE
                         round(NVL(pctabpr.pvendaatac7, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                       END,
                       null,
                       null,
                       null,
                       null,
                       0  ,
                      nvl(pctribut.mostrarpvendasemst,gregpcconsum.mostrarpvendasemst),
                      nvl(pctribut.usapmcbasest,'N'),
                      nvl(pcest.custonfsemst,nvl(pcest.valorultent,0)),
                      nvl(pctribut.percredpvendasimplesnac,0),
                       nvl(pcest.vlstultent,0),
                       nvl(pctribut.percdifaliquotas,0),
                       nvl(pcest.custonfsemstguiaultent,0),
                       nvl(pcest.ivaultent,0),
                       nvl(pcest.aliqicms1ultent,0),
                       nvl(pcest.aliqicms2ultent,0),
                       nvl(pcest.redbaseivaultent,100),
                       nvl(pcest.percicmsfretefobstultent,0),
                       nvl(pcest.vlfreteconhecultent,0),
                       nvl(pcest.percaliqextguiaultent,0),
                       nvl(pcest.baseicmsultent,0),
                       nvl(pcest.vlstguiaultent,0),
                       nvl(pctribut.usaisencaoicmsvp,'S') ,
                       nvl(pctribut.isencaostorgaopub,'N'),
                       pctribut.pagtonomedocliente ,
                       nvl(pctabpr.perdescmaxbalcao,0) ,
                       pctabpr.precofab ,
                       null,
                       null,
                       null,
                       nvl(pctribut.usavlultentmediobasest, 'N'),
                       nvl(pctabpr.vlultentmes,0),
                       nvl(pctribut.usabaseicmsreduzida,'N'),
                       nvl(pctribut.usabcrultent,'N'),
                       nvl(pcest.basebcr,0),
                       nvl(pcest.stbcr,0),
                       nvl(pctribut.pautafonte,0),
                       nvl(pctribut.aplicadescisencaomed,'N'), --HIS.02613.2014
                       nvl(pctribut.usaptabelabasest,'N'),
                       nvl(pctribut.regimeespisenstfonte,'N'),
                       nvl(pctabpr.percdescsimplesnac,0),
                       NVL(pctribut.codicmtabinternac, 0), -- HIS.02787.2016
                       nvl(pctabpr.vlst,0), -- MED-1510
                       nvl(pctabpr.vlipi,0), -- MED-1510
                       nvl(pctribut.destacdescicmisencaocomercial,'N') -- DDMEDICA-3065
                  into p_regprecos
                  from pctabpr, pctribut, pcest, pcprodut
                 where pctribut.codst = vncodst
                   and pctabpr.codprod = p_regitem.codprod
                   and pcest.codprod = p_regitem.codprod
                   and pctabpr.numregiao = p_regregiao.numregiao
                   and pcest.codfilial = decode(p_regfilial.origemcustofilialretira,'V',p_regpedido.codfilial,p_regitem.codfilialretira)
                   and pcprodut.codprod = p_regitem.codprod;
              exception
                when no_data_found then
                  if vsmensagem is not null
                  then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;

                  vsmensagem       := vsmensagem || vschar || 'preco do produto não encontrado (P4)#;';
                   p_regitem.valido        := false;
                   p_regorigempreco.valido := false;


                  if p_Regitem.codmotivonaoatend is null then
                     p_regitem.codmotivonaoatend := 21;

                  end if;

                when others then
                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem              := vsmensagem || vschar ||
                                             'ERRO AO BUSCAR PRECO DO PRODUTO#;' ||
                                             'Verifique preços registrados pelo UF do cliente nas rotinas 201 e ou 2301#;' ||
                                             sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';';
                  p_regitem.valido        := false;
                  p_regorigempreco.valido := false;

                      if p_Regitem.codmotivonaoatend is null then
                         p_regitem.codmotivonaoatend := 21;

                      end if;

              end;


                  --tarefa 132437

                      p_regitem.qtpecas := null;

                      if p_regproduto.tipoestoque = 'FR' then


                          vnqt := p_Regitem.qt;

                          if  upper(trim(p_regitem.unidadevenda))  = upper(trim(p_Regproduto.unidademaster)) then

                              p_regitem.qt   := vnqt * p_regproduto.pesobrutomaster;
                              p_regitem.qtcx := vnqt;
                              p_regitem.qtpecas := null;
                              p_regprecos.qtunit := 1;

                          elsif upper(Trim(p_regitem.unidadevenda)) = 'PC' then
                              p_regitem.qt := vnqt * p_regproduto.pesopeca;
                              p_regitem.qtpecas := vnqt;
                              p_regitem.qtcx    := null;
                              p_regprecos.qtunit := 1;

                          end if;


                            IF p_regfilial.ARREDONDAQTEMBALFRIOS = 'S' THEN

                              P_REGITEM.QTCX := ROUND(P_REGITEM.QTCX);
                              P_REGITEM.QTPECAS := ROUND(P_REGITEM.QTPECAS) ;
                              P_REGITEM.QT := ROUND(P_REGITEM.QT) ;

                            END IF;

                    end if;  --fim 132437


            end if;


           --não usa tributação por estado
          else
            -- busca as informacoes da tabela de preco.
            begin
              select NVL(pctribut.aliqicms1, 0),
                     NVL(pctribut.aliqicms2, 0),
                     NVL(pctribut.codicmtab, 0),
                     pctabpr.codst,
                     NVL(pcest.custocont, 0),
                     NVL(pcest.custofin, 0),
                     NVL(pcest.custoreal, 0),
                     NVL(pcest.custorep, 0),
                     NVL(pcest.custoultent, 0),
                     NVL(pctabpr.excluido, 'N'),
                     NVL(pctribut.iva, 0),
                     NVL(pctribut.pauta, 0),
                     NVL(pctribut.peracrescismopf, 0),
                     NVL(pctabpr.perdescautor, 0),
                     NVL(pctribut.perdesccusto, 0),
                     NVL(pctabpr.perdescmax, 0),
                     NVL(pctabpr.perdescmaxesp, 0),
                     pctribut.perdestab,
                     NVL(pctabpr.precominimovenda, 0),
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO1 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvenda, 0),gregpcconsum.numcasasdecvenda)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO1 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvenda1, 0),gregpcconsum.numcasasdecvenda)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO2 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvenda2, 0),gregpcconsum.numcasasdecvenda)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO3 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvenda3, 0),gregpcconsum.numcasasdecvenda)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO4 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvenda4, 0),gregpcconsum.numcasasdecvenda)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO5 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvenda5, 0),gregpcconsum.numcasasdecvenda)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO6 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvenda6, 0),gregpcconsum.numcasasdecvenda)
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDASEMIMPOSTO7 * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvenda7, 0),gregpcconsum.numcasasdecvenda)
                     END,
                     NVL(pctabpr.qtdescautor, 0),
                     NVL(pctribut.aplicaacrescpjisenta, 'N'),
                     NVL(percbaseredst, 0),
                     nvl(pctribut.tipocalculognre, 'P'),
                     NVL(pctribut.ivafonte, 0),
                     NVL(pctribut.aliqicms1fonte, 0),
                     NVL(pctribut.aliqicms2fonte, 0),
                     NVL(pctribut.percbaseredstfonte, 0),
                     nvl(pctribut.percbasered, 0),
                     nvl(pctribut.perbaserednrpa, 0),
                     nvl(pctribut.percbaseredconsumidor, 0),
                     nvl(utilizapercbaseredpf, 'N'),
                     nvl(pcest.valorultent,0),
                     nvl(pctribut.usavalorultentbasest, 'N'),
                     nvl(pctribut.usavalorultentbasest2, 'N'),
                     NVL(pctribut.codicmtabpf, 0),
                     nvl(pctribut.perdescsuframa, 0),
                     nvl(pctribut.perdescicmisencao, 0),
                     pctabpr.descontafrete,
                     nvl(pctribut.percdescpis, 0),
                     nvl(pctribut.percdesccofins, 0),
                     nvl(pctribut.perdescrepasse,0),
                     nvl(pctabpr.precomaxconsum,0),
                     1,
                     1,
                     (select pcprodfilial.qtminimaatacado
                        from pcprodfilial
                       where pcprodfilial.codprod   = p_regitem.codprod
                         and pcprodfilial.codfilial = p_regpedido.codfilial) qtminimaatacado, --PCNIL 0,--nvl(pcembalagem.qtminimaatacado,0),
                     nvl(pctabpr.pvendaatac,0),--PCNIL 0,
                     0,
                     0,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO1  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvendaatac1, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO2  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvendaatac2, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO3  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvendaatac3, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO4  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvendaatac4, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO5  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvendaatac5, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO6  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvendaatac6, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                     END,
                     CASE WHEN (NVL(PCTRIBUT.UTILIZARSTFONTEPRECIFIC,'N') = 'S') THEN --PCNIL
                       ROUND(PCTABPR.PVENDAATACSEMIMPOSTO7  * (1 + (NVL(PCPRODUT.PERCIPIVENDA,0) / 100)),gregpcconsum.numcasasdecvenda)
                     ELSE
                       round(NVL(pctabpr.pvendaatac7, 0),gregpcconsum.numcasasdecvenda)--PCNIL 0,
                     END,
                     null,
                     null,
                     null,
                     null,
                     0,
                     nvl(pctribut.mostrarpvendasemst,gregpcconsum.mostrarpvendasemst),
                     nvl(pctribut.usapmcbasest,'N'),
                     nvl(pcest.custonfsemst,nvl(pcest.valorultent,0)),
                     nvl(pctribut.percredpvendasimplesnac,0),
                     nvl(pcest.vlstultent,0),
                     nvl(pctribut.percdifaliquotas,0),
                     nvl(pcest.custonfsemstguiaultent,0),
                     nvl(pcest.ivaultent,0),
                     nvl(pcest.aliqicms1ultent,0),
                     nvl(pcest.aliqicms2ultent,0),
                     nvl(pcest.redbaseivaultent,100),
                     nvl(pcest.percicmsfretefobstultent,0),
                     nvl(pcest.vlfreteconhecultent,0),
                     nvl(pcest.percaliqextguiaultent,0),
                     nvl(pcest.baseicmsultent,0),
                     nvl(pcest.vlstguiaultent,0),
                     nvl(pctribut.usaisencaoicmsvp,'S'),
                     nvl(pctribut.isencaostorgaopub,'N') ,
                     pctribut.pagtonomedocliente ,
                     nvl(pctabpr.perdescmaxbalcao,0)  ,
                     pctabpr.precofab,
                     null,
                     null,
                     null,
                     nvl(pctribut.usavlultentmediobasest, 'N'),
                     nvl(pctabpr.vlultentmes,0),
                     nvl(pctribut.usabaseicmsreduzida,'N'),
                     nvl(pctribut.usabcrultent,'N'),
                     nvl(pcest.basebcr,0),
                     nvl(pcest.stbcr,0),
                     nvl(pctribut.pautafonte,0),
                     nvl(pctribut.aplicadescisencaomed,'N'), --HIS.02613.2014
                     nvl(pctribut.usaptabelabasest,'N'),
                     nvl(pctribut.regimeespisenstfonte,'N'),
                     nvl(pctabpr.percdescsimplesnac,0),
                     NVL(pctribut.codicmtabinternac, 0), -- HIS.02787.2016
                     nvl(pctabpr.vlst,0), -- MED-1510
                     nvl(pctabpr.vlipi,0), -- MED-1510
                     nvl(pctribut.destacdescicmisencaocomercial,'N') -- DDMEDICA-3065
                into p_regprecos
                from pctabpr, pctribut, pcest, pcprodut
               where pctabpr.codst = pctribut.codst
                 and pctabpr.codprod = p_regitem.codprod
                 and pcest.codprod = p_regitem.codprod
                 and pctabpr.numregiao = p_regregiao.numregiao
                 and pcest.codfilial = decode(p_regfilial.origemcustofilialretira,'V',p_regpedido.codfilial,p_regitem.codfilialretira)
                 and pcprodut.codprod = p_regitem.codprod;
            exception
              when no_data_found then
                if vsmensagem is not null
                then
                  vschar := '#';
                else
                  vschar := null;
                end if;

                vsmensagem       := vsmensagem || vschar || 'preco do produto não encontrado (P5)#;';
                p_regitem.valido        := false;
                p_regorigempreco.valido := false;


                if p_Regitem.codmotivonaoatend is null then
                   p_regitem.codmotivonaoatend := 21;

                end if;

              when others then
                if vsmensagem is not null then
                  vschar := '#';
                else
                  vschar := null;
                end if;
                vsmensagem              := vsmensagem || vschar ||
                                           'ERRO AO BUSCAR PRECO DO PRODUTO#;' ||
                                           'Verifique preços registrados pelo UF do cliente nas rotinas 201 e ou 2301#;' ||
                                           sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';';
                p_regitem.valido        := false;
                p_regorigempreco.valido := false;

                      if p_Regitem.codmotivonaoatend is null then
                         p_regitem.codmotivonaoatend := 21;

                      end if;


            end;


                  --tarefa 132437

                      p_regitem.qtpecas := null;

                      if p_regproduto.tipoestoque = 'FR' then


                          vnqt := p_Regitem.qt;

                          if  upper(trim(p_regitem.unidadevenda))  = upper(trim(p_Regproduto.unidademaster)) then

                              p_regitem.qt   := vnqt * p_regproduto.pesobrutomaster;
                              p_regitem.qtcx := vnqt;
                              p_regitem.qtpecas := null;
                              p_regprecos.qtunit := 1;

                          elsif upper(Trim(p_regitem.unidadevenda)) = 'PC' then
                              p_regitem.qt := vnqt * p_regproduto.pesopeca;
                              p_regitem.qtpecas := vnqt;
                              p_regitem.qtcx    := null;

                          end if;


                            IF p_regfilial.ARREDONDAQTEMBALFRIOS = 'S' THEN

                              P_REGITEM.QTCX := ROUND(P_REGITEM.QTCX);
                              P_REGITEM.QTPECAS := ROUND(P_REGITEM.QTPECAS) ;
                              P_REGITEM.QT := ROUND(P_REGITEM.QT) ;

                            END IF;

                    end if;  --fim 132437


          end if;

       END IF;


           if p_regfilial.PRECOPOREMBALAGEM = 'S' and p_regfilial.utilizavendaporembalagem = 'S' then

               p_regorigemdesc.pembalagem := 'S';

            --Varejo
            IF p_regfilial.tipoprecificacao <> 'A' THEN
             IF p_regprecos.qtminimaatacado > 1 THEN
              IF p_regitem.qt >= p_regprecos.qtminimaatacado THEN
               p_regproduto.ptabela := p_regprecos.pvendaatac/p_regprecos.qtunit;
               PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvendaatac',p_regprecos.pvendaatac,'qtunit',p_regprecos.qtunit);
              ELSE
               p_regproduto.ptabela := p_regprecos.pvendaemb/p_regprecos.qtunit;
               PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvendaemb',p_regprecos.pvendaemb,'qtunit',p_regprecos.qtunit);
              END IF;
             ELSE
              p_regproduto.ptabela := p_regprecos.pvendaemb/p_regprecos.qtunit;
               PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvendaemb',p_regprecos.pvendaemb,'qtunit',p_regprecos.qtunit);
             END IF;
             --Atacado
            ELSE
              p_regproduto.ptabela := p_regprecos.pvendaatac/p_regprecos.qtunit;
              PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvendaatac',p_regprecos.pvendaatac,'qtunit',p_regprecos.qtunit);
            END IF;

           --tarefa 70944 verificar poferta como preco minimo
           IF (p_regprecos.poferta > 0) AND
               trunc(SYSDATE) BETWEEN p_regprecos.dtofertaini AND
               p_regprecos.dtofertafim then

               if p_regitem.qt < p_regprecos.qtminimaatacado then
                  p_regproduto.ptabela := p_regprecos.poferta/P_REGPRECOS.qtunit;
                  PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'poferta',p_regprecos.poferta,'qtunit',p_regprecos.qtunit);
               end if;
            END IF;

            IF p_regfilial.tipoprecificacao <> 'A' THEN
             IF (p_regprecos.poferta > 0) AND
                (trunc(SYSDATE) BETWEEN p_regprecos.dtofertaini AND
                p_regprecos.dtofertafim) THEN
              IF p_regitem.qt < p_regprecos.qtminimaatacado then

              p_regproduto.ptabela := p_regprecos.poferta/P_REGPRECOS.QTUNIT;
              PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'poferta',p_regprecos.poferta,'qtunit',p_regprecos.qtunit);
              END IF;
             END IF;
            ELSE
             IF (p_regprecos.pofertaatac > 0) AND
                (trunc(SYSDATE) BETWEEN p_regprecos.dtofertaatacini AND
                p_regprecos.dtofertaatacfim) THEN
              IF p_regitem.qt >= p_regprecos.qtminimaatacado THEN
              p_regproduto.ptabela := p_regprecos.pofertaatac/P_REGPRECOS.QTUNIT;
              PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pofertaatac',p_regprecos.pofertaatac,'qtunit',p_regprecos.qtunit);
              END IF;
             END IF;
            END IF;


                 if nvl(p_regproduto.ptabela,0) = 0 then

                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem              := vsmensagem || vschar ||
                                             'PRECO DE TABELA ZERADO;';

                  p_regitem.valido        := false;
                  p_regorigempreco.valido := false;
                end if;






         ELSE

           --PCNIL - TIPO PRECIFICAÇÃO ATACADO
           IF (NVL( p_regfilial.tipoprecificacao,'P') = 'A') THEN

             -- Se a Quantidade Vendida for abaixo do Mínimo da Quantidade Atacado
             IF ((NVL(p_regitem.qt,0) * NVL(p_regprecos.qtunit,0)) < NVL(p_regprecos.qtminimaatacado,0)) AND
                (NVL(p_regprecos.qtminimaatacado,0) > 0) then

              if p_regitem.numpr = 1
              then
                p_regproduto.ptabela := p_regprecos.pvendaatac1;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvendaatac1',p_regprecos.pvendaatac1,NULL,NULL);
              elsif p_regitem.numpr = 2
              then
                p_regproduto.ptabela := p_regprecos.pvendaatac2;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvendaatac2',p_regprecos.pvendaatac2,NULL,NULL);
              elsif p_regitem.numpr = 3
              then
                p_regproduto.ptabela := p_regprecos.pvendaatac3;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvendaatac3',p_regprecos.pvendaatac3,NULL,NULL);
              elsif p_regitem.numpr = 4
              then
                p_regproduto.ptabela := p_regprecos.pvendaatac4;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvendaatac4',p_regprecos.pvendaatac4,NULL,NULL);
              elsif p_regitem.numpr = 5
              then
                p_regproduto.ptabela := p_regprecos.pvendaatac5;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvendaatac5',p_regprecos.pvendaatac5,NULL,NULL);
              elsif p_regitem.numpr = 6
              then
                p_regproduto.ptabela := p_regprecos.pvendaatac6;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvendaatac6',p_regprecos.pvendaatac6,NULL,NULL);
              elsif p_regitem.numpr = 7
              then
                p_regproduto.ptabela := p_regprecos.pvendaatac7;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvendaatac7',p_regprecos.pvendaatac7,NULL,NULL);
              end if;

            ELSE

              if p_regitem.numpr = 1
              then
                p_regproduto.ptabela := p_regprecos.pvenda1;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda1',p_regprecos.pvenda1,NULL,NULL);
              elsif p_regitem.numpr = 2
              then
                p_regproduto.ptabela := p_regprecos.pvenda2;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda2',p_regprecos.pvenda2,NULL,NULL);
              elsif p_regitem.numpr = 3
              then
                p_regproduto.ptabela := p_regprecos.pvenda3;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda3',p_regprecos.pvenda3,NULL,NULL);
              elsif p_regitem.numpr = 4
              then
                p_regproduto.ptabela := p_regprecos.pvenda4;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda4',p_regprecos.pvenda4,NULL,NULL);
              elsif p_regitem.numpr = 5
              then
                p_regproduto.ptabela := p_regprecos.pvenda5;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda5',p_regprecos.pvenda5,NULL,NULL);
              elsif p_regitem.numpr = 6
              then
                p_regproduto.ptabela := p_regprecos.pvenda6;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda6',p_regprecos.pvenda6,NULL,NULL);
              elsif p_regitem.numpr = 7
              then
                p_regproduto.ptabela := p_regprecos.pvenda7;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda7',p_regprecos.pvenda7,NULL,NULL);
              end if;

            END IF;

           -- TIPO PRECIFICAÇÃO PADRÃO
           ELSE

              if p_regitem.numpr = 1
              then
                p_regproduto.ptabela := p_regprecos.pvenda1;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda1',p_regprecos.pvenda1,NULL,NULL);
              elsif p_regitem.numpr = 2
              then
                p_regproduto.ptabela := p_regprecos.pvenda2;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda2',p_regprecos.pvenda2,NULL,NULL);
              elsif p_regitem.numpr = 3
              then
                p_regproduto.ptabela := p_regprecos.pvenda3;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda3',p_regprecos.pvenda3,NULL,NULL);
              elsif p_regitem.numpr = 4
              then
                p_regproduto.ptabela := p_regprecos.pvenda4;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda4',p_regprecos.pvenda4,NULL,NULL);
              elsif p_regitem.numpr = 5
              then
                p_regproduto.ptabela := p_regprecos.pvenda5;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda5',p_regprecos.pvenda5,NULL,NULL);
              elsif p_regitem.numpr = 6
              then
                p_regproduto.ptabela := p_regprecos.pvenda6;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda6',p_regprecos.pvenda6,NULL,NULL);
              elsif p_regitem.numpr = 7
              then
                p_regproduto.ptabela := p_regprecos.pvenda7;
                PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'pvenda7',p_regprecos.pvenda7,NULL,NULL);
              end if;

           END IF; -- FIM CONDIÇÃO TIPO PRECIFICAÇÃO

         end if;

end if;

   --------------------------------
   -- Se Cliente Simples Nacional
   -- e Filial usa Desconto Simples
   --------------------------------
   IF (p_regcliente.simplesnacional  = 'S') AND
      (p_regfilial.usadescsimplesnac = 'S') THEN

     -- Pesquisa Tipo de Promoção - MED-1566
     BEGIN
       SELECT PCPROMOCAOMED.TIPOPOLITICA
         INTO vvTipoPolitica
         FROM PCPROMOCAOMED
        WHERE (PCPROMOCAOMED.CODPROMOCAOMED = p_regitem.codpromocaomed);
     EXCEPTION
       WHEN NO_DATA_FOUND THEN
         vvTipoPolitica := NULL;
     END;

     -- Se Preço Fixo ou Preço Fixo por Faixa de Quantidade
     IF (NVL(vvTipoPolitica,'N') IN ('P','F')) THEN

       PGRAVA_LOG_VALOR('não aplica percdescsimplesnac em promoção de preço fixo',p_regitem.codpromocaomed);

     -- Outras Políticas
     ELSE

       PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'ptabela',p_regproduto.ptabela,NULL,NULL);

       -- Guarda o Valor do Desconto do Simples Nacional antes de aplicar o desconto do simples nacional
       p_regitem.valordescsimplesnac := p_regproduto.ptabela * (NVL(p_regprecos.percdescsimplesnac,0) / 100);
       PGRAVA_LOG_PTABELA(p_regitem.valordescsimplesnac,'aplicando percdescsimplesnac',p_regprecos.percdescsimplesnac,NULL,NULL,'N','valordescsimplesnac');

       -- Aplica o Desconto do Simples Nacional no Preço de Tabela
       p_regproduto.ptabela := p_regproduto.ptabela * (1 - (NVL(p_regprecos.percdescsimplesnac,0) / 100));
       PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'percdescsimplesnac',p_regprecos.percdescsimplesnac,NULL,NULL);

       -- PCNIL - Regra Específica Aplica Desconto do Simples no Força de Vendas no PREÇO DE VENDA
       IF (FUSA_REGRA_MEDICAMENTOS('99','USAREGRAFVAPLICADESCSIMPLESREG') = 'S') THEN
         PGRAVA_LOG_PTABELA(p_regitem.pvenda,'antes de aplicar percdescsimplesnac',p_regprecos.percdescsimplesnac,NULL,NULL,'N','PVenda');
         p_regitem.pvenda := p_regitem.pvenda * (1 - (NVL(p_regprecos.percdescsimplesnac,0) / 100));
         PGRAVA_LOG_PTABELA(p_regitem.pvenda,'apos aplicar percdescsimplesnac',p_regprecos.percdescsimplesnac,NULL,NULL,'N','PVenda');
         p_regitem.percdescsimplesnac := p_regprecos.percdescsimplesnac; -- Guarda para poder calcular a redução do cmv no final do processo
       END IF;

     END IF; -- Fim Condição se Preço Fixo ou outras Políticas

   END IF;

   p_regorigemdesc.ptabela := p_regproduto.ptabela;

   p_regitem.vlrepasse := null;
   p_regitem.vloutros := null;
   p_regitem.vlbonific := null;

   if p_regfilial.utilizacontrolemedicamentos = 'S' then

       -- 2881.043813.2016 - Repasse em TV5
       if p_regpedido.condvenda IN (1,5) then

          -- Se o Pedido foi recebido por Integração de OL via Banco de Dados OU Se o Repasse for pelo STBCR
          IF (NVL(p_regpedido.integracaopedoperlog,'N')   = 'S')  OR
             (NVL(p_regfilial.TipoAplicRepasseFilial,' ') = 'AS') OR
             ((NVL(p_regpedido.origemped,' ') = 'F') AND (NVL(p_regpedido.tipofv,'FV') = 'FV') AND (NVL(p_regfilial.precosemrepassefv,'N') = 'S')) OR
             ((NVL(p_regpedido.origemped,' ') = 'W') AND (NVL(p_regfilial.somarrepasseprecoeccommerce,'N') = 'S')) THEN -- MED-1822 - E-Commerce

            -- Calcula o Repasse
            PKG_MEDICAMENTOS.P_OBTEM_VLREPASSE(p_regpedido.codfilial,
                                               p_regpedido.codcli,
                                               p_regregiao.numregiao,
                                               p_regpedido.condvenda,
