                  elsif p_regfilial.tipoimportacaovenda = 'RP'  then
                     p_regpedido.valido := false;

                    if p_Regitem.codmotivonaoatend is null then
                       p_regitem.codmotivonaoatend := 25;

                    end if;


                  elsif p_regfilial.tipoimportacaovenda = 'BP'  then
                     p_Regpedido.posicao := 'B';
                     p_regpedido.codmotivo := 17;
                     --p_regpedido.log       := p_regpedido.log || CHR(13) ||'Data de Vencimento do alvara(FUNC ou ANVISA) esta vencida';

                     p_regpedido.motivoposicao := 'Data de Vencimento do alvara(FUNC ou ANVISA) esta vencida';

                  end if;
                end if;

            else

                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem              := vsmensagem || vschar ||
                                             'Cliente sem data do alvara (FUNC ou AVISA);';

                  if p_regfilial.tipoimportacaovenda = 'RI'  then
                     p_regitem.valido := false;
                     p_regorigempreco.valido := false;


                    if p_Regitem.codmotivonaoatend is null then
                       p_regitem.codmotivonaoatend := 25;

                    end if;


                  elsif p_regfilial.tipoimportacaovenda = 'RP'  then
                     p_regpedido.valido := false;

                    if p_Regitem.codmotivonaoatend is null then
                       p_regitem.codmotivonaoatend := 25;

                    end if;


                  elsif p_regfilial.tipoimportacaovenda = 'BP'  then
                     p_Regpedido.posicao := 'B';
                     p_regpedido.codmotivo := 17;
                     --p_regpedido.log       := p_regpedido.log || CHR(13) ||'Data de Vencimento do alvara(FUNC ou ANVISA) esta vencida';

                     p_regpedido.motivoposicao := 'Cliente sem data do alvara (FUNC ou AVISA)';

                  end if;


            end if;

         end if;

         if p_regproduto.retinoico = 'S' then

            if p_regcliente.numalvararetinoico is null then

                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem              := vsmensagem || vschar ||
                                             'Cliente sem numero de alvara de retinoico;';

                     p_Regpedido.posicao := 'B';


                     p_regpedido.motivoposicao := 'Cliente sem numero de alvara de retinoico';


            end if;



             if p_Regcliente.dtvencalvararetinoico is not null then

                if (p_regcliente.dtvencalvararetinoico < trunc(sysdate)) then

                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem              := vsmensagem || vschar ||
                                             'DATA DO ALVARA DE RETINOICO ESTA VENCIDA;';

                     p_Regpedido.posicao := 'B';

                     p_regpedido.codmotivo := 17;
                     p_regpedido.motivoposicao := 'Data do alvara de retinoico esta vencida';

                end if;

              else
                if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem              := vsmensagem || vschar ||
                                             'Cliente sem data de Alvara de Retinoico;';

                     p_Regpedido.posicao := 'B';
                     p_regpedido.codmotivo := 17;

                     p_regpedido.motivoposicao := 'Data do alvara de retinoico esta vencida';

              end if;

          end if;


     end if; -- p_regfilial.validaalvaraporitem = 'S'

    end if; -- p_regfilial.utilizacontrolemedicamentos = 'S'

    end if;


  p_regitem.geragnre_cnpjcliente := null;

     -- 160801
       if p_regprecos.tipocalculognre = 'P' and p_regprecos.pagtonomedocliente = 'S' then

          p_regitem.geragnre_cnpjcliente := 'S';

       end if;


      --if p_regfilial.utilizacontrolemedicamentos = 'N' then
      --Desconto por Atividade
      begin
        -- HIS.00182.2016
        IF (NVL(p_regfilial.medaplicardescomcliptabela,'N') = 'S') THEN
          select (100 - ( (100 * (1 - (NVL(PCATIVI.PERCDESC,0)  / 100))) * (1 - ((NVL(PCCLIENT.PERDESC,0) * -1) / 100)) )) PERDESCATIV
            into vnperdescativ
            from pcativi, pcclient
           where pcclient.codcli = p_regcliente.codcli
             and pcclient.codatv1 = pcativi.codativ(+);
        ELSE
          select NVL(pcativi.percdesc, 0)
            into vnperdescativ
            from pcativi, pcclient
           where pcclient.codcli = p_regcliente.codcli
             and pcclient.codatv1 = pcativi.codativ;
        END IF;
      exception
        when others then
          vnperdescativ := 0;
      end;

      if vnperdescativ <> 0 then
        p_regproduto.ptabela := (p_regproduto.ptabela +
                                (p_regproduto.ptabela * vnperdescativ / 100));
        p_regorigempreco.PERCRAMOATIV := vnperdescativ;
        p_regorigemdesc.percdescpcativi := vnperdescativ;
        PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'vnperdescativ',vnperdescativ,NULL,NULL);
      end if;
     --end if;

      --------------------------------------------------------
      --// HIS.01889.2017 - Obter a Taxa do Acordo de Parceria
      --------------------------------------------------------
      IF (NVL(p_regfilial.usaracrescdescacordoparceria,'N') = 'S') AND
         (NVL(p_Regpedido.CODPROMOCAOMED,0) > 0) THEN

        -- Obtém Valores do Acordo de Parceria
        PKG_MEDICAMENTOS.P_TAXACORDOPARCERIA(p_Regpedido.codfilial,
                                             p_Regpedido.codfilialnf,
                                             p_regitem.codprod,
                                             p_Regpedido.codcli,
                                             p_regcliente.numregiao,
                                             p_Regpedido.condvenda,
                                             p_Regpedido.origemped,
                                             p_Regpedido.tipofv,
                                             NULL, -- Integradora
                                             p_Regpedido.codplpag,
                                             TRUNC(SYSDATE),
                                             vrDadosAcordoParceria.vvAchouTaxa,
                                             vrDadosAcordoParceria.vnCodAcordo,
                                             vrDadosAcordoParceria.vnPercTaxa,
                                             vrDadosAcordoParceria.vnPerCom,
                                             vrDadosAcordoParceria.vvCampo);
        IF (NVL(vrDadosAcordoParceria.vvAchouTaxa,'N') = 'S') THEN
