          p_regproduto.ptabela := (p_regproduto.ptabela - (p_regproduto.ptabela * NVL(vrDadosAcordoParceria.vnPercTaxa,0) / 100));

          PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'vrDadosAcordoParceria.vnPercTaxa',vrDadosAcordoParceria.vnPercTaxa,NULL,NULL);

          -- HIS.01889.2017 - Atualização da Variável de Priorização de Comissão do Acordo de Parceria
          IF (vrDadosAcordoParceria.vnPerCom IS NOT NULL) THEN
            p_regitem.priorizacomissacordoparceria := 'S';
          ELSE
