          p_regitem.priorizacomissacordoparceria := 'N';
          p_regitem.percomacordoparceria          := NULL;
          p_regorigempreco.codacordoparceria      := NULL;
          p_regorigempreco.percdescacordoparceria := NULL;
        END IF;

