            --Custo Real
            ELSIF p_regcliente.tipocustotransf = 'R'
            THEN
               p_regproduto.ptabela := p_regprecos.custoreal;
               PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'custoreal para tipocustotransf R ',p_regprecos.custoreal,NULL,NULL);

               if nvl(p_regprecos.custoreal,0) = 0 then

                   if vsmensagem is not null then
                     vschar := '#';
                    else
                      vschar := null;
                   end if;

                      vsmensagem  := vsmensagem || vschar ||'Produto sem custoreal, necessario para pedido tipo 10';

                    p_regitem.valido := false;


               end if;


            --Custo Contábil
            ELSIF p_regcliente.tipocustotransf = 'C'
            THEN
               p_regproduto.ptabela := p_regprecos.custocont;
               PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'custocont para tipocustotransf C ',p_regprecos.custocont,NULL,NULL);

               if nvl(p_regprecos.custocont,0) = 0 then

                   if vsmensagem is not null then
                     vschar := '#';
                    else
                      vschar := null;
                   end if;

                      vsmensagem  := vsmensagem || vschar ||'Produto sem custocont, necessario para pedido tipo 10';

                    p_regitem.valido := false;


               end if;

            --Custo Financeiro
            ELSIF p_regcliente.tipocustotransf = 'F'
            THEN
               p_regproduto.ptabela := p_regprecos.custofin;
               PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'custofin para tipocustotransf F ',p_regprecos.custofin,NULL,NULL);

                if nvl(p_regprecos.custofin,0) = 0 then

                   if vsmensagem is not null then
                     vschar := '#';
                    else
                      vschar := null;
                   end if;

                      vsmensagem  := vsmensagem || vschar ||'Produto sem custofin, necessario para pedido tipo 10';

                    p_regitem.valido := false;


               end if;

            --Custo Última Entrada
            ELSIF p_regcliente.tipocustotransf = 'U'
            THEN
               p_regproduto.ptabela := p_regprecos.custoultent;
               PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'custoultent para tipocustotransf U ',p_regprecos.custoultent,NULL,NULL);

                if nvl(p_regprecos.custoultent,0) = 0 then

