                   end if;

                      vsmensagem  := vsmensagem || vschar ||'Produto sem custoultent, necessario para pedido tipo 10';

                    p_regitem.valido := false;


               end if;


            --Valor Última Entrada
            ELSIF p_regcliente.tipocustotransf = 'V'
