            PGRAVA_LOG_VALOR('peracrestransf sobre o pvenda',p_regcliente.peracrestransf);

        end if;

      p_regorigempreco.PORIGINAL := p_regproduto.ptabela;
      p_regitem.poriginal        := p_regproduto.ptabela;


      -- DDMEDICA-683 - Guarda o Preço de Tabela sem a Taxa para usar no cálculo da promoção de markup
      p_regitem.PVENDA1BASEPROMOMARKUP := p_regproduto.ptabela;
      PGRAVA_LOG_VALOR('PVENDA1BASEPROMOMARKUP',p_regitem.PVENDA1BASEPROMOMARKUP);
      
