      PGRAVA_LOG_TEXTO('origemcustofilialretira',p_regfilial.origemcustofilialretira);
      PGRAVA_LOG_TEXTO('tipocustomarkupmed',p_regitem.tipocustomarkupmed);
      PGRAVA_LOG_TEXTO('vvAchouCustoMarkup',vvAchouCustoMarkup);
      PGRAVA_LOG_VALOR('customarkupmed',p_regitem.customarkupmed);


    if p_regitem.cesta = 'N' or (p_regitem.cesta = 'S' and vbvalidoprecofixocesta = false) then


     -- if p_regfilial.utilizacontrolemedicamentos = 'N' then
