      ELSE
        IF (p_regpedido.condvenda <> 3 AND p_regpedido.condvenda <> 6 AND
           p_regpedido.condvenda <> 12) OR gregpcconsum.aplicaacrescpftv3 = 'S'
        THEN
          IF gregpcconsum.acrescimopfcomie = 'S'
          THEN
            if ((((p_regprecos.APLICAACRESCPJISENTA = 'S')
                and ((p_regcliente.IEENT = 'ISENTA')
                or (p_regcliente.IEENT = 'ISENTO')))
                or ((p_regcliente.TIPOFJ = 'F')
                or (p_regcliente.CONSUMIDORFINAL = 'S')))
                and (p_regcliente.Contribuinte = 'N')) THEN
  
              p_regproduto.ptabela := (p_regproduto.ptabela +
                                      (p_regproduto.ptabela * p_regprecos.peracrescismopf / 100));
              PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'peracrescismopf',p_regprecos.peracrescismopf,NULL,NULL);
  
              p_regorigempreco.PERCACRESCPF := p_regprecos.peracrescismopf;
               p_regorigemdesc.peracrespf    := p_regprecos.peracrescismopf;
  
  
            END IF;
          ELSE
            if ((((p_Regprecos.APLICAACRESCPJISENTA = 'S')
                and ((p_regcliente.IEENT = 'ISENTA')
                or (p_regcliente.IEENT = 'ISENTO')))
                or (((p_regcliente.TIPOFJ = 'F')
                or (p_regcliente.CONSUMIDORFINAL = 'S'))
                and (Trim(p_regcliente.IEENT) = '')))
                and (p_regcliente.Contribuinte = 'N')) then
  
              p_regproduto.ptabela := (p_regproduto.ptabela +
                                      (p_regproduto.ptabela * p_regprecos.peracrescismopf / 100));
              PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'peracrescismopf',p_regprecos.peracrescismopf,NULL,NULL);
  
              p_regorigempreco.PERCACRESCPF := p_regprecos.peracrescismopf;
               p_regorigemdesc.peracrespf    := p_regprecos.peracrescismopf;
  
            END IF;
          END IF;
        END IF;
      END IF;


      end if;


   --***********************************************


    if p_regprecos.mostrarpvendasemst = 'S' and p_regprecos.tipocalculognre = 'P' then

      PGRAVA_LOG_VALOR('pvenda com Imposto',p_regitem.pvenda);

      vbcalculosemimposto := funcoesvendas.calculo_preco_sem_impostos(nvl(p_regproduto.PERCIPIVENDA,0),
                                                           p_regproduto.vlpautaipivenda,
                                                           p_regproduto.vlipiporkgvenda,
                                                           p_regitem.pvenda,
                                                           p_regprecos.pauta,
                                                           p_regproduto.pesobruto,
                                                           p_regprecos.percdifaliquotas,
                                                           p_regproduto.percipivenda,
