                                                           p_regprecos.vlultentmes);

      PGRAVA_LOG_VALOR('ptabela com Imposto',p_regproduto.ptabela);

      vbcalculosemimposto := funcoesvendas.calculo_preco_sem_impostos(nvl(p_regproduto.PERCIPIVENDA,0),
                                                           p_regproduto.vlpautaipivenda,
                                                           p_regproduto.vlipiporkgvenda,
                                                           p_regproduto.ptabela,
                                                           p_regprecos.pauta,
                                                           p_regproduto.pesobruto,
                                                           p_regprecos.percdifaliquotas,
                                                           p_regproduto.percipivenda,
                                                           p_regprecos.valorultent,
                                                           p_regprecos.iva,
                                                           p_regprecos.percbaseredst,
                                                           p_regprecos.aliqicms1,
                                                           p_regprecos.aliqicms2,
                                                           p_regprecos.usavalorultentbasest,
                                                           p_regprecos.usavalorultentbasest2,
                                                           p_regfilial.uf,
                                                           p_regcliente.estent,
                                                           vnptabelasemimposto,
                                                           vsmensagemprecosemimposto,
                                                           p_regprecos.usapmcbasest,
                                                           p_regproduto.precomaxconsum,
                                                           p_regprecos.usavlultentmediobasest,
                                                           p_regprecos.vlultentmes);

     if vnpvendasemimposto < p_regitem.pvenda  and ((p_regitem.pvenda - vnpvendasemimposto) > 0.01)  then
       p_regitem.pvenda := round(vnpvendasemimposto,gregpcconsum.numcasasdecvenda);
     end if;

     if vnptabelasemimposto < p_regproduto.ptabela  and ((p_regproduto.ptabela - vnptabelasemimposto) > 0.01) then
       p_Regproduto.ptabela := round(vnptabelasemimposto,gregpcconsum.numcasasdecvenda);
     end if;

     PGRAVA_LOG_VALOR('pvenda sem Imposto',p_regitem.pvenda);
     PGRAVA_LOG_VALOR('ptabela sem Imposto',p_regproduto.ptabela);

   end if;

  /*************************************************************************************************
   *************************************************************************************************
   ***************************     INICIO DEFINIÇÃO DOS DESCONTOS     ******************************
   *************************************************************************************************
   *************************************************************************************************/

   ------------------------------------------------------------------------------
   -- INICIALIZAÇÃO DE VARIÁVEIS PARA TODOS OS PEDIDOS FV (COM E SEM PROMOÇÃO) --
   ------------------------------------------------------------------------------

   vsprioritariageral   := 'N';

   p_regitem.pvendabase := p_regproduto.ptabela;

   vsmensagemdescquant  := p_regitem.prioritaria;

   vnperdescprioritaria := 0;
   vsprioritaria        := 'N';
   vsrotprioritaria     := null;

   vnpercdescfinpolitica := 0; -- MED-1645

   -- Dados da Promoção do Item do Pedido - 5685.084449.2016
   BEGIN
     SELECT CASE
              WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('M'))     THEN
                'D' -- DDMEDICA-6841 - Políticas de Markup são consideradas como Desconto
              WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('Q','D')) THEN
                'D'
              WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('F','P')) THEN
                'P'
              WHEN (PCPROMOCAOMED.TIPOPOLITICA = 'B')        AND
                   (PCPROMOCAOMED.TIPOPROMOCAO = 'N')        THEN -- HIS.03831.2017
                'N'
              WHEN (PCPROMOCAOMED.TIPOPOLITICA = 'B')        AND
                   (PCPROMOCAOMED.TIPOPROMOCAO = 'B')        THEN
                'N'
            END TIPOPROMOPRECODESC
       INTO vrDadosPromocaoItem.vvTipoPromoPrecoDesc
       FROM PCPROMOCAOMED
      WHERE (PCPROMOCAOMED.CODPROMOCAOMED  = p_regitem.codpromocaomed);
   EXCEPTION
     WHEN NO_DATA_FOUND THEN
       BEGIN
         SELECT CASE
                  WHEN (PCLOGPROMOCAOMED.TIPOPOLITICA IN ('M'))     THEN
                    'D' -- DDMEDICA-6841 - Políticas de Markup são consideradas como Desconto
                  WHEN (PCLOGPROMOCAOMED.TIPOPOLITICA IN ('Q','D')) THEN
                    'D'
                  WHEN (PCLOGPROMOCAOMED.TIPOPOLITICA IN ('F','P')) THEN
                    'P'
                  WHEN (PCLOGPROMOCAOMED.TIPOPOLITICA = 'B')        AND
                       (PCLOGPROMOCAOMED.TIPOPROMOCAO = 'N')        THEN -- HIS.03831.2017
                    'N'
                  WHEN (PCLOGPROMOCAOMED.TIPOPOLITICA = 'B')        AND
                       (PCLOGPROMOCAOMED.TIPOPROMOCAO = 'B')        THEN
                    'N'
                END TIPOPROMOPRECODESC
           INTO vrDadosPromocaoItem.vvTipoPromoPrecoDesc
           FROM PCLOGPROMOCAOMED
          WHERE (PCLOGPROMOCAOMED.CODPROMOCAOMED  = p_regitem.codpromocaomed)
            AND (ROWNUM                           = 1);
       EXCEPTION
         WHEN NO_DATA_FOUND THEN
           vrDadosPromocaoItem.vvTipoPromoPrecoDesc := NULL;
       END;
   END;

  ----------------------------------------------------
  -- Plano Pagamento da Linha de Prazo - DDMEDICA-7182
  ----------------------------------------------------
  IF (p_regfilial.tipoprazomedicam = '4') AND
     (p_regitem.codplpagLinhaPrazo IS NULL) THEN
    p_regitem.codplpagLinhaPrazo := p_regpedido.codplpag;
  END IF;
  ---------------------------------------------
  -- Plano Pagamento do Produto - DDMEDICA-6249
  ---------------------------------------------  
  vnCodPlPagProduto := INTEGRADORACOMPLE_MED.F_RETORNAR_PLPAG_ITEM(p_regfilial.tipoprazomedicam,
                                                                   p_regproduto.codprod,
                                                                   p_regitem.codplpagLinhaPrazo,
                                                                   p_regpedido.codplpag,
                                                                   p_regpedido.codplpagetico,
                                                                   p_regpedido.codplpaggenerico,
                                                                   p_regproduto.grupofaturamento);
  PGRAVA_LOG_TEXTO('Tipo de Prazo Med:', p_regfilial.tipoprazomedicam);
  PGRAVA_LOG_TEXTO('Plano do Pedido:', p_regpedido.codplpag);
  PGRAVA_LOG_TEXTO('Plano Ético do Pedido:', p_regpedido.codplpagetico);
  PGRAVA_LOG_TEXTO('Plano Genérico do Pedido:', p_regpedido.codplpaggenerico);
  PGRAVA_LOG_TEXTO('Plano da Linha:', p_regitem.codplpagLinhaPrazo);
  PGRAVA_LOG_TEXTO('Plano de Pagamento do Produto:', vnCodPlPagProduto);
  ---------------------------------------------  

 /***********************************************************************************************
                               SE O PEDIDO FV USA PROMOÇÃO
  ***********************************************************************************************/
  IF (NVL(p_regpedido.codpromocaomed,0) > 0) THEN

   PGRAVA_LOG_TEXTO('proc_validaritemped USANDO PROMOÇÃO', p_regpedido.codpromocaomed);

    ----------------------------------------------------------------------
    -- INICIALIZAÇÃO DE VARIÁVEIS PARA TODOS OS PEDIDOS FV COM PROMOÇÃO --
    ----------------------------------------------------------------------

    -- Variáveis para Log ---------------------------------------------
    vnPrecoTabelaPromocaoLog := p_regproduto.ptabela;
    vvTipoPromocaoLog        := ' ';
    vnPercDescPromocaoLog    := 0;
    vnPrecoFixoPromocaoLog   := 0;
    vnCodPromocaoLog         := 0; -- 5685.084449.2016

    -- Base RCA -------------------------------------------------------
    vnptabelaaux       := p_regproduto.ptabela;
    p_regitem.pbaserca := p_regproduto.ptabela;

    -- DESCONTO FLEXÍVEL (Desconto Máximo) ----------------------------
    vnpermaxdesc := 0;
    -- Escolha do maior desconto - comparacao com desconto da tabela de preços
    if p_regprecos.perdescmax > vnpermaxdesc then
      vnpermaxdesc                    := p_regprecos.perdescmax;
      p_regorigempreco.TIPODESCFLEX   := '2';
      p_regorigempreco.PERCDESCFLEX   := p_regprecos.perdescmax;
      --
      p_regorigemdesc.perdesc         := p_regprecos.perdescmax;
      p_regorigemdesc.tipodesc        := 'F';
      p_regorigemdesc.codrotinadesc   := 201;
      p_regorigemdesc.codpoliticadesc := null;
    end if;
    -- escolha do maior desconto - comparacao com desconto do cliente
    if p_regcliente.perdesc > vnpermaxdesc then
      vnpermaxdesc                    := p_regcliente.perdesc;
      p_regorigempreco.TIPODESCFLEX   := '1';
      p_regorigempreco.PERCDESCFLEX   := p_regcliente.perdesc;
      --
      p_regorigemdesc.perdesc         := p_regcliente.perdesc;
      p_regorigemdesc.tipodesc        := 'F';
      p_regorigemdesc.codrotinadesc   := 302;
      p_regorigemdesc.codpoliticadesc := null;
    end if;

   ---------------------------------------------------------------------------
    --                        PESQUISA PROMOÇÃO VIGENTE                     --
   ---------------------------------------------------------------------------

    -- 5685.084449.2016
    -- Se Restringe a pesquisa à promoção enviada no Item do Pedido
    -- e a Promoção enviada no Item do Pedido for de Preço Fixo -> DEVE IGNORAR A PESQUISA DE PROMOÇÃO para não ficar dando mensagem de rejeição sem necessidade
    IF ( (NVL(p_regpedido.restringirpromocaomed,'N') = 'S') OR
         (NVL(p_regfilial.restringirpromocaofvmed,'N') = 'S') OR
         (NVL(vrDadosPromocaoItem.vvTipoPromoPrecoDesc,'D') = 'N') ) AND
        (NVL(vrDadosPromocaoItem.vvTipoPromoPrecoDesc,'D') IN ('P','N')) THEN -- HIS.03831.2017 - Incluso "N"

      NULL; -->> Não Validar Promoção aqui quando a Promoção enviada no Item do Pedido for de Preço Fixo ou Bonificação

    ELSE

      -- Chama Procedimento para Retornar a Promoção Vigente
      INTEGRADORACOMPLE_MED.P_OBTEM_DESC_PROMOCAO(1,
                                  'N', -- Não grava Tabela Temporária,
                                  'N', -- Não executa Commit
                                  p_regpedido.data,
                                  p_regpedido.codfilial,
                                  p_regfilial.tipoprazomedicam,
                                  p_regcliente.numregiao,
                                  p_regpedido.codusur,
                                  p_regpedido.origemped,
                                  p_regpedido.tipofv,
                                  vnCodPlPagProduto,
                                  p_regpedido.codcondicaovenda,
                                  p_regitem.codpromocaomed, -- Promoção do Item pra Priorização
                                  p_regpedido.codcli,
                                  p_regproduto.codprod,
                                  p_regitem.qt,
                                  vrRetornoPromocao.vvTipoPromoPrecoDesc,
                                  vrRetornoPromocao.vnCodDesconto,
                                  vrRetornoPromocao.vnCodPromocaoMed,
                                  vrRetornoPromocao.vnPrecoFixo,
                                  vrRetornoPromocao.vnPercDesc,
                                  vrRetornoPromocao.vnPercDescFin,
                                  vrRetornoPromocao.vnInicioIntervaloQt,
                                  vrRetornoPromocao.vnVlDescCmv,         -- DDMEDICA-5009
                                  vrRetornoPromocao.vnPerDescCmv,        -- DDMEDICA-5009
                                  vrRetornoPromocao.vnNumVerba,          -- DDMEDICA-5009
                                  vrRetornoPromocao.vnValorCotaNumVerba, -- DDMEDICA-5009
                                  vrRetornoPromocao.vvSemVerbaVlDescCmv, -- DDMEDICA-5009
                                  vrRetornoPromocao.vvOcorreramErros,
                                  vrRetornoPromocao.vvMsgErros,
                                  NULL,
                                  case when
                                  (nvl(p_regitem.codpromocaomed,0) > 0) OR
                                  (NVL(p_regfilial.restringirpromocaofvmed,'N') = 'S') THEN
                                  'S' ELSE 'N' END,      -- 5685.084449.2016
                                  NVL(vrDadosPromocaoItem.vvTipoPromoPrecoDesc,'D'), -- 5685.084449.2016
                                  p_regitem.PVENDA1BASEPROMOMARKUP,   -- DDMEDICA-683 - Usar o Preço Tabela sem Taxa no Cálculo do Desconto do Markup
                                  p_regitem.customarkupmed,           -- DDMEDICA-6900
                                  p_regitem.percmarkupmed,            -- DDMEDICA-6837
                                  p_regpedido.integradora,
                                  p_regfilial.concedenteferta);

      -- Se Restringe a pesquisa à promoção enviada no Item do Pedido
      IF ((NVL(p_regpedido.restringirpromocaomed,'N') = 'S') OR
          (NVL(p_regfilial.restringirpromocaofvmed,'N') = 'S')) AND -- 5685.084449.2016
         (NVL(p_regitem.codpromocaomed,0) > 0) AND
         (NVL(p_regitem.codpromocaomed,0) <> NVL(vrRetornoPromocao.vnCodPromocaoMed,0)) THEN
        -- Se não encontrou o Código da Promoção do Item nos Descontos Vigentes, rejeita o Item
        vrRetornoPromocao.vvOcorreramErros := 'S';
        vrRetornoPromocao.vvMsgErros       := 'Promoção de Desconto não encontrada ou fora da vigência';
        -- LOG
        PGRAVA_LOG_TEXTO('', '');
        PGRAVA_LOG_TEXTO('Retorno FV PD', 'INTEGRADORACOMPLE_MED.P_OBTEM_DESC_PROMOCAO');
        PGRAVA_LOG_TEXTO('vrRetornoPromocao.vvMsgErros', vrRetornoPromocao.vvMsgErros);
        PGRAVA_LOG_TEXTO('Promocao do Item', p_regitem.codpromocaomed);
        PGRAVA_LOG_TEXTO('Promocao Encontrada', vrRetornoPromocao.vnCodPromocaoMed);
        PGRAVA_LOG_TEXTO('Tipo Promocao Encontrada', vrDadosPromocaoItem.vvTipoPromoPrecoDesc);
        PGRAVA_LOG_TEXTO('Valor Verba Promoção', vrRetornoPromocao.vnVlDescCmv);
        PGRAVA_LOG_TEXTO('Número Verba Promoção', vrRetornoPromocao.vnNumVerba);
        PGRAVA_LOG_TEXTO('Valor Cota Verba Promoção', vrRetornoPromocao.vnValorCotaNumVerba);
        PGRAVA_LOG_TEXTO('Sem NUMVERBA', vrRetornoPromocao.vvSemVerbaVlDescCmv);
        PGRAVA_LOG_TEXTO('PTabela Markup', p_regitem.PVENDA1BASEPROMOMARKUP);
        PGRAVA_LOG_TEXTO('Custo Markup', p_regitem.customarkupmed);
        PGRAVA_LOG_TEXTO('% Markup', p_regitem.percmarkupmed);
      -- Se Restringe a pesquisa à promoção enviada no item do Pedido e NÃO enviou Código de Promoção no Item do Pedido
      ELSIF ((NVL(p_regpedido.restringirpromocaomed,'N') = 'S') OR
             (NVL(p_regfilial.restringirpromocaofvmed,'N') = 'S')) AND
            (NVL(p_regitem.codpromocaomed,0) = 0) THEN
        -- LOG
        PGRAVA_LOG_TEXTO('', '');
        PGRAVA_LOG_TEXTO('Retorno FV PD', 'INTEGRADORACOMPLE_MED.P_OBTEM_DESC_PROMOCAO');
        PGRAVA_LOG_TEXTO('Condicao', 'Restringe a pesquisa à promoção enviada e NÃO enviou Promoção');
        PGRAVA_LOG_TEXTO('Promocao do Item', p_regitem.codpromocaomed);
        PGRAVA_LOG_TEXTO('Promocao Ignorada', vrRetornoPromocao.vnCodPromocaoMed);
        PGRAVA_LOG_TEXTO('Tipo Promocao Ignorada', vrDadosPromocaoItem.vvTipoPromoPrecoDesc);
        PGRAVA_LOG_TEXTO('Valor Verba Promoção Ignorada', vrRetornoPromocao.vnVlDescCmv);
        -- PCNIL
        -- Usa a mesma Regra da Política de Desconto para Determinar o PBASERCA igual na 2316
        -- Sem esta Condição pegava o maior desconto, e ainda garante que processa como se fosse uma Política
        -- por causa do PBASERCA que tem que ser calculado para gerar Débito e Crédito
        vrRetornoPromocao.vvTipoPromoPrecoDesc := 'D';
        vrRetornoPromocao.vnCodDesconto        := NULL;
        vrRetornoPromocao.vnCodPromocaoMed     := NULL;
        vrRetornoPromocao.vnPrecoFixo          := NULL;
        vrRetornoPromocao.vnPercDesc           := 0;
        vrRetornoPromocao.vnPercDescFin        := 0;
        vrRetornoPromocao.vnInicioIntervaloQt  := NULL;
        vrRetornoPromocao.vnVlDescCmv          := NULL;
        vrRetornoPromocao.vnPerDescCmv         := NULL;
        vrRetornoPromocao.vnNumVerba           := NULL;
        vrRetornoPromocao.vnValorCotaNumVerba  := NULL;
        vrRetornoPromocao.vvSemVerbaVlDescCmv  := NULL;
        vrRetornoPromocao.vvOcorreramErros     := 'N';
        vrRetornoPromocao.vvMsgErros           := NULL;
      END IF;

      -- Se ocorreram Erros
      IF (NVL(vrRetornoPromocao.vvOcorreramErros,'N') = 'S') THEN

        IF (NVL(p_regfilial.rejeitarpedpromoinvalidafv,'N') = 'S') THEN
          p_regpedido.valido := false;
        ELSE
          p_regitem.valido := false;
        END IF;

        if p_Regitem.codmotivonaoatend is null then
          p_regitem.codmotivonaoatend := 26 ;
        end if;


        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;
        vsmensagem := vsmensagem || vschar ||  'Aviso Desconto da Promoção: '|| vrRetornoPromocao.vvMsgErros;

        -- LOG
        PGRAVA_LOG_TEXTO('', '');
        PGRAVA_LOG_TEXTO('Retorno FV PD', 'INTEGRADORACOMPLE_MED.P_OBTEM_DESC_PROMOCAO');
        PGRAVA_LOG_TEXTO('Aviso Desconto da Promoção', vrRetornoPromocao.vvMsgErros);

      ELSE

        -- Se a Promoção Vigente for de Desconto
        IF    (vrRetornoPromocao.vvTipoPromoPrecoDesc = 'D') THEN

          -- REGRA EXCEÇÃO MED
          -- SE PROMOÇÃO DE DESCONTO, O PREÇO DE VENDA SERÁ CONGELADO - PREÇO TABELA - % DESCONTO DA PROMOÇÃO, ignorando as edições do RCA
          IF (p_regfilial.usaregramanterdscpromodescfv = 'S') THEN
            BEGIN
              SELECT TIPOPOLITICA
                INTO vvTipoPoliticaExcecaoMED
                FROM PCPROMOCAOMED
               WHERE (CODPROMOCAOMED = vrRetornoPromocao.vnCodPromocaoMed);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vvTipoPoliticaExcecaoMED := NULL;
            END;
            -- Se Política de Desconto
            IF (vvTipoPoliticaExcecaoMED = 'D') THEN
              p_regitem.pvenda := NVL(p_regproduto.ptabela,0) * (1 - (NVL(vrRetornoPromocao.vnPercDesc,0) / 100));
            END IF;
          END IF;

          ---*** EXISTE POLÍTICA ***---
          vbexistepolitica := TRUE;

          ---------------------------------------------------------------------------
          -- Variáveis para Log
          ---------------------------------------------------------------------------
          vvTipoPromocaoLog     := vrRetornoPromocao.vvTipoPromoPrecoDesc;
          vnPercDescPromocaoLog := vrRetornoPromocao.vnPercDesc;
          vnCodPromocaoLog      := vrRetornoPromocao.vnCodPromocaoMed; -- 5685.084449.2016

          ---------------------------------------------------------------------------
          -- Variáveis que já existiam na Package para Registro dos Dados da Promoção
          ---------------------------------------------------------------------------
          vnpercdescpolitica         := vrRetornoPromocao.vnPercDesc;
          vnpercdescfinpolitica      := vrRetornoPromocao.vnPercDescFin;
          vnpercdescpolitica_acres   := 0; -- VERIFICAR DEPOIS REGRA
          vsalteraptabela            := 'N';
          vnpercpbaserca             := vrRetornoPromocao.vnPercDesc;
          vsprioritaria_aux          := 'N';
          vsquestionaprioritaria_aux := 'N';
          vncodpolpbaserca_561       :=  vrRetornoPromocao.vnCodDesconto;
          -- Pesquisa algumas informações na 561
          BEGIN
            SELECT NVL(PCDESCONTO.BASECREDDEBRCA, 'N')
                 , NVL(PCDESCONTO.CREDITASOBREPOLITICA,'S')
                 , PCDESCONTO.DTINICIO
                 , PCDESCONTO.DTFIM
                 , PCDESCONTO.PERCDESCBASERCA -- DESC_BASE_RCA_PRM
              INTO vsbasecreddebrca
                 , vscreditasobrepolitica
                 , vdDtInicioFlexPromocao
                 , vdDtFimFlexPromocao
                 , vnPerDescBaseRcaPrm        -- DESC_BASE_RCA_PRM
              FROM PCDESCONTO
             WHERE (PCDESCONTO.CODDESCONTO    = vrRetornoPromocao.vnCodDesconto)
               AND (PCDESCONTO.CODPROMOCAOMED = vrRetornoPromocao.vnCodPromocaoMed)
               AND (ROWNUM                    = 1);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vsbasecreddebrca       := 'N';
              vscreditasobrepolitica := 'S';
              vdDtInicioFlexPromocao := NULL;
              vdDtFimFlexPromocao    := NULL;
          END;
          -- Pesquisa informações da Promoção -- DESC_BASE_RCA_PRM
          BEGIN
            SELECT NVL(PCPROMOCAOMED.UTILIZAPERCDESCBASERCA, 'N')
              INTO vvUtilizaPerDescBaseRcaPrm
              FROM PCPROMOCAOMED
             WHERE (PCPROMOCAOMED.CODPROMOCAOMED = vrRetornoPromocao.vnCodPromocaoMed);
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
              vvUtilizaPerDescBaseRcaPrm := 'N';
          END;
          -- Desconto da Base do RCA -- DESC_BASE_RCA_PRM
          IF (NVL(vvUtilizaPerDescBaseRcaPrm,'N') = 'S') THEN
            vnpercpbaserca := NVL(vnPerDescBaseRcaPrm,0);
          END IF;

          ----------------------------------------------------------------------------------------------------
          -- REDEFINIÇÃO do Desconto Máximo quando o Desconto da Promoção for maior o da PCTABPR e da PCCLIENT
          ----------------------------------------------------------------------------------------------------
          IF (NVL(vnpercdescpolitica,0) > NVL(vnpermaxdesc,0)) THEN

            -->> Promoção usa o Desconto como Máximo
            vnpermaxdesc                      := vnpercdescpolitica;
            p_regorigempreco.TIPODESCFLEX     := '3';
            p_regorigempreco.PERCDESCFLEX     := vnpercdescpolitica;
            p_regorigempreco.DTINICIODESCFLEX := vdDtInicioFlexPromocao;
            p_regorigempreco.CODDESCFLEX      := vrRetornoPromocao.vnCodDesconto;
            p_regorigempreco.DTFIMDESCFLEX    := vdDtFimFlexPromocao;
            p_regorigemdesc.perdesc           := vnpercdescpolitica;
            p_regorigemdesc.tipodesc          := 'F';
            p_regorigemdesc.codrotinadesc     := 561;
            p_regorigemdesc.codpoliticadesc   := vrRetornoPromocao.vnCodDesconto;

          END IF;

          --------------------------------------------------------------------------------
          -- Definição do Preço da Política para usar na Validação da Autorização de Preço
          --------------------------------------------------------------------------------
          IF vnpercdescpolitica > 0 THEN -->> Desconto

            -- IMPORTANTE: 1.6 - Preço Tabela abatido do Desconto da Política para comparar com o Preço de Venda do Pedido e validar autorização de venda
            -- (Origem: proc_validaritemped() e ...)
            vnppolitica := (ROUND(p_regproduto.ptabela,
                                  gregpcconsum.numcasasdecvenda)) *
                           (1 - (vnpercdescpolitica / 100));
            vnppolitica := ROUND(vnppolitica,
                                 gregpcconsum.numcasasdecvenda);
          END IF;




          ---------------------------
          -- DEFINIÇÃO da Base do RCA
          ---------------------------
          -- MED-1822 - Arredonda somente no Final pra ficar igual à 2316
          --vnppolitica_pbaserca      := (ROUND(vnptabelaaux, gregpcconsum.numcasasdecvenda)) * (1 - (vnpercpbaserca / 100));
          --vnppolitica_pbaserca      := ROUND(vnppolitica_pbaserca, gregpcconsum.numcasasdecvenda);
          vnppolitica_pbaserca      := (vnptabelaaux) * (1 - (vnpercpbaserca / 100));
          -- Guarda o Percentual de Desconto da Base do RCA ao importar o Pedido do Força de Vendas
          p_regitem.percdescbaserca := vnpercpbaserca;



          ---------------------------------------------------------------------------------
          -- POLÍTICA PARA APLICAR VERBA CMV
          -- MED-2453 - Trouxe para antes de Validar Debita/Credita para ficar igual à 2316
          ---------------------------------------------------------------------------------

          p_regitem.percverbacmvcli := NULL;

          vbvalidoverbacmv := TRUE;

          -- E-Commerce - MED-1822
          IF (p_regpedido.origemped = 'W') then
            IF (p_regfilial.ignpoliticaverbacmvecommerce = 'S') THEN
              vbvalidoverbacmv := FALSE;
              PGRAVA_LOG_TEXTO('Ignorar Verba CMV CLI', p_regfilial.ignpoliticaverbacmvecommerce);
            END IF;
          END IF;

          -- Isento Rebaixa CMV Cliente
          IF (F_ISENTOREBAIXACMV(p_regitem.codpromocaomed)) THEN
            vbvalidoverbacmv := FALSE;
            PGRAVA_LOG_TEXTO('Isento Verba CMV CLI Promoção', p_regitem.codpromocaomed);
          END IF;

          -- Se pode ler a Política para aplicar Verba CMV - MED-1822 -------------------
          IF (vbvalidoverbacmv) THEN

            begin
              vbvalidoverbacmv := funcoesvendas.calcularpercverbacmv(p_regitem.codprod,
                                                                     p_regproduto.codsec,
                                                                     p_regproduto.codepto,
                                                                     p_regpedido.data,
                                                                     p_regpedido.codcli,
                                                                     gregpcconsum.numcasasdecvenda,
                                                                     vsmensagemverbacmv,
                                                                     p_regitem.percverbacmvcli,
                                                                     p_regcliente.codrede
                                                                    );
            exception when others then
                 if p_regitem.codmotivonaoatend is null then
                    p_regitem.codmotivonaoatend := 23;
                 end if;
            end;

            if vsmensagemverbacmv is not null then

             if substr(vsmensagemverbacmv,1,1) in ('S','N') then

               vsalteracontacorrente := substr(vsmensagemverbacmv,1,1);

             else

              proc_registralog(p_regpedido.numped,
                               p_regpedido.numpedrca,
                               p_regitem.codprod,
                               p_regitem.codauxiliar,
                               p_regitem.cgccli,
                               null,
                               null,
                               null,
                               p_regpedido.codusur,
                               p_regitem.dtaberturapedpalm,
                               null,
                               '3',
                               vsmensagemverbacmv,
                               null,
                               p_regitem.numseqifv);

                 if p_regitem.codmotivonaoatend is null then
                    p_regitem.codmotivonaoatend := 23;
                 end if;

             end if;

            end if;

            if nvl(p_regitem.percverbacmvcli, 0) <> 0 then

              if vsalteracontacorrente = 'S' then

                -- LOG
                PGRAVA_LOG_VALOR('PBaseRCA antes da Verba CMV CLI', vnppolitica_pbaserca);

                -- MED-1822 - Igualar a 2316
                IF (NVL(p_regfilial.tipocalcstfonte,'2') = '1') THEN
                  vnppolitica_pbaserca := NVL(vnppolitica_pbaserca,0) + ( NVL(p_regproduto.ptabela,0) * (p_regitem.percverbacmvcli / 100) );
                ELSE
                  vnppolitica_pbaserca := NVL(vnppolitica_pbaserca,0) + ( NVL(p_regitem.pvenda,0)     * (p_regitem.percverbacmvcli / 100) );
                END IF;

                -- LOG
                PGRAVA_LOG_VALOR('% Verba CMV CLI', p_regitem.percverbacmvcli);
                PGRAVA_LOG_VALOR('PBaseRCA após Verba CMV CLI', vnppolitica_pbaserca);

              end if;

            end if;

          END IF; -- FIM: Se pode ler a Política para aplicar Verba CMV - MED-1822 ------

          -- MED-1822 - Arredonda igual a 2316 após o bloco da Verba CMV
          vnppolitica_pbaserca := round(vnppolitica_pbaserca,gregpcconsum.numcasasdecvenda);

          -------------------------------------------------------------------------------
          -------------------------------------------------------------------------------



          -- DESC_BASE_RCA_PRM
          --// 4663.075505.2015 - Uso da Opção da 2323 Não Debitar Conta Corrente ao Conceder Desconto (PCEDESCONTO.BASECREDDEBRCA = 'S')
          --// Uso do Parâmetro TIPOCONFIGDEBCREDRCAPROMOMED devido a conflito com a Máxima Sistemas detectado pela Palmed
          IF ((NVL(p_regfilial.tipoconfigdebcredrcapromomed,'0') = '1') OR
              (NVL(p_regfilial.tipoconfigdebcredrcapromomed,'0') = '2')) THEN
            --//
            --// Troquei nas condições (NVL(p_regitem.pvenda,0) < NVL(vnppolitica,0)) e (NVL(p_regitem.pvenda,0) > NVL(vnppolitica,0)) a variável vnppolitica por vnppolitica_pbaserca,
            --// porque quando TIPOCONFIGDEBCREDRCAPROMOMED for igual a 1 ou 2, deve se comparar o PVENDA com o Preço Tabela - % Desconto Conta-Corrente e não com o PTABELA - % Desconto Comercial da Promoção
            --//
            -- Se aumentar o Preço mesmo com desconto zerado deve usar a regra
            --IF (NVL(vnpercdescpolitica,0) <> 0)  THEN --// Se a Promoção tinha Desconto
              --// Se for debitar o conta-corrente (vendeu mais barato: Valor Liquido < Valor Tabela com Desconto da Promoção)
              IF (NVL(p_regitem.pvenda,0) < NVL(vnppolitica_pbaserca,0)) THEN
                --// Opção da 2323 não debitar ao conceder desconto (PCEDESCONTO.BASECREDDEBRCA)
                IF (NVL(vsbasecreddebrca,'N') = 'S') THEN
                  --// Não debitará mais: Base do Rca será igual ao Valor Liquido
                  vnppolitica_pbaserca := NVL(p_regitem.pvenda,0);
                END IF;
              END IF;

              --// Se for creditar o conta-corrente (vendeu mais caro: Valor Liquido > Valor Tabela com Desconto da Promoção)
              IF (NVL(p_regitem.pvenda,0) > NVL(vnppolitica_pbaserca,0)) THEN
                --// Opção da 2323 Creditar a Conta-Corrente do RCA se não conceder desconto total (PCEDESCONTO.CREDITASOBREPOLITICA)
                IF (NVL(vscreditasobrepolitica,'N') = 'N') then
                  vnppolitica_pbaserca:= NVL(p_regitem.pvenda,0); --// Não Creditará
                --ELSE
                --  vnppolitica_pbaserca := NVL(vnppolitica_pbaserca,0); --// MANTÉM: Creditará
                END IF;
              END IF;
            --END IF; --// Fim Se a Promoção tinha Desconto
          END IF;

          ---------------------------------
          -- Finaliza Histórico do Desconto
          ---------------------------------
          p_regorigemdesc.basedebcredrca              := vsbasecreddebrca;
