    /******************************************
     Pesquisa Promoção Vigente - HIS.03889.2014
           (QUE ALTERA O PTABELA)
     ******************************************/

     -- 5685.084449.2016
     -- Se Restringe a pesquisa à promoção enviada no Item do Pedido
     -- e a Promoção enviada no Item do Pedido for de Desconto -> DEVE IGNORAR A PESQUISA DE PROMOÇÃO para não ficar dando mensagem de rejeição sem necessidade
     IF ( (NVL(p_regpedido.restringirpromocaomed,'N') = 'S') OR
          (NVL(p_regfilial.restringirpromocaofvmed,'N') = 'S') OR
          (NVL(vrDadosPromocaoItem.vvTipoPromoPrecoDesc,'D') = 'N') ) AND
          (NVL(vrDadosPromocaoItem.vvTipoPromoPrecoDesc,'D') IN ('D','N','M')) THEN -- HIS.03831.2017 - Incluso "N"

       NULL; -->> Não Validar Promoção aqui quando a Promoção enviada no Item do Pedido for de Desconto ou Bonificação

     ELSE

       -- Chama Procedimento para Retornar a Promoção Vigente
       INTEGRADORACOMPLE_MED.P_OBTEM_DESC_PROMOCAO(1,
                                   'N', -- Não grava Tabela Temporária,
                                   'N', -- Não executa Commit
                                   p_regpedido.data,
                                   p_regpedido.codfilial,
                                   p_regfilial.tipoprazomedicam,
                                   p_regcliente.numregiao,
                                   p_regpedido.codusur,
                                   p_regpedido.origemped,
                                   p_regpedido.tipofv,
                                   vnCodPlPagProduto,
                                   p_regpedido.codcondicaovenda,
                                   p_regitem.codpromocaomed, -- Promoção do Item pra Priorização
                                   p_regpedido.codcli,
                                   p_regproduto.codprod,
                                   p_regitem.qt,
                                   vrRetornoPromocao.vvTipoPromoPrecoDesc,
                                   vrRetornoPromocao.vnCodDesconto,
                                   vrRetornoPromocao.vnCodPromocaoMed,
                                   vrRetornoPromocao.vnPrecoFixo,
                                   vrRetornoPromocao.vnPercDesc,
                                   vrRetornoPromocao.vnPercDescFin,
                                   vrRetornoPromocao.vnInicioIntervaloQt,
                                   vrRetornoPromocao.vnVlDescCmv,         -- DDMEDICA-5009
                                   vrRetornoPromocao.vnPerDescCmv,        -- DDMEDICA-5009
                                   vrRetornoPromocao.vnNumVerba,          -- DDMEDICA-5009
                                   vrRetornoPromocao.vnValorCotaNumVerba, -- DDMEDICA-5009
                                   vrRetornoPromocao.vvSemVerbaVlDescCmv, -- DDMEDICA-5009
                                   vrRetornoPromocao.vvOcorreramErros,
                                   vrRetornoPromocao.vvMsgErros,
                                   NULL,
                                   case when
                                   (nvl(p_regitem.codpromocaomed,0) > 0) OR
                                   (NVL(p_regfilial.restringirpromocaofvmed,'N') = 'S') THEN
                                   'S' ELSE 'N' END,      -- 5685.084449.2016
                                   NVL(vrDadosPromocaoItem.vvTipoPromoPrecoDesc,'D'),  -- 5685.084449.2016
                                   p_regitem.PVENDA1BASEPROMOMARKUP,   -- DDMEDICA-6841 - Usar o Preço Tabela sem Taxa no Cálculo do Desconto do Markup
                                   p_regitem.customarkupmed,           -- DDMEDICA-6900
                                   p_regitem.percmarkupmed,            -- DDMEDICA-6837
                                   p_regpedido.integradora,
                                   p_regfilial.concedenteferta);

        -- Se Restringe a pesquisa do preço fixo à promoção enviada no Item do Pedido -- 5685.084449.2016
        IF ((NVL(p_regpedido.restringirpromocaomed,'N') = 'S') OR
            (NVL(p_regfilial.restringirpromocaofvmed,'N') = 'S')) AND
           (NVL(p_regitem.codpromocaomed,0) > 0) AND
           (NVL(p_regitem.codpromocaomed,0) <> NVL(vrRetornoPromocao.vnCodPromocaoMed,0)) THEN
            -- Se não encontrou o Código da Promoção do Item nos Preços Fixos Vigentes, rejeita o Item
            vrRetornoPromocao.vvOcorreramErros := 'S';
            vrRetornoPromocao.vvMsgErros       := 'Promoção de Preço Fixo não encontrada ou fora da vigência';
            -- LOG
            PGRAVA_LOG_TEXTO('', '');
            PGRAVA_LOG_TEXTO('Retorno FV PP', 'INTEGRADORACOMPLE_MED.P_OBTEM_DESC_PROMOCAO');
            PGRAVA_LOG_TEXTO('vrRetornoPromocao.vvMsgErros', vrRetornoPromocao.vvMsgErros);
            PGRAVA_LOG_TEXTO('Promocao do Item', p_regitem.codpromocaomed);
            PGRAVA_LOG_TEXTO('Promocao Encontrada', vrRetornoPromocao.vnCodPromocaoMed);
            PGRAVA_LOG_TEXTO('Tipo Promocao Encontrada', vrDadosPromocaoItem.vvTipoPromoPrecoDesc);
            PGRAVA_LOG_TEXTO('Valor Verba Promoção', vrRetornoPromocao.vnVlDescCmv);
            PGRAVA_LOG_TEXTO('Número Verba Promoção', vrRetornoPromocao.vnNumVerba);
            PGRAVA_LOG_TEXTO('Valor Cota Verba Promoção', vrRetornoPromocao.vnValorCotaNumVerba);
            PGRAVA_LOG_TEXTO('Sem NUMVERBA', vrRetornoPromocao.vvSemVerbaVlDescCmv);
            PGRAVA_LOG_TEXTO('PTabela Markup', p_regitem.PVENDA1BASEPROMOMARKUP);
            PGRAVA_LOG_TEXTO('Custo Markup', p_regitem.customarkupmed);
            PGRAVA_LOG_TEXTO('% Markup', p_regitem.percmarkupmed);
        END IF;

       -- Se ocorreram Erros
       IF (NVL(vrRetornoPromocao.vvOcorreramErros,'N') = 'S') THEN

         IF (NVL(p_regfilial.rejeitarpedpromoinvalidafv,'N') = 'S') THEN
           p_regpedido.valido := false;
         ELSE
           p_regitem.valido := false;
         END IF;

            if p_Regitem.codmotivonaoatend is null then
               p_regitem.codmotivonaoatend :=26 ;

            end if;


           if vsmensagem is not null then
              vschar := '#';
            else
              vschar := null;
            end if;
            vsmensagem              := vsmensagem || vschar ||
                                       'Aviso Preço de Fixo da Promoção: '|| vrRetornoPromocao.vvMsgErros;

            -- LOG
            PGRAVA_LOG_TEXTO('', '');
            PGRAVA_LOG_TEXTO('Retorno FV PP', 'INTEGRADORACOMPLE_MED.P_OBTEM_DESC_PROMOCAO');
            PGRAVA_LOG_TEXTO('Aviso Preço de Fixo da Promoção', vrRetornoPromocao.vvMsgErros);

       ELSE

         -- Se a Promoção Vigente for de Preço Fixo
         IF (vrRetornoPromocao.vvTipoPromoPrecoDesc = 'P') THEN

           ---------------------------------------------------------------------------
           -- Variáveis para Log
           ---------------------------------------------------------------------------
           vvTipoPromocaoLog      := vvTipoPromocaoLog || vrRetornoPromocao.vvTipoPromoPrecoDesc;
           vnPrecoFixoPromocaoLog := vrRetornoPromocao.vnPrecoFixo;
           vnCodPromocaoLog       := vrRetornoPromocao.vnCodPromocaoMed; -- 5685.084449.2016

           ---------------------------------------------------------------------------
           -- Atualiza Item do Pedido
           ---------------------------------------------------------------------------
           p_regproduto.ptabela               := vrRetornoPromocao.vnPrecoFixo;
           vnpercdescfinpolitica              := vrRetornoPromocao.vnPercDescFin; -- DDMEDICA-6837
           PGRAVA_LOG_PTABELA(p_regproduto.ptabela,'vnPrecoFixo da Promoção',vrRetornoPromocao.vnPrecoFixo,NULL,NULL);
           PGRAVA_LOG_PTABELA(vnpercdescfinpolitica,'vnPercDescFin da Promoção',vrRetornoPromocao.vnPercDescFin,NULL,NULL);
           PGRAVA_LOG_TEXTO('Valor Verba Promoção', vrRetornoPromocao.vnVlDescCmv);
           PGRAVA_LOG_TEXTO('Número Verba Promoção', vrRetornoPromocao.vnNumVerba);
           PGRAVA_LOG_TEXTO('Valor Cota Verba Promoção', vrRetornoPromocao.vnValorCotaNumVerba);
           PGRAVA_LOG_TEXTO('Sem NUMVERBA', vrRetornoPromocao.vvSemVerbaVlDescCmv);
           p_regitem.pbaserca                 := vrRetornoPromocao.vnPrecoFixo;
           --DDVENDAS-41882 - Quando a opção "creditar a conta corrente do RCA..." estava desmarcada na 2323 quando o tipo de política
           --é de Preço Fixo(P) mesmo assim estava creditando. 
           BEGIN
             SELECT NVL(PCDESCONTO.BASECREDDEBRCA, 'N')
                  , NVL(PCDESCONTO.CREDITASOBREPOLITICA,'S')
                  , PCDESCONTO.DTINICIO
                  , PCDESCONTO.DTFIM
                  , PCDESCONTO.PERCDESCBASERCA -- DESC_BASE_RCA_PRM
               INTO vsbasecreddebrca
                  , vscreditasobrepolitica
                  , vdDtInicioFlexPromocao
                  , vdDtFimFlexPromocao
                  , vnPerDescBaseRcaPrm        -- DESC_BASE_RCA_PRM
               FROM PCDESCONTO
              WHERE (PCDESCONTO.CODDESCONTO    = vrRetornoPromocao.vnCodDesconto)
                AND (PCDESCONTO.CODPROMOCAOMED = vrRetornoPromocao.vnCodPromocaoMed)
                AND (ROWNUM                    = 1);
           EXCEPTION
             WHEN NO_DATA_FOUND THEN
               vsbasecreddebrca       := 'N';
               vscreditasobrepolitica := 'S';
               vdDtInicioFlexPromocao := NULL;
               vdDtFimFlexPromocao    := NULL;
           END;                 
                     
           IF (NVL(p_regitem.pvenda,0) > NVL(p_regitem.pbaserca,0)) THEN
               --Opção da 2323 Creditar a Conta-Corrente do RCA se não conceder desconto total (PCEDESCONTO.CREDITASOBREPOLITICA)
               IF (NVL(vscreditasobrepolitica,'N') = 'N') then
                 p_regitem.pbaserca:= NVL(p_regitem.pvenda,0); --Não Creditará               
               END IF;
           END IF;
           --DDVENDAS-41882 FIM            
           p_regitem.coddesconto              := vrRetornoPromocao.vnCodDesconto;
           p_regitem.codpromocaomed           := vrRetornoPromocao.vnCodPromocaoMed;
           p_regitem.numverbacampanha         := vrRetornoPromocao.vnNumVerba;  -- DDMEDICA-5009
           p_regitem.vldesccmvpromocaomed     := vrRetornoPromocao.vnVlDescCmv; -- DDMEDICA-5009           
           p_regitem.iniciointervalodescquant := vrRetornoPromocao.vnInicioIntervaloQt;
           p_regitem.aplicoupromocao          := 'S';

         END IF;

       END IF; -- Fim Condição Se ocorreram Erros

     END IF; -- Fim Condição: 5685.084449.2016 - Ignora a Pesquisa de Promoção de Preço Fixo


   if p_regfilial.utilizacontrolemedicamentos = 'S' then

       -- Venda Tipo 1
       if p_regpedido.condvenda = 1 then

            -- HIS.04408.2015
            IF (FUNCOES_MED.FUNC_UTILIZAPRECOFABRICA(p_regproduto.tipomerc,
                                                     p_regproduto.utilizaprecofabrica,
                                                     p_regpedido.tipofv)) THEN

              --tarefa 136584

              p_regitem.precomaxconsum := p_regproduto.precomaxconsum;

              -- Preços ZFM passaram a ser pesquisados na PRC_MED_OBTEM_PMC_PRODUTO
              p_regitem.poriginal    := p_regproduto.custorep;

             if p_regpedido.tipofv in ('OL','PE') then

                 -- PERBONIFIC para ficar igual à 2316
                 IF (NVL(p_regitem.perbonific,0) = 0) THEN
                   p_regitem.perbonific := nvl(p_regproduto.percbonificvenda,0);
                 END IF;

                 p_regitem.vlbonific  := (p_regproduto.ptabela * p_regitem.perbonific)/100;

             else

              if gregpcconsum.usadescporlinhaprod = 'S' and gregpcconsum.aceitadescflexprodmonitorado = 'S'
                 and p_regcliente.origempreco = 'F' then


                 begin

                   select p.percbonific,p.percdesccom
                   into p_regitem.perbonific,p_regitem.perdesccom
                   from pcplpagi p
                   where p.codplpag = p_regpedido.codplpag
                   and   p.codlinhaprod = p_regproduto.codlinhaprod;
                  exception when others then

                     p_regitem.perbonific := 0;
                     p_regitem.perdesccom := 0;
                  end;



                   p_regitem.vlbonific  := (p_regproduto.ptabela * p_regitem.perbonific)/100;

                   p_Regitem.vldesccom := (p_regproduto.ptabela * p_regitem.perdesccom)/100;


               else
                   p_regitem.perbonific := nvl(p_regproduto.percbonificvenda,0);
                   p_regitem.vlbonific  := (p_regproduto.ptabela * p_regitem.perbonific)/100;

               end if;
               end if;
             end if;

           -- HIS.02854.2015 - Comentado durante o desenvolvimento da tarefa, o preço tabela e base rca estava ficando diferente da 2316, que não abate o valor da bonificação no ptabela e pbaserca
           --p_regproduto.ptabela := round(p_regproduto.ptabela - nvl(p_regitem.vlbonific,0) - nvl(p_regitem.vldesccom,0),gregpcconsum.numcasasdecvenda);
           --p_regitem.pbaserca    := round(p_regitem.pbaserca - nvl(p_regitem.vlbonific,0) - nvl(p_regitem.vldesccom,0),gregpcconsum.numcasasdecvenda);

       -- Diferente de Venda Tipo 1
       else

            -- HIS.03249.2016 - Durante a validação da alteração da comissão, identificado que vendas <> tipo 1 precisam do PMC
            IF (FUNCOES_MED.FUNC_UTILIZAPRECOFABRICA(p_regproduto.tipomerc,
                                                     p_regproduto.utilizaprecofabrica,
                                                     p_regpedido.tipofv)) THEN

              p_regitem.precomaxconsum := p_regproduto.precomaxconsum;

            END IF;

       end if;




       --tarefa 147507
        -- MED-1645 - Por causa da politica da 561 para baixar a base rca que faz chegar vbexistepolitica = False,
        --            precisei mudar a condição
        --if vbexistepolitica = true  then
    if ((nvl(p_regitem.USACASHBACK,'N') = 'S') AND (nvl(p_regitem.perdescboleto,0) > 0 )) THEN
    
        if (nvl(p_regfilial.basecalcdescfinmed,'1') = '2') then
                p_regitem.VLDESCBOLETO := round((nvl(p_regitem.pvenda,0) - nvl(p_regitem.vlrepasse,0)) * (nvl(p_regitem.perdescboleto,0)/100),6); -- MED-1645
                PGRAVA_LOG_VALOR('Valor Desconto Boleto pelo Líquido', p_regitem.VLDESCBOLETO);
              -- Se a Base de Cálculo do Desconto Financeiro for o Preço Bruto
              else
                p_regitem.VLDESCBOLETO := round(p_regproduto.ptabela * (nvl(p_regitem.perdescboleto,0)/100),6); -- MED-1645
                PGRAVA_LOG_VALOR('Valor Desconto Boleto pelo Bruto', p_regitem.VLDESCBOLETO);
              end if;
    
        elsif (nvl(vnpercdescfinpolitica,0) > 0) then

            if nvl(p_regitem.perdescboleto,0) <= nvl(vnpercdescfinpolitica,0) then

              -- Tarefa: 184043 - Se a Base de Cálculo do Desconto Financeiro for o Preço Liquido
              if (nvl(p_regfilial.basecalcdescfinmed,'1') = '2') then
                p_regitem.VLDESCBOLETO := round((nvl(p_regitem.pvenda,0) - nvl(p_regitem.vlrepasse,0)) * (nvl(p_regitem.perdescboleto,0)/100),6); -- MED-1645
                PGRAVA_LOG_VALOR('Valor Desconto Boleto pelo Líquido', p_regitem.VLDESCBOLETO);
              -- Se a Base de Cálculo do Desconto Financeiro for o Preço Bruto
              else
                p_regitem.VLDESCBOLETO := round(p_regproduto.ptabela * (nvl(p_regitem.perdescboleto,0)/100),6); -- MED-1645
                PGRAVA_LOG_VALOR('Valor Desconto Boleto pelo Bruto', p_regitem.VLDESCBOLETO);
              end if;


            else


                 if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;

                    vsmensagem              := vsmensagem || vschar ||
                                               'DESCONTO FINANCEIRO ENVIADO : '||nvl(p_regitem.perdescboleto,0);
                    vsmensagem              := vsmensagem || ' ACIMA DO PERMITIDO : ' ||
                                               nvl(vnpercdescfinpolitica,0) || ';';

                    p_regitem.valido        := false;
                    p_regorigempreco.valido := false;

                  if p_Regitem.codmotivonaoatend is null then
                     p_regitem.codmotivonaoatend := 26;

                  end if;
            end if;

        else

           if nvl(p_regitem.perdescboleto,0) > 0 then


                 if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;

                    vsmensagem              := vsmensagem || vschar ||
                                               'DESCONTO FINANCEIRO ENVIADO : '||nvl(p_regitem.perdescboleto,0);
                    vsmensagem              := vsmensagem || ' ACIMA DO PERMITIDO : ' ||
                                               0 || ';';

                    p_regitem.valido        := false;
                    p_regorigempreco.valido := false;

                  if p_Regitem.codmotivonaoatend is null then
                     p_regitem.codmotivonaoatend := 26;

                  end if;


           else

               p_regitem.perdescboleto := 0;
               p_regitem.vldescboleto := 0;
           end if;

        end if;



        -- HIS.04408.2015
         IF ((FUNCOES_MED.FUNC_UTILIZAPRECOFABRICA(p_regproduto.tipomerc,
                                                   p_regproduto.utilizaprecofabrica,
                                                   p_regpedido.tipofv)) AND
             (p_Regproduto.utilizaprecomaxconsumidor = 'S')) THEN


           if p_regcliente.origempreco = 'F' then

               if nvl(p_regproduto.precomaxconsum,0) <> 0 and (p_regitem.pvenda > p_regproduto.precomaxconsum) then

                      if vsmensagem is not null then
