                      vsmensagem              := vsmensagem || 'PRECO DE VENDA: ' ||
                                                 p_regitem.pvenda || ';';
                      vsmensagem              := vsmensagem || 'PRECO MAX CONSUM  : ' ||
                                                 p_regproduto.precomaxconsum || ';';

                      p_regitem.valido        := false;
                      p_regorigempreco.valido := false;

                      if p_Regitem.codmotivonaoatend is null then
                         p_regitem.codmotivonaoatend := 27;

                      end if;


               end if;

            elsif p_regcliente.origempreco = 'T' then

               if nvl(p_regprecos.precomaxconsum,0)<> 0 and ( p_regitem.pvenda > p_regprecos.precomaxconsum) then

                   p_Regitem.valido := false;

                      if vsmensagem is not null then
                        vschar := '#';
                      else
                        vschar := null;
                      end if;

                      vsmensagem              := vsmensagem || vschar ||
                                                 'PRECO DE VENDAS ACIMA DO PRECO MAX CONSUMIDOR;';
                      vsmensagem              := vsmensagem || 'PRECO DE VENDA: ' ||
                                                 p_regitem.pvenda || ';';
                      vsmensagem              := vsmensagem || 'PRECO MAX CONSUM  : ' ||
                                                 p_regprecos.precomaxconsum || ';';

                      p_regitem.valido        := false;
                      p_regorigempreco.valido := false;

                    if p_Regitem.codmotivonaoatend is null then
                       p_regitem.codmotivonaoatend := 27;

                    end if;



               end if;

           end if;


        end if;

     ------------------------------------------------------
     -- Validação de Preço Acima do Fábrica - DDMEDICA-7688
     -- Deve ser antes de somar o Repasse
     ------------------------------------------------------
     PGRAVA_LOG_TEXTO('Permite Venda acima PF', p_regfilial.permitevendacimapf);
     PGRAVA_LOG_TEXTO('Tipo Merc', p_regproduto.tipomerc);
     PGRAVA_LOG_TEXTO('Utiliza PF', p_regproduto.utilizaprecofabrica);
     PGRAVA_LOG_VALOR('Preço Fábrica', p_Regproduto.custorep);
     PGRAVA_LOG_VALOR('Preço Venda', p_regitem.pvenda);
     IF (FUNC_VALIDA_PRECO_ACIMAFABRICA(p_regproduto.tipomerc,
                                        p_regproduto.utilizaprecofabrica,
                                        p_regpedido.tipofv)) THEN -- DDVENDAS-31641
       PGRAVA_LOG_TEXTO('Valida Preço Fábrica', 'Sim');
       IF (F_PRECO_ACIMA_FABRICA(p_regfilial.permitevendacimapf,
                                 p_Regproduto.custorep,
                                 p_regitem.pvenda)) THEN
         if vsmensagem is not null then
           vschar := '#';
         else
           vschar := null;
         end if;
         vsmensagem := vsmensagem || vschar ||
                       'PRECO DE VENDA ' || p_regitem.pvenda || ' ACIMA DO PREÇO FÁBRICA ' || p_Regproduto.custorep || ';';
         p_regitem.valido := false;
         p_regorigempreco.valido := false;  
         if p_Regitem.codmotivonaoatend is null then
           p_regitem.codmotivonaoatend := 27;
         end if;
       END IF;
     END IF;


   end if;


         if p_regitem.cesta = 'S' and (p_Regproduto.ptabela <> vnptabelacesta) and vbvalidoprecofixocesta = false
          then

            vnperdesccesta := ((vnptabelacesta -  p_regproduto.ptabela ) /
                                  vnptabelacesta);

            vnsubtotal     := 0;

            vnpvendamaior := 0;

            vncount := gvet_regitenscesta.count;

            for i in 1 .. vncount
            loop

              if p_regpedido.numped = gvet_regitenscesta(i).numped
                 and p_regitem.codprod = gvet_regitenscesta(i).codprodcesta
              then

                gvet_regitenscesta(i).pvenda := round(gvet_regitenscesta(i).pvenda -
                                                      (gvet_regitenscesta(i).pvenda * vnperdesccesta)
                                                     ,gregpcconsum.numcasasdecvenda);

                gvet_regitenscesta(i).ptabela := round(gvet_regitenscesta(i).ptabela -
                                                      (gvet_regitenscesta(i).ptabela * vnperdesccesta)
                                                     ,gregpcconsum.numcasasdecvenda);


                vnsubtotal := vnsubtotal +
                              (gvet_regitenscesta(i).pvenda * gvet_regitenscesta(i).qt);


                if gvet_regitenscesta(i).pvenda > vnpvendamaior then
                   vnpvendamaior := gvet_regitenscesta(i).pvenda;
                   vnreg := i;

                end if;

              end if;


            end loop;

            if vnsubtotal <> p_regproduto.ptabela
            then

              vndif := (p_regproduto.ptabela - vnsubtotal)/gvet_regitenscesta(vnreg).qt;

              gvet_regitenscesta(vnreg).pvenda := round(gvet_regitenscesta(vnreg).pvenda + vndif,gregpcconsum.numcasasdecvenda);
              gvet_regitenscesta(vnreg).ptabela := round(gvet_regitenscesta(vnreg).ptabela + vndif,gregpcconsum.numcasasdecvenda);


            end if;
          end if;

          if p_regitem.cesta = 'S' and (p_regitem.pvenda <> p_Regproduto.ptabela)
          then

            vnperdesccesta := ((p_regproduto.ptabela - p_regitem.pvenda) /
                              p_regproduto.ptabela);
            vnsubtotal     := 0;

            vnpvendamaior := 0;
            vndif := 0;

            vncount := gvet_regitenscesta.count;

            for i in 1 .. vncount
            loop

              if p_regpedido.numped = gvet_regitenscesta(i)
              .numped
                 and p_regitem.codprod = gvet_regitenscesta(i).codprodcesta
              then

                gvet_regitenscesta(i).pvenda := round(gvet_regitenscesta(i)
                                                      .pvenda -
                                                      (gvet_regitenscesta(i)
                                                       .pvenda * vnperdesccesta)
                                                     ,gregpcconsum.numcasasdecvenda);


                vnsubtotal := vnsubtotal +
                              (gvet_regitenscesta(i).pvenda * gvet_regitenscesta(i).qt);


                if gvet_regitenscesta(i).pvenda > vnpvendamaior then
                   vnpvendamaior := gvet_regitenscesta(i).pvenda;
                   vnreg := i;

                end if;

              end if;


            end loop;

            if vnsubtotal <> p_regitem.pvenda
            then

              vndif := (p_regitem.pvenda - vnsubtotal)/gvet_regitenscesta(vnreg).qt;

              gvet_regitenscesta(vnreg).pvenda := round(gvet_regitenscesta(vnreg).pvenda + vndif,gregpcconsum.numcasasdecvenda);


            end if;
          end if;



      --*** ESTAVA AQUI: Bloco movido para depois do Cálculo do Preço Mínimo e Máximo, para o Repasse não interferir na Conta da Validação do Preço, IGUAL A 2316 ***---


      -- calculo preco minimo
      vnpvendamin := (ROUND(p_regproduto.ptabela,
                            gregpcconsum.numcasasdecvenda)) *
                     (1 - (vnpermaxdesc / 100));
      vnpvendamin := ROUND(vnpvendamin, gregpcconsum.numcasasdecvenda);




      -- calculo preco maximo
      vnpvendamax   := (ROUND(p_regproduto.ptabela,
                              gregpcconsum.numcasasdecvenda)) *
                       (1 + vnpermaxvenda / 100);

      vnpvendamax   := ROUND(vnpvendamax, gregpcconsum.numcasasdecvenda);

      vnptabela_ant := p_regproduto.ptabela;


      ---------------------
      -- RESTRIÇÃO DE PREÇO
      ---------------------
      -- Restrição Preço/Desconto
      IF (NOT FUNCOES_MED.FValidarRestricaoPrecoDescMed(p_regpedido.codfilial,
                                                        p_regitem.codprod,
                                                        p_regitem.pvenda,
                                                        'FV',
                                                        vvMsgRestricaoPrecoDescMed)) THEN
        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;
        vsmensagem := vsmensagem || vschar || vvMsgRestricaoPrecoDescMed;
        p_regitem.valido        := FALSE;
        p_regorigempreco.valido := FALSE;
        if p_Regitem.codmotivonaoatend is null then
           p_regitem.codmotivonaoatend := 26;
        end if;
      END IF;
      -- FIM RESTRIÇÃO DE PREÇO

      if p_Regfilial.broker = 'N' then

      if p_regpedido.condvenda not in (10, 20) or (p_regpedido.condvenda = 20 and p_regfilial.validarprecovendatv20 = 'S') then

      if p_Regitem.codcombo is  null then

      -- IMPORTANTE: 2.1 verifica desconto permitido para validar autorização de venda
      -- (Origem: proc_validaritemped() e ...)
      if p_regitem.pvenda < vnpvendamin then

        -- Como padrão rejeita produto
        vbRejeicaoPrecoMinimo := TRUE;
        IF (NVL(p_regfilial.meddifaceiteprecominimofv,0) > 0) THEN
          IF (ABS(p_regitem.pvenda - vnpvendamin) <= NVL(p_regfilial.meddifaceiteprecominimofv,0)) THEN
            -- Se usa parâmetro permitindo diferença até difaceiteprecominimofv e está dentro desse universo, não rejeita
            vbRejeicaoPrecoMinimo := FALSE;
          END IF;
        END IF;

        -- Se realmente rejeitar o produto
        IF (vbRejeicaoPrecoMinimo) THEN

          vbvalido_autori := funcoesvendas.validarautorizacaovenda(p_regpedido.numped,
                                                                   p_regpedido.codcli,
                                                                   p_regpedido.codusur,
                                                                   p_regpedido.codplpag,
                                                                   8888,
                                                                   p_regitem.codprod,
                                                                   vnptabela_ant,
                                                                   p_regproduto.ptabela,
                                                                   p_regitem.pvenda,
                                                                   p_regitem.codauxiliar,
                                                                   vnpermaxdesc,
                                                                   gregpcconsum.numcasasdecvenda,
                                                                   gregpcconsum.utilizavendaporembalagem,
                                                                   p_regitem.pbaserca,
                                                                   vnpvendamin,
                                                                   vsmensagemautori);
          if vbvalido_autori = false then

            if p_regfilial.aceitadesctmkfv = 'S' then
              p_Regpedido.posicao := 'B';

              p_regpedido.codmotivo := 5;
              p_Regpedido.motivoposicao := p_Regitem.codprod||'- Item com desconto acima do permitido';

              p_regitem.codmotivoposicaomed := 6; --DDMEDICA-2742
              vvMotivoPosicaoMed            := 'Preço ' || INTEGRADORACOMPLE_MED.FFORMATAR_NUMERO_PARA_TEXTO(p_regitem.pvenda,gregpcconsum.numcasasdecvenda) || ' abaixo do preço mínimo permitido de ' || INTEGRADORACOMPLE_MED.FFORMATAR_NUMERO_PARA_TEXTO(vnpvendamin,gregpcconsum.numcasasdecvenda);--DDMEDICA-2742
              p_regitem.motivoposicaomed    := SUBSTR(vvMotivoPosicaoMed,1,80);

              p_regpedido.motivoposicao := 'Item com preco acima do permitido';

             -- p_regpedido.log := p_regpedido.log||CHR(13)||p_Regitem.codprod||'- Item com desconto acima do permitido';
            elsif p_regfilial.aceitadesctmkfv = 'RP' then

              p_regpedido.valido := false;

              if p_regpedido.vbexisteitemcomdesc = false then
                p_Regpedido.vbexisteitemcomdesc := true;

                  proc_registralog(p_regpedido.numped,
                                   p_regpedido.numpedrca,
                                   null,
                                   null,
                                   p_Regitem.cgccli,
                                   null,
                                   null,
                                   null,
                                   p_regpedido.codusur,
                                   p_regitem.dtaberturapedpalm,
                                   null,
                                   '2',
                                   'Pedido possui item com desconto acima do permitido.',
                                   null,
                                   null);

              end if;

            else
              p_regitem.valido        := vbvalido_autori;
              p_regorigempreco.valido := vbvalido_autori;

              if p_Regitem.codmotivonaoatend is null then
                 p_regitem.codmotivonaoatend := 26;

              end if;


            end if;

          else

            begin
              select pcautori.nrautorizacao,
                     pcautori.percdescautor,
                     pcautori.dataautorizacao,
                     pcautori.iniciointervalo,
                     pcautori.fimintervalo
                into vnnrautorizacao,
                     vnpercdescautor,
                     vddataautori,
                     vniniciointervalo,
                     vnfimintervalo
                from pcautori
               where data_utilizacao = trunc(SYSDATE)
                 AND statusutiliz = 'S'
                 AND numped = p_regpedido.numped
                 AND pvendido = p_regitem.pvenda;
            exception
              when others then
                vnnrautorizacao   := null;
                vnpercdescautor   := null;
                vddataautori      := null;
                vniniciointervalo := null;
                vnfimintervalo    := null;
            end;

            p_regorigempreco.CODAUTORIZACAO        := vnnrautorizacao;
            p_regorigempreco.PERCDESCAUTOR         := vnpercdescautor;
            p_regorigempreco.DTINICIOAUTOR         := vddataautori;
            p_regorigempreco.DTFIMAUTOR            := vddataautori;
            p_regorigempreco.INICIOINTERVALOAUTORI := vniniciointervalo;
            p_regorigempreco.FIMINTERVALOAUTORI    := vnfimintervalo;
            p_regorigempreco.TIPODESCFLEX          := '5';
            p_regorigempreco.PERCDESCFLEX          := vnpercdescautor;
            p_regorigempreco.DTINICIODESCFLEX      := vddataautori;
            p_regorigempreco.DTFIMDESCFLEX         := vddataautori;
            p_regorigempreco.CODDESCFLEX           := vnnrautorizacao;
          end if;

          if vsmensagemautori is not null then
            if vsmensagem is not null then
              vschar := '#';
            else
              vschar := null;
            end if;
            vsmensagem := vsmensagem || vschar || vsmensagemautori;

            -- 5685.084449.2016 - Gravar o Motivo Desconto Inválido
            if p_Regitem.codmotivonaoatend is null then
               p_regitem.codmotivonaoatend := 26;
            end if;

            -- Se usou Promoção
            --IF (NVL(p_regpedido.codpromocaomed,0) > 0) THEN
              vsmensagem := vsmensagem || vschar || '[ Promoção Pedido   '   || NVL(p_regpedido.codpromocaomed,0)      || ' / '  || -- 5685.084449.2016
                                                    'Promoção Item '         || NVL(p_regitem.codpromocaomed,0)        || ' >> ' || -- 5685.084449.2016
                                                    'PTabIni      = '  || NVL(vnPrecoTabelaPromocaoLog,0)              || ' ; '  ||
                                                    'PTabela      = '  || NVL(p_regproduto.ptabela,0)                  || ' ; '  ||
                                                    'Tipo Prm     = '  || NVL(vvTipoPromocaoLog,' ')                   || ' ; '  ||
                                                    '%Desc Prm    = '  || NVL(vnPercDescPromocaoLog,0)                 || ' ; '  ||
                                                    'Preço Prm    = '  || NVL(vnPrecoFixoPromocaoLog,0)                || ' ; '  ||
                                                    'Cód. Prm     = '  || NVL(vnCodPromocaoLog,0)                      || ' ; '  || -- 5685.084449.2016
                                                    'ParDifAceite = '  || NVL(p_regfilial.meddifaceiteprecominimofv,0) || ']';
               -- Log Específico
               p_regitem.logprocmed := vsmensagem || CHR(13);
            --END IF;
          end if;

        END IF; -- FIM: IF (vbRejeicaoPrecoMinimo) THEN

      end if; -- FIM: if p_regitem.pvenda < vnpvendamin then

      -- verifica preco minimo permitido
      if p_regitem.pvenda < round(p_regprecos.precominimovenda,gregpcconsum.numcasasdecvenda) then

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;

          vsmensagem              := vsmensagem || vschar ||
                                     'PRECO ABAIXO DO PRECO MINIMO;';
          vsmensagem              := vsmensagem || 'PRECO DE VENDA: ' ||
                                     p_regitem.pvenda || ';';
          vsmensagem              := vsmensagem || 'PRECO TABELA  : ' ||
                                     ROUND(p_regproduto.ptabela,
                                           gregpcconsum.numcasasdecvenda) || ';';
          vsmensagem              := vsmensagem || 'PRECO MINIMO  : ' ||
                                     round(p_regprecos.precominimovenda,gregpcconsum.numcasasdecvenda) || ';';


          if p_regfilial.tipoimportacaovenda = 'RI'  then
             p_regitem.valido := false;
             p_regorigempreco.valido := false;

            if p_Regitem.codmotivonaoatend is null then
               p_regitem.codmotivonaoatend := 27;

            end if;


          elsif p_regfilial.tipoimportacaovenda = 'RP'  then
             p_regpedido.valido := false;

              if p_Regpedido.codmotivonaoatend is null then
                 p_regpedido.codmotivonaoatend := 27;

              end if;


          elsif p_regfilial.tipoimportacaovenda = 'BP'  then
              p_Regpedido.posicao := 'B';
              p_regpedido.codmotivo := 5;

              if length(p_regpedido.log) <= 3000 or p_regpedido.log is null then
                p_regpedido.log       := p_regpedido.log || CHR(13) || 'Item com preco abaixo do preco minimo';
              end if;

              p_regpedido.motivoposicao := 'Item com preco abaixo do preco minimo';


          end if;

       end if; -- FIM: p_regitem.pvenda < round(p_regprecos.precominimovenda,gregpcconsum.numcasasdecvenda)

       end if;


      -- verifica preco maximo
      if p_regitem.pvenda > vnpvendamax then

        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;

        vsmensagem              := vsmensagem || vschar ||
                                   'PRECO ACIMA DO PERMITIDO;';
        vsmensagem              := vsmensagem || 'PRECO DE VENDA: ' ||
                                   p_regitem.pvenda || ';';
        vsmensagem              := vsmensagem || 'PRECO TABELA  : ' ||
                                   ROUND(p_regproduto.ptabela,
                                         gregpcconsum.numcasasdecvenda) || ';';
        vsmensagem              := vsmensagem || 'ACRESCIMO(%)  : ' ||
                                   NVL(vnpermaxvenda, 100) || ';';
        vsmensagem              := vsmensagem || 'PRECO MAXIMO  : ' ||
                                   vnpvendamax || ';';

        if p_regfilial.tipoimportacaovenda = 'RI'  then
           p_regitem.valido := false;
           p_regorigempreco.valido := false;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 27;

          end if;


        elsif p_regfilial.tipoimportacaovenda = 'RP'  then
           p_regpedido.valido := false;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 27;

          end if;


        elsif p_regfilial.tipoimportacaovenda = 'BP'  then
            p_regpedido.posicao   := 'B';
            p_regpedido.codmotivo := 6;

            if length(p_regpedido.log) <= 3000 or p_regpedido.log is null then
              p_regpedido.log       := p_regpedido.log || CHR(13) || 'Item com preco acima do permitido';
            end if;


        end if;

      end if;

      end if;

     end if; -- FIM: if p_Regfilial.broker = 'N' then



     -- INICIO: Bloco movido para depois do Cálculo do Preço Mínimo e Máximo, para o Repasse não interferir na Conta da Validação do Preço, IGUAL A 2316
     -- MED-1822 - Somente arredonda aqui se tiver repasse para ficar igual à 2316 a parte do ST
     IF (nvl(p_regitem.vlrepasse,0) <> 0) THEN
       -- DDMEDICA-3065 - Arredonda depois do ST
       --p_regproduto.ptabela := round(p_regproduto.ptabela + nvl(p_regitem.vlrepasse,0),gregpcconsum.numcasasdecvenda);
       --p_regitem.pbaserca := round(p_regitem.pbaserca + nvl(p_regitem.vlrepasse,0),gregpcconsum.numcasasdecvenda);
       p_regproduto.ptabela := p_regproduto.ptabela + nvl(p_regitem.vlrepasse,0);

       p_regitem.pbaserca := p_regitem.pbaserca + nvl(p_regitem.vlrepasse,0);
     END IF;
     -- FIM: Bloco movido para depois do Cálculo do Preço Mínimo e Máximo, para o Repasse não interferir na Conta da Validação do Preço, IGUAL A 2316

     -- Se o Pedido foi recebido por Integração de OL via Banco de Dados OU Se o Repasse for pelo STBCR
     -- deve somar o repasse ao preço porque recebeu ele líquido - HIS.00211.2016
     -- (PRE-REQUISITO ST BCR - Força de Vendas passar o Preço sem Repasse)
     IF (NVL(p_regpedido.integracaopedoperlog,'N')   = 'S')  OR
        (NVL(p_regfilial.TipoAplicRepasseFilial,' ') = 'AS') OR
        ((NVL(p_regpedido.origemped,' ') = 'F') AND (NVL(p_regpedido.tipofv,'FV') = 'FV') AND (NVL(p_regfilial.precosemrepassefv,'N') = 'S')) OR
        ((NVL(p_regpedido.origemped,' ') = 'W') AND (NVL(p_regfilial.somarrepasseprecoeccommerce,'N') = 'S')) THEN -- MED-1822 - E-Commerce
       -- MED-1822 - Somente arredonda aqui se tiver repasse para ficar igual à 2316 a parte do ST
       IF (nvl(p_regitem.vlrepasse,0) <> 0) THEN
         -- DDMEDICA-3065 - Arredonda depois do ST
         --p_regitem.pvenda := round(p_regitem.pvenda + nvl(p_regitem.vlrepasse,0),gregpcconsum.numcasasdecvenda);
         p_regitem.pvenda := p_regitem.pvenda + nvl(p_regitem.vlrepasse,0);
       END IF;
     END IF;

     -------------------------------------------------------------------------------------------------------
     -- 4493.064633.2016 - INICIO: ULTIMA VALIDAÇÃO - PREÇOS ZERADOS - para não dar erro de divisão por zero
     -------------------------------------------------------------------------------------------------------
     -- Preço Tabela
     if (nvl(p_regproduto.ptabela,0) = 0) then
       if vsmensagem is not null then
         vschar := '#';
       else
         vschar := null;
       end if;
       vsmensagem := vsmensagem || vschar ||
                     'PRECO TABELA ZERADO;';
       p_regitem.valido := false;
       p_regorigempreco.valido := false;

       if p_Regitem.codmotivonaoatend is null then
         p_regitem.codmotivonaoatend := 27;
       end if;
     end if;
     -- Preço Venda
     if (nvl(p_regitem.pvenda,0) = 0) then
       if vsmensagem is not null then
         vschar := '#';
       else
         vschar := null;
       end if;
       vsmensagem := vsmensagem || vschar ||
                     'PRECO VENDA ZERADO;';
       p_regitem.valido := false;
       p_regorigempreco.valido := false;

       if p_Regitem.codmotivonaoatend is null then
         p_regitem.codmotivonaoatend := 27;
       end if;
     end if;
     ----------------------------------------------------------------------------------------------------
     -- 4493.064633.2016 - FIM: ULTIMA VALIDAÇÃO - PREÇOS ZERADOS - para não dar erro de divisão por zero
     ----------------------------------------------------------------------------------------------------

    end if; -- FIM: if p_Regitem.valido = true then



    if p_Regpedido.condvenda in (5, 6, 11, 12) then
      if gregpcconsum.usaptabelacomobase = 'S' then
        -- 4954.013038.2018 - Igualar a 2316, abatendo o Desconto da Promoção
        p_regitem.pbaserca := p_regproduto.ptabela * (1 - NVL(p_regitem.percdescbaserca,0) / 100);
      else
        p_regitem.pbaserca := p_regitem.pvenda;
      end if;
    end if;


    ---------------------------------------------
    -- INICIO: TETOS DE DESCONTO - HIS.00365.2016
    ---------------------------------------------
    -- Calcula Desconto para uso na Proc. de Validação
    IF ((p_regproduto.ptabela-NVL(p_regitem.st,0)-NVL(p_regitem.vlrepasse,0)) <> 0) THEN
      vrDadosRetValidaProd.vnPercDesc := ( ( (p_regproduto.ptabela-NVL(p_regitem.st,0)-NVL(p_regitem.vlrepasse,0)) - (p_regitem.pvenda-NVL(p_regitem.st,0)-NVL(p_regitem.vlrepasse,0)) ) / (p_regproduto.ptabela-NVL(p_regitem.st,0)-NVL(p_regitem.vlrepasse,0)) ) * 100;
    ELSE
      vrDadosRetValidaProd.vnPercDesc := 0;
    END IF;
    -- Chama Proc. de Validação - DDVENDAS-35778
    PKG_FUNCOESVENDAS_MED.P_VALIDACAO_FINAL_PROD_01('I', -- Origem Chamada = Integradora
                                                    'I', -- Tipo Chamada = Inclusão do Item do Pedido
                                                    'S', -- Grava Tabela Temporária
                                                    p_regpedido.origemped,
                                                    p_regpedido.tipofv,
                                                    p_regpedido.integradora,
                                                    p_regpedido.codfilial,
                                                    p_regpedido.codfilialnf,
                                                    p_regitem.codfilialretira,
                                                    p_regpedido.codcli,
                                                    p_regregiao.numregiao,
                                                    p_regpedido.codusur,
                                                    p_regitem.codplpag,
                                                    p_regitem.codpromocaomed,
                                                    p_regitem.codprod,
                                                    p_regitem.qt,
                                                    vrDadosRetValidaProd.vnPercDesc,
                                                    (p_regitem.pvenda-NVL(p_regitem.st,0)-NVL(p_regitem.vlrepasse,0)),
                                                    0, -- Aqui ainda não tem NumPed (Passar zero)
                                                    0, -- Aqui ainda não tem NumSeq (Passar zero)
                                                    p_regitem.precomaxconsum, -- HIS.01765.2016
                                                    vrDadosRetValidaProd.vvTipoRejeicaoProduto,
                                                    vrDadosRetValidaProd.vvMotivoNaoPodeComprar,
                                                    vrDadosRetValidaProd.vnQtdeLimite,
                                                    p_regitem.coddesconto,
                                                    NULL, -- Aqui não tem NUMLOTE
                                                    p_regitem.numlotepromocaomed,
                                                    (p_regproduto.ptabela-NVL(p_regitem.st,0)-NVL(p_regitem.vlrepasse,0)),
                                                    p_regitem.PVENDA1BASEPROMOMARKUP,
                                                    p_regitem.customarkupmed);
    -->> Primeiro verifica críticas que bloqueiam
    FOR vc_Rejeicoes IN (SELECT PCMED_VALIDACAO_GERAL_PRODUTO.CODREJEICAO
                              , PCMED_VALIDACAO_GERAL_PRODUTO.CODMOTIVONAOATEND
                              , PCMED_VALIDACAO_GERAL_PRODUTO.DESCRICAOREJEICAO
                              , PCMED_VALIDACAO_GERAL_PRODUTO.OBSERVACAO
                           FROM PCMED_VALIDACAO_GERAL_PRODUTO
                          WHERE (PCMED_VALIDACAO_GERAL_PRODUTO.TIPOREJEICAO = 'B')) LOOP -->> Somente Críticas que Bloqueiam o Item
      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem := vsmensagem || vschar || vc_Rejeicoes.CODREJEICAO || '-' || vc_Rejeicoes.DESCRICAOREJEICAO ||' (' || vc_Rejeicoes.OBSERVACAO || ')';
      p_regpedido.posicao   := 'B';
      p_regpedido.codmotivo := 6; -->> deverá ser adicionado campo de código de motivo na PCMED_VALIDACAO_GERAL_PRODUTO
      if p_Regitem.codmotivonaoatend is null then
         p_regitem.codmotivonaoatend := vc_Rejeicoes.CODMOTIVONAOATEND;
      end if;
    END LOOP;
    -->> Depois verifica críticas que rejeitam
    FOR vc_Rejeicoes IN (SELECT PCMED_VALIDACAO_GERAL_PRODUTO.CODREJEICAO
                              , PCMED_VALIDACAO_GERAL_PRODUTO.CODMOTIVONAOATEND
                              , PCMED_VALIDACAO_GERAL_PRODUTO.DESCRICAOREJEICAO
                              , PCMED_VALIDACAO_GERAL_PRODUTO.OBSERVACAO
                           FROM PCMED_VALIDACAO_GERAL_PRODUTO
                          WHERE (PCMED_VALIDACAO_GERAL_PRODUTO.TIPOREJEICAO = 'R')) LOOP -->> Somente Críticas que Rejeitam o Item
      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem := vsmensagem || vschar || vc_Rejeicoes.CODREJEICAO || '-' || vc_Rejeicoes.DESCRICAOREJEICAO ||' (' || vc_Rejeicoes.OBSERVACAO || ')';
      p_regitem.valido        := FALSE;
      p_regorigempreco.valido := FALSE;
      if p_Regitem.codmotivonaoatend is null then
         p_regitem.codmotivonaoatend := vc_Rejeicoes.CODMOTIVONAOATEND;
      end if;
    END LOOP;
    ---------------------------------------------
    -- FIM: TETOS DE DESCONTO - HIS.00365.2016
    ---------------------------------------------

    end if;

    -- Se Gravou Array de Log Específico
    IF (vtLogImportacaoItem.COUNT > 0) THEN
      FOR viIdxImportacaoItem IN vtLogImportacaoItem.FIRST..vtLogImportacaoItem.LAST LOOP
        -- Log Específico
        p_regitem.logprocmed := p_regitem.logprocmed || vtLogImportacaoItem(viIdxImportacaoItem) || CHR(13);
      END LOOP;
    END IF;

    -- registra log
    if (vsmensagem is not null) then
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       p_regitem.codprod,
                       p_regitem.codauxiliar,
                       p_Regitem.cgccli,
                       null,
                       null,
                       null,
                       p_regpedido.codusur,
                       p_Regpedido.dtaberturapedpalm,
                       null,
                       '3',
                       vsmensagem,
                       null,
                       p_Regitem.numseqifv);
    end if;
  exception
    when others then

      p_regitem.valido        := false;
      p_regorigempreco.valido := false;
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       p_regitem.codprod,
                       p_regitem.codauxiliar,
                       p_Regitem.cgccli,
                       null,
                       null,
                       null,
                       p_regpedido.codusur,
                       p_regitem.dtaberturapedpalm,
                       null,
                       '3',
                       sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->002->' || SQLERRM,
                       null,
                       p_Regitem.numseqifv);

      if p_Regitem.codmotivonaoatend is null then
         p_regitem.codmotivonaoatend := 28;

      end if;


  end proc_validaritemped;


procedure proc_validaritemOLePE(p_regitem        in out t_itemped,
                                p_regorigempreco in out t_origempreco,
                                p_regpedido      in out t_cabped,
                                p_regcliente     in t_clientepedido,
                                p_regrca         in t_rca,
                                p_regregiao      in t_regiaocliente,
                                p_regplpag       in t_planodepagamento,
                                p_regplpagetico  in t_plpagetico,
                                p_regplpaggenerico  in t_plpaggenerico,
                                p_regfilial      in t_filial,
                                p_regproduto     out t_produto,
                                p_regprecos      out t_precosetributacao,
                                vscoddistrib     in pcprodut.coddistrib%type) is

    vicontador                   number;
    vsmensagem                   varchar2(32767) := null;
    vsmensagempolitica           varchar2(32767);
    vschar                       varchar2(1) default '#';
    vnpermaxdesc                 number;
    vnpvendamin                  number;
    vnpvendamax                  number;
    vbexistepolitica             boolean;
    vnpercdescquant              pcdescquant.percdesc%type;
    vnpercdescpolitica           pcdesconto.percdesc%type;
    vsbasecreddebrca             pcdesconto.basecreddebrca%type;
    vndesconto                   number;
    vnpvenda_autori              number;
    vbvalidoprecofixo            boolean := true;
    vnprecofixo                  number;
    vnperdescativ                number;
    vnptabela_ant                number;
    vnppolitica                  number;
    vnptabeladescquant           number;
    vsmensagemdescquant          varchar2(32767);
    vddtfim                      date;
    vbvalidodescquant            boolean := false;
    vsmensagemprecofixo          varchar2(32767);
    vnpermaxvenda                number;
    vsmensagempolitica_acres     varchar2(32767);
    vbexistepolitica_acres       boolean;
    vnpercdescpolitica_acres     pcdesconto.percdesc%type;
    vsmensagem_rest              varchar2(32767);
    vscreditasobrepolitica       varchar2(1);
    vnpercaux                    number;
    vnpercquantflex              number;
    vscreditasobreptabela        varchar2(1);
    vsmensagemautori             varchar2(1000);
    vbvalido_autori              boolean;
    vnpercdescpolitica_acres_aux pcdesconto.percdesc%type;
    vnnrautorizacao              number;
    vnpercdescautor              number;
    vddataautori                 date;
    vniniciointervalo            number;
    vnfimintervalo               number;
    vncodst                      pctribut.codst%type;
    vsbasecreddebrca_quant       pcdescquant.basecreddebrca%type;
    vnpercbaserca_quant          pcdescquant.percdesc%type;
    vnptabelaaux                 pcpedi.ptabela%type;

    vsalteraptabela              pcdesconto.alteraptabela%type;
    vnpercpbaserca               pcdesconto.percdesc%type;
    vnqt                         number;
    vbRetValidarrestricaovenda   boolean;


    vbecesta                     boolean;
    vsmensagemcesta              varchar2(300);
    vsmensagemitenscesta         varchar2(300);
    vnptabelacesta               number;
    vbvalidoprecofixocesta       boolean;
    vnsubtotal                   number;
    vnperdesccesta               number := 0;
    vnpvendamaior                number;
    vnreg                        number;
    vndif                        number;
    vncount                      number ;
    vnmultiplo                   pcprodfilial.multiplo%type;

    vscodfilialnf                pcfilial.codigo%type;
   vbcalculosemimposto          boolean;
    vnpvendasemimposto           pcpedi.pvenda%type;
    vnptabelasemimposto          pcpedi.ptabela%type;
    vsmensagemprecosemimposto    varchar2(300);


    vsprioritaria                pcdesconto.prioritaria%type;
    vsquestionaprioritaria       pcdesconto.questionausoprioritaria%type;
    vsprioritaria_aux            pcdesconto.prioritaria%type;
    vsquestionaprioritaria_aux   pcdesconto.questionausoprioritaria%type;
    vnperdescprioritaria         number;
    vsrotprioritaria             varchar2(3);

    vnpercpbaserca_desc          pcdescquant.percdesc%type;
    vnperdesc                    number;

    vsocorreramerros             varchar2(1);
    vsmensagemdescontos          varchar2(500);
    vnptabela_aux                number;

    vstipovalidadescindustria    pccondvendalinha.tipovalidadescindustria%type;
    vndescmaxindustria           pccondvendalinha.descmaxindustria%type;

    -- HIS.01334.2014
    vvPodeComprarProduto       VARCHAR2(1);
    vvMotivoNaoPodeComprar     VARCHAR2(4000);
    vnQtdeLimiteAlvara         pcpedi.qt%type;
    --
    vvMsgPmcUf                 VARCHAR2(4000);

    -- Variáveis para uso na função de obter Promoção - HIS.03889.2014
    TYPE TRecRetornoPromocao   IS RECORD(
         vvTipoPromoPrecoDesc  VARCHAR2(1),
         vnCodDesconto         PCDESCONTO.CODDESCONTO%TYPE,
         vnCodPromocaoMed      PCDESCONTO.CODPROMOCAOMED%TYPE,
         vnPrecoFixo           PCDESCONTO.PRECOFIXOPROMOCAOMED%TYPE,
         vnPercDesc            PCDESCONTO.PERCDESC%TYPE,
         vnPercDescFin         PCDESCONTO.PERCDESCFIN%TYPE,
         vnInicioIntervaloQt   PCDESCONTO.INICIOINTERVALOPROMOCAOMED%TYPE,
         vnVlDescCmv           PCDESCONTO.VLDESCCMVPROMOCAOMED%TYPE, -- DDMEDICA-5009
         vnPerDescCmv          NUMBER, -- DDMEDICA-5009
         vnNumVerba            NUMBER, -- DDMEDICA-5009
         vnValorCotaNumVerba   NUMBER, -- DDMEDICA-5009
         vvSemVerbaVlDescCmv   VARCHAR2(1), -- DDMEDICA-5009
         vvOcorreramErros      VARCHAR2(1),
         vvMsgErros            VARCHAR2(240),
         vvMsgProc             VARCHAR2(4000));
    vrRetornoPromocao          TRecRetornoPromocao;
    vnCodPlPagProduto          pcplpag.codplpag%type;
    --

    -- Variáveis para uso na função de obter st fonte em clientes não fonte
    TYPE TRecRetornoStFonte     IS RECORD(
         vnBaseicstFonte        PCPEDI.BASEICST%TYPE,
         vnStFonte              PCPEDI.ST%TYPE,
         vsMensagemStFonte      VARCHAR2(100),
         vvRegimeEspIsenStFonte PCTRIBUT.REGIMEESPISENSTFONTE%TYPE,
         vnAliqIcms1Fonte       PCTRIBUT.ALIQICMS1FONTE%TYPE,
         vnAliqIcms2Fonte       PCTRIBUT.ALIQICMS2FONTE%TYPE,
         vnIvaFonte             PCTRIBUT.IVAFONTE%TYPE,
         vnPercBaseRedStFonte   PCTRIBUT.PERCBASEREDSTFONTE%TYPE,
         vnPauta                PCPEDI.PAUTA%TYPE, -- HIS.03377.2017
         vvObservacaoStFonte    PCPEDI.OBSERVACAOSTFONTE%TYPE,  -- HIS.03377.2017
         vvIndEscalaRelevante   PCPEDI.INDESCALARELEVANTE%TYPE, -- HIS.03377.2017
         vvCnpjFabricante       PCPEDI.CNPJFABRICANTE%TYPE, -- HIS.03377.2017
         vvFabricante           PCPEDI.FABRICANTE%TYPE, -- HIS.03377.2017
         vnStClienteGnreFonte   PCPEDI.STCLIENTEGNRE%TYPE,   -- DDMEDICA-7697
         vnPmPfMedicamento      PCPEDI.PMPFMEDICAMENTO%TYPE, -- DDMEDICA-7697
         vvClienteFonteSt       PCCLIENT.CLIENTEFONTEST%TYPE -- DDMEDICA-7697
         );
    vrRetornoStFonte            TRecRetornoStFonte;

    -- Restrição Preço/Desconto
    vvMsgRestricaoPrecoDescMed  VARCHAR2(2000);

    -- Dados do Repassse
    TYPE TRecDadosRepasse       IS RECORD(
         vnValorRepasse         PCPEDI.VLREPASSE%TYPE,
         vvTipoRepasse          VARCHAR2(2),
         vvMensagemRepasse      VARCHAR2(2000));
    vrDadosRepasse              TRecDadosRepasse;

    -- TETOS DE DESCONTO - HIS.00365.2016
    TYPE TRecDadosRetValidaProd IS RECORD(
         vnPercDesc             NUMBER,
         vvTipoRejeicaoProduto  VARCHAR2(1),
         vvMotivoNaoPodeComprar VARCHAR2(2000),
         vnQtdeLimite           NUMBER);
    vrDadosRetValidaProd        TRecDadosRetValidaProd;

    -- ACORDO PREÇO PEDIDO ELETRÔNICO
    TYPE TRecDadosRetAcordoPE   IS RECORD(
         vvAchouAcordo          VARCHAR2(1),
         vnCodAcordo            NUMBER,
         vnCodPromocaoMed       NUMBER,
         vvTipoPromocao         VARCHAR2(2),
         vnPreco                NUMBER,
         vnPercDesc             NUMBER,
         vnVlDescCmv            PCDESCONTO.VLDESCCMVPROMOCAOMED%TYPE, -- DDMEDICA-5009
         vnPerDescCmv           NUMBER,      -- DDMEDICA-5009
         vnNumVerba             NUMBER,      -- DDMEDICA-5009
         vnValorCotaNumVerba    NUMBER,      -- DDMEDICA-5009
         vvSemVerbaVlDescCmv    VARCHAR2(1), -- DDMEDICA-5009
         vvOcorreramErros       VARCHAR2(1),
         vvMsgErros             VARCHAR2(250));
    vrDadosRetAcordoPE          TRecDadosRetAcordoPE;

    -- HIS.01889.2017 - Obter a Taxa do Acordo de Parceria
    TYPE TRecDadosAcordoParceria IS RECORD(
         vvAchouTaxa             VARCHAR2(1),
         vnCodAcordo             NUMBER,
         vnPercTaxa              NUMBER,
         vnPerCom                NUMBER,
         vvCampo                 VARCHAR2(250));
    vrDadosAcordoParceria        TRecDadosAcordoParceria;

    -- Array para Armazenar o LOG da Importação do Item
    TYPE TTLogImportacaoItem    IS TABLE OF VARCHAR2(2000) INDEX BY BINARY_INTEGER;
    vtLogImportacaoItem         TTLogImportacaoItem;
    -- Array para Armazenar o JSON da Importação do Item - MED-1503
    TYPE TTJsonImportacaoItem   IS TABLE OF VARCHAR2(32000) INDEX BY BINARY_INTEGER;
    vtJsonImportacaoItem        TTJsonImportacaoItem;

    -- Record de Retorno das Validações - MED-1503
    TYPE TRecRetValidacao       IS RECORD(
         vvRejeitado            VARCHAR2(1),
         vvMotivoRejeitado      VARCHAR2(255),
         vvObservacao           VARCHAR2(32000),
         vvRetJson              VARCHAR2(32000),
         vnValorRetorno         NUMBER);
    vrRetValidacao              TRecRetValidacao;

    -- Dados dos Itens do Funcep - HIS.04200.2017
    TYPE TRecDadosFuncep               IS RECORD(
         nVLBASEFCPICMS                PCPEDI.VLBASEFCPICMS%TYPE,      -- HIS.04200.2017
         nVLBASEFCPST                  PCPEDI.VLBASEFCPST%TYPE,        -- HIS.04200.2017
         nVLBCFCPSTRET                 PCPEDI.VLBCFCPSTRET%TYPE,       -- HIS.04200.2017
         nPERFCPSTRET                  PCPEDI.PERFCPSTRET%TYPE,        -- HIS.04200.2017
         nVLFCPSTRET                   PCPEDI.VLFCPSTRET%TYPE,         -- HIS.04200.2017
         nPERFCPSN                     PCPEDI.PERFCPSN%TYPE,           -- HIS.04200.2017
         nVLFECP                       PCPEDI.VLFECP%TYPE,             -- HIS.04200.2017
         nVLACRESCIMOFUNCEP            PCPEDI.VLACRESCIMOFUNCEP%TYPE,  -- HIS.04200.2017
         nPERACRESCIMOFUNCEP           PCPEDI.PERACRESCIMOFUNCEP%TYPE, -- HIS.04200.2017
         nALIQICMSFECP                 PCPEDI.ALIQICMSFECP%TYPE,       -- HIS.04200.2017
         nVLCREDFCPICMSSN              PCPEDI.VLCREDFCPICMSSN%TYPE,    -- HIS.04200.2017
         nCODCONFIGFUNCEPMED           PCPEDI.CODCONFIGFUNCEPMED%TYPE  -- HIS.04200.2017
         );
    vrDadosFuncep                      TRecDadosFuncep;

    -- Retorno do Pré-Cadastro de Descontos da Indústria - DDMEDICA-1835
    TYPE TRecRetCadDescIndustria       IS RECORD(
         vnPrioridade                  NUMBER,
         vvTipo                        VARCHAR2(200),
         vnPercentual                  NUMBER,
         vnPercRefDebCred              NUMBER,
         vnPercAcrescimo               NUMBER,
         vnPrioridadeAcrescimo         NUMBER);
    vrRetCadDescIndustria              TRecRetCadDescIndustria;

    vPRIORIZARCAINTEGRADORARCALIN VARCHAR2(200);

    -- Parâmetro Específico SERVCON - DDMEDICA-5511
    vREJEITARITEMFORAFAIXAPROMOQT      PCREGRASEXCECAOMED.VALOR%TYPE;

    -- DDMEDICA-5980
    TYPE TRecDadosPromocaoItem IS RECORD(
         vvTipoPromoPrecoDesc  VARCHAR2(1),
         vvTipoPromocao        PCPROMOCAOMED.TIPOPROMOCAO%TYPE); -- DDVENDAS-33961
    vrDadosPromocaoItem        TRecDadosPromocaoItem;

    -- DDMEDICA-6900
    vvAchouCustoMarkup         VARCHAR2(255);

    -- DDMEDICA-7697
    TYPE TRecDadosStAntecip        IS RECORD(
         nBCSTRETANTERIOR          PCPEDI.BCSTRETANTERIOR%TYPE,
         nVLICMSSUBSTITUTOANTERIOR PCPEDI.VLICMSSUBSTITUTOANTERIOR%TYPE,
         nVLICMSSTRETANTERIOR      PCPEDI.VLICMSSTRETANTERIOR%TYPE);
    vrDadosStAntecip               TRecDadosStAntecip;
    
    -- DDVENDAS-33961
    vnPrecoBaseDescIndustriaOferta NUMBER;
    vnPercDescIndustriaOferta      NUMBER;
    
    -- PROCEDIMENTO PARA GRAVAÇÃO DO LOG DE TEXO GERAL DO ITEM
    PROCEDURE PGRAVA_LOG_TEXTO(pi_vMensagem IN VARCHAR2,
                               pi_vValor    IN VARCHAR2) IS
      vvMensagemLogImportacaoItem VARCHAR2(2000);
      viIdxLogImpItem             INTEGER;
    BEGIN
      viIdxLogImpItem := NVL(vtLogImportacaoItem.COUNT,0) + 1;

      vvMensagemLogImportacaoItem := '[' || TRIM(TO_CHAR(viIdxLogImpItem,'0000')) || '] ' || pi_vMensagem || ': ' || NVL(pi_vValor,' ');

      vtLogImportacaoItem(viIdxLogImpItem) := SUBSTR(vvMensagemLogImportacaoItem,1,2000);
    END PGRAVA_LOG_TEXTO;

    -- PROCEDIMENTO PARA GRAVAÇÃO DO LOG DE VALOR GERAL DO ITEM
    PROCEDURE PGRAVA_LOG_VALOR(pi_vMensagem IN VARCHAR2,
                               pi_nValor    IN NUMBER) IS
      vvMensagemLogImportacaoItem VARCHAR2(2000);
      viIdxLogImpItem             INTEGER;
    BEGIN
      viIdxLogImpItem := NVL(vtLogImportacaoItem.COUNT,0) + 1;

      vvMensagemLogImportacaoItem := '[' || TRIM(TO_CHAR(viIdxLogImpItem,'0000')) || '] ' || pi_vMensagem || ': ' || NVL(pi_nValor,0);

      vtLogImportacaoItem(viIdxLogImpItem) := SUBSTR(vvMensagemLogImportacaoItem,1,2000);
    END PGRAVA_LOG_VALOR;

    -- PROCEDIMENTO PARA GRAVAÇÃO DO JSON DE VALOR GERAL DO ITEM - MED-1503
    PROCEDURE PGRAVA_JSON_ITEM(pi_vMensagem IN VARCHAR2) IS
      viIdxJsonImpItem INTEGER;
    BEGIN
      viIdxJsonImpItem := NVL(vtJsonImportacaoItem.COUNT,0) + 1;

      vtJsonImportacaoItem(viIdxJsonImpItem) := pi_vMensagem;
    END PGRAVA_JSON_ITEM;

  begin

    -- Inicializa Log do Item
    vtLogImportacaoItem.DELETE;
    -- Inicializa Json do Item - MED-1503
    vtJsonImportacaoItem.DELETE;

    p_regitem.valido        := true;

    vsmensagem              := null;

    p_regorigempreco.valido := true;
    p_regorigempreco.numped := p_regpedido.numped;
    p_regitem.codcli        := p_regpedido.codcli;
    p_regitem.vldescboleto  := 0;

    -- Dados da Promoção do Item do Pedido - DDMEDICA-5980
    -- Tipo da Promoção - DDVENDAS-33961
    BEGIN
      SELECT CASE
               WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('M'))     THEN
                 'D' -- DDMEDICA-6841 - Políticas de Markup são consideradas como Desconto
               WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('Q','D')) THEN
                 'D'
               WHEN (PCPROMOCAOMED.TIPOPOLITICA IN ('F','P')) THEN
                 'P'
               WHEN (PCPROMOCAOMED.TIPOPOLITICA = 'B')        AND
                    (PCPROMOCAOMED.TIPOPROMOCAO = 'N')        THEN -- HIS.03831.2017
                 'N'
             END TIPOPROMOPRECODESC
           , TIPOPROMOCAO  
        INTO vrDadosPromocaoItem.vvTipoPromoPrecoDesc
           , vrDadosPromocaoItem.vvTipoPromocao
        FROM PCPROMOCAOMED
       WHERE (PCPROMOCAOMED.CODPROMOCAOMED  = p_regitem.codpromocaomed);
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        BEGIN
          SELECT CASE
                   WHEN (PCLOGPROMOCAOMED.TIPOPOLITICA IN ('M'))     THEN
                     'D' -- DDMEDICA-6841 - Políticas de Markup são consideradas como Desconto
                   WHEN (PCLOGPROMOCAOMED.TIPOPOLITICA IN ('Q','D')) THEN
                     'D'
                   WHEN (PCLOGPROMOCAOMED.TIPOPOLITICA IN ('F','P')) THEN
                     'P'
                   WHEN (PCLOGPROMOCAOMED.TIPOPOLITICA = 'B')        AND
                        (PCLOGPROMOCAOMED.TIPOPROMOCAO = 'N')        THEN -- HIS.03831.2017
                     'N'
                 END TIPOPROMOPRECODESC
               , TIPOPROMOCAO 
            INTO vrDadosPromocaoItem.vvTipoPromoPrecoDesc
               , vrDadosPromocaoItem.vvTipoPromocao
            FROM PCLOGPROMOCAOMED
           WHERE (PCLOGPROMOCAOMED.CODPROMOCAOMED  = p_regitem.codpromocaomed)
             AND (ROWNUM                           = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vrDadosPromocaoItem.vvTipoPromoPrecoDesc := NULL;
            vrDadosPromocaoItem.vvTipoPromocao       := NULL;  
        END;
    END;
   
    -- RCA da Linha (OL e PE) - DDMEDICA-1835
    IF (p_regpedido.tipofv IN ('OL','PE')) THEN
      IF (FUSA_REGRA_MEDICAMENTOS('99',
                                  'APURARCOMISSAOPELORCALINHA') = 'S') THEN
        -- Não pode ser um RCA que veio no Pedido
        IF (NVL(INTEGRADORACOMPLE_MED.F_RCA_PREPOSTO(p_regpedido.codusur,
                                                     p_regpedido.codvendedorpedol),'N') <> 'S') THEN
          -- Verifica Parâmetro Específico para Manter o RCA da Integradora
          vPRIORIZARCAINTEGRADORARCALIN := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                                    'PRIORIZARCAINTEGRADORARCALINHA',
                                                                    'N');
