                     null,
                     null,
                     null,
                     null,
                     0,
                     nvl(pctribut.mostrarpvendasemst,gregpcconsum.mostrarpvendasemst),
                     nvl(pctribut.usapmcbasest,'N'),
                     nvl(pcest.custonfsemst,nvl(pcest.valorultent,0)),
                     nvl(pctribut.percredpvendasimplesnac,0),
                     nvl(pcest.vlstultent,0),
                     nvl(pctribut.percdifaliquotas,0),
                     nvl(pcest.custonfsemstguiaultent,0),
                     nvl(pcest.ivaultent,0),
                     nvl(pcest.aliqicms1ultent,0),
                     nvl(pcest.aliqicms2ultent,0),
                     nvl(pcest.redbaseivaultent,100),
                     nvl(pcest.percicmsfretefobstultent,0),
                     nvl(pcest.vlfreteconhecultent,0),
                     nvl(pcest.percaliqextguiaultent,0),
                     nvl(pcest.baseicmsultent,0),
                     nvl(pcest.vlstguiaultent,0),
                     nvl(pctribut.usaisencaoicmsvp,'S'),
                     nvl(pctribut.isencaostorgaopub,'N') ,
                     pctribut.pagtonomedocliente ,
                     nvl(pctabpr.perdescmaxbalcao,0) ,
                     pctabpr.precofab ,
                     null,
                     null,
                     null,
                     nvl(pctribut.usavlultentmediobasest, 'N'),
                     nvl(pctabpr.vlultentmes,0),
                     nvl(pctribut.usabaseicmsreduzida,'N'),
                     nvl(pctribut.usabcrultent,'N'),
                     nvl(pcest.basebcr,0),
                     nvl(pcest.stbcr,0),
                     nvl(pctribut.pautafonte,0),
                     nvl(pctribut.aplicadescisencaomed,'N'), --HIS.02613.2014
                     nvl(pctribut.usaptabelabasest,'N'),
                     nvl(pctribut.regimeespisenstfonte,'N'),
                     nvl(pctabpr.percdescsimplesnac,0),
                     NVL(pctribut.codicmtabinternac, 0), -- HIS.02787.2016
                     nvl(pctabpr.vlst,0), -- MED-1510
                     nvl(pctabpr.vlipi,0), -- MED-1510
                     nvl(pctribut.destacdescicmisencaocomercial,'N') -- DDMEDICA-3065
                into p_regprecos
                from pctabpr, pctribut, pcest, pcprodut
               where pctabpr.codst = pctribut.codst
                 and pctabpr.codprod = p_regitem.codprod
                 and pcest.codprod = p_regitem.codprod
                 and pctabpr.numregiao = p_regregiao.numregiao
                 and pcest.codfilial = decode(p_regfilial.origemcustofilialretira,'V',p_regpedido.codfilial,p_regitem.codfilialretira)
                 and pcprodut.codprod = p_regitem.codprod;
              PGRAVA_LOG_TEXTO('verificado informacoes da tabela de preco','Preço PROD/Região'); -- LOG

            exception
              when no_data_found then
                if vsmensagem is not null
                then
                  vschar := '#';
                else
                  vschar := null;
                end if;

                vsmensagem       := vsmensagem || vschar || 'preco do produto não encontrado (P10)#;';
                p_regitem.valido        := false;
                p_regorigempreco.valido := false;


                if p_Regitem.codmotivonaoatend is null then
                   p_regitem.codmotivonaoatend := 21;

                end if;

              when others then
                if vsmensagem is not null then
                  vschar := '#';
                else
                  vschar := null;
                end if;
                vsmensagem              := vsmensagem || vschar ||
                                           'ERRO AO BUSCAR PRECO DO PRODUTO#;' ||
                                           sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';';
                p_regitem.valido        := false;
                p_regorigempreco.valido := false;

                if p_Regitem.codmotivonaoatend is null then
                   p_regitem.codmotivonaoatend := 21;

                end if;

            end;


                  --tarefa 132437

                      p_regitem.qtpecas := null;

                      if p_regproduto.tipoestoque = 'FR' then


                          vnqt := p_Regitem.qt;

                          if  upper(trim(p_regitem.unidadevenda))  = upper(trim(p_Regproduto.unidademaster)) then

                              p_regitem.qt   := vnqt * p_regproduto.pesobrutomaster;
                              p_regitem.qtcx := vnqt;
                              p_regitem.qtpecas := null;
                              p_regprecos.qtunit := 1;

                          elsif upper(Trim(p_regitem.unidadevenda)) = 'PC' then
                              p_regitem.qt := vnqt * p_regproduto.pesopeca;
                              p_regitem.qtpecas := vnqt;
                              p_regitem.qtcx    := null;

                          end if;


                            IF p_regfilial.ARREDONDAQTEMBALFRIOS = 'S' THEN

                              P_REGITEM.QTCX := ROUND(P_REGITEM.QTCX);
                              P_REGITEM.QTPECAS := ROUND(P_REGITEM.QTPECAS) ;
                              P_REGITEM.QT := ROUND(P_REGITEM.QT) ;

                            END IF;

                    end if;  --fim 132437


          end if;

       END IF;




           if p_regfilial.PRECOPOREMBALAGEM = 'S' and p_regfilial.utilizavendaporembalagem = 'S' then

            --Varejo
            IF p_regfilial.tipoprecificacao <> 'A' THEN
             IF p_regprecos.qtminimaatacado > 1 THEN
              IF p_regitem.qt >= p_regprecos.qtminimaatacado THEN
               p_regproduto.ptabela := p_regprecos.pvendaatac/p_regprecos.qtunit;
               PGRAVA_LOG_VALOR('p_regproduto.ptabela varejo a' || ': ',p_regproduto.ptabela);
              ELSE
               p_regproduto.ptabela := p_regprecos.pvendaemb/p_regprecos.qtunit;
               PGRAVA_LOG_VALOR('p_regproduto.ptabela varejo b' || ': ',p_regproduto.ptabela);
              END IF;
             ELSE
              p_regproduto.ptabela := p_regprecos.pvendaemb/p_regprecos.qtunit;
              PGRAVA_LOG_VALOR('p_regproduto.ptabela varejo c' || ': ',p_regproduto.ptabela);
             END IF;
             --Atacado
            ELSE
              p_regproduto.ptabela := p_regprecos.pvendaatac/p_regprecos.qtunit;
              PGRAVA_LOG_VALOR('p_regproduto.ptabela atacado' || ': ',p_regproduto.ptabela);

            END IF;

           --tarefa 70944 verificar poferta como preco minimo
           IF (p_regprecos.poferta > 0) AND
               trunc(SYSDATE) BETWEEN p_regprecos.dtofertaini AND
               p_regprecos.dtofertafim then

               if p_regitem.qt < p_regprecos.qtminimaatacado then
                  p_regproduto.ptabela := p_regprecos.poferta/P_REGPRECOS.qtunit;
                  PGRAVA_LOG_VALOR('p_regproduto.ptabela oferta a' || ': ',p_regproduto.ptabela);
               end if;
            END IF;

            IF p_regfilial.tipoprecificacao <> 'A' THEN
             IF (p_regprecos.poferta > 0) AND
                (trunc(SYSDATE) BETWEEN p_regprecos.dtofertaini AND
                p_regprecos.dtofertafim) THEN
              IF p_regitem.qt < p_regprecos.qtminimaatacado then

              p_regproduto.ptabela := p_regprecos.poferta/P_REGPRECOS.QTUNIT;
              PGRAVA_LOG_VALOR('p_regproduto.ptabela oferta b' || ': ',p_regproduto.ptabela);
              END IF;
             END IF;
            ELSE
             IF (p_regprecos.pofertaatac > 0) AND
                (trunc(SYSDATE) BETWEEN p_regprecos.dtofertaatacini AND
                p_regprecos.dtofertaatacfim) THEN
              IF p_regitem.qt >= p_regprecos.qtminimaatacado THEN
              p_regproduto.ptabela := p_regprecos.pofertaatac/P_REGPRECOS.QTUNIT;
              PGRAVA_LOG_VALOR('p_regproduto.ptabela oferta c' || ': ',p_regproduto.ptabela);
              END IF;
             END IF;
            END IF;

                if nvl(p_regproduto.ptabela,0) = 0 then

                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem              := vsmensagem || vschar ||
                                             'PRECO DE TABELA ZERADO;';

                  p_regitem.valido        := false;
                  p_regorigempreco.valido := false;
                end if;


                if p_Regitem.codmotivonaoatend is null then
                   p_regitem.codmotivonaoatend := 21;

                end if;



         ELSE

           --PCNIL - TIPO PRECIFICAÇÃO ATACADO
           IF (NVL( p_regfilial.tipoprecificacao,'P') = 'A') THEN

             -- Se a Quantidade Vendida for abaixo do Mínimo da Quantidade Atacado
             IF ((NVL(p_regitem.qt,0) * NVL(p_regprecos.qtunit,0)) < NVL(p_regprecos.qtminimaatacado,0)) AND
                (NVL(p_regprecos.qtminimaatacado,0) > 0) then

               if p_regitem.numpr = 1
               then
                 p_regproduto.ptabela := p_regprecos.pvendaatac1;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvendaatac1' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 2
               then
                 p_regproduto.ptabela := p_regprecos.pvendaatac2;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvendaatac2' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 3
               then
                 p_regproduto.ptabela := p_regprecos.pvendaatac3;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvendaatac3' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 4
               then
                 p_regproduto.ptabela := p_regprecos.pvendaatac4;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvendaatac4' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 5
               then
                 p_regproduto.ptabela := p_regprecos.pvendaatac5;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvendaatac5' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 6
               then
                 p_regproduto.ptabela := p_regprecos.pvendaatac6;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvendaatac6' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 7
               then
                 p_regproduto.ptabela := p_regprecos.pvendaatac7;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvendaatac7' || ': ',p_regproduto.ptabela);
               end if;

             ELSE

               if p_regitem.numpr = 1
               then
                 p_regproduto.ptabela := p_regprecos.pvenda1;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda1' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 2
               then
                 p_regproduto.ptabela := p_regprecos.pvenda2;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda2' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 3
               then
                 p_regproduto.ptabela := p_regprecos.pvenda3;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda3' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 4
               then
                 p_regproduto.ptabela := p_regprecos.pvenda4;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda4' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 5
               then
                 p_regproduto.ptabela := p_regprecos.pvenda5;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda5' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 6
               then
                 p_regproduto.ptabela := p_regprecos.pvenda6;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda6' || ': ',p_regproduto.ptabela);
               elsif p_regitem.numpr = 7
               then
                 p_regproduto.ptabela := p_regprecos.pvenda7;
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda7' || ': ',p_regproduto.ptabela);
               end if;

             END IF;

           -- PRECIFICAÇÃO PADRÃO
           ELSE

              if p_regitem.numpr = 1
              then
                p_regproduto.ptabela := p_regprecos.pvenda1;
                PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda1 pad' || ': ',p_regproduto.ptabela);
              elsif p_regitem.numpr = 2
              then
                p_regproduto.ptabela := p_regprecos.pvenda2;
                PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda2 pad' || ': ',p_regproduto.ptabela);
              elsif p_regitem.numpr = 3
              then
                p_regproduto.ptabela := p_regprecos.pvenda3;
                PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda3 pad' || ': ',p_regproduto.ptabela);
              elsif p_regitem.numpr = 4
              then
                p_regproduto.ptabela := p_regprecos.pvenda4;
                PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda4 pad' || ': ',p_regproduto.ptabela);
              elsif p_regitem.numpr = 5
              then
                p_regproduto.ptabela := p_regprecos.pvenda5;
                PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda5 pad' || ': ',p_regproduto.ptabela);
              elsif p_regitem.numpr = 6
              then
                p_regproduto.ptabela := p_regprecos.pvenda6;
                PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda6 pad' || ': ',p_regproduto.ptabela);
              elsif p_regitem.numpr = 7
              then
                p_regproduto.ptabela := p_regprecos.pvenda7;
                PGRAVA_LOG_VALOR('p_regproduto.ptabela pvenda7 pad' || ': ',p_regproduto.ptabela);
              end if;

            END IF; -- FIM CONDIÇÃO TIPO PRECIFICAÇÃO

         end if;

end if;

   PGRAVA_LOG_VALOR('INICIO: p_regproduto.ptabela' || ': ',p_regproduto.ptabela);

   --------------------------------
   -- Se Cliente Simples Nacional
   -- e Filial usa Desconto Simples
   --------------------------------
   IF (p_regcliente.simplesnacional  = 'S') AND
      (p_regfilial.usadescsimplesnac = 'S') THEN

     -- Aplica o Desconto do Simples Nacional no Preço de Tabela (Somente se utilizar o Preço de Tabela por Região, Preço Fábrica não vai aplicar)
     IF (p_regpedido.origempreco = 'T') THEN
       p_regproduto.ptabela := p_regproduto.ptabela * (1 - (NVL(p_regprecos.percdescsimplesnac,0) / 100));
       PGRAVA_LOG_VALOR('Aplicar p_regprecos.percdescsimplesnac' || ': ',p_regprecos.percdescsimplesnac);
       PGRAVA_LOG_VALOR('p_regproduto.ptabela' || ': ',p_regproduto.ptabela);
     END IF;

   END IF;

   -- Inicia Variável que controlará Aplicação da Promoção - HIS.03889.2014
   p_regitem.aplicoupromocao := 'N';

   p_regitem.vlrepasse := null;
   p_regitem.vloutros := null;
   p_regitem.vlbonific := null;


    if p_regpedido.origemped = 'R' then
      if gregpcconsum.abatefretevendabalcao = 'S' and
         p_regprecos.descontafrete = 'S' then
        p_regorigempreco.TIPOFRETE := '1';
        p_regorigempreco.PERCFRETE := p_regregiao.perfrete;
      end if;

      if nvl(gregpcconsum.percacrescimobalcao, 0) > 0 then
        p_regorigempreco.PERCACRESCBALCAO := gregpcconsum.percacrescimobalcao;
      end if;

    end if;

    -- verifica se produto esta excluido na regiao
    if p_regprecos.excluido = 'S' then

      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem              := vsmensagem || vschar ||
                                 'PRODUTO EXCLUIDO DA REGIAO ;';

      p_regitem.valido        := false;
      p_regorigempreco.valido := false;


          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 12;

          end if;

    end if;

    -- 4180.122638.2016 - Revalidação do Custo do Produto - OL e PE
    IF (NVL(p_regprecos.custofin,0)  = 0) AND
       (NVL(p_regprecos.custoreal,0) = 0) AND
       (NVL(p_regprecos.custorep,0)  = 0) THEN

      PGRAVA_LOG_TEXTO('Revalidação dos Custos','');
      PGRAVA_LOG_VALOR('p_regitem.codprod',p_regitem.codprod);
      PGRAVA_LOG_VALOR('p_regregiao.numregiao',p_regregiao.numregiao);
      PGRAVA_LOG_TEXTO('p_regfilial.origemcustofilialretira',p_regfilial.origemcustofilialretira);
      PGRAVA_LOG_TEXTO('p_regpedido.codfilial',p_regpedido.codfilial);
      PGRAVA_LOG_TEXTO('p_regitem.codfilialretira',p_regitem.codfilialretira);
      PGRAVA_LOG_VALOR('vncodst',vncodst);
      PGRAVA_LOG_TEXTO('vscodfilialnf',vscodfilialnf);
      PGRAVA_LOG_TEXTO('p_Regcliente.estent',p_Regcliente.estent);

      -- Pesquisa Custos na PCEST
      BEGIN
        SELECT custofin
             , custoreal
             , custorep
          INTO p_regprecos.custofin
             , p_regprecos.custoreal
             , p_regprecos.custorep
          FROM PCEST
         WHERE CODPROD   = p_regitem.codprod
           AND CODFILIAL = decode(p_regfilial.origemcustofilialretira,'V',p_regpedido.codfilial,p_regitem.codfilialretira);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          PGRAVA_LOG_TEXTO('Custos não encontrados na PCEST','');
      END;

    END IF; -- Fim Condição Produtos sem Custos

    -- produto sem custo financeiro
    if p_regprecos.custofin = 0 then

      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem              := vsmensagem || vschar ||
                                 'PRODUTO SEM CUSTO FINANCEIRO;';

      p_regitem.valido        := false;
      p_regorigempreco.valido := false;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 23;

          end if;


    end if;

    -- produto sem custo real
    if p_regprecos.custoreal = 0 then
      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem              := vsmensagem || vschar ||
                                 'PRODUTO SEM CUSTO REAL;';

      p_regitem.valido        := false;
      p_regorigempreco.valido := false;


          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 23;

          end if;


    end if;

    -- produto sem custo real + crédito de icm
    if p_regprecos.custorep = 0 then

      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem              := vsmensagem || vschar ||
                                 'PRODUTO SEM CUSTO REPOSICAO;';

      p_regitem.valido        := false;
      p_regorigempreco.valido := false;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 23;

          end if;


    end if;


    --tarefa 130781
    if p_regfilial.utilizacontrolemedicamentos = 'N' and p_regfilial.precoporembalagem = 'N' and p_regitem.cesta = 'N' then
      -- verifica produto com preco 0 (zero)
      if (p_regprecos.pvenda <= 0) or (p_regprecos.pvenda1 <= 0) or
         (p_regprecos.pvenda2 <= 0) or (p_regprecos.pvenda3 <= 0) or
         (p_regprecos.pvenda4 <= 0) or (p_regprecos.pvenda5 <= 0) or
         (p_regprecos.pvenda6 <= 0) or (p_regprecos.pvenda7 <= 0) then

        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;
        vsmensagem              := vsmensagem || vschar ||
                                   'PRECO DE TABELA ZERADO;';

        p_regitem.valido        := false;
        p_regorigempreco.valido := false;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 21;

          end if;


      end if;
    end if;


     -- Inicializa Controle de Rejeição
     vrRetValidacao.vvRejeitado := 'N';

    /* MED-1499 - Usar nova Função
    --*** VALIDAR PRIMEIRAMENTE SE TEM LINHA DE PRAZO ***---
    IF (NVL(p_regproduto.codlinhaprazo,0) = 0) THEN

      p_regitem.valido := false;

      if vsmensagem is not null then
         vschar := '#';
       else
         vschar := null;
       end if;
       vsmensagem              := vsmensagem || vschar ||
                                  'Linha de Prazo não cadastrada na Rotina 203 - Cadastrar Produto. Produto não poderá ser importado.';

       if p_Regitem.codmotivonaoatend is null then
          p_regitem.codmotivonaoatend := 12; -- Problemas Cadastrais
       end if;

    END IF;

    --*** VALIDAR SE TEM CONDIÇÃO DE VENDA ***---
    IF (NVL(p_regpedido.codcondicaovenda,0) = 0) THEN

      p_regitem.valido := false;

      if vsmensagem is not null then
         vschar := '#';
       else
         vschar := null;
       end if;
       vsmensagem              := vsmensagem || vschar ||
                                  'Não foi encontrada Condição de Venda cadastrada na Rotina 2311 que atenda as regras da Integradora (Rotina 2302). Produto não poderá ser importado.';

       if p_Regitem.codmotivonaoatend is null then
          p_regitem.codmotivonaoatend := 12; -- Problemas Cadastrais
       end if;

    END IF;
    */
    --------------------------------------------------------------
    -- INICIO: MED-1499 - Validação de Cadastros de Linha de Prazo
    BEGIN
      INTEGRADORACOMPLE_MED.proc_validacadastrolinhaprazo(p_regpedido.integradora,
                                                          p_regpedido.tipofv,
                                                          p_regproduto.codlinhaprazo,
                                                          p_regpedido.codcondicaovenda,
                                                          p_regpedido.prazo_pcpedretorno,
                                                          p_regpedido.tipoprazo_pcpedretorno,
                                                          p_regpedido.codigoprazo_pcpedretorno,
                                                          vrRetValidacao.vvRejeitado,
                                                          vrRetValidacao.vvMotivoRejeitado,
                                                          vrRetValidacao.vvObservacao,
                                                          vrRetValidacao.vvRetJson);
      IF (vrRetValidacao.vvRejeitado = 'S') THEN

        -- Não é mais Válido
        p_regitem.valido := false;
        -- Atualiza Mensagem
        P_ADD_MENSAGEM('Rejeição 26: ' || vrRetValidacao.vvObservacao,
                       26,
                       vsmensagem,
                       p_regitem.codmotivonaoatend);
        -- Grava Json
        PGRAVA_JSON_ITEM(vrRetValidacao.vvRetJson);

      END IF;

    EXCEPTION
      WHEN OTHERS THEN
        -- Não é mais Válido
        p_regitem.valido := false;
        -- Atualiza Mensagem
        P_ADD_MENSAGEM('Erro ao validar linha de prazo. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                       26,
                       vsmensagem,
                       p_regitem.codmotivonaoatend);
    END;
    -- FIM:  MED-1499 - Validação de Cadastros de Linha de Prazo
    --------------------------------------------------------------

    ----------------------------------------------------
    -- Plano Pagamento da Linha de Prazo - DDMEDICA-7182
    ----------------------------------------------------
    IF (p_regfilial.tipoprazomedicam = '4') AND 
       (p_regitem.codplpagLinhaPrazo IS NULL) THEN
      p_regitem.codplpagLinhaPrazo := p_regpedido.codplpag;
    END IF;
    ---------------------------------------------  
    -- Plano Pagamento do Produto - DDMEDICA-6249
    ---------------------------------------------  
    vnCodPlPagProduto := INTEGRADORACOMPLE_MED.F_RETORNAR_PLPAG_ITEM(p_regfilial.tipoprazomedicam,
                                                                     p_regproduto.codprod,
                                                                     p_regitem.codplpagLinhaPrazo,
                                                                     p_regpedido.codplpag,
                                                                     p_regpedido.codplpagetico,
                                                                     p_regpedido.codplpaggenerico,
                                                                     p_regproduto.grupofaturamento);
    PGRAVA_LOG_TEXTO('Tipo de Prazo Med:', p_regfilial.tipoprazomedicam);
    PGRAVA_LOG_TEXTO('Plano do Pedido:', p_regpedido.codplpag);
    PGRAVA_LOG_TEXTO('Plano Ético do Pedido:', p_regpedido.codplpagetico);
    PGRAVA_LOG_TEXTO('Plano Genérico do Pedido:', p_regpedido.codplpaggenerico);
    PGRAVA_LOG_TEXTO('Plano da Linha:', p_regitem.codplpagLinhaPrazo);
    PGRAVA_LOG_TEXTO('Plano de Pagamento do Produto:', vnCodPlPagProduto);
    ---------------------------------------------  

    -- tratamento com relacao ao preco e descontos
    if p_regitem.valido = true then


    --tarefa 128635
    if p_regitem.cesta = 'S'
      then


        funcoesvendas.buscarprecocestabasica(p_regpedido.numped
                                            ,p_regitem.codprod
                                            ,p_regregiao.numregiao
                                            ,p_regitem.numpr
                                            ,vbecesta
                                            ,vnptabelacesta
                                            ,vsmensagemcesta
                                            ,p_regfilial.utilizavendaporembalagem
                                            ,p_regfilial.precoporembalagem
                                            ,p_regfilial.tipoprecificacao
                                            ,p_regpedido.codfilial
                                            ,p_regitem.qt);


        if vbecesta = false
        then

          if vsmensagem is not null
          then
            vschar := '#';
          else
            vschar := null;
          end if;

          vsmensagem       := vsmensagem || vschar ||
                              ' Nao encontrado cadastro como cesta';
          p_regitem.valido := false;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 12;

          end if;


        else
          p_regproduto.ptabela := vnptabelacesta;
          p_regitem.pbaserca := vnptabelacesta;
          p_regitem.pvenda1  := vnptabelacesta;


         /************************************************************************
          INICIO: PACOTE MEDICAMENTOS NÃO USA CESTA BÁSICA - proc_validaitenscesta
          ************************************************************************
          proc_validaitenscesta(p_regitem,
                                p_regorigempreco,
                                p_regproduto,
                                p_regpedido,
                                p_regfilial,
                                p_regregiao,
                                p_regcliente,
                                p_regplpag,
                                vsmensagemitenscesta,
                                vbvalidoprecofixocesta);
         /************************************************************************
          FIM: PACOTE MEDICAMENTOS NÃO USA CESTA BÁSICA - proc_validaitenscesta
          ************************************************************************/
          vsmensagemcesta := 'PROBLEMAS NA VALIDAÇÃO DA CESTA BÁSICA: INTEGRADORA_MED.proc_validaitenscesta';

        end if;

        if trim(vsmensagemcesta) is not null
        then

          if vsmensagem is not null
          then
            vschar := '#';
          else
            vschar := null;
          end if;

          vsmensagem       := vsmensagem || vschar || vsmensagemcesta;
          p_regitem.valido := false;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 12;

          end if;

        end if;

        if trim(vsmensagemitenscesta) is not null
        then

          if vsmensagem is not null
          then
            vschar := '#';
          else
            vschar := null;
          end if;

          vsmensagem       := vsmensagem || vschar || vsmensagemitenscesta;
          p_regitem.valido := false;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 12;

          end if;

        end if;

    else

      -- Validação Alvará por Controle de Venda -- HIS.01334.2014
      if (nvl(p_regfilial.validalvaraportipoctlven,'N') = 'S') then

         -- VALIDAÇÃO DE REJEIÇÃO DE ITEM
         PRC_MED_VALIDA_CONTROLE_VENDA('I', -->> Indicador de validação de Inclusão do Item
                                       p_Regpedido.codcli,
                                       p_regcliente.tipofj,
                                       p_regitem.codprod,
                                       p_regitem.qt,
                                       NULL, -- Na Integradora não precisa passar o Num. Pedido
                                       NULL, -- Na Integradora não precisa passar o Num. Seq.
                                       vvPodeComprarProduto,
                                       vvMotivoNaoPodeComprar,
                                       vnQtdeLimiteAlvara);
         -- Se não pode vender
         if (vvPodeComprarProduto <> 'S') then
              -- Se aceita parte da venda
              if (nvl(vnQtdeLimiteAlvara,0) > 0) then
                -- Altera a Quantidade
                p_regitem.qt := nvl(vnQtdeLimiteAlvara,0);
              else
                -- Item Inválido
                p_regitem.valido := false;
                p_regorigempreco.valido := false;

                IF vsmensagem IS NOT NULL
                THEN
                  vschar := '#';
                ELSE
                  vschar := NULL;
                END IF;

                vsmensagem := vsmensagem || vschar || vvMotivoNaoPodeComprar ||';';

                if p_Regitem.codmotivonaoatend is null then
                  p_regitem.codmotivonaoatend := 25;
                end if;
              end if;
         -- Se puder vender
         else
           -- VALIDAÇÃO DE BLOQUEIO DO PEDIDO
           PRC_MED_VALIDA_CONTROLE_VENDA('G', -->> Indicador de validação de gravação do pedido
                                         p_Regpedido.codcli,
                                         p_regcliente.tipofj,
                                         p_regitem.codprod,
                                         p_regitem.qt,
                                         NULL, -- Na Integradora não precisa passar o Num. Pedido
                                         NULL, -- Na Integradora não precisa passar o Num. Seq.
                                         vvPodeComprarProduto,
                                         vvMotivoNaoPodeComprar,
                                         vnQtdeLimiteAlvara);
           -- Se não pode vender
           if (vvPodeComprarProduto <> 'S') then
           
                -- DDVENDAS-37313 - Sobreposição do Bloqueio por Alvará Vencido
                IF (NVL(p_regfilial.sobreposicaobloqueioalvara,'NA') IN ('RP','RI')) THEN
                
                  -- Pedido Inválido
                  IF    (p_regfilial.sobreposicaobloqueioalvara = 'RP') THEN
                    p_regpedido.valido := false;
                    
                    if p_Regpedido.codmotivonaoatend is null then
                       p_regpedido.codmotivonaoatend := 25;

                    end if;
                    
                  -- Item Inválido
                  ELSIF (p_regfilial.sobreposicaobloqueioalvara = 'RI') THEN
                    p_regitem.valido := false;
                    p_regorigempreco.valido := false;
                    
                    if p_Regitem.codmotivonaoatend is null then
                      p_regitem.codmotivonaoatend := 25;
                    end if;
                    
                  END IF;
  
                  IF vsmensagem IS NOT NULL
                  THEN
                    vschar := '#';
                  ELSE
                    vschar := NULL;
                  END IF;
  
                  vsmensagem := vsmensagem || vschar || vvMotivoNaoPodeComprar ||';';
                                  
                ELSE
                
                  -- Bloqueia Pedido
                  p_Regpedido.posicao := 'B';
                  p_regpedido.codmotivo := 17;
  
                  p_regpedido.motivoposicao := 'Bloqueio por Tipo de Controle de Venda;';
  
                  IF vsmensagem IS NOT NULL
                  THEN
                    vschar := '#';
                  ELSE
                    vschar := NULL;
                  END IF;
  
                  vsmensagem := vsmensagem || vschar || vvMotivoNaoPodeComprar ||';';
                END IF;   
           end if;
         end if;

       end if; -- Fim Condição Validação Alvará por Controle de Venda


       -- DDMEDICA-6900 - Custo da Promoção de Markup
       p_regitem.tipocustomarkupmed := p_regfilial.custo_prom_markup_st;
       PKG_MEDICAMENTOS.P_OBTEM_CUSTO_PROMO_MARKUP(p_regpedido.codfilial,
                                                   p_regitem.codfilialretira,
                                                   p_regproduto.codprod,
                                                   p_regfilial.origemcustofilialretira,
                                                   p_regitem.tipocustomarkupmed,
                                                   NULL, -- Na Integradora não tem Crossdocking
                                                   p_regprecos.custofin,
                                                   vvAchouCustoMarkup,
                                                   p_regitem.customarkupmed);
       PGRAVA_LOG_TEXTO('origemcustofilialretira',p_regfilial.origemcustofilialretira);
       PGRAVA_LOG_TEXTO('tipocustomarkupmed',p_regitem.tipocustomarkupmed);
       PGRAVA_LOG_TEXTO('vvAchouCustoMarkup',vvAchouCustoMarkup);
       PGRAVA_LOG_VALOR('customarkupmed',p_regitem.customarkupmed);


      --tarefa 130781
      if p_regfilial.utilizacontrolemedicamentos = 'S' then

         -- Pedidos OL e Eletrônicos não observarão o parâmetro do cliente origem preço


         -- HIS.04408.2015
         IF (FUNCOES_MED.FUNC_UTILIZAPRECOFABRICA(p_regproduto.tipomerc,
                                                  p_regproduto.utilizaprecofabrica,
                                                  p_regpedido.tipofv)) THEN

           if p_regpedido.origempreco = 'F' then

               -- Preços ZFM passaram a ser pesquisados na PRC_MED_OBTEM_PMC_PRODUTO
               if nvl(p_Regproduto.custorep,0) = 0 then

                    if vsmensagem is not null then
                      vschar := '#';
                    else
                      vschar := null;
                    end if;
                    vsmensagem     := vsmensagem || vschar ||
                                               'PREÇO FÁBRICA DESTE PRODUTO ESTA ZERADO;';


                    -- 153405
                    p_regitem.valido        := false;
                    p_regorigempreco.valido := false;
                    if p_Regitem.codmotivonaoatend is null then
                      p_regitem.codmotivonaoatend := 21;
                    end if;


               else
                  p_regproduto.ptabela := p_regproduto.custorep;
                  PGRAVA_LOG_VALOR('p_regproduto.ptabela custorep' || ': ',p_regproduto.ptabela);
               end if;

           end if;

         end if;


         -- DDMEDICA-5980 - Guarda o Preço de Tabela sem a Taxa para usar no cálculo da promoção de markup
         p_regitem.PVENDA1BASEPROMOMARKUP := p_regproduto.ptabela;
         PGRAVA_LOG_VALOR('PVENDA1BASEPROMOMARKUP após Preço Fábrica',p_regitem.PVENDA1BASEPROMOMARKUP);                  

         -- LOG -- DDVENDAS-33961 - Ofertas do Operador Logístico
         vnPrecoBaseDescIndustriaOferta := p_regproduto.ptabela;
         PGRAVA_LOG_TEXTO('*** regitem.restringirpromocaomed', p_regitem.restringirpromocaomed);
         PGRAVA_LOG_TEXTO('*** p_regfilial.concedenteferta', p_regfilial.concedenteferta);

         ---------------------------------------------------------------------
         -- Parâmetro Específico SERVCON - DDMEDICA-2777
         -----------------------------------------------

         -- LOG -- DDVENDAS-31504
         PGRAVA_LOG_TEXTO('*** restringirpromocaomed', p_regpedido.restringirpromocaomed);
         PGRAVA_LOG_TEXTO('*** integracaopedoperlog', p_regpedido.integracaopedoperlog);

         -- LOG
         PGRAVA_LOG_TEXTO('', '');
         PGRAVA_LOG_TEXTO('REJEITARITEMSEMPROMOCAOPE', FUSA_REGRA_MEDICAMENTOS('99','REJEITARITEMSEMPROMOCAOPE'));

         -- Se usa Regra Específica SERVCON
         IF (NVL(FUSA_REGRA_MEDICAMENTOS('99','REJEITARITEMSEMPROMOCAOPE'),'N') = 'S') THEN

           -- LOG
           PGRAVA_LOG_TEXTO('REJEITARITEMSEMPROMOCAOPE: p_regpedido.codpromocaomed' || ': ',p_regpedido.codpromocaomed);
           PGRAVA_LOG_TEXTO('REJEITARITEMSEMPROMOCAOPE: p_regitem.codpromocaomed'   || ': ',p_regitem.codpromocaomed);
           PGRAVA_LOG_TEXTO('', '');

         END IF; -- Fim Condição: Parâmetro Específico SERVCON - DDMEDICA-2777
         ---------------------------------------------------------------------


         --------------------------------------------------------------------------------
         -- INICIO: DDMEDICA-5511 - Validação Itens Fora da Faixa de Quantidade - SERVCON

         -- Rejeitar Itens Fora da Faixa de Quantidade - DDMEDICA-5511
         vREJEITARITEMFORAFAIXAPROMOQT := FUSA_REGRA_MEDICAMENTOS('99','REJEITARITEMFORAFAIXAPROMOQTPE');

         -- LOG
         PGRAVA_LOG_TEXTO('', '');
         PGRAVA_LOG_TEXTO('REJEITARITEMFORAFAIXAPROMOQTPE', vREJEITARITEMFORAFAIXAPROMOQT);
         
         -- Se Rejeitar Itens Fora da Faixa de Quantidade
         IF (vREJEITARITEMFORAFAIXAPROMOQT = 'S') THEN
         
            BEGIN
              INTEGRADORACOMPLE_MED.proc_validarestricao_servcon(p_regpedido.codcondicaovenda,
                                                                 p_regproduto.codprod,
                                                                 p_regitem.qt,
                                                                 vrRetValidacao.vvRejeitado,
                                                                 vrRetValidacao.vvMotivoRejeitado,
                                                                 vrRetValidacao.vvObservacao,
                                                                 vrRetValidacao.vvRetJson);
              IF (vrRetValidacao.vvRejeitado = 'S') THEN
        
                -- Não é mais Válido
                p_regitem.valido := false;
                -- Atualiza Mensagem
                P_ADD_MENSAGEM('Rejeição 26: ' || vrRetValidacao.vvObservacao,
                               26,
                               vsmensagem,
                               p_regitem.codmotivonaoatend);
                -- Grava Json
                PGRAVA_JSON_ITEM(vrRetValidacao.vvRetJson);
        
              END IF;
        
            EXCEPTION
              WHEN OTHERS THEN
                -- Não é mais Válido
                p_regitem.valido := false;
                -- Atualiza Mensagem
                P_ADD_MENSAGEM('Erro na Validação de Itens Fora da Faixa de Quantidade (SERVCON). '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                               26,
                               vsmensagem,
                               p_regitem.codmotivonaoatend);
            END;
            
         END IF; -- FIM: Se Rejeitar Itens Fora da Faixa de Quantidade
  
         -- FIM: DDMEDICA-5511 - Validação Itens Fora da Faixa de Quantidade - SERVCON
         -----------------------------------------------------------------------------


        /******************************************
         Pesquisa Promoção Vigente - HIS.03889.2014
               (QUE ALTERA O PTABELA)
         ******************************************/

         -- DDVENDAS-31504 - Se Restringe a pesquisa à promoção enviada no Item do Pedido
         -- e a Promoção enviada no Item do Pedido for de Desconto ou Bonificação ou Markup
         --> DEVE IGNORAR A PESQUISA DE PROMOÇÃO para não ficar dando mensagem de rejeição sem necessidade
         --> Observação: Na versão 30.4 não chega mais o Tipo M-Markup, se chegar é algum cadastro antigo quando ainda era somente desconto
         --> DDVENDAS-33961 - Incluída a Restrição por Item
         IF ((NVL(p_regpedido.restringirpromocaomed,'N') = 'S') OR
             (NVL(p_regitem.restringirpromocaomed,'N') = 'S')) AND
            (NVL(vrDadosPromocaoItem.vvTipoPromoPrecoDesc,'D') IN ('D','N','M')) THEN
    
             NULL; -->> Não Validar Promoção aqui quando a Promoção enviada no Item do Pedido for de Desconto ou Bonificação

         -- Se o Pedido foi recebido por Integração de OL via Banco de Dados
         -- DDMEDICA-6841 - Pode ser feita a pesquisa de promoções de markup que alteram o PTABELA
         -- DDVENDAS-33961 - Incluída a Restrição por Item
         ELSIF ((NVL(p_regpedido.integracaopedoperlog,'N') = 'S') OR 
                (NVL(p_regpedido.restringirpromocaomed,'N') = 'S') OR -- DDVENDAS-31504
                (NVL(p_regitem.restringirpromocaomed,'N') = 'S')) and 
               (NVL(vrDadosPromocaoItem.vvTipoPromoPrecoDesc,'X') <> 'M') THEN -->> Somente Promoção do Item Diferente de Markup que pode Pesquisar de Promoção que altera PTABELA - DDMEDICA-5980

             -- Chama Procedimento para Retornar a Promoção Vigente
             INTEGRADORACOMPLE_MED.P_OBTEM_DESC_PROMOCAO(1,
                                         'N', -- Não grava Tabela Temporária,
                                         'N', -- Não executa Commit
                                         p_regpedido.data,
                                         p_regpedido.codfilial,
                                         p_regfilial.tipoprazomedicam,
                                         p_regcliente.numregiao,
                                         p_regpedido.codusur,
                                         p_regpedido.origemped,
                                         p_regpedido.tipofv,
                                         vnCodPlPagProduto,
                                         p_regpedido.codcondicaovenda,
                                         p_regitem.codpromocaomed, -- Promoção do Item pra Priorização
                                         p_regpedido.codcli,
                                         p_regproduto.codprod,
                                         p_regitem.qt,
                                         vrRetornoPromocao.vvTipoPromoPrecoDesc,
                                         vrRetornoPromocao.vnCodDesconto,
                                         vrRetornoPromocao.vnCodPromocaoMed,
                                         vrRetornoPromocao.vnPrecoFixo,
                                         vrRetornoPromocao.vnPercDesc,
                                         vrRetornoPromocao.vnPercDescFin,
                                         vrRetornoPromocao.vnInicioIntervaloQt,
                                         vrRetornoPromocao.vnVlDescCmv,         -- DDMEDICA-5009
                                         vrRetornoPromocao.vnPerDescCmv,        -- DDMEDICA-5009
                                         vrRetornoPromocao.vnNumVerba,          -- DDMEDICA-5009
                                         vrRetornoPromocao.vnValorCotaNumVerba, -- DDMEDICA-5009
                                         vrRetornoPromocao.vvSemVerbaVlDescCmv, -- DDMEDICA-5009
                                         vrRetornoPromocao.vvOcorreramErros,
                                         vrRetornoPromocao.vvMsgErros,
                                         NULL,                                     -- NUMPEDRCA - DDMEDICA-6841
                                         NVL(p_regitem.restringirpromocaomed,
                                             NVL(p_regpedido.restringirpromocaomed,'N')), -- Como Padrão não Prioriza o Desconto da Promoção, pega o Maior -- DDVENDAS-31504 // DDVENDAS-33961 - Priorizar Restrição do Item
                                         vrDadosPromocaoItem.vvTipoPromoPrecoDesc, -- DDMEDICA-6841
                                         p_regitem.PVENDA1BASEPROMOMARKUP,         -- DDMEDICA-6841 - Usar o Preço Tabela sem Taxa no Cálculo do Desconto do Markup
                                         p_regitem.customarkupmed,                 -- DDMEDICA-6900
                                         p_regitem.percmarkupmed,                  -- DDMEDICA-6837
                                         p_regpedido.integradora,
                                         p_regfilial.concedenteferta);

             -- DDVENDAS-31504 - Se Restringe a pesquisa à promoção enviada no Item do Pedido
             -- DDVENDAS-33961 - Incluída Restrição do Item
             IF ((NVL(p_regpedido.restringirpromocaomed,'N') = 'S') OR
                 (NVL(p_regitem.restringirpromocaomed,'N') = 'S')) AND
                (NVL(p_regitem.codpromocaomed,0) <> NVL(vrRetornoPromocao.vnCodPromocaoMed,0)) THEN
               -- Se não encontrou o Código da Promoção do Item nos Descontos Vigentes, rejeita o Item
               vrRetornoPromocao.vvOcorreramErros := 'S';
               vrRetornoPromocao.vvMsgErros       := 'Promoção de Desconto do Item do Pedido não encontrada ou fora da vigência';
             END IF;
             
             -- DDVENDAS-33961 - Validação Oferta
             IF (NVL(vrRetornoPromocao.vvOcorreramErros,'N') <>  'S') THEN
              vrRetornoPromocao.vvOcorreramErros := F_PRECO_INVALIDO_OFERTA(p_regpedido.tipofv,
                                                                            gregpcconsum.numcasasdecvenda,
                                                                            p_regfilial.meddifaceiteprecominimofv,
                                                                            p_regitem.restringirpromocaomed,
                                                                            p_regproduto.codprod,
                                                                            p_regitem.codpromocaomed,
                                                                            vrDadosPromocaoItem.vvTipoPromoPrecoDesc,
                                                                            vrDadosPromocaoItem.vvTipoPromocao,
                                                                            vrRetornoPromocao.vnPrecoFixo,
                                                                            0,
                                                                            p_regitem.precoedi,
                                                                            p_regitem.qt,
                                                                            vrRetornoPromocao.vvMsgErros);
             END IF;                                                                      

             -- Se ocorreram Erros
             IF (NVL(vrRetornoPromocao.vvOcorreramErros,'N') = 'S') THEN

               p_regitem.valido := false;

                  if p_Regitem.codmotivonaoatend is null then
                     p_regitem.codmotivonaoatend :=26 ;

                  end if;


                 if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem              := vsmensagem || vschar ||
                                             'Críticas ao validar desconto da promoção. '|| vrRetornoPromocao.vvMsgErros;

               -- LOG
               PGRAVA_LOG_TEXTO('', '');
               PGRAVA_LOG_TEXTO('Retorno integracaopedoperlog', 'INTEGRADORACOMPLE_MED.P_OBTEM_DESC_PROMOCAO');
               PGRAVA_LOG_TEXTO('Condicao', 'Críticas ao validar desconto da promoção (QUE ALTERA O PTABELA)');
               PGRAVA_LOG_TEXTO('vrRetornoPromocao.vvMsgErros', vrRetornoPromocao.vvMsgErros);

             ELSE

               -- Se a Promoção Vigente for de Preço Fixo
               IF (vrRetornoPromocao.vvTipoPromoPrecoDesc = 'P') THEN
                 p_regproduto.ptabela               := vrRetornoPromocao.vnPrecoFixo;
                 p_Regitem.perdescboleto            := vrRetornoPromocao.vnPercDescFin;
                 p_regitem.perdescfin               := 0; -- Desconto Financeiro da Promoção é somente do campo perdescboleto
                 p_regitem.pbaserca                 := vrRetornoPromocao.vnPrecoFixo;
                 p_regitem.coddesconto              := vrRetornoPromocao.vnCodDesconto;
                 p_regitem.codpromocaomed           := vrRetornoPromocao.vnCodPromocaoMed;
                 p_regitem.numverbacampanha         := vrRetornoPromocao.vnNumVerba;  -- DDMEDICA-5009
                 p_regitem.vldesccmvpromocaomed     := vrRetornoPromocao.vnVlDescCmv; -- DDMEDICA-5009                 
                 p_regitem.iniciointervalodescquant := vrRetornoPromocao.vnInicioIntervaloQt;
                 p_regitem.aplicoupromocao          := 'S';
                 PGRAVA_LOG_TEXTO('Promoção Preço Fixo integracaopedoperlog = SIM','');
                 PGRAVA_LOG_VALOR('p_regproduto.ptabela vrRetornoPromocao.vnPrecoFixo' || ': ',p_regproduto.ptabela);
                 PGRAVA_LOG_VALOR('p_Regitem.perdescboleto vrRetornoPromocao.vnPercDescFin' || ': ',p_Regitem.perdescboleto);
                 PGRAVA_LOG_VALOR('p_regitem.coddesconto'              || ': ',p_regitem.coddesconto);
                 PGRAVA_LOG_VALOR('p_regitem.codpromocaomed'           || ': ',p_regitem.codpromocaomed);
                 PGRAVA_LOG_VALOR('p_regitem.iniciointervalodescquant' || ': ',p_regitem.iniciointervalodescquant);
                 PGRAVA_LOG_TEXTO('Valor Verba Promoção', vrRetornoPromocao.vnVlDescCmv);
                 PGRAVA_LOG_TEXTO('Número Verba Promoção', vrRetornoPromocao.vnNumVerba);
                 PGRAVA_LOG_TEXTO('Valor Cota Verba Promoção', vrRetornoPromocao.vnValorCotaNumVerba);
                 PGRAVA_LOG_TEXTO('Sem NUMVERBA', vrRetornoPromocao.vvSemVerbaVlDescCmv);
                 PGRAVA_LOG_TEXTO('PTabela Markup', p_regitem.PVENDA1BASEPROMOMARKUP);
                 PGRAVA_LOG_TEXTO('Custo Markup', p_regitem.customarkupmed);
                 PGRAVA_LOG_TEXTO('% Markup', p_regitem.percmarkupmed);
               END IF;

             END IF; -- Fim Condição Se ocorreram Erros

