      if (NVL(p_regfilial.utilizacontrolemedicamentos,'N') = 'N') or
         ((NVL(p_regpedido.tipofv,' ') = 'PE') and (NVL(p_regpedido.origempreco,' ') = 'T')) then
        --Desconto por Atividade
        begin
          -- HIS.00182.2016
          IF (NVL(p_regfilial.medaplicardescomcliptabela,'N') = 'S') THEN
            select (100 - ( (100 * (1 - (NVL(PCATIVI.PERCDESC,0)  / 100))) * (1 - ((NVL(PCCLIENT.PERDESC,0) * -1) / 100)) )) PERDESCATIV
              into vnperdescativ
              from pcativi, pcclient
             where pcclient.codcli = p_regcliente.codcli
               and pcclient.codatv1 = pcativi.codativ(+);
          ELSE
            select NVL(pcativi.percdesc, 0)
              into vnperdescativ
              from pcativi, pcclient
             where pcclient.codcli = p_regcliente.codcli
               and pcclient.codatv1 = pcativi.codativ;
          END IF;
        exception
          when others then
            vnperdescativ := 0;
        end;

        if vnperdescativ <> 0 then
          p_regproduto.ptabela := (p_regproduto.ptabela +
                                  (p_regproduto.ptabela * vnperdescativ / 100));
          p_regorigempreco.PERCRAMOATIV := vnperdescativ;
          PGRAVA_LOG_VALOR('Aplicando vnperdescativ' || ': ',vnperdescativ);
          PGRAVA_LOG_VALOR('p_regproduto.ptabela' || ': ',p_regproduto.ptabela);
        end if;
     end if;

