     --// HIS.01889.2017 - Obter a Taxa do Acordo de Parceria
     --------------------------------------------------------
     IF (NVL(p_regfilial.usaracrescdescacordoparceria,'N') = 'S') AND
        (NVL(p_Regpedido.CODPROMOCAOMED,0) > 0) THEN

       -- Obtém Valores do Acordo de Parceria
       PKG_MEDICAMENTOS.P_TAXACORDOPARCERIA(p_Regpedido.codfilial,
                                            p_Regpedido.codfilialnf,
                                            p_regitem.codprod,
                                            p_Regpedido.codcli,
                                            p_regcliente.numregiao,
                                            p_Regpedido.condvenda,
                                            p_Regpedido.origemped,
                                            p_Regpedido.tipofv,
                                            NULL, -- Integradora
                                            p_Regpedido.codplpag,
                                            TRUNC(SYSDATE),
                                            vrDadosAcordoParceria.vvAchouTaxa,
                                            vrDadosAcordoParceria.vnCodAcordo,
                                            vrDadosAcordoParceria.vnPercTaxa,
                                            vrDadosAcordoParceria.vnPerCom,
                                            vrDadosAcordoParceria.vvCampo);
       IF (NVL(vrDadosAcordoParceria.vvAchouTaxa,'N') = 'S') THEN
         -- 3.1 Desconto ou Acréscimo do Acordo de Parceria
         p_regproduto.ptabela := (p_regproduto.ptabela - (p_regproduto.ptabela * NVL(vrDadosAcordoParceria.vnPercTaxa,0) / 100));

         PGRAVA_LOG_VALOR('Aplicando vrDadosAcordoParceria.vnPercTaxa' || ': ',vrDadosAcordoParceria.vnPercTaxa);
         PGRAVA_LOG_VALOR('p_regproduto.ptabela' || ': ',p_regproduto.ptabela);

         -- HIS.01889.2017 - Atualização da Variável de Priorização de Comissão do Acordo de Parceria
          IF (vrDadosAcordoParceria.vnPerCom IS NOT NULL) THEN
            p_regitem.priorizacomissacordoparceria := 'S';
          ELSE
            p_regitem.priorizacomissacordoparceria := 'N';
          END IF;
         p_regitem.percomacordoparceria            := vrDadosAcordoParceria.vnPerCom;
         p_regorigempreco.codacordoparceria        := vrDadosAcordoParceria.vnCodAcordo;
         p_regorigempreco.percdescacordoparceria   := vrDadosAcordoParceria.vnPercTaxa;
       ELSE
         -- HIS.01889.2017 - Atualização da Variável de Priorização de Comissão do Acordo de Parceria
         p_regitem.priorizacomissacordoparceria  := 'N';
         p_regitem.percomacordoparceria          := NULL;
         p_regorigempreco.codacordoparceria      := NULL;
         p_regorigempreco.percdescacordoparceria := NULL;
       END IF;

