      -- DDMEDICA-6929
      IF (NVL(p_regfilial.IGNORARACRESCIMOPFTRIBUT,'N') = 'S') THEN
        PGRAVA_LOG_VALOR('Ignorando p_regprecos.peracrescismopf a' || ': ',p_regprecos.peracrescismopf);
      ELSE
        IF (p_regpedido.condvenda <> 3 AND p_regpedido.condvenda <> 6 AND
           p_regpedido.condvenda <> 12) OR gregpcconsum.aplicaacrescpftv3 = 'S'
        THEN
          IF gregpcconsum.acrescimopfcomie = 'S'
          THEN
            if ((((p_regprecos.APLICAACRESCPJISENTA = 'S')
                and ((p_regcliente.IEENT = 'ISENTA')
                or (p_regcliente.IEENT = 'ISENTO')))
                or ((p_regcliente.TIPOFJ = 'F')
                or (p_regcliente.CONSUMIDORFINAL = 'S')))
                and (p_regcliente.Contribuinte = 'N')) THEN
  
              p_regproduto.ptabela := (p_regproduto.ptabela +
                                      (p_regproduto.ptabela * p_regprecos.peracrescismopf / 100));
  
              p_regorigempreco.PERCACRESCPF := p_regprecos.peracrescismopf;
  
              PGRAVA_LOG_VALOR('Aplicando p_regprecos.peracrescismopf a' || ': ',p_regprecos.peracrescismopf);
              PGRAVA_LOG_VALOR('p_regproduto.ptabela' || ': ',p_regproduto.ptabela);
  
            END IF;
          ELSE
            if ((((p_Regprecos.APLICAACRESCPJISENTA = 'S')
                and ((p_regcliente.IEENT = 'ISENTA')
                or (p_regcliente.IEENT = 'ISENTO')))
                or (((p_regcliente.TIPOFJ = 'F')
                or (p_regcliente.CONSUMIDORFINAL = 'S'))
                and (Trim(p_regcliente.IEENT) = '')))
                and (p_regcliente.Contribuinte = 'N')) then
  
              p_regproduto.ptabela := (p_regproduto.ptabela +
                                      (p_regproduto.ptabela * p_regprecos.peracrescismopf / 100));
  
              p_regorigempreco.PERCACRESCPF := p_regprecos.peracrescismopf;
  
              PGRAVA_LOG_VALOR('Aplicando p_regprecos.peracrescismopf b' || ': ',p_regprecos.peracrescismopf);
              PGRAVA_LOG_VALOR('p_regproduto.ptabela' || ': ',p_regproduto.ptabela);
  
            END IF;
          END IF;
        END IF;
      END IF;


      end if;


   --***********************************************


    if p_regprecos.mostrarpvendasemst = 'S' and p_regprecos.tipocalculognre = 'P'  then

      PGRAVA_LOG_VALOR('p_regproduto.ptabela antes calculo_preco_sem_impostos' || ': ',p_regproduto.ptabela);

      vbcalculosemimposto := funcoesvendas.calculo_preco_sem_impostos(nvl(p_regproduto.PERCIPIVENDA,0),
                                                           p_regproduto.vlpautaipivenda,
                                                           p_regproduto.vlipiporkgvenda,
                                                           p_regproduto.ptabela,
                                                           p_regprecos.pauta,
                                                           p_regproduto.pesobruto,
                                                           p_regprecos.percdifaliquotas,
                                                           p_regproduto.percipivenda,
                                                           p_regprecos.valorultent,
                                                           p_regprecos.iva,
                                                           p_regprecos.percbaseredst,
                                                           p_regprecos.aliqicms1,
                                                           p_regprecos.aliqicms2,
                                                           p_regprecos.usavalorultentbasest,
                                                           p_regprecos.usavalorultentbasest2,
                                                           p_regfilial.uf,
                                                           p_regcliente.estent,
                                                           vnptabelasemimposto,
                                                           vsmensagemprecosemimposto,
                                                           p_regprecos.usapmcbasest,
                                                           p_regproduto.precomaxconsum,
                                                           p_regprecos.usavlultentmediobasest,
                                                           p_regprecos.vlultentmes);

     PGRAVA_LOG_VALOR('p_regproduto.ptabela após calculo_preco_sem_impostos' || ': ',p_regproduto.ptabela);

     if vnptabelasemimposto < p_regproduto.ptabela  and ((p_regproduto.ptabela - vnptabelasemimposto) > 0.01) then
       p_Regproduto.ptabela := round(vnptabelasemimposto,gregpcconsum.numcasasdecvenda);
     end if;



   end if;

 --**********************************************


      p_regitem.pvendabase := p_regproduto.ptabela;
      p_regitem.pbaserca    := p_regproduto.ptabela;

  /******************************************
   Pesquisa Promoção Vigente - HIS.03889.2014
   ******************************************/

   -- DDVENDAS-31504 - Se Restringe a pesquisa à promoção enviada no Item do Pedido
   -- e a Promoção enviada no Item do Pedido for de Preço Fixo ou Bonificação
   --> DEVE IGNORAR A PESQUISA DE PROMOÇÃO DESCONTO para não ficar dando mensagem de rejeição sem necessidade
   -- DDVENDAS-33961 - Incluída a Restrição do Item
   IF ((NVL(p_regpedido.restringirpromocaomed,'N') = 'S') OR
       (NVL(p_regitem.restringirpromocaomed,'N') = 'S')) AND
      (NVL(vrDadosPromocaoItem.vvTipoPromoPrecoDesc,'D') IN ('P','N')) THEN

       NULL; -->> IGNORA A PESQUISA DA PROMOÇÃO DE DESCONTO

   -- Se o Pedido foi recebido por Integração de OL via Banco de Dados
   -- e ainda não aplicou a Promoção
   -- DDVENDAS-33961 - Incluída a Restrição do Item
   ELSIF ((NVL(p_regpedido.integracaopedoperlog,'N') = 'S') OR
          (NVL(p_regpedido.restringirpromocaomed,'N') = 'S') OR -- DDVENDAS-31504
          (NVL(p_regitem.restringirpromocaomed,'N') = 'S')) and 
         (NVL(p_regitem.aplicoupromocao,'N')       <> 'S') THEN

       -- Chama Procedimento para Retornar a Promoção Vigente
       INTEGRADORACOMPLE_MED.P_OBTEM_DESC_PROMOCAO(1,
                                   'N', -- Não grava Tabela Temporária,
                                   'N', -- Não executa Commit
                                   p_regpedido.data,
                                   p_regpedido.codfilial,
                                   p_regfilial.tipoprazomedicam,
                                   p_regcliente.numregiao,
                                   p_regpedido.codusur,
                                   p_regpedido.origemped,
                                   p_regpedido.tipofv,
                                   vnCodPlPagProduto,
                                   p_regpedido.codcondicaovenda,
                                   p_regitem.codpromocaomed, -- Promoção do Item pra Priorização
                                   p_regpedido.codcli,
                                   p_regproduto.codprod,
                                   p_regitem.qt,
                                   vrRetornoPromocao.vvTipoPromoPrecoDesc,
                                   vrRetornoPromocao.vnCodDesconto,
                                   vrRetornoPromocao.vnCodPromocaoMed,
                                   vrRetornoPromocao.vnPrecoFixo,
                                   vrRetornoPromocao.vnPercDesc,
                                   vrRetornoPromocao.vnPercDescFin,
                                   vrRetornoPromocao.vnInicioIntervaloQt,
                                   vrRetornoPromocao.vnVlDescCmv,         -- DDMEDICA-5009
                                   vrRetornoPromocao.vnPerDescCmv,        -- DDMEDICA-5009
                                   vrRetornoPromocao.vnNumVerba,          -- DDMEDICA-5009
                                   vrRetornoPromocao.vnValorCotaNumVerba, -- DDMEDICA-5009
                                   vrRetornoPromocao.vvSemVerbaVlDescCmv, -- DDMEDICA-5009
                                   vrRetornoPromocao.vvOcorreramErros,
                                   vrRetornoPromocao.vvMsgErros,
                                   NULL,                                     -- NUMPEDRCA - DDMEDICA-5980
                                   NVL(p_regitem.restringirpromocaomed,
                                       NVL(p_regpedido.restringirpromocaomed,'N')), -- DDMEDICA-5980 - Como Padrão não Prioriza o Desconto da Promoção, pega o Maior -- DDVENDAS-31504 // DDVENDAS-33961 - Priorizar Restrição do Item
                                   vrDadosPromocaoItem.vvTipoPromoPrecoDesc, -- DDMEDICA-5980
                                   p_regitem.PVENDA1BASEPROMOMARKUP,         -- DDMEDICA-5980 - Usar o Preço Tabela sem Taxa no Cálculo do Desconto do Markup
                                   p_regitem.customarkupmed,                 -- DDMEDICA-6900
                                   p_regitem.percmarkupmed,                  -- DDMEDICA-6837
                                   p_regpedido.integradora,
                                   p_regfilial.concedenteferta);
                                   
       -- DDVENDAS-31504 - Se Restringe a pesquisa à promoção enviada no Item do Pedido
       -- DDVENDAS-33961 - Incluída a Restrição do Item
       IF ((NVL(p_regpedido.restringirpromocaomed,'N') = 'S') OR
           (NVL(p_regitem.restringirpromocaomed,'N') = 'S')) AND
           (NVL(p_regitem.codpromocaomed,0) <> NVL(vrRetornoPromocao.vnCodPromocaoMed,0)) THEN
         -- Se não encontrou o Código da Promoção do Item nos Descontos Vigentes, rejeita o Item
         vrRetornoPromocao.vvOcorreramErros := 'S';
         vrRetornoPromocao.vvMsgErros       := 'Promoção de Desconto do Item do Pedido não encontrada ou fora da vigência';
       END IF;
       
       -- DDVENDAS-33961 - Validação Oferta
       IF (NVL(vrRetornoPromocao.vvOcorreramErros,'N') <>  'S') THEN
        vrRetornoPromocao.vvOcorreramErros := F_PRECO_INVALIDO_OFERTA(p_regpedido.tipofv,
                                                                      gregpcconsum.numcasasdecvenda,
                                                                      p_regfilial.meddifaceiteprecominimofv,
                                                                      p_regitem.restringirpromocaomed,
                                                                      p_regproduto.codprod,
                                                                      p_regitem.codpromocaomed,
                                                                      vrDadosPromocaoItem.vvTipoPromoPrecoDesc,
                                                                      vrDadosPromocaoItem.vvTipoPromocao,
                                                                      p_regproduto.ptabela,
                                                                      vrRetornoPromocao.vnPercDesc,
                                                                      p_regitem.precoedi,
                                                                      p_regitem.qt,
                                                                      vrRetornoPromocao.vvMsgErros);
       END IF;                                                                      

       -- Se ocorreram Erros
       IF (NVL(vrRetornoPromocao.vvOcorreramErros,'N') = 'S') THEN

         p_regitem.valido := false;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend :=26 ;

          end if;


         if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem              := vsmensagem || vschar ||
                                     'Críticas ao validar desconto da promoção. '|| vrRetornoPromocao.vvMsgErros;

         -- LOG
         PGRAVA_LOG_TEXTO('', '');
         PGRAVA_LOG_TEXTO('Retorno integracaopedoperlog', 'INTEGRADORACOMPLE_MED.P_OBTEM_DESC_PROMOCAO');
         PGRAVA_LOG_TEXTO('Condicao', 'Críticas ao validar desconto da promoção');
         PGRAVA_LOG_TEXTO('vrRetornoPromocao.vvMsgErros', vrRetornoPromocao.vvMsgErros);

       ELSE

         -- Se a Promoção Vigente for de Desconto
         IF (vrRetornoPromocao.vvTipoPromoPrecoDesc = 'D') THEN

           vnperdesc                          := vrRetornoPromocao.vnPercDesc;
           p_regitem.perdesccom               := vrRetornoPromocao.vnPercDesc;
           p_Regitem.perbonific               := 0; -- Promoção não tem perbonific
           p_Regitem.perdescboleto            := vrRetornoPromocao.vnPercDescFin;
           p_regitem.perdescfin               := 0; -- Desconto Financeiro da Promoção é somente do campo perdescboleto
           p_regitem.coddesconto              := vrRetornoPromocao.vnCodDesconto;
           p_regitem.codpromocaomed           := vrRetornoPromocao.vnCodPromocaoMed;
           p_regitem.numverbacampanha         := vrRetornoPromocao.vnNumVerba;  -- DDMEDICA-5009
           p_regitem.vldesccmvpromocaomed     := vrRetornoPromocao.vnVlDescCmv; -- DDMEDICA-5009
           p_regitem.iniciointervalodescquant := vrRetornoPromocao.vnInicioIntervaloQt;
           p_regitem.aplicoupromocao          := 'S';

           PGRAVA_LOG_TEXTO('Promoção Desconto integracaopedoperlog = SIM','');
           PGRAVA_LOG_VALOR('vnperdesc'                          || ': ',vnperdesc);
           PGRAVA_LOG_VALOR('p_Regitem.perdescboleto'            || ': ',p_Regitem.perdescboleto);
           PGRAVA_LOG_VALOR('p_regitem.coddesconto'              || ': ',p_regitem.coddesconto);
           PGRAVA_LOG_VALOR('p_regitem.codpromocaomed'           || ': ',p_regitem.codpromocaomed);
           PGRAVA_LOG_VALOR('p_regitem.iniciointervalodescquant' || ': ',p_regitem.iniciointervalodescquant);
           PGRAVA_LOG_TEXTO('Valor Verba Promoção', vrRetornoPromocao.vnVlDescCmv);
           PGRAVA_LOG_TEXTO('Número Verba Promoção', vrRetornoPromocao.vnNumVerba);
           PGRAVA_LOG_TEXTO('Valor Cota Verba Promoção', vrRetornoPromocao.vnValorCotaNumVerba);
           PGRAVA_LOG_TEXTO('Sem NUMVERBA', vrRetornoPromocao.vvSemVerbaVlDescCmv);
           PGRAVA_LOG_TEXTO('PTabela Markup', p_regitem.PVENDA1BASEPROMOMARKUP);
           PGRAVA_LOG_TEXTO('Custo Markup', p_regitem.customarkupmed);
           PGRAVA_LOG_TEXTO('% Markup', p_regitem.percmarkupmed);

         END IF;
           
       END IF; -- Fim Condição Se ocorreram Erros

   END IF; -- Fim Pesquisa Promoção Vigente - HIS.03889.2014


   -- Se ainda não aplicou a Promoção - HIS.03889.2014
   -- DDVENDAS-31504 - Se não Restringe a Promoção enviada no Item do Pedido (Se Restringir não pode usar a P_OBTEM_DESC_INTEGRADORA porque pega o maior)
   -- DDVENDAS-33961 - Restrição do Item
   IF (NVL(p_regitem.aplicoupromocao,'N') <> 'S') AND
      (NVL(p_regpedido.restringirpromocaomed,'N') <> 'S') AND
      (NVL(p_regitem.restringirpromocaomed,'N') <> 'S') THEN

     begin

       PGRAVA_LOG_TEXTO('Consultando Descontos da Integradora','');

       -- DDMEDICA-706
       INTEGRADORACOMPLE_MED.P_OBTEM_DESC_INTEGRADORA(p_regitem.codprod,
                                                      p_regitem.qt,
                                                      p_regpedido.codcondicaovenda,
                                                      p_regpedido.codcli,
                                                      p_regpedido.DATA,
                                                      p_regpedido.codfilial,
                                                      p_Regregiao.numregiao,
                                                      p_regpedido.codusur,
                                                      p_regpedido.origemped,
                                                      p_regproduto.codprodprinc,
                                                      gregpcconsum.numcasasdecvenda,
                                                      p_regitem.codplpag,
                                                      p_regitem.numdias,
                                                      p_regcliente.classevenda,
                                                      p_regcliente.codpraca,
                                                      p_regfilial.naousarautdebcredpoldesc,
                                                      p_regitem.prioritaria,
                                                      p_regpedido.tipofv,
                                                      vsbasecreddebrca,
                                                      vscreditasobrepolitica,
                                                      vsalteraptabela,
                                                      vnpercpbaserca,
                                                      vscreditasobreptabela,
                                                      vsbasecreddebrca_quant,
                                                      vnpercpbaserca_desc,
                                                      vnperdesc,
                                                      p_Regitem.perbonific,
                                                      p_regitem.perdesccom,
                                                      p_Regitem.perdescboleto,
                                                      p_regitem.perdescfin,
                                                      vsocorreramerros,
                                                      vsmensagemdescontos,
                                                      p_regproduto.codlinhaprazo, -- 155824);
                                                      nvl(gregpcconsum.tratarrestricaoacrescimo,'N'), -- 4663.087543.2014
                                                      NVL(p_regpedido.aplicaracrescimopolitica,'N'),
                                                      vrRetornoPromocao.vnCodDesconto,         -- HIS.03080.2016
                                                      vrRetornoPromocao.vnCodPromocaoMed,      -- HIS.03080.2016
                                                      vrRetornoPromocao.vnPrecoFixo,           -- HIS.03080.2016
                                                      vrRetornoPromocao.vvTipoPromoPrecoDesc,  -- HIS.03080.2016
                                                      vrRetornoPromocao.vnVlDescCmv,           -- DDMEDICA-5009
                                                      vrRetornoPromocao.vnPerDescCmv,          -- DDMEDICA-5009
                                                      vrRetornoPromocao.vnNumVerba,            -- DDMEDICA-5009
                                                      vrRetornoPromocao.vnValorCotaNumVerba,   -- DDMEDICA-5009
                                                      vrRetornoPromocao.vvSemVerbaVlDescCmv,   -- DDMEDICA-5009
                                                      vrRetornoPromocao.vvMsgProc,             -- HIS.03080.2016
                                                      'N', -- pi_vGravaTabTemp,
                                                      'N', -- pi_vExecutaCommit
                                                      p_regpedido.integradora,                 -- DDMEDICA-6837
                                                      p_regitem.PVENDA1BASEPROMOMARKUP,        -- DDMEDICA-6837
                                                      p_regitem.customarkupmed,                -- DDMEDICA-6900
                                                      vrRetornoPromocao.vnInicioIntervaloQt,   -- DDMEDICA-6837
                                                      p_regitem.percmarkupmed);                -- DDMEDICA-6837
                                                                                                            
        PGRAVA_LOG_TEXTO('vrRetornoPromocao.vvTipoPromoPrecoDesc:',vrRetornoPromocao.vvTipoPromoPrecoDesc);
        PGRAVA_LOG_TEXTO('vrRetornoPromocao.vvMsgProc:',vrRetornoPromocao.vvMsgProc);

        if vsmensagemdescontos is null then

          -- Se a Promoção Vigente for de Desconto
          IF (NVL(vrRetornoPromocao.vvTipoPromoPrecoDesc,' ') = 'D') THEN -- MED-1554 - NVL()
            -- O Percentual de Desconto está contido na variável vnperdesc que é parâmetro de retorno da procedure
            p_regitem.coddesconto              := vrRetornoPromocao.vnCodDesconto;
            p_regitem.codpromocaomed           := vrRetornoPromocao.vnCodPromocaoMed;
            p_regitem.numverbacampanha         := vrRetornoPromocao.vnNumVerba;  -- DDMEDICA-5009
            p_regitem.vldesccmvpromocaomed     := vrRetornoPromocao.vnVlDescCmv; -- DDMEDICA-5009
            p_regitem.iniciointervalodescquant := vrRetornoPromocao.vnInicioIntervaloQt;
            p_regitem.aplicoupromocao          := 'S';
            PGRAVA_LOG_TEXTO('Promoção Desconto Integradora','');
            PGRAVA_LOG_VALOR('vnperdesc'                          || ': ',vnperdesc);
            PGRAVA_LOG_VALOR('p_Regitem.perbonific'               || ': ',p_Regitem.perbonific);
            PGRAVA_LOG_VALOR('p_regitem.perdesccom'               || ': ',p_regitem.perdesccom);
            PGRAVA_LOG_VALOR('p_Regitem.perdescboleto'            || ': ',p_Regitem.perdescboleto);
            PGRAVA_LOG_VALOR('p_regitem.coddesconto'              || ': ',p_regitem.coddesconto);
            PGRAVA_LOG_VALOR('p_regitem.codpromocaomed'           || ': ',p_regitem.codpromocaomed);
            PGRAVA_LOG_VALOR('p_regitem.iniciointervalodescquant' || ': ',p_regitem.iniciointervalodescquant);
            PGRAVA_LOG_TEXTO('Valor Verba Promoção', vrRetornoPromocao.vnVlDescCmv);
            PGRAVA_LOG_TEXTO('Número Verba Promoção', vrRetornoPromocao.vnNumVerba);
            PGRAVA_LOG_TEXTO('Valor Cota Verba Promoção', vrRetornoPromocao.vnValorCotaNumVerba);
            PGRAVA_LOG_TEXTO('Sem NUMVERBA', vrRetornoPromocao.vvSemVerbaVlDescCmv);            
            PGRAVA_LOG_TEXTO('PTabela Markup', p_regitem.PVENDA1BASEPROMOMARKUP);
            PGRAVA_LOG_TEXTO('Custo Markup', p_regitem.customarkupmed);
            PGRAVA_LOG_TEXTO('% Markup', p_regitem.percmarkupmed);
          -- Se a Promoção Vigente for de Preço Fixo
          ELSIF (NVL(vrRetornoPromocao.vvTipoPromoPrecoDesc,' ') = 'P') THEN -- MED-1554 - NVL()
            -->> Preço Fixo - HIS.03080.2016
            p_regproduto.ptabela               := vrRetornoPromocao.vnPrecoFixo;
            p_regitem.pbaserca                 := vrRetornoPromocao.vnPrecoFixo;
            IF (NVL(p_Regitem.perbonific,0) > 0) AND 
               (NVL(vnperdesc,0) = NVL(p_Regitem.perbonific,0)) THEN
              -- DDMEDICA-4418 - SOMENTE DESCONTO DE BONIFICAÇÃO DA CONDIÇÃO DE VENDA,
              -- NÃO TEM DESCONTO COMERCIAL, MANTÉM O DESC. BONIFICAÇÃO QUE SEGUIRÁ JUNTO COM O PREÇO FIXO 
              p_regitem.perdesccom             := 0; -->> NÃO TEM DESCONTO COMERCIAL            
              PGRAVA_LOG_TEXTO('Desc. Bonif. da Cond. Venda junto com Promoção de Preço Fixo','');
            ELSE
              vnperdesc                        := 0; -->> NÃO TEM DESCONTO
              p_regitem.perdesccom             := 0; -->> NÃO TEM DESCONTO COMERCIAL            
              p_Regitem.perbonific             := 0; -->> NÃO TEM PERBONIFIC
            END IF;
            p_regitem.coddesconto              := vrRetornoPromocao.vnCodDesconto;
            p_regitem.codpromocaomed           := vrRetornoPromocao.vnCodPromocaoMed;
            p_regitem.numverbacampanha         := vrRetornoPromocao.vnNumVerba;  -- DDMEDICA-5009
            p_regitem.vldesccmvpromocaomed     := vrRetornoPromocao.vnVlDescCmv; -- DDMEDICA-5009
            p_regitem.iniciointervalodescquant := vrRetornoPromocao.vnInicioIntervaloQt;
            p_regitem.aplicoupromocao          := 'S';
            PGRAVA_LOG_TEXTO('Promoção Preço Fixo Integradora','');
            PGRAVA_LOG_VALOR('p_regproduto.ptabela vrRetornoPromocao.vnPrecoFixo' || ': ',p_regproduto.ptabela);
            PGRAVA_LOG_VALOR('p_Regitem.perbonific'               || ': ',p_Regitem.perbonific);
            PGRAVA_LOG_VALOR('p_Regitem.perdescboleto'            || ': ',p_Regitem.perdescboleto);
            PGRAVA_LOG_VALOR('p_regitem.coddesconto'              || ': ',p_regitem.coddesconto);
            PGRAVA_LOG_VALOR('p_regitem.codpromocaomed'           || ': ',p_regitem.codpromocaomed);
            PGRAVA_LOG_VALOR('p_regitem.iniciointervalodescquant' || ': ',p_regitem.iniciointervalodescquant);
            PGRAVA_LOG_TEXTO('Valor Verba Promoção', vrRetornoPromocao.vnVlDescCmv);
            PGRAVA_LOG_TEXTO('Número Verba Promoção', vrRetornoPromocao.vnNumVerba);
            PGRAVA_LOG_TEXTO('Valor Cota Verba Promoção', vrRetornoPromocao.vnValorCotaNumVerba);
            PGRAVA_LOG_TEXTO('Sem NUMVERBA', vrRetornoPromocao.vvSemVerbaVlDescCmv);
            PGRAVA_LOG_TEXTO('PTabela Markup', p_regitem.PVENDA1BASEPROMOMARKUP);
            PGRAVA_LOG_TEXTO('Custo Markup', p_regitem.customarkupmed);
            PGRAVA_LOG_TEXTO('% Markup', p_regitem.percmarkupmed);
          -- MED-1554 - Se Política da 561
          ELSE
            -- Se achou Política de Desconto
            IF (vrRetornoPromocao.vnCodDesconto > 0) AND
               ((NVL(vnperdesc,0) <> 0) OR (NVL(p_Regitem.perdescboleto,0) <> 0)) THEN
              p_regitem.coddesconto := vrRetornoPromocao.vnCodDesconto;
              PGRAVA_LOG_TEXTO('Política de Desconto','');
              PGRAVA_LOG_VALOR('vnperdesc'                || ': ',vnperdesc);
              PGRAVA_LOG_VALOR('p_Regitem.perbonific'     || ': ',p_Regitem.perbonific);
              PGRAVA_LOG_VALOR('p_regitem.perdesccom'     || ': ',p_regitem.perdesccom);
              PGRAVA_LOG_VALOR('p_Regitem.perdescboleto'  || ': ',p_Regitem.perdescboleto);
              PGRAVA_LOG_VALOR('p_regitem.coddesconto'    || ': ',p_regitem.coddesconto);
              PGRAVA_LOG_VALOR('p_regitem.codpromocaomed' || ': ',p_regitem.codpromocaomed);
              PGRAVA_LOG_TEXTO('Valor Verba Promoção', vrRetornoPromocao.vnVlDescCmv);
              PGRAVA_LOG_TEXTO('Número Verba Promoção', vrRetornoPromocao.vnNumVerba);
              PGRAVA_LOG_TEXTO('Valor Cota Verba Promoção', vrRetornoPromocao.vnValorCotaNumVerba);
              PGRAVA_LOG_TEXTO('PTabela Markup', p_regitem.PVENDA1BASEPROMOMARKUP);
              PGRAVA_LOG_TEXTO('Custo Markup', p_regitem.customarkupmed);
              PGRAVA_LOG_TEXTO('% Markup', p_regitem.percmarkupmed);
            END IF;
          END IF;

        else

         p_regitem.valido := false;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend :=26 ;

          end if;


         if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem              := vsmensagem || vschar ||
                                     'Erro ao validar desconto. '||vsmensagemdescontos;



        end if;


       exception when others then

         p_regitem.valido := false;

         if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem              := vsmensagem || vschar ||
                                     'Erro ao validar desconto. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM;
          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 26;

          end if;

      end;

   END IF; -- Se ainda não aplicou a Promoção - HIS.03889.2014



   ---------------------------------------------------------------------
   -- Parâmetro Específico Pedidos Eletronicos - DDMEDICA-3143
   -----------------------------------------------

   -- LOG
   PGRAVA_LOG_TEXTO('', '');
   PGRAVA_LOG_TEXTO('REJEITARITEMSEMPROMOCAOPE', FUSA_REGRA_MEDICAMENTOS('99','REJEITARITEMSEMPROMOCAOPE'));
   PGRAVA_LOG_TEXTO('integracaopedoperlog', p_regpedido.integracaopedoperlog);

   -- Se o Pedido foi recebido por Integração de OL via Banco de Dados
   -- DDMEDICA-3143 - Regra alterada para que atenda pedidos eletronicos e não somente a Servcom
   IF (NVL(p_regpedido.tipofv,'FV') = 'PE') AND
      (NVL(FUSA_REGRA_MEDICAMENTOS('99','REJEITARITEMSEMPROMOCAOPE'),'N') = 'S') THEN

     -- LOG
     PGRAVA_LOG_TEXTO('REJEITARITEMSEMPROMOCAOPE: p_regitem.codpromocaomed'               || ': ',p_regitem.codpromocaomed);
     PGRAVA_LOG_TEXTO('REJEITARITEMSEMPROMOCAOPE: vrRetornoPromocao.vnCodPromocaoMed'     || ': ',vrRetornoPromocao.vnCodPromocaoMed);
     PGRAVA_LOG_TEXTO('REJEITARITEMSEMPROMOCAOPE: vrRetornoPromocao.vnCodDesconto'        || ': ',vrRetornoPromocao.vnCodDesconto);
     PGRAVA_LOG_TEXTO('REJEITARITEMSEMPROMOCAOPE: vrRetornoPromocao.vvTipoPromoPrecoDesc' || ': ',vrRetornoPromocao.vvTipoPromoPrecoDesc);

     -- Se chegou aqui sem Promoção Aplicada no Item
     IF (NVL(p_regitem.codpromocaomed,0) = 0) THEN

       p_regitem.valido := false;

       if p_Regitem.codmotivonaoatend is null then
          p_regitem.codmotivonaoatend := 26 ;
       end if;

       if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;
        vsmensagem := vsmensagem || vschar ||
                     'Venda não autorizada sem condição comercial (Promoção) pela integração SERVCON conforme parâmetro da rotina 2345. '|| vrRetornoPromocao.vvMsgErros;

        -- LOG
        PGRAVA_LOG_TEXTO('Venda não autorizada sem condição comercial (Promoção) pela integração SERVCON','');
        PGRAVA_LOG_TEXTO('','');

     END IF;

   END IF; -- Fim Condição: Parâmetro Específico SERVCON - DDMEDICA-2777
   ---------------------------------------------------------------------



   --tarefa 153899

    SELECT count(*)
      into vicontador
      FROM PCCONDVENDALINHA p
     WHERE P.codcondicaovenda = p_regpedido.codcondicaovenda
       AND P.codlinhaprazo    = p_regproduto.codlinhaprazo;


     if vicontador = 0 then

        p_regitem.valido := false;

         if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem              := vsmensagem || vschar ||
                                     'Linha : '||p_regproduto.codlinhaprazo||' não cadastrada na cond. venda '||p_Regpedido.codcondicaovenda;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 18;

          end if;


     elsif vicontador = 1 then

        SELECT p.tipovalidadescindustria,p.descmaxindustria
          into vstipovalidadescindustria,vndescmaxindustria
          FROM PCCONDVENDALINHA p
         WHERE P.codcondicaovenda = p_regpedido.codcondicaovenda
           AND P.codlinhaprazo    = p_regproduto.codlinhaprazo;

        -- DDMEDICA-1835 - Validação conforme 2306
        INTEGRADORACOMPLE_MED.P_OBTER_DESC_SPREAD_OL('D',
                                                     p_regpedido.codfilial,
                                                     p_regproduto.codprod,
                                                     p_regpedido.codcli,
                                                     p_regpedido.integradora,
                                                     p_regpedido.codcondicaovenda,
                                                     vrRetCadDescIndustria.vnPrioridade,
                                                     vrRetCadDescIndustria.vvTipo,
                                                     vrRetCadDescIndustria.vnPercentual,
                                                     vrRetCadDescIndustria.vnPercRefDebCred,
                                                     vrRetCadDescIndustria.vnPercAcrescimo,
                                                     vrRetCadDescIndustria.vnPrioridadeAcrescimo);
        IF (vrRetCadDescIndustria.vvTipo = 'R') THEN
          vndescmaxindustria        := vrRetCadDescIndustria.vnPercentual;
          vstipovalidadescindustria := 'R'; -->> Rejeitar se acima do máximo
          PGRAVA_LOG_VALOR('vndescmaxindustria Gestão OL' || ': ',vndescmaxindustria);
        END IF;

     else

         p_regitem.valido := false;

         if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem              := vsmensagem || vschar ||
                                     'Linha : '||p_regproduto.codlinhaprazo||' encontrada mais de uma para a cond. venda '||p_Regpedido.codcondicaovenda;

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 18;

          end if;

      end if;



       -- O Desconto da Indústria recebido no OL deverá ser adicionado ao Desconto Total do Produto a
       -- ser concedido em Nota Fiscal


          -- Se Pedido de OL e
          -- Desconto da Indústria do Arquivo superior ao Máximo cadastrado na Condição
          if (p_regpedido.TIPOFV = 'OL') and
             (nvl(p_regitem.precoedi,0) = 0) and -- HIS.02194.2016 - Integração Pharmalink - Preço (O Pharmalink passou a validar Preço no OL da Perfumaria, portanto somente se não aplicou o preço do arquivo pode realizar esta validação)
             (p_regitem.PERCDESCEDI > nvl(vndescmaxindustria,0)) then

            -- Se definido na Condição para Rejeitar Item
            if vstipovalidadescindustria  = 'R' then

                 p_regitem.valido := false;

               if vsmensagem is not null then
                  vschar := '#';
                else
                  vschar := null;
                end if;
                vsmensagem              := vsmensagem || vschar ||
                                           'Desconto EDI enviado maior que o maximo parametrizado para industria. (Desc. EDI = ' || p_regitem.PERCDESCEDI || ' ; Desc. Máximo: ' || vndescmaxindustria || ')';
                if p_Regitem.codmotivonaoatend is null then
                   p_regitem.codmotivonaoatend := 902;

                end if;



            elsif vstipovalidadescindustria  = 'M' then

              p_regitem.percdescedi := vndescmaxindustria;

            end if;

          end if;
          --fim tarefa 153899

       -- O Desconto da Indústria recebido no OL deverá ser adicionado ao Desconto Total do Produto a
       -- ser concedido em Nota Fiscal

       -- Inicializa o Desconto da Industria
       p_regitem.percdescindustria := null;

       -- Adiciona ao Desconto Final do Item da NF o Desconto da Industria recebido no Arquivo de OL
       if ((p_regpedido.origemped = 'F')   AND
           (p_regpedido.TIPOFV = 'OL')     AND
           (nvl(p_regitem.precoedi,0) = 0) -- HIS.02194.2016 - Integração Pharmalink - Preço (O Pharmalink passou a validar Preço no OL da Perfumaria, portanto somente se não aplicou o preço do arquivo pode realizar esta validação)
          ) then

                -- Se o Desconto for de 100%
                if (p_regitem.percdescedi = 100) then

                  -- Se a Integradora utiliza a regra de Desconto 100% para Produtos Bonificados

                  -- Regra da Bonificação - Concede 50% de desconto (vem o dobro de unidades do produto
                  -- no arquivo e os 50% em todas as unidades bancará o brinde)
                  if (p_regpedido.UTILIZAREGRADESC100 = 'S') then

                    -- ALTERA O DESCONTO, DEVERÁ SER GRAVADO NO ITEM DO PEDIDO (PCPEDI.PERCDESCINDUSTRIA)
                    -- TAMBÉM 50%
                    p_regitem.percdescedi := 50;

                  end if;

                end if;

                PGRAVA_LOG_VALOR('vnperdesc antes de aplicar p_regitem.percdescedi' || ': ',vnperdesc);

                -- Soma Desconto da Indústria
                vnperdesc := nvl(vnperdesc,0) + nvl(p_regitem.percdescedi,0);

                PGRAVA_LOG_VALOR('p_regitem.percdescedi' || ': ',p_regitem.percdescedi);
                PGRAVA_LOG_VALOR('vnperdesc com p_regitem.percdescedi' || ': ',vnperdesc);

                -- Guarda o Desconto da Industria para relatórios de apuracao do OL
                p_regitem.percdescindustria := p_regitem.percdescedi;

         end if;

        -- Nao deixar ficar maior que 99,99%
        if (vnperdesc > 99.99) then

          -- Inicio - Rejeição - Dava Erro no Cálculo do Lucro - Preço Venda Zerado
          if p_regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 26 ;
          end if;

          p_regitem.valido := false;

           if vsmensagem is not null then
              vschar := '#';
            else
              vschar := null;
            end if;
            vsmensagem              := vsmensagem || vschar ||
                                       'Desconto Total Inválido: ' || NVL(vnperdesc,0);
          -- Fim - Rejeição - Dava Erro no Cálculo do Lucro - Preço Venda Zerado

           vnperdesc := 99.99;
        end if;

       -- DDVENDAS-33961 - Contabilização da Oferta como Desconto da Indústria
       IF (p_regpedido.TIPOFV = 'OL') AND
          (p_regitem.codpromocaomed > 0) AND
          (p_regitem.precoedi > 0) AND
          (p_regfilial.concedenteferta = 'I') THEN
                   
         p_regproduto.ptabela      := NVL(vnPrecoBaseDescIndustriaOferta,0);
         vnPercDescIndustriaOferta := ROUND((1-(p_regitem.precoedi/vnPrecoBaseDescIndustriaOferta))*100, 2);
                  
         PGRAVA_LOG_VALOR('Ptabela de Oferta para cálculo no desconto da industria' || ': ',p_regproduto.ptabela);
         PGRAVA_LOG_VALOR('PVenda de Oferta para cálculo no desconto da industria' || ': ',p_regitem.precoedi);
         PGRAVA_LOG_VALOR('Oferta contabilizada no desconto da industria' || ': ',vnPercDescIndustriaOferta);
         
         -- Guarda o novo Desconto da Industria para relatórios de apuracao do OL
         IF (NVL(vnPercDescIndustriaOferta,0) > 99.99) THEN
           p_regitem.percdescindustria := 99.99;
         ELSE
           p_regitem.percdescindustria := NVL(vnPercDescIndustriaOferta,0);
         END IF; 
                   
       END IF;

     ---*****     

     if p_regfilial.utilizacontrolemedicamentos = 'S' then

         -- Venda Tipo 1
         if p_regpedido.condvenda = 1 then


              -- HIS.04408.2015
              IF (FUNCOES_MED.FUNC_UTILIZAPRECOFABRICA(p_regproduto.tipomerc,
                                                       p_regproduto.utilizaprecofabrica,
                                                       p_regpedido.tipofv)) THEN

                --tarefa 136584

                p_regitem.precomaxconsum := p_regproduto.precomaxconsum;

                -- Preços ZFM passaram a ser pesquisados na PRC_MED_OBTEM_PMC_PRODUTO
                p_regitem.poriginal      := p_regproduto.custorep;

              -- PMC deverá gravar para os Liberados para ficar igual à 2316
              ELSIF (p_regproduto.tipomerc = 'L') THEN
                p_regitem.precomaxconsum := p_regproduto.precomaxconsum;
              END IF;

         -- Diferente de Venda Tipo 1
         else

            -- HIS.03249.2016 - Durante a validação da alteração da comissão, identificado que vendas <> tipo 1 precisam do PMC
              -- HIS.04408.2015
              IF (FUNCOES_MED.FUNC_UTILIZAPRECOFABRICA(p_regproduto.tipomerc,
                                                       p_regproduto.utilizaprecofabrica,
                                                       p_regpedido.tipofv)) THEN

                p_regitem.precomaxconsum := p_regproduto.precomaxconsum;

              -- PMC deverá gravar para os Liberados para ficar igual à 2316
              ELSIF (p_regproduto.tipomerc = 'L') THEN
                p_regitem.precomaxconsum := p_regproduto.precomaxconsum;
              END IF;

         end if;

     end if;

     ---*****

     if p_regproduto.ptabela = 0 then

        if p_regitem.codmotivonaoatend is null then
           p_regitem.codmotivonaoatend := 27 ;

        end if;

        p_regitem.valido := false;

         if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;
          vsmensagem              := vsmensagem || vschar ||
                                     'Preco de tabela zerado. ';

     else

     -- Aplicação do Desconto da Tributação sobre o Preço de Tabela quando este for Origem Preço "FÁBRICA"  no OL e PE
     IF ((p_regpedido.tipofv IN ('OL','PE')) AND
         (p_regpedido.origempreco = 'F') AND
         (p_regpedido.aplicardescptabelatribut = 'S')) THEN
       p_regproduto.ptabela := round(p_regproduto.ptabela * (1 - (nvl(p_regprecos.perdesctab,0) / 100)),gregpcconsum.numcasasdecvenda);
       PGRAVA_LOG_VALOR('aplicando p_regprecos.perdesctab' || ': ',p_regprecos.perdesctab);
       PGRAVA_LOG_VALOR('p_regproduto.ptabela' || ': ',p_regproduto.ptabela);
     END IF;

     -- Se OL somente considerando somente o cenário: Preço do Distribuidor + Desconto da Indústria (Regra Padrão)
     if (p_regpedido.tipofv = 'OL') and
        (nvl(p_regitem.precoedi,0) = 0) then -- HIS.02194.2016 - Integração Pharmalink - Preço (O Pharmalink passou a validar Preço no OL da Perfumaria)

         -- Calcula o Preço Venda dos Pedidos de OL (Preço e Desconto do Distribuidor + Desconto da Indústria)
         p_regitem.pvenda := round(p_regproduto.ptabela * (1 - (nvl(vnperdesc,0) / 100)),gregpcconsum.numcasasdecvenda);
         PGRAVA_LOG_VALOR('p_regitem.pvenda' || ': ',p_regitem.pvenda);
         PGRAVA_LOG_VALOR('vnperdesc sobre p_regitem.pvenda' || ': ',vnperdesc);

     -- Se OL somente considerando somente o cenário: Preço Líquido da Indústria
     elsif (p_regpedido.tipofv = 'OL') and
           (nvl(p_regitem.precoedi,0) <> 0) then -- HIS.02194.2016 - Integração Pharmalink - Preço (O Pharmalink passou a validar Preço no OL da Perfumaria)

         -- Calcula o Preço Venda dos Pedidos de OL (Preço Líquido da Indústria)
         p_regitem.pvenda := round(p_regitem.precoedi,gregpcconsum.numcasasdecvenda);
         PGRAVA_LOG_VALOR('p_regitem.pvenda' || ': ',p_regitem.pvenda);
         PGRAVA_LOG_VALOR('p_regitem.precoedi sobre p_regitem.pvenda' || ': ',p_regitem.precoedi);

      -- Se PE
      elsif (p_regpedido.tipofv = 'PE') then

                -- Validação do Desconto do EDI maior que o Desconto do Distribuidor
                if (p_regitem.PERCDESCEDI > nvl(vnperdesc,0)) then

                  -- Conceder Desc. EDI
                  if (p_regpedido.TIPOVALIDADESCEDIMAIOR = 'E') then
                    vnperdesc               := p_regitem.percdescedi;
                    p_Regitem.perbonific    := 0; -- Tarefa 153405
                    p_regitem.perdesccom    := p_regitem.percdescedi; -- Tarefa 153405 -> Concede o Desconto do EDI no Comercial                    p_Regitem.perdescboleto := 0;
                  -- Rejeitar Item
                  elsif (p_regpedido.TIPOVALIDADESCEDIMAIOR = 'R') then

                    if vsmensagem is not null then
                      vschar := '#';
                    else
                      vschar := null;
                    end if;

                      vsmensagem              := vsmensagem || vschar || 'Produto Faturado com Desconto Diferente';
                      p_Regitem.valido := false;

                      if p_Regitem.codmotivonaoatend is null then

                        p_Regitem.codmotivonaoatend := 901;

                      end if;

                  end if;

                 end if;

                -- Validação do Desconto do EDI menor que o Desconto do Distribuidor
                if (p_regitem.PERCDESCEDI < vnperdesc) then

                  -- Conceder Desc. EDI
                  if (p_regpedido.TIPOVALIDADESCEDIMENOR = 'E') then
                    vnperdesc               := p_regitem.percdescedi;
                    p_Regitem.perbonific    := 0; -- Tarefa 153405
                    p_regitem.perdesccom    := p_regitem.percdescedi; -- Tarefa 153405 -> Concede o Desconto do EDI no Comercial                     p_Regitem.perdescboleto := 0;
                  -- Rejeitar Item
                  elsif (p_regpedido.TIPOVALIDADESCEDIMENOR = 'R') then
                    if vsmensagem is not null then
                      vschar := '#';
                    else
                      vschar := null;
                    end if;

                      vsmensagem              := vsmensagem || vschar || 'Produto Faturado com Desconto Diferente';

                      p_Regitem.valido := false;

                      if p_Regitem.codmotivonaoatend is null then

                        p_Regitem.codmotivonaoatend := 901;

                      end if;

                  end if;

                end if;

                if nvl(p_regitem.perdescboleto,0) > 0 then

                    p_regitem.VLDESCBOLETO := p_regproduto.ptabela * (p_regitem.perdescboleto)/100;

                end if;

                -- HIS.04408.2015
                IF (FUNCOES_MED.FUNC_UTILIZAPRECOFABRICA(p_regproduto.tipomerc,
                                                         p_regproduto.utilizaprecofabrica,
                                                         p_regpedido.tipofv))  AND
                   (NVL(p_regpedido.origempreco,'X') = 'F') THEN

                  -- Validação do Preço Fábrica do EDI maior que o Preço Fábrica do Distribuidor
                  if (p_regitem.precoedi > p_regitem.poriginal) then

                    -- Conceder Preço Fábrica EDI
                    if (p_regpedido.TIPOVALIDAPRECOEDIMAIOR = 'E') then
                       p_regproduto.PTABELA := p_regitem.precoedi;
                       p_regitem.poriginal  := p_regitem.precoedi;
                       PGRAVA_LOG_VALOR('Conceder Preço Fábrica EDI maior no p_regproduto.PTABELA' || ': ',p_regproduto.PTABELA);

                    -- Rejeitar Item
                    elsif (p_regpedido.TIPOVALIDAPRECOEDIMAIOR = 'R') then
                       -- Se acata a diferença [Tarefa: 158047]
                       if (abs(p_regitem.precoedi - p_regitem.poriginal) <= nvl(p_regpedido.vlmaxaceitedifpreco,0)) then
                         p_regproduto.PTABELA := p_regitem.precoedi;
                         p_regitem.poriginal  := p_regitem.precoedi;
                         PGRAVA_LOG_VALOR('Conceder Preço Fábrica EDI maior no p_regproduto.PTABELA acatando dif.' || ': ',p_regproduto.PTABELA);
                       else

                         if vsmensagem is not null then
                           vschar := '#';
                         else
                           vschar := null;
                         end if;

                         vsmensagem              := vsmensagem || vschar ||'Produto Faturado com Preço Diferente';

                         p_Regitem.valido := false;

                         if p_Regitem.codmotivonaoatend is null then

                           p_Regitem.codmotivonaoatend :=901 ;

                         end if;

                       end if;

                    end if;

                  end if;

                  -- Validação do Preço Fábrica do EDI menor que o Preço Fábrica do Distribuidor
                  if (p_regitem.precoedi < p_regitem.poriginal) then

                    -- Conceder Preço Fábrica EDI
                     if(p_regpedido.TIPOVALIDAPRECOEDIMENOR = 'E') then
                       p_regproduto.PTABELA := p_regitem.precoedi;
                       p_regitem.poriginal  := p_regitem.precoedi;
                       PGRAVA_LOG_VALOR('Conceder Preço Fábrica EDI menor no p_regproduto.PTABELA' || ': ',p_regproduto.PTABELA);
                    -- Rejeitar Item
                     elsif (p_regpedido.TIPOVALIDAPRECOEDIMENOR = 'R') then
                      -- Se acata a diferença [Tarefa: 158047]
                       if (abs(p_regitem.precoedi - p_regitem.poriginal) <= nvl(p_regpedido.vlmaxaceitedifpreco,0)) then
                         p_regproduto.PTABELA := p_regitem.precoedi;
                         p_regitem.poriginal  := p_regitem.precoedi;
                         PGRAVA_LOG_VALOR('Conceder Preço Fábrica EDI menor no p_regproduto.PTABELA acatando dif.' || ': ',p_regproduto.PTABELA);
                       else

                         if vsmensagem is not null then
                           vschar := '#';
                         else
                           vschar := null;
                         end if;

                         vsmensagem              := vsmensagem || vschar ||'Produto Faturado com Preço Diferente';

                         p_Regitem.valido := false;

                         if p_Regitem.codmotivonaoatend is null then

                           p_Regitem.codmotivonaoatend := 901;

                         end if;

                       end if;

                     end if;

                  end if;

                -- Se o Tipo de Mercadoria não é Medicamento
                else

                  -- Validação do Preço de Tabela do EDI maior que o Preço Tabela do Distribuidor
                  if (p_regitem.PRECOEDI > p_regproduto.PTABELA) then

                    -- Conceder Preço Tabela do EDI
                    if (p_regpedido.TIPOVALIDAPRECOEDIMAIOR = 'E') then
                      p_regproduto.PTABELA := p_regitem.PRECOEDI;
                      PGRAVA_LOG_VALOR('Conceder Preço EDI maior no p_regproduto.PTABELA (não medicam.)' || ': ',p_regproduto.PTABELA);
                    -- Rejeitar Item
                    elsif (p_regpedido.TIPOVALIDAPRECOEDIMAIOR = 'R') then
                      -- Se acata a diferença [Tarefa: 158047]
                      if (abs(p_regitem.PRECOEDI - p_regproduto.PTABELA) <= nvl(p_regpedido.vlmaxaceitedifpreco,0)) then
                        p_regproduto.PTABELA := p_regitem.PRECOEDI;
                        PGRAVA_LOG_VALOR('Conceder Preço EDI maior no p_regproduto.PTABELA (não medicam.) se acatar dif.' || ': ',p_regproduto.PTABELA);
                      else

                        if vsmensagem is not null then
                          vschar := '#';
                        else
                          vschar := null;
                        end if;

                        vsmensagem              := vsmensagem || vschar ||'Produto Faturado com Preço Diferente';

                        p_Regitem.valido := false;

                        if p_Regitem.codmotivonaoatend is null then

                          p_Regitem.codmotivonaoatend :=901;

                        end if;

                      end if;

                    end if;

                  end if;

                  -- Validação do Preço de Tabela do EDI menor que o Preço de Tabela do Distribuidor
                  if (p_regitem.PRECOEDI <  p_regproduto.PTABELA) then

                    -- Conceder Preço Tabela do EDI
                    if (p_regpedido.TIPOVALIDAPRECOEDIMENOR = 'E') then
                      p_Regproduto.PTABELA := p_regitem.PRECOEDI;
                      PGRAVA_LOG_VALOR('Conceder Preço EDI menor no p_regproduto.PTABELA (não medicam.)' || ': ',p_regproduto.PTABELA);
                    -- Rejeitar Item
                    elsif (p_regpedido.TIPOVALIDAPRECOEDIMENOR = 'R') then
                      -- Se acata a diferença [Tarefa: 158047]
                      if (abs(p_regitem.PRECOEDI - p_regproduto.PTABELA) <= nvl(p_regpedido.vlmaxaceitedifpreco,0)) then
                        p_Regproduto.PTABELA := p_regitem.PRECOEDI;
                        PGRAVA_LOG_VALOR('Conceder Preço EDI menor no p_regproduto.PTABELA (não medicam.) se acatar dif.' || ': ',p_regproduto.PTABELA);
                      else

                        if vsmensagem is not null then
                          vschar := '#';
                        else
                          vschar := null;
                        end if;

                        vsmensagem              := vsmensagem || vschar ||'Produto Faturado com Preço Diferente';

                        p_Regitem.valido := false;

                        if p_Regitem.codmotivonaoatend is null then

                          p_Regitem.codmotivonaoatend := 901;

                        end if;

                      end if;

                    end if;

                  end if;


                end if; -- Condição se Medicamentos ou Perfumaria

                -- Calcula o Preço Venda Liberado dos Pedidos Eletronicos
                p_regitem.pvenda := round(p_regproduto.ptabela * (1 - (nvl(vnperdesc,0) / 100)),gregpcconsum.numcasasdecvenda);

                PGRAVA_LOG_VALOR('Preço Venda Liberado dos Pedidos Eletronicos' || ': ',p_regitem.pvenda);
                PGRAVA_LOG_VALOR('vnperdesc sobre Preço Venda Liberado dos Pedidos Eletronicos' || ': ',vnperdesc);

      end if;

      end if;


