            p_Regitem.perdescboleto            := 0; -- Acordo de Preço PE não tem perdescboleto
            p_regitem.perdescfin               := 0; -- Acordo de Preço PE não tem perdescboleto
            p_regitem.coddesconto              := NULL;
            p_regitem.codacordosistoperlog     := vrDadosRetAcordoPE.vnCodAcordo;
            p_regitem.codpromocaomed           := vrDadosRetAcordoPE.vnCodPromocaoMed;
            p_regitem.numverbacampanha         := vrDadosRetAcordoPE.vnNumVerba;  -- DDMEDICA-5009
            p_regitem.vldesccmvpromocaomed     := vrDadosRetAcordoPE.vnVlDescCmv; -- DDMEDICA-5009
            p_regitem.aplicoupromocao          := 'S';

