            p_regitem.pbaserca                 := vrDadosRetAcordoPE.vnPreco;
            vnperdesc                          := vrDadosRetAcordoPE.vnPercDesc;
            p_regitem.perdesccom               := vrDadosRetAcordoPE.vnPercDesc;
            p_Regitem.perbonific               := 0; -- Acordo de Preço PE não tem perbonific
            p_Regitem.perdescboleto            := 0; -- Acordo de Preço PE não tem perdescboleto
            p_regitem.perdescfin               := 0; -- Acordo de Preço PE não tem perdescboleto
            p_regitem.coddesconto              := NULL;
            p_regitem.codacordosistoperlog     := vrDadosRetAcordoPE.vnCodAcordo;
            p_regitem.codpromocaomed           := vrDadosRetAcordoPE.vnCodPromocaoMed;
            p_regitem.numverbacampanha         := vrDadosRetAcordoPE.vnNumVerba;  -- DDMEDICA-5009
            p_regitem.vldesccmvpromocaomed     := vrDadosRetAcordoPE.vnVlDescCmv; -- DDMEDICA-5009
            p_regitem.aplicoupromocao          := 'S';

            -- Calcula o Preço Venda do Pedido PE
            p_regitem.pvenda := round(p_regproduto.ptabela * (1 - (nvl(vnperdesc,0) / 100)),gregpcconsum.numcasasdecvenda);

            PGRAVA_LOG_TEXTO('Promoção Desconto Acordo Preço Pedido Eletrônico','');
            PGRAVA_LOG_VALOR('p_regproduto.ptabela vrDadosRetAcordoPE.vnPreco' || ': ',p_regproduto.ptabela);
            PGRAVA_LOG_VALOR('vnperdesc'                                       || ': ',vnperdesc);
            PGRAVA_LOG_VALOR('p_regitem.codpromocaomed'                        || ': ',p_regitem.codpromocaomed);
            PGRAVA_LOG_VALOR('p_regitem.pvenda'                                || ': ',p_regitem.pvenda);
          -- Se Achou Acordo sem Promoção do PE (Somente Preço Tabela Diferenciado)
          ELSIF (NVL(vrDadosRetAcordoPE.vvAchouAcordo,' ') = 'S') THEN
            p_regproduto.ptabela               := vrDadosRetAcordoPE.vnPreco;
            p_regitem.pbaserca                 := vrDadosRetAcordoPE.vnPreco;
            vnperdesc                          := 0; -- Acordo sem Promoção PE não tem perbonific
            p_regitem.perdesccom               := 0; -- Acordo sem Promoção PE não tem perbonific
            p_Regitem.perbonific               := 0; -- Acordo sem Promoção PE não tem perbonific
            p_Regitem.perdescboleto            := 0; -- Acordo sem Promoção PE não tem perdescboleto
            p_regitem.perdescfin               := 0; -- Acordo sem Promoção PE não tem perdescboleto
            p_regitem.coddesconto              := NULL;
            p_regitem.codacordosistoperlog     := vrDadosRetAcordoPE.vnCodAcordo;
            p_regitem.codpromocaomed           := vrDadosRetAcordoPE.vnCodPromocaoMed;
            p_regitem.numverbacampanha         := vrDadosRetAcordoPE.vnNumVerba;  -- DDMEDICA-5009
            p_regitem.vldesccmvpromocaomed     := vrDadosRetAcordoPE.vnVlDescCmv; -- DDMEDICA-5009
            p_regitem.aplicoupromocao          := 'S';

            -- Calcula o Preço Venda do Pedido PE
            p_regitem.pvenda := round(p_regproduto.ptabela * (1 - (nvl(vnperdesc,0) / 100)),gregpcconsum.numcasasdecvenda);

            PGRAVA_LOG_TEXTO('Acordo Preço Pedido Eletrônico sem Promoção','');
            PGRAVA_LOG_VALOR('p_regproduto.ptabela vrDadosRetAcordoPE.vnPreco' || ': ',p_regproduto.ptabela);
            PGRAVA_LOG_VALOR('vnperdesc'                                       || ': ',vnperdesc);
            PGRAVA_LOG_VALOR('p_regitem.codpromocaomed'                        || ': ',p_regitem.codpromocaomed);
            PGRAVA_LOG_VALOR('p_regitem.pvenda'                                || ': ',p_regitem.pvenda);
          END IF;
        END IF;
      END IF; -- FIM CONDIÇÃO: - APÓS CONSULTAR TODAS AS POLÍTICAS, VERIFICA ACORDO DE PREÇO DO PEDIDO ELETRÔNICO


      vnptabela_aux := p_regproduto.ptabela;

