                                            vrDadosStAntecip.nBCSTRETANTERIOR,          -- DDMEDICA-7697
                                            vrDadosStAntecip.nVLICMSSUBSTITUTOANTERIOR, -- DDMEDICA-7697
                                            vrDadosStAntecip.nVLICMSSTRETANTERIOR,      -- DDMEDICA-7697
                                            vrRetornoStFonte.vnStClienteGnreFonte,      -- DDMEDICA-7697
                                            vrRetornoStFonte.vnPmPfMedicamento,         -- DDMEDICA-7697 
                                            vrRetornoStFonte.vvClienteFonteSt,          -- DDMEDICA-7697 
                                            p_regcliente.estent                         -- DDVENDAS-33718
                                            );

        -- Se Calculou ST Fonte em Clientes Não Fonte
        IF ((NVL(vrRetornoStFonte.vnStFonte,0) + NVL(vrDadosStAntecip.nVLICMSSTRETANTERIOR,0)) > 0) THEN

          PGRAVA_LOG_VALOR('p_regproduto.ptabela antes do ST' || ': ',p_regproduto.ptabela);
          PGRAVA_LOG_VALOR('p_regitem.pvenda antes do ST' || ': ', p_regitem.pvenda);

          -- Soma ao PTabela e PVenda
          p_regproduto.ptabela      := NVL(p_regproduto.ptabela,0) 
                                          + NVL(vrRetornoStFonte.vnStFonte,0)
                                          + NVL(vrDadosStAntecip.nVLICMSSTRETANTERIOR,0) -- DDMEDICA-7697
                                          + NVL(vrDadosFuncep.nVLFECP,0);
          p_regitem.pvenda          := NVL(p_regitem.pvenda,0)     
