                                          + NVL(vrDadosStAntecip.nVLICMSSTRETANTERIOR,0) -- DDMEDICA-7697
                                          + NVL(vrDadosFuncep.nVLFECP,0);

          -- Guarda o ST aplicado no PTabela e PVenda
          p_regitem.somoustptabela  := 'S';

          PGRAVA_LOG_VALOR('vrRetornoStFonte.vnStFonte' || ': ',vrRetornoStFonte.vnStFonte);
          PGRAVA_LOG_VALOR('vrDadosStAntecip.nVLICMSSTRETANTERIOR' || ': ',vrDadosStAntecip.nVLICMSSTRETANTERIOR);
          PGRAVA_LOG_VALOR('vrDadosFuncep.nVLFECP' || ': ',vrDadosFuncep.nVLFECP);
          PGRAVA_LOG_VALOR('p_regproduto.ptabela após ST' || ': ',p_regproduto.ptabela);
          PGRAVA_LOG_VALOR('p_regitem.pvenda após ST' || ': ', p_regitem.pvenda);

        END IF;

      END IF; -- Fim Condição Aplicação do ST Fonte para Clientes não Fonte

   if p_regfilial.utilizacontrolemedicamentos = 'S' then

        -- HIS.04408.2015
        IF ((FUNCOES_MED.FUNC_UTILIZAPRECOFABRICA(p_regproduto.tipomerc,
