                      if vsmensagem is not null then
                        vschar := '#';
                      else
                        vschar := null;
                      end if;

                      vsmensagem              := vsmensagem || vschar ||
                                                 'PRECO DE VENDAS ACIMA DO PRECO MAX CONSUMIDOR;';
                      vsmensagem              := vsmensagem || 'PRECO DE VENDA: ' ||
