                                                   vrDadosRepasse.vvTipoRepasse,
                                                   vrDadosRepasse.vnValorRepasse);
                IF (vrDadosRepasse.vvMensagemRepasse IS NOT NULL) THEN
                  if vsmensagem is not null then
                    vschar := '#';
                  else
                    vschar := null;
                  end if;
                  vsmensagem              := vsmensagem || vschar ||
                                            vrDadosRepasse.vvMensagemRepasse || ';' ||
                                             sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';';
                  p_regitem.valido        := false;
                  p_regorigempreco.valido := false;
                  if p_Regitem.codmotivonaoatend is null then
                    p_regitem.codmotivonaoatend := 23;
                  end if;
                END IF;

                p_regitem.vlrepasse := NVL(vrDadosRepasse.vnValorRepasse,0);
                p_regitem.vloutros  := NVL(vrDadosRepasse.vnValorRepasse,0);

              ELSE

                 if p_regproduto.tipomerc in ('M','MA','L') and p_regcliente.repasse = 'S' then

                   -- Tipo de Aplicação do Repasse = Acréscimo sobre Preço Bruto - Tarefa 153405
                    if    (nvl(p_regfilial.TipoAplicRepasseFilial,'AB') = 'AB') then
                      p_regitem.vlrepasse := vnptabela_aux * p_regprecos.perdescrepasse/100;
                      p_regitem.vloutros := p_regitem.vlrepasse;
                    -- Tipo de Aplicação do Repasse = Acréscimo ST Ult Ent - HIS.03788.2015
                    elsif  (nvl(p_regfilial.TipoAplicRepasseFilial,'AB') = 'AS') then
                       IF (NVL(p_regprecos.usabcrultent,'N') = 'S')      AND
                          (NVL(p_regcliente.consumidorfinal,'N') <> 'S') THEN
                         BEGIN
                           SELECT NVL(STBCR ,0)
                             INTO p_regitem.vlrepasse
                             FROM PCEST
                            WHERE (PCEST.CODPROD   = p_regitem.codprod)
                              AND (PCEST.CODFILIAL = p_regpedido.codfilial);
                          EXCEPTION
                            WHEN NO_DATA_FOUND THEN
                              p_regitem.vlrepasse := 0;
                          END;
                          p_regitem.vloutros := p_regitem.vlrepasse;
                          -- Se não achou o ST BCR
                          IF (NVL(p_regitem.vlrepasse,0) <= 0) THEN
                            if vsmensagem is not null then
                              vschar := '#';
                            else
                              vschar := null;
                            end if;
                            vsmensagem              := vsmensagem || vschar ||
                                                      'PRODUTO SEM ST BCR PARA FORMAÇÃO DO REPASSE#;' ||
                                                       sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';';
                            p_regitem.valido        := false;
                            p_regorigempreco.valido := false;

                            if p_Regitem.codmotivonaoatend is null then
                              p_regitem.codmotivonaoatend := 23;
                             end if;
                          END IF;
                        END IF; -- Fim Condição: usabcrultent
                    -- Tipo de Aplicação do Repasse = Acréscimo sobre Preço Bruto - Tarefa 153405
                    elsif (nvl(p_regfilial.TipoAplicRepasseFilial,'AB') = 'AL') then
                      p_regitem.vlrepasse := (vnptabela_aux * (1-(nvl(vnperdesc,0)/100))) * (p_regprecos.perdescrepasse/100);
                      p_regitem.vloutros := p_regitem.vlrepasse;
                    end if;

                  end if;

              END IF; -- Se o Pedido foi recebido por Integração de OL via Banco de Dados OU Se o Repasse for pelo STBCR OU o OL/PE possui tratamento diferenciado

            end if;
         end if;

     /************************************************
      ACRÉSCIMO DE OPERADOR LOGÍSTICO - HIS.00262.2018
      ************************************************/
      p_regitem.vlacrescoperlog := NULL;
      IF (NVL(p_regitem.percacrescoperlog,0) > 0) AND  -->> SE GRAVOU NO ITEM O % ACRÉSCIMO OL
         (NVL(p_regitem.vlrepasse,0) = 0)         THEN -->> NÃO PODE TER REPASSE
        -- Calcula o valor do acréscimo do operador logístico
        p_regitem.vlacrescoperlog   := (vnptabela_aux * (1-(nvl(vnperdesc,0)/100))) * (NVL(p_regitem.percacrescoperlog,0)/100);
        PGRAVA_LOG_VALOR('p_regitem.vlacrescoperlog'   || ': ',p_regitem.vlacrescoperlog);
        --
        PGRAVA_LOG_VALOR('p_regproduto.ptabela antes percacrescoperlog' || ': ', p_regproduto.ptabela);
        PGRAVA_LOG_VALOR('p_regitem.pvenda antes percacrescoperlog'     || ': ', p_regitem.pvenda);
        p_regproduto.ptabela := round(p_regproduto.ptabela + nvl(p_regitem.vlacrescoperlog,0),gregpcconsum.numcasasdecvenda);
        p_regitem.pbaserca   := round(p_regitem.pbaserca   + nvl(p_regitem.vlacrescoperlog,0),gregpcconsum.numcasasdecvenda);
        p_regitem.pvenda     := round(p_regitem.pvenda     + nvl(p_regitem.vlacrescoperlog,0),gregpcconsum.numcasasdecvenda);
        PGRAVA_LOG_VALOR('p_regproduto.ptabela após percacrescoperlog' || ': ', p_regproduto.ptabela);
        PGRAVA_LOG_VALOR('p_regitem.pvenda após percacrescoperlog'     || ': ', p_regitem.pvenda);
      END IF; -- FIM: ACRÉSCIMO DE OPERADOR LOGÍSTICO - HIS.00262.2018

      -- Tarefa: 184043 - Cálculo do Desconto Financeiro em Pedidos Eletrônicos
      --                  conforme parâmetro de definição da Base de Cálculo
      --                  Ampliado ao Operador Logístico
      if (p_regpedido.tipofv IN ('OL','PE')) then
        -- Se existe Desconto Financeiro para o Item
        if nvl(p_regitem.perdescboleto,0) > 0 then

           -- Se a Base de Cálculo do Desconto Financeiro for o Preço Liquido
           if (nvl(p_regfilial.basecalcdescfinmed,'1') = '2') then
             p_regitem.VLDESCBOLETO := round(p_regitem.pvenda * (p_regitem.perdescboleto/100),6); -- MED-1645
           -- Se a Base de Cálculo do Desconto Financeiro for o Preço Bruto
           else
             p_regitem.VLDESCBOLETO := round(p_regproduto.ptabela * (p_regitem.perdescboleto/100),6); -- MED-1645
           end if;

        end if;
      end if;


      PGRAVA_LOG_VALOR('p_regproduto.ptabela antes Repasse' || ': ',p_regproduto.ptabela);
      PGRAVA_LOG_VALOR('p_regitem.pvenda antes Repasse' || ': ', p_regitem.pvenda);

      p_regproduto.ptabela := round(p_regproduto.ptabela + nvl(p_regitem.vlrepasse,0),gregpcconsum.numcasasdecvenda);
      p_regitem.pbaserca := round(p_regitem.pbaserca + nvl(p_regitem.vlrepasse,0),gregpcconsum.numcasasdecvenda);




      -- Acrescenta o Repasse aos Pedidos de OL e Eletrônicos
      p_regitem.pvenda := round(p_regitem.pvenda+ nvl(p_regitem.vlrepasse,0),gregpcconsum.numcasasdecvenda);

--//      if p_regpedido.tipofv = 'OL' then

         p_Regitem.pbaserca := p_regitem.pvenda;

--//      end if;


      PGRAVA_LOG_VALOR('p_regitem.vlrepasse' || ': ',p_regitem.vlrepasse);
      PGRAVA_LOG_VALOR('p_regproduto.ptabela após Repasse' || ': ',p_regproduto.ptabela);
      PGRAVA_LOG_VALOR('p_regitem.pvenda após Repasse' || ': ', p_regitem.pvenda);


      -------------------------------------------------------------------------------------------------------
      -- 4493.064633.2016 - INICIO: ULTIMA VALIDAÇÃO - PREÇOS ZERADOS - para não dar erro de divisão por zero
      -------------------------------------------------------------------------------------------------------
      -- Preço Tabela
      if (nvl(p_regproduto.ptabela,0) = 0) then
        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;
        vsmensagem := vsmensagem || vschar ||
                      'PRECO TABELA ZERADO;';
        p_regitem.valido := false;
        p_regorigempreco.valido := false;

        if p_Regitem.codmotivonaoatend is null then
          p_regitem.codmotivonaoatend := 27;
        end if;
      end if;
      -- Preço Venda
      if (nvl(p_regitem.pvenda,0) = 0) then
        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;
        vsmensagem := vsmensagem || vschar ||
                      'PRECO VENDA ZERADO;';
        p_regitem.valido := false;
        p_regorigempreco.valido := false;

        if p_Regitem.codmotivonaoatend is null then
          p_regitem.codmotivonaoatend := 27;
        end if;
      end if;
      ----------------------------------------------------------------------------------------------------
      -- 4493.064633.2016 - FIM: ULTIMA VALIDAÇÃO - PREÇOS ZERADOS - para não dar erro de divisão por zero
      ----------------------------------------------------------------------------------------------------

    end if; -- FIM: if p_Regitem.valido = true then

    if p_Regpedido.condvenda in (5, 6, 11, 12) then
      if gregpcconsum.usaptabelacomobase = 'S' then
        -- 4954.013038.2018 - Igualar a 2316, abatendo o Desconto da Promoção
        p_regitem.pbaserca := p_regproduto.ptabela * (1 - NVL(p_regitem.percdescbaserca,0) / 100);
      else
        p_regitem.pbaserca := p_regitem.pvenda;
      end if;
    end if;


    end if;

    ---------------------
    -- RESTRIÇÃO DE PREÇO
    ---------------------
    -- Restrição Preço/Desconto
    IF (NOT FUNCOES_MED.FValidarRestricaoPrecoDescMed(p_regpedido.codfilial,
                                                      p_regitem.codprod,
                                                      p_regitem.pvenda,
                                                      p_regpedido.tipofv,
                                                      vvMsgRestricaoPrecoDescMed)) THEN
      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem := vsmensagem || vschar || vvMsgRestricaoPrecoDescMed;
      p_regitem.valido        := FALSE;
      p_regorigempreco.valido := FALSE;
      if p_Regitem.codmotivonaoatend is null then
         p_regitem.codmotivonaoatend := 26;
      end if;
    END IF;
    -- FIM RESTRIÇÃO DE PREÇO

    ---------------------------------------------
    -- INICIO: TETOS DE DESCONTO - HIS.00365.2016
    ---------------------------------------------
    -- Calcula Desconto para uso na Proc. de Validação
    IF ((p_regproduto.ptabela-NVL(p_regitem.st,0)-NVL(p_regitem.vlrepasse,0)) <> 0) THEN
      vrDadosRetValidaProd.vnPercDesc := ( ( (p_regproduto.ptabela-NVL(p_regitem.st,0)-NVL(p_regitem.vlrepasse,0)) - (p_regitem.pvenda-NVL(p_regitem.st,0)-NVL(p_regitem.vlrepasse,0)) ) / (p_regproduto.ptabela-NVL(p_regitem.st,0)-NVL(p_regitem.vlrepasse,0)) ) * 100;
    ELSE
      vrDadosRetValidaProd.vnPercDesc := 0;
    END IF;
    -- Chama Proc. de Validação
    PKG_FUNCOESVENDAS_MED.P_VALIDACAO_FINAL_PROD('I', -- Origem Chamada = Integradora
                                                 'I', -- Tipo Chamada = Inclusão do Item do Pedido
                                                 'S', -- Grava Tabela Temporária
                                                 p_regpedido.origemped,
                                                 p_regpedido.tipofv,
                                                 p_regpedido.integradora,
                                                 p_regpedido.codfilial,
                                                 p_regpedido.codfilialnf,
                                                 p_regitem.codfilialretira,
                                                 p_regpedido.codcli,
                                                 p_regregiao.numregiao,
                                                 p_regpedido.codusur,
                                                 p_regitem.codplpag,
                                                 p_regitem.codpromocaomed,
                                                 p_regitem.codprod,
                                                 p_regitem.qt,
                                                 vrDadosRetValidaProd.vnPercDesc,
                                                 (p_regitem.pvenda-NVL(p_regitem.st,0)-NVL(p_regitem.vlrepasse,0)),
                                                 0, -- Aqui ainda não tem NumPed (passar zero)
                                                 0, -- Aqui ainda não tem NumSeq (passar zero)
                                                 p_regitem.precomaxconsum, -- HIS.01765.2016
                                                 vrDadosRetValidaProd.vvTipoRejeicaoProduto,
                                                 vrDadosRetValidaProd.vvMotivoNaoPodeComprar,
                                                 vrDadosRetValidaProd.vnQtdeLimite,
                                                 p_regitem.coddesconto,
                                                 NULL, -- Aqui não tem NUMLOTE
                                                 p_regitem.numlotepromocaomed);
    -->> Primeiro verifica críticas que bloqueiam
    FOR vc_Rejeicoes IN (SELECT PCMED_VALIDACAO_GERAL_PRODUTO.CODREJEICAO
                              , PCMED_VALIDACAO_GERAL_PRODUTO.CODMOTIVONAOATEND
                              , PCMED_VALIDACAO_GERAL_PRODUTO.DESCRICAOREJEICAO
                              , PCMED_VALIDACAO_GERAL_PRODUTO.OBSERVACAO
                           FROM PCMED_VALIDACAO_GERAL_PRODUTO
                          WHERE (PCMED_VALIDACAO_GERAL_PRODUTO.TIPOREJEICAO = 'B')) LOOP -->> Somente Críticas que Bloqueiam o Item
      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem := vsmensagem || vschar || vc_Rejeicoes.CODREJEICAO || '-' || vc_Rejeicoes.DESCRICAOREJEICAO ||' (' || vc_Rejeicoes.OBSERVACAO || ')';
      p_regpedido.posicao   := 'B';
      p_regpedido.codmotivo := 6; -->> deverá ser adicionado campo de código de motivo na PCMED_VALIDACAO_GERAL_PRODUTO
      if p_Regitem.codmotivonaoatend is null then
         p_regitem.codmotivonaoatend := vc_Rejeicoes.CODMOTIVONAOATEND;
      end if;
    END LOOP;
    -->> Depois verifica críticas que rejeitam
    FOR vc_Rejeicoes IN (SELECT PCMED_VALIDACAO_GERAL_PRODUTO.CODREJEICAO
                              , PCMED_VALIDACAO_GERAL_PRODUTO.CODMOTIVONAOATEND
                              , PCMED_VALIDACAO_GERAL_PRODUTO.DESCRICAOREJEICAO
                              , PCMED_VALIDACAO_GERAL_PRODUTO.OBSERVACAO
                           FROM PCMED_VALIDACAO_GERAL_PRODUTO
                          WHERE (PCMED_VALIDACAO_GERAL_PRODUTO.TIPOREJEICAO = 'R')) LOOP -->> Somente Críticas que Rejeitam o Item
      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem := vsmensagem || vschar || vc_Rejeicoes.CODREJEICAO || '-' || vc_Rejeicoes.DESCRICAOREJEICAO ||' (' || vc_Rejeicoes.OBSERVACAO || ')';
      p_regitem.valido        := FALSE;
      p_regorigempreco.valido := FALSE;
      if p_Regitem.codmotivonaoatend is null then
         p_regitem.codmotivonaoatend := vc_Rejeicoes.CODMOTIVONAOATEND;
      end if;
    END LOOP;
    ---------------------------------------------
    -- FIM: TETOS DE DESCONTO - HIS.00365.2016
    ---------------------------------------------

    -- Se Gravou Array de Log Específico - HIS.03080.2016
    IF (vtLogImportacaoItem.COUNT > 0) THEN
      FOR viIdxImportacaoItem IN vtLogImportacaoItem.FIRST..vtLogImportacaoItem.LAST LOOP
        -- Log Específico
        p_regitem.logprocmed := p_regitem.logprocmed || vtLogImportacaoItem(viIdxImportacaoItem) || CHR(13);
      END LOOP;
    END IF;

    -- Se Gravou Array de Log Específico - MED-1499
    IF (vtJsonImportacaoItem.COUNT > 0) THEN
      FOR viIdxImportacaoItem IN vtJsonImportacaoItem.FIRST..vtJsonImportacaoItem.LAST LOOP
        -- Log Específico
        p_regitem.jsonprocmed := p_regitem.jsonprocmed || vtJsonImportacaoItem(viIdxImportacaoItem) || CHR(13);
      END LOOP;
    END IF;

    -- registra log
    if (vsmensagem is not null) then
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       p_regitem.codprod,
                       p_regitem.codauxiliar,
                       p_Regitem.cgccli,
                       null,
                       null,
                       null,
                       p_regpedido.codusur,
                       p_Regpedido.dtaberturapedpalm,
                       null,
                       '3',
                       vsmensagem,
                       null,
                       p_regitem.numseqifv);
    end if;
  exception
    when others then

      p_regitem.valido        := false;
      p_regorigempreco.valido := false;
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       p_regitem.codprod,
                       p_regitem.codauxiliar,
                       p_Regitem.cgccli,
                       null,
                       null,
                       null,
                       p_regpedido.codusur,
                       p_regitem.dtaberturapedpalm,
                       null,
                       '3',
                       sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->003->' || SQLERRM,
                       null,
                       p_regitem.numseqifv);

          if p_Regitem.codmotivonaoatend is null then
             p_regitem.codmotivonaoatend := 28;

          end if;


  end proc_validaritemOLePE;



    procedure enviarmensagensrca is

  begin
    begin


      FOR c_pcmens IN (SELECT pcmens.rowid id,
                              pcmens.data,
                              pcmens.codfuncemite,
                              pcempr.nome,
                              pcmens.mens1,
                              pcmens.mens2,
                              pcmens.mens3,
                              pcmens.mens4,
                              pcmens.mens5,
                              pcmens.mens6,
                              pcmens.mens7,
                              pcmens.mens8,
                              pcmens.codusur
                         FROM pcmens, pcempr
                        WHERE NVL(enviado, 'N') = 'N'
                          and pcmens.codfuncemite = pcempr.matricula) LOOP



          insert into pcmensfv
          (  retorno, --1
             codusur, --2
             data, --3
             mens1, --4
             mens2, --5
             mens3, --6
             mens4, --7
             mens5, --8
             mens6, --9
             mens7, --10
             mens8, --11
             codfuncemite, --12
             dtinclusao --13
          )
          values ( 2, --1
                   c_pcmens.codusur, --2
                   c_pcmens.data, --3
                   c_pcmens.mens1, --4
                   c_pcmens.mens2, --5
                   c_pcmens.mens3, --6
                   c_pcmens.mens4, --7
                   c_pcmens.mens5, --8
                   c_pcmens.mens6, --9
                   c_pcmens.mens7, --10
                   c_pcmens.mens8, --11
                   c_pcmens.codfuncemite, --12
                   sysdate   --13
          );


        UPDATE pcmens
           SET enviado = 'S'
         WHERE rowid = c_pcmens.id;

        COMMIT;


      END LOOP;


    EXCEPTION
      WHEN OTHERS THEN
        ROLLBACK;
    end;
  end enviarmensagensrca;


   /*
    MED-1499 - Substituída pela INTEGRADORACOMPLE_MED.proc_validacreditocliente
    function func_validaautorizacaopcautorc( p_regcliente   in t_clientepedido,
                                            p_codusur       in pcpedc.codusur%type,
                                            p_regfilial     in t_filial,
                                            p_vldisp        in number ,
                                            p_vlatend       in number) return number is

    vnvlliberado    number;

   begin

            begin

                  select sum(pcautorc.vlliberado)
                  into vnvlliberado
                  from pcautorc, pcempr
                  where ((pcautorc.codcli = p_regcliente.codcli) OR
                      (p_regfilial.somacreditocliprincipal = 'S' and ( pcautorc.codcli in (select pcclient.codcli from pcclient where codcliprinc = p_regcliente.codcliprinc))))
                   and pcautorc.codusur = p_codusur
                   and pcautorc.codfunc = pcempr.matricula
                   and pcautorc.liberalimcred = 'S'
                   and pcautorc.dtutilizacao is null
                   and pcautorc.codfuncutilizacao is null
                   and (p_vldisp +  nvl(pcautorc.vlliberado,0)) >= p_vlatend
                   and rownum = 1
                  order by data;
                 exception when others then

                   vnvlliberado := 0;

             end;

     return vnvlliberado;



  end func_validaautorizacaopcautorc;
  */


/*
MED-1499 - Substituída pela INTEGRADORACOMPLE_MED.proc_validacreditocliente
procedure proc_atualizarpcautorc(p_numped      IN pcpedc.numped%type,
                                 p_codusur     IN pcpedc.codusur%type,
                                 p_codcli      IN pcpedc.codcli%type,
                                 p_vlpendente  IN number,
                                 p_limcred     IN number) is

  vnnumpedido pcautorc.numpedido%type;

begin


      select numpedido
      into vnnumpedido
      from pcautorc
      where codusur = p_codusur
      and codcli    = p_codcli
      and codfuncutilizacao is null
      and dtutilizacao is null
      and rownum = 1
      order by data;


      for reg in (select *
                  from pcautorc
                  where numpedido = vnnumpedido
                  and codusur = p_codusur
                  and codcli = p_codcli
                  for update) loop

        exit;
       end loop;

          update pcautorc
          set  limcred = p_limcred
               ,vlpendente = p_vlpendente
               ,dtutilizacao = trunc(sysdate)
               ,codfuncutilizacao = 8888
               ,numpedutilizacao = p_numped
          where numpedido = vnnumpedido
          and codusur = p_codusur
          and codcli = p_codcli
          and codfuncutilizacao is null
          and dtutilizacao is null;


end proc_atualizarpcautorc;
*/

 /*
  MED-1499 - Substituída pela INTEGRADORACOMPLE_MED.proc_validacreditocliente
  function func_existelimitecliente(p_regpedido       in t_cabped,
                                    p_regcliente      in t_clientepedido,
                                    p_regfilial       in t_filial,
                                    p_vltotped        in number,
                                    p_saldodisponivel out number)
    return boolean is

    vncontasareceberemaberto number;
    vnvalorpedidospendentes  number;
    vnvllimcredtot           number;


  begin

    p_saldodisponivel := 0;


  if p_regfilial.somacreditocliprincipal  = 'N' then



    if p_Regfilial.usabnflimitecredito = 'S' then

      -- Pendencias no contas a receber do cliente
      select sum(NVL(pcprest.valor, 0))
        into vncontasareceberemaberto
        from pcprest
       where pcprest.codcli = p_regcliente.codcli
         and pcprest.dtpag is null ;

        select sum(NVL(vlatend, 0))
          into vnvalorpedidospendentes
          from pcpedc
         where codcli   = p_regcliente.codcli
           and dtcancel is null
           and posicao  in ('L', 'M');

    else
      -- Pendencias no contas a receber do cliente
      select sum(NVL(pcprest.valor, 0))
        into vncontasareceberemaberto
        from pcprest
       where pcprest.codcli = p_regcliente.codcli
         and pcprest.dtpag is null
         and PCPREST.CODCOB not in ('BNF','BNFT','BNTR','BNFR','BNRP');


        select sum(NVL(vlatend, 0))
          into vnvalorpedidospendentes
          from pcpedc
         where codcli   = p_regcliente.codcli
           and dtcancel is null
           and posicao  in ('L', 'M')
           and CODCOB not in ('BNF','BNFT','BNTR','BNFR','BNRP');


    end if;

    p_saldodisponivel := ((nvl(p_regcliente.limcred,0) * (1 + (NVL (gregpcconsum.perexcedelimcred, 0) / 100)) )-
                         (NVL(vncontasareceberemaberto, 0) +
                         NVL(vnvalorpedidospendentes, 0)));

    p_saldodisponivel := ROUND(p_saldodisponivel,
                               gregpcconsum.numcasasdecvenda);

    --Calcula o valor disponivel de credito para o cliente
    if p_vltotped > p_saldodisponivel then

       if  p_saldodisponivel + func_validaautorizacaopcautorc(p_regcliente,
                                                          p_regpedido.codusur,
                                                          p_regfilial,
                                                          p_saldodisponivel,
                                                          p_vltotped) >= p_vltotped then


             proc_atualizarpcautorc(p_regpedido.numped,
                                    p_regpedido.codusur,
                                    p_regpedido.codcli,
                                    (NVL(vncontasareceberemaberto, 0) +  NVL(vnvalorpedidospendentes, 0)),
                                    p_regcliente.limcred);


            return true;

       else
          return false;
       end if;
    else
      return true;
    end if;

 else

    if p_Regfilial.usabnflimitecredito = 'S' then

    -- Pendencias no contas a receber do cliente
    select sum(NVL(pcprest.valor, 0))
      into vncontasareceberemaberto
      from pcprest
     where (pcprest.codcli in (select pcclient.codcli from pcclient where pcclient.codcliprinc =  p_regcliente.codcliprinc) OR
            pcprest.codcli = p_regpedido.codcli)
       and pcprest.dtpag is null;

    -- Pedidos pendentes do cliente
    select sum(NVL(vlatend, 0))
      into vnvalorpedidospendentes
      from pcpedc
     where (codcli   in (select pcclient.codcli from pcclient where pcclient.codcliprinc =  p_regcliente.codcliprinc) OR
            codcli = p_regpedido.codcli)
       and dtcancel is null
       and posicao  in ('L', 'M');


    else

    -- Pendencias no contas a receber do cliente
    select sum(NVL(pcprest.valor, 0))
      into vncontasareceberemaberto
      from pcprest
     where (pcprest.codcli in (select pcclient.codcli from pcclient where pcclient.codcliprinc =  p_regcliente.codcliprinc) OR
            pcprest.codcli = p_regpedido.codcli)
       and pcprest.dtpag is null
       and PCPREST.CODCOB not in ('BNF','BNFT','BNTR','BNFR','BNRP');

    -- Pedidos pendentes do cliente
    select sum(NVL(vlatend, 0))
      into vnvalorpedidospendentes
      from pcpedc
     where (codcli   in (select pcclient.codcli from pcclient where pcclient.codcliprinc =  p_regcliente.codcliprinc) OR
            codcli = p_regpedido.codcli)
       and dtcancel is null
       and posicao  in ('L', 'M')
       and CODCOB not in ('BNF','BNFT','BNTR','BNFR','BNRP');


    end if;


     select sum(pcclient.limcred)
     into vnvllimcredtot
     from pcclient
     where (pcclient.codcliprinc =  p_regcliente.codcliprinc OR pcclient.codcli = p_regpedido.codcli);

    p_saldodisponivel := ((nvl(vnvllimcredtot,0)* (1 + (NVL (gregpcconsum.perexcedelimcred, 0) / 100))) -
                         (NVL(vncontasareceberemaberto, 0) +
                         NVL(vnvalorpedidospendentes, 0)));

    p_saldodisponivel := ROUND(p_saldodisponivel,
                               gregpcconsum.numcasasdecvenda);

    --Calcula o valor disponivel de credito para o cliente
    if p_vltotped > p_saldodisponivel then

       if  p_saldodisponivel + func_validaautorizacaopcautorc(p_regcliente,
                                                              p_regpedido.codusur,
                                                              p_regfilial,
                                                              p_saldodisponivel,
                                                              p_vltotped) >= p_vltotped then


             proc_atualizarpcautorc(p_regpedido.numped,
                                    p_regpedido.codusur,
                                    p_regpedido.codcli,
                                    (NVL(vncontasareceberemaberto, 0) +  NVL(vnvalorpedidospendentes, 0)),
                                    p_regcliente.limcred);


            return true;

       else
          return false;
       end if;
    else
      return true;
    end if;


 end if;

  exception
    when others then

      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       null,
                       null,
                       p_regpedido.cgccli,
                       null,
                       null,
                       null,
                       p_regpedido.codusur,
                       p_regpedido.dtaberturapedpalm,
                       null,
                       '2',
                       sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->004->' || SQLERRM || ';',
                       null);
      return false;

  end func_existelimitecliente;
  */

  function func_calculanumparcplpag(p_regplpag in t_planodepagamento)
    return integer is
    vnnumparcelas integer;
  begin
    vnnumparcelas := 1;
    if p_regplpag.prazo1 > 0 then
      vnnumparcelas := 1;
      if p_regplpag.prazo2 > 0 then
        vnnumparcelas := vnnumparcelas + 1;
        if p_regplpag.prazo3 > 0 then
          vnnumparcelas := vnnumparcelas + 1;
          if p_regplpag.prazo4 > 0 then
            vnnumparcelas := vnnumparcelas + 1;
            if p_regplpag.prazo5 > 0 then
              vnnumparcelas := vnnumparcelas + 1;
              if p_regplpag.prazo6 > 0 then
                vnnumparcelas := vnnumparcelas + 1;
                if p_regplpag.prazo7 > 0 then
                  vnnumparcelas := vnnumparcelas + 1;
                  if p_regplpag.prazo8 > 0 then
                    vnnumparcelas := vnnumparcelas + 1;
                    if p_regplpag.prazo9 > 0 then
                      vnnumparcelas := vnnumparcelas + 1;
                      if p_regplpag.prazo10 > 0 then
                        vnnumparcelas := vnnumparcelas + 1;
                      end if;
                    end if;
                  end if;
                end if;
              end if;
            end if;
          end if;
        end if;
      end if;
    end if;
    return vnnumparcelas;
  end func_calculanumparcplpag;


/*MED-869
function func_inseriritemcesta
  (
    p_regrca     in t_rca,
    p_regcliente in t_clientepedido,
    p_regitem    in t_itemped,
    p_regpedido  in t_cabped,
    p_regregiao  in t_regiaocliente,
    p_regfilial  in t_filial

  ) return boolean is

    vslinha            varchar2(10);
    vncountitenscesta  number := 0;
    vnnumseq           number;
    vbcalcularst       boolean;
    vsmensagem_st      varchar2(1000);
    vnstfonte          number;
    vsmensagem_stfonte varchar2(1000);
    vsmensagem_comiss  varchar2(1000);
    vnperdesc           number;
    vbcodicmtabpf       boolean;
    vnbaseicstfonte     pcpedi.baseicst%type;

    vnpercom                   pcpedi.percom%type;

    vbUsaPcTabComiss           boolean;
    vbUsaPcComissaoUsur        boolean;
    vbUsaPCComissaoPlPag       boolean;
    vbUsaPCComissaoRegiao      boolean;
    vicont                     number;
    vbUsaPCComissaofilial      boolean;
    vnperluc                   number;

    vncodcomis                 pcorigemcomis.codcomis%type;
    vscodrotinacomis           pcorigemcomis.codrotinacomis%type;
    vsLetraComiss              pcpedi.letracomiss%type;
    vsConsiderarIpiAliqicms2   varchar2(1);

    vncodicmtabinternac        number; -- HIS.02787.2016

    vvMsgErroCalcularCMV       varchar2(2000); -- HIS.02787.2016

  begin

    vncountitenscesta := gvet_regitenscesta.count;
    vnnumseq          := 0;

    for i in 1 .. vncountitenscesta
    loop

      if p_regpedido.numped = gvet_regitenscesta(i)
      .numped
         and p_regitem.codprod = gvet_regitenscesta(i).codprodcesta
      then

         vsConsiderarIpiAliqicms2 := 'N';

        if (p_regcliente.ConsumidorFinal = 'S') and ((gvet_regitenscesta(i).Importado = 'S') or (gvet_regitenscesta(i).Importado = 'D')) and
           (p_regfilial.uf <> p_regcliente.estent) and (gvet_regitenscesta(i).AGREGARIPICALCULOST = 'S') then

           vsConsiderarIpiAliqicms2 := 'S';
        end if;


        vbcalcularst := funcoesvendas.calcularst(gvet_regitenscesta(i).pvenda
                                                ,0
                                                ,p_regpedido.percvenda
                                                ,gregpcconsum.tipocalcst
                                                ,gregpcconsum.calcstpf
                                                ,gvet_regitenscesta(i).mostrarpvendasemst
                                                ,gregpcconsum.consideraisentoscomopf
                                                ,p_regcliente.calculast
                                                ,p_regcliente.ieent
                                                ,p_regcliente.tipofj
                                                ,gvet_regitenscesta(i).pauta
                                                ,gvet_regitenscesta(i).iva
                                                ,gvet_regitenscesta(i).aliqicms1
                                                ,gvet_regitenscesta(i).aliqicms2
                                                ,gvet_regitenscesta(i).percbaseredst
                                                ,gregpcconsum.numcasasdecvenda
                                                ,0
                                                ,p_regfilial.uf
                                                ,p_regcliente.estent
                                                , gvet_regitenscesta(i).usavalorultentbasest
                                                , gvet_regitenscesta(i).usavalorultentbasest2
                                                ,gvet_regitenscesta(i).valorultent
                                                ,p_regcliente.contribuinte
                                                ,p_regcliente.utilizaiesimplificada
                                                ,vsmensagem_st
                                                ,gvet_regitenscesta(i).st
                                                ,gvet_regitenscesta(i).baseicst
                                                ,gregpcconsum.aceitapfcontribuinte
                                                ,gvet_regitenscesta(i).usapmcbasest
                                                ,gvet_regitenscesta(i).precomaxconsum
                                                ,gvet_regitenscesta(i).custonfsemst
                                                ,p_regcliente.consumidorfinal
                                                ,vsConsiderarIpiAliqicms2
                                                ,gvet_regitenscesta(i).usavlultentmediobasest
                                                ,gvet_regitenscesta(i).vlultentmes
                                                );

        if vsmensagem_st is not null
        then
        proc_registralog(p_regpedido.numped,
                         p_regpedido.numpedrca,
                         p_regitem.codprod,
                         p_regitem.codauxiliar,
                         null,
                         null,
                         null,
                         null,
                         p_regpedido.codusur,
                         p_regpedido.dtaberturapedpalm,
                         null,
                         '3',
                         vsmensagem_st,
                         null);
        end if;

        vnstfonte := 0;

        -------------------
        -- CALCULA ST FONTE
        -------------------
        PRC_MED_OBTEM_STFONTE_30(p_regpedido.codfilial,
                                 p_regitem.codprod,
                                 p_regpedido.codcli,
                                 p_regregiao.numregiao,
                                 p_regpedido.condvenda,
                                 p_regpedido.percvenda,
                                 gvet_regitenscesta(i).codst,
                                 gvet_regitenscesta(i).pvenda,
                                 0,
                                 gvet_regitenscesta(i).precomaxconsum,
                                 gvet_regitenscesta(i).valorultent,
                                 gvet_regitenscesta(i).custonfsemst,
                                 gvet_regitenscesta(i).ptabela,
                                 'N', -->> Padrão Não (Simples Nacional)
                                 'N', -->> Não Pesquisa Custos
                                 'N', -->> Não é Item Bonificado
                                 0,   -->> Não passa Frete e Outras Despesas
                                 vnbaseicstfonte,
                                 vnstfonte,
                                 vsmensagem_stfonte,
                                 gvet_regitenscesta(i).RegimeEspIsenStFonte,
                                 gvet_regitenscesta(i).aliqicms1fonte,
                                 gvet_regitenscesta(i).aliqicms2fonte,
                                 gvet_regitenscesta(i).ivafonte,
                                 gvet_regitenscesta(i).percbaseredstfonte,
                                 'O',   -->> Chamada = Outros
                                 0,     -->> Não é preciso passar Qtde. para PEPS
                                 NULL,  -->> Não é preciso passar Número do Pedido para PEPS
                                 p_regpedido.codfilialnf, -- HIS.03377.2017
                                 gvet_regitenscesta(i).pauta, -- HIS.03377.2017
                                 gvet_regitenscesta(i).observacaostfonte,  -- HIS.03377.2017
                                 gvet_regitenscesta(i).indescalarelevante, -- HIS.03377.2017
                                 gvet_regitenscesta(i).cnpjfabricante, -- HIS.03377.2017
                                 gvet_regitenscesta(i).fabricante); -- HIS.03377.2017

        if vnbaseicstfonte > 0 then

         gvet_regitenscesta(i).baseicst := vnbaseicstfonte;

        end if;


        if vsmensagem_stfonte is not null
        then
        proc_registralog(p_regpedido.numped,
                         p_regpedido.numpedrca,
                         p_regitem.codprod,
                         p_regitem.codauxiliar,
                         null,
                         null,
                         null,
                         null,
                         p_regpedido.codusur,
                         p_regpedido.dtaberturapedpalm,
                         null,
                         '3',
                         vsmensagem_stfonte,
                         null);
        end if;

        if (gvet_regitenscesta(i).st = 0)
           and (vnSTFONTE <> 0)
        then

          gvet_regitenscesta(i).st := vnSTFONTE;

          gvet_regitenscesta(i).PVENDA := Round(gvet_regitenscesta(i).PVENDA + vnSTFONTE
                                               ,gregpcconsum.numcasasdecvenda);


          gvet_regitenscesta(i).PTABELA := Round(gvet_regitenscesta(i)
                                                 .PTABELA + vnSTFONTE
                                                ,gregpcconsum.numcasasdecvenda);

          gvet_regitenscesta(i).IVA := gvet_regitenscesta(i).ivafonte;

          gvet_regitenscesta(i).PAUTA := 0;

          gvet_regitenscesta(i).ALIQICMS1 := gvet_regitenscesta(i).aliqicms1fonte;

          gvet_regitenscesta(i).ALIQICMS2 := gvet_regitenscesta(i).aliqicms2fonte;

          gvet_regitenscesta(i).PERCBASEREDST := gvet_regitenscesta(i).percbaseredst;

          gvet_regitenscesta(i).PERCBASEREDSTFONTE := gvet_regitenscesta(i)
                                                     .PERCBASEREDSTFONTE;

          gvet_regitenscesta(i).REGIMEESPISENSTFONTE := gvet_regitenscesta(i)
                                                       .REGIMEESPISENSTFONTE;

        end if;


        if gvet_regitenscesta(i).codicmtabpf is null
        then
          vbcodicmtabpf := true;
        else
          vbcodicmtabpf := false;
        end if;

          -- HIS.02787.2016 -- comentado
          p_calcularcmv_med(p_regfilial.tributsaidaorigemnacimp -- HIS.02787.2016
                                 ,gregpcconsum.abaterimpostoscomissaorca
                                 ,gregpcconsum.aplicarindicecmv
                                 ,gregpcconsum.Incluircomissaosugpvendacmv
                                 ,nvl(gregpcconsum.txvenda, 0)
                                 ,p_regcliente.tipofj
                                 ,p_regcliente.utilizaiesimplificada
                                 ,p_regcliente.ieent
                                 ,gvet_regitenscesta(i).freteespecial
                                 ,p_regregiao.PERFRETETERCEIROS
                                 ,p_regregiao.PERFRETEESPECIAL
                                 ,gvet_regitenscesta(i).vlcustofin
                                 ,gvet_regitenscesta(i).vlcustoreal
                                 ,gvet_regitenscesta(i).perdesccusto
                                 ,gvet_regitenscesta(i).codicmtab
                                 ,vbcodicmtabpf
                                 ,gvet_regitenscesta(i).codicmtabpf
                                 ,p_regpedido.percvenda
                                 ,gvet_regitenscesta(i).pvenda
                                 ,0
                                 ,gvet_regitenscesta(i).ST
                                 ,0
                                 ,0
                                 ,p_regcliente.contribuinte
                                 , 0
                                 , 0--nvl(gvet_Regitem(j).VLREDPVENDASIMPLESNA,0)
                                 , p_regcliente.consumidorfinal
                                 , nvl(gregpcconsum.consideraisentoscomopf,'N')
                                 ,gvet_regitenscesta(i).perfretecmv
                                 ,gvet_regitenscesta(i).CUSTOFINEST
                                 ,gvet_regitenscesta(i).txvenda
                                 ,gvet_regitenscesta(i).perdesccusto
                                 ,gvet_regitenscesta(i).CODICMTAB
                                 ,gvet_regitenscesta(i).VLCUSTOREAL
                                 ,gvet_regitenscesta(i).VLCUSTOFIN
                                 ,gvet_regitenscesta(i).VLDESCCUSTOCMV
                                 ,p_regpedido.codcli                      -- HIS.02787.2016
                                 ,0 -- p_custoprecific                    -- HIS.02787.2016
                                 ,gvet_regitenscesta(i).codprodcesta      -- HIS.02787.2016
                                 ,p_regpedido.codfilial                   -- HIS.02787.2016
                                 ,gvet_regitenscesta(i).QT                -- HIS.02787.2016
                                 ,gvet_regitenscesta(i).codicmtabinternac -- HIS.02787.2016
                                 ,gvet_regitenscesta(i).PRODIMPORTADOPEPS -- HIS.02787.2016
                                 ,gvet_regitenscesta(i).NUMTRANSENTPEPS   -- HIS.02787.2016
                                 ,vvMsgErroCalcularCMV                    -- HIS.02787.2016
                                 );

         vnperdesc := ((gvet_regitenscesta(i).ptabela - gvet_regitenscesta(i).pvenda) / gvet_regitenscesta(i).ptabela) * 100;
         vnperdesc := ROUND(vnperdesc, gregpcconsum.numcasasdecvenda);

         -- 4493.064633.2016 - Tratamento de Erro por Divisão por Zero
         BEGIN
           vnperluc := ((gvet_regitenscesta(i).pvenda - gvet_regitenscesta(i).vlcustofin) / gvet_regitenscesta(i).pvenda) * 100;
         EXCEPTION
           WHEN ZERO_DIVIDE THEN
             vnperluc := 0;
         END;

              -- busca percentual de comissao
        vsmensagem_comiss := null;


              select count(*)
              into vicont
              from pctabcomiss p;

              if vicont <> 0 then
                vbUsaPcTabComiss := true;
              else
                vbUsaPcTabComiss := false;
              end if;

              select count(*)
              into vicont
              from pccomissaousur p;

              if vicont <> 0 then
                vbUsaPcComissaoUsur := true;
              else
                vbUsaPcComissaoUsur := false;
              end if;


              select count(*)
              into vicont
              from pccomissaoplpag p;

              if vicont <> 0 then
                vbUsaPcComissaoplpag := true;
              else
                vbUsaPCComissaoPlPag := false;
              end if;


              select count(*)
              into vicont
              from pccomissaoregiao p;

              if vicont <> 0 then
                vbUsaPcComissaoregiao := true;
              else
                vbUsaPcComissaoregiao := false;
              end if;

              if p_regfilial.broker = 'S' then
                 vbUsaPCComissaofilial := true;
              else
                 vbUsaPCComissaofilial := false;
              end if;

             --****************************************
             -- Comissão Integradora OL [HIS.00490.2014]
             --****************************************
              if nvl(upper(p_regpedido.usacomissaointegradora),'N') = 'S' then

                 -- Comissão cadastrada na rotina 2302
                 gvet_regitenscesta(i).percom := p_regpedido.percom;

              else

                --***********************************
                -- COMISSÃO: PEDIDO FV QUE USA PROMOÇÃO
                --************************************
                IF ((NVL(p_regpedido.TIPOFV,'FV')      = 'F') AND
                    (NVL(p_regpedido.codpromocaomed,0) > 0))  THEN

                  -- ITENS CESTA não tem Comissão cadastrada na rotina 2323
                  vnpercom := 0;

                --**********************
                -- COMISSÃO: DEMAIS CASOS
                --**********************
                ELSE

                  begin

                  gvet_regitenscesta(i).percom := FUNCOESVENDAS.Definir_Comissao_Item_Vendido
                                     (p_regregiao.numregiao,
                                      vnperluc,
                                      vnperdesc,
                                      vbUsaPcTabComiss,
                                      vbUsaPcComissaoUsur,
                                      vbUsaPCComissaoPlPag,
                                      vbUsaPCComissaoRegiao,
                                      vbUsaPCComissaofilial,
                                      gregpcconsum.usacomissaoporrca,
                                      gregpcconsum.OrdemAvaliacaoComissaoRCA,
                                      gregpcconsum.usacomissaoporcliente,
                                      gregpcconsum.USACOMISSAOPORLINHAPROD,
                                      gregpcconsum.comissaorcatipovenda,
                                      p_regrca.tipovend,
                                      p_regrca.percent,
                                      p_regrca.percent2,
                                      gvet_regitenscesta(i).codprodmp,
                                      gvet_regitenscesta(i).pcomint1,
                                      gvet_regitenscesta(i).PCOMEXT1,
                                      gvet_regitenscesta(i).PCOMREP1,
                                      gvet_regitenscesta(i).codlinhaprod,
                                      gvet_regitenscesta(i).tipocomissao,
                                      gvet_regitenscesta(i).codepto,
                                      gvet_regitenscesta(i).codsec,
                                      gvet_regitenscesta(i).classe,
                                      p_regitem.tipovenda,
                                      p_regitem.codplpag,
                                      p_regpedido.data,
                                      p_regpedido.codfilial,
                                      p_regpedido.codusur,
                                      p_regfilial.considerarcomissaozero,
                                      p_regfilial.tipoavaliacaocomissao,
                                      p_regcliente.percomcli,
                                      p_regcliente.codcli,
                                      null,
                                      vncodcomis,
                                      vscodrotinacomis,
                                      vsLetraComiss,
                                      vsmensagem_comiss,
                                      gvet_regitenscesta(i).codauxiliar ,
                                      null ,--regprecos.pcomint1_emb,
                                      null ,--regprecos.PCOMEXT1_emb,
                                      null ,--regprecos.PCOMREP1_emb,
                                      p_regfilial.utilizavendaporembalagem);
                               exception when others then
                                 proc_registralog(p_regpedido.numped,
                                     p_regpedido.numpedrca,
                                     p_regitem.codprod,
                                     p_regitem.codauxiliar,
                                     null,
                                     null,
                                     null,
                                     null,
                                     p_regpedido.codusur,
                                     p_regpedido.dtaberturapedpalm,
                                     null,
                                     '3',
                                     vsmensagem_comiss,
                                     null);
                            end ;

                END IF; -- FIM CONDIÇÃO COMISSÃO: PEDIDO FV QUE USA PROMOÇÃO

              end if; -- Fim Condição Se Comissão Integradora OL

                     if nvl(gregpcconsum.incluircomissaocmvvenda,'S') = 'N' then
                          vnpercom := 0;
                     else
                         vnpercom := gvet_regitenscesta(i).percom;
                     end if;

                     -- HIS.03249.2016 - Tipos de Venda que não têm Comissão
                     IF (p_regpedido.condvenda IN (4, 5, 8, 9, 10, 13, 11, 20)) THEN
                       vnpercom := 0;
                     END IF;


          -- HIS.02787.2016 -- comentado
          p_calcularcmv_med(p_regfilial.tributsaidaorigemnacimp -- HIS.02787.2016
                                 ,gregpcconsum.abaterimpostoscomissaorca
                                 ,gregpcconsum.aplicarindicecmv
                                 ,gregpcconsum.Incluircomissaosugpvendacmv
                                 ,nvl(gregpcconsum.txvenda, 0)
                                 ,p_regcliente.tipofj
                                 ,p_regcliente.utilizaiesimplificada
                                 ,p_regcliente.ieent
                                 ,gvet_regitenscesta(i).freteespecial
                                 ,p_regregiao.PERFRETETERCEIROS
                                 ,p_regregiao.PERFRETEESPECIAL
                                 ,gvet_regitenscesta(i).vlcustofin
                                 ,gvet_regitenscesta(i).vlcustoreal
                                 ,gvet_regitenscesta(i).perdesccusto
                                 ,gvet_regitenscesta(i).codicmtab
                                 ,vbcodicmtabpf
                                 ,gvet_regitenscesta(i).codicmtabpf
                                 ,p_regpedido.percvenda
                                 ,gvet_regitenscesta(i).pvenda
                                 ,vnPERCOM
                                 ,gvet_regitenscesta(i).ST
                                 ,0
                                 ,0
                                 ,p_regcliente.contribuinte
                                 , 0
                                 , 0--nvl(gvet_Regitem(j).VLREDPVENDASIMPLESNA,0)
                                 , p_regcliente.consumidorfinal
                                 , nvl(gregpcconsum.consideraisentoscomopf,'N')
                                 ,gvet_regitenscesta(i).perfretecmv
                                 ,gvet_regitenscesta(i).CUSTOFINEST
                                 ,gvet_regitenscesta(i).txvenda
                                 ,gvet_regitenscesta(i).perdesccusto
                                 ,gvet_regitenscesta(i).CODICMTAB
                                 ,gvet_regitenscesta(i).VLCUSTOREAL
                                 ,gvet_regitenscesta(i).VLCUSTOFIN
                                 ,gvet_regitenscesta(i).VLDESCCUSTOCMV
                                 ,p_regpedido.codcli                      -- HIS.02787.2016
                                 ,0 -- p_custoprecific                    -- HIS.02787.2016
                                 ,gvet_regitenscesta(i).codprodcesta      -- HIS.02787.2016
                                 ,p_regpedido.codfilial                   -- HIS.02787.2016
                                 ,gvet_regitenscesta(i).QT                -- HIS.02787.2016
                                 ,gvet_regitenscesta(i).codicmtabinternac -- HIS.02787.2016
                                 ,gvet_regitenscesta(i).PRODIMPORTADOPEPS -- HIS.02787.2016
                                 ,gvet_regitenscesta(i).NUMTRANSENTPEPS   -- HIS.02787.2016
                                 ,vvMsgErroCalcularCMV                    -- HIS.02787.2016
                                 );


     if p_regpedido.orcamento = 'S' then

             insert into pcorcavendaicesta
                (
                numorca,
                codprod,
                numseq,
                codauxiliar,
                codprodmp,
                qtmp,
                pvenda,
                ptabela,
                pbaserca,
                baseicst,
                st,
                stclientegnre,
                percipi,
                vlipi,
                perciss,
                vliss,
                vldescsuframa,
                vlcustofin,
                vlcustoreal,
                vlcustorep,
                vlcustocont,
                vldesccustocmv,
                codst,
                percom,
                perdesctab,
                iva ,
                aliqicms1,
                aliqicms2,
                pauta,
                percbasered,
                custofinest,
                percbaseredstfonte,
                percbaseredst,
                perdesccusto,
                codicmtab,
                txvenda,
                perfretecmv
                )

        values (  p_regpedido.numped,
                  p_regitem.codprod,
                  p_regitem.numseq,
                  gvet_regitenscesta(i).codauxiliar,
                  gvet_regitenscesta(i).codprodmp,
                  gvet_regitenscesta(i).qt,
                  gvet_regitenscesta(i).pvenda,
                  gvet_regitenscesta(i).ptabela,
                  gvet_regitenscesta(i).ptabela,
                  gvet_regitenscesta(i).baseicst,
                  gvet_regitenscesta(i).st,
                  null,--gvet_regitenscesta(i).stclientegnre,
                  null,--gvet_regitenscesta(i).percipi,
                  null,--gvet_regitenscesta(i).vlipi,
                  null,--gvet_regitenscesta(i).perciss,
                  null,--gvet_regitenscesta(i).vliss,
                  null,--gvet_regitenscesta(i).vldescsuframa,
                  gvet_regitenscesta(i).vlcustofin,
                  gvet_regitenscesta(i).vlcustoreal,
                  gvet_regitenscesta(i).custorep,
                  gvet_regitenscesta(i).custocont,
                  gvet_regitenscesta(i).vldesccustocmv,
                  gvet_regitenscesta(i).codst,
                  gvet_regitenscesta(i).percom,
                  null,--gvet_regitenscesta(i).perdesctab,
                  gvet_regitenscesta(i).iva ,
                  gvet_regitenscesta(i).aliqicms1,
                  gvet_regitenscesta(i).aliqicms2,
                  gvet_regitenscesta(i).pauta,
                  gvet_regitenscesta(i).percbasered,
                  gvet_regitenscesta(i).custofinest,
                  gvet_regitenscesta(i).percbaseredstfonte,
                  gvet_regitenscesta(i).percbaseredst,
                  gvet_regitenscesta(i).perdesccusto,
                  gvet_regitenscesta(i).codicmtab,
                  gvet_regitenscesta(i).txvenda,
                  gvet_regitenscesta(i).perfretecmv
                  );


     else

        insert into pcpedicesta
          (numped,
           codprod,
           numseq,
           codprodmp,
           qtmp,
           pvenda,
           ptabela,
           pbaserca,
           st,
           vlcustofin,
           vlcustoreal,
           percom,
           baseicst,
           aliqicms1,
           aliqicms2,
           percbaseredst,
           iva,
           pauta,
           percbaseredstfonte,
           percbasered,
           codst,
           vlcustorep,
           vlcustocont,
           custofinest,
           perdesccusto,
           codicmtab,
           perfretecmv,
           txvenda,
           vldesccustocmv,
           codauxiliar)
        values
          (p_regpedido.numped,
           p_regitem.codprod,
           p_regitem.numseq,
           gvet_regitenscesta(i).codprodmp,
           gvet_regitenscesta(i).qt,
           gvet_regitenscesta(i).pvenda,
           gvet_regitenscesta(i).ptabela,
           gvet_regitenscesta(i).ptabela,
           gvet_regitenscesta(i).st,
           gvet_regitenscesta(i).vlcustofin,
           gvet_regitenscesta(i).vlcustoreal,
           gvet_regitenscesta(i).percom,
           gvet_regitenscesta(i).baseicst,
           gvet_regitenscesta(i).aliqicms1,
           gvet_regitenscesta(i).aliqicms2,
           gvet_regitenscesta(i).percbaseredst,
           gvet_regitenscesta(i).iva,
           gvet_regitenscesta(i).pauta,
           gvet_regitenscesta(i).percbaseredstfonte,
           gvet_regitenscesta(i).percbasered,
           gvet_regitenscesta(i).codst,
           gvet_regitenscesta(i).custorep,
           gvet_regitenscesta(i).custocont,
           gvet_regitenscesta(i).custofinest,
           gvet_regitenscesta(i).perdesccusto,
           gvet_regitenscesta(i).codicmtab,
           gvet_regitenscesta(i).perfretecmv,
           gvet_regitenscesta(i).txvenda,
           gvet_regitenscesta(i).vldesccustocmv,
           gvet_regitenscesta(i).codauxiliar
           );

       end if;
      end if;
    end loop;


    return true;
  exception
    when others then
        proc_registralog(p_regpedido.numped,
                         p_regpedido.numpedrca,
                         p_regitem.codprod,
                         p_regitem.codauxiliar,
                         null,
                         null,
                         null,
                         null,
                         p_regpedido.codusur,
                         p_regpedido.dtaberturapedpalm,
                         null,
                         '3',
                         'Problemas na gravacao o item de cesta ' || sqlcode || '-' ||
                          DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM || ';' ,
                          null);


      return false;
  end func_inseriritemcesta;
*/



  function func_inseriritempedido(p_regpedido      in t_cabped,
                                  p_regitem        in out t_itemped,
                                  p_regprecos      in t_precosetributacao,
                                  p_regproduto     in t_produto,
                                  p_regorigempreco in t_origempreco,
                                  p_regorigemcomiss in t_origemcomiss,
                                  p_regorigemdesc   in t_origemdesc,
                                  p_regrca         in t_rca,
                                  p_regcliente     in t_clientepedido,
                                  p_regfilial      in t_filial,
                                  p_Regregiao      in t_regiaocliente)

    return boolean is

    vbvalido   boolean;

  vnvlcustofin      pcpedi.vlcustofin%type;
  vnvlcustoreal     pcpedi.vlcustoreal%type;
  vnvlcustorep      pcpedi.vlcustorep%type;
  vncustofinest     pcpedi.custofinest%type;
  vnvlcustocont     pcpedi.vlcustocont%type;
  vnpercom          pcpedi.percom%type;

  -- RCA por Linha de Prazo - 4415.012539.2017
  vnCodUsurItem     pcpedi.codusur%type;
  vPRIORIZARCAINTEGRADORARCALIN VARCHAR2(200);
  
  -- DDMEDICA-4177
  vnPBonific        pcpedi.pbonific%type;

  begin

    if (nvl(p_regpedido.tipofv,' ') not in ('OL','PE')) then
      -- Se chegou aqui sem Gravar o Campo
      IF (p_Regitem.tipocomissaomed IS NULL) THEN
        p_Regitem.tipocomissaomed := 'F';
      END IF;
    end if;



    -- 4415.012539.2017 - RCA por Linha de Prazo
    vnCodUsurItem := p_regpedido.codusur;
    IF (NVL(p_regitem.codusurLinhaPrazo,0) > 0) THEN
      vnCodUsurItem := p_regitem.codusurLinhaPrazo;
    -- DDMEDICA-1835 - RCA por Linha de Produto
    ELSIF (NVL(p_regitem.codusurlinha,0) > 0) THEN
      -- Se E-Commerce - DDMEDICA-4240
      IF (NVL(p_regpedido.origemped,'F') = 'W') THEN
        vnCodUsurItem := p_regitem.codusurlinha;
      -- Se não for E-Commerce
      ELSE
        -- Não pode ser um RCA que veio no Pedido
        IF (NVL(INTEGRADORACOMPLE_MED.F_RCA_PREPOSTO(p_regpedido.codusur,
                                                     p_regpedido.codvendedorpedol),'N') <> 'S') THEN
          -- Verifica Parâmetro Específico para Manter o RCA da Integradora
          vPRIORIZARCAINTEGRADORARCALIN := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                                    'PRIORIZARCAINTEGRADORARCALINHA',
                                                                    'N');
          IF (NVL(vPRIORIZARCAINTEGRADORARCALIN,'N') <> 'S') THEN
            vnCodUsurItem := p_regitem.codusurlinha;
          END IF;
        END IF;
      END IF;
    END IF;

    -- DDMEDICA-4177
    vnPBonific := NULL;
    IF (p_Regitem.bonific = 'F') THEN
      vnPBonific := p_regitem.pvenda;
    END IF;

    -- Plano Pagamento da Linha de Prazo - DDMEDICA-7182
    IF (p_regfilial.tipoprazomedicam = '4') AND 
       (p_regitem.codplpagLinhaPrazo IS NULL) THEN
      p_regitem.codplpagLinhaPrazo := p_regpedido.codplpag;
    END IF;
    p_Regitem.codlinhaprazo := p_regproduto.codlinhaprazo;

    insert into pcpedi
      (codcli,        --1
       codicmtab,     --2
       codprod,       --3
       codst,         --4
       codusur,       --5
       DATA,          --6
       numped,        --7
