       fabricante,         -- HIS.03377.2017
       percacrescoperlog,  -- HIS.00262.2018
       vlacrescoperlog,    -- HIS.00262.2018
       VLBASEFCPICMS,      -- HIS.04200.2017
       VLBASEFCPST,        -- HIS.04200.2017
       VLBCFCPSTRET,       -- HIS.04200.2017
