       PERACRESCIMOFUNCEP, -- HIS.04200.2017
       ALIQICMSFECP,       -- HIS.04200.2017
       VLCREDFCPICMSSN,    -- HIS.04200.2017
       CODCONFIGFUNCEPMED,
       GRUPOFATURAMENTO,   -- MED-1499
       vlverbacmvcli,      -- MED-1822
       PERREDCOMISS,       -- DDMEDICA-1460
       NUMLOTEPROMOCAOMED,
       codmotivoposicaomed,
       motivoposicaomed, 
       bonific,            -- DDMEDICA-4177
       pbonific,           -- DDMEDICA-4177       
       NUMVERBACAMPANHA,    -- DDMEDICA-5009
       VLDESCCMVPROMOCAOMED,-- DDMEDICA-5009
       PERCCUSTFORNEC,      -- DDMEDICA-5009
       classevenda,         -- DDMEDICA-5086       
       bcstretanterior,          -- DDMEDICA-7697
       vlicmssubstitutoanterior, -- DDMEDICA-7697
       vlicmsstretanterior,      -- DDMEDICA-7697
       pmpfmedicamento,           -- DDMEDICA-7697
       usacashback,            -- DDVENDAS-35840
       numitemped -- DDVENDAS-44985
       )
    values
      (p_regpedido.codcli,       --1
       p_regitem.codicmtab,    --2
       p_regitem.codprod,        --3
       p_regprecos.codst,        --4
       --p_regpedido.codusur,    --5
       vnCodUsurItem,            --5 -->>> *** ATENÇÃO ESPECIAL - RCA DA LINHA DE PRAZO OU DO PEDIDO - 4415.012539.2017 ***
       p_regpedido.data,         --6
       p_regpedido.numped,       --7
       p_regitem.numseq,         --8
       NVL(p_regitem.percom,0),  --9
       p_regitem.perdesc,        --10
       p_regpedido.posicao,      --11
       p_regproduto.ptabela,     --12
       p_regitem.pvenda,         --13
       p_regitem.qt,             --14
       0,                        --15
       p_regitem.st,             --16
       p_regitem.stclientegnre,  --17
       p_regPRECOS.custocont,    --18
       decode(p_regpedido.condvenda,
              4,
              0,
              decode(p_regfilial.tipobroker,
                     'MAB',
                     nvl(p_regprecos.precofab,p_regitem.vlcustofin),
                     p_regitem.vlcustofin)),  --19
       decode(p_regpedido.condvenda,
              4,
              0,
              decode(p_regfilial.tipobroker,
                     'MAB',
                     nvl(p_regprecos.precofab,p_regitem.vlcustoreal),
                     p_regitem.vlcustoreal)),    --20
       p_regprecos.custorep,     --21
       p_regitem.pbaserca,       --22
       p_regitem.pvendabase,     --23
       p_regitem.iva,            --24
       p_regitem.pauta,          --25
       p_regitem.aliqicms1,      --26
       p_regitem.aliqicms2,      --27
       p_regitem.percbaseredst,  --28
       p_regitem.percbaseredstfonte, --29
       p_regitem.baseicst,           --30
       p_regitem.perfretecmv,        --31
       p_regitem.custofinest,        --32
       p_regitem.txvenda,            --33
       p_regitem.perdesccusto,       --34
       p_regitem.vldesccustocmv,     --35
       p_regitem.letracomiss,        --36
       p_regitem.vlipi,              --37
       p_regitem.percipi,            --38
       p_regitem.vldescsuframa,      --39
       p_regitem.vldescicmisencao,   --40
       p_regitem.perdescisentoicms,  --41
       p_regitem.vlverbacmv,         --42
       p_regitem.pvenda1,            --43
       p_regitem.percdescpis,        --44
       p_regitem.percdesccofins,     --45
       p_regitem.vldescreducaopis,   --46
       p_regitem.vldescreducaocofins, --47
       p_regitem.codauxiliar,          --48
       p_Regitem.qtpecas,              --49
       p_regitem.qtcx,                  --50
       p_Regitem.vlrepasse,           --51
       p_regitem.vlbonific,            --52
       p_regitem.perbonific,          --53
       p_regitem.vloutros,              --54
       p_regitem.perdesccom,            --55
       p_regitem.vldesccom ,             --56
       p_regprecos.qtunit,               --57
       p_regitem.vlredpvendasimplesna,    --58
       p_Regitem.vlredcmvsimplesnac,       --59
       p_regitem.codfilialretira,            --60
       p_regitem.poriginal,                 --61
