       p_regitem.st,                                -- 81 -->> DDMEDICA-7609
       p_regitem.st,                                -- 82 -->> DDMEDICA-7609
       -- INICIO: HIS.04557.2015 - ICMS Partilha
       p_regitem.vlbasepartdest, --83
       p_regitem.aliqfcp, --84
