       -- FIM: HIS.04557.2015 - ICMS Partilha
       p_regitem.CODDESCONTO,
       p_regitem.percdescbaserca,
       p_Regitem.tipocomissaomed,
       -- Grava CODFISCAL e CST - HIS.03261.2016
       p_Regitem.codfiscal,
       p_Regitem.sittribut,
       p_Regitem.prodimportadopeps,  -- HIS.02787.2016
       p_Regitem.numtransentpeps,    -- HIS.02787.2016
       p_Regitem.codlinhaprazo,      -- 4415.012539.2017
       p_Regitem.codplpagLinhaPrazo, -- 4415.012539.2017
       p_regitem.codacordosistoperlog,
       p_Regitem.observacaostfonte,  -- HIS.03377.2017
       p_Regitem.indescalarelevante, -- HIS.03377.2017
       p_Regitem.cnpjfabricante,     -- HIS.03377.2017
       p_Regitem.fabricante,         -- HIS.03377.2017
       p_Regitem.percacrescoperlog,  -- HIS.00262.2018
       p_Regitem.vlacrescoperlog,    -- HIS.00262.2018
       p_Regitem.VLBASEFCPICMS,      -- HIS.04200.2017
       p_Regitem.VLBASEFCPST,        -- HIS.04200.2017
       p_Regitem.VLBCFCPSTRET,       -- HIS.04200.2017
       p_Regitem.PERFCPSTRET,        -- HIS.04200.2017
       p_Regitem.VLFCPSTRET,         -- HIS.04200.2017
