       p_regitem.USACASHBACK, -- DDVENDAS-35840
       p_regitem.numitemped -- DDVENDAS-44985
       );

    -- Se Compra de Operador Logístico para Transferência atualizada a Quantidade Atendida na Importação
    if ((p_regpedido.integradora > 0) and
        (p_regpedido.layout = 1) and -- Pharmalink
        (p_regpedido.condvenda = 10)) then
      BEGIN
        UPDATE PCPEDCOMPRAOPERLOGITE
           SET PCPEDCOMPRAOPERLOGITE.QTATEND = p_regitem.qt
         WHERE (PCPEDCOMPRAOPERLOGITE.NUMPED  = TO_NUMBER(TRIM(p_regpedido.numpedcli)))
           AND (PCPEDCOMPRAOPERLOGITE.CODPROD = p_regitem.codprod);
      EXCEPTION
        WHEN OTHERS THEN
          NULL;
      END;
    end if;

    -- DDMEDICA-198 - Atualiza o NUMSEQ gerado na PCPEDI para o registro da PCPEDIFV
    UPDATE PCPEDIFV
       SET NUMSEQITEMPEDMED = p_regitem.numseq -->> NUMSEQ DA PCPEDI
     WHERE (PCPEDIFV.NUMPEDRCA         = p_regitem.numpedrca)
       AND (PCPEDIFV.CGCCLI            = p_regitem.cgccli)
       AND (PCPEDIFV.CODUSUR           = p_regitem.codusur)
       AND (PCPEDIFV.DTABERTURAPEDPALM = p_regitem.dtaberturapedpalm)
       AND (PCPEDIFV.CODPROD           = p_regitem.codprod)
       AND (PCPEDIFV.NUMSEQ            = p_regitem.numseqifv); -->> NUMSEQ DA PCPEDIFV

    begin

      insert into pcorigempreco
