         dtaberturapedpalm, --53
         dtfechamentopedpalm, --54
         numregiao,           --55
         usaintegracaowms,    --56
         usacredrca,          --57
         usadebcredrca,       --58
         bonificaltdebcredrca, --59
         trocaaltdebcredrca,   --60
         crmaltdebcredrca,     --61
         brokeraltdebcredrca,  --62
         tipomovccrca,          --63
         vlfrete,              --64
         codfornecfrete,       --65
