         codbnf,                        --85
         custobonificacao,              --86
         codfornecbonific ,              --87
         vlentrada,                       --88
         numpedvanxml,                     --89
         codendentcli ,                     --90
         codclirecebedor,                     --91
         codestabelecimento,                 --92
         numtabela,                           --93
         codmotbloqueio ,                      --94
