         codusur3,                              --98
         codusur4,                              --99
         codacordoparceria,                     -- 100
         geracp,                                -- 101
         codpromocaomed,                        -- 102
         vlfreteoutrasdesp                      -- 103
        ,descintermediador                      -- 104 - DDMEDICA-6201  
        ,cnpjintermediador                      -- 105 - DDMEDICA-6201  
         )
      values
        (p_regpedido.codcli,    --1
         p_regpedido.codcob,    --2
         p_regrca.coddistrib,   --3
         p_regpedido.codemitente, --4
         p_regpedido.codfilial, --5
         p_regpedido.codfilialnf, --6
         p_regpedido.codplpag,   --7
         p_regcliente.codpraca,  --8
         p_regrca.codsupervisor,  --9
         p_regrca.codusur,        --10
         p_regpedido.condvenda,   --11
         p_regpedido.data,         --12
         NVL(p_regpedido.dtentrega, p_regpedido.data), -- 13
         TO_NUMBER(TO_CHAR(sysdate, 'HH24')), --14
         TO_NUMBER(TO_CHAR(sysdate, 'MI')),    --15
         0,                                    --16
         p_contitensvalidos,                   --17
         p_regpedido.numped,                   --18
         TRIM(p_regpedido.numpedcli),          --19
         p_regpedido.numpedrca,                --20
         p_regpedido.obs1,                     --21
         p_regpedido.obs2,                     --22
         p_regpedido.obsentrega1,              --23
         p_regpedido.obsentrega2,              --24
         'N',                                  --25
         p_regpedido.origemped,                --26
         p_regpedido.percvenda,                --27
         vnperdescped,                         --28
         p_regpedido.posicao,                  --29
         p_regplpag.prazo1,                    --30
         p_regplpag.prazo2,                    --31
         p_regplpag.prazo3,                    --32
         p_regplpag.prazo4,                    --33
         p_regplpag.prazo5,                    --34
         p_regplpag.prazo6,                    --35
         p_regplpag.prazo7,                    --36
         p_regplpag.prazo8,                    --37
