         p_regplpag.tipovenda,                 --43
         p_totpesoped,                         --44
         p_totvolumeped,                       --45
         decode(p_regpedido.condvenda,
                5,
                0,
                decode(p_regpedido.condvenda,20,0,
                p_vltotped)),                   --46
         p_vlcustocontped,                     --47
         decode(p_regpedido.condvenda,20,0,p_vlcustofinped),                      --48
         decode(p_regpedido.condvenda,20,0,p_vlcustorealped),                     --49
         decode(p_regpedido.condvenda,20,0,p_vlcustorepped),                      --50
         decode(p_regpedido.condvenda,20,0,p_vltottab),                           --51
         p_vltotped,                           --52
         p_regpedido.dtaberturapedpalm,        --53
         p_regpedido.dtfechamentopedpalm,      --54
         p_regregiao.numregiao,                --55
         p_regfilial.usaintegracaowms,         --56
         p_regpedido.usacredrca,               --57
         p_regpedido.usadebcredrca,            --58
         p_regpedido.bonificaltdebcredrca,     --59
         p_regpedido.trocaaltdebcredrca,       --60
