         p_Regpedido.brokeraltdebcredrca,      --62
         p_Regpedido.tipomovccrca,              --63
         p_regpedido.vlfrete,              --64
         p_regpedido.codfornecfrete,       --65
         nvl(p_regpedido.fretedespacho,p_regcliente.fretedespacho),        --66
         p_regpedido.freteredespacho,       --67
         P_REGFILIAL.broker,                 --68
         p_regpedido.tipodocumento,           --69
         p_regpedido.codclinf,                --70
         p_regpedido.contaordem,               --71
         p_regpedido.codmotivo,                --72
         p_Regpedido.motivoposicao,            --73
         p_regpedido.log,                       --74
         p_regpedido.codclitv8,                  --75
         p_regpedido.codplpagetico,              --76
         p_regpedido.codplpaggenerico,            --77
         p_regpedido.codcondicaovenda,             --78
         p_regpedido.tipofv ,                       --79
         p_regpedido.tipoprioridadeentrega,          --80
         p_Regpedido.localdesembaraco,               --81
         p_regpedido.ufdesembaraco,                   --82
         p_regpedido.numpedtv1,                        --83
         p_regpedido.agrupamento ,                     --84
         p_regpedido.codbnf,                        --85
         p_regpedido.custobonificacao,              --86
         p_regpedido.codfornecbonific ,              --87
         p_regpedido.vlentrada ,                      --88
         SUBSTR(TRIM(p_regpedido.numpedvanxml),1,15),  --89 --DDMEDICA-5411
         p_regpedido.codendentcli,                     --90
         p_regpedido.codclirecebedor,                   --91
         p_regregiao.codestabelecimento,                  --92
         p_regpedido.numtabela ,                           --93
         NULL, --MED-2161--p_regpedido.codmotiv              --94
         p_regfilial.utilizavendaporembalagem,               --95
         p_regpedido.codusur2,                              --97
         p_regpedido.codusur3,                              --98
         p_regpedido.codusur4,                              --99
         p_regpedido.codacordoparceria,                     -- 100
         nvl(p_regpedido.geracp,'N'),                       -- 101
         p_regpedido.codpromocaomed,                        -- 102
         p_regpedido.vlfreteoutrasdesp                      -- 103
        ,gregpedido.descintermediador                       -- 104 - DDMEDICA-6201  
        ,gregpedido.cnpjintermediador                       -- 105 - DDMEDICA-6201  
         );

        if p_regpedido.condvenda = 13 and p_Regpedido.codcli in (1,2,3) --clientes consumidor final
        then

          insert into pcvendaconsum
          (numped,
           cliente,
           cgcent,
           enderent,
           municent,
           estent,
           cepent,
           ieent)
        values
          (p_regpedido.numped,
           p_regcliente.cliente,
           p_regcliente.cgcent,
           p_regcliente.enderent,
           p_regcliente.municent,
           p_regcliente.estent,
           p_regcliente.cepent,
           p_regcliente.ieent);

        end if;


    else

      select sum(NVL(pcpedi.pvenda, 0) * NVL(pcpedi.qt, 0)), --1
             sum(NVL(pcpedi.ptabela, 0) * NVL(pcpedi.qt, 0)), --2
             count(*),                                        --3
             sum((NVL(pcpedi.qt, 0) + NVL(pcpedi.qtfalta, 0)) *
                 NVL(pcpedi.pvenda, 0)),                       --4
             sum(NVL(pcpedi.vlcustofin, 0) * NVL(pcpedi.qt, 0)), --5
             sum(NVL(pcpedi.vlcustorep, 0) * NVL(pcpedi.qt, 0)),  --6
             sum(NVL(pcpedi.vlcustoreal, 0) * NVL(pcpedi.qt, 0)),  --7
             sum(NVL(pcpedi.vlcustocont, 0) * NVL(pcpedi.qt, 0)),  --8
             sum(NVL(pcprodut.pesobruto, 0) * NVL(pcpedi.qt, 0)),    --9
             sum(NVL(pcprodut.volume, 0) * NVL(pcpedi.qt, 0))     --10
        into at_vlatend, --1
             at_vltabela, --2
             at_numitens, --3
             at_vltotal,  --4
             at_vlcustofin, --5
             at_vlcustorep, --6
             at_vlcustoreal, --7
             at_vlcustocont,  --8
             at_totpeso,    --9
             at_totvolume   --10
        from pcpedi, pcprodut
       where pcpedi.numped = p_regpedido.numped
         and pcpedi.codprod = pcprodut.codprod;
         
      update pcpedc
         set vlatend     = decode(p_regpedido.condvenda,5,0,decode(p_regpedido.condvenda,20,0,at_vlatend)),
             vltabela    = decode(p_regpedido.condvenda,20,0,at_vltabela),
             numitens    = at_numitens,
             vltotal     = at_vltotal,
             vlcustofin  = decode(p_regpedido.condvenda,20,0,at_vlcustofin),
             vlcustorep  = decode(p_regpedido.condvenda,20,0,at_vlcustorep),
             vlcustoreal = decode(p_regpedido.condvenda,20,0,at_vlcustoreal),
             vlcustocont = at_vlcustocont,
             totpeso     = at_totpeso,
             totvolume   = at_totvolume
       where numped = p_regpedido.numped;
       
    end if;

    -- DDMEDICA-6036 - Garantir o CODDISTRIB do Produto que ficou no Pedido
    INTEGRADORACOMPLE_MED.P_ATU_DISTRIB_PEDIDO_INICIAL(p_regpedido.numped,
                                                       P_REGFILIAL.MEDPERMITEDISTRIBDIFRCA);

--tarefa 160801
    update pcclient p
    set p.dtultcomp = trunc(sysdate)
    where codcli = p_regpedido.codcli;

    -- Se Compra de Operador Logístico para Transferência atualiza Situação para Importado
    if ((p_regpedido.integradora > 0) and
        (p_regpedido.layout = 1) and -- Pharmalink
        (p_regpedido.condvenda = 10)) then
      BEGIN
        UPDATE PCPEDCOMPRAOPERLOGCAB
           SET PCPEDCOMPRAOPERLOGCAB.SITUACAO = 'I'
         WHERE (PCPEDCOMPRAOPERLOGCAB.NUMPED = TO_NUMBER(TRIM(p_regpedido.numpedcli)));
      EXCEPTION
        WHEN OTHERS THEN
          NULL;
      END;
    end if;

    -- HIS.01025.2015 - Separar Origem - FocoPDV
    IF (gregpedido.integracaopedoperlog       = 'S') AND
       (gregpedido.tipodeforigempedidooperlog = '2') THEN
      -- Redefine Origem Pedido
      vvOrigemPed := NULL;
      vvTipoFv    := NULL;
      IF    (gregpedido.origempedidooperlog = 'T') THEN
        vvOrigemPed := 'T';
      ELSIF (gregpedido.origempedidooperlog = 'F') THEN
        vvOrigemPed := 'F';
      ELSIF (gregpedido.origempedidooperlog = 'W') THEN
        vvOrigemPed := 'W';
      ELSIF (gregpedido.origempedidooperlog = 'E') THEN
        vvOrigemPed := 'F';
        vvTipoFv    := 'PE';
      END IF;
      -- Se possui uma origem válida atualiza Pedido
      IF (vvOrigemPed IS NOT NULL) THEN
        update pcpedc
           set origemped = vvOrigemPed,
               tipofv    = vvTipoFv
         where numped = p_regpedido.numped;
      END IF;
    END IF; -- FIM: HIS.01025.2015 - Separar Origem - FocoPDV

    --- MED-1600 - atualiza tabela de retorno do pedido (Preciso do NUMPED aqui para que no próximo Pedido do Laço do Array possa verificar se já está na PCPEDC)
    IF ((NVL(p_regpedido.tipofv,'FV') IN ('OL','PE')) OR
        (NVL(p_regpedido.integradora,0) > 0))         THEN
      BEGIN
        UPDATE pcpedretorno
           SET numped            = p_regpedido.numped
         WHERE numpedrca         = p_regpedido.numpedrca
           and cgccli            = p_regpedido.cgccli
           and codusur           = p_regpedido.codusur
           and dtaberturapedpalm = p_regpedido.dtaberturapedpalm;
      EXCEPTION
        WHEN OTHERS THEN
          NULL;
      END;
    END IF;

    -- Motivos do Bloqueio
    BEGIN

      IF (gvetregistrabloqueio.COUNT > 0) THEN
        FOR idxBloqueio IN gvetregistrabloqueio.FIRST..gvetregistrabloqueio.LAST LOOP

          IF (gvetregistrabloqueio(idxBloqueio).numpedrca         = gregpedido.numpedrca AND
              gvetregistrabloqueio(idxBloqueio).codusur           = gregpedido.codusur   AND
              gvetregistrabloqueio(idxBloqueio).cgccli            = gregpedido.cgccli    AND
              gvetregistrabloqueio(idxBloqueio).dtaberturapedpalm = gregpedido.dtaberturapedpalm) THEN

            -- MED-2161 - Grava Bloqueio do Pedido
            INTEGRADORACOMPLE_MED.proc_insere_bloqueiospedido('N', -->> NÃO atualiza motivo na PCPEDC
                                                              p_regpedido.numped,
                                                              gvetregistrabloqueio(idxBloqueio).codmotivo,
                                                              gvetregistrabloqueio(idxBloqueio).codmotbloqueio,
                                                              gvetregistrabloqueio(idxBloqueio).motivo);

          END IF;

        END LOOP;
      END IF;

    EXCEPTION
      WHEN OTHERS THEN
        NULL;
    END;

    return true;

  exception
    when others then
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       null,
                       null,
                       p_Regpedido.cgccli,
                       null,
                       null,
                       null,
                       p_Regpedido.codusur,
                       p_Regpedido.dtaberturapedpalm,
                       null,
                       '2',
                       sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->007->' || SQLERRM || ';',
                       null,
                       null);
      return false;

      if p_Regpedido.codmotivonaoatend is null then
         p_regpedido.codmotivonaoatend := 4;

      end if;


  end func_inserircabpedido;

