          null,--p_regcliente.telent,                 --61
          p_regcliente.ieent,                       --62
          p_regcliente.codatv1,                  --63
          p_regcliente.municent,                   --64
          p_regpedido.codfilialnf,              --65
          (trunc(sysdate) + nvl(gregpcconsum.prazovalidadeorcamento,0)),               --66
          p_vlcustocontped,                     --67
          p_vlcustorepped ,                     --68
          p_regpedido.origemped,                 --69
          p_regregiao.numregiao,                --70
          p_regpedido.log,                      --71
          p_regfilial.usaintegracaowms,         --72
          null,                                 --73
          p_regpedido.codmotivo,                --74
          p_regfilial.broker,                   --75
          substr(p_regpedido.motivoposicao,1,50),            --76
          null,                                 --77
          p_regpedido.tipoprioridadeentrega,    --78
          p_regpedido.codplpagetico,            --79
          p_regpedido.codplpaggenerico          --80
          );




    return true;

  exception
    when others then
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       null,
                       null,
                       p_Regpedido.cgccli,
                       null,
                       null,
                       null,
                       p_Regpedido.codusur,
                       p_Regpedido.dtaberturapedpalm,
                       null,
                       '2',
                       sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->008->' || SQLERRM || ';',
                       null,
                       null);
      return false;

  end func_inserirorcamento;

  procedure proc_GravaLogConvEmbalagem(p_NUMPED in pcpedc.numped%type,
                                      p_CODFILIAL in pcpedc.codfilial%type,
                                      p_CODPROD in pcpedi.codprod%type,
                                      p_QTESTGER in pcest.qtestger%type,
                                      vbGravouLogConversaoEstoque out Boolean,
                                      p_mensagem out varchar2) is

   vnQTESTGER_DEPOIS number;
   vnNUMTRANSVENDA number;
   vnCODPROD_MASTER number;
   vnQT_MASTER number;
   vnQTESTGER_MASTER number;
   vbBuscouDadosConversao boolean;
   vicont number;
   vsprograma varchar2(80);
   vnqt number;

begin
   --Buscar dados da Conversão
   vbBuscouDadosConversao := False;
   p_mensagem := null;

   SELECT count(*)
   into vicont
     FROM PCMOV
    WHERE PCMOV.DTMOV = TRUNC (SYSDATE)
      AND PCMOV.CODPROD = p_CODPROD
      AND PCMOV.CODFILIAL = p_CODFILIAL
      AND NVL (PCMOV.CODOPER, 'X') = 'EP'
   GROUP BY PCMOV.NUMTRANSVENDA
   ORDER BY PCMOV.NUMTRANSVENDA DESC;

   if vicont is not null then

      begin
       SELECT PCMOV.NUMTRANSVENDA, SUM(PCMOV.QT) QT
       into vnNUMTRANSVENDA,vnqt
       FROM PCMOV
      WHERE PCMOV.DTMOV = TRUNC (SYSDATE)
        AND PCMOV.CODPROD = p_CODPROD
        AND PCMOV.CODFILIAL = p_CODFILIAL
        AND NVL (PCMOV.CODOPER, 'X') = 'EP'
     GROUP BY PCMOV.NUMTRANSVENDA
     ORDER BY PCMOV.NUMTRANSVENDA DESC;
     exception when others then
      vnNUMTRANSVENDA := null;
      vnqt := 0;
     end;

      vnQTESTGER_DEPOIS := p_QTESTGER + vnQT;

      if vnnumtransvenda is not null then

      SELECT count(*)
        into vicont
        FROM PCMOV, PCEST
       WHERE PCMOV.DTMOV = TRUNC (SYSDATE)
         AND PCMOV.NUMTRANSVENDA = vnNUMTRANSVENDA
         AND PCMOV.CODFILIAL = p_CODFILIAL
         AND PCMOV.CODPROD = PCEST.CODPROD
         AND PCMOV.CODFILIAL = PCEST.CODFILIAL
         AND NVL (PCMOV.CODOPER, 'X') = 'SP';

      if vicont <> 0 then

         SELECT PCMOV.CODPROD, PCMOV.QT, PCEST.QTESTGER
          into vnCODPROD_MASTER,vnQT_MASTER,vnQTESTGER_MASTER
          FROM PCMOV, PCEST
         WHERE PCMOV.DTMOV = TRUNC (SYSDATE)
           AND PCMOV.NUMTRANSVENDA = vnNUMTRANSVENDA
           AND PCMOV.CODFILIAL = p_CODFILIAL
           AND PCMOV.CODPROD = PCEST.CODPROD
           AND PCMOV.CODFILIAL = PCEST.CODFILIAL
           AND NVL (PCMOV.CODOPER, 'X') = 'SP';

         vbBuscouDadosConversao := True;
      end if;
      end if;
   end if;

   if vbBuscouDadosConversao = true then


      BEGIN
         -- utilização do rownum. Se a alteração for disparada por um usuário com permissão de sysdba
         -- ou for um job cadastrado por este usuário, o USERENV('SESSIONID') deste usuário é null.
         SELECT SUBSTR(program,1,80)
           INTO vsprograma
           FROM usuarios_logados
          WHERE audsid = USERENV ('SESSIONID')
            AND rownum = 1;
      EXCEPTION
         WHEN NO_DATA_FOUND THEN
            vsprograma := NULL;
      END;


      --Gravação de log do acesso a esta permissão

         INSERT INTO PCLOGALTERACAODADOS
                     (DATA,
                      CODFUNC,
                      CODROTINA,
                      TABELA,
                      COLUNA,
                      TIPOVALOR,
                      VALORNUM,
                      VALORNUMANT,
                      VALORALFA,
                      VALORALFAANT,
                      USACTRLACESSO,
                      CODCTRLACESSO,
                      OBSERVACOES,
                      MAQUINA,
                      PROGRAMA,
                      TERMINAL,
                      OSUSER)
         VALUES      (SYSDATE,
                      8888,
                      2596,
                      'PCEST',
                      'QTESTGER',
                      'N',
                      vnqtestger_depois,
                      p_qtestger,
                      NULL,
                      NULL,
                      'S',
                      NULL,
                      'CONV. EMB. PROD. '||' PED.: ' || p_NUMPED,
                      'PRODUCAO',
                      vsPROGRAMA,
                      p_numped,
                      p_codprod);


         INSERT INTO PCLOGALTERACAODADOS
                     (DATA,
                      CODFUNC,
                      CODROTINA,
                      TABELA,
                      COLUNA,
                      TIPOVALOR,
                      VALORNUM,
                      VALORNUMANT,
                      VALORALFA,
                      VALORALFAANT,
                      USACTRLACESSO,
                      CODCTRLACESSO,
                      OBSERVACOES,
                      MAQUINA,
                      PROGRAMA,
                      TERMINAL,
                      OSUSER)
         VALUES      (SYSDATE,
                      8888,
                      2596,
                      'PCEST',
                      'QTESTGER',
                      'N',
                      vnqtestger_master,
                      vnQTESTGER_MASTER + vnQT_MASTER,
                      NULL,
                      NULL,
                      'S',
                      NULL,
                      'CONV. EMB. PROD. '||' PED.: ' || p_NUMPED,
                      'REQUISICAO',
                      vsPROGRAMA,
                      p_numped,
                      vncodprod_master);


   end if;

   exception when others then
     p_mensagem := 'Erro ao gravar log de conversão de embalagem : '||SQLCODE||' '||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM;

end proc_GravaLogConvEmbalagem;


  procedure proc_gravapedido(p_regpedido  in out t_cabped,
                              p_numseq     in number,
                              p_regfilial  in t_filial,
                              p_regcliente in t_clientepedido,
                              p_regrca     in t_rca,
                              p_regplpag   in t_planodepagamento,
                              vnvlatend    out number,
                              vntotpeso    out number,
                              vntotvolume  out number,
                              p_vltotped   in  number) is

    cursor cr_estoque(p_numped pcpedc.numped%type) is
      select *
        from pcest
       where exists (select pcpedi.codprod
                from pcpedi
               where pcpedi.numped = p_numped
                 and pcpedi.codprod = pcest.codprod
                 and pcpedi.numseq > p_numseq
                 and pcest.codfilial = pcpedi.codfilialretira)

      --for update
      ;

    vnqtdisponivel             number;
    vnqtatend                  number;
    vnqtfalta                  number;
    vnvltabela                 number;
    vnvltotal                  number;
    vnvlcustofin               number;
    vnvlcustoreal              number;
    vnvlcustorep               number;
    vnvlcustocont              number;
    vnnumitens                 number;
    vnsomafalta                number;
    vbfazreservaestoque        boolean;
    vnqtdisponivel_cont        number;
    vnnumseq                   number;
    vnqtminautoservico         number;
    vicont                     number;
    vncodcertific              pccertific.codcertific%type;
    vnqttotprod                number;

    vnmultiplo                 pcprodut.multiplo%type;
    vnmultiplo_prod            pcprodut.multiplo%type;
    vschecarmultiplovendabnf   pcprodut.checarmultiplovendabnf%type;

    vbfazreservaestoque_aux    boolean;

    vbrejeitapedido            boolean;
    vsaceitavendafracao_prod   pcprodut.aceitavendafracao%type;
    vsaceitavendafracao        pcprodfilial.aceitavendafracao%type;
    vschecarmultiplovendabnf_prod  pcprodut.checarmultiplovendabnf%type;

    -- 5666.058584.2016 - Valor Mínimo Pós Corte
    vstipovalorminimo          pccondicaovenda.tipovalorminimo%type;
    vnvalorminimocondicao      pccondicaovenda.valorminimoped%type;

    -- HIS.04281.2017 - Variável para definir se Movimenta Saldo RCA
    vvMovimentarSaldoRca       VARCHAR2(1);
    -- HIS.04281.2017 - Retorno da Proc. de Gravação do Pedido
    TYPE TRecRetGravacaoPed    IS RECORD(
         vvRetorno             VARCHAR2(250),
         vvMsgErros            VARCHAR2(2000),
         vvPosicaoFinalPedido  VARCHAR2(1),
         vnCodMotivo           NUMBER,
         vvMotivoPosicao       VARCHAR2(2000),
         vvObservacaoMotivo    VARCHAR2(2000),
         vvExistemFaltas       VARCHAR2(1));
    vrRetGravacaoPed           TRecRetGravacaoPed;
    -- Array com os Dados das Faltas
    TYPE TT_FTA_CODPROD        IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
    TYPE TT_FTA_CODAUXILIAR    IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
    TYPE TT_FTA_ESTOQUEDISP    IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
    TYPE TT_FTA_QTDEORIGINAL   IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
    TYPE TT_FTA_NUMSEQ         IS TABLE OF NUMBER INDEX BY BINARY_INTEGER; -- DDMEDICA-198
    vtFTA_CODPROD              TT_FTA_CODPROD;
    vtFTA_CODAUXILIAR          TT_FTA_CODAUXILIAR;
    vtFTA_ESTOQUEDISP          TT_FTA_ESTOQUEDISP;
    vtFTA_QTDEORIGINAL         TT_FTA_QTDEORIGINAL;
    vtFTA_NUMSEQ               TT_FTA_NUMSEQ; -- DDMEDICA-198
    -- Mensagem de Log Exclusão do Pedido
    vvMsgLogExclusaoPedido     VARCHAR2(250);

    -- Controle de Lock de Estoque
    vvQtdeTentativasProcPed    VARCHAR2(1);
    TYPE TT_LockEst_CodProd    IS TABLE OF PCEST.CODPROD%TYPE INDEX BY BINARY_INTEGER;
    TYPE TT_LockEst_CodFilial  IS TABLE OF PCEST.CODFILIAL%TYPE INDEX BY BINARY_INTEGER;
    vtLockEst_CodProd          TT_LockEst_CodProd;
    vtLockEst_CodFilial        TT_LockEst_CodFilial;
    vbSucessoLocarEstoque      BOOLEAN;
    vvMsgErroLocarEstoque      VARCHAR2(2000);

    -- Controle de Rejeição do Pedido
    TYPE TT_MotivoAbortaPedido IS TABLE OF VARCHAR2(4000) INDEX BY BINARY_INTEGER;
    vtMotivosAbortaPedido      TT_MotivoAbortaPedido;

    -- Variável para identificar se ainda existe Pedido
    vvExistePedido             VARCHAR2(1);

    -- DDMEDICA-198
    vnnumseqifv                PCPEDIFV.NUMSEQ%TYPE;

    -- DDMEDICA-683 - Flag de Exclusão do Produto por Saldo RCA
    vbExcuiuProdutoSaldoRca    BOOLEAN;

    -- Array para Armazenar o LOG da Importação do Pedido - MEDICA-477
    TYPE TTLogImportacaoPed    IS TABLE OF VARCHAR2(32000) INDEX BY BINARY_INTEGER;
    vtLogImportacaoPed         TTLogImportacaoPed;
    -- PROCEDIMENTO PARA GRAVAÇÃO DO LOG DE VALOR GERAL DO ITEM - MEDICA-477
    PROCEDURE PGRAVA_LOG(pi_vMensagem IN VARCHAR2) IS
      vvMensagemLogImportacaoPed VARCHAR2(32000);
      viIdxLogImpPed             INTEGER;
    BEGIN
      viIdxLogImpPed := NVL(vtLogImportacaoPed.COUNT,0) + 1;

      vvMensagemLogImportacaoPed := '[' || TRIM(TO_CHAR(viIdxLogImpPed,'0000')) || '] ' || pi_vMensagem;

      vtLogImportacaoPed(viIdxLogImpPed) := vvMensagemLogImportacaoPed;
    END PGRAVA_LOG;

  begin

   /********************************************************************************************************
    INICIO: HIS.04281.2017 - Refatoração do Estoque - Procedimento para Baixar Estoque e Atualizer Saldo RCA
    ********************************************************************************************************/

    -- Se chegar aqui como Pendente, atualizar como Liberado
    IF (p_regpedido.posicao = 'P') THEN
      p_regpedido.posicao := 'L';
    END IF;

    -- Atualiza a Posição do Pedido com a Posição que chegou aqui
    UPDATE PCPEDC
       SET POSICAO = p_regpedido.posicao
     WHERE (NUMPED = p_regpedido.numped);
    PGRAVA_LOG('PCPEDC.POSICAO Inicial: ' || p_regpedido.posicao);
    -- MED-2161 - Grava Bloqueio do Pedido
    IF (p_regpedido.posicao IN ('B','P')) THEN
      INTEGRADORACOMPLE_MED.proc_insere_bloqueiospedido('S', -->> Atualiza Motivo na PCPEDC
                                                        p_regpedido.numped,
                                                        p_regpedido.codmotivo,
                                                        NULL,
                                                        p_regpedido.motivoposicao);
    END IF;
    -- Atualiza a Posição dos Itens do Pedido com a Posição que chegou aqui
    UPDATE PCPEDI
       SET POSICAO = p_regpedido.posicao
     WHERE (NUMPED = p_regpedido.numped);

    -- HIS.04281.2017 - Se o OL e PE não movimenta Saldo RCA
    vvMovimentarSaldoRca := NVL(p_regpedido.usadebcredrca,'N'); --> Definido anteriormente validando cadastros do Winthor
    IF (p_regpedido.tipofv IN ('OL','PE')) THEN
      vvMovimentarSaldoRca := 'N';
    END IF;

    -------------------------------------------
    -- LOCK DE ESTOQUE
    -------------------------------------------

    -- Pesquisa Configuração de Lock de Estoque
    vvQtdeTentativasProcPed := FOBTEM_PARAM_INTEGRADORA(p_regpedido.integradora,
                                                        'QTDETENTATIVASPROCPED'
                                                        ,'0');

    -- Verificação de Sucesso no Lock
    vbSucessoLocarEstoque := TRUE;
    vvMsgErroLocarEstoque := NULL;

    -- Limpa Arrays só utilizados para Lock
    vtLockEst_CodProd.DELETE;
    vtLockEst_CodFilial.DELETE;

    -- Se Esperar locar o Produto até o final
    IF (NVL(vvQtdeTentativasProcPed,'0') = '0') THEN
      BEGIN
        SELECT PCEST.CODPROD
             , PCEST.CODFILIAL
          BULK COLLECT INTO vtLockEst_CodProd
                          , vtLockEst_CodFilial
          FROM PCEST
         WHERE ((PCEST.CODPROD, PCEST.CODFILIAL) IN (SELECT PCPEDI.CODPROD
                                                          , NVL(PCPEDI.CODFILIALRETIRA, p_regpedido.codfilial)
                                                       FROM PCPEDI
                                                      WHERE (PCPEDI.NUMPED = p_regpedido.numped)))
           FOR UPDATE; -->> ESPERA ATÉ LOCAR
      EXCEPTION
        WHEN OTHERS THEN
          vbSucessoLocarEstoque := FALSE;
          vvMsgErroLocarEstoque := SQLERRM;
      END;
    -- Se NÃO Esperar Locar
    ELSE
      BEGIN
        SELECT PCEST.CODPROD
             , PCEST.CODFILIAL
          BULK COLLECT INTO vtLockEst_CodProd
                          , vtLockEst_CodFilial
          FROM PCEST
         WHERE ((PCEST.CODPROD, PCEST.CODFILIAL) IN (SELECT PCPEDI.CODPROD
                                                          , NVL(PCPEDI.CODFILIALRETIRA, p_regpedido.codfilial)
                                                       FROM PCPEDI
                                                      WHERE (PCPEDI.NUMPED = p_regpedido.numped)))
           FOR UPDATE NOWAIT; -->> NÃO ESPERA ATÉ LOCAR
      EXCEPTION
        WHEN OTHERS THEN
          vbSucessoLocarEstoque := FALSE;
          vvMsgErroLocarEstoque := SQLERRM;
      END;
    END IF;

   /**************************
    **************************
    Se conseguiu Locar Estoque
    **************************
    **************************/
    IF (vbSucessoLocarEstoque) THEN

      ----------------------------------------------------------------
      ----------------------------------------------------------------
      -- Chama Procedimento para Validar Mínimo e Saldo Conta Corrente
      ----------------------------------------------------------------
      ----------------------------------------------------------------

      PKG_GRAVACAO_PEDIDO_MED.P_GRAVACAO_PEDIDO_01(2513, -- pi_nCodRotina
                                                   p_regpedido.numped,
                                                   p_regpedido.codusur,
                                                   8888, -- pi_nMatricula
                                                   'S',  -- pi_vGuardaFalta
                                                   'N',  -- pi_vGravarPedidoItensFalta
                                                   NULL, -- pi_nNumPedidoItensFalta
                                                   vvMovimentarSaldoRca,
                                                   'VM', -- pi_vChamadaProcesso
                                                   p_regpedido.posicao,
                                                   'N',  -- pi_vBrindes
                                                   NULL, -- pi_nCodProdEdicao
                                                   vrRetGravacaoPed.vvRetorno,
                                                   vrRetGravacaoPed.vvMsgErros,
                                                   vrRetGravacaoPed.vvPosicaoFinalPedido,
                                                   vrRetGravacaoPed.vnCodMotivo,
                                                   vrRetGravacaoPed.vvMotivoPosicao,
                                                   vrRetGravacaoPed.vvObservacaoMotivo,
                                                   vrRetGravacaoPed.vvExistemFaltas,
                                                   null,  -- pi_vCodFilial
                                                   null,  -- pi_nCodCli
                                                   null,  -- pi_nCondVenda
                                                   null,  -- pi_nCodPlPag
                                                   null,  -- pi_nCodPlPagEtico
                                                   null,  -- pi_nCodPlPagGenerico
                                                   null,  -- pi_vCodCob
                                                   null,  -- pi_dDtEntrega
                                                   null,  -- pi_vOrigemPed
                                                   null,  -- pi_vTipoFv
                                                   p_regpedido.integradora, -- pi_nIntegradora
                                                   null,  -- pi_nCodCondicaoVenda,
                                                   null,  -- pi_nCodUsur,
                                                   null,  -- pi_vVendaAssistida,
                                                   null,  -- pi_nVlDescNeg,
                                                   null,  -- pi_vPedidoAvaria,
                                                   null,  -- pi_nNumTransEntCrossDock,
                                                   null,  -- pi_vGeraCP,
                                                   null,  -- pi_nNumTransEntOrigConsig,
                                                   null,  -- pi_nNumTransEntOrigTrocaNota,
                                                   p_regpedido.codmotivo,
                                                   null,  -- pi_nCodMotivoBloqueio,
                                                   p_regpedido.motivoposicao,
                                                   p_regpedido.integradora,
                                                   p_regpedido.codpromocaomed,
                                                   p_regpedido.faturamentointegral, -- DDMEDICA-6533
                                                   p_regpedido.totunidades,
                                                   p_regcliente.numregiao);        -- DDMEDICA-6533
                                                   
      PGRAVA_LOG('>> Retorno da Gravação ao Validar Mínimo');
      PGRAVA_LOG('vvPosicaoFinalPedido: ' || vrRetGravacaoPed.vvPosicaoFinalPedido);
      PGRAVA_LOG('vnCodMotivo: '          || vrRetGravacaoPed.vnCodMotivo);
      PGRAVA_LOG('vvPosicaoFinalPedido: ' || vrRetGravacaoPed.vvMotivoPosicao);
      PGRAVA_LOG('vvObservacaoMotivo: '   || vrRetGravacaoPed.vvObservacaoMotivo);

      -- Se NÃO ocorreram erros ao Validar Mínimo e Saldo Conta Corrente ----------------------------
      IF (vrRetGravacaoPed.vvRetorno IS NULL) THEN

        -------------------------------------------
        -- Laço de Retorno com os Motivo da Posição
        -------------------------------------------
        vtMotivosAbortaPedido.DELETE;
        FOR vc_Motivo IN (SELECT CASE
                                   WHEN (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'P') THEN
                                     1
                                   WHEN (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'B') THEN
                                     2
                                   ELSE
                                     3
                                 END ORDENACAO
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.DESCRICAOREJEICAO
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTIVO
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.MOTIVOPOSICAO
                               , PCMED_VALIDACAO_ESTOQUE_RESERV.OBSERVACAO
                            FROM PCMED_VALIDACAO_ESTOQUE_RESERV
                           WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO IN ('P','B','A'))
                           ORDER BY 1 -->> CLASSIFICAR A ORDENAÇÃO (Deixar os que abortam por último)
                           ) LOOP

          -- Atualiza a Posição do Pedido atualizando motivo do bloqueio
          -- (Desta forma a Trigger de Motivos de Posição dispara e grava todos os Motivos encontrados)
          UPDATE PCPEDC
             SET POSICAO = vrRetGravacaoPed.vvPosicaoFinalPedido
           WHERE (NUMPED = p_regpedido.numped);
          PGRAVA_LOG('PCPEDC.POSICAO ao Validar Mínimo: ' || vrRetGravacaoPed.vvPosicaoFinalPedido || ' (' || vc_Motivo.MOTIVOPOSICAO || ')');           
          -- MED-2161 - Grava Bloqueio do Pedido
          INTEGRADORACOMPLE_MED.proc_insere_bloqueiospedido('S', -->> Atualiza Motivo na PCPEDC
                                                            p_regpedido.numped,
                                                            vc_Motivo.CODMOTIVO,
                                                            NULL,
                                                            vc_Motivo.MOTIVOPOSICAO);

           -- Se houver alguma Ação para Abortar o Pedido
           IF (vc_Motivo.ACAO = 'A') THEN
             vtMotivosAbortaPedido(NVL(vtMotivosAbortaPedido.COUNT,0) + 1) := vc_Motivo.DESCRICAOREJEICAO || ': ' || vc_Motivo.OBSERVACAO;
           END IF;

        END LOOP; -- Fim: Laço de Retorno com os Motivo da Posição

        -----------------------------------------
        -- Atualização Final da Posição do Pedido
        -----------------------------------------

        -- Atualiza Variável da Posição do Pedido
        p_regpedido.posicao := vrRetGravacaoPed.vvPosicaoFinalPedido;

        -- Se Liberado/Montado
        IF    (vrRetGravacaoPed.vvPosicaoFinalPedido IN ('L','M')) THEN

           -- Muda Posição Limpando Motivo do Bloqueio
           UPDATE PCPEDC
              SET POSICAO       = vrRetGravacaoPed.vvPosicaoFinalPedido
                , MOTIVOPOSICAO = NULL
                , CODMOTIVO     = NULL
            WHERE (NUMPED = p_regpedido.numped);
           PGRAVA_LOG('PCPEDC.POSICAO após Validar Mínimo: ' || vrRetGravacaoPed.vvPosicaoFinalPedido || ' (L/M)');           

        -- Se Bloqueado/Pendente
        ELSIF (vrRetGravacaoPed.vvPosicaoFinalPedido IN ('B','P')) THEN

           -- Atualiza a Posição do Pedido atualizando motivo do bloqueio
           UPDATE PCPEDC
              SET POSICAO = vrRetGravacaoPed.vvPosicaoFinalPedido
                , LOG     = SUBSTR(LOG,1,3000) || CHR(13) || vrRetGravacaoPed.vvObservacaoMotivo
            WHERE (NUMPED = p_regpedido.numped);
           PGRAVA_LOG('PCPEDC.POSICAO após Validar Mínimo: ' || vrRetGravacaoPed.vvPosicaoFinalPedido || ' (B/P)');           
           -- MED-2161 - Grava Bloqueio do Pedido
           INTEGRADORACOMPLE_MED.proc_insere_bloqueiospedido('S', -->> Atualiza Motivo na PCPEDC
                                                             p_regpedido.numped,
                                                             vrRetGravacaoPed.vnCodMotivo,
                                                             NULL,
                                                             vrRetGravacaoPed.vvMotivoPosicao);

        END IF; -- Fim Condição: Nova Posição

       /***********************************************
        SE ABORTA O PEDIDO POR NAO ATINGIR VALOR MÍNIMO
        ***********************************************/
        IF (NVL(vtMotivosAbortaPedido.COUNT,0) > 0) THEN

          FOR viLacoAborta IN vtMotivosAbortaPedido.FIRST..vtMotivosAbortaPedido.LAST LOOP

            proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             null,
                             null,
                             p_regpedido.cgccli,
                             null,
                             null,
                             null,
                             p_Regpedido.codusur,
                             p_Regpedido.dtaberturapedpalm,
                             null,
                             '2',
                             vtMotivosAbortaPedido(viLacoAborta),
                             null,
                             null);

          END LOOP;

          -- Exclui Pedido
          delete from pcpedc
           where numped = p_regpedido.numped;
          -- Exclui Itens do Pedido
          delete from pcpedi
           where pcpedi.numped  = p_regpedido.numped;
          -- Exclui Origem do Preço dos Itens do Pedido
          delete from pcorigempreco
           where numped  = p_regpedido.numped;

          -- Marca Pedido como Inválido
          p_regpedido.valido := false;

       /*******************************************************
        SE <NÃO> ABORTA O PEDIDO POR NAO ATINGIR O VALOR MÍNIMO
        *******************************************************/
        ELSE

          -- DDMEDICA-683 - Flag de Exclusão do Produto por Saldo RCA
          vbExcuiuProdutoSaldoRca := FALSE;

          -------------------------------------------------
          -- LOG dos valores calculados na Validação de C/C
          -------------------------------------------------
          FOR vc_CriticasCalc IN (SELECT CODPROD
                                       , NUMSEQ
                                       , QT
                                       , (PVENDA-NVL(ST,0)) PRECO
                                       , (PBASERCA-NVL(STPBASERCA,0)) BASERCA
                                       , SALDORCA
                                       , SALDOPED
                                       , SALDOITEM
                                       , VENDAPERMITIDA
                                       , ACAO
                                    FROM PCMED_VALIDACAO_SALDO_ITEM
                                   WHERE (NUMPED      = p_regpedido.numped)
                                     AND (CODREJEICAO = 12) -- Crítica de Saldo RCA
                                    ORDER BY NVL(SALDOITEM,0) DESC) LOOP -->> FUNDAMENTAL: NÃO MEXER: Ordenar do maior saldo positivo para o menor saldo
            PGRAVA_LOG('{ CODPROD = '       || vc_CriticasCalc.CODPROD        || ' | ' ||
                       ' NUMSEQ = '         || vc_CriticasCalc.NUMSEQ         || ' | ' ||
                       ' QT = '             || vc_CriticasCalc.QT             || ' | ' ||
                       ' PRECO = '          || vc_CriticasCalc.PRECO          || ' | ' ||
                       ' BASERCA = '        || vc_CriticasCalc.BASERCA        || ' | ' ||
                       ' SALDORCA = '       || vc_CriticasCalc.SALDORCA       || ' | ' ||
                       ' SALDOPED = '       || vc_CriticasCalc.SALDOPED       || ' | ' ||
                       ' SALDOITEM = '      || vc_CriticasCalc.SALDOITEM      || ' | ' ||
                       ' VENDAPERMITIDA = ' || vc_CriticasCalc.VENDAPERMITIDA || ' | ' ||
                       ' ACAO = '           || vc_CriticasCalc.ACAO           || ' } ');
          END LOOP;

          ---------------------------------------------------------------------------------------------
          -- Exclusão dos Itens que não pode movimentar conta corrente
          -- (Registros marcados com VENDAPERMITIDA = N quando o Parâmetro VALIDARSALDORCAPORITEM = 'S'
          ---------------------------------------------------------------------------------------------

          -- Laço de Itens que serão excluídos automaticamente por saldo de conta corrente insuficiente
          -- Código Rejeição = 12
          -- MED-2349 - Somente Validações que não gravam o Pedido como Bloqueado
          FOR vc_ItensExclusao IN (SELECT PCMED_VALIDACAO_SALDO_ITEM.CODPROD
                                        , PCMED_VALIDACAO_SALDO_ITEM.NUMSEQ
                                        , PCPRODUT.CODAUXILIAR
                                        , PCMED_VALIDACAO_SALDO_ITEM.SALDORCA
                                        , PCMED_VALIDACAO_SALDO_ITEM.SALDOPED
                                        , PCMED_VALIDACAO_SALDO_ITEM.SALDOITEM
                                     FROM PCMED_VALIDACAO_SALDO_ITEM
                                        , PCPRODUT
                                    WHERE (PCPRODUT.CODPROD                          = PCMED_VALIDACAO_SALDO_ITEM.CODPROD)
                                      AND (PCMED_VALIDACAO_SALDO_ITEM.NUMPED         = p_regpedido.numped)
                                      AND (PCMED_VALIDACAO_SALDO_ITEM.VENDAPERMITIDA = 'N')
                                      AND (PCMED_VALIDACAO_SALDO_ITEM.ACAO          <> 'B') -- Somente Validações que não gravam o Pedido como Bloqueado - MED-2349
                                      AND (PCMED_VALIDACAO_SALDO_ITEM.CODREJEICAO    = 12)) LOOP

            -- DDMEDICA-198 - Pesquisa o NUMSEQ da PCPEDIFV
            BEGIN
              SELECT PCPEDIFV.NUMSEQ
                INTO vnnumseqifv
                FROM PCPEDIFV
               WHERE (PCPEDIFV.NUMPEDRCA         = p_regpedido.numpedrca)
                 AND (PCPEDIFV.CGCCLI            = p_regpedido.cgccli)
                 AND (PCPEDIFV.CODUSUR           = p_regpedido.codusur)
                 AND (PCPEDIFV.DTABERTURAPEDPALM = p_regpedido.dtaberturapedpalm)
                 AND (PCPEDIFV.CODPROD           = vc_ItensExclusao.CODPROD)
                 AND (PCPEDIFV.NUMSEQITEMPEDMED  = vc_ItensExclusao.NUMSEQ)
                 AND (ROWNUM                     = 1);
            EXCEPTION
              WHEN NO_DATA_FOUND THEN
                vnnumseqifv := NULL;
            END;

            proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             vc_ItensExclusao.CODPROD,
                             vc_ItensExclusao.CODAUXILIAR,
                             p_regpedido.cgccli,
                             NULL,
                             NULL,
                             null,
                             p_regpedido.codusur,
                             p_regpedido.dtaberturapedpalm,
                             null,
                             '3',
                             'Rca sem credito disponivel > Saldo RCA [' || NVL(vc_ItensExclusao.SALDORCA,0) ||
                               '] Saldo acumulado do pedido [' || NVL(vc_ItensExclusao.SALDOPED,0) ||
                                 '] Saldo do item [' || NVL(vc_ItensExclusao.SALDOITEM,0) || ';',
                             NULL,
                             vnnumseqifv);

            -- Exclui Itens do Pedido
            delete from pcpedi
             where pcpedi.numped  = p_regpedido.numped
               and pcpedi.codprod = vc_ItensExclusao.CODPROD
               and pcpedi.numseq  = vc_ItensExclusao.NUMSEQ;
            -- Exclui Origem do Preço dos Itens do Pedido
            delete from pcorigempreco
             where numped  = p_regpedido.numped
               and codprod = vc_ItensExclusao.CODPROD
               and numseq  = vc_ItensExclusao.NUMSEQ;

            -- DDMEDICA-683 - Excluiu Produto por Saldo RCA
            vbExcuiuProdutoSaldoRca := TRUE;

          END LOOP;

          -- Verifica se ficaram Itens no Pedido
          select count(*) numitens
            into vnnumitens
           from pcpedi
          where pcpedi.numped = p_regpedido.numped;

          -- Se todos os Itens foram excluidos do Pedido por Saldo Negativo de Conta Corrente
          IF (vnnumitens = 0) THEN

            proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             null,
                             null,
                             p_regpedido.cgccli,
                             null,
                             null,
                             null,
                             p_Regpedido.codusur,
                             p_Regpedido.dtaberturapedpalm,
                             null,
                             '2',
                             'Rca sem credito disponivel',
                             null,
                             null);

            -- Exclui Pedido
            delete from pcpedc
             where numped = p_regpedido.numped;

            proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             null,
                             null,
                             p_regpedido.cgccli,
                             null,
                             null,
                             null,
                             p_Regpedido.codusur,
                             p_Regpedido.dtaberturapedpalm,
                             null,
                             '2',
                             'Rca sem credito disponivel',
                             null,
                             null);

            -- Marca Pedido como Inválido
            p_regpedido.valido := false;

          -- Se ainda ficaram itens após processo de exclusão de itens por conta-corrente
          ELSE

            -----------------------------------------------------------------------------------------------------
            -----------------------------------------------------------------------------------------------------
            -- DDMEDICA-683 - Chama Procedimento para Validar Mínimo após corte de produtos por Conta Corrente --
            -----------------------------------------------------------------------------------------------------
            -----------------------------------------------------------------------------------------------------
            IF (vbExcuiuProdutoSaldoRca) THEN

              PKG_GRAVACAO_PEDIDO_MED.P_GRAVACAO_PEDIDO_01(2513, -- pi_nCodRotina
                                                           p_regpedido.numped,
                                                           p_regpedido.codusur,
                                                           8888, -- pi_nMatricula
                                                           'S',  -- pi_vGuardaFalta
                                                           'N',  -- pi_vGravarPedidoItensFalta
                                                           NULL, -- pi_nNumPedidoItensFalta
                                                           vvMovimentarSaldoRca,
                                                           'VM', -- pi_vChamadaProcesso
                                                           p_regpedido.posicao,
                                                           'N',  -- pi_vBrindes
                                                           NULL, -- pi_nCodProdEdicao
                                                           vrRetGravacaoPed.vvRetorno,
                                                           vrRetGravacaoPed.vvMsgErros,
                                                           vrRetGravacaoPed.vvPosicaoFinalPedido,
                                                           vrRetGravacaoPed.vnCodMotivo,
                                                           vrRetGravacaoPed.vvMotivoPosicao,
                                                           vrRetGravacaoPed.vvObservacaoMotivo,
                                                           vrRetGravacaoPed.vvExistemFaltas,
                                                           null,  -- pi_vCodFilial
                                                           null,  -- pi_nCodCli
                                                           null,  -- pi_nCondVenda
                                                           null,  -- pi_nCodPlPag
                                                           null,  -- pi_nCodPlPagEtico
                                                           null,  -- pi_nCodPlPagGenerico
                                                           null,  -- pi_vCodCob
                                                           null,  -- pi_dDtEntrega
                                                           null,  -- pi_vOrigemPed
                                                           null,  -- pi_vTipoFv
                                                           p_regpedido.integradora, -- pi_nIntegradora
                                                           null,  -- pi_nCodCondicaoVenda,
                                                           null,  -- pi_nCodUsur,
                                                           null,  -- pi_vVendaAssistida,
                                                           null,  -- pi_nVlDescNeg,
                                                           null,  -- pi_vPedidoAvaria,
                                                           null,  -- pi_nNumTransEntCrossDock,
                                                           null,  -- pi_vGeraCP,
                                                           null,  -- pi_nNumTransEntOrigConsig,
                                                           null,  -- pi_nNumTransEntOrigTrocaNota,
                                                           p_regpedido.codmotivo,
                                                           null,  -- pi_nCodMotivoBloqueio,
                                                           p_regpedido.motivoposicao,
                                                           p_regpedido.integradora,
                                                           p_regpedido.codpromocaomed,
                                                           p_regpedido.faturamentointegral, -- DDMEDICA-6533
                                                           p_regpedido.totunidades,
                                                           p_regcliente.numregiao);        -- DDMEDICA-6533
                                                           
              PGRAVA_LOG('>> Retorno da Gravação após corte de produtos por C/C');
              PGRAVA_LOG('vvPosicaoFinalPedido: ' || vrRetGravacaoPed.vvPosicaoFinalPedido);
              PGRAVA_LOG('vnCodMotivo: '          || vrRetGravacaoPed.vnCodMotivo);
              PGRAVA_LOG('vvPosicaoFinalPedido: ' || vrRetGravacaoPed.vvMotivoPosicao);
              PGRAVA_LOG('vvObservacaoMotivo: '   || vrRetGravacaoPed.vvObservacaoMotivo);
                                                           
              -- Se NÃO ocorreram erros ao Validar Mínimo após corte de produtos por Conta Corrente ----------------------------
              IF (vrRetGravacaoPed.vvRetorno IS NULL) THEN

                -------------------------------------------
                -- Laço de Retorno com os Motivo da Posição
                -------------------------------------------
                vtMotivosAbortaPedido.DELETE;
                FOR vc_Motivo IN (SELECT CASE
                                           WHEN (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'P') THEN
                                             1
                                           WHEN (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO = 'B') THEN
                                             2
                                           ELSE
                                             3
                                         END ORDENACAO
                                       , PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO
                                       , PCMED_VALIDACAO_ESTOQUE_RESERV.CODREJEICAO
                                       , PCMED_VALIDACAO_ESTOQUE_RESERV.DESCRICAOREJEICAO
                                       , PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTIVO
                                       , PCMED_VALIDACAO_ESTOQUE_RESERV.MOTIVOPOSICAO
                                       , PCMED_VALIDACAO_ESTOQUE_RESERV.OBSERVACAO
                                    FROM PCMED_VALIDACAO_ESTOQUE_RESERV
                                   WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO IN ('P','B','A'))
                                   ORDER BY 1 -->> CLASSIFICAR A ORDENAÇÃO (Deixar os que abortam por último)
                                   ) LOOP

                  -- Atualiza a Posição do Pedido atualizando motivo do bloqueio
                  -- (Desta forma a Trigger de Motivos de Posição dispara e grava todos os Motivos encontrados)
                  UPDATE PCPEDC
                     SET POSICAO = vrRetGravacaoPed.vvPosicaoFinalPedido
                   WHERE (NUMPED = p_regpedido.numped);
                  PGRAVA_LOG('PCPEDC.POSICAO no corte C/C: ' || vrRetGravacaoPed.vvPosicaoFinalPedido || ' (' || vc_Motivo.MOTIVOPOSICAO || ')');
                  -- MED-2161 - Grava Bloqueio do Pedido
                  INTEGRADORACOMPLE_MED.proc_insere_bloqueiospedido('S', -->> Atualiza Motivo na PCPEDC
                                                                    p_regpedido.numped,
                                                                    vc_Motivo.CODMOTIVO,
                                                                    NULL,
                                                                    vc_Motivo.MOTIVOPOSICAO);

                   -- Se houver alguma Ação para Abortar o Pedido
                   IF (vc_Motivo.ACAO = 'A') THEN
                     vtMotivosAbortaPedido(NVL(vtMotivosAbortaPedido.COUNT,0) + 1) := vc_Motivo.DESCRICAOREJEICAO || ': ' || vc_Motivo.OBSERVACAO;
                   END IF;

                END LOOP; -- Fim: Laço de Retorno com os Motivo da Posição

                -----------------------------------------
                -- Atualização Final da Posição do Pedido
                -----------------------------------------

                -- Atualiza Variável da Posição do Pedido
                p_regpedido.posicao := vrRetGravacaoPed.vvPosicaoFinalPedido;

                -- Se Liberado/Montado
                IF    (vrRetGravacaoPed.vvPosicaoFinalPedido IN ('L','M')) THEN

                   -- Muda Posição Limpando Motivo do Bloqueio
                   UPDATE PCPEDC
                      SET POSICAO       = vrRetGravacaoPed.vvPosicaoFinalPedido
                        , MOTIVOPOSICAO = NULL
                        , CODMOTIVO     = NULL
                    WHERE (NUMPED = p_regpedido.numped);
                   PGRAVA_LOG('PCPEDC.POSICAO após corte C/C: ' || vrRetGravacaoPed.vvPosicaoFinalPedido || ' (L/M)');           

                -- Se Bloqueado/Pendente
                ELSIF (vrRetGravacaoPed.vvPosicaoFinalPedido IN ('B','P')) THEN

                   -- Atualiza a Posição do Pedido atualizando motivo do bloqueio
                   UPDATE PCPEDC
                      SET POSICAO = vrRetGravacaoPed.vvPosicaoFinalPedido
                        , LOG     = SUBSTR(LOG,1,3000) || CHR(13) || vrRetGravacaoPed.vvObservacaoMotivo
                    WHERE (NUMPED = p_regpedido.numped);
                   PGRAVA_LOG('PCPEDC.POSICAO após corte C/C: ' || vrRetGravacaoPed.vvPosicaoFinalPedido || ' (B/P)');           
                   -- MED-2161 - Grava Bloqueio do Pedido
                   INTEGRADORACOMPLE_MED.proc_insere_bloqueiospedido('S', -->> Atualiza Motivo na PCPEDC
                                                                     p_regpedido.numped,
                                                                     vrRetGravacaoPed.vnCodMotivo,
                                                                     NULL,
                                                                     vrRetGravacaoPed.vvMotivoPosicao);

                END IF; -- Fim Condição: Nova Posição

               /***********************************************
                SE ABORTA O PEDIDO POR NAO ATINGIR VALOR MÍNIMO
                ***********************************************/
                IF (NVL(vtMotivosAbortaPedido.COUNT,0) > 0) THEN

                  FOR viLacoAborta IN vtMotivosAbortaPedido.FIRST..vtMotivosAbortaPedido.LAST LOOP

                    proc_registralog(p_regpedido.numped,
                                     p_regpedido.numpedrca,
                                     null,
                                     null,
                                     p_regpedido.cgccli,
                                     null,
                                     null,
                                     null,
                                     p_Regpedido.codusur,
                                     p_Regpedido.dtaberturapedpalm,
                                     null,
                                     '2',
                                     vtMotivosAbortaPedido(viLacoAborta),
                                     null,
                                     null);

                  END LOOP;

                  -- Exclui Pedido
                  delete from pcpedc
                   where numped = p_regpedido.numped;
                  -- Exclui Itens do Pedido
                  delete from pcpedi
                   where pcpedi.numped  = p_regpedido.numped;
                  -- Exclui Origem do Preço dos Itens do Pedido
                  delete from pcorigempreco
                   where numped  = p_regpedido.numped;

                  -- Marca Pedido como Inválido
                  p_regpedido.valido := false;

                END IF; -- Fim: SE ABORTA O PEDIDO POR NAO ATINGIR VALOR MÍNIMO

              END IF; -- Se NÃO ocorreram erros ao Validar Mínimo após corte de produtos por Conta Corrente ----------------------------

            END IF; -- DDMEDICA-683 (vbExcuiuProdutoSaldoRca)

          END IF; -- Fim Condição: Se todos os Itens foram excluidos do Pedido por Saldo Negativo de Conta Corrente

        END IF; -- FIM CONDIÇÃO: SE ABORTA O PEDIDO POR NAO ATINGIR VALOR MÍNIMO

       /************************************************************************
        VERIFICA SE AINDA TEM PEDIDO APÓS A REALIZAÇÃO DAS VALIDAÇÕES ANTERIORES
        ************************************************************************/

        -- Pesquisa Pedido
        BEGIN
          SELECT 'S'
            INTO vvExistePedido
            FROM PCPEDC
           WHERE (NUMPED = p_regpedido.numped);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vvExistePedido := 'N';
        END;

       /***************************************************************
        SE AINDA TEM PEDIDO APÓS A REALIZAÇÃO DAS VALIDAÇÕES ANTERIORES
        ***************************************************************/
        IF (vvExistePedido = 'S') THEN

          -------------------------------------------
          -------------------------------------------
          -- Chama Procedimento para Baixa do Estoque
          -------------------------------------------
          -------------------------------------------

          PKG_GRAVACAO_PEDIDO_MED.P_GRAVACAO_PEDIDO_01(2513, -- pi_nCodRotina
                                                       p_regpedido.numped,
                                                       p_regpedido.codusur,
                                                       8888, -- pi_nMatricula
                                                       'S',  -- pi_vGuardaFalta
                                                       'N',  -- pi_vGravarPedidoItensFalta
                                                       NULL, -- pi_nNumPedidoItensFalta
                                                       vvMovimentarSaldoRca,
                                                       'GP', -- pi_vChamadaProcesso
                                                       p_regpedido.posicao,
                                                       'N',  -- pi_vBrindes
                                                       NULL, -- pi_nCodProdEdicao
                                                       vrRetGravacaoPed.vvRetorno,
                                                       vrRetGravacaoPed.vvMsgErros,
                                                       vrRetGravacaoPed.vvPosicaoFinalPedido,
                                                       vrRetGravacaoPed.vnCodMotivo,
                                                       vrRetGravacaoPed.vvMotivoPosicao,
                                                       vrRetGravacaoPed.vvObservacaoMotivo,
                                                       vrRetGravacaoPed.vvExistemFaltas,
                                                       null,  -- pi_vCodFilial
                                                       null,  -- pi_nCodCli
                                                       null,  -- pi_nCondVenda
                                                       null,  -- pi_nCodPlPag
                                                       null,  -- pi_nCodPlPagEtico
                                                       null,  -- pi_nCodPlPagGenerico
                                                       null,  -- pi_vCodCob
                                                       null,  -- pi_dDtEntrega
                                                       null,  -- pi_vOrigemPed
                                                       null,  -- pi_vTipoFv
                                                       p_regpedido.integradora, -- pi_nIntegradora
                                                       null,  -- pi_nCodCondicaoVenda,
                                                       null,  -- pi_nCodUsur,
                                                       null,  -- pi_vVendaAssistida,
                                                       null,  -- pi_nVlDescNeg,
                                                       null,  -- pi_vPedidoAvaria,
                                                       null,  -- pi_nNumTransEntCrossDock,
                                                       null,  -- pi_vGeraCP,
                                                       null,  -- pi_nNumTransEntOrigConsig,
                                                       null,  -- pi_nNumTransEntOrigTrocaNota,
                                                       p_regpedido.codmotivo,
                                                       null,  -- pi_nCodMotivoBloqueio,
                                                       p_regpedido.motivoposicao,
                                                       p_regpedido.integradora,
                                                       p_regpedido.codpromocaomed,
                                                       p_regpedido.faturamentointegral, -- DDMEDICA-6533
                                                       p_regpedido.totunidades,
                                                       p_regcliente.numregiao);        -- DDMEDICA-6533

          PGRAVA_LOG('>> Retorno da Gravação na Baixa do Estoque');
          PGRAVA_LOG('vvPosicaoFinalPedido: ' || vrRetGravacaoPed.vvPosicaoFinalPedido);
          PGRAVA_LOG('vnCodMotivo: '          || vrRetGravacaoPed.vnCodMotivo);
          PGRAVA_LOG('vvPosicaoFinalPedido: ' || vrRetGravacaoPed.vvMotivoPosicao);
          PGRAVA_LOG('vvObservacaoMotivo: '   || vrRetGravacaoPed.vvObservacaoMotivo);

          -- Se NÃO ocorreram erros ---------------------------------------------------------------------
          IF (vrRetGravacaoPed.vvRetorno IS NULL) THEN

            -- Se Cancelou o Pedido por Falta de Estoque
            IF (NVL(vrRetGravacaoPed.vvPosicaoFinalPedido,'L') = 'C') THEN

              proc_registralog(p_regpedido.numped,
                               p_regpedido.numpedrca,
                               null,
                               null,
                               p_regpedido.cgccli,
                               null,
                               null,
                               null,
                               p_Regpedido.codusur,
                               p_Regpedido.dtaberturapedpalm,
                               null,
                               '2',
                               'Pedido cancelado por falta de estoque em todos os produtos' || ';',
                               null,
                               null);

             -- Marca Pedido como Inválido
             p_regpedido.valido := false;

             -- Precisa do COMMIT pra registrar as Faltas e Logs
             COMMIT;

            -- Se NÃO cancelou o Pedido
            ELSE

              -- Se Liberado/Montado
              IF    (vrRetGravacaoPed.vvPosicaoFinalPedido IN ('L','M')) THEN

                 -- Muda Posição Limpando Motivo do Bloqueio
                 UPDATE PCPEDC
                    SET POSICAO       = vrRetGravacaoPed.vvPosicaoFinalPedido
                      , MOTIVOPOSICAO = NULL
                      , CODMOTIVO     = NULL
                  WHERE (NUMPED = p_regpedido.numped);
                 PGRAVA_LOG('PCPEDC.POSICAO após Baixa de Estoque: ' || vrRetGravacaoPed.vvPosicaoFinalPedido || ' (L/M)');           

              -- Se Bloqueado/Pendente
              ELSIF (vrRetGravacaoPed.vvPosicaoFinalPedido IN ('B','P')) THEN

                 -- Atualiza a Posição do Pedido atualizando motivo do bloqueio
                 UPDATE PCPEDC
                    SET POSICAO = vrRetGravacaoPed.vvPosicaoFinalPedido
                      , LOG     = SUBSTR(LOG,1,3000) || CHR(13) || vrRetGravacaoPed.vvObservacaoMotivo
                  WHERE (NUMPED = p_regpedido.numped);
                 PGRAVA_LOG('PCPEDC.POSICAO após Baixa de Estoque: ' || vrRetGravacaoPed.vvPosicaoFinalPedido || ' (B/P)');           
                 -- MED-2161 - Grava Bloqueio do Pedido
                 INTEGRADORACOMPLE_MED.proc_insere_bloqueiospedido('S', -->> Atualiza Motivo na PCPEDC
                                                                   p_regpedido.numped,
                                                                   vrRetGravacaoPed.vnCodMotivo,
                                                                   NULL,
                                                                   vrRetGravacaoPed.vvMotivoPosicao);

              END IF; -- Fim Condição: Nova Posição

            END IF; -- Fim Condição: Se Cancelou o Pedido por Falta de Estoque
            
          -- Se ocorreram erros -------------------------------------------------------------------------
          ELSE

            proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             null,
                             null,
                             p_regpedido.cgccli,
                             null,
                             null,
                             null,
                             p_Regpedido.codusur,
                             p_Regpedido.dtaberturapedpalm,
                             null,
                             '2',
                             'Pedido rejeitado por problemas na gravação do estoque: #' || vrRetGravacaoPed.vvMsgErros || ';',
                             null,
                             null);

            -- Exclui Itens do Pedido
            delete from pcpedi
             where pcpedi.numped = p_regpedido.numped;
            -- Exclui Origem do Preço dos Itens do Pedido
            delete from pcorigempreco
             where numped = p_regpedido.numped;
            -- Exclui Pedido
            delete from pcpedc
             where numped = p_regpedido.numped;

            -- Marca Pedido como Inválido
            p_regpedido.valido          := false;
            p_regpedido.errolockestoque := 'S'; -- Motivo Lock Estoque

          END IF; -- Fim Condição: Se ocorreram erros

        END IF; -- Fim Condição: SE AINDA TEM PEDIDO APÓS A REALIZAÇÃO DAS VALIDAÇÕES ANTERIORES

      -- Se OCORRERAN erros ao Validar Mínimo e Saldo Conta Corrente --------------------------------
      ELSE

        proc_registralog(p_regpedido.numped,
                         p_regpedido.numpedrca,
                         null,
                         null,
                         p_regpedido.cgccli,
                         null,
                         null,
                         null,
                         p_Regpedido.codusur,
                         p_Regpedido.dtaberturapedpalm,
                         null,
                         '2',
                         'Pedido rejeitado por erros ao analisar os itens faltantes: #' || vrRetGravacaoPed.vvMsgErros || ';', -- MED-2349
                         null,
                         null);

        -- Exclui Itens do Pedido
        delete from pcpedi
         where pcpedi.numped = p_regpedido.numped;
        -- Exclui Origem do Preço dos Itens do Pedido
        delete from pcorigempreco
         where numped = p_regpedido.numped;
        -- Exclui Pedido
        delete from pcpedc
         where numped = p_regpedido.numped;

        -- Marca Pedido como Inválido
        p_regpedido.valido := false;

      END IF; -- Fim Condição: Se OCORRERAN erros ao Validar Mínimo e Saldo Conta Corrente ----------

    -- Se NÃO conseguiu Locar Estoque
    ELSE

      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       null,
                       null,
                       p_regpedido.cgccli,
                       null,
                       null,
                       null,
                       p_Regpedido.codusur,
                       p_Regpedido.dtaberturapedpalm,
                       null,
                       '2',
                       'Pedido rejeitado por problemas ao locar o estoque: #' || vvMsgErroLocarEstoque || ';',
                       null,
                       null);

      -- Exclui Itens do Pedido
      delete from pcpedi
       where pcpedi.numped = p_regpedido.numped;
      -- Exclui Origem do Preço dos Itens do Pedido
      delete from pcorigempreco
       where numped = p_regpedido.numped;
      -- Exclui Pedido
      delete from pcpedc
       where numped = p_regpedido.numped;

      -- Marca Pedido como Inválido
      p_regpedido.valido          := false;
      p_regpedido.errolockestoque := 'S'; -- Motivo Lock Estoque

    END IF; -- Fim Condição: Se teve Sucesso ao Locar Estoque

    ---------------------------------------------
    -- Atualiza Log dos Itens do FV com as Faltas
    ---------------------------------------------

    -- Inicializa Arrays
    vtFTA_CODPROD.DELETE;
    vtFTA_CODAUXILIAR.DELETE;
    vtFTA_ESTOQUEDISP.DELETE;
    vtFTA_QTDEORIGINAL.DELETE;
    vtFTA_NUMSEQ.DELETE; -- DDMEDICA-198

    -- Insere Dados em Arrays
    EXECUTE IMMEDIATE 'SELECT T.CODPROD, P.CODAUXILIAR, T.ESTOQUEDISPONIVEL, T.QTDEORIGINAL, T.NUMSEQ FROM PCMED_FALTAS_ESTOQUE_RESERV T, PCPRODUT P WHERE (P.CODPROD = T.CODPROD) AND (T.QTDEFALTA > 0)'
       BULK COLLECT INTO vtFTA_CODPROD
                       , vtFTA_CODAUXILIAR
                       , vtFTA_ESTOQUEDISP
                       , vtFTA_QTDEORIGINAL
                       , vtFTA_NUMSEQ; -- DDMEDICA-198

    -- Se Achou Faltas
    IF (NVL(vtFTA_CODPROD.COUNT,0) > 0) THEN
      FOR viIdxItem IN vtFTA_CODPROD.FIRST..vtFTA_CODPROD.LAST LOOP

        -- DDMEDICA-198 - Pesquisa o NUMSEQ da PCPEDIFV
        BEGIN
          SELECT PCPEDIFV.NUMSEQ
            INTO vnnumseqifv
            FROM PCPEDIFV
           WHERE (PCPEDIFV.NUMPEDRCA         = p_regpedido.numpedrca)
             AND (PCPEDIFV.CGCCLI            = p_regpedido.cgccli)
             AND (PCPEDIFV.CODUSUR           = p_regpedido.codusur)
             AND (PCPEDIFV.DTABERTURAPEDPALM = p_regpedido.dtaberturapedpalm)
             AND (PCPEDIFV.CODPROD           = vtFTA_CODPROD(viIdxItem))
             AND (PCPEDIFV.NUMSEQITEMPEDMED  = vtFTA_NUMSEQ(viIdxItem))
             AND (ROWNUM                     = 1);
        EXCEPTION
          WHEN NO_DATA_FOUND THEN
            vnnumseqifv := NULL;
        END;

        proc_registralog(p_regpedido.numped,
                         p_regpedido.numpedrca,
                         vtFTA_CODPROD(viIdxItem),
                         vtFTA_CODAUXILIAR(viIdxItem),
                         p_regpedido.cgccli,
                         null,
                         null,
                         null,
                         p_regpedido.codusur,
                         p_regpedido.dtaberturapedpalm,
                         null,
                         '3',
                         'Produto sem estoque no momento da importação!;'||
                         'Qt Disponivel : '|| vtFTA_ESTOQUEDISP(viIdxItem) ||' Qt Pedida : '|| vtFTA_QTDEORIGINAL(viIdxItem) ||';',
                         null,
                         vnnumseqifv); -->> NUMSEQ DA PCPEDIFV

      END LOOP;
    END IF;

   /********************************************************************************************************
    FIM: HIS.04281.2017 - Refatoração do Estoque - Procedimento para Baixar Estoque e Atualizer Saldo RCA
    ********************************************************************************************************/

    -- Se Gravou Array de Log - MEDICA-477
    IF (vtLogImportacaoPed.COUNT > 0) THEN
      p_regpedido.logprocmed := p_regpedido.logprocmed || CHR(13) || CHR(13) ;
      FOR viIdxImportacaoPed IN vtLogImportacaoPed.FIRST..vtLogImportacaoPed.LAST LOOP
        -- Log Específico
        p_regpedido.logprocmed := p_regpedido.logprocmed || vtLogImportacaoPed(viIdxImportacaoPed) || CHR(13);
      END LOOP;
      p_regpedido.logprocmed := p_regpedido.logprocmed || CHR(13);
    END IF;

  exception
    when others then
      p_regpedido.valido := false;
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       null,
                       null,
                       p_Regpedido.cgccli,
                       null,
                       null,
                       null,
                       p_Regpedido.codusur,
                       p_regpedido.dtaberturapedpalm,
                       null,
                       '2',
                       sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->011->' || SQLERRM || ';',
                       null,
                       null);

      -- rollback;
      if nvl(p_regpedido.numpedorig, 0) = 0 then

        delete from pcpedc where pcpedc.numped = p_regpedido.numped;

        delete from pcpedi where pcpedi.numped = p_regpedido.numped;
        --      commit;
      end if;

  end proc_gravapedido;




  procedure proc_validacaofinalcab(p_regpedido        in out t_cabped,
                                   p_regcliente       in t_clientepedido,
                                   p_regplpag         in out t_planodepagamento,
                                   p_regplpagetico    in t_plpagetico,
                                   p_regplpaggenerico in t_plpaggenerico,
                                   p_regcob           in t_pccob,
                                   p_regfilial        in t_filial,
                                   p_regrca           in t_rca,
                                   p_contitensvalidos in number,
                                   p_vltotped         in number,
                                   p_vltotped_ant     in number,
                                   p_vltottab         in number,
                                   p_vlcustofin       in number) is

    vsmensagem             varchar2(32767);
    vschar                 varchar2(1) default '#';
    vnsaldodisponivel      number;
    vnnumeroparcelas       integer;
    vnvalorparcela         number;
    vsmensagem_vendapf     varchar2(1000);
    vnvlminpedido          pccob.vlminpedido%type;
    vnvlpedido             number;

    vstipovalorminimo      pccondicaovenda.tipovalorminimo%type;
    vnvalorminimocondicao  pccondicaovenda.valorminimoped%type;
    vnvltotvendabonificmes number := 0;
    vsmensagemprazovariavel varchar2(1000);

    vnperdesctot            number;
    vicontparc              number;
    vnvlminvendabk          number(18,6);
    vnperluc                number(18,6);
    vnmargemminaplicada     number; -- MED-2079

    -- MED-869
    TYPE TRetIntegradoraComple IS RECORD(
         vvValido              VARCHAR2(1),
         vnCodMotivoNaoAtend   NUMBER(10),
         vvMensagem            VARCHAR2(32767),
         vvMsgErros            VARCHAR2(32767));
    vrRetIntegradoraComple     TRetIntegradoraComple;

    -- Array para Armazenar o LOG da Importação do Item - MED-1503
    TYPE TTLogImportacaoPed     IS TABLE OF VARCHAR2(2000) INDEX BY BINARY_INTEGER;
    vtLogImportacaoPed          TTLogImportacaoPed;
    -- Array para Armazenar o JSON da Importação do Pedido - MED-1503
    TYPE TTJsonImportacaoPed    IS TABLE OF VARCHAR2(32000) INDEX BY BINARY_INTEGER;
    vtJsonImportacaoPed         TTJsonImportacaoPed;

    -- Record de Retorno das Validações - MED-1503
    TYPE TRecRetValidacao       IS RECORD(
         vvRejeitado            VARCHAR2(1),
         vvMotivoRejeitado      VARCHAR2(255),
         vvObservacao           VARCHAR2(32000),
         vvRetJson              VARCHAR2(32000),
         vvGravarComoBloqueado  VARCHAR2(1),
         vnValorRetorno         NUMBER,
         vvLogRetorno           VARCHAR2(32000));
    vrRetValidacao              TRecRetValidacao;

    -- MED-1499 - Retorno da Proc. de Gravação do Pedido
    TYPE TRecRetGravacaoPed    IS RECORD(
         vvRetorno             VARCHAR2(250),
         vvMsgErros            VARCHAR2(2000),
         vvPosicaoFinalPedido  VARCHAR2(1),
         vnCodMotivo           NUMBER,
         vvMotivoPosicao       VARCHAR2(2000),
         vvObservacaoMotivo    VARCHAR2(2000),
         vvExistemFaltas       VARCHAR2(1));
    vrRetGravacaoPed           TRecRetGravacaoPed;

    -- DDMEDICA-5009
    vvAlertasRevalidaPromocao   VARCHAR2(1);
    vvRejeicoesRevalidaPromocao VARCHAR2(1);

    -- PROCEDIMENTO PARA GRAVAÇÃO DO LOG DE TEXO GERAL DO PEDIDO
    PROCEDURE PGRAVA_LOG_TEXTO(pi_vMensagem IN VARCHAR2,
                               pi_vValor    IN VARCHAR2) IS
      vvMensagemLogImportacaoPed VARCHAR2(32000);
      viIdxLogImpPed             INTEGER;
    BEGIN
      viIdxLogImpPed := NVL(vtLogImportacaoPed.COUNT,0) + 1;

      vvMensagemLogImportacaoPed := '[' || TRIM(TO_CHAR(viIdxLogImpPed,'0000')) || '] ' || pi_vMensagem || ': ' || NVL(pi_vValor,' ');

      vtLogImportacaoPed(viIdxLogImpPed) := vvMensagemLogImportacaoPed;
    END PGRAVA_LOG_TEXTO;

    -- PROCEDIMENTO PARA GRAVAÇÃO DO LOG DE VALOR GERAL DO PEDIDO
    PROCEDURE PGRAVA_LOG_VALOR(pi_vMensagem IN VARCHAR2,
                               pi_nValor    IN NUMBER) IS
      vvMensagemLogImportacaoPed VARCHAR2(2000);
      viIdxLogImpPed             INTEGER;
    BEGIN
      viIdxLogImpPed := NVL(vtLogImportacaoPed.COUNT,0) + 1;

      vvMensagemLogImportacaoPed := '[' || TRIM(TO_CHAR(viIdxLogImpPed,'0000')) || '] ' || pi_vMensagem || ': ' || NVL(pi_nValor,0);

      vtLogImportacaoPed(viIdxLogImpPed) := SUBSTR(vvMensagemLogImportacaoPed,1,2000);
    END PGRAVA_LOG_VALOR;

    -- PROCEDIMENTO PARA GRAVAÇÃO DO JSON DE VALOR GERAL DO PEDIDO - MED-1503
    PROCEDURE PGRAVA_JSON_PED(pi_vMensagem IN VARCHAR2) IS
      viIdxJsonImpPed INTEGER;
    BEGIN
      viIdxJsonImpPed := NVL(vtJsonImportacaoPed.COUNT,0) + 1;

      vtJsonImportacaoPed(viIdxJsonImpPed) := pi_vMensagem;
    END PGRAVA_JSON_PED;

  begin

    -- Inicializa Log do Pedido - MED-1503
    vtLogImportacaoPed.DELETE;
    -- Inicializa Json do Pedido - MED-1503
    vtJsonImportacaoPed.DELETE;

    vsmensagem := null;


     --tarefa 147989
    if p_regplpag.formaparcelamento = 'V' and p_regpedido.numpedorig = 0 then

         select count(*)
           into vicontparc
           from pcpedcvcto
           where numped = p_regpedido.numped;


        if p_vltotped/vicontparc < p_regplpag.vlminparcela then


            if vsmensagem is null then

              vsmensagem := 'Valor da Parcela do pedido : '||round(p_vltotped/vicontparc,2)||' menor que o permitido : '|| p_regplpag.vlminparcela;

            else

              vsmensagem := vsmensagem||CHR(13)||'Valor da Parcela do pedido : '||round(p_vltotped/vicontparc,2)||' menor que o permitido : '|| p_regplpag.vlminparcela;

            end if;

        end if;

    end if;


     if p_regpedido.condvenda = 5 and p_regfilial.vlmaxvendabonificmes > 0 then

       begin
        select sum(round(nvl(pcpedi.qt, 0) * nvl(pcpedi.pvenda, 0), 2))
        into vnvltotvendabonificmes
        from pcpedi, pcpedc
        where pcpedc.numped = pcpedi.numped
         and pcpedc.dtcancel is null
         and to_char(pcpedc.data,'mm/yyyy') = to_char(trunc(sysdate),'mm/yyyy')
         and pcpedc.codfilial = p_regpedido.codfilial
         and pcpedc.condvenda in (5, 11)
         and pcpedc.numped <> p_regpedido.numped;
        exception when others then
          vnvltotvendabonificmes := 0 ;
        end ;


      if nvl(p_vltotped,0) + nvl(vnvltotvendabonificmes,0) > p_regfilial.vlmaxvendabonificmes then

        if vsmensagem is not null then
           vschar := '#';
        else
          vschar := null;
         end if;

        vsmensagem         := vsmensagem || vschar || 'O pedido nao podera ser gravado, por que o valor do pedido de(' ||
                            p_vltotped || ') + o valor de vendas bonificadas para este mês (' ||vnvltotvendabonificmes||' )#';
        vsmensagem         := vsmensagem || 'ultrapassa o valor de estipulado para bonificações no mês ('||p_regfilial.vlmaxvendabonificmes ||' );';

       p_regpedido.valido := false;

        if p_Regpedido.codmotivonaoatend is null then
                   p_regpedido.codmotivonaoatend := 34;

        end if;

      end if;


    end if;



    if p_regpedido.tipofv in ( 'OL','PE') then

      begin
      select p.tipovalorminimo,p.valorminimoped
      into vstipovalorminimo,vnvalorminimocondicao
      from pccondicaovenda p
      where p.codcondicaovenda = p_regpedido.codcondicaovenda;
      exception when others then

        vstipovalorminimo := null;

      end;
    end if;

      --tarefa 211580
  if p_vltotped > gregpcconsum.vlmaxvenda and nvl(gregpcconsum.vlmaxvenda,0) > 0 then

     if gregpcconsum.aceitavendabloq = 'S' then
        p_regpedido.posicao := 'B';
        p_regpedido.codmotivo := 4;
        p_regpedido.motivoposicao := 'Pedido excede valor maximo por pedido.';
     else
        p_regpedido.valido := false;
     end if;

        if vsmensagem is not null then
           vschar := '#';
        else
          vschar := null;
         end if;

        vsmensagem         := vsmensagem || vschar || 'Valor do pedido de(' ||
                            p_vltotped || ') execede o valor maximo estipulado por pedido (' ||gregpcconsum.vlmaxvenda||' ).';

        if p_regpedido.codmotivonaoatend is null then
         p_regpedido.codmotivonaoatend := 16;

      end if;


  end if;




   /* INICIO: MED-1499 - Melhoria de Mensagens - Passou a ser validado na procedure de gravação do pedido
    -- 5666.058584.2016 - Valor Mínimo Pós Corte
    if p_regpedido.tipofv in ('OL','PE') and vstipovalorminimo IN ('C','A') then


          if p_vltotped < vnvalorminimocondicao then


              if vsmensagem is not null then
                vschar := '#';
              else
                vschar := null;
              end if;
              vsmensagem         := vsmensagem || vschar || 'Valor do pedido antes do corte (' ||
                                    p_vltotped || ') menor que o#';
              vsmensagem         := vsmensagem || 'mínimo (' || vnvalorminimocondicao || ') da condicao de venda: ' ||
                                    p_regpedido.codcondicaovenda || ';';

               p_regpedido.valido := false;

                if p_Regpedido.codmotivonaoatend is null then
                   p_regpedido.codmotivonaoatend := 34;

                end if;


            end if;

    else

    begin
      select nvl(pccob.vlminpedido, 0)
        into vnvlminpedido
        from pccob
       where codcob = p_regpedido.codcob;
    exception
      when others then
        vnvlminpedido := 0;
    end;

    if p_vltotped < vnvlminpedido then


      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem         := vsmensagem || vschar || 'Valor do pedido (' ||
                            p_vltotped || ') menor que o#';
      vsmensagem         := vsmensagem || 'mínimo para a cobranca: ' ||
                            p_regpedido.codcob || ';';

           if gregpcconsum.aceitavendabloq = 'S' then
             p_regpedido.posicao := 'B';
             p_regpedido.codmotivo := 9;
             p_regpedido.motivoposicao := 'Valor do pedido menor que minimo para cobranca';

           else
              p_regpedido.valido := false;
           end if;



        if p_Regpedido.codmotivonaoatend is null then
           p_regpedido.codmotivonaoatend := 34;

        end if;


    end if;

    end if;
    FIM: MED-1499 - Melhoria de Mensagens - Passou a ser validado na procedure de gravação do pedido*/


    /*MED-1499 - Trocada por uma Função
    --tarefa 142808
    if p_regpedido.condvenda not in (4,5,8) then

        if nvl(p_regfilial.permaxdescvenda,0) > 0 then

             if p_vltottab <> 0 then
                vnperdesctot := ROUND((((p_vltottab - p_vltotped) / p_vltottab) * 100),
                                      gregpcconsum.numcasasdecvenda);
              else
                vnperdesctot := 0;
              end if;

          if vnperdesctot > nvl(p_regfilial.permaxdescvenda,0) then

              if vsmensagem is not null then
                vschar := '#';
              else
                vschar := null;
              end if;
              vsmensagem         := vsmensagem || vschar || 'Percentual médio de desconto do pedido (' ||
                                    vnperdesctot || ') maior que o#';
              vsmensagem         := vsmensagem || 'máximo cadastrado por filial: ' ||
                                    nvl(p_regfilial.permaxdescvenda,0) || ';';

               p_regpedido.valido := false;

             if p_Regpedido.codmotivonaoatend is null then
                p_regpedido.codmotivonaoatend := 34;

            end if;


          end if;

        else
          if nvl(gregpcconsum.permaxdescvenda,0) > 0 then


             if p_vltottab <> 0 then
                vnperdesctot := ROUND((((p_vltottab - p_vltotped) / p_vltottab) * 100),
                                      gregpcconsum.numcasasdecvenda);
              else
                vnperdesctot := 0;
              end if;

                  if vnperdesctot > nvl(gregpcconsum.permaxdescvenda,0) then

                       if vsmensagem is not null then
                            vschar := '#';
                          else
                            vschar := null;
                          end if;
                          vsmensagem         := vsmensagem || vschar || 'Percentual médio de desconto do pedido (' ||
                                                vnperdesctot || ') maior que o#';
                          vsmensagem         := vsmensagem || 'máximo cadastrado para a empresa: ' ||
                                                nvl(gregpcconsum.permaxdescvenda,0) || ';';

                           p_regpedido.valido := false;

                          if p_Regpedido.codmotivonaoatend is null then
                             p_regpedido.codmotivonaoatend := 34;

                          end if;

                  end if;

          end if;

        end if;
     end if;
   */
    -----------------------------------------------------------
    -- INICIO: MED-1499 - Validação de Desconto Médio do Pedido
    BEGIN
      INTEGRADORACOMPLE_MED.proc_validadescmediopedido(p_regpedido.codfilial,
                                                       p_regpedido.condvenda,
                                                       p_regfilial.permaxdescvenda,
                                                       gregpcconsum.permaxdescvenda,
                                                       p_vltottab,
                                                       p_vltotped,
                                                       gregpcconsum.numcasasdecvenda,
                                                       p_regfilial.IGNORARPERMAXDESCVENDA, -- MED-2574
                                                       vrRetValidacao.vvRejeitado,
                                                       vrRetValidacao.vvMotivoRejeitado,
                                                       vrRetValidacao.vvObservacao,
                                                       vrRetValidacao.vvRetJson);
      IF (vrRetValidacao.vvRejeitado = 'S') THEN

        -- Não é mais Válido
        p_regpedido.valido := false;
        -- Atualiza Mensagem
        P_ADD_MENSAGEM('Rejeição 34: ' || vrRetValidacao.vvObservacao,
                       34,
                       vsmensagem,
                       p_Regpedido.codmotivonaoatend);
        -- Grava Json
        PGRAVA_JSON_PED(vrRetValidacao.vvRetJson);

      END IF;

    EXCEPTION
      WHEN OTHERS THEN
        -- Não é mais Válido
        p_regpedido.valido := false;
        -- Atualiza Mensagem
        P_ADD_MENSAGEM('Erro ao validar percentual médio de desconto do pedido. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                       34,
                       vsmensagem,
                       p_Regpedido.codmotivonaoatend);
    END;
    -- Grava LOG (Pra poder depois analisar o motivo do primeiro processamento que rejeitou antes de reprocessar)
    PGRAVA_LOG_TEXTO('PERMAXDESCVENDA',p_regfilial.permaxdescvenda);
    PGRAVA_LOG_TEXTO('IGNORARPERMAXDESCVENDA',p_regfilial.IGNORARPERMAXDESCVENDA);
    -- FIM:  MED-1499 - Validação de Desconto Médio do Pedido
    ---------------------------------------------------------

  /* INICIO: MED-1499 - Melhoria de Mensagens - Passou a ser validado na procedure de gravação do pedido
    --Por rca
   if nvl(p_Regrca.vlvendaminped,0) > 0 then

       if p_vltotped < nvl(p_Regrca.vlvendaminped,0) then

         if vsmensagem is not null then
           vschar := '#';
         else
          vschar := null;
         end if;

            vsmensagem         := vsmensagem || vschar || 'Valor do pedido (' ||
                                  p_vltotped||  ') menor que o#' || ';';
            vsmensagem         := vsmensagem || 'mínimo permitido para o RCA: ' ||
                                  p_regrca.vlvendaminped || ';';

           if gregpcconsum.aceitavendabloq = 'S' then
             p_regpedido.posicao := 'B';
             p_regpedido.codmotivo := 8;
             p_regpedido.motivoposicao := 'Valor do pedido menor que minimo para RCA';

           else
              p_regpedido.valido := false;
           end if;


       end if;

   end if;
   FIM: MED-1499 - Melhoria de Mensagens - Passou a ser validado na procedure de gravação do pedido*/


  /* INICIO: MED-1499 - Melhora de Mensagens - Valor Minimo e Qtde Mínima de Itens do Plano Pagamento
   --MED-869--O valor mínimo do plano de pagamento não tem restrição de antes e após o corte, somente o valor mínimo da condição
   --if (p_regpedido.tipofv in ('OL','PE') and vstipovalorminimo <> 'C') or p_regpedido.tipofv not in ('OL','PE') then

    if p_regfilial.utilizacontrolemedicamentos = 'S' and p_regcliente.utilizaplpagmedicamento = 'S' then

       -------------------------------------------------------------------------
       -- MED-869 - Validar Valor Mínimo do Plano Ético e Genérico do Cliente
       --           Criado Procedimento que pode ser usado antes ou após o corte
       --           Aqui é Antes o Corte
       -------------------------------------------------------------------------
       RECOMPILAR_DEPENDENCIAS;
       INTEGRADORACOMPLE_MED.proc_validaminplanosmed(p_regpedido.codplpagetico,
                                                     p_regpedido.codplpaggenerico,
                                                     p_regpedido.numped,
                                                     vrRetIntegradoraComple.vvValido,
                                                     vrRetIntegradoraComple.vnCodMotivoNaoAtend,
                                                     vrRetIntegradoraComple.vvMensagem,
                                                     vrRetIntegradoraComple.vvMsgErros);
       IF (vrRetIntegradoraComple.vvValido = 'N') THEN
         if vsmensagem is not null then
           vschar := '#';
         else
           vschar := null;
         end if;
         vsmensagem := vsmensagem || vschar || vrRetIntegradoraComple.vvMensagem;
         IF (NVL(vrRetIntegradoraComple.vnCodMotivoNaoAtend,0) > 0) THEN
           p_regpedido.codmotivonaoatend := vrRetIntegradoraComple.vnCodMotivoNaoAtend;
         END IF;
         p_regpedido.valido := false; -->> Pedido não é mais Válido
       END IF;

    else

        if p_contitensvalidos < p_regplpag.numitensminimo then

          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;

          vsmensagem         := vsmensagem || vschar || 'Numero de itens (' ||
                                p_contitensvalidos || ') menor que o#';
          vsmensagem         := vsmensagem ||
                                'mínimo para o plano de pagamento: ' ||
                                p_regplpag.codplpag || ';';
          p_regpedido.valido := false;


          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 35;

          end if;

        end if;

        if p_vltotped < p_regplpag.vlminpedido then


          if p_regfilial.bloquearpedidosabaixovlminimo = 'S' then

            p_regpedido.posicao := 'B';
            p_regpedido.codmotivo := 10;
            p_Regpedido.motivoposicao := 'Valor do pedido menor que o minimo para Plano de Pagamento';
            p_regpedido.log := p_regpedido.log||CHR(13)||'Valor do pedido menor que o minimo para Plano de Pagamento';

          else

             p_regpedido.valido := false;

          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 34;

          end if;


          end if;


          if vsmensagem is not null then
            vschar := '#';
          else
            vschar := null;
          end if;

          vsmensagem         := vsmensagem || vschar || 'Valor do pedido (' ||
                                p_vltotped || ') menor que o#';
          vsmensagem         := vsmensagem ||
                                'mínimo para o plano de pagamento: ' ||
                                p_regplpag.codplpag || ';';


        end if;

    end if;

   --MED-869--O valor mínimo do plano de pagamento não tem restrição de antes e após o corte, somente o valor mínimo da condição
   --end if;
   FIM: MED-1499 - Melhora de Mensagens - Valor Minimo e Qtde Mínima de Itens do Plano Pagamento*/

    ----------------------------------------------------------------------------------------
    ----------------------------------------------------------------------------------------
    -- Validação das Promoções - DDMEDICA-5009
    ----------------------------------------------------------------------------------------
    ----------------------------------------------------------------------------------------
    PKG_GRAVACAO_PEDIDO_MED.P_REVALIDA_PROMOCAO('2513', -- pi_vOrigemChamada
                                                8888, -- pi_nMatricula
                                                p_regpedido.numped,
                                                p_regpedido.codcli,
                                                p_regpedido.codusur,
                                                p_regpedido.codplpag,
                                                p_regpedido.codplpagetico,
                                                p_regpedido.codplpaggenerico,
                                                p_regpedido.codcob,
                                                p_regpedido.codpromocaomed,
                                                p_regcliente.numregiao,
                                                p_regpedido.codfilial,
                                                p_regpedido.codfilialnf,
                                                p_regpedido.origemped,
                                                p_regpedido.tipofv,
                                                p_regpedido.codcondicaovenda,
                                                vvAlertasRevalidaPromocao,
                                                vvRejeicoesRevalidaPromocao);
    -- Grava Log
    PGRAVA_LOG_TEXTO('AlertasRevalidaPromocao = ',vvAlertasRevalidaPromocao);
    PGRAVA_LOG_TEXTO('RejeicoesRevalidaPromocao = ',vvRejeicoesRevalidaPromocao);

    ----------------------------------------------------------------------------------------
    ----------------------------------------------------------------------------------------
    -- Chama Procedimento para Validar Mínimos e NÃO VALIDAR Saldo Conta Corrente - MED-1499
    ----------------------------------------------------------------------------------------
    ----------------------------------------------------------------------------------------
    BEGIN
      PKG_GRAVACAO_PEDIDO_MED.P_GRAVACAO_PEDIDO_01(2513, -- pi_nCodRotina
                                                   p_regpedido.numped,
                                                   p_regpedido.codusur,
                                                   8888, -- pi_nMatricula
                                                   'N',  -- pi_vGuardaFalta >> NÃO GUARDAR FALTAS AQUI
                                                   'N',  -- pi_vGravarPedidoItensFalta >> NÃO GERAR PEDIDO FALTAS AQUI
                                                   NULL, -- pi_nNumPedidoItensFalta
                                                   'N',  -- pi_vMovimentarSaldoRca >> NÃO VALIDAR CONTA CORRENTE AQUI
                                                   'VM', -- pi_vChamadaProcesso
                                                   p_regpedido.posicao,
                                                   'N',  -- pi_vBrindes
                                                   NULL, -- pi_nCodProdEdicao
                                                   vrRetGravacaoPed.vvRetorno,
                                                   vrRetGravacaoPed.vvMsgErros,
                                                   vrRetGravacaoPed.vvPosicaoFinalPedido,
                                                   vrRetGravacaoPed.vnCodMotivo,
                                                   vrRetGravacaoPed.vvMotivoPosicao,
                                                   vrRetGravacaoPed.vvObservacaoMotivo,
                                                   vrRetGravacaoPed.vvExistemFaltas,
                                                   p_regpedido.codfilial,
                                                   p_regpedido.codcli,
                                                   p_regpedido.condvenda,
                                                   p_regpedido.codplpag,
                                                   p_regpedido.codplpagetico,
                                                   p_regpedido.codplpaggenerico,
                                                   p_regpedido.codcob,
                                                   p_regpedido.data,
                                                   p_regpedido.origemped,
                                                   p_regpedido.tipofv,
                                                   p_regpedido.integradora,
                                                   p_regpedido.codcondicaovenda,
                                                   p_regpedido.codusur,
                                                   'N',   -- pi_vVendaAssistida
                                                   0,     -- pi_nVlDescNeg
                                                   null,  -- pi_vPedidoAvaria,
                                                   null,  -- pi_nNumTransEntCrossDock,
                                                   null,  -- pi_vGeraCP,
                                                   null,  -- pi_nNumTransEntOrigConsig,
                                                   null,  -- pi_nNumTransEntOrigTrocaNota,
                                                   p_regpedido.codmotivo,
                                                   null,  -- pi_nCodMotivoBloqueio,
                                                   p_regpedido.motivoposicao,
                                                   p_regpedido.integradora,
                                                   p_regpedido.codpromocaomed,
                                                   p_regpedido.faturamentointegral, -- DDMEDICA-6533
                                                   p_regpedido.totunidades,
                                                   p_regcliente.numregiao);        -- DDMEDICA-6533

      --------------------------------------------
      -- Laço de Retorno com os Motivo de Rejeição
      --------------------------------------------
      FOR vc_Motivo IN (SELECT PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO
                             , PCMED_VALIDACAO_ESTOQUE_RESERV.TIPOREJEICAO
                             , PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTIVO
                             , PCMED_VALIDACAO_ESTOQUE_RESERV.MOTIVOPOSICAO
                             , (PCMED_VALIDACAO_ESTOQUE_RESERV.DESCRICAOREJEICAO || CHR(13) || PCMED_VALIDACAO_ESTOQUE_RESERV.OBSERVACAO) OBSERVACAO
                             , PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTIVONAOATEND
                             , PCMED_VALIDACAO_ESTOQUE_RESERV.CODROTINAS
                             , PCMED_VALIDACAO_ESTOQUE_RESERV.NUMEROPARAMETRO
                             , PCMED_VALIDACAO_ESTOQUE_RESERV.PERMISSAO
                             , PCMED_VALIDACAO_ESTOQUE_RESERV.SOLUCAOP1
                          FROM PCMED_VALIDACAO_ESTOQUE_RESERV
                         WHERE (PCMED_VALIDACAO_ESTOQUE_RESERV.ACAO IN ('P','B','A'))
                           AND (PCMED_VALIDACAO_ESTOQUE_RESERV.CODMOTIVONAOATEND > 0) -->> AQUI SOMENTE OS MOTIVOS TRATADOS
                         ) LOOP

         -- Se grava o Pedido como Bloqueado
         IF    (vc_Motivo.ACAO IN ('P','B')) THEN

           p_regpedido.posicao       := 'B';
           p_regpedido.motivoposicao := vc_Motivo.MOTIVOPOSICAO;
           p_regpedido.codmotivo     := vc_Motivo.CODMOTIVO;
           -- Atualiza Mensagem
           P_ADD_MENSAGEM('Bloqueio ' || vc_Motivo.CODMOTIVO || ': ' || vc_Motivo.OBSERVACAO,
                          NULL, -->> Não altera a variável p_regpedido.codmotivonaoatend
                          vsmensagem,
                          p_regpedido.codmotivonaoatend);
           -- Registra novo Motivo
           proc_registralogbloqueio(p_regpedido.numpedrca,
                                    p_regpedido.codusur,
                                    p_regpedido.cgccli,
                                    p_regpedido.dtaberturapedpalm,
                                    p_regpedido.codmotivo,
                                    NULL,
                                    p_regpedido.motivoposicao);

         -- Se houver alguma Ação para Bloquear o Pedido
         ELSE

          -- Não é mais Válido
          p_regpedido.valido := False;
          -- Atualiza Mensagem
          P_ADD_MENSAGEM('Rejeição ' || vc_Motivo.CODMOTIVONAOATEND || ': ' || vc_Motivo.OBSERVACAO,
                         vc_Motivo.CODMOTIVONAOATEND,
                         vsmensagem,
                         p_regpedido.codmotivonaoatend);

         END IF;

         -- Gerar JSON
         vrRetValidacao.vvRetJson := INTEGRADORACOMPLE_MED.func_gerarlogjson(vc_Motivo.TIPOREJEICAO,
                                                                             vc_Motivo.OBSERVACAO,
                                                                             vc_Motivo.CODROTINAS,
                                                                             vc_Motivo.NUMEROPARAMETRO,
                                                                             vc_Motivo.PERMISSAO,
                                                                             vc_Motivo.SOLUCAOP1 || CHR(13) || 'Após revisão dos cadastros, o Pedido poderá ser reprocessado na Consulta de Pedidos da Rotina 2302, na aba "Pedidos", podendo ser feita a multi-seleção de Pedidos para reprocessamento.');

        -- Grava Json
        PGRAVA_JSON_PED(vrRetValidacao.vvRetJson);

      END LOOP; -- Fim: Laço de Retorno com os Motivo de Rejeição
    EXCEPTION
      WHEN OTHERS THEN
        -- Não é mais Válido
        p_regpedido.valido := false;
        -- Atualiza Mensagem
        P_ADD_MENSAGEM('Erro ao validar valores mínimos do plano de pagamento do pedido. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                       34,
                       vsmensagem,
                       p_Regpedido.codmotivonaoatend);
    END;
    -- FIM:  MED-1499 - Validação de Mínimos do Pedido
    --------------------------------------------------


   --tarefa 193104
   -- 4493.064633.2016 - Tratamento de Erro por Divisão por Zero
   BEGIN
     select round((((p_vltotped - p_vlcustofin) / p_vltotped) * 100),gregpcconsum.numcasasdecvenda)
     into vnperluc
     from dual;
   EXCEPTION
     WHEN ZERO_DIVIDE THEN
       vnperluc := 0;
   END;

   /*INICIO: MED-2079 - Alterada forma de validar a Magem Mínima
    -- Operador Logístico não possui crítica de margem mínima (Descontos da Industria)
    if (nvl(p_Regpedido.tipofv,'FV') <> 'OL') then
      if vnperluc < p_regplpag.margemmin and nvl(p_regplpag.margemmin,0) > 0 then

        if p_regfilial.bloqpedabaixomargemfv = 'S' then
          p_regpedido.posicao := 'B';
          p_regpedido.codmotivo := 16;

          p_Regpedido.motivoposicao := 'Margem de lucratividade do pedido menor que minima o';
          p_regpedido.log := p_regpedido.log||CHR(13)||'Margem de lucratividade do pedido menor que a minima';

        else
           p_regpedido.valido := false;
        end if;



        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;

        vsmensagem         := vsmensagem || vschar || 'Margem de lucratividade do pedido (' ||
                              vnperluc || ') menor que a#';
        vsmensagem         := vsmensagem ||
                              'mínima para o plano de pagamento: ' ||
                              p_regplpag.codplpag || ';';


      end if;
    end if;
    FIM: MED-2079 - Alterada forma de validar a Magem Mínima */

    ---------------------------------------------------------------
    -- INICIO: MED-2079 - Validação da Margem Minima
    BEGIN
      INTEGRADORACOMPLE_MED.proc_validamargemminima(p_regpedido.origemped,
                                                    p_regpedido.tipofv,
                                                    p_regpedido.codfilial,
                                                    p_regfilial.validarmargemminimaolpe,
                                                    p_regfilial.percmargemminvendamed,
                                                    p_regfilial.tipovalidmargemminvendamed,
                                                    p_regplpag.codplpag,
                                                    p_regplpag.margemmin,
                                                    vnperluc,
                                                    p_regfilial.bloqpedabaixomargemfv,
                                                    vrRetValidacao.vvRejeitado,
                                                    vrRetValidacao.vvMotivoRejeitado,
                                                    vrRetValidacao.vvObservacao,
                                                    vrRetValidacao.vvRetJson,
                                                    vrRetValidacao.vvGravarComoBloqueado,
                                                    vnmargemminaplicada);
      IF (vrRetValidacao.vvRejeitado = 'S') THEN

        -- Se grava o Pedido como Bloqueado
        IF (NVL(vrRetValidacao.vvGravarComoBloqueado,'N') = 'S') THEN
          p_regpedido.posicao       := 'B';
          p_regpedido.motivoposicao := vrRetValidacao.vvMotivoRejeitado;
          p_regpedido.codmotivo     := 16;
          -- Atualiza Mensagem
          P_ADD_MENSAGEM('Bloqueio 34: ' || vrRetValidacao.vvObservacao,
                         NULL, -->> Não altera a variável p_regpedido.codmotivonaoatend
                         vsmensagem,
                         p_regpedido.codmotivonaoatend);
          -- Registra novo Motivo
          proc_registralogbloqueio(p_regpedido.numpedrca,
                                   p_regpedido.codusur,
                                   p_regpedido.cgccli,
                                   p_regpedido.dtaberturapedpalm,
                                   p_regpedido.codmotivo,
                                   NULL,
                                   p_regpedido.motivoposicao);
        ELSE
           p_regpedido.valido := FALSE;
           -- Não é mais Válido
           p_regpedido.valido := False;
           -- Atualiza Mensagem
           P_ADD_MENSAGEM('Rejeição 34: ' || vrRetValidacao.vvObservacao,
                          34,
                          vsmensagem,
                          p_regpedido.codmotivonaoatend);
        END IF;

        -- Grava Json
        PGRAVA_JSON_PED(vrRetValidacao.vvRetJson);

        -- Grava LOG (Pra poder depois analisar o motivo do primeiro processamento que rejeitou antes de reprocessar)
        PGRAVA_LOG_TEXTO('RetJson',vrRetValidacao.vvRetJson);

      END IF;

      -- Guarda a Margem do Pedido para Mensagem se Pedido OL e PE
      IF (NVL(p_Regpedido.tipofv,'FV') IN ('OL','PE')) AND
         (NVL(p_regfilial.validarmargemminimaolpe,'N') = 'S') THEN
        IF (NVL(p_regfilial.tipovalidmargemminvendamed,'0') IN ('2','3')) OR
           (NVL(p_regplpag.margemmin,0) > 0) THEN
          p_regpedido.margempedido      := vnperluc;
          p_regpedido.margemminaplicada := vnmargemminaplicada;
        END IF;
      END IF;

      -- Grava Log
      PGRAVA_LOG_TEXTO('Margem Pedido = ',vnperluc); -- LOG
      PGRAVA_LOG_TEXTO('Margem Mínima = ',vnmargemminaplicada); -- LOG

    EXCEPTION
      WHEN OTHERS THEN
        -- Não é mais Válido
        p_regpedido.valido := False;
        -- Atualiza Mensagem
        P_ADD_MENSAGEM('Erro ao validar margem minima. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                       34,
                       vsmensagem,
                       p_regpedido.codmotivonaoatend);
    END;
    -- FIM:  MED-1499 - MED-2079 - Validação da Margem Minima
    ---------------------------------------------------------

    -- MED-1499 - Log
    PGRAVA_LOG_TEXTO('Informações para Validação do Limite de Crédito',''); -- LOG
    PGRAVA_LOG_TEXTO('verificalimcredcodcobd',gregpcconsum.verificalimcredcodcobd); -- LOG
    PGRAVA_LOG_TEXTO('codcob',p_regpedido.codcob); -- LOG
    PGRAVA_LOG_TEXTO('cartao',p_regcob.cartao); -- LOG
    PGRAVA_LOG_TEXTO('bloqpedlimcred',NVL(p_regfilial.bloqpedlimcred, 'N')); -- LOG
    PGRAVA_LOG_TEXTO('Limite Crédito: Posicao Anterior = ',p_regpedido.posicao); -- LOG

    if (nvl(gregpcconsum.verificalimcredcodcobd, 'S') = 'S' and
       (p_regpedido.codcob in ('D', 'DH') or p_regcob.cartao = 'S' ) ) or
       (p_regpedido.codcob not in ('D', 'DH') and p_regcob.cartao = 'N' ) then

      select decode(p_regpedido.numpedorig,
                    0,
                    p_vltotped,
                    p_vltotped - p_vltotped_ant)
        into vnvlpedido
        from dual;

      if p_regplpag.tipoentrada = 3 and p_regplpag.descentlimcredcli = 'S' then
        vnvlpedido := vnvlpedido - nvl(p_regpedido.vlentrada,0) ;

      end if;


     /*
      MED-1499 - Substituída pela INTEGRADORACOMPLE_MED.proc_validacreditocliente
      -- Caso ultrapasse o limite de cred, grava o pedido como bloqueado.
      if not func_existelimitecliente(p_regpedido,
                                      p_regcliente,
                                      p_regfilial,
                                      vnvlpedido,
                                      vnsaldodisponivel) then
        if nvl(p_regpedido.numpedorig, 0) = 0 then

          if NVL(p_regfilial.bloqpedlimcred, 'N') = 'S' then
            p_regpedido.posicao := 'B';

            p_regpedido.codmotivo := 3;
            p_Regpedido.motivoposicao := 'Cliente sem limite de credito';
            p_regpedido.log := p_regpedido.log||CHR(13)||'Cliente sem limite de credito';

          else
            p_regpedido.valido := false;

          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 36;

          end if;


          end if;

        else
          if p_regpedido.posicao <> 'B' then
            p_regpedido.valido := false;

            if p_regpedido.codmotivonaoatend is null then
               p_regpedido.codmotivonaoatend := 36;

            end if;


          end if;
        end if;

        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;

        vsmensagem := vsmensagem || vschar || 'Pedido ultrapassa credito#';
        vsmensagem := vsmensagem || 'disponivel do cliente#';
        vsmensagem := vsmensagem || 'Valor do Pedido   : ' || p_vltotped || '#';
        vsmensagem := vsmensagem || 'Credito disponivel: ' ||
                      vnsaldodisponivel || ';';

      end if;
      */

      ---------------------------------------------------------------
      -- INICIO: MED-1499 - Validação do Limite de Crédito do Cliente
      BEGIN
        INTEGRADORACOMPLE_MED.proc_validacreditocliente(p_regpedido.numped,
                                                        p_regpedido.codcli,
                                                        p_regcliente.codcliprinc,
                                                        p_regpedido.codusur,
                                                        p_regcliente.limcred,
                                                        vnvlpedido,
                                                        p_regfilial.somacreditocliprincipal,
                                                        p_regfilial.usabnflimitecredito,
                                                        gregpcconsum.perexcedelimcred,
                                                        gregpcconsum.numcasasdecvenda,
                                                        'S', -->> Atualizar Autorização de Crédito adicional se houver
                                                        p_regfilial.bloqpedlimcred,
                                                        vrRetValidacao.vvRejeitado,
                                                        vrRetValidacao.vvMotivoRejeitado,
                                                        vrRetValidacao.vvObservacao,
                                                        vrRetValidacao.vvRetJson,
                                                        vrRetValidacao.vvGravarComoBloqueado,
                                                        vrRetValidacao.vnValorRetorno,
                                                        vrRetValidacao.vvLogRetorno); -- DDMEDICA-3551
        IF (vrRetValidacao.vvRejeitado = 'S') THEN

          IF (NVL(p_regpedido.numpedorig, 0) = 0) THEN

            -- Se grava o Pedido como Bloqueado
            IF (NVL(vrRetValidacao.vvGravarComoBloqueado,'N') = 'S') THEN
               p_regpedido.posicao       := 'B';
               p_regpedido.motivoposicao := 'Cliente sem limite de credito / data vecto limite credito.';
               p_regpedido.codmotivo     := 3;
               -- Atualiza Mensagem
               P_ADD_MENSAGEM('Bloqueio 36: ' || vrRetValidacao.vvObservacao,
                              NULL, -->> Não altera a variável p_regpedido.codmotivonaoatend
                              vsmensagem,
                              p_regpedido.codmotivonaoatend);
              -- Registra novo Motivo
              proc_registralogbloqueio(p_regpedido.numpedrca,
                                       p_regpedido.codusur,
                                       p_regpedido.cgccli,
                                       p_regpedido.dtaberturapedpalm,
                                       p_regpedido.codmotivo,
                                       NULL,
                                       p_regpedido.motivoposicao);
            -- Se Rejeita o Pedido
            ELSE
              -- Não é mais Válido
              p_regpedido.valido := False;
              -- Atualiza Mensagem
              P_ADD_MENSAGEM('Rejeição 36: ' || vrRetValidacao.vvObservacao,
                             36,
                             vsmensagem,
                             p_regpedido.codmotivonaoatend);
            END IF;

          ELSE

            IF (p_regpedido.posicao <> 'B') then
              -- Não é mais Válido
              p_regpedido.valido := false;
              -- Atualiza Mensagem
              P_ADD_MENSAGEM('Rejeição 36: ' || vrRetValidacao.vvObservacao,
                             36,
                             vsmensagem,
                             p_regpedido.codmotivonaoatend);
            END IF;

          END IF;

          -- Grava Json
          PGRAVA_JSON_PED(vrRetValidacao.vvRetJson);

          -- Grava LOG (Pra poder depois analisar o motivo do primeiro processamento que rejeitou antes de reprocessar)
          PGRAVA_LOG_TEXTO('RetJson',vrRetValidacao.vvRetJson);

        END IF;

        -- Grava Log
        PGRAVA_LOG_TEXTO('Limite Crédito: Rejeitado = ',vrRetValidacao.vvRejeitado); -- LOG
        PGRAVA_LOG_TEXTO('Limite Crédito: Posicao = ',p_regpedido.posicao); -- LOG

      EXCEPTION
        WHEN OTHERS THEN
          -- Não é mais Válido
          p_regpedido.valido := False;
          -- Atualiza Mensagem
          P_ADD_MENSAGEM('Erro ao validar limite de crédito do cliente. '||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                         36,
                         vsmensagem,
                         p_regpedido.codmotivonaoatend);
      END;
      -- FIM:  MED-1499 -  Validação do Limite de Crédito do Cliente
      --------------------------------------------------------------

      --p_regpedido.vlsaldodisponivelcli := vnsaldodisponivel;
      p_regpedido.vlsaldodisponivelcli := vrRetValidacao.vnValorRetorno; -->> Valor Retornado pela Validação do Limite de Crédito - MED-1499

      -- MED-1499 - Log
      PGRAVA_LOG_TEXTO('vnvlpedido',vnvlpedido); -- LOG
      PGRAVA_LOG_TEXTO('vlsaldodisponivelcli',p_regpedido.vlsaldodisponivelcli); -- LOG
      -- DDMEDICA-3551
      BEGIN
        PGRAVA_LOG_TEXTO('Det. Saldo Disp.',vrRetValidacao.vvLogRetorno);
      EXCEPTION
        WHEN OTHERS THEN
          PGRAVA_LOG_TEXTO('Det. Saldo Disp.',SQLERRM);
      END;

    end if;


        PGRAVA_LOG_TEXTO('UF Entrega na Validação Final do Cabeçalho',p_regcliente.estent); -- DDVENDAS-33718

        if nvl(gregpcconsum.travavendapf, 'N') = 'S' and
           ((p_regcliente.tipofj = 'F' and p_regcliente.contribuinte = 'N') or
             (p_regcliente.CONSUMIDORFINAL = 'S') or
             ((gregpcconsum.CONSIDERAISENTOSCOMOPF = 'S') and
             ((trim(p_regcliente.IEENT) = '') or
              (p_regcliente.ieent is null) or
             (Upper(p_regcliente.IEENT) = 'ISENTA') or
             (Upper(p_regcliente.ieent) = 'ISENTO')))) then
          p_regpedido.valido := false;
          vsmensagem         := vsmensagem || vschar ||
                                'VENDA PARA PESSOA FISICA NAO PERMITIDA.';

          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 16;

          end if;

        end if;

        if (nvl(p_regfilial.permitirvendainterestadualpf, 'S') = 'N') and
           ((p_regcliente.estent <> p_regfilial.uf) and
           ((p_regcliente.tipofj = 'F' and p_regcliente.contribuinte = 'N') or
             (p_regcliente.CONSUMIDORFINAL = 'S') or
             ((gregpcconsum.CONSIDERAISENTOSCOMOPF = 'S') and
             ((trim(p_regcliente.IEENT) = '') or
              (p_regcliente.ieent is null) or
             (Upper(p_regcliente.IEENT) = 'ISENTA') or
             (Upper(p_regcliente.ieent) = 'ISENTO'))))) then
          p_regpedido.valido := false;
          vsmensagem         := vsmensagem || vschar ||
                                'VENDA INTERESTADUAL PARA PESSOA FISICA NAO PERMITIDA NESTA FILIAL';

          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 16;

          end if;

        end if;


    if ((nvl(p_regfilial.permitirvendaestadualpfcomie, 'S') = 'N') and
       (p_regcliente.estent = p_regfilial.uf) and
       ((p_regcliente.tipofj = 'F') and (p_regcliente.CONTRIBUINTE = 'N') and
       (trim(upper(p_regcliente.ieent)) <> '' and
       trim(upper(p_regcliente.ieent)) <> 'ISENTA' and
       trim(upper(p_regcliente.ieent)) <> 'ISENTO'))) then
      p_regpedido.valido := false;
      vsmensagem         := vsmensagem || vschar ||
                            'VENDA ESTADUAL PARA PESSOA FISICA COM INSC ESTADUAL NAO PERMITIDA NESTA FILIAL';

          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 16;

          end if;


    end if;

    if (nvl(p_regfilial.permitirvendaestadualpfsemie, 'S') = 'N') and
       (p_regcliente.estent = p_regfilial.uf) and
       ((p_regcliente.tipofj = 'F') and (p_regcliente.CONTRIBUINTE = 'N') and
       (trim(upper(p_regcliente.ieent)) = '' or
       trim(upper(p_regcliente.ieent)) = 'ISENTA' or
       trim(upper(p_regcliente.ieent)) = 'ISENTO')) then
      p_regpedido.valido := false;
      vsmensagem         := vsmensagem || vschar ||
                            'VENDA ESTADUAL PARA PESSOA FISICA SEM/ISENTA INSC ESTADUAL NAO PERMITIDA NESTA FILIAL';

          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 16;

          end if;



    end if;

    if nvl(p_regcliente.VALIDAMAXVENDAPF, 'N') = 'S' then
      --Verificar venda p/ pessoa física
      if (p_regcliente.tipofj = 'F' and p_regcliente.contribuinte = 'N') or
         (p_regcliente.CONSUMIDORFINAL = 'S') or
         ((gregpcconsum.CONSIDERAISENTOSCOMOPF = 'S') and
         ((trim(p_regcliente.IEENT) = '') or
         (Upper(p_regcliente.IEENT) = 'ISENTA') or
         (Upper(p_regcliente.ieent) = 'ISENTO'))) then
        if not
            funcoesvendas.verificarvalormaximovendapf(p_regcliente.codcli,
                                                      p_vltotped,
                                                      0,
                                                      p_regpedido.percvenda,
                                                      nvl(gregPCCONSUM.ACEITAVENDAPF,
                                                          'S'),
                                                      nvl(gregPCCONSUM.VERIFICARLIMVENDAPF,
                                                          'N'),
                                                      gregPCCONSUM.VLMAXVENDAPF,
                                                      gregPCCONSUM.PERLIMVENDAPF,
                                                      gregPCCONSUM.VLMAXPEDIDOPF,
                                                      gregPCCONSUM.CONSIDERAISENTOSCOMOPF,
                                                      p_regpedido.codfilial,
                                                      vsMensagem_vendapf) then
          if vsMensagem_vendapf is not null then
            p_regpedido.valido := false;


          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 16;

          end if;

            vsmensagem         := vsmensagem || vschar ||
                                  vsmensagem_vendapf;
          end if;
        end if;
      end if;
    end if;




    if (p_regpedido.tipofv in ('OL','PE') and vstipovalorminimo <> 'C') or p_regpedido.tipofv not in ('OL','PE') then


    vnvlminvendabk := nvl(p_regfilial.vlminvendabkfilial,0);

    if vnvlminvendabk = 0 and gregpcconsum.vlminvendabk > 0 then

       vnvlminvendabk := gregpcconsum.vlminvendabk;
    end if;


   /* INICIO: MED-1499 - Melhoria de Mensagens - Passou a ser validado na procedure de gravação do pedido
    -- verifica valor parcela minima para cobranca BK
    if p_regpedido.codcob = 'BK' or p_regcob.boleto = 'S' then

      vnnumeroparcelas := func_calculanumparcplpag(p_regplpag);
      vnvalorparcela   := ROUND((p_vltotped / vnnumeroparcelas),
                                gregpcconsum.numcasasdecvenda);

    if gregpcconsum.tipovlminvendabk = 'VP' then

      if vnvalorparcela < NVL(vnvlminvendabk, 0) then
        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;
        vsmensagem         := vsmensagem || vschar ||
                              'Valor da parcela menor#';
        vsmensagem         := vsmensagem || 'que valor minimo para#';
        vsmensagem         := vsmensagem || 'cobranca bancaria (BK)#';
        vsmensagem         := vsmensagem || 'Vl. Parcela : ' ||
                              vnvalorparcela || '#';
        vsmensagem         := vsmensagem || 'Vl. Minimo  : ' ||
                              NVL(vnvlminvendabk, 0) || ';';

         if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 34;

          end if;

        if nvl(gregpcconsum.aceitavendabloq,'N') = 'S' then

           p_regpedido.posicao := 'B';
           p_regpedido.codmotivo := 15;
           p_regpedido.motivoposicao := 'Valor do Pedido menor que o minimo para cobrança BK';
           p_regpedido.log := p_regpedido.log||CHR(13)||'Valor do Pedido menor que o minimo para cobrança BK';

        else

          p_regpedido.valido := false;

        end if;
      end if;

    elsif gregpcconsum.tipovlminvendabk = 'VT' then


      if p_vltotped < NVL(vnvlminvendabk, 0) then
        if vsmensagem is not null then
          vschar := '#';
        else
          vschar := null;
        end if;
        vsmensagem         := vsmensagem || vschar ||
                              'Valor do pedido menor#';
        vsmensagem         := vsmensagem || 'que valor minimo para#';
        vsmensagem         := vsmensagem || 'cobranca bancaria (BK)#';
        vsmensagem         := vsmensagem || 'Vl. Pedido : ' ||
                              p_vltotped || '#';
        vsmensagem         := vsmensagem || 'Vl. Minimo  : ' ||
                              NVL(vnvlminvendabk, 0) || ';';

          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 34;

          end if;

        if nvl(gregpcconsum.aceitavendabloq,'N') = 'S' then

           p_regpedido.posicao := 'B';
           p_regpedido.codmotivo := 15;
           p_regpedido.motivoposicao := 'Valor do Pedido menor que o minimo para cobrança BK';
           p_regpedido.log := p_regpedido.log||CHR(13)||'Valor do Pedido menor que o minimo para cobrança BK';

        else

          p_regpedido.valido := false;

        end if;
      end if;

    end if;
    end if;
    FIM: MED-1499 - Melhoria de Mensagens - Passou a ser validado na procedure de gravação do pedido*/


  /* INICIO: MED-1499 - Melhoria de Mensagens - Passou a ser validado na procedure de gravação do pedido
   if p_regpedido.origemped <> 'R' or (p_regpedido.origemped = 'R' and p_regfilial.validavlminvendabalcao = 'S') then

   if p_regpedido.condvenda in (1,7,13) and p_regfilial.vlminvendafv > 0 then

    if p_vltotped < p_regfilial.vlminvendafv then

      if vsmensagem is not null then
        vschar := '#';
      else
        vschar := null;
      end if;
      vsmensagem         := vsmensagem || vschar || 'Valor do pedido (' ||
                            p_vltotped || ') menor que o #';
      vsmensagem         := vsmensagem || 'mínimo para o pedido (' ||
                            p_regfilial.vlminvendafv || ');';

           if gregpcconsum.aceitavendabloq = 'S' then
             p_regpedido.posicao := 'B';
             p_regpedido.codmotivo := 11;
             p_regpedido.motivoposicao := 'Valor do pedido menor que minimo para pedido';
           else
              p_regpedido.valido := false;
           end if;



          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 34;

          end if;


    end if;

    elsif p_Regpedido.condvenda = 5 then


      if p_vltotped > nvl(gregpcconsum.vlmaxvendabnf, 0) and nvl(gregpcconsum.vlmaxvendabnf, 0) > 0
      then
        if vsmensagem is not null
        then
          vschar := '#';
        else
          vschar := null;
        end if;

        vsmensagem         := vsmensagem || vschar || 'Valor do pedido (' || p_vltotped ||
                              ') maior que o #';
        vsmensagem         := vsmensagem || 'maximo para o pedido bonificado (' ||
                              nvl(gregpcconsum.vlmaxvendabnf, 0) || ');';
      p_regpedido.valido := false;

          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 34;

          end if;


      end if;

      if p_vltotped < p_regfilial.vlminvendabnffv and p_regfilial.vlminvendabnffv > 0
      then
        if vsmensagem is not null
        then
          vschar := '#';
        else
          vschar := null;
        end if;

        vsmensagem         := vsmensagem || vschar || 'Valor do pedido (' || p_vltotped ||
                              ') menor que o #';
        vsmensagem         := vsmensagem || 'mínimo para o pedido bonificado (' ||
                              p_regfilial.vlminvendabnffv || ');';
        p_regpedido.valido := false;

          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 34;

          end if;


      end if;

  end if;
  end if;
  FIM: MED-1499 - Melhoria de Mensagens - Passou a ser validado na procedure de gravação do pedido*/

  end if;

    -- Se Gravou Array de Log Específico - MED-1499
    IF (vtLogImportacaoPed.COUNT > 0) THEN
      FOR viIdxImportacaoPed IN vtLogImportacaoPed.FIRST..vtLogImportacaoPed.LAST LOOP
        -- Log Específico
        p_regpedido.logprocmed := p_regpedido.logprocmed || vtLogImportacaoPed(viIdxImportacaoPed) || CHR(13);
      END LOOP;
    END IF;

    -- Se Gravou Array de Log Específico - MED-1499
    IF (vtJsonImportacaoPed.COUNT > 0) THEN
      FOR viIdxImportacaoPed IN vtJsonImportacaoPed.FIRST..vtJsonImportacaoPed.LAST LOOP
        -- Log Específico
        p_regpedido.jsonprocmed := p_regpedido.jsonprocmed || vtJsonImportacaoPed(viIdxImportacaoPed) || CHR(13);
      END LOOP;
    END IF;


    -- registra log
    if (vsmensagem is not null) then
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       null,
                       null,
                       p_regpedido.cgccli,
                       null,
                       null,
                       null,
                       p_regpedido.codusur,
                       p_Regpedido.dtaberturapedpalm,
                       null,
                       '2',
                       vsmensagem,
                       null,
                       null);
    end if;

  exception
    when others then
      p_regpedido.valido := false;
      proc_registralog(p_regpedido.numped,
                       p_regpedido.numpedrca,
                       null,
                       null,
                       p_regpedido.cgccli,
                       null,
                       null,
                       null,
                       p_regpedido.codusur,
                       p_Regpedido.dtaberturapedpalm,
                       null,
                       '2',
                       sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->012->' || SQLERRM,
                       null,
                       null);

          if p_regpedido.codmotivonaoatend is null then
             p_regpedido.codmotivonaoatend := 4;

          end if;


  end proc_validacaofinalcab;



  PROCEDURE proc_encontraperluc (p_regitem          IN t_itemped,
                                 p_regpedido        IN t_cabped,
                                 p_regcliente       IN t_clientepedido,
                                 p_regproduto       IN OUT t_produto,
                                 p_regprecos        IN OUT t_precosetributacao,
                                 p_regrca           IN t_rca,
                                 p_Regregiao        IN t_regiaocliente,
                                 p_regfilial        IN t_filial,
                                 p_perlucsemred     OUT number,
                                 p_mensagem         OUT varchar2
                                 ) IS

    vniva                           pcpedi.iva%type;
    vnpbaserca                      pcpedi.pbaserca%type;
    vbcalculastvalido               boolean;
    vsuffilialnf                    pcfilial.uf%type;
    vbcodicmtabpf                   boolean;
    vsmensagem_st                   varchar2(1000);
    vsmensagem_comiss               varchar2(1000);
    vnperluc                        number;
    vnperdesc                       number;

    vnpvenda                       pcpedi.pvenda%type;
    vnptabela                      pcpedi.ptabela%type;
    vnvlipi                        pcpedi.vlipi%type;
    vnpercipi                      pcpedi.percipi%type;
    vnst                           pcpedi.st%type;
    vnbaseicst                     pcpedi.baseicst%type;
    vnpercom                       pcpedi.percom%type;
    vnperfretecmv                  pcpedi.perfretecmv%type;
    vncustofinest                  pcpedi.custofinest%type;
    vntxvenda                      pcpedi.txvenda%type;
    vnperdesccusto                 pcpedi.perdesccusto%type;
    vncodicmtab                    pcpedi.codicmtab%type;
    vnvlcustoreal                  pcpedi.vlcustoreal%type;
    vnvlcustofin                   pcpedi.vlcustofin%type;
    vnvldesccustocmv               pcpedi.vldesccustocmv%type;
    vsletracomiss                  pcpedi.letracomiss%type;
    vncodaux                       number;

    vicont                          number;
    vbUsaPcTabComiss                boolean;
    vbUsaPcComissaoUsur             boolean;
    vbUsaPCComissaoPlPag            boolean;
    vbUsaPCComissaoRegiao           boolean;
    vbUsaPCComissaofilial           boolean;
    vncodcomiss                     pcorigemcomis.codcomis%type;
    vncodrotinacomiss               pcorigemcomis.codrotinacomis%type;

    vvPromocaoPriorizaComissao      PCPROMOCAOMED.PRIORIZACOMISSAO%type; -- 5047.047570.2016

    vnPRODIMPORTADOPEPS             pcpedi.prodimportadopeps%type; -- HIS.02787.2016
    vnNUMTRANSENTPEPS               pcpedi.numtransentpeps%type;   -- HIS.02787.2016
    vvMsgErroCalcularCMV            varchar2(2000);                -- HIS.02787.2016

    vnPerComIntegradora             NUMBER;

  BEGIN


     vnpvenda := p_regitem.pvenda;
     vnptabela := p_regproduto.ptabela;
     vnpbaserca := p_Regitem.pbaserca;


              BEGIN
              SELECT pcfilial.uf
                INTO vsuffilialnf
                FROM pcfilial
               WHERE pcfilial.codigo =
                     nvl(p_regcliente.codfilialnf,
                         p_regpedido.codfilial);
            EXCEPTION
              WHEN OTHERS THEN
                vsuffilialnf := NULL;
            END;


            if p_regprecos.codicmtabpf is null
            then
              vbcodicmtabpf := true;
            else
              vbcodicmtabpf := false;
            end if;


        vniva := p_regprecos.iva;

         --50 parametros
          vbcalculastvalido := funcoesvendas.calcularimpostos(vnpvenda,
                                                              vnptabela,
                                                              vnpbaserca,
                                                              vnvlipi,
                                                              vnpercipi,
                                                              nvl(p_regproduto.percipivenda, 0),
                                                              p_regpedido.percvenda,
                                                              gregpcconsum.tipocalcst,
                                                              gregpcconsum.calcstpf,
                                                              p_regprecos.mostrarpvendasemst,
                                                              gregpcconsum.consideraisentoscomopf,
                                                              p_regcliente.calculast,
                                                              p_regcliente.ieent,
                                                              p_regcliente.tipofj,
                                                              p_regprecos.pauta,
                                                              vniva,
                                                              p_regprecos.aliqicms1,
                                                              p_regprecos.aliqicms2,
                                                              p_regprecos.percbaseredst,
                                                              gregpcconsum.numcasasdecvenda,
                                                              0,
                                                              p_regfilial.uf,
                                                              p_regcliente.estent,
                                                              nvl(p_regprecos.usavalorultentbasest,'N'),
                                                              nvl(p_regprecos.usavalorultentbasest2,'N'),
                                                              p_regprecos.valorultent,
                                                              p_regcliente.isentoipi,
                                                              0,
                                                              gregpcconsum.calcularstcomipi,
                                                              gregpcconsum.tipocalcipi,
                                                              p_regcliente.codfilialnf,
                                                              p_regpedido.condvenda,
                                                              p_regcliente.contribuinte,
                                                              vsuffilialnf,
                                                              p_regproduto.importado,
                                                              p_regfilial.calcularipivenda,
                                                              p_regproduto.PERCIPIVENDATAB ,
                                                              p_regproduto.VLPAUTAIPIVENDA,
                                                              p_regproduto.VLPAUTAIPIVENDATAB,
                                                              p_regproduto.VLIPIPORKGVENDA,
                                                              p_regproduto.VLIPIPORKGVENDATAB,
                                                              p_regproduto.PESOBRUTO,
                                                              p_regprecos.TIPOCALCULOGNRE,
                                                              p_regcliente.simplesnacional,
                                                              p_regprecos.PERCREDPVENDASIMPLESNAC ,
                                                              'N',
                                                              null ,
                                                              vsmensagem_st,
                                                              vnst,
                                                              vnbaseicst,
                                                              gregpcconsum.aceitapfcontribuinte,
                                                              p_regprecos.custonfsemst,
                                                              p_regprecos.usapmcbasest,
                                                              p_regproduto.precomaxconsum,
                                                              p_Regcliente.consumidorfinal,
                                                              'N',
                                                              p_regprecos.usavlultentmediobasest,
                                                              p_regprecos.vlultentmes
                                                              );


                           -- calcula o percentual de desconto
                    vnperdesc := func_calcularperdescitem(vnptabela,vnpvenda,vncodaux);


            -- HIS.02787.2016
            p_calcularcmv_med(p_regfilial.tributsaidaorigemnacimp, -- HIS.02787.2016
                                    gregpcconsum.abaterimpostoscomissaorca,
                                    gregpcconsum.aplicarindicecmv,
                                    gregpcconsum.Incluircomissaosugpvendacmv,
                                    nvl(gregpcconsum.txvenda, 0),
                                    p_regcliente.tipofj,
                                    p_regcliente.utilizaiesimplificada,
                                    p_regcliente.ieent,
                                    p_regproduto.freteespecial,
                                    p_regregiao.PERFRETETERCEIROS,
                                    p_regregiao.PERFRETEESPECIAL,
                                    p_regprecos.custofin,
                                    p_regprecos.custoreal,
                                    p_regprecos.perdesccusto,
                                    p_regprecos.codicmtab,
                                    vbcodicmtabpf,
                                    p_regprecos.codicmtabpf,
                                    p_regpedido.percvenda,
                                    ----------------------------------
                                    --(vnpvenda - nvl(p_regitem.VLREDPVENDASIMPLESNA,0)) ,
                                    CASE NVL(p_regfilial.usadescsimplesnac,'N') WHEN 'S' THEN vnpvenda ELSE nvl(round((vnpvenda - nvl(p_regitem.VLREDPVENDASIMPLESNA,0)), 2),
                                        0) END,
                                    ----------------------------------
                                    0,
                                    vnST,
                                    vnvlipi,
                                    0,
                                    p_regcliente.contribuinte,
                                    0,
                                    ----------------------------------
                                    --nvl(p_regitem.VLREDPVENDASIMPLESNA,0),
                                    CASE NVL(p_regfilial.usadescsimplesnac,'N') WHEN 'S' THEN 0 ELSE nvl(p_regitem.VLREDPVENDASIMPLESNA,
                                        0) END,
                                    ----------------------------------
                                    p_regcliente.consumidorfinal,
                                    nvl(gregpcconsum.consideraisentoscomopf,'N'),
                                    vnperfretecmv,
                                    vnCUSTOFINEST,
                                    vntxvenda,
                                    vnperdesccusto,
                                    vnCODICMTAB,
                                    vnVLCUSTOREAL,
                                    vnVLCUSTOFIN,
                                    vnVLDESCCUSTOCMV,
                                    p_regpedido.codcli,            -- HIS.02787.2016
                                    0, -- p_custoprecific          -- HIS.02787.2016
                                    p_regitem.codprod,             -- HIS.02787.2016
                                    p_regpedido.codfilial,         -- HIS.02787.2016
                                    p_regitem.qt,                  -- HIS.02787.2016
                                    p_regprecos.codicmtabinternac, -- HIS.02787.2016
                                    p_regitem.vldesccmvpromocaomed,-- DDMEDICA-5009
                                    0,                             -- DDMEDICA-7697 -- Aqui não tem O ST Recolhido Anteriormente
                                    vnPRODIMPORTADOPEPS,           -- HIS.02787.2016
                                    vnNUMTRANSENTPEPS,             -- HIS.02787.2016
                                    vvMsgErroCalcularCMV           -- HIS.02787.2016
                                    );

          -- 4493.064633.2016 - Tratamento de Erro por Divisão por Zero
          BEGIN
            vnperluc := ((vnpvenda - vnVLCUSTOFIN) / vnpvenda)*100;
          EXCEPTION
            WHEN ZERO_DIVIDE THEN
              vnperluc := 0;
          END;


          -- busca percentual de comissao
          vsmensagem_comiss := NULL;
                    select count(*)
                    into vicont
                    from pctabcomiss p;

                    if vicont <> 0 then
                      vbUsaPcTabComiss := true;
                    else
                      vbUsaPcTabComiss := false;
                    end if;

                    select count(*)
                    into vicont
                    from pccomissaousur p;

                    if vicont <> 0 then
                      vbUsaPcComissaoUsur := true;
                    else
                      vbUsaPcComissaoUsur := false;
                    end if;


                    select count(*)
                    into vicont
                    from pccomissaoplpag p;

                    if vicont <> 0 then
                      vbUsaPcComissaoplpag := true;
                    else
                      vbUsaPCComissaoPlPag := false;
                    end if;


                    select count(*)
                    into vicont
                    from pccomissaoregiao p;

                    if vicont <> 0 then
                      vbUsaPcComissaoregiao := true;
                    else
                      vbUsaPcComissaoregiao := false;
                    end if;

                    if p_regfilial.broker = 'S' then
                       vbUsaPCComissaofilial := true;
                    else
                       vbUsaPCComissaofilial := false;
                    end if;

                   /****************************************
                    Comissão Integradora OL [HIS.00490.2014]
                    ****************************************/
                    if nvl(upper(p_regpedido.usacomissaointegradora),'N') = 'S' then

                       -- Comissão cadastrada na rotina 2302
                       vnpercom := p_regpedido.percom;

                     /*************************************
                      COMISSÃO: INTEGRADORA - DDMEDICA-1835
                      *************************************/
                      IF (INTEGRADORACOMPLE_MED.F_OBTER_COMISSAO_INTEGRADORA(p_regitem.coddesconto,
                                                                             p_regitem.codpromocaomed,
                                                                             p_regrca.tipovend,
                                                                             p_regitem.codprod,
                                                                             p_regpedido.integradora,
                                                                             vnPerComIntegradora) = 'S') THEN
                        vnpercom := vnPerComIntegradora;
                      END IF;

                    else

                      -- Verifica se a Promoção do Item Prioriza a Comissão -- 5047.047570.2016
                      BEGIN
                        SELECT PCPROMOCAOMED.PRIORIZACOMISSAO
                          INTO vvPromocaoPriorizaComissao
                          FROM PCPROMOCAOMED
                         WHERE (PCPROMOCAOMED.CODPROMOCAOMED = p_regitem.codpromocaomed);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vvPromocaoPriorizaComissao := NULL;
                      END;

                     /***********************************
                      COMISSÃO: PEDIDO FV QUE USA PROMOÇÃO
                      ************************************/
                      IF ((NVL(p_regpedido.codpromocaomed,0)   > 0))   AND
                          (NVL(vvPromocaoPriorizaComissao,'N') = 'S')  THEN

                        -- Comissão cadastrada na rotina 2323
                        BEGIN
                          vnpercom := INTEGRADORACOMPLE_MED.F_OBTER_COMISSAO_PROMOCAO(p_regitem.coddesconto,
                                                                                      p_regitem.codpromocaomed,
                                                                                      p_regrca.tipovend,
                                                                                      p_regitem.codprod);
                        EXCEPTION
                          WHEN OTHERS THEN
                            vsmensagem_comiss :=  'Erro Cálculo Comissão Promoção : ' || SUBSTR('Erro: ' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,240);
                            proc_registralog(p_regpedido.numped,
                                             p_regpedido.numpedrca,
                                             p_regitem.codprod,
                                             p_regitem.codauxiliar,
                                             p_regitem.cgccli,
                                             null,
                                             null,
                                             null,
                                             p_regpedido.codusur,
                                             p_regitem.dtaberturapedpalm,
                                             null,
                                             '3',
                                            'Erro ao calcular comissão. '||SQLCODE||' '||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                                            null,
                                            p_regitem.numseqifv);
                        END;

                     /**********************
                      COMISSÃO: DEMAIS CASOS
                      **********************/
                      ELSE

                        begin

                        vnpercom := FUNCOESVENDAS.Definir_Comissao_Item_Vendido
                                           (p_regregiao.numregiao,
                                            vnperluc,
                                            vnperdesc,
                                            vbUsaPcTabComiss,
                                            vbUsaPcComissaoUsur,
                                            vbUsaPCComissaoPlPag,
                                            vbUsaPCComissaoRegiao,
                                            vbUsaPCComissaofilial,
                                            gregpcconsum.usacomissaoporrca,
                                            gregpcconsum.OrdemAvaliacaoComissaoRCA,
                                            gregpcconsum.usacomissaoporcliente,
                                            gregpcconsum.USACOMISSAOPORLINHAPROD,
                                            gregpcconsum.comissaorcatipovenda,
                                            p_regrca.tipovend,
                                            p_regrca.percent,
                                            p_regrca.percent2,
                                            p_regproduto.codprod,
                                            p_regproduto.pcomint1,
                                            p_regproduto.PCOMEXT1,
                                            p_regproduto.PCOMREP1,
                                            p_regproduto.codlinhaprod,
                                            p_regproduto.tipocomissao,
                                            p_regproduto.codepto,
                                            p_regproduto.codsec,
                                            p_regproduto.classe,
                                            p_regitem.tipovenda,
                                            p_regitem.codplpag,
                                            p_regpedido.data,
                                            p_regpedido.codfilial,
                                            p_regpedido.codusur,
                                            p_regfilial.considerarcomissaozero,
                                            p_regfilial.tipoavaliacaocomissao,
                                            p_regcliente.percomcli,
                                            p_regcliente.codcli,
                                            p_regitem.coddesconto,
                                            vncodcomiss,
                                            vncodrotinacomiss,
                                            vsLetraComiss,
                                            vsmensagem_comiss,
                                            p_regitem.codauxiliar ,
                                            p_regprecos.pcomint1_emb,
                                            P_regprecos.PCOMEXT1_emb,
                                            P_regprecos.PCOMREP1_emb,
                                            p_regfilial.utilizavendaporembalagem);
                                     exception when others then
                                      proc_registralog(p_regpedido.numped,
                                                       p_regpedido.numpedrca,
                                                       p_regitem.codprod,
                                                       p_regitem.codauxiliar,
                                                       p_regitem.cgccli,
                                                       null,
                                                       null,
                                                       null,
                                                       p_regpedido.codusur,
                                                       p_regitem.dtaberturapedpalm,
                                                       null,
                                                       '3',
                                                      'Erro ao calcular comissão. '||SQLCODE||' '||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                                                      null,
                                                      p_regitem.numseqifv);

                                     end;

                       /****************************
                        COMISSÃO: ACORDO DE PARCERIA
                        ****************************/
                        -- HIS.01889.2017 - Se não aplicou a Comissão da PCDESCONTO
                        IF (NVL(vncodrotinacomiss,0) <> 561) THEN
                          IF ((NVL(p_regpedido.codpromocaomed,0) > 0) AND
                              (NVL(p_regitem.priorizacomissacordoparceria,'N') = 'S')) THEN

                            vnpercom := p_regitem.percomacordoparceria;

                          END IF;
                        END IF;

                      END IF; -- FIM CONDIÇÃO COMISSÃO: PEDIDO FV QUE USA PROMOÇÃO

                    end if; -- Fim Condição Se Comissão Integradora OL

                    -- HIS.03249.2016 - Tipos de Venda que não têm Comissão
                    IF (p_regpedido.condvenda IN (4, 5, 8, 9, 10, 13, 11, 20)) THEN
                      vnpercom := 0;
                    ELSIF(p_regpedido.aplicarperredcomiss = 'S') then
                      vnpercom := vnpercom * (1 - NVL(p_regitem.PERREDCOMISS,0) /100);
                    END IF;

                    -- DDMEDICA-1835 - Se Bloqueia a Comissão do RCA
                    IF (INTEGRADORACOMPLE_MED.F_BLOQUEIA_COMISSAO(NVL(p_regitem.codusurlinha,p_regpedido.codusur)) = 'S') THEN
                      vnpercom := 0;
                    END IF;

          IF vsmensagem_comiss IS NOT NULL
          THEN
            proc_registralog(p_regpedido.numped,
                             p_regpedido.numpedrca,
                             p_regitem.codprod,
                             p_regitem.codauxiliar,
                             p_regpedido.cgccli,
                             NULL,
                             NULL,
                             NULL,
                             p_regpedido.codusur,
                             p_regpedido.dtaberturapedpalm,
                             null,
                             '3',
                             vsmensagem_comiss,
                             NULL,
                             p_regitem.numseqifv);
          END IF;



            -- HIS.02787.2016
            p_calcularcmv_med(p_regfilial.tributsaidaorigemnacimp, -- HIS.02787.2016
                                    gregpcconsum.abaterimpostoscomissaorca,
                                    gregpcconsum.aplicarindicecmv,
                                    gregpcconsum.Incluircomissaosugpvendacmv,
                                    nvl(gregpcconsum.txvenda,0),
                                    p_regcliente.tipofj,
                                    p_regcliente.utilizaiesimplificada,
                                    p_regcliente.ieent,
                                    p_regproduto.freteespecial,
                                    p_regregiao.PERFRETETERCEIROS,
                                    p_regregiao.PERFRETEESPECIAL,
                                    p_regprecos.custofin ,
                                    p_regprecos.custoreal,
                                    p_regprecos.perdesccusto,
                                    p_regprecos.codicmtab,
                                    vbcodicmtabpf,
                                    p_regprecos.codicmtabpf,
                                    p_regpedido.percvenda,
                                    ----------------------------------
                                    --round((vnpvenda - nvl(p_regitem.VLREDPVENDASIMPLESNA,0)), 2),
                                    CASE NVL(p_regfilial.usadescsimplesnac,'N') WHEN 'S' THEN vnpvenda ELSE nvl(round((vnpvenda - nvl(p_regitem.VLREDPVENDASIMPLESNA,0)), 2),
                                        0) END,
                                    ----------------------------------
                                    vnPERCOM,
                                    vnST,
                                    0,
                                    0,
                                    p_regcliente.contribuinte,
                                    0,
                                    ----------------------------------
                                    --nvl(p_regitem.VLREDPVENDASIMPLESNA,0),
                                    CASE NVL(p_regfilial.usadescsimplesnac,'N') WHEN 'S' THEN 0 ELSE nvl(p_regitem.VLREDPVENDASIMPLESNA,
                                        0) END,
                                    ----------------------------------
                                    p_regcliente.consumidorfinal,
                                    nvl(gregpcconsum.consideraisentoscomopf,'N'),
                                    vnperfretecmv,
                                    vnCUSTOFINEST,
                                    vntxvenda,
                                    vnperdesccusto,
                                    vnCODICMTAB,
                                    vnVLCUSTOREAL,
                                    vnVLCUSTOFIN,
                                    vnVLDESCCUSTOCMV,
                                    p_regpedido.codcli,            -- HIS.02787.2016
                                    0, -- p_custoprecific          -- HIS.02787.2016
                                    p_regitem.codprod,             -- HIS.02787.2016
                                    p_regpedido.codfilial,         -- HIS.02787.2016
                                    p_regitem.qt,                  -- HIS.02787.2016
                                    p_regprecos.codicmtabinternac, -- HIS.02787.2016
                                    p_regitem.vldesccmvpromocaomed,-- DDMEDICA-5009
                                    0,                             -- DDMEDICA-7697 -- Aqui não tem O ST Recolhido Anteriormente
                                    vnPRODIMPORTADOPEPS,           -- HIS.02787.2016
                                    vnNUMTRANSENTPEPS,             -- HIS.02787.2016
                                    vvMsgErroCalcularCMV           -- HIS.02787.2016
                                    );


          p_perlucsemred := ((vnpvenda - vnVLCUSTOFIN) / vnpvenda)*100;




  EXCEPTION
    WHEN OTHERS THEN
      p_mensagem := 'Erro ao encontrar percentual de lucratividade :' || SQLCODE || '-' ||
                    DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM;
  END proc_encontraperluc;


FUNCTION func_calculanovopvenda (vnpvendasemimp     IN number,
                                p_regpedido        IN t_cabped,
                                p_regproduto       IN t_produto,
                                p_regprecos        IN t_precosetributacao)
 return number is

  vnvlipi   number;
  vnst      number;
  vnBase01  number;
  vnBase02  number;
  vscalcularipivenda pcfilial.calcularipivenda%type;
  vnpercbaseredst number;
  vnPercRedPVendaSimplesNac number;
  vnst1     number;
  vnst2     number;
  vnNovoPVendaSimpNasc number;

  vnbcst number;


 begin

  vnVLIPI := 0;

    select pcfilial.calcularipivenda
    into vscalcularipivenda
    from pcfilial
    where codigo = p_regpedido.codfilial;

  if (p_regprecos.USAPMCBASEST = 'S') and
       (p_regproduto.PRECOMAXCONSUM > 0) then -- Tarefa 132424



        vnBCST := (p_regproduto.PRECOMAXCONSUM * (p_regprecos.PERCBASEREDST / 100));

        vnST1 := (vnBCST * (p_regprecos.ALIQICMS1 / 100));
        vnST2 := (vnPVendaSemImp * (p_regprecos.ALIQICMS2 / 100));
        vnST := vnST1 - vnST2;


      vnNovoPVendaSimpNasc := vnPVendaSemImp + vnST;

  else


  --Tarefa 70519 - Projeto 69444
  if vsCALCULARIPIVENDA = 'N' then
    vnVLIPI := 0;
  else

    if p_regproduto.VLPAUTAIPIVENDA > 0 then
      vnVLIPI := p_Regproduto.VLPAUTAIPIVENDA;
    else
      if p_regproduto.vlipiporkgvenda > 0 then
        vnVLIPI := p_regproduto.PESOBRUTO * p_regproduto.VLIPIPORKGVENDA;
      else
        if p_regproduto.PERCIPIVENDA > 0 then
          vnVLIPI := vnpvendasemimp * (p_regproduto.PERCIPIVENDA / 100);
        end if;
      end if;
    end if;

    IF gregpcconsum.tipocalcipi = 'T2' THEN
        vnvlipi := round(vnvlipi * 100) / 100;
      ELSIF gregpcconsum.tipocalcipi = 'A2' THEN
        vnvlipi := round(vnvlipi, 2);
      ELSIF gregpcconsum.tipocalcipi = 'PV' THEN
        vnvlipi := round(vnvlipi, gregpcconsum.numcasasdecvenda);
     END IF;

  end if;



   vnBase01 := vnPVendaSemImp;
   vnBase02 := vnPVendaSemImp;

          if gregpcconsum.calcularstcomipi = 'S' then
            vnBase01 := vnPVendaSemImp + vnVLIPI;
          end if;

          if p_Regprecos.percbaseredst = 0 then
            vnpercbaseredst := 100;
          else vnpercbaseredst := p_regprecos.percbaseredst;
          end if;

          if p_regprecos.PERCREDPVENDASIMPLESNAC = 0 then
             vnPercRedPVendaSimplesNac := 100;
          else
             vnPercRedPVendaSimplesNac := p_regprecos.PERCREDPVENDASIMPLESNAC;
          end if;

          if p_regprecos.pauta = 0 then
            vnST1 := ((vnbase01 * (1 + (((p_regprecos.iva / 100) * (vnPercRedPVendaSimplesNac / 100))))) * (vnpercbaseredst / 100)) * (p_regprecos.aliqicms1 / 100);
          else
            vnST1 := p_regprecos.pauta * (p_regprecos.aliqicms1 / 100);
          end if;

            vnST2 := (vnBase02 * (p_regprecos.aliqicms2 / 100));

            vnST := vnST1 - vnST2;

               --Calcular ST - Truncar com 2 casas decimais
              IF gregpcconsum.tipocalcst = 'T2'
              THEN
                vnst := trunc((vnst) * 100) / 100;
              ELSIF gregpcconsum.tipocalcst  = 'A2'
              THEN
                vnst := round((vnst) * 100) / 100;
              ELSIF gregpcconsum.tipocalcst  = 'PV'
              THEN
                vnst := round(vnst,
                                  gregpcconsum.numcasasdecvenda);
              END IF;



          if vnST < 0 then
            vnST := 0;
          end if;

          vnNovoPVendaSimpNasc := vnPVendaSemImp + vnST;

          if vsCALCULARIPIVENDA = 'S' then
            vnNovoPVendaSimpNasc := vnNovoPVendaSimpNasc + vnVLIPI;
          end if;

          vnNovoPVendaSimpNasc := round( vnNovoPVendaSimpNasc,gregpcconsum.numcasasdecvenda);

 end if;



   return(vnNovoPVendaSimpNasc);

 end func_calculanovopvenda ;



PROCEDURE proc_encontrapvenda (p_regitem          IN OUT t_itemped,
                               p_regpedido        IN t_cabped,
                               p_regcliente       IN t_clientepedido,
                               p_regregiao        IN t_regiaocliente,
                               p_regrca           IN t_rca,
                               p_regproduto       IN OUT t_produto,
                               p_regprecos        IN OUT t_precosetributacao,
                               p_percdif          OUT number, --diferença entre pvenda e ptabela
                               p_percdif2         OUT number, --diferença entre ptabela e pbaserca
                               p_mensagem         OUT VARCHAR2) IS

    vnpvendasemimposto               number;
    vsmensagemprecosemimposto       varchar2(1000);
    vsuffilial                      pcfilial.uf%type;
    vbcalculaprecosemimposto        boolean;
    vsmensagemredsimplesnac         varchar2(1000);
    vnvlreducao                     number;
    vbcalcularedsimplesnac          boolean;
    vbcalculastvalido               boolean;
    vnpbaserca                      pcpedi.pbaserca%type;
    vnvlipi                         pcpedi.vlipi%type;
    vnpercipi                       pcpedi.percipi%type;
    vsuffilialnf                    pcfilial.uf%type;
    vscalcularipivenda              pcfilial.calcularipivenda%type;
    vsmensagem_st                   varchar2(1000);
    vnstpvenda                      pcpedi.st%type;
    vnbaseicst                      pcpedi.baseicst%type;
    vnvldif                         number;
    vnpercdif                       number;
    vnpvenda                        pcpedi.pvenda%type;
    vnptabela                       pcpedi.ptabela%type;
    vnptabelasemimposto             number;
    vniva                           pcpedi.iva%type;
    vnpbasercasemimposto            number;
    vnvldif2                        number;
    vnpercdif2                      number;
    vnnovopvenda                    number;
    vnnovoptabela                   number;
    vnnovopbaserca                  number;


  BEGIN


   if p_regprecos.mostrarpvendasemst = 'N' then

    vnpvenda := p_regitem.pvenda;
    vnptabela := p_regproduto.ptabela;
    vnpbaserca := p_regitem.pbaserca;

    select uf,pcfilial.calcularipivenda
    into vsuffilial,vscalcularipivenda
    from pcfilial
    where codigo = p_regpedido.codfilial;

    select uf
    into vsuffilialnf
    from pcfilial
    where codigo = nvl(p_regcliente.codfilialnf, p_regpedido.codfilial);



    vniva := p_regprecos.iva;

    vnvldif := 0;
    vnpercdif := 0;


     --Retirar impostos do preço de venda
     vbcalculaprecosemimposto := funcoesvendas.calculo_preco_sem_impostos(nvl(p_regproduto.PERCIPIVENDA,0),
                                                           p_regproduto.vlpautaipivenda,
                                                           p_regproduto.vlipiporkgvenda,
                                                           vnpvenda,
                                                           p_regprecos.pauta,
                                                           p_regproduto.pesobruto,
                                                           p_regprecos.percdifaliquotas,
                                                           p_regproduto.percipivenda,
                                                           p_regprecos.valorultent,
                                                           vniva,
                                                           p_regprecos.percbaseredst,
                                                           p_regprecos.aliqicms1,
                                                           p_regprecos.aliqicms2,
                                                           p_regprecos.usavalorultentbasest,
                                                           p_regprecos.usavalorultentbasest2,
                                                           vsuffilial,
                                                           p_regcliente.estent,
                                                           vnpvendasemimposto,
                                                           vsmensagemprecosemimposto,
                                                           p_regprecos.usapmcbasest,
                                                           p_regproduto.precomaxconsum,
                                                           p_regprecos.usavlultentmediobasest,
                                                           p_regprecos.vlultentmes);

               if vsmensagemprecosemimposto is not null then

                      proc_registralog(p_regpedido.numped,
                                       p_regpedido.numpedrca,
                                       p_regproduto.codprod,
                                       p_regitem.codauxiliar,
                                       p_regpedido.cgccli,
                                       NULL,
                                       NULL,
                                       NULL,
                                       p_regpedido.codusur,
                                       p_regpedido.dtaberturapedpalm,
                                       null,
                                       '3',
                                       'Erro ao calcular preço sem imposto'||vsmensagemprecosemimposto,
                                       NULL,
                                       p_regitem.numseqifv);


              end if;


      vnpvendasemimposto := round(vnpvendasemimposto,gregpcconsum.numcasasdecvenda);

     --Retirar impostos do preço de tabela
     vbcalculaprecosemimposto := funcoesvendas.calculo_preco_sem_impostos(nvl(p_regproduto.PERCIPIVENDA,0),
                                                           p_regproduto.vlpautaipivenda,
                                                           p_regproduto.vlipiporkgvenda,
                                                           vnptabela,
                                                           p_regprecos.pauta,
                                                           p_regproduto.pesobruto,
                                                           p_regprecos.percdifaliquotas,
                                                           p_regproduto.percipivenda,
                                                           p_regprecos.valorultent,
                                                           vniva,
                                                           p_regprecos.percbaseredst,
                                                           p_regprecos.aliqicms1,
                                                           p_regprecos.aliqicms2,
                                                           p_regprecos.usavalorultentbasest,
                                                           p_regprecos.usavalorultentbasest2,
                                                           vsuffilial,
                                                           p_regcliente.estent,
                                                           vnptabelasemimposto,
                                                           vsmensagemprecosemimposto,
                                                           p_regprecos.usapmcbasest,
                                                           p_regproduto.precomaxconsum,
                                                           p_regprecos.usavlultentmediobasest,
                                                           p_regprecos.vlultentmes);

               if vsmensagemprecosemimposto is not null then

                      proc_registralog(p_regpedido.numped,
                                       p_regpedido.numpedrca,
                                       p_regproduto.codprod,
                                       p_regitem.codauxiliar,
                                       p_regpedido.cgccli,
                                       NULL,
                                       NULL,
                                       NULL,
                                       p_regpedido.codusur,
                                       p_regpedido.dtaberturapedpalm,
                                       null,
                                       '3',
                                       'Erro ao calcular preço sem imposto'||vsmensagemprecosemimposto,
                                       NULL,
                                       p_regitem.numseqifv);


              end if;

    vnptabelasemimposto := round(vnptabelasemimposto,gregpcconsum.numcasasdecvenda);


     --Retirar impostos do preço base para calculo de deb/cred de rca
     vbcalculaprecosemimposto := funcoesvendas.calculo_preco_sem_impostos(nvl(p_regproduto.PERCIPIVENDA,0),
                                                           p_regproduto.vlpautaipivenda,
                                                           p_regproduto.vlipiporkgvenda,
                                                           vnpbaserca,
                                                           p_regprecos.pauta,
                                                           p_regproduto.pesobruto,
                                                           p_regprecos.percdifaliquotas,
                                                           p_regproduto.percipivenda,
                                                           p_regprecos.valorultent,
                                                           vniva,
                                                           p_regprecos.percbaseredst,
                                                           p_regprecos.aliqicms1,
                                                           p_regprecos.aliqicms2,
                                                           p_regprecos.usavalorultentbasest,
                                                           p_regprecos.usavalorultentbasest2,
                                                           vsuffilial,
                                                           p_regcliente.estent,
                                                           vnpbasercasemimposto,
                                                           vsmensagemprecosemimposto,
                                                           p_regprecos.usapmcbasest,
                                                           p_regproduto.precomaxconsum,
                                                           p_regprecos.usavlultentmediobasest,
                                                           p_regprecos.vlultentmes);

               if vsmensagemprecosemimposto is not null then

                      proc_registralog(p_regpedido.numped,
                                       p_regpedido.numpedrca,
                                       p_regproduto.codprod,
                                       p_regitem.codauxiliar,
                                       p_regpedido.cgccli,
                                       NULL,
                                       NULL,
                                       NULL,
                                       p_regpedido.codusur,
                                       p_regpedido.dtaberturapedpalm,
                                       null,
                                       '3',
                                       'Erro ao calcular preço sem imposto'||vsmensagemprecosemimposto,
                                       NULL,
                                       p_regitem.numseqifv);


              end if;

    vnpbasercasemimposto := round(vnpbasercasemimposto,gregpcconsum.numcasasdecvenda);

     --diferença pvenda com ptabela
     vnvldif := vnptabelasemimposto - vnpvendasemimposto;

     vnpercdif := ( vnvldif * 100)/vnptabelasemimposto ;

     --diferença ptabela com pbaserca
     vnvldif2 := vnptabelasemimposto - vnpbasercasemimposto;

     vnpercdif2 := ( vnvldif2 * 100)/vnptabelasemimposto ;

     --Calcular novo st para pvenda
     if p_regcliente.simplesnacional = 'S' then
         if p_regprecos.pauta > 0 or nvl(p_regprecos.iva,0) > 0 or (p_regprecos.aliqicms1 > 0 or p_regprecos.aliqicms2 > 0)  then

          vnnovopvenda := func_calculanovopvenda(vnpvendasemimposto,
                                                p_regpedido,
                                                p_regproduto,
                                                p_regprecos);


         end if;

     end if;

     --somar novo st ao pvenda
     p_regitem.pvenda := nvl(vnnovopvenda,vnpvendasemimposto);

     vniva := p_regprecos.iva;

     --Calcular novo st para ptabela
     if p_regcliente.simplesnacional = 'S' then
         if p_regprecos.pauta > 0 or nvl(p_regprecos.iva,0) > 0 or (p_regprecos.aliqicms1 > 0 or p_regprecos.aliqicms2 > 0)  then

            vnnovoptabela := func_calculanovopvenda(vnptabelasemimposto,
                                                    p_regpedido,
                                                    p_regproduto,
                                                    p_regprecos);


         end if;

     end if;



     --somar novo st ao ptabela
     p_regproduto.ptabela := nvl(vnnovoptabela,vnptabelasemimposto);


     vniva := p_regprecos.iva;

     --Calcular novo st para pbaserca
     if p_regcliente.simplesnacional = 'S' then
         if p_regprecos.pauta > 0 or nvl(p_regprecos.iva,0) > 0 or (p_regprecos.aliqicms1 > 0 or p_regprecos.aliqicms2 > 0)  then

            vnnovopbaserca :=  func_calculanovopvenda(vnpbasercasemimposto,
                                                p_regpedido,
                                                p_regproduto,
                                                p_regprecos);


         end if;

     end if;

     --somar novo st ao ptabela
     p_regitem.pbaserca := nvl(vnnovopbaserca,vnpbasercasemimposto);



   else

    vnvldif := 0;
    vnpercdif := 0;


 --diferença pvenda com ptabela
     vnvldif := p_regproduto.ptabela - p_regitem.pvenda;

     vnpercdif := ( vnvldif * 100)/p_regproduto.ptabela ;

     --diferença ptabela com pbaserca
     vnvldif2 := p_Regproduto.ptabela - p_regitem.pbaserca;

     vnpercdif2 := ( vnvldif2 * 100)/p_regproduto.ptabela ;


   end if;

    p_percdif := vnpercdif;
    p_percdif2 := vnpercdif2;



  EXCEPTION
    WHEN OTHERS THEN
      p_mensagem := 'Erro ao encontrar pvenda :' || SQLCODE || '-' ||
                    DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM;
  END proc_encontrapvenda;



PROCEDURE proc_encontracmvcomred (p_regitem       IN t_itemped,
                               p_regpedido        IN t_cabped,
                               p_regcliente       IN t_clientepedido,
                               p_regregiao        IN t_regiaocliente,
                               p_regrca           IN t_rca,
                               p_regfilial        IN t_filial,
                               p_regproduto       IN OUT t_produto,
                               p_regprecos        IN OUT t_precosetributacao,
                               p_vlcustofimsemimposto OUT number,
                               p_mensagem         OUT VARCHAR2) IS



    vsuffilial                      pcfilial.uf%type;
    vsmensagemredsimplesnac         varchar2(1000);
    vnvlreducao                     number;
    vbcalcularedsimplesnac          boolean;
    vbcalculastvalido               boolean;
    vnpbaserca                      pcpedi.pbaserca%type;
    vnvlipi                         pcpedi.vlipi%type;
    vnpercipi                       pcpedi.percipi%type;
    vsuffilialnf                    pcfilial.uf%type;
    vscalcularipivenda              pcfilial.calcularipivenda%type;
    vsmensagem_st                   varchar2(1000);
    vnstpvenda                      pcpedi.st%type;
    vnbaseicst                      pcpedi.baseicst%type;
    vnvldif                         number;
    vnpercdif                       number;
    vnpvenda                        pcpedi.pvenda%type;
    vnptabela                       pcpedi.ptabela%type;
    vniva                           pcpedi.iva%type;
    vnperdesc                       number;
    vnperluc                        number;
    vbcodicmtabpf                   boolean;
    vsmensagem_comiss               varchar2(1000);
    vnperfretecmv                   pcpedi.perfretecmv%type;
    vnCUSTOFINEST                   pcpedi.custofinest%type;
    vntxvenda                       pcpedi.txvenda%type;
    vnperdesccusto                  pcpedi.perdesccusto%type;
    vnCODICMTAB                     pcpedi.codicmtab%type;
    vnVLCUSTOREAL                   pcpedi.vlcustoreal%type;
    vnVLCUSTOFIN                    pcpedi.vlcustofin%type;
    vnVLDESCCUSTOCMV                pcpedi.vldesccustocmv%type;
    vnpercom                        pcpedi.percom%type;
    vsletracomiss                   pcpedi.letracomiss%type;
    vnVLREDPVENDASIMPLESNA          number;
    vncodaux                       number;

    vicont                          number;
    vbUsaPcTabComiss                boolean;
    vbUsaPcComissaoUsur             boolean;
    vbUsaPCComissaoPlPag            boolean;
    vbUsaPCComissaoRegiao           boolean;
    vbUsaPCComissaofilial           boolean;
    vncodcomiss                     pcorigemcomis.codcomis%type;
    vncodrotinacomiss               pcorigemcomis.codrotinacomis%type;

    vvPromocaoPriorizaComissao      PCPROMOCAOMED.PRIORIZACOMISSAO%type; -- 5047.047570.2016

    vnPRODIMPORTADOPEPS             pcpedi.prodimportadopeps%type; -- HIS.02787.2016
    vnNUMTRANSENTPEPS               pcpedi.numtransentpeps%type;   -- HIS.02787.2016
    vvMsgErroCalcularCMV            varchar2(2000);                -- HIS.02787.2016

    vnPerComIntegradora             NUMBER;

    -- DDMEDICA-3639   Simples Nacional ST Fonte na Integradora
    TYPE TRecRetSimplesNac            IS RECORD(
         vTipoRedSimplesNac           VARCHAR2(255),
         nPercRedSimplesNac           NUMBER,
         nValorRedSimplesNac          NUMBER,
         nValorRedSimplesNacNoPreco   NUMBER,
         nValorRedSimplesNacNoStFonte NUMBER,
         vOcorreramErros              VARCHAR2(255),
         vMsgErros                    VARCHAR2(255));
    vrRetSimplesNac                   TRecRetSimplesNac;

  BEGIN


    vnpvenda := p_regitem.pvenda;
    vnptabela := p_regproduto.ptabela;
    vnpbaserca := p_regitem.pbaserca;

    select uf,pcfilial.calcularipivenda
    into vsuffilial,vscalcularipivenda
    from pcfilial
    where codigo = p_regpedido.codfilial;

    select uf
    into vsuffilialnf
    from pcfilial
    where codigo = nvl(p_regcliente.codfilialnf, p_regpedido.codfilial);

    if p_regprecos.codicmtabpf is null
    then
      vbcodicmtabpf := true;
    else
      vbcodicmtabpf := false;
    end if;

    vnvldif := vnptabela - vnpvenda;

    vnpercdif := ( vnvldif * 100)/vnptabela;

     -- DDMEDICA-3639 - Simples Nacional ST Fonte na Integradora
     IF (NVL(p_regcliente.clientefontest,'N')   = 'S') AND
        (NVL(p_regcliente.simplesnacional,'N')  = 'S') AND
        (NVL(p_regfilial.usadescsimplesnac,'N') = 'N') THEN

       PKG_MEDICAMENTOS.P_CALC_RED_SIMPLES_NAC(p_regpedido.codfilial,
                                               p_regpedido.codcli,
                                               p_regproduto.codprod,
                                               p_regpedido.condvenda,
                                               vnpvenda,
                                               vnptabela,
                                               vnvlipi,
                                               0, -- pi_nPrecoMaxConsum,
                                               p_regproduto.tipomerc,
                                               p_regcliente.codfilialnf,
                                               vrRetSimplesNac.vTipoRedSimplesNac,
                                               vrRetSimplesNac.nPercRedSimplesNac,
                                               vrRetSimplesNac.nValorRedSimplesNac,
                                               vrRetSimplesNac.nValorRedSimplesNacNoPreco,
                                               vrRetSimplesNac.nValorRedSimplesNacNoStFonte,
                                               vrRetSimplesNac.vOcorreramErros,
                                               vrRetSimplesNac.vMsgErros,
                                               p_regregiao.numregiao, -- DDVENDAS-33718
                                               p_regcliente.estent);  -- DDVENDAS-33718
       -->> Se Redução no Preço
       IF (vrRetSimplesNac.vTipoRedSimplesNac = 'P') THEN
         vnVLREDPVENDASIMPLESNA := NVL(vrRetSimplesNac.nValorRedSimplesNacNoPreco,0);
       END IF;

     ELSE

        vbcalcularedsimplesnac := funcoesvendas.calcularredsimplesnac(p_regprecos.custofin,
                                                                      p_regprecos.custonfsemst,
                                                                      p_regprecos.custonfsemstguiaultent,
                                                                      p_regprecos.ivaultent,
                                                                      p_regprecos.aliqicms1ultent,
                                                                      p_regprecos.aliqicms2ultent,
                                                                      p_regprecos.redbaseivaultent,
                                                                      p_regprecos.percicmsfretefobstultent,
                                                                      p_regprecos.vlfreteconhecultent,
                                                                      p_regprecos.percaliqextguiaultent,
                                                                      p_regprecos.vlstultent,
                                                                      p_regprecos.baseicmsultent,
                                                                      p_regprecos.vlstguiaultent,
                                                                      p_regprecos.PERCREDPVENDASIMPLESNAC,
                                                                      gregpcconsum.numcasasdecvenda,
                                                                      null,
                                                                      null,
                                                                      null,
                                                                      null,
                                                                      vsmensagemredsimplesnac,
                                                                      vnVLREDPVENDASIMPLESNA);

   END IF;

    vnpvenda := round(vnpvenda - nvl(vnVLREDPVENDASIMPLESNA,0),gregpcconsum.numcasasdecvenda);
    vnptabela := round(vnptabela - nvl(vnVLREDPVENDASIMPLESNA,0),gregpcconsum.numcasasdecvenda);

   if vnpercdif <> 0 then
        vnpvenda := vnptabela - (vnptabela * (vnpercdif/100));

    end if;


       vniva := p_regprecos.iva;

     --Calcular novo st para pvenda

                    --50 parametros
                    vbcalculastvalido := funcoesvendas.calcularimpostos(vnpvenda,
                                                                        vnptabela,
                                                                        vnpbaserca,
                                                                        vnvlipi,
                                                                        vnpercipi,
                                                                        nvl(p_regproduto.percipivenda, 0),
                                                                        p_regpedido.percvenda,
                                                                        gregpcconsum.tipocalcst,
                                                                        gregpcconsum.calcstpf,
                                                                        p_Regprecos.mostrarpvendasemst,
                                                                        gregpcconsum.consideraisentoscomopf,
                                                                        p_regcliente.calculast,
                                                                        p_regcliente.ieent,
                                                                        p_regcliente.tipofj,
                                                                        p_regprecos.pauta,
                                                                        vniva,
                                                                        p_regprecos.aliqicms1,
                                                                        p_regprecos.aliqicms2,
                                                                        p_regprecos.percbaseredst,
                                                                        gregpcconsum.numcasasdecvenda,
                                                                        0,
                                                                        vsuffilial,
                                                                        p_regcliente.estent,
                                                                        nvl(p_regprecos.usavalorultentbasest,'N'),
                                                                        nvl(p_regprecos.usavalorultentbasest2,'N'),
                                                                        p_regprecos.valorultent,
                                                                        p_regcliente.isentoipi,
                                                                        0,
                                                                        gregpcconsum.calcularstcomipi,
                                                                        gregpcconsum.tipocalcipi,
                                                                        p_regcliente.codfilialnf,
                                                                        p_regpedido.condvenda,
                                                                        p_regcliente.contribuinte,
                                                                        vsuffilialnf,
                                                                        p_regproduto.importado,
                                                                        vscalcularipivenda,
                                                                        p_regproduto.PERCIPIVENDATAB ,
                                                                        p_regproduto.VLPAUTAIPIVENDA,
                                                                        p_regproduto.VLPAUTAIPIVENDATAB,
                                                                        p_regproduto.VLIPIPORKGVENDA,
                                                                        p_regproduto.VLIPIPORKGVENDATAB,
                                                                        p_regproduto.PESOBRUTO,
                                                                        p_regprecos.TIPOCALCULOGNRE,
                                                                        p_regcliente.simplesnacional,
                                                                        p_regprecos.PERCREDPVENDASIMPLESNAC ,
                                                                        'N',
                                                                        null ,
                                                                        vsmensagem_st,
                                                                        vnstpvenda,
                                                                        vnbaseicst,
                                                                        gregpcconsum.aceitapfcontribuinte,
                                                                        p_regprecos.custonfsemst,
                                                                        p_regprecos.usapmcbasest,
                                                                        p_regproduto.precomaxconsum,
                                                                        p_Regcliente.consumidorfinal,
                                                                        'N',
                                                                        p_regprecos.usavlultentmediobasest,
                                                                        p_regprecos.vlultentmes
                                                                        );


           --calcular cmv do preço de venda reduzido

               -- calcula o percentual de desconto
                vnperdesc := func_calcularperdescitem(vnptabela,vnpvenda,vncodaux);


                   -- HIS.02787.2016
                  p_calcularcmv_med(p_regfilial.tributsaidaorigemnacimp, -- HIS.02787.2016
                                          gregpcconsum.abaterimpostoscomissaorca,
                                          gregpcconsum.aplicarindicecmv,
                                          gregpcconsum.Incluircomissaosugpvendacmv,
                                          nvl(gregpcconsum.txvenda, 0),
                                          p_regcliente.tipofj,
                                          p_regcliente.utilizaiesimplificada,
                                          p_regcliente.ieent,
                                          p_regproduto.freteespecial,
                                          p_regregiao.PERFRETETERCEIROS,
                                          p_regregiao.PERFRETEESPECIAL,
                                          p_regprecos.custofin,
                                          p_regprecos.custoreal,
                                          p_regprecos.perdesccusto,
                                          p_regprecos.codicmtab,
                                          vbcodicmtabpf,
                                          p_regprecos.codicmtabpf,
                                          p_regpedido.percvenda,
                                          vnpvenda  ,
                                          0,
                                          vnSTpvenda,
                                          p_regitem.vlipi,
                                          0,
                                          p_regcliente.contribuinte,
                                          0,
                                          0,
                                          p_regcliente.consumidorfinal,
                                          nvl(gregpcconsum.consideraisentoscomopf,'N'),
                                          vnperfretecmv,
                                          vnCUSTOFINEST,
                                          vntxvenda,
                                          vnperdesccusto,
                                          vnCODICMTAB,
                                          vnVLCUSTOREAL,
                                          vnVLCUSTOFIN,
                                          vnVLDESCCUSTOCMV,
                                          p_regpedido.codcli,            -- HIS.02787.2016
                                          0, -- p_custoprecific          -- HIS.02787.2016
                                          p_regitem.codprod,             -- HIS.02787.2016
                                          p_regpedido.codfilial,         -- HIS.02787.2016
                                          p_regitem.qt,                  -- HIS.02787.2016
                                          p_regprecos.codicmtabinternac, -- HIS.02787.2016
                                          p_regitem.vldesccmvpromocaomed,-- DDMEDICA-5009
                                          0,                             -- DDMEDICA-7697 -- Aqui não tem O ST Recolhido Anteriormente
                                          vnPRODIMPORTADOPEPS,           -- HIS.02787.2016
                                          vnNUMTRANSENTPEPS,             -- HIS.02787.2016
                                          vvMsgErroCalcularCMV           -- HIS.02787.2016
                                          );

                -- 4493.064633.2016 - Tratamento de Erro por Divisão por Zero
                BEGIN
                  vnperluc := ((vnpvenda - vnVLCUSTOFIN) / vnpvenda )*100;
                EXCEPTION
                  WHEN ZERO_DIVIDE THEN
                    vnperluc := 0;
                END;


                -- busca percentual de comissao
                vsmensagem_comiss := NULL;
                    select count(*)
                    into vicont
                    from pctabcomiss p;

                    if vicont <> 0 then
                      vbUsaPcTabComiss := true;
                    else
                      vbUsaPcTabComiss := false;
                    end if;

                    select count(*)
                    into vicont
                    from pccomissaousur p;

                    if vicont <> 0 then
                      vbUsaPcComissaoUsur := true;
                    else
                      vbUsaPcComissaoUsur := false;
                    end if;


                    select count(*)
                    into vicont
                    from pccomissaoplpag p;

                    if vicont <> 0 then
                      vbUsaPcComissaoplpag := true;
                    else
                      vbUsaPCComissaoPlPag := false;
                    end if;


                    select count(*)
                    into vicont
                    from pccomissaoregiao p;

                    if vicont <> 0 then
                      vbUsaPcComissaoregiao := true;
                    else
                      vbUsaPcComissaoregiao := false;
                    end if;

                    if p_regfilial.broker = 'S' then
                       vbUsaPCComissaofilial := true;
                    else
                       vbUsaPCComissaofilial := false;
                    end if;

                  --Comissão Integradora OL [HIS.00490.2014]
                  if nvl(upper(p_regpedido.usacomissaointegradora),'N') = 'S' then

                    -- Comissão cadastrada na rotina 2302
                    vnpercom := p_regpedido.percom;

                   /*************************************
                    COMISSÃO: INTEGRADORA - DDMEDICA-1835
                    *************************************/
                    IF (INTEGRADORACOMPLE_MED.F_OBTER_COMISSAO_INTEGRADORA(p_regitem.coddesconto,
                                                                           p_regitem.codpromocaomed,
                                                                           p_regrca.tipovend,
                                                                           p_regitem.codprod,
                                                                           p_regpedido.integradora,
                                                                           vnPerComIntegradora) = 'S') THEN
                      vnpercom := vnPerComIntegradora;
                    END IF;

                  else

                      -- Verifica se a Promoção do Item Prioriza a Comissão -- 5047.047570.2016
                      BEGIN
                        SELECT PCPROMOCAOMED.PRIORIZACOMISSAO
                          INTO vvPromocaoPriorizaComissao
                          FROM PCPROMOCAOMED
                         WHERE (PCPROMOCAOMED.CODPROMOCAOMED = p_regitem.codpromocaomed);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          vvPromocaoPriorizaComissao := NULL;
                      END;

                     /***********************************
                      COMISSÃO: PEDIDO FV QUE USA PROMOÇÃO
                      ************************************/
                      IF ((NVL(p_regpedido.codpromocaomed,0)   > 0))   AND
                          (NVL(vvPromocaoPriorizaComissao,'N') = 'S')  THEN

                        -- Comissão cadastrada na rotina 2323
                        BEGIN
                          vnpercom := INTEGRADORACOMPLE_MED.F_OBTER_COMISSAO_PROMOCAO(p_regitem.coddesconto,
                                                                                      p_regitem.codpromocaomed,
                                                                                      p_regrca.tipovend,
                                                                                      p_regitem.codprod);
                        EXCEPTION
                          WHEN OTHERS THEN
                            vsmensagem_comiss :=  'Erro Cálculo Comissão Promoção : ' || SUBSTR('Erro: ' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,240);
                            proc_registralog(p_regpedido.numped,
                                             p_regpedido.numpedrca,
                                             p_regitem.codprod,
                                             p_regitem.codauxiliar,
                                             p_regitem.cgccli,
                                             null,
                                             null,
                                             null,
                                             p_regpedido.codusur,
                                             p_regitem.dtaberturapedpalm,
                                             null,
                                             '3',
                                            'Erro ao calcular comissão. '||SQLCODE||' '||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                                            null,
                                            p_regitem.numseqifv);
                        END;

                     /**********************
                      COMISSÃO: DEMAIS CASOS
                      **********************/
                      else

                        begin
                        vnpercom := FUNCOESVENDAS.Definir_Comissao_Item_Vendido
                                           (p_regregiao.numregiao,
                                            vnperluc,
                                            vnperdesc,
                                            vbUsaPcTabComiss,
                                            vbUsaPcComissaoUsur,
                                            vbUsaPCComissaoPlPag,
                                            vbUsaPCComissaoRegiao,
                                            vbUsaPCComissaofilial,
                                            gregpcconsum.usacomissaoporrca,
                                            gregpcconsum.OrdemAvaliacaoComissaoRCA,
                                            gregpcconsum.usacomissaoporcliente,
                                            gregpcconsum.USACOMISSAOPORLINHAPROD,
                                            gregpcconsum.comissaorcatipovenda,
                                            p_regrca.tipovend,
                                            p_regrca.percent,
                                            p_regrca.percent2,
                                            p_regproduto.codprod,
                                            p_regproduto.pcomint1,
                                            p_regproduto.PCOMEXT1,
                                            p_regproduto.PCOMREP1,
                                            p_regproduto.codlinhaprod,
                                            p_regproduto.tipocomissao,
                                            p_regproduto.codepto,
                                            p_regproduto.codsec,
                                            p_regproduto.classe,
                                            p_regitem.tipovenda,
                                            p_regitem.codplpag,
                                            p_regpedido.data,
                                            p_regpedido.codfilial,
                                            p_regpedido.codusur,
                                            p_regfilial.considerarcomissaozero,
                                            p_regfilial.tipoavaliacaocomissao,
                                            p_regcliente.percomcli,
                                            p_regcliente.codcli,
                                            p_regitem.coddesconto,
                                            vncodcomiss,
                                            vncodrotinacomiss,
                                            vsLetraComiss,
                                            vsmensagem_comiss,
                                            p_regitem.codauxiliar ,
                                            p_regprecos.pcomint1_emb,
                                            P_regprecos.PCOMEXT1_emb,
                                            P_regprecos.PCOMREP1_emb,
                                            p_regfilial.utilizavendaporembalagem
                                            );
                                     exception when others then
                                      proc_registralog(p_regpedido.numped,
                                                       p_regpedido.numpedrca,
                                                       p_regitem.codprod,
                                                       p_regitem.codauxiliar,
                                                       p_regitem.cgccli,
                                                       null,
                                                       null,
                                                       null,
                                                       p_regpedido.codusur,
                                                       p_regitem.dtaberturapedpalm,
                                                       null,
                                                       '3',
                                                      'Erro ao calcular comissão. '||SQLCODE||' '||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                                                      null,
                                                      p_regitem.numseqifv);

                                     end;

                       /****************************
                        COMISSÃO: ACORDO DE PARCERIA
                        ****************************/
                        IF (NVL(vncodrotinacomiss,0) <> 561) THEN
                          IF ((NVL(p_regpedido.codpromocaomed,0) > 0) AND
                              (NVL(p_regitem.priorizacomissacordoparceria,'N') = 'S')) THEN

                            vnpercom := NVL(p_regitem.percomacordoparceria,0);

                          END IF;
                        END IF;


                      end if; -- FIM CONDIÇÃO COMISSÃO: PEDIDO FV QUE USA PROMOÇÃO

                    end if; -- Fim Condição Se Comissão Integradora OL

                    -- HIS.03249.2016 - Tipos de Venda que não têm Comissão
                    IF (p_regpedido.condvenda IN (4, 5, 8, 9, 10, 13, 11, 20)) THEN
                       vnpercom := 0;
                    ELSIF(p_regpedido.aplicarperredcomiss = 'S') then
                      vnpercom := vnpercom * (1 - NVL(p_regitem.PERREDCOMISS,0) /100);
                    END IF;

                    -- Se Bloqueia a Comissão do RCA
                    IF (INTEGRADORACOMPLE_MED.F_BLOQUEIA_COMISSAO(NVL(p_regitem.codusurlinha,p_regpedido.codusur)) = 'S') THEN
                      vnpercom := 0;
                    END IF;

                IF vsmensagem_comiss IS NOT NULL
                THEN
                  proc_registralog(p_regpedido.numped,
                                   p_regpedido.numpedrca,
                                   p_regitem.codprod,
                                   p_regitem.codauxiliar,
                                   p_regpedido.cgccli,
                                   NULL,
                                   NULL,
                                   NULL,
                                   p_regpedido.codusur,
                                   p_regpedido.dtaberturapedpalm,
                                   null,
                                   '3',
                                   vsmensagem_comiss,
                                   NULL,
                                   p_regitem.numseqifv);
                END IF;



                  -- HIS.02787.2016
                  p_calcularcmv_med(p_regfilial.tributsaidaorigemnacimp, -- HIS.02787.2016
                                          gregpcconsum.abaterimpostoscomissaorca,
                                          gregpcconsum.aplicarindicecmv,
                                          gregpcconsum.Incluircomissaosugpvendacmv,
                                          nvl(gregpcconsum.txvenda,0),
                                          p_regcliente.tipofj,
                                          p_regcliente.utilizaiesimplificada,
