                                          p_regregiao.PERFRETEESPECIAL,
                                          p_regprecos.custofin ,
                                          p_regprecos.custoreal,
                                          p_regprecos.perdesccusto,
                                          p_regprecos.codicmtab,
                                          vbcodicmtabpf,
                                          p_regprecos.codicmtabpf,
                                          p_regpedido.percvenda,
                                          vnpvenda ,
                                          vnPERCOM,
                                          vnSTpvenda,
                                          0,
                                          0,
                                          p_regcliente.contribuinte,
                                          0,
                                          0 ,
                                          p_regcliente.consumidorfinal,
                                          nvl(gregpcconsum.consideraisentoscomopf,'N'),
                                          vnperfretecmv,
                                          vnCUSTOFINEST,
                                          vntxvenda,
                                          vnperdesccusto,
                                          vnCODICMTAB,
                                          vnVLCUSTOREAL,
                                          vnVLCUSTOFIN,
                                          vnVLDESCCUSTOCMV,
                                          p_regpedido.codcli,            -- HIS.02787.2016
                                          0, -- p_custoprecific          -- HIS.02787.2016
                                          p_regitem.codprod,             -- HIS.02787.2016
                                          p_regpedido.codfilial,         -- HIS.02787.2016
                                          p_regitem.qt,                  -- HIS.02787.2016
                                          p_regprecos.codicmtabinternac, -- HIS.02787.2016
                                          p_regitem.vldesccmvpromocaomed,-- DDMEDICA-5009
                                          0,                             -- DDMEDICA-7697 -- Aqui não tem O ST Recolhido Anteriormente
                                          vnPRODIMPORTADOPEPS,           -- HIS.02787.2016
                                          vnNUMTRANSENTPEPS,             -- HIS.02787.2016
                                          vvMsgErroCalcularCMV           -- HIS.02787.2016
                                          );


           -- fim calcular cmv do preço de venda sem impostos

         p_vlcustofimsemimposto := vnvlcustofin;






  EXCEPTION
    WHEN OTHERS THEN
      p_mensagem := 'Erro ao encontrar pvenda :' || SQLCODE || '-' ||
                    DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM;
  END proc_encontracmvcomred;

  ------------------------------------------------------------------------------
  -- Procedimento para arredondar o calculo da desoneração - DDMEDICA-2961
  ------------------------------------------------------------------------------
  FUNCTION F_ARREDONDAMENTO_DESONERACAO(pi_nValor            IN NUMBER,
                                        pi_vNumCasasDecimais IN NUMBER,
                                        pi_vRegraMinimo      IN VARCHAR2,
                                        pi_nCodSt            IN NUMBER)
  RETURN NUMBER IS
    nValorDesoneracao              NUMBER;
    vDESTACDESCICMISENCAOCOMERCIAL PCTRIBUT.DESTACDESCICMISENCAOCOMERCIAL%TYPE;
  BEGIN

    SELECT ROUND(pi_nValor,pi_vNumCasasDecimais) INTO nValorDesoneracao FROM DUAL;

    IF (nValorDesoneracao = 0) AND
       (pi_vRegraMinimo = 'S') THEN
      BEGIN
        SELECT PCTRIBUT.DESTACDESCICMISENCAOCOMERCIAL
          INTO vDESTACDESCICMISENCAOCOMERCIAL
          FROM PCTRIBUT
         WHERE (PCTRIBUT.CODST = pi_nCodSt);
      EXCEPTION
        WHEN NO_DATA_FOUND THEN
          vDESTACDESCICMISENCAOCOMERCIAL := 'N';
      END;
      IF (NVL(vDESTACDESCICMISENCAOCOMERCIAL,'N') <> 'S') THEN -- DDMEDICA-4289 - Isenção ST não participa da Regra
        -- DDMEDICA-4289 - Condicionar às casas decimais do preço de venda para não gerar preço negativo
        IF    (NVL(pi_vNumCasasDecimais,2) = 3) THEN
          nValorDesoneracao := 0.001;
        ELSIF (NVL(pi_vNumCasasDecimais,2) = 4) THEN
          nValorDesoneracao := 0.0001;
        ELSIF (NVL(pi_vNumCasasDecimais,2) = 5) THEN
          nValorDesoneracao := 0.00001;
        ELSIF (NVL(pi_vNumCasasDecimais,2) = 6) THEN
          nValorDesoneracao := 0.000001;
        ELSE
          nValorDesoneracao := 0.01;
        END IF;
      END IF;
    END IF;

    -- Retorno
    RETURN NVL(nValorDesoneracao,0);

  END F_ARREDONDAMENTO_DESONERACAO;

