    vnvlredcmvsimplesnac       pcpedi.vlredcmvsimplesnac%type;
    vnptabela                  pcpedi.ptabela%type;
    vsmensagempvenda           varchar2(1000);
    vsmensagemredsimplesnac    varchar2(1000);
    vbcalcularedsimplesnac     boolean;
    vnperlucsemred             number;
    vnvlcustofin               number;
    vnpercdif                  number;
    vniva                      pcpedi.iva%type;
    vsmensagemperluc           number;
    vnvlcustofinsemred         number;
    vnpvendainicio             number;
    vnvlcustofinsemimpostos    number;
    vsmensagemcustofin         varchar2(1000);
    vnpercdesccom              number;
    vnpercdescrca              number;


    vnpercom                   pcpedi.percom%type;

    vbUsaPcTabComiss           boolean;
    vbUsaPcComissaoUsur        boolean;
    vbUsaPCComissaoPlPag       boolean;
    vbUsaPCComissaoRegiao      boolean;
    vicont                     number;
    vbUsaPCComissaofilial      boolean;
    vbvalidodescontocombo      boolean;
    vsmensagemdescontocombo    varchar2(300);


    viexistebrinde              number;
    vnnumpedbrinde              pcpedc.numped%type;

    vsmensagembrinde            varchar2(3000);
    vsgeroubrinde               varchar2(1);

    viexisterestref             number;
    viexisterest                number;

    vsmensagemrestst            varchar2(1000);
    vnpedidorestst              pcpedc.numped%type;

     vsmensagempedidotv8         varchar2(1000);
    vnnumpedtv8                 pcpedc.numped%type;
    vsposicaotv8                pcpedc.posicao%type;
    vnmotivotv8                 varchar2(1000);

    -- INICIO: HIS.04557.2015 - ICMS Partilha
    tICMSPARTILHA               tipo_icms_partilha;
    vsMSGPartilha               varchar2(1000);
    vnCodMSGPartilha            number;
    -- FIM: HIS.04557.2015 - ICMS Partilha

    vvPromocaoPriorizaComissao  PCPROMOCAOMED.PRIORIZACOMISSAO%type; -- 5047.047570.2016

    -- PCNIL - Regra Específica Distribuidor de SC para não aplicar Redução do Simples Nacional no Preço
    vbAplicarRedSimplesNoPreco  BOOLEAN;

    -- Retorno procedimento para buscar o CFOP e CST -- HIS.03261.2016
    TYPE TRecRetDefinirCodFiscal  IS RECORD(
         vnCodFiscal              PCPEDI.CODFISCAL%TYPE,
         vvSitTrib                PCPEDI.SITTRIBUT%TYPE,
         vvTipoCodFiscal          VARCHAR2(100),
         vvTipoSitTrib            VARCHAR2(100));
    vrRetDefinirCodFiscal         TRecRetDefinirCodFiscal;
    vvMsgErroPartilha             VARCHAR2(200);

    vvMsgErroCalcularCMV          varchar2(2000); -- HIS.02787.2016

    -- HIS.03536.2016
    vvComboPrmValido              VARCHAR2(1);
    vvMotivoRejeicaoComboPrm      VARCHAR2(250);
    vvPodeGravarComboPrm          VARCHAR2(1);
    vvMotivoNaoPodeGravarComboPrm VARCHAR2(2000);
    -- MED-1510
    vsFoiPrecificadoComIpi        VARCHAR2(1);

    -- Taxa Frete
    TYPE TRecRetTaxaFrete         IS RECORD(
         vvAchouFrete             VARCHAR2(1),
         vnValorTaxa              NUMBER,
         vnValorMinimo            NUMBER);
    vrRetTaxaFrete                TRecRetTaxaFrete;

    -- Variável usada para evitar erro desnecessário por package de campanha inválida e o OL/PE não precisar apurar campanha brindes
    vbApurarCampanhaBrindes       BOOLEAN;

    vnPerComIntegradora           NUMBER;

    -- DDMEDICA-2349
    vvOcorreramErrosRecalcSt      VARCHAR2(1);
    vvMsgErrosRecalcSt            VARCHAR2(250);

    -- DDMEDICA-2832
    vbCalculouSTPacote            BOOLEAN;
    vnPTabelaSemImpostoPacote     NUMBER;
    vnPBaseRcaSemImpostoPacote    NUMBER;
    vnPVendaSemImpostoPacote      NUMBER;

    -- DDMEDICA-3639   Simples Nacional ST Fonte na Integradora
    TYPE TRecRetSimplesNac            IS RECORD(
         vTipoRedSimplesNac           VARCHAR2(255),
         nPercRedSimplesNac           NUMBER,
         nValorRedSimplesNac          NUMBER,
         nValorRedSimplesNacNoPreco   NUMBER,
         nValorRedSimplesNacNoStFonte NUMBER,
         vOcorreramErros              VARCHAR2(255),
         vMsgErros                    VARCHAR2(255));
    vrRetSimplesNac                   TRecRetSimplesNac;

    vvVersionamentoPkg                VARCHAR2(20);
    
    vnPRECOBRUTO                      NUMBER; -- DDMEDICA-5009
    
    -- DDMEDICA-6049
    vnNumCasasDecPrecoPrecificacao    NUMBER;

    -- DDMEDICA-7594 - Valores de Retorno da Procedure de Benefícios Fiscais
    vnPercDescSuframaResult           NUMBER;
    vnPrecoLiqResultAuxBF             NUMBER;
    vnPrecoTabResultAuxBF             NUMBER;
    vnPrecoRcaResultAuxBF             NUMBER;
    vvErrosBenefFiscaisBF             VARCHAR2(255);
    vvMsgErrosBenefFiscaisBF          VARCHAR2(4000);

    -- DDMEDICA-7697
    vnStClienteGnreFonte              PCPEDI.STCLIENTEGNRE%TYPE;
    TYPE TRecDadosStAntecip           IS RECORD(
         nBCSTRETANTERIOR             PCPEDI.BCSTRETANTERIOR%TYPE,
         nVLICMSSUBSTITUTOANTERIOR    PCPEDI.VLICMSSUBSTITUTOANTERIOR%TYPE,
         nVLICMSSTRETANTERIOR         PCPEDI.VLICMSSTRETANTERIOR%TYPE);
    vrDadosStAntecip                  TRecDadosStAntecip;
    vvRetClienteFonteSt               PCCLIENT.CLIENTEFONTEST%TYPE;

    -- DDVENDAS-38483
    vvOcorreramErrosQuebraPedido     VARCHAR2(1);
    vvMsgErrosQuebraPedido           VARCHAR2(4000);
    vvPosicaoQuebraPedido            PCPEDC.POSICAO%TYPE;
    vsAchouPedidoTV8                 VARCHAR2(1);

  begin
  
    vvVersionamentoPkg := F_OBTER_VERSIONAMENTO;
  
    vncontped := gvet_regpedido.count;

    if vncontped > 0 then

      for i in 1 .. vncontped loop
        vscoddistrib := null;

        begin

          proc_validarcabped(gvet_regpedido(i),
                             regcliente,
                             regrca,
                             regregiao,
                             regplpag,
                             regplpagetico,
                             regplpaggenerico,
                             regcob,
                             regfilial);

          if gvet_regpedido(i).valido = true then

            vncontitem         := gvet_regitem.count;
            vncontcombo        := gvet_regcombo.count; -- HIS.03536.2016
            vncontitematual    := 0;
            vncontcomboatual   := 0; -- HIS.03536.2016
            vnnumseq           := 0;
            vnmaxnumseq        := 0;
            vncontitensvalidos := 0;
            vnvltotped         := 0;
            vnvltottab         := 0;
            vnvltotbaserca     := 0;
            vntotpesoped       := 0;
            vntotvolumeped     := 0;
            vnvlcustocontped   := 0;
            vnvlcustofinped    := 0;
            vnvlcustorealped   := 0;
            vnvlcustorepped    := 0;
            vnqtinicial        := 0;



            if nvl(gvet_regpedido(i).numpedorig, 0) <> 0 then

              select sum(pcpedi.qt * pcpedi.pvenda),
                     sum(pcpedi.qt * pcpedi.ptabela),
                     sum(pcpedi.qt * pcpedi.pbaserca),
                     max(numseq),
                     count(*)
                into vnvltotped_ant,
                     vnvltottab_ant,
                     vnvltotbaserca_ant,
                     vnnumseq,
                     vnqtinicial
                from pcpedi
               where pcpedi.numped = gvet_regpedido(i).numped;

              vnsaldo_ant := vnvltotped_ant -
                             nvl(vnvltotbaserca_ant, vnvltottab_ant);
              vnnumseq    := nvl(vnnumseq, 0);
              vnmaxnumseq := nvl(vnnumseq, 0);

            end if;

            for j in 1 .. vncontitem loop


                vnpercdesccom := 0;
                vnpercdescrca := 0;


              begin

                if
                    (gvet_regpedido(i).numpedrca = gvet_regitem(j).numpedrca AND
                    gvet_regpedido(i).cgccli    = gvet_regitem(j).cgccli    AND
                    gvet_regpedido(i).codusur   = gvet_regitem(j).codusur   AND
                    gvet_regpedido(i).dtaberturapedpalm = gvet_regitem(j).dtaberturapedpalm AND
                    ((nvl(gvet_regpedido(i).numpedorig, 0) = 0) or
                   (nvl(gvet_regpedido(i).numpedorig, 0) <> 0 and
                    (gvet_regpedido(i).numpedorig = gvet_regitem(j).numpedorig)))) then

                  if (nvl(gvet_regpedido(i).tipofv,'FV') in ('OL','PE')) THEN --validação de itens para pedidos OL e PE

                    proc_validaritemOLePE(gvet_regitem(j),
                                          gvet_regorigempreco(j),
                                          gvet_regpedido(i),
                                          regcliente,
                                          regrca,
                                          regregiao,
                                          regplpag,
                                          regplpagetico,
                                          regplpaggenerico,
                                          regfilial,
                                          regproduto,
                                          regprecos,
                                          vscoddistrib);

                  else --validação de itens para pedidos do Força de Vendas

                    proc_validaritemped(gvet_regitem(j),
                                        gvet_regorigempreco(j),
                                        gvet_regorigemcomiss(j),
                                        gvet_regorigemdesc(j),
                                        gvet_regpedido(i),
                                        regcliente,
                                        regrca,
                                        regregiao,
                                        regplpag,
                                        regplpagetico,
                                        regplpaggenerico,
                                        regfilial,
                                        regproduto,
                                        regprecos,
                                        vscoddistrib);
                  end if;

                  if gvet_regitem(j).valido = true then

                    -- LOG
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13);
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'INICIO DO CÁLCULO DOS IMPOSTOS';
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela: ' || regproduto.ptabela;
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda: '  || gvet_regitem(j).pvenda;
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'UF Entrega ao Processar Pedidos: ' || regcliente.estent; -- DDVENDAS-33718
                    
                    /*------------------------------------------------------------
                         CALCULAR ICMS PARTILHA (normal) - HIS.04557.2015
                    ------------------------------------------------------------*/
                    IF F_EXISTEICMSPARTILHA(GVET_REGPEDIDO(I).CODCLI,
                                            GVET_REGPEDIDO(I).CODFILIAL,
                                            GVET_REGPEDIDO(I).CODFILIALNF,
                                            regcliente.estent) THEN -- DDVENDAS-33718
                    BEGIN

                      -- Chama procedimento para buscar o CFOP e CST -- HIS.03261.2016
                      PKG_MEDICAMENTOS.P_DEFINIR_CODFISCAL(NVL(GVET_REGPEDIDO(I).CODFILIALNF,GVET_REGPEDIDO(I).CODFILIAL),
                                                           GVET_REGPEDIDO(I).CODCLI,
                                                           gvet_regitem(j).codprod,
                                                           regprecos.codst,
                                                           gvet_regpedido(i).condvenda,
                                                           NULL, -- pi_nNumNotaConsign // Aqui na 2316 não tem Devolução Simbólica
                                                           NULL, -- pi_vTipoCfopTv4 // ICMS Partilha somente TV1 e TV5
                                                           gvet_regpedido(i).codcob,
                                                           NULL, -- pi_vProntaEntrega // ICMS Partilha somente TV1 e TV5
                                                           NULL, -- pi_vUsaCfopVendaNaTv10 // ICMS Partilha somente TV1 e TV5
                                                           NULL, -- pi_vVendaTriangular // ICMS Partilha somente TV1 e TV5
                                                           NULL, -- pi_vContaOrdem // ICMS Partilha somente TV1 e TV5
                                                           NULL, -- pi_nCodBnf
                                                           NULL, -- pi_vFornecEntrega // ICMS Partilha somente TV1 e TV5
                                                           NULL, -- pi_nNumTransEntOrigConsig // Aqui na 2316 não tem Devolução Simbólica
                                                           NULL, -- pi_nCfopNfDegusta // ICMS Partilha somente TV1 e TV5
                                                           0,    -- pi_nVlDescSuframa
                                                           gvet_regitem(j).pvenda,
                                                           'N', -->> Não é Item Bonificado
                                                           NULL, -- pi_vRegimeEspIsenStFonte // Se não passar esta opção, a procedure realiza o cálculo
                                                           vrRetDefinirCodFiscal.vnCodFiscal,
                                                           vrRetDefinirCodFiscal.vvSitTrib,
                                                           vrRetDefinirCodFiscal.vvTipoCodFiscal,
                                                           vrRetDefinirCodFiscal.vvTipoSitTrib,
                                                           regcliente.estent); -- DDVENDAS-33718

                      -- Grava CODFISCAL e CST - HIS.03261.2016
                      gvet_regitem(j).codfiscal := vrRetDefinirCodFiscal.vnCodFiscal;
                      gvet_regitem(j).sittribut := vrRetDefinirCodFiscal.vvSitTrib;

                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'CodFiscal: '     || NVL(vrRetDefinirCodFiscal.vnCodFiscal,0);
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'SitTrib: '       || NVL(vrRetDefinirCodFiscal.vvSitTrib,' ');
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'TipoCodFiscal: ' || NVL(vrRetDefinirCodFiscal.vvTipoCodFiscal,' ');
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'TipoSitTrib: '   || NVL(vrRetDefinirCodFiscal.vvTipoSitTrib,' ');

                      pkg_fwpc_fiscal.icmspartilha_calcular_1_4(NVL(GVET_REGPEDIDO(I).CODFILIALNF,GVET_REGPEDIDO(I).CODFILIAL),
                                                                GVET_REGPEDIDO(I).CODCLI,
                                                                '', -- P_UFOPERCONSUM
                                                                '', -- P_UFENTREGA
                                                                GVET_REGPEDIDO(I).DATA,
                                                                regproduto.ptabela,
                                                                regprecos.codst,
                                                                gvet_regitem(j).codprod,
                                                                vrRetDefinirCodFiscal.vnCodFiscal, -- HIS.03261.2016
                                                                vrRetDefinirCodFiscal.vvSitTrib,   -- HIS.03261.2016
                                                                tICMSPARTILHA,
                                                                vnCodMSGPartilha,
                                                                vsMSGPartilha);

                      regproduto.ptabela := regproduto.ptabela + NVL(tICMSPARTILHA.VLICMSPART,0);

                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor ICMS Partilha: ' || NVL(tICMSPARTILHA.VLICMSPART,0);
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela com ICMS Partilha: ' || regproduto.ptabela;

                      if GVET_REGPEDIDO(I).precocompartilha = 'S' then
                        gvet_regitem(j).pvenda := gvet_regitem(j).pvenda - nvl(gvet_regitem(j).vlicmspart,0);
                        -- LOG
                        gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda SEM ICMS Partilha: ' || gvet_regitem(j).pvenda;
                      end if;

                      pkg_fwpc_fiscal.icmspartilha_calcular_1_4(NVL(GVET_REGPEDIDO(I).CODFILIALNF,GVET_REGPEDIDO(I).CODFILIAL),
                                                                GVET_REGPEDIDO(I).CODCLI,
                                                                '', -- P_UFOPERCONSUM
                                                                '', -- P_UFENTREGA
                                                                GVET_REGPEDIDO(I).DATA,
                                                                gvet_regitem(j).pvenda,
                                                                regprecos.codst,
                                                                gvet_regitem(j).codprod,
                                                                vrRetDefinirCodFiscal.vnCodFiscal, -- HIS.03261.2016
                                                                vrRetDefinirCodFiscal.vvSitTrib,   -- HIS.03261.2016
                                                                tICMSPARTILHA,
                                                                vnCodMSGPartilha,
                                                                vsMSGPartilha);

                      gvet_regitem(j).pvenda            := gvet_regitem(j).pvenda + NVL(tICMSPARTILHA.VLICMSPART,0);
                      -- LOG
                      gvet_regitem(j).logprocmed        := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda COM ICMS Partilha: ' || gvet_regitem(j).pvenda;
                      gvet_regitem(j).vlbasepartdest      := tICMSPARTILHA.vlbasepartdest;
                      gvet_regitem(j).aliqfcp             := tICMSPARTILHA.aliqfcp;
                      gvet_regitem(j).vlfcppart         := tICMSPARTILHA.vlfcppart;
                      gvet_regitem(j).vlicmspartdest      := tICMSPARTILHA.vlicmspartdest;
                      gvet_regitem(j).vlicmspart          := tICMSPARTILHA.vlicmspart;
                      gvet_regitem(j).vlicmsdifaliqpart := tICMSPARTILHA.VLICMSDIFALIQ;
                      gvet_regitem(j).percbaseredpart   := tICMSPARTILHA.PERCBASERED;
                      gvet_regitem(j).percprovpart      := tICMSPARTILHA.percprovpart;
                      gvet_regitem(j).vlicmspartrem     := tICMSPARTILHA.vlicmspartrem;
                      gvet_regitem(j).aliqinternadest   := tICMSPARTILHA.aliqinternadest;
                      gvet_regorigempreco(j).vlicmspart := tICMSPARTILHA.vlicmspart;
                      if  tICMSPARTILHA.vlicmspart = 0 then
                        gvet_regorigempreco(j).vlicmspart := tICMSPARTILHA.VLICMSDIFALIQ;
                      end if;


                      pkg_fwpc_fiscal.icmspartilha_calcular_1_4(NVL(GVET_REGPEDIDO(I).CODFILIALNF,GVET_REGPEDIDO(I).CODFILIAL),
                                                                GVET_REGPEDIDO(I).CODCLI,
                                                                '', -- P_UFOPERCONSUM
                                                                '', -- P_UFENTREGA
                                                                GVET_REGPEDIDO(I).DATA,
                                                                gvet_regitem(j).pbaserca,
                                                                regprecos.codst,
                                                                gvet_regitem(j).codprod,
                                                                vrRetDefinirCodFiscal.vnCodFiscal, -- HIS.03261.2016
                                                                vrRetDefinirCodFiscal.vvSitTrib,   -- HIS.03261.2016
                                                                tICMSPARTILHA,
                                                                vnCodMSGPartilha,
                                                                vsMSGPartilha);

                      gvet_regitem(j).pbaserca := gvet_regitem(j).pbaserca + NVL(tICMSPARTILHA.VLICMSPART,0);

                    EXCEPTION
                      WHEN OTHERS THEN
                        vvMsgErroPartilha :=  'Erro Cálculo Partilha : ' || SUBSTR(DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,200);
                        proc_registralog(gvet_regpedido(i).numped,
                                         gvet_regpedido(i).numpedrca,
                                         gvet_regitem(j).codprod,
                                         gvet_regitem(j).codauxiliar,
                                         gvet_regitem(j).cgccli,
                                         null,
                                         null,
                                         null,
                                         gvet_regpedido(i).codusur,
                                         gvet_regitem(j).dtaberturapedpalm,
                                         null,
                                         '3',
                                         vvMsgErroPartilha,
                                         null,
                                         gvet_regitem(j).numseqifv);
                    END;
                    END IF;
                    /*------------------------------------------------------------
                                       FIM CALCULAR ICMS PARTILHA
                    ------------------------------------------------------------*/



                    if regplpag.formaparcelamento = 'V' and gvet_regpedido(i).numpedorig = 0 then
                          if gvet_regpedido(i).percplpag is not null then


                           -- LOG
                           gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Aplicando aos preços percplpag: ' || gvet_regpedido(i).percplpag;
                           gvet_regitem(j).pvenda     := round(gvet_regitem(j).pvenda * (1 + (gvet_regpedido(i).percplpag / 100)),gregpcconsum.numcasasdecvenda);
                           regproduto.ptabela         := round(regproduto.ptabela * (1 + (gvet_regpedido(i).percplpag / 100)),gregpcconsum.numcasasdecvenda);
                           gvet_regitem(j).pbaserca   := round(gvet_regitem(j).pbaserca * (1 + (gvet_regpedido(i).percplpag / 100)),gregpcconsum.numcasasdecvenda);

                         end if;
                     end if;


                    if vscoddistrib is null then
                      vscoddistrib := regproduto.coddistrib;
                    end if;

                    vncontitematual := vncontitematual + 1;

                    begin
                      select pcfilial.uf
                        into vsuffilialnf
                        from pcfilial
                       where pcfilial.codigo = gvet_regpedido(i).codfilialnf;
                    exception
                      when others then
                        vsuffilialnf := null;
                    end;


                     if regprecos.codicmtabpf is null
                     then
                       vbcodicmtabpf := true;
                     else
                       vbcodicmtabpf := false;
                     end if;



                  if regcliente.simplesnacional = 'S' and regprecos.percredpvendasimplesnac <> 0 and gvet_regitem(j).aplicadescontosimples  = 'S' then

                     --só atualiza caso não tenha impostos
                     if (regprecos.aliqicms1 <= regprecos.aliqicms2)  and
                         regprecos.pauta = 0 and regprecos.iva = 0 then
                       --encontrar perluc antes dos calculos de redução do simples nacional

                       vnpvendainicio := gvet_regitem(j).pvenda;

                       -- LOG
                       gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda antes de aplicar percredpvendasimplesnac: ' || gvet_regitem(j).pvenda;

                       proc_encontraperluc (gvet_regitem(j),
                                            gvet_regpedido(i),
                                            regcliente,
                                            regproduto,
                                            regprecos,
                                            regrca,
                                            Regregiao,
                                            regfilial,
                                            vnperlucsemred,
                                            vsmensagemperluc
                                            )  ;

                          vnvlcustofinsemred := gvet_regitem(j).vlcustofin ;

                         -- LOG
                         gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela após aplicar percredpvendasimplesnac parte 2: ' || regproduto.ptabela;
                         gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda após aplicar percredpvendasimplesnac parte 1: '  || gvet_regitem(j).pvenda;

                     end if;
                   end if;




                   --Encontrar pvenda correto para o simples nacional
                   if regcliente.simplesnacional = 'S' and regprecos.percredpvendasimplesnac <> 0 and gvet_regitem(j).aplicadescontosimples  = 'S' and
                      NVL(regfilial.usadescsimplesnac,'N') = 'N' then --PCNIL - Somente se a Filial não Utilizar Desconto Simples Nacional

                        proc_encontracmvcomred (gvet_regitem(j),
                                                gvet_regpedido(i),
                                                regcliente,
                                                regregiao,
                                                regrca,
                                                regfilial,
                                                regproduto,
                                                regprecos,
                                                vnvlcustofinsemimpostos,
                                                vsmensagemcustofin) ;

                     IF vsmensagemcustofin IS NOT NULL
                       THEN
                         proc_registralog(gvet_regpedido(i).numped,
                                          gvet_regpedido(i).numpedrca,
                                          gvet_regitem(j).codprod,
                                          gvet_regitem(j).codauxiliar,
                                          gvet_regitem(j).cgccli,
                                          null,
                                          null,
                                          null,
                                          gvet_regpedido(i).codusur,
                                          gvet_regitem(j).dtaberturapedpalm,
                                          null,
                                          '3',
                                          vsmensagemcustofin,
                                          NULL,
                                          gvet_regitem(j).numseqifv);
                       END IF;



                     if (regprecos.pauta > 0 or nvl(regprecos.iva,0) > 0 or nvl(regprecos.aliqicms1,0) > 0 or nvl(regprecos.aliqicms2,0) > 0) or
                          gvet_regitem(j).pvenda <> regproduto.ptabela  then


                      proc_encontrapvenda (gvet_regitem(j),
                                           gvet_regpedido(i),
                                           regcliente,
                                           regregiao,
                                           regrca,
                                           regproduto,
                                           regprecos ,
                                           vnpercdesccom,
                                           vnpercdescrca,
                                           vsmensagempvenda);

                     -- LOG
                     gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela após aplicar percredpvendasimplesnac parte 2: ' || regproduto.ptabela;
                     gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda após aplicar percredpvendasimplesnac parte 2: '  || gvet_regitem(j).pvenda;

                     IF vsmensagempvenda IS NOT NULL
                       THEN
                         proc_registralog(gvet_regpedido(i).numped,
                                          gvet_regpedido(i).numpedrca,
                                          gvet_regitem(j).codprod,
                                          gvet_Regitem(j).codauxiliar,
                                           gvet_regitem(j).cgccli,
                                           null,
                                           null,
                                           null,
                                           gvet_regpedido(i).codusur,
                                           gvet_regitem(j).dtaberturapedpalm,
                                           null,
                                          '3',
                                          vsmensagempvenda,
                                          NULL,
                                          gvet_regitem(j).numseqifv);
                       END IF;
                    end if;


                   end if; -- FIM: Encontrar pvenda correto para o simples nacional


                    gvet_regitem(j).iva           := regprecos.iva;
                    gvet_regitem(j).pauta         := regprecos.pauta;
                    gvet_regitem(j).aliqicms1     := regprecos.aliqicms1;
                    gvet_regitem(j).aliqicms2     := regprecos.aliqicms2;
                    gvet_regitem(j).percbaseredst := regprecos.percbaseredst;

                    -- DDMEDICA-6049 - Número de Casas Decimais diferenciado para cálculo do Preço sem Impostos da Precificação
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'USARARREDONDAMENTODIFPRECOST: ' || regfilial.usararredondamentodifprecost;                      
                    IF (NVL(regfilial.usararredondamentodifprecost,'N') = 'S') THEN
                      vnNumCasasDecPrecoPrecificacao := 12;
                    ELSE
                      vnNumCasasDecPrecoPrecificacao := gregpcconsum.numcasasdecvenda;
                    END IF;
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'NumCasasDecPrecoPrecificacao: ' || vnNumCasasDecPrecoPrecificacao;

                   /*******************************************************************
                    Cálculo do ST Precificação Pacote - DDMEDICA-2832
                    *************************************************/
                    IF (NVL(regfilial.UTILIZACALCULOSTPACOTE,'N')  = 'S') THEN

                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13);
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'INICIANDO O CÁLCULO DOS IMPOSTOS NA PRECIFICACAO PAC:';
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela: ' || regproduto.ptabela;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda: '  || gvet_regitem(j).pvenda;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'PBaseRca: '     || gvet_regitem(j).pbaserca;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor IPI: '    || gvet_regitem(j).vlipi;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% IPI: '        || gvet_regitem(j).percipi;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% IPI: '        || nvl(regproduto.percipivenda, 0);
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'FoiPrecificadoComIpi: ' || vsFoiPrecificadoComIpi; -- MED-1510

                      -- PTABELA
                      vbCalculouSTPacote := INTEGRADORACOMPLE_MED.FCALCULAR_ST(gregpcconsum.numcasasdecvenda,
                                                                               gvet_regpedido(i).codfilial,
                                                                               gvet_regpedido(i).codfilialnf,
                                                                               gvet_Regitem(j).codfilialretira,
                                                                               gvet_regpedido(i).codcli,
                                                                               gvet_regpedido(i).codplpag,
                                                                               gvet_Regitem(j).codprod,
                                                                               gvet_Regitem(j).codauxiliar,
                                                                               gvet_regpedido(i).condvenda,
                                                                               regregiao.numregiao,
                                                                               regproduto.ptabela,
                                                                               'N', -- pi_vITEMBNF
                                                                               0,   -- pi_nVALORDESCPIS_COFINS
                                                                               0,   -- pi_nVALORDESCICMS
                                                                               0,   -- pi_nVALORSUFRAMA
                                                                               vsmensagem_st,
                                                                               gvet_regitem(j).st,
                                                                               gvet_regitem(j).baseicst,
                                                                               gvet_regitem(j).vlipi,
                                                                               gvet_regitem(j).vlbasefcpst,
                                                                               gvet_regitem(j).aliqicmsfecp,
                                                                               gvet_regitem(j).vlfecp,
                                                                               vnPTabelaSemImpostoPacote);


                      if vsmensagem_st is not null then
                        proc_registralog(gvet_regpedido(i).numped,
                                         gvet_regpedido(i).numpedrca,
                                         gvet_regitem(j).codprod,
                                         gvet_Regitem(j).codauxiliar,
                                         gvet_regitem(j).cgccli,
                                         null,
                                         null,
                                         null,
                                         gvet_regpedido(i).codusur,
                                         gvet_regitem(j).dtaberturapedpalm,
                                         null,
                                         '3',
                                         vsmensagem_st,
                                         null,
                                         gvet_regitem(j).numseqifv);
                      end if;

                      -- PBASERCA
                      vbCalculouSTPacote := INTEGRADORACOMPLE_MED.FCALCULAR_ST(gregpcconsum.numcasasdecvenda,
                                                                               gvet_regpedido(i).codfilial,
                                                                               gvet_regpedido(i).codfilialnf,
                                                                               gvet_Regitem(j).codfilialretira,
                                                                               gvet_regpedido(i).codcli,
                                                                               gvet_regpedido(i).codplpag,
                                                                               gvet_Regitem(j).codprod,
                                                                               gvet_Regitem(j).codauxiliar,
                                                                               gvet_regpedido(i).condvenda,
                                                                               regregiao.numregiao,
                                                                               gvet_regitem(j).pbaserca,
                                                                               'N', -- pi_vITEMBNF
                                                                               0,   -- pi_nVALORDESCPIS_COFINS
                                                                               0,   -- pi_nVALORDESCICMS
                                                                               0,   -- pi_nVALORSUFRAMA
                                                                               vsmensagem_st,
                                                                               gvet_regitem(j).st,
                                                                               gvet_regitem(j).baseicst,
                                                                               gvet_regitem(j).vlipi,
                                                                               gvet_regitem(j).vlbasefcpst,
                                                                               gvet_regitem(j).aliqicmsfecp,
                                                                               gvet_regitem(j).vlfecp,
                                                                               vnPBaseRcaSemImpostoPacote);

                      if vsmensagem_st is not null then
                        proc_registralog(gvet_regpedido(i).numped,
                                         gvet_regpedido(i).numpedrca,
                                         gvet_regitem(j).codprod,
                                         gvet_Regitem(j).codauxiliar,
                                         gvet_regitem(j).cgccli,
                                         null,
                                         null,
                                         null,
                                         gvet_regpedido(i).codusur,
                                         gvet_regitem(j).dtaberturapedpalm,
                                         null,
                                         '3',
                                         vsmensagem_st,
                                         null,
                                         gvet_regitem(j).numseqifv);
                      end if;

                      -- PVENDA
                      vbCalculouSTPacote := INTEGRADORACOMPLE_MED.FCALCULAR_ST(gregpcconsum.numcasasdecvenda,
                                                                               gvet_regpedido(i).codfilial,
                                                                               gvet_regpedido(i).codfilialnf,
                                                                               gvet_Regitem(j).codfilialretira,
                                                                               gvet_regpedido(i).codcli,
                                                                               gvet_regpedido(i).codplpag,
                                                                               gvet_Regitem(j).codprod,
                                                                               gvet_Regitem(j).codauxiliar,
                                                                               gvet_regpedido(i).condvenda,
                                                                               regregiao.numregiao,
                                                                               gvet_regitem(j).pvenda,
                                                                               'N', -- pi_vITEMBNF
                                                                               0,   -- pi_nVALORDESCPIS_COFINS
                                                                               0,   -- pi_nVALORDESCICMS
                                                                               0,   -- pi_nVALORSUFRAMA
                                                                               vsmensagem_st,
                                                                               gvet_regitem(j).st,
                                                                               gvet_regitem(j).baseicst,
                                                                               gvet_regitem(j).vlipi,
                                                                               gvet_regitem(j).vlbasefcpst,
                                                                               gvet_regitem(j).aliqicmsfecp,
                                                                               gvet_regitem(j).vlfecp,
                                                                               vnPVendaSemImpostoPacote);

                      if vsmensagem_st is not null then
                        proc_registralog(gvet_regpedido(i).numped,
                                         gvet_regpedido(i).numpedrca,
                                          gvet_regitem(j).codprod,
                                         gvet_Regitem(j).codauxiliar,
                                         gvet_regitem(j).cgccli,
                                         null,
                                         null,
                                         null,
                                         gvet_regpedido(i).codusur,
                                         gvet_regitem(j).dtaberturapedpalm,
                                         null,
                                         '3',
                                         vsmensagem_st,
                                         null,
                                         gvet_regitem(j).numseqifv);
                      end if;

                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13);
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'VALORES CALCULADOS DOS IMPOSTOS NA PRECIFICACAO PAC SEM IMP:';
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela: ' || vnPTabelaSemImpostoPacote;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'P.BaseRca: '    || vnPBaseRcaSemImpostoPacote;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda: '  || vnPVendaSemImpostoPacote;

                      -- ACRESCENTA O IPI NOS PREÇOS
                      regproduto.ptabela       := ROUND((NVL(vnPTabelaSemImpostoPacote,0)  + NVL(gvet_regitem(j).vlipi,0)), NVL(gregpcconsum.numcasasdecvenda,0));
                      gvet_regitem(j).pbaserca := ROUND((NVL(vnPBaseRcaSemImpostoPacote,0) + NVL(gvet_regitem(j).vlipi,0)), NVL(gregpcconsum.numcasasdecvenda,0));
                      gvet_regitem(j).pvenda   := ROUND((NVL(vnPVendaSemImpostoPacote,0)   + NVL(gvet_regitem(j).vlipi,0)), NVL(gregpcconsum.numcasasdecvenda,0));

                      -- Se o tipo do cálculo de GNRE for por Cliente
                      -- o ST deverá ser retirado do preço e zerado
                      IF NVL(regprecos.tipocalculognre,'X') = 'C' THEN

                        -- LOG
                        gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'ST GNRE';

                        gvet_regitem(j).stclientegnre := gvet_regitem(j).st;
                        gvet_regitem(j).st       := 0;
                        gvet_regitem(j).baseicst := 0;

                        -- Soma ST FCP ao Preço de Venda e Preço de Tabela conforme parametrização
                        regproduto.ptabela       := ROUND((NVL(regproduto.ptabela,0)       + NVL(gvet_regitem(j).vlfecp,0)), NVL(gregpcconsum.numcasasdecvenda,0));
                        gvet_regitem(j).pbaserca := ROUND((NVL(gvet_regitem(j).pbaserca,0) + NVL(gvet_regitem(j).vlfecp,0)), NVL(gregpcconsum.numcasasdecvenda,0));
                        gvet_regitem(j).pvenda   := ROUND((NVL(gvet_regitem(j).pvenda,0)   + NVL(gvet_regitem(j).vlfecp,0)), NVL(gregpcconsum.numcasasdecvenda,0));

                      ELSE

                        -- LOG
                        gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'NAO E ST GNRE';

                        -- Não tem ST GNRE
                        gvet_regitem(j).stclientegnre := NULL;

                        -- Soma ST ao Preço de Venda e Preço de Tabela conforme parametrização
                        regproduto.ptabela       := ROUND((NVL(regproduto.ptabela,0)       + NVL(gvet_regitem(j).st,0) + NVL(gvet_regitem(j).vlfecp,0)), NVL(gregpcconsum.numcasasdecvenda,0));
                        gvet_regitem(j).pbaserca := ROUND((NVL(gvet_regitem(j).pbaserca,0) + NVL(gvet_regitem(j).st,0) + NVL(gvet_regitem(j).vlfecp,0)), NVL(gregpcconsum.numcasasdecvenda,0));
                        gvet_regitem(j).pvenda   := ROUND((NVL(gvet_regitem(j).pvenda,0)   + NVL(gvet_regitem(j).st,0) + NVL(gvet_regitem(j).vlfecp,0)), NVL(gregpcconsum.numcasasdecvenda,0));

                      END IF;

                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13);
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'VALORES CALCULADOS DOS IMPOSTOS NA PRECIFICACAO PAC COM IMP:';
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela: ' || regproduto.ptabela;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'P. BaseRca: '   || gvet_regitem(j).pbaserca;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda: '  || gvet_regitem(j).pvenda;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor IPI: '    || gvet_regitem(j).vlipi;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% IPI: '        || gvet_regitem(j).percipi;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% IPI Venda: '  || nvl(regproduto.percipivenda, 0);
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Vl.ST: '        || gvet_regitem(j).st;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Base ST: '      || gvet_regitem(j).baseicst;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Vl.FECP: '      || gvet_regitem(j).vlfecp;

                   /*******************************************************************
                    Cálculo do ST Precificação Medicamentos - DDMEDICA-2832
                    *******************************************************/
                    ELSE
                    
                      ------------------------------------------------------------------------------------------------------------------
                      -- HIS.01858.2015 - Quando o ST for na Precificação, mas usou Operador Logístico a Preço Fábrica e somou
                      --                  o ST como se fosse ST Fonte, não pode manipular o conforme regras de imporstos na precificação
                      ------------------------------------------------------------------------------------------------------------------
                      IF (NVL(gvet_regitem(j).somoustptabela,'N') = 'S') THEN

                        -- LOG
                        gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13);
                        gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'SEM O CÁLCULO DOS IMPOSTOS NA PRECIFICACAO MED (SOMOU ST PTABELA):';

                        gvet_regitem(j).baseicst := 0;
                        gvet_regitem(j).st       := 0;

                      ELSE

                        begin

                          -- MED-1510
                          vsFoiPrecificadoComIpi := 'N';
                          IF (NVL(regprecos.vlipi,0) > 0) THEN
                            vsFoiPrecificadoComIpi := 'S';
                          END IF;

                          -- LOG
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13);
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'INICIANDO O CÁLCULO DOS IMPOSTOS NA PRECIFICACAO MED:';
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela: ' || regproduto.ptabela;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda: '  || gvet_regitem(j).pvenda;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'P. BaseRca: '   || gvet_regitem(j).pbaserca; -- DDMEDICA-7609
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor IPI: '    || gvet_regitem(j).vlipi;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% IPI: '        || gvet_regitem(j).percipi;
