                                                                              regproduto.percipivendatab,
                                                                              regproduto.vlpautaipivenda,
                                                                              regproduto.vlpautaipivendatab,
                                                                              regproduto.vlipiporkgvenda,
                                                                              regproduto.vlipiporkgvendatab,
                                                                              regproduto.pesobruto,
                                                                              regprecos.tipocalculognre,
