                           if regprecos.tipocalculognre = 'C' then

                             begin
                               --24 parâmetros
                               vbcalculastvalido := funcoesvendas.calcularst(gvet_regitem(j).pvenda,
                                                                             0,
                                                                             gvet_regpedido(i).percvenda,
                                                                             gregpcconsum.tipocalcst,
                                                                             gregpcconsum.calcstpf,
