                               gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda após calcular impostos (tipocalculognre = C): '  || gvet_regitem(j).pvenda;

                            exception when others then
                               if gvet_Regitem(j).codmotivonaoatend is null then
                                  gvet_regitem(j).codmotivonaoatend := 30;
                                   end if;
                             end;

                           end if; -- Fim (regprecos.tipocalculognre = 'C')

                           if vsmensagem_st is not null then
