                    END IF; -- Fim Condição: Se ST Precificação de Cliente Pacote ou Medicamentos - DDMEDICA-2832
                   /*******************************************************************/

                    -- INICIO: MED-1510 - IPI Somado no Preço de Venda (Igual a 2316) -------------
                    IF (NVL(gregpcconsum.calcularstcomipi,'N') = 'N') THEN
                      -- Se Produto tem IPI
                      IF ((nvl(regproduto.percipivenda, 0) <> 0)
                        OR (nvl(regproduto.vlpautaipivenda,0) <> 0)
                        OR (nvl(regproduto.vlipiporkgvenda,0) <> 0))
                        AND (nvl(regcliente.isentoipi,'N') = 'N')
                        AND (nvl(gvet_regpedido(i).condvenda,0) <> 8) THEN
                        -- Se a Filial calcula IPI na Venda
                        IF (nvl(regfilial.calcularipivenda,'N') = 'S') THEN
                          -- LOG
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13);
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'INICIANDO O CÁLCULO DO IPI SOBRE O PREÇO DE VENDA:';
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Filial: '       || gvet_regpedido(i).codfilial;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Produto: '      || gvet_regitem(j).codprod;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Cliente: '      || gvet_regpedido(i).codcli;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Região: '       || regregiao.numregiao;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela: ' || regproduto.ptabela;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda: '  || gvet_regitem(j).pvenda;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'PbaseRca: '     || gvet_regitem(j).Pbaserca;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor IPI: '    || gvet_regitem(j).vlipi;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Vl.ST: '        || nvl(gvet_regitem(j).st,0);
                          -- Cálculo do IPI
                          if (nvl(regproduto.VLPAUTAIPIVENDA,0) > 0) then
                            gvet_regitem(j).vlipi := nvl(regproduto.VLPAUTAIPIVENDA,0);
                          else
                            if (nvl(regproduto.vlipiporkgvenda,0) > 0) then
                              gvet_regitem(j).vlipi := nvl(regproduto.PESOBRUTO,0) * nvl(regproduto.VLIPIPORKGVENDA,0);
                            else
                              if (nvl(regproduto.PERCIPIVENDA,0) > 0) then
                                gvet_regitem(j).vlipi := (nvl(gvet_regitem(j).pvenda,0) - nvl(gvet_regitem(j).st,0) - nvl(gvet_regitem(j).vlipi,0)) * (nvl(regproduto.PERCIPIVENDA,0) / 100);
                              end if;
                            end if;
                          end if;
                          -- Arredondamento do IPI
                          IF gregpcconsum.tipocalcipi = 'T2' THEN
                            gvet_regitem(j).vlipi := round(gvet_regitem(j).vlipi * 100) / 100;
                          ELSIF gregpcconsum.tipocalcipi = 'A2' THEN
                            gvet_regitem(j).vlipi := round(gvet_regitem(j).vlipi, 2);
                          ELSIF gregpcconsum.tipocalcipi = 'PV' THEN
                            gvet_regitem(j).vlipi := round(gvet_regitem(j).vlipi, gregpcconsum.numcasasdecvenda);
                          END IF;
                          -- Soma o Valor do IPI nos Preços Venda, BaseRca e Tabela
                          gvet_regitem(j).PVENDA := Round(gvet_regitem(j)
                                                          .PVENDA + gvet_regitem(j).vlipi,
                                                          NVL(vnNumCasasDecPrecoPrecificacao,gregpcconsum.numcasasdecvenda)); -- DDMEDICA-6049
                          gvet_regitem(j).Pbaserca := Round(gvet_regitem(j)
                                                            .Pbaserca +
                                                            gvet_regitem(j).vlipi,
                                                            NVL(vnNumCasasDecPrecoPrecificacao,gregpcconsum.numcasasdecvenda)); -- DDMEDICA-6049
                          regproduto.PTABELA := Round(regproduto.PTABELA +
                                                      gvet_regitem(j).vlipi,
                                                      NVL(vnNumCasasDecPrecoPrecificacao,gregpcconsum.numcasasdecvenda)); -- DDMEDICA-6049
                          -- LOG
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor IPI: ' || gvet_regitem(j).vlipi;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela: ' || regproduto.ptabela;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda: '  || gvet_regitem(j).pvenda;
                          gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'PbaseRca: '     || gvet_regitem(j).Pbaserca;
                        end if;
                      END IF;
                    END IF;
                    -- FIM: MED-1510 - IPI Somado no Preço de Venda (Igual a 2316) ----------------


                   /*******************************************************************
                    Cálculo do ST Fonte Pacote - DDMEDICA-2832
                    ******************************************/
                    IF (NVL(regfilial.UTILIZACALCULOSTPACOTE,'N')  = 'S') THEN

                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'SEM ST FONTE (REGRA PACOTE)';

                   /*******************************************************************
                    Cálculo do ST Fonte Medicamentos - DDMEDICA-2832
                    ************************************************/
                    ELSE




                    begin

                      vnstfonte := 0;

                      -------------------
                      -- CALCULA ST FONTE
                      -------------------
                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13);
