                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Filial: '       || gvet_regpedido(i).codfilial;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Produto: '      || gvet_regitem(j).codprod;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Cliente: '      || gvet_regpedido(i).codcli;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Região: '       || regregiao.numregiao;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela: ' || regproduto.ptabela;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda: '  || gvet_regitem(j).pvenda;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'P. BaseRca: '   || gvet_regitem(j).pbaserca; -- DDMEDICA-7609                      
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor IPI: '    || gvet_regitem(j).vlipi;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Vl.ST: '        || nvl(gvet_regitem(j).st,0);
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Liquido: '|| (gvet_regitem(j).pvenda - nvl(gvet_regitem(j).vlipi,0) - nvl(gvet_regitem(j).st,0));
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'PMC: '          || regproduto.precomaxconsum;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'CodSt: '        || regprecos.codst;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Cond.Venda: '   || gvet_regpedido(i).condvenda;

                      PKG_MEDICAMENTOS.P_OBTEM_STFONTE_42(gvet_regpedido(i).codfilial,
                                                          gvet_regitem(j).codprod,
                                                          gvet_regpedido(i).codcli,
                                                          regregiao.numregiao,
                                                          gvet_regpedido(i).condvenda,
                                                          gvet_regpedido(i).percvenda,
                                                          regprecos.codst,
                                                          (gvet_regitem(j).pvenda - nvl(gvet_regitem(j).vlipi,0) - nvl(gvet_regitem(j).st,0) - nvl(gvet_regitem(j).vlrepasse,0)),
                                                          gvet_Regitem(j).vlipi,
                                                          regproduto.precomaxconsum,
                                                          regprecos.valorultent,
                                                          regprecos.custonfsemst,
                                                          (regproduto.PTABELA - nvl(gvet_regitem(j).vlipi,0) - nvl(gvet_regitem(j).st,0) - nvl(gvet_regitem(j).vlrepasse,0)),
                                                          'N', -->> Padrão Não (Simples Nacional)
                                                          'N', -->> Não Pesquisa Custos
                                                          'N', -->> Não é Item Bonificado
                                                          0,   -->> Não passa Frete e Outras Despesas
                                                          vnbaseicst,
                                                          vnstfonte,
                                                          vsmensagem_stfonte,
