                                                          'O',   -->> Chamada = Outros
                                                          0,     -->> Não é preciso passar Qtde. para PEPS
                                                          NULL,  -->> Não é preciso passar Número do Pedido para PEPS
                                                          gvet_regpedido(i).codfilialnf, -- HIS.03377.2017
                                                          regprecos.pauta, -- HIS.03377.2017
                                                          gvet_regitem(j).observacaostfonte,  -- HIS.03377.2017
                                                          gvet_regitem(j).indescalarelevante, -- HIS.03377.2017
