                                                          gvet_regitem(j).fabricante, -- HIS.03377.2017
                                                          gvet_regitem(j).VLBASEFCPICMS,      -- HIS.04200.2017
                                                          gvet_regitem(j).VLBASEFCPST,        -- HIS.04200.2017
                                                          gvet_regitem(j).VLBCFCPSTRET,       -- HIS.04200.2017
                                                          gvet_regitem(j).PERFCPSTRET,        -- HIS.04200.2017
                                                          gvet_regitem(j).VLFCPSTRET,         -- HIS.04200.2017
                                                          gvet_regitem(j).PERFCPSN,           -- HIS.04200.2017
                                                          gvet_regitem(j).VLFECP,             -- HIS.04200.2017
                                                          gvet_regitem(j).VLACRESCIMOFUNCEP,  -- HIS.04200.2017
                                                          gvet_regitem(j).PERACRESCIMOFUNCEP, -- HIS.04200.2017
                                                          gvet_regitem(j).ALIQICMSFECP,       -- HIS.04200.2017
                                                          gvet_regitem(j).VLCREDFCPICMSSN,    -- HIS.04200.2017
                                                          gvet_regitem(j).CODCONFIGFUNCEPMED,
                                                          'F', -- pi_vOrdemCalculo
                                                          'N', -- pi_vMemoriaCalculo
                                                          0,   -- pi_nValorNotaFiscal
                                                          'N', -- pi_vPedidoAvaria
                                                          vrDadosStAntecip.nBCSTRETANTERIOR,          -- DDMEDICA-7697
                                                          vrDadosStAntecip.nVLICMSSUBSTITUTOANTERIOR, -- DDMEDICA-7697
                                                          vrDadosStAntecip.nVLICMSSTRETANTERIOR,      -- DDMEDICA-7697
                                                          vnStClienteGnreFonte,                       -- DDMEDICA-7697
                                                          gvet_regitem(j).pmpfmedicamento,            -- DDMEDICA-7697
                                                          vvRetClienteFonteSt,                        -- DDMEDICA-7697
                                                          regcliente.estent                           -- DDVENDAS-33718
                                                          );

                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13);
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'VALORES CALCULADOS DO ST FONTE:';
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Base ST: '              || vnbaseicst;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor ST: '             || vnstfonte;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'RegimeEspIsenStFonte: ' || regprecos.RegimeEspIsenStFonte;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Aliq1: '                || regprecos.aliqicms1fonte;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Aliq2: '                || regprecos.aliqicms2fonte;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Iva: '                  || regprecos.ivafonte;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '%Redução da Base: '     || regprecos.percbaseredstfonte;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Pauta: '                || regprecos.pauta;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Obs.ST: '               || gvet_regitem(j).observacaostfonte;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Escala: '               || gvet_regitem(j).indescalarelevante;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'CNPJ Fabricante: '      || gvet_regitem(j).cnpjfabricante;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'BASE ST FCP: '          || gvet_regitem(j).VLBASEFCPST;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'VL ST FCP: '            || gvet_regitem(j).VLFECP;
                      -- DDMEDICA-7697
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'BCSTRETANTERIOR: '          || vrDadosStAntecip.nBCSTRETANTERIOR;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'VLICMSSUBSTITUTOANTERIOR: ' || vrDadosStAntecip.nVLICMSSUBSTITUTOANTERIOR;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'VLICMSSTRETANTERIOR: '      || vrDadosStAntecip.nVLICMSSTRETANTERIOR;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'vnStClienteGnreFonte: '     || vnStClienteGnreFonte;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'pmpfmedicamento: '          || gvet_regitem(j).pmpfmedicamento;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'vvRetClienteFonteSt: '      || vvRetClienteFonteSt;

                     exception when others then

                      if gvet_Regitem(j).codmotivonaoatend is null then
                          gvet_regitem(j).codmotivonaoatend := 30;
                       end if;

                     end;


                    if vnbaseicst > 0 then
                      gvet_regitem(j).baseicst := vnbaseicst;
                    end if;

                    if vsmensagem_stfonte is not null then
                      proc_registralog(gvet_regpedido(i).numped,
                                       gvet_regpedido(i).numpedrca,
                                       gvet_regitem(j).codprod,
                                       gvet_Regitem(j).codauxiliar,
                                       gvet_regitem(j).cgccli,
                                       null,
                                       null,
                                       null,
                                       gvet_regpedido(i).codusur,
                                       gvet_regitem(j).dtaberturapedpalm,
                                       null,
                                       '3',
                                       vsmensagem_stfonte,
                                       null,
                                       gvet_regitem(j).numseqifv);
                    end if;

                    -- DDMEDICA-7697 - Adicionado O ST Recolhido Anteriormente
                    if (gvet_regitem(j).st = 0) and
                       (((NVL(vnSTFONTE,0) + NVL(vrDadosStAntecip.nVLICMSSTRETANTERIOR,0)) <> 0) or (NVL(gvet_regitem(j).VLFECP,0) <> 0))then

                      -- ST FONTE PRÓPRIO
                      gvet_regitem(j).st                       := vnSTFONTE;
                      -- DDMEDICA-7697 - ST FONTE RECOLHIDO ANTERIORMENTE
                      gvet_regitem(j).bcstretanterior          := vrDadosStAntecip.nBCSTRETANTERIOR;
                      gvet_regitem(j).vlicmssubstitutoanterior := vrDadosStAntecip.nVLICMSSUBSTITUTOANTERIOR;
                      gvet_regitem(j).vlicmsstretanterior      := vrDadosStAntecip.nVLICMSSTRETANTERIOR;

                      gvet_regitem(j).PVENDA := Round(gvet_regitem(j).PVENDA 
                                                     + NVL(vnSTFONTE,0) 
                                                     + NVL(gvet_regitem(j).vlicmsstretanterior,0) -- DDMEDICA-7697
                                                     + NVL(gvet_regitem(j).VLFECP,0), gregpcconsum.numcasasdecvenda);
                      gvet_regitem(j).Pbaserca := Round(gvet_regitem(j).Pbaserca 
                                                       + NVL(vnSTFONTE,0) 
                                                       + NVL(gvet_regitem(j).vlicmsstretanterior,0) -- DDMEDICA-7697
                                                       + NVL(gvet_regitem(j).VLFECP,0), gregpcconsum.numcasasdecvenda);
                      regproduto.PTABELA := Round(regproduto.PTABELA 
                                                 + NVL(vnSTFONTE,0) 
                                                 + NVL(gvet_regitem(j).vlicmsstretanterior,0) -- DDMEDICA-7697
                                                 + NVL(gvet_regitem(j).VLFECP,0), gregpcconsum.numcasasdecvenda);

                      gvet_regitem(j).IVA := regprecos.ivafonte;
                      gvet_regitem(j).PAUTA := 0;
                      gvet_regitem(j).ALIQICMS1 := regprecos.aliqicms1fonte;
                      gvet_regitem(j).ALIQICMS2 := regprecos.aliqicms2fonte;
                      gvet_regitem(j).PERCBASEREDST := regprecos.percbaseredst;
                      gvet_regitem(j).PERCBASEREDSTFONTE := regprecos.PERCBASEREDSTFONTE;
                      gvet_regitem(j).REGIMEESPISENSTFONTE := regprecos.regimeespisenstfonte;

                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'CALCULADO SEM ST NA PRECIFICAÇÃO E COM ST FONTE:'; -- DDMEDICA-7609
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela com ST: ' || regproduto.PTABELA;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda com ST: '  || gvet_regitem(j).PVENDA; -- DDMEDICA-7609
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'P. BaseRca com ST: '   || gvet_regitem(j).pbaserca; -- DDMEDICA-7609
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'ST: '                  || gvet_regitem(j).st; -- DDMEDICA-7609
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'ST FECP: '             || gvet_regitem(j).VLFECP; -- DDMEDICA-7609                      
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'vlicmsstretanterior: ' || gvet_regitem(j).vlicmsstretanterior; -- DDMEDICA-7697                      
                     
                    -- Somar o FECP quando tem ST na Precificação
                    elsif (gvet_regitem(j).st > 0) and
                          ((NVL(vnSTFONTE,0) <> 0) and (NVL(gvet_regitem(j).VLFECP,0) <> 0))then
                       
                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'SOMAR O ST DO FECP QUANDO TEM ST NA PRECIFICAÇÃO:';
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela sem o ST do FECP: ' || regproduto.PTABELA;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda sem o ST do FECP: '  || gvet_regitem(j).PVENDA;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'P. BaseRca sem o ST do FECP: '   || gvet_regitem(j).Pbaserca; -- DDMEDICA-7609    
                     
                      gvet_regitem(j).PVENDA := Round(gvet_regitem(j).PVENDA + NVL(gvet_regitem(j).VLFECP,0),
                                                      gregpcconsum.numcasasdecvenda);
                      gvet_regitem(j).Pbaserca := Round(gvet_regitem(j).Pbaserca + NVL(gvet_regitem(j).VLFECP,0), 
                                                        gregpcconsum.numcasasdecvenda);
                      regproduto.PTABELA := Round(regproduto.PTABELA + NVL(gvet_regitem(j).VLFECP,0),
                                                  gregpcconsum.numcasasdecvenda);
                       
                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela com o ST do FECP: ' || regproduto.PTABELA;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda com o ST do FECP: '  || gvet_regitem(j).PVENDA;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'P. BaseRca com o ST do FECP: '   || gvet_regitem(j).Pbaserca; -- DDMEDICA-7609    
                       
                    end if;

                    -- DDMEDICA-7697 - ST GNRE FONTE
                    IF (vvRetClienteFonteSt = 'S') THEN
                      gvet_regitem(j).stclientegnre := vnStClienteGnreFonte;
                    END IF;

                    gvet_regorigempreco(j).vlst                := gvet_regitem(j).st;
                    gvet_regorigempreco(j).VLFECP              := gvet_regitem(j).VLFECP;
                    -- DDMEDICA-7697 - ST Recolhido Anteriormente
                    gvet_regorigempreco(j).vlicmsstretanterior := gvet_regitem(j).vlicmsstretanterior;

                    END IF; -- Se ST Fonte Pacote/Medicamentos - DDMEDICA-2832
                   /*******************************************************************/

                    -- calcula o percentual de desconto
                    gvet_regitem(j).perdesc := func_calcularperdescitem(regproduto.ptabela,
                                                                        gvet_regitem(j).pvenda,gvet_regitem(j).codmotivonaoatend);


                   gvet_Regitem(j).VLREDPVENDASIMPLESNA := null;

                   --114903
                   --if regcliente.simplesnacional = 'S' and regprecos.percredpvendasimplesnac <> 0 and gvet_regitem(j).aplicadescontosimples  = 'S' then
                   if regcliente.simplesnacional = 'S' and gvet_regitem(j).aplicadescontosimples  = 'S' then

                     --// PCNIL - MERGE: 2316 - Tarefa 118427
                     if (NVL(regfilial.usadescsimplesnac,'N') = 'S') then

                       -- Deve usar o Valor do Desconto do Simmples Nacional antes de aplicar qualquer política que altera PTabela
                       gvet_Regitem(j).VLREDPVENDASIMPLESNA := NVL(gvet_Regitem(j).valordescsimplesnac,0);

                       -- LOG
                       gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor que foi reduzido do Preço Tabela - SIMPLESNAC: ' || gvet_Regitem(j).VLREDPVENDASIMPLESNA;

                     else

                       -- DDMEDICA-3639 - Simples Nacional ST Fonte na Integradora
                       IF (NVL(regcliente.clientefontest,'N')   = 'S') AND
                          (NVL(regcliente.simplesnacional,'N')  = 'S') AND
                          (NVL(regfilial.usadescsimplesnac,'N') = 'N') THEN

                         PKG_MEDICAMENTOS.P_CALC_RED_SIMPLES_NAC(gvet_regpedido(i).codfilial,
                                                                 gvet_regpedido(i).codcli,
                                                                 gvet_regitem(j).codprod,
                                                                 gvet_regpedido(i).condvenda,
                                                                 (nvl(gvet_regitem(j).pvenda,0) - nvl(gvet_regitem(j).st,0) - nvl(gvet_regitem(j).vlrepasse,0)),
                                                                 (nvl(regproduto.ptabela,0) - nvl(gvet_regitem(j).st,0) - nvl(gvet_regitem(j).vlrepasse,0)),
                                                                 gvet_regitem(j).vlipi,
                                                                 gvet_regitem(j).precomaxconsum,
                                                                 regproduto.tipomerc,
                                                                 regcliente.codfilialnf,
                                                                 vrRetSimplesNac.vTipoRedSimplesNac,
                                                                 vrRetSimplesNac.nPercRedSimplesNac,
                                                                 vrRetSimplesNac.nValorRedSimplesNac,
                                                                 vrRetSimplesNac.nValorRedSimplesNacNoPreco,
                                                                 vrRetSimplesNac.nValorRedSimplesNacNoStFonte,
                                                                 vrRetSimplesNac.vOcorreramErros,
                                                                 vrRetSimplesNac.vMsgErros,
                                                                 regregiao.numregiao, -- DDVENDAS-33718
                                                                 regcliente.estent);  -- DDVENDAS-33718
                         -->> Se Redução no Preço
                         IF    (vrRetSimplesNac.vTipoRedSimplesNac = 'P') THEN
                           gvet_Regitem(j).VLREDPVENDASIMPLESNA := NVL(vrRetSimplesNac.nValorRedSimplesNacNoPreco,0);
                           gvet_Regitem(j).tiporedsimplesnac    := vrRetSimplesNac.vTipoRedSimplesNac;
                         -->> Se Redução no ST
                         ELSIF (vrRetSimplesNac.vTipoRedSimplesNac = 'S') THEN
                           gvet_Regitem(j).VLREDPVENDASIMPLESNA := NVL(vrRetSimplesNac.nValorRedSimplesNacNoStFonte,0);
                           gvet_Regitem(j).tiporedsimplesnac    := vrRetSimplesNac.vTipoRedSimplesNac;
                         END IF;

                         IF (vrRetSimplesNac.vOcorreramErros = 'S') THEN
                            proc_registralog(gvet_regpedido(i).numped,
                                             gvet_regpedido(i).numpedrca,
                                             gvet_regitem(j).codprod,
                                             gvet_regitem(j).codauxiliar,
                                             gvet_regitem(j).cgccli,
                                             null,
                                             null,
                                             null,
                                             gvet_regpedido(i).codusur,
                                             gvet_regitem(j).dtaberturapedpalm,
                                             null,
                                             '3',
                                             vrRetSimplesNac.vMsgErros,
                                             NULL,
                                             gvet_regitem(j).numseqifv);
                          END IF;

                       ELSE

                         --só atualiza caso não tenha impostos
                         if (regprecos.percredpvendasimplesnac <> 0)     and -->> Transportei para esta condição porque comentei ela acima (114903)
                            (regprecos.aliqicms1 <= regprecos.aliqicms2) and
                             regprecos.pauta = 0 and regprecos.iva = 0   then


                              vbcalcularedsimplesnac := funcoesvendas.calcularredsimplesnac(regprecos.custofin,
                                                                              regprecos.custonfsemst,
                                                                              regprecos.custonfsemstguiaultent,
                                                                              regprecos.ivaultent,
                                                                              regprecos.aliqicms1ultent,
                                                                              regprecos.aliqicms2ultent,
                                                                              regprecos.redbaseivaultent,
                                                                              regprecos.percicmsfretefobstultent,
                                                                              regprecos.vlfreteconhecultent,
                                                                              regprecos.percaliqextguiaultent,
                                                                              regprecos.vlstultent,
                                                                              regprecos.baseicmsultent,
                                                                              regprecos.vlstguiaultent,
                                                                              regprecos.PERCREDPVENDASIMPLESNAC,
                                                                              gregpcconsum.numcasasdecvenda,
                                                                              null,
                                                                              null,
                                                                              null,
                                                                              null,
                                                                              vsmensagemredsimplesnac,
                                                                              gvet_Regitem(j).VLREDPVENDASIMPLESNA);

                           IF vsmensagemredsimplesnac IS NOT NULL
                            THEN
                              proc_registralog(gvet_regpedido(i).numped,
                                               gvet_regpedido(i).numpedrca,
                                               gvet_regitem(j).codprod,
                                               gvet_regitem(j).codauxiliar,
                                               gvet_regitem(j).cgccli,
                                               null,
                                               null,
                                               null,
                                               gvet_regpedido(i).codusur,
                                               gvet_regitem(j).dtaberturapedpalm,
                                               null,
                                               '3',
                                               vsmensagemredsimplesnac,
                                               NULL,
                                               gvet_regitem(j).numseqifv);
                            END IF;

                         end if; -- FIM: --só atualiza caso não tenha impostos

                       END IF; -- FIM: DDMEDICA-3639 - Simples Nacional ST Fonte na Integradora

                     end if; -- FIM: PCNIL - MERGE: 2316 - Tarefa 118427

                   end if; -- FIM: if regcliente.simplesnacional = 'S' and regprecos.percredpvendasimplesnac <> 0 and gvet_regitem(j).aplicadescontosimples  = 'S'

                   /******************************************
                    INICIO: BENEFÍCIOS FISCAIS - DDMEDICA-7584
                    ******************************************/
                    
                    -- LOG
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || 'PREÇOS ANTES DOS BENEFICIOS FISCAIS'; -- DDMEDICA-7609
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela: ' || regproduto.PTABELA;
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda: '  || gvet_regitem(j).PVENDA;
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'P. BaseRca: '   || gvet_regitem(j).pbaserca; -- DDMEDICA-7609
                    
                    -- Inicializa Valores dos Descontos dos Benefícios Fiscais
                    gvet_regitem(j).VlDescReducaoPIS           := 0;
                    gvet_regitem(j).PercDescPIS                := 0;
                    gvet_regitem(j).VlDescReducaoCofins        := 0;
                    gvet_regitem(j).PercDescCofins             := 0;
                    gvet_regorigempreco(j).VlDescReducaoPIS    := 0;
                    gvet_regorigempreco(j).PercDescPIS         := 0;
                    gvet_regorigempreco(j).VlDescReducaoCofins := 0;
                    gvet_regorigempreco(j).PercDescCofins      := 0;
                    vnperdescisentoicms                        := 0;
                    gvet_regitem(j).vldescicmisencao           := 0;
                    gvet_regitem(j).VLDESCSUFRAMA              := 0;
                    vnVlDescSuframa                            := 0;
                    
                    -- Obter os Valores dos Descontos dos Benefícios Fiscais
                    PKG_MEDICAMENTOS.P_OBTER_VALORES_BENEF_FISCAIS(gvet_regpedido(i).codfilial,
                                                                   gvet_regpedido(i).codfilialnf,
                                                                   gvet_regpedido(i).codcli,
                                                                   gvet_regitem(j).codprod,
                                                                   regprecos.codst,
                                                                   gregpcconsum.numcasasdecvenda,
                                                                   gregpcconsum.tipocalcsulframa,
                                                                   regprecos.perdescicmisencao,
                                                                   regprecos.aplicadescisencaomed,
                                                                   (gvet_regitem(j).PVENDA
                                                                    - nvl(gvet_regitem(j).ST,0)
                                                                    - nvl(gvet_regitem(j).VLIPI,0)
                                                                    - nvl(gvet_regitem(j).VLFECP,0)),
                                                                   (regproduto.ptabela
                                                                    - nvl(gvet_regitem(j).ST,0)
                                                                    - nvl(gvet_regitem(j).VLIPI,0)
                                                                    - nvl(gvet_regitem(j).VLFECP,0)),
                                                                   (gvet_regitem(j).pbaserca
                                                                    - nvl(gvet_regitem(j).ST,0)
                                                                    - nvl(gvet_regitem(j).VLIPI,0)
                                                                    - nvl(gvet_regitem(j).VLFECP,0)),
                                                                   gvet_regitem(j).qt,
                                                                   gvet_regitem(j).VlDescReducaoPIS,
                                                                   gvet_regitem(j).PercDescPIS,
                                                                   gvet_regitem(j).VlDescReducaoCofins,
                                                                   gvet_regitem(j).PercDescCofins,
                                                                   gvet_regitem(j).vldescicmisencao,
                                                                   gvet_regitem(j).perdescisentoicms,
                                                                   gvet_regitem(j).VLDESCSUFRAMA,
                                                                   vnPercDescSuframaResult,
                                                                   vnPrecoLiqResultAuxBF,
                                                                   vnPrecoTabResultAuxBF,
                                                                   vnPrecoRcaResultAuxBF,
                                                                   vvErrosBenefFiscaisBF,
                                                                   vvMsgErrosBenefFiscaisBF);
                    IF (vvErrosBenefFiscaisBF = 'S') THEN
                       gvet_regitem(j).valido := FALSE;
                       proc_registralog(gvet_regpedido(i).numped,
                                        gvet_regpedido(i).numpedrca,
                                        gvet_regitem(j).codprod,
                                        gvet_regitem(j).codauxiliar,
                                        gvet_regitem(j).cgccli,
                                        null,
                                        null,
                                        null,
                                        gvet_regpedido(i).codusur,
                                        gvet_regitem(j).dtaberturapedpalm,
                                        null,
                                        '3',
                                        SUBSTR('Benef. Fiscal inválido por: ' || vvMsgErrosBenefFiscaisBF,1,255),
                                        null,
                                        gvet_regitem(j).numseqifv);
                      if gvet_Regitem(j).codmotivonaoatend is null then
                        gvet_regitem(j).codmotivonaoatend := 27; -- Preço Inválido
                      end if;                                      
                    END IF;                            
                    
                    -- Guarda Valores dos Benefícios Fiscais na Origem do Preço
                    gvet_regorigempreco(j).vldescreducaopis    := gvet_regitem(j).vldescreducaopis;
                    gvet_regorigempreco(j).percdescpis         := gvet_regitem(j).percdescpis;
                    gvet_regorigempreco(j).vldescreducaocofins := gvet_regitem(j).vldescreducaocofins;
                    gvet_regorigempreco(j).percdesccofins      := gvet_regitem(j).percdesccofins;
                    gvet_regorigempreco(j).vldescicms          := gvet_regitem(j).vldescicmisencao;
                    gvet_regorigempreco(j).vlsuframa           := gvet_regitem(j).vldescsuframa;
                    gvet_regorigempreco(j).vlipi               := gvet_regitem(j).vlipi;

                    -- Aplica valores dos descontos dos Benefícios Fiscais nos Preços
                    gvet_regitem(j).pvenda   := round((gvet_regitem(j).pvenda
                                                       - nvl(gvet_regitem(j).vldescreducaopis,0)
                                                       - nvl(gvet_regitem(j).vldescreducaocofins,0)
                                                       - nvl(gvet_regitem(j).vldescicmisencao,0)
                                                       - nvl(gvet_regitem(j).vldescsuframa,0)),
                                                      gregpcconsum.numcasasdecvenda);

                    regproduto.ptabela       := round((regproduto.ptabela 
                                                       - nvl(gvet_regitem(j).vldescreducaopis,0)
                                                       - nvl(gvet_regitem(j).vldescreducaocofins,0)
                                                       - nvl(gvet_regitem(j).vldescicmisencao,0)
                                                       - nvl(gvet_regitem(j).vldescsuframa,0)),
                                                      gregpcconsum.numcasasdecvenda);

                    gvet_regitem(j).pbaserca := round((gvet_regitem(j).pbaserca
                                                       - nvl(gvet_regitem(j).vldescreducaopis,0)
                                                       - nvl(gvet_regitem(j).vldescreducaocofins,0)
                                                       - nvl(gvet_regitem(j).vldescicmisencao,0)
                                                       - nvl(gvet_regitem(j).vldescsuframa,0)),
                                                      gregpcconsum.numcasasdecvenda);

                    -- LOG
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || 'PREÇOS FINAIS'; -- DDMEDICA-7609
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela reduzido dos Benefícios Fiscais: ' || regproduto.PTABELA;
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda reduzido dos Benefícios Fiscais: '  || gvet_regitem(j).PVENDA;
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'P. BaseRca reduzido dos Benefícios Fiscais: '   || gvet_regitem(j).pbaserca; -- DDMEDICA-7609
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor Desc. PIS: '                              || nvl(gvet_regitem(j).vldescreducaopis,0);
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor Desc. COFINS: '                           || nvl(gvet_regitem(j).vldescreducaocofins,0);
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor Desc. ICMS: '                             || nvl(gvet_regitem(j).vldescicmisencao,0);
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% Desc. ICMS: '                                 || nvl(gvet_regitem(j).perdescisentoicms,0);
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor Desc. SUFRAMA: '                          || nvl(gvet_regitem(j).vldescsuframa,0);
                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% Desc. SUFRAMA: '                              || nvl(vnPercDescSuframaResult,0);

                    -- DDMEDICA-4289 - Preço Inválido
                    IF (gvet_regitem(j).vldescicmisencao > 0) AND
                       (gvet_regitem(j).pvenda <= 0)          THEN
                       gvet_regitem(j).valido := FALSE;
                       proc_registralog(gvet_regpedido(i).numped,
                                        gvet_regpedido(i).numpedrca,
                                        gvet_regitem(j).codprod,
                                        gvet_regitem(j).codauxiliar,
                                        gvet_regitem(j).cgccli,
                                        null,
                                        null,
                                        null,
                                        gvet_regpedido(i).codusur,
                                        gvet_regitem(j).dtaberturapedpalm,
                                        null,
                                        '3',
                                        'Preço inválido devido ao valor mínimo da desoneração de ICMS',
                                        null,
                                        gvet_regitem(j).numseqifv);
                      if gvet_Regitem(j).codmotivonaoatend is null then
                        gvet_regitem(j).codmotivonaoatend := 27; -- Preço Inválido
                      end if;                                      
                    END IF;                                     

                   /******************************************
                    FIM: BENEFÍCIOS FISCAIS - DDMEDICA-7584
                    ******************************************/

                    if regprecos.codicmtabpf is null then
                      vbcodicmtabpf := true;
                    else
                      vbcodicmtabpf := false;
                    end if;

                   /***********************************
                    RCA POR LINHA DE PRAZO - E-COMMERCE
                              4415.012539.2017
                    ***********************************/
                    IF (regfilial.tipoprazomedicam = '4')  AND
                       (gvet_regpedido(i).ORIGEMPED = 'W') THEN

                      -- Pesquisa RCA para a Linha de Prazo
                      BEGIN
                        SELECT PCCLIENTLINHAPRAZOUSUR.CODUSUR
                          INTO gvet_regitem(j).codusurLinhaPrazo
                          FROM PCCLIENTLINHAPRAZOUSUR
                         WHERE (PCCLIENTLINHAPRAZOUSUR.CODCLI        = gvet_regpedido(i).codcli)
                           AND (PCCLIENTLINHAPRAZOUSUR.CODLINHAPRAZO = regproduto.codlinhaprazo)
                           AND (PCCLIENTLINHAPRAZOUSUR.TIPO          = 'P')
                           AND (ROWNUM                               = 1);
                      EXCEPTION
                        WHEN NO_DATA_FOUND THEN
                          gvet_regitem(j).codusurLinhaPrazo := NULL;
                      END;

                      -- Se possui RCA por Linha de Prazo
                     /*
                      IF (gvet_regitem(j).codusurLinhaPrazo > 0) THEN

                        -- Pesquisa Plano de Pagamento da Linha de Prazo
                        BEGIN
                          PRC_MED_CLIENTLINHAPRAZO(gvet_regpedido(i).codfilial,
                                                   gvet_regpedido(i).codcli,
                                                   gvet_regitem(j).codusurLinhaPrazo,
                                                   0);
                          BEGIN
                            SELECT PCMED_CLIENTLINHAPRAZO.CODPLPAG
                              INTO gvet_regitem(j).codplpagLinhaPrazo
                              FROM PCMED_CLIENTLINHAPRAZO
                             WHERE (PCMED_CLIENTLINHAPRAZO.CODCLI        = gvet_regpedido(i).codcli)
                               AND (PCMED_CLIENTLINHAPRAZO.CODLINHAPRAZO = regproduto.codlinhaprazo)
                               AND (ROWNUM                               = 1);
                          EXCEPTION
                            WHEN NO_DATA_FOUND THEN
                              gvet_regitem(j).codplpagLinhaPrazo := NULL;
                          END;
                        EXCEPTION
                          WHEN OTHERS THEN
                            proc_registralog(gvet_regpedido(i).numped,
                                             gvet_regpedido(i).numpedrca,
                                             gvet_regitem(j).codprod,
                                             gvet_regitem(j).codauxiliar,
                                             gvet_regitem(j).cgccli,
                                             null,
                                             null,
                                             null,
                                             gvet_regpedido(i).codusur,
                                             gvet_regitem(j).dtaberturapedpalm,
                                             null,
                                             '3',
                                             'Erro LP: ' || sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->013->' || SQLERRM || ';',
                                             null);
                          if gvet_Regitem(j).codmotivonaoatend is null then
                             gvet_regitem(j).codmotivonaoatend := 999;
                          end if;
                        END;

                      END IF; -- Fim Condição Se possui RCA por Linha de Prazo
                      */

                      -- Guarda a Linha de Prazo
                      gvet_regitem(j).codlinhaprazo := regproduto.codlinhaprazo;

                    END IF; -- FIM CONDIÇÃO: RCA POR LINHA DE PRAZO - E-COMMERCE

                   /*************************************
                    RCA POR LINHA DO PRODUTO - E-COMMERCE
                                 DDMEDICA-4240
                    ***********************************/
                    IF (gvet_regpedido(i).ORIGEMPED = 'W') THEN
                      IF (FUSA_REGRA_MEDICAMENTOS('99',
                                                  'APURARCOMISSAOPELORCALINHA') = 'S') THEN

                        gvet_regitem(j).codusurlinha := INTEGRADORACOMPLE_MED.F_OBTER_RCA_LINHAPROD(gvet_regpedido(i).codcli,
                                                                                                    gvet_regitem(j).CODPROD,
                                                                                                    gvet_regpedido(i).codfilial,
                                                                                                    regfilial.usarcaclientelinhaporfilialmed);

                        -- Log
                        gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'RCA Linha: ' || gvet_regitem(j).codusurlinha;

                      END IF;
                    END IF; -- FIM CONDIÇÃO: RCA POR LINHA DO PRODUTO - E-COMMERCE

                    -- MED-869
                    RECOMPILAR_DEPENDENCIAS;

                    begin
                    -- CMV sem comissao
                    --31 parâmetros
                      -- HIS.02787.2016
                      -- DDMEDICA-7719 - Adicionado o ST Recolhido Anteriormente
                      p_calcularcmv_med(regfilial.tributsaidaorigemnacimp, -- HIS.02787.2016
                                              gregpcconsum.abaterimpostoscomissaorca,
                                              gregpcconsum.aplicarindicecmv,
                                              gregpcconsum.incluircomissaosugpvendacmv,
                                              nvl(gregpcconsum.txvenda, 0),
                                              regcliente.tipofj,
                                              regcliente.utilizaiesimplificada,
                                              regcliente.ieent,
                                              regproduto.freteespecial,
                                              regregiao.perfreteterceiros,
                                              regregiao.perfreteespecial,
                                              regprecos.custofin,
                                              regprecos.custoreal,
                                              regprecos.perdesccusto,
                                              regprecos.codicmtab,
                                              vbcodicmtabpf,
                                              regprecos.codicmtabpf,
                                              gvet_regpedido(i).percvenda,
                                              gvet_regitem(j).pvenda,
                                              0,
                                              (NVL(gvet_regitem(j).st,0)
                                               + NVL(gvet_regitem(j).vlfecp,0)),
                                              gvet_regitem(j).vlipi,
                                              0,
                                              regcliente.contribuinte,
                                              0,
                                              ----------------------------------
                                              --nvl(gvet_Regitem(j).VLREDPVENDASIMPLESNA,0),
                                              CASE NVL(regfilial.usadescsimplesnac,'N') WHEN 'S' THEN 0 ELSE nvl(gvet_Regitem(j).VLREDPVENDASIMPLESNA,
                                                  0) END,
                                              ----------------------------------
                                              regcliente.consumidorfinal,
                                              nvl(gregpcconsum.consideraisentoscomopf,'N'),
                                              gvet_regitem(j).perfretecmv,
                                              gvet_regitem(j).CUSTOFINEST,
                                              gvet_regitem(j).txvenda,
                                              gvet_regitem(j).perdesccusto,
                                              gvet_regitem(j).CODICMTAB,
                                              gvet_regitem(j).VLCUSTOREAL,
                                              gvet_regitem(j).VLCUSTOFIN,
                                              gvet_regitem(j).VLDESCCUSTOCMV,
                                              gvet_regpedido(i).codcli,          -- HIS.02787.2016
                                              0, -- p_custoprecific              -- HIS.02787.2016
                                              gvet_regitem(j).CODPROD,           -- HIS.02787.2016
                                              gvet_regpedido(i).codfilial,       -- HIS.02787.2016
                                              gvet_regitem(j).QT,                -- HIS.02787.2016
                                              regprecos.codicmtabinternac,       -- HIS.02787.2016
                                              gvet_regitem(j).vldesccmvpromocaomed,-- DDMEDICA-5009
                                              gvet_regitem(j).vlicmsstretanterior, -- DDMEDICA-7697
                                              gvet_regitem(j).PRODIMPORTADOPEPS, -- HIS.02787.2016
                                              gvet_regitem(j).NUMTRANSENTPEPS,   -- HIS.02787.2016
                                              vvMsgErroCalcularCMV               -- HIS.02787.2016
                                              );

                        gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Msg CMV: ' || vvMsgErroCalcularCMV;

                     exception when others then

                          if gvet_Regitem(j).codmotivonaoatend is null then
                            gvet_regitem(j).codmotivonaoatend := 23;

                         end if;


                     end;

                    -- Tratamento de Erro por Divisão por Zero (4493.064633.2016)
                    BEGIN
                      vnperluc := ((gvet_regitem(j).pvenda - gvet_regitem(j).vlcustofin) / gvet_regitem(j).pvenda) * 100;
                    EXCEPTION
                      WHEN ZERO_DIVIDE THEN
                        vnperluc := 0;
                    END;

                    -- busca percentual de comissao
                    vsmensagem_comiss := null;

                    select count(*)
                    into vicont
                    from pctabcomiss p;

                    if vicont <> 0 then
                      vbUsaPcTabComiss := true;
                    else
                      vbUsaPcTabComiss := false;
                    end if;

                    select count(*)
                    into vicont
                    from pccomissaousur p;

                    if vicont <> 0 then
                      vbUsaPcComissaoUsur := true;
                    else
                      vbUsaPcComissaoUsur := false;
                    end if;


                    select count(*)
                    into vicont
                    from pccomissaoplpag p;

                    if vicont <> 0 then
                      vbUsaPcComissaoplpag := true;
                    else
                      vbUsaPCComissaoPlPag := false;
                    end if;


                    select count(*)
                    into vicont
                    from pccomissaoregiao p;

                    if vicont <> 0 then
                      vbUsaPcComissaoregiao := true;
                    else
                      vbUsaPcComissaoregiao := false;
                    end if;

                    if regfilial.broker = 'S' then
                       vbUsaPCComissaofilial := true;
                    else
                       vbUsaPCComissaofilial := false;
                    end if;

                --Comissão Integradora OL [HIS.00490.2014]
                if nvl(upper(gvet_regpedido(i).usacomissaointegradora),'N') = 'S' then

                  gvet_regitem(j).percom := gvet_regpedido(i).percom;
                  gvet_regitem(j).tipocomissaomed := 'FIN'; -- 5047.047570.2016

                 /*************************************
                  COMISSÃO: INTEGRADORA - DDMEDICA-1835
                  *************************************/
                  IF (INTEGRADORACOMPLE_MED.F_OBTER_COMISSAO_INTEGRADORA(gvet_regitem(j).coddesconto,
                                                                         gvet_regitem(j).codpromocaomed,
                                                                         regrca.tipovend,
                                                                         gvet_regitem(j).codprod,
                                                                         gvet_regpedido(i).integradora,
                                                                         vnPerComIntegradora) = 'S') THEN
                    gvet_regitem(j).percom := vnPerComIntegradora;
                  END IF;

                  -- LOG
                  gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% Comissão Integradora: ' || gvet_regitem(j).percom;

                else

                  -- Verifica se a Promoção do Item Prioriza a Comissão -- 5047.047570.2016
                  BEGIN
                    SELECT PCPROMOCAOMED.PRIORIZACOMISSAO
                      INTO vvPromocaoPriorizaComissao
                      FROM PCPROMOCAOMED
                     WHERE (PCPROMOCAOMED.CODPROMOCAOMED = gvet_regitem(j).codpromocaomed);
                  EXCEPTION
                    WHEN NO_DATA_FOUND THEN
                      vvPromocaoPriorizaComissao := NULL;
                  END;

                 /***********************************
                  COMISSÃO: PEDIDO FV QUE USA PROMOÇÃO
                  ************************************/
                  IF ((NVL(gvet_regpedido(i).codpromocaomed,0)   > 0))   AND
                      (NVL(vvPromocaoPriorizaComissao,'N') = 'S')        THEN

                    -- Comissão cadastrada na rotina 2323
                    BEGIN
                      gvet_regitem(j).percom := INTEGRADORACOMPLE_MED.F_OBTER_COMISSAO_PROMOCAO(gvet_regitem(j).coddesconto,
                                                                                                gvet_regitem(j).codpromocaomed,
                                                                                                regrca.tipovend,
                                                                                                gvet_regitem(j).codprod);
                      gvet_regitem(j).tipocomissaomed := 'FPM'; -- 5047.047570.2016

                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% Comissão Promoção: ' || gvet_regitem(j).percom;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Cód. Desconto: '       || gvet_regitem(j).coddesconto;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Cód. Promoção: '       || gvet_regitem(j).codpromocaomed;

                    EXCEPTION
                      WHEN OTHERS THEN
                        vsmensagem_comiss :=  'Erro Cálculo Comissão Promoção : ' || SUBSTR('Erro: ' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || ' >> ' || SQLERRM,1,240);
                        proc_registralog(gvet_regpedido(i).numped,
                                         gvet_regpedido(i).numpedrca,
                                         gvet_regitem(j).codprod,
                                         gvet_regitem(j).codauxiliar,
                                         gvet_regitem(j).cgccli,
                                         null,
                                         null,
                                         null,
                                         gvet_regpedido(i).codusur,
                                         gvet_regitem(j).dtaberturapedpalm,
                                         null,
                                         '3',
                                        'Erro ao calcular comissão. '||SQLCODE||' '||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                                        null,
                                        gvet_regitem(j).numseqifv);
                    END;

                 /**********************
                  COMISSÃO: DEMAIS CASOS
                  **********************/
                  ELSE

                    begin
                      gvet_regitem(j).percom := FUNCOESVENDAS.Definir_Comissao_Item_Vendido
                                       (regregiao.numregiao,
                                        vnperluc,
                                        gvet_regitem(j).perdesc,
                                        vbUsaPcTabComiss,
                                        vbUsaPcComissaoUsur,
                                        vbUsaPCComissaoPlPag,
                                        vbUsaPCComissaoRegiao,
                                        vbUsaPCComissaofilial,
                                        gregpcconsum.usacomissaoporrca,
                                        gregpcconsum.OrdemAvaliacaoComissaoRCA,
                                        gregpcconsum.usacomissaoporcliente,
                                        gregpcconsum.USACOMISSAOPORLINHAPROD,
                                        gregpcconsum.comissaorcatipovenda,
                                        regrca.tipovend,
                                        regrca.percent,
                                        regrca.percent2,
                                        regproduto.codprod,
                                        regproduto.pcomint1,
                                        regproduto.PCOMEXT1,
                                        regproduto.PCOMREP1,
                                        regproduto.codlinhaprod,
                                        regproduto.tipocomissao,
                                        regproduto.codepto,
                                        regproduto.codsec,
                                        regproduto.classe,
                                        gvet_regitem(j).tipovenda,
                                        gvet_regitem(j).codplpag,
                                        gvet_regpedido(i).data,
                                        gvet_regpedido(i).codfilial,
                                        gvet_regpedido(i).codusur,
                                        regfilial.considerarcomissaozero,
                                        regfilial.tipoavaliacaocomissao,
                                        regcliente.percomcli,
                                        regcliente.codcli,
                                        gvet_regitem(j).coddesconto,
                                        gvet_regorigemcomiss(j).codcomis,
                                        gvet_regorigemcomiss(j).codrotinacomis,
                                        gvet_regitem(j).LetraComiss,
                                        vsmensagem_comiss,
                                        gvet_regitem(j).codauxiliar ,
                                        regprecos.pcomint1_emb,
                                        regprecos.PCOMEXT1_emb,
                                        regprecos.PCOMREP1_emb,
                                        regfilial.utilizavendaporembalagem
                                        );

                      -- 5047.047570.2016
                      gvet_regitem(j).tipocomissaomed := 'FXX';
                      IF    (gvet_regorigemcomiss(j).codrotinacomis = 3304) THEN
                        gvet_regitem(j).tipocomissaomed := 'FTR';
                      ELSIF (gvet_regorigemcomiss(j).codrotinacomis = 2014) THEN
                        gvet_regitem(j).tipocomissaomed := 'FEB';
                      ELSIF (gvet_regorigemcomiss(j).codrotinacomis = 203)  THEN
                        gvet_regitem(j).tipocomissaomed := 'FPR';
                      ELSIF (gvet_regorigemcomiss(j).codrotinacomis = 302)  THEN
                        gvet_regitem(j).tipocomissaomed := 'FCL';
                      ELSIF (gvet_regorigemcomiss(j).codrotinacomis = 517)  THEN
                        gvet_regitem(j).tipocomissaomed := 'FRC';
                      ELSIF (gvet_regorigemcomiss(j).codrotinacomis = 558)  THEN
                        gvet_regitem(j).tipocomissaomed := 'FLP';
                      ELSIF (gvet_regorigemcomiss(j).codrotinacomis = 550)  THEN
                        gvet_regitem(j).tipocomissaomed := 'FLC';
                      ELSIF (gvet_regorigemcomiss(j).codrotinacomis = 553)  THEN
                        gvet_regitem(j).tipocomissaomed := 'FUS';
                      ELSIF (gvet_regorigemcomiss(j).codrotinacomis = 583)  THEN
                        gvet_regitem(j).tipocomissaomed := 'FPL';
                      ELSIF (gvet_regorigemcomiss(j).codrotinacomis = 363)  THEN
                        gvet_regitem(j).tipocomissaomed := 'FRG';
                      ELSIF (gvet_regorigemcomiss(j).codrotinacomis = 2110) THEN
                        gvet_regitem(j).tipocomissaomed := 'FFI';
                      ELSIF (gvet_regorigemcomiss(j).codrotinacomis = 561)  THEN
                        gvet_regitem(j).tipocomissaomed := 'FDS';
                      END IF;

                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% Comissão: '    || gvet_regitem(j).percom;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Cód. Desconto: ' || gvet_regitem(j).coddesconto;

                     exception when others then

                         if gvet_Regitem(j).codmotivonaoatend is null then
                            gvet_regitem(j).codmotivonaoatend := 23;

                         end if;

                       end;

                 /****************************
                  COMISSÃO: ACORDO DE PARCERIA
                  ****************************/
                  -- HIS.01889.2017 - Se não aplicou a Comissão da PCDESCONTO
                  IF (NVL(gvet_regorigemcomiss(j).codrotinacomis,0) <> 561) THEN
                    IF ((NVL(gvet_regpedido(i).codpromocaomed,0) > 0) AND
                        (NVL(gvet_regitem(j).priorizacomissacordoparceria,'N') = 'S')) THEN

                      gvet_regitem(j).percom          := NVL(gvet_regitem(j).percomacordoparceria,0);
                      gvet_regitem(j).tipocomissaomed := 'FAP'; -- 5047.047570.2016

                    END IF; -- FIM CONDIÇÃO COMISSÃO: PEDIDO FV QUE USA PROMOÇÃO
                  END IF;

                      end if; -- FIM CONDIÇÃO COMISSÃO: PEDIDO FV QUE USA PROMOÇÃO

                     end if; -- --Comissão Integradora OL [HIS.00490.2014]

                     -- HIS.03249.2016 - Tipos de Venda que não têm Comissão
                     IF (gvet_regpedido(i).condvenda IN (4, 5, 8, 9, 10, 13, 11, 20)) THEN
                       gvet_regitem(j).percom := 0;
                       -- LOG
                       gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Cond.Venda não permite Comissão';
                     ELSIF(gvet_regpedido(i).aplicarperredcomiss = 'S') then
                       gvet_regitem(j).percom := gvet_regitem(j).percom * (1 - NVL(gvet_regitem(j).PERREDCOMISS,0) /100);
                       gvet_regitem(j).PERREDCOMISS := gvet_regitem(j).PERREDCOMISS;
                     END IF;

                    -- Se Bloqueia a Comissão do RCA
                    IF (INTEGRADORACOMPLE_MED.F_BLOQUEIA_COMISSAO(NVL(gvet_regitem(j).codusurlinha,gvet_regpedido(i).codusur)) = 'S') THEN
                      gvet_regitem(j).percom := 0;
                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Bloqueio de Comissão';
                    END IF;

                     gvet_regorigemcomiss(j).percom                     := gvet_regitem(j).percom;
                     gvet_regorigemcomiss(j).perdesc                    := gvet_regitem(j).perdesc;
                     gvet_regorigemcomiss(j).tipocomissao               := regproduto.tipocomissao;
                     gvet_regorigemcomiss(j).codlinhaprod               := regproduto.codlinhaprod;
                     gvet_regorigemcomiss(j).ordemavaliacaocomissaorca  := gregpcconsum.ordemavaliacaocomissaorca;
                     gvet_regorigemcomiss(j).usacomissaoporrca          := gregpcconsum.usacomissaoporrca;
                     gvet_regorigemcomiss(j).usacomissaoporcliente      := gregpcconsum.usacomissaoporcliente;
                     gvet_regorigemcomiss(j).usacomissaoporlinhaprod    := gregpcconsum.usacomissaoporlinhaprod;
                     gvet_regorigemcomiss(j).comissaorcatipovenda       := gregpcconsum.comissaorcatipovenda;


                    if vsmensagem_comiss is not null
                    then
                      proc_registralog(gvet_regpedido(i).numped,
                                       gvet_regpedido(i).numpedrca,
                                       gvet_regitem(j).codprod,
                                       gvet_regitem(j).codauxiliar,
                                       gvet_regitem(j).cgccli,
                                       null,
                                       null,
                                       null,
                                       gvet_regpedido(i).codusur,
                                       gvet_regitem(j).dtaberturapedpalm,
                                       null,
                                       '3',
                                      vsmensagem_comiss,
                                      null,
                                      gvet_regitem(j).numseqifv);

                         if gvet_Regitem(j).codmotivonaoatend is null then
                            gvet_regitem(j).codmotivonaoatend := 31;

                         end if;


                    end if;


                   --207034 Comissão por Profissionais

                    if gvet_regpedido(i).codusur2 is not null then

                     begin

                       funcoesvendas.Definir_Comissao_Profissional(gvet_regitem(j).codprod,
                                                                   gvet_regpedido(i).codcli,
                                                                   gvet_regpedido(i).codusur2,
                                                                   gvet_regitem(j).tipovenda,
                                                                   gvet_regpedido(i).codfilial,
                                                                   regfilial.considerarcomissaozero,
                                                                   gregpcconsum.comissaorcatipovenda,
                                                                   gvet_regitem(j).percom2
                                                                   );
                     exception when others then

                       proc_registralog(gvet_regpedido(i).numped,
                                       gvet_regpedido(i).numpedrca,
                                       gvet_regitem(j).codprod,
                                       gvet_regitem(j).codauxiliar,
                                       gvet_regitem(j).cgccli,
                                       null,
                                       null,
                                       null,
                                       gvet_regpedido(i).codusur,
                                       gvet_regitem(j).dtaberturapedpalm,
                                       null,
                                       '3',
                                      'Erro ao calcular comissao para RCA 2',
                                      null,
                                      gvet_regitem(j).numseqifv);
                     end;

                    end if;

                    if gvet_regpedido(i).codusur3 is not null then

                     begin

                       funcoesvendas.Definir_Comissao_Profissional(gvet_regitem(j).codprod,
                                                                   gvet_regpedido(i).codcli,
                                                                   gvet_regpedido(i).codusur3,
                                                                   gvet_regitem(j).tipovenda,
                                                                   gvet_regpedido(i).codfilial,
                                                                   regfilial.considerarcomissaozero,
                                                                   gregpcconsum.comissaorcatipovenda,
                                                                   gvet_regitem(j).percom3
                                                                   );
                     exception when others then

                       proc_registralog(gvet_regpedido(i).numped,
                                       gvet_regpedido(i).numpedrca,
                                       gvet_regitem(j).codprod,
                                       gvet_regitem(j).codauxiliar,
                                       gvet_regitem(j).cgccli,
                                       null,
                                       null,
                                       null,
                                       gvet_regpedido(i).codusur,
                                       gvet_regitem(j).dtaberturapedpalm,
                                       null,
                                       '3',
                                      'Erro ao calcular comissao para RCA 3',
                                      null,
                                      gvet_regitem(j).numseqifv);
                     end;

                    end if;

                    if gvet_regpedido(i).codusur4 is not null then

                     begin

                       funcoesvendas.Definir_Comissao_Profissional(gvet_regitem(j).codprod,
                                                                   gvet_regpedido(i).codcli,
                                                                   gvet_regpedido(i).codusur4,
                                                                   gvet_regitem(j).tipovenda,
                                                                   gvet_regpedido(i).codfilial,
                                                                   regfilial.considerarcomissaozero,
                                                                   gregpcconsum.comissaorcatipovenda,
                                                                   gvet_regitem(j).percom4
                                                                   );
                     exception when others then

                       proc_registralog(gvet_regpedido(i).numped,
                                       gvet_regpedido(i).numpedrca,
                                       gvet_regitem(j).codprod,
                                       gvet_regitem(j).codauxiliar,
                                       gvet_regitem(j).cgccli,
                                       null,
                                       null,
                                       null,
                                       gvet_regpedido(i).codusur,
                                       gvet_regitem(j).dtaberturapedpalm,
                                       null,
                                       '3',
                                      'Erro ao calcular comissao para RCA 4',
                                      null,
                                      gvet_regitem(j).numseqifv);
                     end;

                    end if;


                     if gvet_Regpedido(i).condvenda = 20 then

                         gvet_Regitem(j).percom := 0;

                      end if;


                    -- calculo dos custos
                    /*                    proc_buscacustoproduto(gvet_regitem(j),
                    regprecos,
                    gvet_regpedido(i));*/


                     if nvl(gregpcconsum.incluircomissaocmvvenda,'S') = 'N' then
                          vnpercom := 0;
                     else
                         vnpercom := gvet_regitem(j).percom;
                     end if;


                    begin
                    -- 31 parâmetros
                      -- HIS.02787.2016
                      -- 
                      p_calcularcmv_med(regfilial.tributsaidaorigemnacimp, -- HIS.02787.2016
                                              gregpcconsum.abaterimpostoscomissaorca,
                                              gregpcconsum.aplicarindicecmv,
                                              gregpcconsum.incluircomissaosugpvendacmv,
                                              nvl(gregpcconsum.txvenda, 0),
                                              regcliente.tipofj,
                                              regcliente.utilizaiesimplificada,
                                              regcliente.ieent,
                                              regproduto.freteespecial,
                                              regregiao.perfreteterceiros,
                                              regregiao.perfreteespecial,
                                              regprecos.custofin,
                                              regprecos.custoreal,
                                              regprecos.perdesccusto,
                                              regprecos.codicmtab,
                                              vbcodicmtabpf,
                                              regprecos.codicmtabpf,
                                              gvet_regpedido(i).percvenda,
                                              gvet_regitem(j).pvenda,
                                              vnpercom,
                                              (NVL(gvet_regitem(j).st,0)
                                               + NVL(gvet_regitem(j).vlfecp,0)),
                                              gvet_regitem(j).vlipi,
                                              0,
                                              regcliente.contribuinte,
                                              0,
                                              ----------------------------------
                                              --nvl(gvet_Regitem(j).VLREDPVENDASIMPLESNA,0),
                                              CASE NVL(regfilial.usadescsimplesnac,'N') WHEN 'S' THEN 0 ELSE nvl(gvet_Regitem(j).VLREDPVENDASIMPLESNA,
                                                  0) END,
                                              ----------------------------------
                                              regcliente.consumidorfinal,
                                              nvl(gregpcconsum.consideraisentoscomopf,'N'),
                                              gvet_regitem(j).perfretecmv,
                                              gvet_regitem(j).CUSTOFINEST,
                                              gvet_regitem(j).txvenda,
                                              gvet_regitem(j).perdesccusto,
                                              gvet_regitem(j).CODICMTAB,
                                              gvet_regitem(j).VLCUSTOREAL,
                                              gvet_regitem(j).VLCUSTOFIN,
                                              gvet_regitem(j).VLDESCCUSTOCMV,
                                              gvet_regpedido(i).codcli,          -- HIS.02787.2016
                                              0, -- p_custoprecific              -- HIS.02787.2016
                                              gvet_regitem(j).CODPROD,           -- HIS.02787.2016
                                              gvet_regpedido(i).codfilial,       -- HIS.02787.2016
                                              gvet_regitem(j).QT,                -- HIS.02787.2016
                                              regprecos.codicmtabinternac,       -- HIS.02787.2016
                                              gvet_regitem(j).vldesccmvpromocaomed,-- DDMEDICA-5009
                                              gvet_regitem(j).vlicmsstretanterior, -- DDMEDICA-7697
                                              gvet_regitem(j).PRODIMPORTADOPEPS, -- HIS.02787.2016
                                              gvet_regitem(j).NUMTRANSENTPEPS,   -- HIS.02787.2016
                                              vvMsgErroCalcularCMV               -- HIS.02787.2016
                                              );

                             gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Msg CMV: ' || vvMsgErroCalcularCMV;

                          exception when others then

                             if gvet_Regitem(j).codmotivonaoatend is null then
                                gvet_regitem(j).codmotivonaoatend := 23;

                             end if;


                          end;

                    ---------------------------------------------------------------------
                    -- DDMEDICA-5009 - Rebaixa de CMV com Verba de Fornecedor da Promoção
                    ---------------------------------------------------------------------
                    IF (NVL(gvet_regitem(j).vldesccmvpromocaomed,0) <> 0) THEN
                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'OLD vlverbacmv: ' || gvet_regitem(j).vlverbacmv;
                      --                   
                      gvet_regitem(j).vlverbacmv := gvet_regitem(j).vldesccmvpromocaomed;
                      vnPRECOBRUTO := (NVL(regproduto.ptabela,0) - NVL(gvet_regitem(j).st,0) - NVL(gvet_regitem(j).vlrepasse,0) - NVL(gvet_regitem(j).vlfecp,0));
                      IF (vnPRECOBRUTO = 0) THEN
                        gvet_regitem(j).perccustfornec := 0;
                      ELSE
                        BEGIN
                          gvet_regitem(j).perccustfornec := (NVL(gvet_regitem(j).vldesccmvpromocaomed,0) / NVL(vnPRECOBRUTO,0)) * 100;
                        EXCEPTION
                          WHEN OTHERS THEN 
                            gvet_regitem(j).perccustfornec := NULL;
                        END;
                      END IF;
                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'NEW vlverbacmv: '       || gvet_regitem(j).vlverbacmv;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'vldesccmvpromocaomed: ' || gvet_regitem(j).vldesccmvpromocaomed;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'vnPRECOBRUTO: '         || vnPRECOBRUTO;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'perccustfornec: '       || gvet_regitem(j).perccustfornec;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'numverbacampanha: '     || gvet_regitem(j).numverbacampanha;
                      --                                         
                    END IF;

                     if regcliente.simplesnacional = 'S'  and regprecos.percredpvendasimplesnac <> 0 and gvet_regitem(j).aplicadescontosimples  = 'S' then

                          -- PCNIL - Regra Específica Distribuidor de SC para não aplicar Redução do Simples Nacional no Preço
                          vbAplicarRedSimplesNoPreco := ((regprecos.aliqicms1 <= regprecos.aliqicms2)  and
                                                         regprecos.pauta = 0 and regprecos.iva = 0);
                          -- DDMEDICA-3639 - Simples Nacional ST Fonte na Integradora
                          IF (gvet_Regitem(j).tiporedsimplesnac = 'P') THEN
                            vbAplicarRedSimplesNoPreco := TRUE;
                          END IF;

                          --só atualiza caso não tenha impostos
                          --if (regprecos.aliqicms1 <= regprecos.aliqicms2)  and
                          --    regprecos.pauta = 0 and regprecos.iva = 0 then
                          if (vbAplicarRedSimplesNoPreco) then

                              -- PCNIL - Regra Específica Distribuidor de SC para não aplicar Redução do Simples Nacional no Preço
                              vbAplicarRedSimplesNoPreco := TRUE;
                              IF (FUSA_REGRA_MEDICAMENTOS('99','USAREGRANAOAPLICREDSIMPLESPRC') = 'S') AND
                                 (regfilial.usadescsimplesnac = 'S') THEN
                                vbAplicarRedSimplesNoPreco := FALSE;
                              END IF;

                              -- Condição para atender USAREGRANAOAPLICREDSIMPLESPRC
                              IF (vbAplicarRedSimplesNoPreco) THEN

                                -- LOG
                                gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13);
                                gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'APLICANDO REDUÿÿO DO SIMPLES NACIONAL DA TRIBUTAÿÿO:';
                                gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor Redução: ' || nvl(gvet_Regitem(j).VLREDPVENDASIMPLESNA,0);
                                gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela: '  || regproduto.ptabela;
                                gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda: '   || gvet_Regitem(j).pvenda;

                                vnptabela := regproduto.ptabela;

                                gvet_Regitem(j).pvenda := round(regproduto.ptabela - nvl(gvet_Regitem(j).VLREDPVENDASIMPLESNA,0),gregpcconsum.numcasasdecvenda);

                                gvet_Regitem(j).pbaserca := round(regproduto.ptabela - nvl(gvet_Regitem(j).VLREDPVENDASIMPLESNA,0),gregpcconsum.numcasasdecvenda);

                                -- LOG
                                gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Venda reduzido do SimplesNac da Tributação: ' || gvet_Regitem(j).pvenda;

                                --preço de venda precisa ser recalculado, por que o desconto comercial
                               --tem que ser efetuado depois da redução do simples nacional

                                if vnpercdesccom <> 0 then
                                    gvet_regitem(j).pvenda := round(gvet_Regitem(j).pvenda - (gvet_Regitem(j).pvenda * (vnpercdesccom/100)),gregpcconsum.numcasasdecvenda);
                                    -- LOG
                                    gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Aplicado Desconto ' || NVL(vnpercdesccom,0) || ' no Preço Venda reduzido do SimplesNac da Tributação: ' || gvet_Regitem(j).pvenda;
                                end if;

                                if vnpercdescrca <> 0 then
                                    gvet_regitem(j).pbaserca := round(gvet_Regitem(j).pbaserca - (gvet_Regitem(j).pbaserca * (vnpercdescrca/100)),gregpcconsum.numcasasdecvenda);
                                end if;


                                Regproduto.ptabela := round(regproduto.ptabela - nvl(gvet_Regitem(j).VLREDPVENDASIMPLESNA,0),gregpcconsum.numcasasdecvenda);
                                -- LOG
                                gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Preço Tabela reduzido do SimplesNac da Tributação: ' || Regproduto.ptabela;


                                -- DDMEDICA-3639 - Simples Nacional ST Fonte na Integradora igual na 2316
                                IF (NVL(gvet_Regitem(j).tiporedsimplesnac,'X') = 'P') THEN

                                  gvet_regitem(j).VLREDCMVSIMPLESNAC := nvl(gvet_Regitem(j).VLREDPVENDASIMPLESNA,0);

                                  gvet_regitem(j).vlcustofin         := nvl(gvet_regitem(j).vlcustofin,0)  - nvl(gvet_regitem(j).VLREDCMVSIMPLESNAC,0);
                                  gvet_regitem(j).vlcustoreal        := nvl(gvet_regitem(j).vlcustoreal,0) - nvl(gvet_regitem(j).VLREDCMVSIMPLESNAC,0);

                                ELSE

                                 --recalcular vlcustofin para que o percentual de lucratividade seja o mesmo se não tivesse tido redução de simples
                                 vnvlcustofin := gvet_regitem(j).pvenda - ((vnperlucsemred /100) *  gvet_regitem(j).pvenda);

                                 gvet_regitem(j).VLREDCMVSIMPLESNAC :=  vnvlcustofinsemimpostos - vnvlcustofin ;

                                 --calculando o percentual de diferença para retirar o vlcustoreal
                                 vnpercdif := ( (vnvlcustofin * 100)/gvet_regitem(j).vlcustofin) - 100;

                                 gvet_regitem(j).vlcustofin := vnvlcustofin;
                                 gvet_regitem(j).vlcustoreal := gvet_regitem(j).vlcustoreal + (gvet_regitem(j).vlcustoreal * (vnpercdif/100));

                                END IF;

                              END IF;  -- Fim Condição para atender USAREGRANAOAPLICREDSIMPLESPRC

                         end if;

                     end if;


                     --------------------------------
                     -- Se Cliente Simples Nacional
                     -- e Filial usa Desconto Simples
                     --------------------------------
                     -- PCNIL - Regra Específica Aplica Desconto do Simples no Força de Vendas no PREÇO DE VENDA
                     IF (FUSA_REGRA_MEDICAMENTOS('99','USAREGRAFVAPLICADESCSIMPLESREG') = 'S') THEN
                       IF (regcliente.simplesnacional  = 'S') AND
                          (regfilial.usadescsimplesnac = 'S') THEN

                         --// Guarda o VLREDCMVSIMPLESNAC
                         gvet_regitem(j).VLREDCMVSIMPLESNAC := gvet_regitem(j).custofinest * (gvet_regitem(j).percdescsimplesnac / 100);
                         --// Reduz o CMV igual a 2316
                         gvet_regitem(j).vlcustofin         := gvet_regitem(j).vlcustofin  - nvl(gvet_regitem(j).VLREDCMVSIMPLESNAC,0);
                         gvet_regitem(j).vlcustoreal        := gvet_regitem(j).vlcustoreal - nvl(gvet_regitem(j).VLREDCMVSIMPLESNAC,0);

                         -- LOG
                         gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% Desconto do Simples Nacional: ' || gvet_regitem(j).percdescsimplesnac;
                         gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'CustoFinEst: '                    || gvet_regitem(j).custofinest;
                         gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor Redução CMV: '              || gvet_regitem(j).VLREDCMVSIMPLESNAC;

                       END IF;
                     END IF;



                    -------------------------------------------------------------------------
                    -- MED-1822 - Aqui ficou somente a Rebaixa do CMV para ficar igual à 2316
                    -- (Aplicado sobre o Preço de Venda com ST)
                    -------------------------------------------------------------------------
                    IF (NVL(gvet_regitem(j).percverbacmvcli,0) <> 0) THEN

                      -- MED-1822 - Igualar a 2316, é gravado no campo pcpedi.vlverbacmvcli
                      --gvet_regitem(j).vlverbacmv := gvet_regitem(j).pvenda *(gvet_regitem(j).percverbacmv / 100);
                      gvet_regitem(j).vlverbacmvcli := gvet_regitem(j).pvenda *(gvet_regitem(j).percverbacmvcli / 100);

                      -- LOG
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || '% Verba CMV CLI: '     || gvet_regitem(j).percverbacmvcli ;
                      gvet_regitem(j).logprocmed := gvet_regitem(j).logprocmed || CHR(13) || 'Valor Verba CMV CLI: ' || gvet_regitem(j).vlverbacmvcli;

                      gvet_regitem(j).vlcustofin := gvet_regitem(j).vlcustofin + gvet_regitem(j).vlverbacmvcli;

                      gvet_regitem(j).vlcustoreal := gvet_regitem(j).vlcustoreal + gvet_regitem(j).vlverbacmvcli;

                    END IF;
                    -------------------------------------------------------------------------
                    -------------------------------------------------------------------------



                    if gvet_regitem(j).valido = true then


                     --tarefa 136584

                     -- HIS.04408.2015
                     IF ((FUNCOES_MED.FUNC_UTILIZAPRECOFABRICA(regproduto.tipomerc,
                                                               regproduto.utilizaprecofabrica,
                                                               gvet_regpedido(i).tipofv)) AND
                         ( nvl(gvet_regitem(j).poriginal,0) <> 0)) then

                        gvet_Regitem(j).descprecofab := ((gvet_regitem(j).poriginal - gvet_Regitem(j).pvenda) / (gvet_regitem(j).poriginal * 100));

                     end if;


                      -- insere item do pedido
                      vnnumseq := vnnumseq + 1;
                      gvet_regitem(j).numseq := vnnumseq;
                      gvet_regorigemcomiss(j).numseq := vnnumseq;
                      gvet_regorigemdesc(j).numseq := vnnumseq;

                      gvet_regorigempreco(j).numseq := vnnumseq;
                      vntotpesoped := vntotpesoped + (regproduto.pesobruto * gvet_regitem(j).qt);
                      vntotvolumeped := vntotvolumeped +(regproduto.volume * gvet_regitem(j).qt);

                      if gvet_regpedido(i).orcamento = 'S' then

                          gvet_regitem(j).valido := func_inseriritemorcamento (gvet_regpedido(i),
                                                                               gvet_regitem(j),
                                                                               regprecos,
                                                                               regproduto,
                                                                               gvet_regorigempreco(j),
                                                                               gvet_regorigemcomiss(j),
                                                                               gvet_regorigemdesc(j),
                                                                               regrca,
                                                                               regcliente,
                                                                               regfilial,
                                                                               regregiao);

                      else


                      gvet_regitem(j).valido := func_inseriritempedido(gvet_regpedido(i),
                                                                       gvet_regitem(j),
                                                                       regprecos,
                                                                       regproduto,
                                                                       gvet_regorigempreco(j),
                                                                       gvet_regorigemcomiss(j),
                                                                       gvet_regorigemdesc(j),
                                                                       regrca,
                                                                       regcliente,
                                                                       regfilial,
                                                                       regregiao);

                     end if;
                    end if;
                  end if;
                end if;

              exception
                when others then

                  gvet_regpedido(i).valido := false;
                  proc_registralog(gvet_regpedido(i).numped,
                                   gvet_regpedido(i).numpedrca,
                                   gvet_regitem(j).codprod,
                                   gvet_regitem(j).codauxiliar,
                                   gvet_regitem(j).cgccli,
                                   null,
                                   null,
                                   null,
                                   gvet_regpedido(i).codusur,
                                   gvet_regitem(j).dtaberturapedpalm,
                                   null,
                                   '3',
                                   sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->013->' || SQLERRM || ';',
                                   null,
                                   gvet_regitem(j).numseqifv);

                    if gvet_Regitem(j).codmotivonaoatend is null then
                       gvet_regitem(j).codmotivonaoatend := 999;

                    end if;



                  exit;
              end;
            end loop; -- FOR j IN 1 .. vncontitem


            -- HIS.03536.2016 - Combos de Promoção de Medicamentos
            for j in 1 .. vncontcombo loop
              begin

                if
                    (gvet_regpedido(i).numpedrca        = gvet_regcombo(j).numpedrca AND
                    gvet_regpedido(i).cgccli            = gvet_regcombo(j).cgccli    AND
                    gvet_regpedido(i).codusur           = gvet_regcombo(j).codusur   AND
                    gvet_regpedido(i).dtaberturapedpalm = gvet_regcombo(j).dtaberturapedpalm
                    ) then

                  -- VERIFICAR SE O COMBO É VÁLIDO
                  FUNCOES_MED.VALIDAR_COMBO_ECOMMERCE(gvet_regcombo(j).codpromocaomed,
                                                      gvet_regpedido(i).codfilial,
                                                      gvet_regpedido(i).codcli,
                                                      regregiao.numregiao,
                                                      gvet_regpedido(i).codusur,
                                                      gvet_regpedido(i).codplpag,
                                                      gvet_regpedido(i).codcondicaovenda,
                                                      gvet_regpedido(i).origemped,
                                                      gvet_regpedido(i).tipofv,
                                                      gvet_regpedido(i).data,
                                                      vvComboPrmValido,
                                                      vvMotivoRejeicaoComboPrm);
                  -- Se Combo VÁLIDO
                  IF (vvComboPrmValido = 'S') THEN

                    -- INSERE ITENS DO COMBO
                    PKG_PROMOCAO_MED.p_valida_promocao(2, -->> Chamado para Inserir Combo
                                            gvet_regpedido(i).numped,
                                            gvet_regpedido(i).codcli,
                                            gvet_regpedido(i).codusur,
                                            gvet_regpedido(i).codfilial,
                                            regregiao.numregiao,
                                            gvet_regpedido(i).condvenda,
                                            gvet_regpedido(i).codplpag,
                                            gvet_regcombo(j).codpromocaomed, -->> Promoção COMBO
                                            gvet_regpedido(i).posicao,
                                            NULL, -- Opção Entrega não precisa preencher no Combo
                                            NULL, -- Rotina Lanc. não precisa preencher no Combo
                                            gvet_regcombo(j).qtcombo,       -->> Qtde de Combos
                                            vvPodeGravarComboPrm,
                                            vvMotivoNaoPodeGravarComboPrm,
                                            gvet_regpedido(i).codfilialnf,
                                            gvet_regpedido(i).codcob);

                    -- Se ocorreram problemas ao gravar o Combo
                    IF (NVL(vvPodeGravarComboPrm,'N') <> 'S') THEN

                      -- Observação do Combo
                      gvet_regcombo(j).observacao_pc :=  gvet_regcombo(j).observacao_pc || '; ' || 'Problemas na Gravação do Combo: ' || vvMotivoNaoPodeGravarComboPrm;

                      -- Se Combo com Faturamento Integral rejeita o Pedido
                      if (gvet_regcombo(j).rejeitapedcomboinvalido = 'S') then
                        gvet_regpedido(i).valido := false;
                        proc_registralog(gvet_regpedido(i).numped,
                                         gvet_regpedido(i).numpedrca,
                                         null,
                                         NULL,
                                         gvet_regpedido(i).cgccli,
                                         NULL,
                                         NULL,
                                         NULL,
                                         gvet_regpedido(i).codusur,
                                         gvet_regpedido(i).dtaberturapedpalm,
                                         null,
                                         '2',
                                         'Problemas na Gravação do Combo ' || gvet_regcombo(j).codpromocaomed || ': ' || vvMotivoNaoPodeGravarComboPrm || ';',
                                         NULL,
                                         null);
                      end if;
                    END IF;

                  -- Se Combo NÃO É VÁLIDO
                  ELSE

                    -- Observação do Combo
                    gvet_regcombo(j).observacao_pc :=  gvet_regcombo(j).observacao_pc || '; ' || 'Combo não permitido: ' || vvMotivoRejeicaoComboPrm;

                    -- Se Combo com Faturamento Integral rejeita o Pedido
                    if (gvet_regcombo(j).rejeitapedcomboinvalido = 'S') then
                      gvet_regpedido(i).valido := false;
                      proc_registralog(gvet_regpedido(i).numped,
                                       gvet_regpedido(i).numpedrca,
                                       null,
                                       NULL,
                                       gvet_regpedido(i).cgccli,
                                       NULL,
                                       NULL,
                                       NULL,
                                       gvet_regpedido(i).codusur,
                                       gvet_regpedido(i).dtaberturapedpalm,
                                       null,
                                       '2',
                                       'Combo ' || gvet_regcombo(j).codpromocaomed || ' não permitido: ' || vvMotivoRejeicaoComboPrm || ';',
                                       NULL,
                                       null);
                    end if;

                  END IF;

                end if;

              exception
                when others then

                  -- Observação do Combo
                  gvet_regcombo(j).observacao_pc :=  gvet_regcombo(j).observacao_pc || '; ' || 'Erro no Processamento do Combo: ' || sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || SQLERRM;

                  -- Se Combo com Faturamento Integral rejeita o Pedido
                  if (gvet_regcombo(j).rejeitapedcomboinvalido = 'S') then
                    gvet_regpedido(i).valido := false;
                    proc_registralog(gvet_regpedido(i).numped,
                                     gvet_regpedido(i).numpedrca,
                                     null,
                                     NULL,
                                     gvet_regpedido(i).cgccli,
                                     NULL,
                                     NULL,
                                     NULL,
                                     gvet_regpedido(i).codusur,
                                     gvet_regpedido(i).dtaberturapedpalm,
                                     null,
                                     '2',
                                     'Erro no Processamento do Combo ' || gvet_regcombo(j).codpromocaomed || ': ' || sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->013->' || SQLERRM || ';',
                                     NULL,
                                     null);
                  end if;
              end;
            end loop; -- FOR j IN 1 .. vncontcombo


              for reg_combos in (select distinct pcpedi.codcombo
                     from pcpedi
                     where numped = gvet_regpedido(i).numped
                     and   codcombo is not null) loop


                  vbvalidodescontocombo := funcoesvendas.verificacampanhasdesconto
                                            (gvet_regpedido(i).numped ,
                                             gvet_regpedido(i).codfilial,
                                             regregiao.numregiao,
                                             gvet_regpedido(i).codcli,
                                             regcliente.codatv1,
                                             regcliente.codcliprinc,
                                             gvet_regpedido(i).codusur,
                                             regrca.codsupervisor,
                                             regrca.coddistrib,
                                             regplpag.pertxfim,
                                             reg_combos.codcombo,
                                             vsmensagemdescontocombo,
                                             gvet_regpedido(i).codplpag);

                  if vbvalidodescontocombo = false then

                     delete from pcorigempreco
                     where numped = gvet_regpedido(i).numped
                     and   codprod in (select codprod from pcpedi where codcombo = reg_Combos.Codcombo);

                     for reg in (select codprod,qt
                                 from pcpedi
                                 where numped = gvet_regpedido(i).numped
                                  and   codcombo = reg_Combos.Codcombo) loop

                          delete from pcpedi
                          where numped = gvet_regpedido(i).numped
                          and   codcombo = reg_Combos.Codcombo
                          and   codprod = reg.codprod;

                                proc_registralog(gvet_regpedido(i).numped,
                                   gvet_regpedido(i).numpedrca,
                                   null,
                                   NULL,
                                   gvet_regpedido(i).cgccli,
                                   NULL,
                                   NULL,
                                   NULL,
                                   gvet_regpedido(i).codusur,
                                   gvet_regpedido(i).dtaberturapedpalm,
                                   null,
                                   '2',
                                  'Prod: '|| reg.codprod||' cortado por fazer parte do combo : '||reg_combos.codcombo||' que foi rejeitado.'||';',
                                   NULL,
                                   null);



                    end loop;

                         proc_registralog(gvet_regpedido(i).numped,
                                   gvet_regpedido(i).numpedrca,
                                   null,
                                   NULL,
                                   gvet_regpedido(i).cgccli,
                                   NULL,
                                   NULL,
                                   NULL,
                                   gvet_regpedido(i).codusur,
                                   gvet_regpedido(i).dtaberturapedpalm,
                                   null,
                                   '2',
                                   vsmensagemdescontocombo||';',
                                   NULL,
                                   null);

                  end if;

            end loop;



          if gvet_regpedido(i).orcamento = 'N' then

            -- verifica se ha itens no pedido
            select count(*),
                   sum(pcpedi.qt * pcpedi.pvenda),
                   sum(pcpedi.qt * pcpedi.ptabela),
                   sum(pcpedi.qt * pcpedi.pbaserca),
                   sum(pcpedi.qt * pcpedi.vlcustocont),
                   sum(pcpedi.qt * pcpedi.vlcustofin),
                   sum(pcpedi.qt * pcpedi.vlcustoreal),
                   sum(pcpedi.qt * pcpedi.vlcustorep)
              into vncontitensvalidos,
                   vnvltotped,
                   vnvltottab,
                   vnvltotbaserca,
                   vnvlcustocontped,
                   vnvlcustofinped,
                   vnvlcustorealped,
                   vnvlcustorepped
              from pcpedi
             where pcpedi.numped = gvet_regpedido(i).numped;


            if vncontitensvalidos <> 0 and vncontitensvalidos > vnqtinicial then

              vnvlsaldoped := 0;

              if gvet_Regpedido(i).condvenda <> 13 then

                vnvlsaldoped := 0;

               /*------------------------------------------------------------------------------------
                Atualização do Conta-Corrente alterado para dentro da proc_gravapedido
                ------------------------------------------------------------------------------------

                BEGIN
                  for reg_itens in (select codprod,
                                           numseq,
                                           qt,
                                           codauxiliar,
                                           pc_pkg_controlarsaldorca.ccrca_saldo_item(gregpcconsum.usacredrca,
                                                                                     gvet_regpedido(i).usadebcredrca,
                                                                                     'N',
                                                                                     gvet_regpedido(i).origemped,
                                                                                     NVL(gvet_regpedido(i).bonificaltdebcredrca,gregpcconsum.bonificaltdebcredrca), -->> bonificaltdebcredrca do pedido poderá ter a regra do Tipo de Bonificação - 4415.043506.2017
                                                                                     gregpcconsum.trocaaltdebcredrca,
                                                                                     gregpcconsum.crmaltdebcredrca,
                                                                                     gregpcconsum.brokeraltdebcredrca,
                                                                                     gregpcconsum.tipomovccrca,
                                                                                     gvet_regpedido(i).condvenda,
                                                                                     'N',
                                                                                     gvet_regpedido(i).codusur,
                                                                                     'V',
                                                                                     pcpedi.pvenda,
                                                                                     pcpedi.ptabela,
                                                                                     pcpedi.pbaserca,
                                                                                     (pcpedi.qt - decode(gvet_regpedido(i).posicao, 'B',
                                                                                                                                     0,
                                                                                                                                   nvl(pcpedi.qtfalta,0))),
                                                                                     'N',
                                                                                     pcpedi.movimentacontacorrenterca  ) saldo
                                      from pcpedi
                                     where numped = gvet_regpedido(i).numped
                                       and pcpedi.numseq > vnmaxnumseq
                                     order by saldo desc)
                                     loop

                    vnvldisponivel := pc_pkg_controlarsaldorca.ccrca_checar_disponivel_atual(gvet_regpedido(i).codusur);

                    if (vnvldisponivel + reg_itens.saldo + vnvlsaldoped) < 0 and reg_itens.saldo < 0 then

                      proc_registralog(gvet_regpedido(i).numped,
                                       gvet_regpedido(i).numpedrca,
                                       reg_itens.codprod,
                                       reg_itens.codauxiliar,
                                       gvet_regpedido(i).cgccli,
                                       NULL,
                                       NULL,
                                       null,
                                       gvet_regpedido(i).codusur,
                                       gvet_regpedido(i).dtaberturapedpalm,
                                       null,
                                       '3',
                                       'Rca sem credito disponivel' || ';',
                                       NULL);

                      if regfilial.aceitavendarcasemsaldofv =  'S' then

                         gvet_Regpedido(i).posicao := 'B';

                         gvet_regpedido(i).motivoposicao := 'Rca sem saldo disponivel';
                         gvet_regpedido(i).log       := gvet_regpedido(i).log || CHR(13) ||
                                                       'Rca sem saldo disponivel';


                      else

                          delete from pcpedi
                           where numped = gvet_regpedido(i).numped
                             and codprod = reg_itens.codprod
                             and numseq  = reg_itens.numseq;

                       end if;

                    else

                      vnvlsaldoped := vnvlsaldoped + reg_itens.saldo;

                    end if;
                  end loop;
                EXCEPTION
                  WHEN OTHERS THEN
                    IF (NVL(gvet_regpedido(i).tipofv,'FV') NOT IN ('OL','PE')) THEN
                      RAISE;
                      END IF;
                END;
                ------------------------------------------------------------------------------------
                Atualização do Conta-Corrente alterado para dentro da proc_gravapedido
                ------------------------------------------------------------------------------------*/

              end if;

             end if;
            end if;

            if gvet_regpedido(i).orcamento = 'S' then

              SELECT COUNT(*),
                     SUM(qt * pvenda),
                     SUM(qt * ptabela),
                     SUM(qt * pbaserca),
                     SUM(qt * vlcustocont),
                     SUM(qt * vlcustofin),
                     SUM(qt * vlcustoreal),
                     SUM(qt * vlcustorep)
                INTO vncontitensvalidos,
                     vnvltotped,
                     vnvltottab,
                     vnvltotbaserca,
                     vnvlcustocontped,
                     vnvlcustofinped,
                     vnvlcustorealped,
                     vnvlcustorepped
                FROM pcorcavendai
               WHERE numorca = gvet_regpedido(i).numped;

            else

              SELECT COUNT(*),
                     SUM(pcpedi.qt * pcpedi.pvenda),
                     SUM(pcpedi.qt * pcpedi.ptabela),
                     SUM(pcpedi.qt * pcpedi.pbaserca),
                     SUM(pcpedi.qt * pcpedi.vlcustocont),
                     SUM(pcpedi.qt * pcpedi.vlcustofin),
                     SUM(pcpedi.qt * pcpedi.vlcustoreal),
                     SUM(pcpedi.qt * pcpedi.vlcustorep)
                INTO vncontitensvalidos,
                     vnvltotped,
                     vnvltottab,
                     vnvltotbaserca,
                     vnvlcustocontped,
                     vnvlcustofinped,
                     vnvlcustorealped,
                     vnvlcustorepped
                FROM pcpedi
               WHERE pcpedi.numped = gvet_regpedido(i).numped;

            end if;

            -- SE GRAVOU ITENS NA PCPEDI --------------------------------------
            if vncontitensvalidos > 0 and vncontitensvalidos > vnqtinicial then

             if regfilial.broker = 'N' then


              -- faz validacao final do cabecalho
              proc_validacaofinalcab(gvet_regpedido(i),
                                     regcliente,
                                     regplpag,
                                     regplpagetico,
                                     regplpaggenerico,
                                     regcob,
                                     regfilial,
                                     regrca,
                                     vncontitensvalidos,
                                     vnvltotped,
                                     vnvltotped_ant,
                                     vnvltottab,
                                     vnvlcustofinped);


              if regplpag.formaparcelamento = 'V' and gvet_regpedido(i).percplpag is not null then

                  update pcpedi
                  set pvenda = round(pvenda * (1 + (gvet_regpedido(i).percplpag / 100)),gregpcconsum.numcasasdecvenda),
                      ptabela = round(ptabela * (1 + (gvet_regpedido(i).percplpag / 100)),gregpcconsum.numcasasdecvenda),
                      pbaserca = round(pbaserca * (1 + (gvet_regpedido(i).percplpag / 100)),gregpcconsum.numcasasdecvenda)
                  where numped = gvet_regpedido(i).numped;

              end if;


              end if;

            -- SE NÃO GRAVOU ITENS NA PCPEDI --------------------------------------
            -- REJEIÇÃO DO PEDIDO: Nenhum item gravado
            else

              gvet_regpedido(i).valido := false;
              proc_registralog(gvet_regpedido(i).numped,
                               gvet_regpedido(i).numpedrca,
                               null,
                               null,
                               gvet_regpedido(i).cgccli,
                               null,
                               null,
                               null,
                               gvet_regpedido(i).codusur,
                               gvet_regpedido(i).dtaberturapedpalm,
                               null,
                               '2',
                               'Nenhum item gravado;',
                               null,
                               null);

               if gvet_regpedido(i).codmotivonaoatend is null then
                  gvet_Regpedido(i).codmotivonaoatend := 39;


               end if;


            end if; -- FIM: SE GRAVOU ITENS NA PCPEDI --------------------------------------


            -- ANTES de inserir o Cabeçalho do Pedido, Valida Taxa de Frete
            IF (gvet_regpedido(i).valido) THEN
              -- Se não mandou a Taxa de Frete na Integração
              IF (gvet_regpedido(i).vlfreteoutrasdesp IS NULL) THEN -->> SE ESTIVER NULO (zero entende-se que mandou taxa zero)
                INTEGRADORACOMPLE_MED.OBTER_TAXA_FRETE(gvet_regpedido(i).codfilial,
                                                       gvet_regpedido(i).origemped,
                                                       gvet_regpedido(i).tipofv,
                                                       vrRetTaxaFrete.vvAchouFrete,
                                                       vrRetTaxaFrete.vnValorTaxa,
                                                       vrRetTaxaFrete.vnValorMinimo);
                IF (vrRetTaxaFrete.vvAchouFrete = 'S') THEN
                  -- Se Total do Pedido ficar abaixo do Mínimo (acima ou igual ao mínimo não aplica a taxa de frete)
                  IF (NVL(vnvltotped,0) < NVL(vrRetTaxaFrete.vnValorMinimo,0)) THEN
                    gvet_regpedido(i).vlfreteoutrasdesp := NVL(vrRetTaxaFrete.vnValorTaxa,0);
                  END IF;
                END IF;
              END IF;
            END IF;


            if gvet_regpedido(i).valido = true then

            if gvet_regpedido(i).orcamento = 'S' then

              gvet_regpedido(i).valido := func_inserirorcamento(gvet_regpedido(i),
                                                                regplpag,
                                                                regrca,
                                                                regcliente,
                                                                regregiao,
                                                                regfilial,
                                                                vncontitensvalidos,
                                                                vnvltotped,
                                                                vnvltottab,
                                                                vntotpesoped,
                                                                vntotvolumeped,
                                                                vnvlcustocontped,
                                                                vnvlcustofinped,
                                                                vnvlcustorealped,
                                                                vnvlcustorepped);

              else

              gvet_regpedido(i).valido := func_inserircabpedido(gvet_regpedido(i),
                                                                regplpag,
                                                                regrca,
                                                                regcliente,
                                                                regregiao,
                                                                regfilial,
                                                                vncontitensvalidos,
                                                                vnvltotped,
                                                                vnvltottab,
                                                                vntotpesoped,
                                                                vntotvolumeped,
                                                                vnvlcustocontped,
                                                                vnvlcustofinped,
                                                                vnvlcustorealped,
                                                                vnvlcustorepped,
                                                                vscoddistrib);
              end if;

              if gvet_regpedido(i).valido = true then

              if gvet_regpedido(i).orcamento = 'N' then

                if regfilial.broker = 'N' then

                /**********************************************************************
                 **********************************************************************
                 **********************************************************************
                 *** C H A M A D A    D A    G R A V A Ç Ã O   D O    P E D I D O   ***
                 **********************************************************************
                 **********************************************************************
                 **********************************************************************/
                 --if gvet_regpedido(i).condvenda <> 7 then
                    -- gravar pedido / baixar estoque / atualizar conta-corrente rca
                    proc_gravapedido(gvet_regpedido(i),
                                      vnmaxnumseq,
                                      regfilial,
                                      regcliente,
                                      regrca,
                                      regplpag,
                                      vnvlatendped,
                                      vntotpesoped,
                                      vntotvolumeped,
                                      vnvltotped);
                  --end if;
                end if;

                if gvet_regpedido(i).valido = true then

                 if regfilial.broker = 'N' then
                  if gvet_regpedido(i).condvenda = 1 and
                     nvl(gvet_regpedido(i).numpedorig, 0) = 0 then

                     gvet_regpedido(i).geroubrinde := 'N';

                     -- Para evitar erro desnecessário por package de campanha inválida e o OL/PE não precisar apurar campanha brindes
                     vbApurarCampanhaBrindes := TRUE;
                     IF (gvet_regpedido(i).tipofv IN ('OL','PE')) THEN
                       IF FOBTEM_PARAM_INTEGRADORA(gvet_regpedido(i).integradora,'APURARCAMPANHABRINDESOLPE','N') = 'N' THEN
                         vbApurarCampanhaBrindes := FALSE;
                       END IF;
                     END IF;

                     if (vbApurarCampanhaBrindes) AND
                        (nvl(regcliente.validarcampanhabrinde,'S') = 'S') then

                        -- MED-1719 - Controle sobre a Package de Campanha
                        BEGIN
                          COMMIT;
                          apurarcampanhasbrindes.proc_apurarcampanha
                                (gvet_regpedido(i).numped,
                                 gvet_regpedido(i).codfilialretira,
                                 gvet_regpedido(i).cgccli,
                                 vnnumseq,
                                 'S',
                                 vsmensagembrinde,
                                 vsgeroubrinde);
                          COMMIT;
                          -- DDMEDICA-2349 - Recalcula ST da Bonificação
                          IF (vsgeroubrinde = 'S') AND -- DDMEDICA-6666
                             (NVL(regfilial.UTILIZACALCULOSTPACOTE,'N') <>  'S') THEN -->> DDMEDICA-3727 - Exclui-se quem usa Tributação do Pacote
                            FOR vc_Bonificacao IN (SELECT NUMPED
                                                     FROM PCPEDC
                                                    WHERE (NUMPEDRCA         = gvet_regpedido(i).numpedrca)
                                                      AND (CODCLI            = gvet_regpedido(i).codcli)
                                                      AND (DTABERTURAPEDPALM = gvet_regpedido(i).dtaberturapedpalm)
                                                      AND (CONDVENDA         = 5)) LOOP
                              PKG_MEDICAMENTOS.P_RECALCULAR_STFONTE(vc_Bonificacao.NUMPED,
                                                         vvOcorreramErrosRecalcSt,
                                                         vvMsgErrosRecalcSt);
                              COMMIT;
                            END LOOP;
                            -- DDMEDICA-6666 - Itens Bonificados de Brinde
                            IF (NVL(regfilial.gerarbrindepedbonific,'N') <>  'S') THEN
                              FOR vc_Bonificacao IN (SELECT DISTINCT NUMPED
                                                       FROM PCPEDI
                                                      WHERE (NUMPED  = gvet_regpedido(i).numped)
                                                        AND (BONIFIC = 'F')
                                                        AND (BRINDE  = 'S')) LOOP
                                PKG_MEDICAMENTOS.P_RECALCULAR_STFONTE(vc_Bonificacao.NUMPED,
                                                                      vvOcorreramErrosRecalcSt,
                                                                      vvMsgErrosRecalcSt,
                                                                      'B');
                                COMMIT;
                              END LOOP;                            
                            END IF;                            
                          END IF;
                         EXCEPTION
                           WHEN OTHERS THEN
                             vsmensagembrinde := NULL;
                             vsgeroubrinde    := NULL;
                         END;

                         if vsmensagembrinde is not null then

                          proc_registralog(gvet_regpedido(i).numped,
                                           gvet_regpedido(i).numpedrca,
                                           null,
                                           null,
                                           gvet_regpedido(i).cgccli,
                                           null,
                                           null,
                                           null,
                                           gvet_regpedido(i).codusur,
                                           gvet_regpedido(i).dtaberturapedpalm,
                                           null,
                                           '2',
                                           vsmensagembrinde,
                                           NULL,
                                           null);



                         end if;

                         if vsgeroubrinde = 'S' then


                            gvet_regpedido(i).geroubrinde := 'S';


                         end if;



                     end if;
                  end if;
                  end if;

                  /*-------------------------------------------------------------------------------------
                   INICIO: HIS.04281.2017 - Refatoração do Estoque - Será usada a nova Package de Estoque
                   --------------------------------------------------------------------------------------
                   if gvet_Regpedido(i).condvenda <> 13 then
                     BEGIN
                       for reg_itens in (select codprod, numseq, qt,
                       pc_pkg_controlarsaldorca.ccrca_saldo_item(gregpcconsum.usacredrca,
                                                                                     gvet_regpedido(i).usadebcredrca,
                                                                                     'N',
                                                                                     gvet_regpedido(i).origemped,
                                                                                     NVL(gvet_regpedido(i).bonificaltdebcredrca,gregpcconsum.bonificaltdebcredrca), -->> bonificaltdebcredrca do pedido poderá ter a regra do Tipo de Bonificação - 4415.043506.2017
                                                                                     gregpcconsum.trocaaltdebcredrca,
                                                                                     gregpcconsum.crmaltdebcredrca,
                                                                                     gregpcconsum.brokeraltdebcredrca,
                                                                                     gregpcconsum.tipomovccrca,
                                                                                     gvet_regpedido(i).condvenda,
                                                                                     'N',
                                                                                     gvet_regpedido(i).codusur,
                                                                                     'V',
                                                                                     pcpedi.pvenda,
                                                                                     pcpedi.ptabela,
                                                                                     pcpedi.pbaserca,
                                                                                     (pcpedi.qt - decode(gvet_regpedido(i).posicao, 'B',
                                                                                                                                     0,
                                                                                                                                   nvl(pcpedi.qtfalta,0))),
                                                                                     'N',
                                                                                     pcpedi.movimentacontacorrenterca  ) saldo
                                          from pcpedi
                                         where numped = gvet_regpedido(i).numped
                                           and numseq > vnmaxnumseq
                                           order by saldo desc) loop

                        vbsaldorca := pc_pkg_controlarsaldorca.ccrca_incluir_item_pedido(8888,
                                                                                         2513,
                                                                                         gvet_regpedido(i).codusur,
                                                                                         gvet_regpedido(i).numped,
                                                                                         reg_itens.codprod,
                                                                                         reg_itens.numseq);
                     end loop;
                   EXCEPTION
                     WHEN OTHERS THEN
                       IF (NVL(gvet_regpedido(i).tipofv,'FV') NOT IN ('OL','PE')) THEN
                         RAISE;
                       END IF;
                   END;


                   end if;
                   -----------------------------------------------------------------------------------
                   FIM: HIS.04281.2017 - Refatoração do Estoque - Será usada a nova Package de Estoque
                   ----------------------------------------------------------------------------------*/

                  if (GREGPCCONSUM.CODCONTAREBAIXACMV is not null or
                     gregpcconsum.codcontarebaixacmvaapurar is not null) then
                       INTEGRADORACOMPLE_MED.proc_RebaixarCMV(gvet_regpedido (i).numped,
                                                              gvet_regpedido (i).data,
                                                              gvet_regpedido(i).codfilial,
                                                              gregpcconsum.CODCONTAREBAIXACMVAAPURAR,
                                                              gregpcconsum.codcontarebaixacmv,
                                                              gvet_regpedido(i).condvenda,
                                                              gvet_regpedido(i).codcli);

                    select sum(pcpedi.qt * pcpedi.vlcustofin),
                         sum(pcpedi.qt * pcpedi.vlcustoreal)
                      into
                           vnvlcustofinped,
                           vnvlcustorealped
                      from pcpedi
                      where pcpedi.numped = gvet_regpedido(i).numped;

                 begin

                  update pcpedc
                  set vlcustofin = decode(gvet_regpedido(i).condvenda,20,0,vnvlcustofinped),
                      vlcustoreal = decode(gvet_regpedido(i).condvenda,20,0,vnvlcustorealped)
                  where  numped = gvet_regpedido(i).numped;
                 exception when others then

                  proc_registralog(gvet_regpedido(i).numped,
                                   gvet_regpedido(i).numpedrca,
                                   null,
                                   null,
                                   gvet_regpedido(i).cgccli,
                                   null,
                                   null,
                                   null,
                                   gvet_regpedido(i).codusur,
                                   gvet_regpedido(i).dtaberturapedpalm,
                                   null,
                                   '2',
                                   'Erro ao atualizar pedido apos rebaixa de cmv :'||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                                   NULL,
                                   null);


                 end;

                 end if;

                /*********
                 COMMIT 01
                 *********/
                 commit;

               --verifica se teve pedido de brinde gerado
               select count(*)
               into viexistebrinde
               from pcpedc
               where numpedrca = gvet_regpedido(i).numpedrca
               and   brinde = 'S';

               if viexistebrinde = 1 then

                   select numped
                   into vnnumpedbrinde
                   from pcpedc
                   where numpedrca = gvet_regpedido(i).numpedrca
                   and   brinde = 'S';


                --rebaixar cmv para itens do pedido de brinde
                 if (gregPCCONSUM.CODCONTAREBAIXACMV is not null) then

                      INTEGRADORACOMPLE_MED.proc_RebaixarCMV(vnnumpedbrinde,
                                                             gvet_regpedido (i).data,
                                                             gvet_Regpedido(i).codfilial,
                                                             gregpcconsum.CODCONTAREBAIXACMVAAPURAR,
                                                             gregpcconsum.codcontarebaixacmv,
                                                             gvet_Regpedido(i).condvenda,
                                                             gvet_Regpedido(i).codcli);



                      select sum(pcpedi.qt * pcpedi.vlcustofin),
                             sum(pcpedi.qt * pcpedi.vlcustoreal)
                          into
                               vnvlcustofinped,
                               vnvlcustorealped
                          from pcpedi
                          where pcpedi.numped = vnnumpedbrinde;

                     begin

                      update pcpedc
                      set vlcustofin = vnvlcustofinped,
                          vlcustoreal = vnvlcustorealped
                      where  numped = vnnumpedbrinde;
                     exception when others then

                  proc_registralog(gvet_regpedido(i).numped,
                                   gvet_regpedido(i).numpedrca,
                                   null,
                                   null,
                                   gvet_regpedido(i).cgccli,
                                   null,
                                   null,
                                   null,
                                   gvet_regpedido(i).codusur,
                                   gvet_regpedido(i).dtaberturapedpalm,
                                   null,
                                   '2',
                                   'Erro ao atualizar pedido apos rebaixa de cmv para pedido de brinde :'||SQLCODE||'-'||DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->' || SQLERRM,
                                   NULL,
                                   null);


                     end;

                     end if;



               end if;

                 /*********
                  COMMIT 02
                  *********/
                  commit;


                    select nvl(vlcorrente,0) + nvl(vllimcred,0)
                    into  vnvlsaldorca
                    from  pcusuari
                    where codusur = gvet_regpedido(i).codusur;


                    update pcpedcfv
                    set pcpedcfv.saldoatualrca = vnvlsaldorca
                      , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
                    where numpedrca            = gvet_regpedido(i).numpedrca
                    and   cgccli               = gvet_regpedido(i).cgccli
                    and   codusur              = gvet_regpedido(i).codusur
                    and   dtaberturapedpalm    = gvet_regpedido(i).dtaberturapedpalm   ;


                 /*********
                  COMMIT 03
                  *********/
                  commit;

                 /*---------------------------------------
                  QUEBRA GERAL DE PEDIDOS - DDVENDAS-38483
                  ---------------------------------------*/
                  IF (NVL(gvet_regpedido(i).tipofv,'FV') NOT IN ('OL','PE')) THEN
                    BEGIN
                      SELECT POSICAO
                        INTO vvPosicaoQuebraPedido
                        FROM PCPEDC
                       WHERE (NUMPED = gvet_regpedido(i).numped);
                    EXCEPTION
                      WHEN NO_DATA_FOUND THEN
                        vvPosicaoQuebraPedido := 'B';
                    END;
                    IF (NVL(vvPosicaoQuebraPedido,'L') NOT IN ('P','B')) THEN
                      PKG_GRAVACAO_PEDIDO_MED.P_FINALIZACAO_PEDIDO_01(2513, -- pi_nCodRotina
                                                                      gvet_regpedido(i).numped,
                                                                      8888, -- pi_nMatricula
                                                                      vvPosicaoQuebraPedido,
                                                                      gvet_regpedido(i).numcar,
                                                                      vvOcorreramErrosQuebraPedido,
                                                                      vvMsgErrosQuebraPedido);
                      IF (vvOcorreramErrosQuebraPedido = 'S') THEN
                        proc_registralog(gvet_regpedido(i).numped,
                                         gvet_regpedido(i).numpedrca,
                                         null,
                                         null,
                                         gvet_regpedido(i).cgccli,
                                         null,
                                         null,
                                         null,
                                         gvet_regpedido(i).codusur,
                                         gvet_regpedido(i).dtaberturapedpalm,
                                         null,
                                         '2',
                                         vvMsgErrosQuebraPedido,
                                         null,
                                         null);
                      END IF;                                                                    
                      -- Efetiva Transações realizadas na Quebra de Pedidos
                      commit;
                    END IF;                                                                    
                  END IF;                                                                    

                 /*-------------------------------------
                  QUEBRA DE PEDIDOS RESTRIÇÃO TRANSPORTE
                  -------------------------------------*/
                  
                  if regfilial.separarprodcomrestricaotransp = 'S' and gvet_regpedido(i).condvenda not in (7) and gvet_regpedido(i).numpedorig = 0 then

                  prc_gerarpedidorestricaotransp(gvet_regpedido(i).numped,
                                                 vsauxpedido,
                                                 vsmensagem);

                  proc_registralog(gvet_regpedido(i).numped,
                                   gvet_regpedido(i).numpedrca,
                                   null,
                                   null,
                                   gvet_regpedido(i).cgccli,
                                   null,
                                   null,
                                   null,
                                   gvet_regpedido(i).codusur,
                                   gvet_regpedido(i).dtaberturapedpalm,
                                   null,
                                   '2',
                                   vsmensagem,
                                   null,
                                   null);

                /*********
                 COMMIT 04
                 *********/
                 commit;


                  else

                        select count(*)
                        into viexisterest
                        from pcpedi,pcprodut
                        where pcpedi.numped = gvet_regpedido(i).numped
                        and   pcpedi.codprod = pcprodut.codprod
                        and   nvl(pcprodut.restricaotransp,'N') = 'S';

                        select count(*)
                        into viexisterestref
                        from pcpedi,pcprodut
                        where pcpedi.numped = gvet_regpedido(i).numped
                        and   pcpedi.codprod = pcprodut.codprod
                        and   nvl(pcprodut.restricaotransp,'N') = 'R';


                        if viexisterestref > 0 then

                           update pcpedc
                           set pcpedc.restricaotransp = 'R'
                           where numped = gvet_regpedido(i).numped;


                        else

                           if viexisterest > 0 then

                               update pcpedc
                               set pcpedc.restricaotransp = 'S'
                               where numped = gvet_regpedido(i).numped;


                           end if;
                        end if;

                       /*********
                        COMMIT 05
                        *********/
                        commit;



                 end if;

             --tarefa 194518

           if regfilial.separarprodcomst = 'S' then


            if gvet_regpedido(i).orcamento = 'N' and gvet_regpedido(i).condvenda not in (7) and gvet_regpedido(i).numpedorig = 0  then

             for reg in (select numped
                         from pcpedc p
                         where p.numpedrca         = gvet_regpedido(i).numpedrca
                         and   p.dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm
                         and   p.codusur           = gvet_regpedido(i).codusur
                         and   p.codcli            = gvet_regpedido(i).codcli
                          )loop



                   prc_gerarpedidoitemcomst(reg.numped,
                                            vnpedidorestst,
                                            vsmensagemrestst);

                     if vsmensagemrestst is not null then

                      proc_registralog(gvet_regpedido(i).numped,
                                       gvet_regpedido(i).numpedrca,
                                       null,
                                       null,
                                       gvet_regpedido(i).cgccli,
                                       null,
                                       null,
                                       null,
                                       gvet_regpedido(i).codusur,
                                       gvet_regpedido(i).dtaberturapedpalm,
                                       null,
                                       '2',
                                       vsmensagemrestst || ';',
                                       null,
                                       null);
                      end if;


              end loop;

             /*********
              COMMIT 06
              *********/
              commit;

             end if;

            end if;


               if gvet_regpedido(i).condvenda = 7 and gvet_regpedido(i).numpedorig = 0 then

                  if regfilial.RESERVARESTOQUETV7 = 'S' then
                     begin
                       SELECT 'S'
                         INTO vsAchouPedidoTV8
                         FROM PCPEDC
                        WHERE (numpedentfut = gvet_regpedido(i).numped)
                          AND (ROWNUM = 1);
                     exception
                       when NO_DATA_FOUND then
                         vsAchouPedidoTV8 := 'N';                       
                     end;
                     
                     if vsAchouPedidoTV8 = 'N' then
                        prc_gerarpedtv8(gvet_regpedido(i).numped,
                                        vsmensagempedidotv8,
                                        vnnumpedtv8,
                                        vsposicaotv8,
                                        vnmotivotv8);



                        if trim(vsmensagempedidotv8) is not null then

                           proc_registralog(gvet_regpedido(i).numped,
                                            gvet_regpedido(i).numpedrca,
                                            null,
                                            null,
                                            gvet_regpedido(i).cgccli,
                                            null,
                                            null,
                                            null,
                                            gvet_regpedido(i).codusur,
                                            gvet_regpedido(i).dtaberturapedpalm,
                                            null,
                                            '2',
                                            vsmensagempedidotv8 || ';',
                                            null,
                                            null);

                        else

                           proc_registralog(gvet_regpedido(i).numped,
                                            gvet_regpedido(i).numpedrca,
                                            null,
                                            null,
                                            gvet_regpedido(i).cgccli,
                                            null,
                                            null,
                                            null,
                                            gvet_regpedido(i).codusur,
                                            gvet_regpedido(i).dtaberturapedpalm,
                                            null,
                                            '2',
                                            'Pedido TV8 gerado : '||vnnumpedtv8||' na posicao : '||vsposicaotv8 ||';',
                                            null,
                                            null);

                        end if;
                     else
                        proc_registralog(gvet_regpedido(i).numped,
                                            gvet_regpedido(i).numpedrca,
                                            null,
                                            null,
                                            gvet_regpedido(i).cgccli,
                                            null,
                                            null,
                                            null,
                                            gvet_regpedido(i).codusur,
                                            gvet_regpedido(i).dtaberturapedpalm,
                                            null,
                                            '2',
                                            'Pedido TV8 gerado : '||vnnumpedtv8||' na posicao : '||vsposicaotv8 ||';',
                                            null,
                                            null);
                     end if;
                   end if;
               end if;



                -- Carregamento de Pedido Balcao Reserva
                if (gvet_regpedido(i).origemped = 'R') and
                   (gvet_regpedido(i).posicao = 'L') then

                  gerarcarregbalcaoreserva(gvet_regpedido(i).numped,
                                           gvet_regpedido(i).numpedrca,
                                           gvet_regpedido(i).codusur,
                                           gvet_regpedido(i).cgccli,
                                           gvet_regpedido(i).dtaberturapedpalm,
                                           null,
                                           vnnumcar);
                end if;

                else

                rollback;

                  if nvl(gvet_regpedido(i).numpedorig, 0) = 0 then

                    if gvet_regpedido(i).orcamento = 'S' then

                         delete from pcorcavendai
                         where numorca = gvet_regpedido(i).numped;

                         delete from pcorcavendac
                         where numorca = gvet_regpedido(i).numped;

                       /*********
                        COMMIT 07
                        *********/
                        commit;

                     else

                       delete from pcpedi
                       where pcpedi.numped = gvet_regpedido(i).numped;

                      delete from pcorigempreco
                       where numped = gvet_regpedido(i).numped;

                      delete from pcpedc
                       where pcpedc.numped = gvet_regpedido(i).numped;

                     /*********
                      COMMIT 08
                      *********/
                      commit;

                      end if;

                 end if;

                end if;

               else

                /*********
                 COMMIT 09
                 *********/
                 commit;

               end if;

              else

                rollback;

                if nvl(gvet_regpedido(i).numpedorig, 0) = 0 then

                 if gvet_regpedido(i).orcamento = 'S' then

                   delete from pcorcavendai
                   where numorca = gvet_regpedido(i).numped;

                   delete from pcorcavendac
                   where numorca = gvet_regpedido(i).numped;

                 /*********
                  COMMIT 10
                  *********/
                  commit;

                 else

                  delete from pcpedi
                   where pcpedi.numped = gvet_regpedido(i).numped;

                  delete from pcorigempreco
                   where numped = gvet_regpedido(i).numped;

                  delete from pcpedc
                   where pcpedc.numped = gvet_regpedido(i).numped;

                 /*********
                  COMMIT 11
                  *********/
                  commit;

                 end if;
                end if;
              end if;
            else
              -- rejeitado na validacao final do cabecalho
              rollback;

              if nvl(gvet_regpedido(i).numpedorig, 0) = 0 then

                 if gvet_regpedido(i).orcamento = 'S' then

                   delete from pcorcavendai
                   where numorca = gvet_regpedido(i).numped;


                 /*********
                  COMMIT 12
                  *********/
                  commit;

                 else

                      delete from pcpedi
                       where pcpedi.numped = gvet_regpedido(i).numped;

                      delete from pcorigempreco
                       where numped = gvet_regpedido(i).numped;

                     /*********
                      COMMIT 13
                      *********/
                      commit;

                  end if;

              end if;

            end if;
          end if; -- pedido valido (gvet_regpedido (i).valido)

        exception
          when others then

            gvet_regpedido(i).valido := false;

          if gvet_Regpedido(i).codmotivonaoatend is null then
             gvet_regpedido(i).codmotivonaoatend := 999;

          end if;


            proc_registralog(gvet_regpedido(i).numped,
                             gvet_regpedido(i).numpedrca,
                             null,
                             null,
                             gvet_regpedido(i).cgccli,
                             null,
                             null,
                             null,
                             gvet_regpedido(i).codusur,
                             gvet_regpedido(i).dtaberturapedpalm,
                             null,
                             '2',
                             sqlcode || '-' || DBMS_UTILITY.FORMAT_ERROR_BACKTRACE || '->014->' || SQLERRM || ';',
                             null,
                             null);
            rollback;

            if nvl(gvet_regpedido(i).numpedorig, 0) = 0 then

              if gvet_regpedido(i).orcamento = 'S' then

                   delete from pcorcavendai
                   where numorca = gvet_regpedido(i).numped;

                   delete from pcorcavendac
                   where numorca = gvet_regpedido(i).numped;

                 /*********
                  COMMIT 14
                  *********/
                  commit;

              else

                  delete from pcpedi
                   where pcpedi.numped = gvet_regpedido(i).numped;

                  delete from pcorigempreco
                   where numped = gvet_regpedido(i).numped;

                  delete from pcpedc
                   where pcpedc.numped = gvet_regpedido(i).numped;

                 /*********
                  COMMIT 15
                  *********/
                  commit;

               end if;

              exit;

            end if;
        end;

      end loop; -- FOR i IN 1 .. vncontped

    end if; -- vncontped > 0

  end proc_processarpedidos;



  PROCEDURE proc_processaretornotab(p_existerro IN BOOLEAN) IS

    vncontlog                   number;
    vncontped                   number;
    vicontador                  number;
    vnqtatend                   pcpedi.qt%type;
    vsobservacaopedcab          varchar2(32767) := null;
    vsobservacaopedcorp         varchar2(32767) := null;

    vnnumped                    pcpedc.numped%type;
    vnnumpedrca                 pcpedc.numpedrca%type;
    vncodcli                    pcpedc.codcli%type;
    vscliente                   pcclient.cliente%type;
    vnvltotal                   number;
    vnvlatend                   number;
    vnqtatendped                number;
    vnqtpedida                  number;
    vsobsfinalpedido            varchar2(1000);

    vncontitem                  number;
    vncodmotanaoatenditem       number;

    vsatendido                  pcpedcfv.atendido%type;
    viexistecorte               number;
    vnqtatendtotped             number;
    vscorte                     varchar2(1);

    vvVersionamentoPkg          VARCHAR2(20);

   BEGIN
     
    vvVersionamentoPkg := F_OBTER_VERSIONAMENTO;
     
    -- Retorna erros genericos tiporeg = 1
    IF p_existerro = TRUE
    THEN
      vncontlog := gvetregistralog.COUNT;


      FOR i IN 1 .. vncontlog LOOP
        IF gvetregistralog(i).tiporeg = 1
        THEN
          -- Gravar log de processamento de pedidos
          BEGIN
            INSERT INTO pclogfv
              (arquivo, codcli, DATA, motivo, numped, numpedcli, numpedrca, status)
            VALUES
              ('PCPEDCFV/PCPEDIFV',
               NULL,
               SYSDATE,
               SUBSTR(replace(replace(gvetregistralog(i).erro, '#', ' '),';',CHR(13)), 1, 100),
               NULL,
               NULL,
               NULL,
               'N');

            COMMIT;
          EXCEPTION
            WHEN OTHERS THEN
              ROLLBACK;
          END;
        END IF;
      END LOOP;
    END IF;





     ----- Mensagens de retorno de codigo de nao atendimento para pedidos 'OL' e 'PE' -------------
     vncontped := gvet_regpedido.count;

     FOR i in 1 .. vncontped loop


        -- 5685.084449.2016 - NVL com 'FV' para gravar sempre o CODMOTIVONAOATEND
        if (NVL(gvet_regpedido(i).tipofv,'FV') in ('OL','PE','FV')) then -- Adicionado FV para gerar Motivos na Integração ArtNew e FocoPdv

          vncontitem := gvet_regitem.count;

          for j in 1 .. vncontitem loop

            if
              (gvet_regpedido(i).numpedrca = gvet_regitem(j).numpedrca AND
              gvet_regpedido(i).cgccli    = gvet_regitem(j).cgccli    AND
              gvet_regpedido(i).codusur   = gvet_regitem(j).codusur   AND
              gvet_regpedido(i).dtaberturapedpalm = gvet_regitem(j).dtaberturapedpalm AND
              ((nvl(gvet_regpedido(i).numpedorig, 0) = 0) or
             (nvl(gvet_regpedido(i).numpedorig, 0) <> 0 and
              (gvet_regpedido(i).numpedorig = gvet_regitem(j).numpedorig)))) then



             if gvet_regitem(j).codmotivonaoatend is not null then

                UPDATE pcpedifv
                   SET codmotivonaoatend  = gvet_regitem(j).codmotivonaoatend
                 WHERE numpedrca              = gvet_regpedido(i).numpedrca
                   AND cgccli                 = gvet_regpedido(i).cgccli
                   and codusur                = gvet_regpedido(i).codusur
                   and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
                   AND codprod                = gvet_regitem(j).codprod
                   AND (codauxiliar           = gvet_regitem(j).codauxiliar or codauxiliar is null)
                   AND numseq                 = gvet_regitem(j).numseqifv; -- DDMEDICA-198
                IF (NVL(SQL%ROWCOUNT,0) = 0) THEN -- DDMEDICA-198
                  UPDATE pcpedifv
                     SET codmotivonaoatend  = gvet_regitem(j).codmotivonaoatend
                   WHERE numpedrca              = gvet_regpedido(i).numpedrca
                     AND cgccli                 = gvet_regpedido(i).cgccli
                     and codusur                = gvet_regpedido(i).codusur
                     and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
                     AND codprod                = gvet_regitem(j).codprod
                     AND (codauxiliar           = gvet_regitem(j).codauxiliar or codauxiliar is null);
                END IF;

             end if;

             if gvet_regitem(j).logprocmed is not null then

                UPDATE pcpedifv
                   SET logprocmed = LOGPROCMED || CHR(13) || gvet_regitem(j).logprocmed
                 WHERE numpedrca              = gvet_regpedido(i).numpedrca
                   AND cgccli                 = gvet_regpedido(i).cgccli
                   and codusur                = gvet_regpedido(i).codusur
                   and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
                   AND codprod                = gvet_regitem(j).codprod
                   AND (codauxiliar           = gvet_regitem(j).codauxiliar or codauxiliar is null)
                   AND numseq                 = gvet_regitem(j).numseqifv; -- DDMEDICA-198
                IF (NVL(SQL%ROWCOUNT,0) = 0) THEN -- DDMEDICA-198
                  UPDATE pcpedifv
                     SET logprocmed = LOGPROCMED || CHR(13) || gvet_regitem(j).logprocmed
                   WHERE numpedrca              = gvet_regpedido(i).numpedrca
                     AND cgccli                 = gvet_regpedido(i).cgccli
                     and codusur                = gvet_regpedido(i).codusur
                     and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
                     AND codprod                = gvet_regitem(j).codprod
                     AND (codauxiliar           = gvet_regitem(j).codauxiliar or codauxiliar is null);
                END IF;

             end if;

             -- MED-1499
             if gvet_regitem(j).jsonprocmed is not null then

                UPDATE pcpedifv
                   SET msgprocmed         = gvet_regitem(j).jsonprocmed
                 WHERE numpedrca              = gvet_regpedido(i).numpedrca
                   AND cgccli                 = gvet_regpedido(i).cgccli
                   and codusur                = gvet_regpedido(i).codusur
                   and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
                   AND codprod                = gvet_regitem(j).codprod
                   AND (codauxiliar           = gvet_regitem(j).codauxiliar or codauxiliar is null)
                   AND numseq                 = gvet_regitem(j).numseqifv; -- DDMEDICA-198
                IF (NVL(SQL%ROWCOUNT,0) = 0) THEN -- DDMEDICA-198
                  UPDATE pcpedifv
                     SET msgprocmed         = gvet_regitem(j).jsonprocmed
                   WHERE numpedrca              = gvet_regpedido(i).numpedrca
                     AND cgccli                 = gvet_regpedido(i).cgccli
                     and codusur                = gvet_regpedido(i).codusur
                     and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
                     AND codprod                = gvet_regitem(j).codprod
                     AND (codauxiliar           = gvet_regitem(j).codauxiliar or codauxiliar is null);
                END IF;

             end if;

            end if;

          end loop;

         if gvet_regpedido(i).codmotivonaoatend is not null then

          -- 2438.022821.2017 - Tratamento para não colocar como Rejeitado para não afetar os retornos (Somente ignorar a importação)
          IF (NVL(gvet_regpedido(i).pedidoJaExistente,'N') <> 'S') THEN

            UPDATE pcpedcfv
               SET codmotivonaoatend = gvet_regpedido(i).codmotivonaoatend
                 , logprocmed        = logprocmed || CHR(13) || 'PROCESSAMENTO EM: ' || TO_CHAR(SYSDATE,'DD/MM/YYYY HH24:MI:SS') || ' - ' || vvVersionamentoPkg || ' ####################################################################################################'
                                                  || CHR(13) || CHR(13)
                                                  || gvet_regpedido(i).logprocmed -- MED-1895
                 , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
             WHERE numpedrca        = gvet_regpedido(i).numpedrca
             and   cgccli           = gvet_regpedido(i).cgccli
             and   codusur          = gvet_regpedido(i).codusur
             and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm;

          ELSE

            -- MED-1895 - Log de Processamento do Pedido
            IF (gvet_regpedido(i).logprocmed IS NOT NULL) THEN
              UPDATE pcpedcfv
                 SET logprocmed        = logprocmed || CHR(13) || 'PROCESSAMENTO EM: ' || TO_CHAR(SYSDATE,'DD/MM/YYYY HH24:MI:SS') || ' - ' || vvVersionamentoPkg || ' ####################################################################################################'
                                                    || CHR(13) || CHR(13)
                                                    || gvet_regpedido(i).logprocmed -- MED-1895
                   , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
               WHERE numpedrca        = gvet_regpedido(i).numpedrca
               and   cgccli           = gvet_regpedido(i).cgccli
               and   codusur          = gvet_regpedido(i).codusur
               and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm;
            END IF;

          END IF;

         else

           -- MED-2420 - Log do Cabeçalho passou a ser gravado sempre
           IF (gvet_regpedido(i).logprocmed IS NOT NULL) THEN
             UPDATE pcpedcfv
                SET logprocmed = logprocmed || CHR(13) || vvVersionamentoPkg || CHR(13) || gvet_regpedido(i).logprocmed
                  , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
              WHERE numpedrca        = gvet_regpedido(i).numpedrca
              and   cgccli           = gvet_regpedido(i).cgccli
              and   codusur          = gvet_regpedido(i).codusur
              and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm;
           END IF;

         end if;

         -- MED-1499 - JSON de Processamento do Pedido SEMPRE
         IF (gvet_regpedido(i).jsonprocmed IS NOT NULL) THEN
           UPDATE pcpedcfv
              SET msgprocmed = gvet_regpedido(i).jsonprocmed
                , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
            WHERE numpedrca        = gvet_regpedido(i).numpedrca
            and   cgccli           = gvet_regpedido(i).cgccli
            and   codusur          = gvet_regpedido(i).codusur
            and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm;
         END IF;

       end if;

     end loop;

     ----- Mensagens de LOG de codigo de nao atendimento para pedidos 'FV' -------------
     vncontped := gvet_regpedido.count;

     FOR i in 1 .. vncontped loop


        if NVL(gvet_regpedido(i).tipofv,' ') not in ('OL','PE') then

          vncontitem := gvet_regitem.count;

          for j in 1 .. vncontitem loop

            if
              (gvet_regpedido(i).numpedrca = gvet_regitem(j).numpedrca AND
              gvet_regpedido(i).cgccli    = gvet_regitem(j).cgccli    AND
              gvet_regpedido(i).codusur   = gvet_regitem(j).codusur   AND
              gvet_regpedido(i).dtaberturapedpalm = gvet_regitem(j).dtaberturapedpalm AND
              ((nvl(gvet_regpedido(i).numpedorig, 0) = 0) or
             (nvl(gvet_regpedido(i).numpedorig, 0) <> 0 and
              (gvet_regpedido(i).numpedorig = gvet_regitem(j).numpedorig)))) then


             if gvet_regitem(j).logprocmed is not null then

                UPDATE pcpedifv
                   SET logprocmed = LOGPROCMED || CHR(13) || gvet_regitem(j).logprocmed
                 WHERE numpedrca              = gvet_regpedido(i).numpedrca
                   AND cgccli                 = gvet_regpedido(i).cgccli
                   and codusur                = gvet_regpedido(i).codusur
                   and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
                   AND codprod                = gvet_regitem(j).codprod
                   AND (codauxiliar           = gvet_regitem(j).codauxiliar or codauxiliar is null)
                   AND numseq                 = gvet_regitem(j).numseqifv; -- DDMEDICA-198
                IF (NVL(SQL%ROWCOUNT,0) = 0) THEN -- DDMEDICA-198
                  UPDATE pcpedifv
                     SET logprocmed = LOGPROCMED || CHR(13) || gvet_regitem(j).logprocmed
                   WHERE numpedrca              = gvet_regpedido(i).numpedrca
                     AND cgccli                 = gvet_regpedido(i).cgccli
                     and codusur                = gvet_regpedido(i).codusur
                     and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
                     AND codprod                = gvet_regitem(j).codprod
                     AND (codauxiliar           = gvet_regitem(j).codauxiliar or codauxiliar is null);
                END IF;

             end if;

             -- MED-1499
             if gvet_regitem(j).jsonprocmed is not null then

                UPDATE pcpedifv
                   SET msgprocmed         = gvet_regitem(j).jsonprocmed
                 WHERE numpedrca              = gvet_regpedido(i).numpedrca
                   AND cgccli                 = gvet_regpedido(i).cgccli
                   and codusur                = gvet_regpedido(i).codusur
                   and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
                   AND codprod                = gvet_regitem(j).codprod
                   AND (codauxiliar           = gvet_regitem(j).codauxiliar or codauxiliar is null)
                   AND numseq                 = gvet_regitem(j).numseqifv; -- DDMEDICA-198
                IF (NVL(SQL%ROWCOUNT,0) = 0) THEN -- DDMEDICA-198
                UPDATE pcpedifv
                   SET msgprocmed         = gvet_regitem(j).jsonprocmed
                 WHERE numpedrca              = gvet_regpedido(i).numpedrca
                   AND cgccli                 = gvet_regpedido(i).cgccli
                   and codusur                = gvet_regpedido(i).codusur
                   and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
                   AND codprod                = gvet_regitem(j).codprod
                   AND (codauxiliar           = gvet_regitem(j).codauxiliar or codauxiliar is null);
                END IF;

             end if;

            end if;

          end loop;

       end if;

     end loop;

   /*********
    COMMIT 16
    *********/
    commit;

     -----------------INICIO PEDIDOS -------------------------

    -- Retorna pedidos gravados com sucesso
    vncontped := gvet_regpedido.COUNT;


    FOR i IN 1 .. vncontped LOOP
      IF gvet_regpedido(i).valido = TRUE
      THEN
        -- recupera critica do cabecalho.
        vncontlog          := gvetregistralog.COUNT;
        vsobservacaopedcab := '';

        vsatendido := 'T';

        FOR j IN 1 .. vncontlog LOOP
          IF (gvetregistralog(j).tiporeg = 2) AND
             (gvetregistralog(j).numped     = gvet_regpedido(i).numped) AND
             (gvetregistralog(j).numpedrca  = gvet_regpedido(i).numpedrca) AND
             (gvetregistralog(j).cgcent     = gvet_regpedido(i).cgccli) AND
             (gvetregistralog(j).codusur    = gvet_regpedido(i).codusur) AND
             (gvetregistralog(j).data       = gvet_regpedido(i).dtaberturapedpalm)
          THEN

            if length(vsobservacaopedcab) <= 3000 or vsobservacaopedcab is null then           
              -- Não Duplicar Críticas - DDMEDICA-6533
              BEGIN
                if (NVL(INSTR(vsobservacaopedcab, 
                              replace(replace(gvetregistralog(j).erro, '#', ' '),';',CHR(13))),0) = 0) THEN 
                  vsobservacaopedcab := vsobservacaopedcab ||
                                        replace(replace(gvetregistralog(j).erro, '#', ' '),';',CHR(13));
                end if;
              EXCEPTION
                WHEN OTHERS THEN
                  vsobservacaopedcab := vsobservacaopedcab ||
                                        replace(replace(gvetregistralog(j).erro, '#', ' '),';',CHR(13));
              END;
            end if;

          END IF;
        END LOOP;

        BEGIN

         if gvet_regpedido(i).orcamento = 'S' then

          select pcorcavendac.numorca,
                       decode(gvet_regpedido(i).numpedorig,
                              0,
                              pcorcavendac.numpedrca,
                              gvet_regpedido(i).numpedrca),
                 pcorcavendac.codcli,
                 pcclient.cliente,
                 pcorcavendac.vltotal,
                 pcorcavendac.vlatend,
                 pcorcavendac.numitens

          into vnnumped,
               vnnumpedrca,
               vncodcli,
               vscliente,
               vnvltotal,
               vnvlatend,
               vnqtatendped
          from pcorcavendac,pcclient
          where pcorcavendac.numorca = gvet_regpedido(i).numped
           and pcorcavendac.codcli = pcclient.codcli;


         else


          select pcpedc.numped,
                       decode(gvet_regpedido(i).numpedorig,
                              0,
                              pcpedc.numpedrca,
                              gvet_regpedido(i).numpedrca),
                 pcpedc.codcli,
                 pcclient.cliente,
                 pcpedc.vltotal,
                 pcpedc.vlatend,
                 pcpedc.numitens

          into vnnumped,
               vnnumpedrca,
               vncodcli,
               vscliente,
               vnvltotal,
               vnvlatend,
               vnqtatendped
          from pcpedc, pcclient
          where pcpedc.numped = gvet_regpedido(i).numped
           and pcpedc.codcli = pcclient.codcli;

         end if;

          vnqtpedida := gvet_regpedido(i).numitens;

               vsobsfinalpedido := '>>PEDIDO      : ' || vnnumpedrca||CHR(13)||
                                    vncodcli || ' - ' || vscliente||CHR(13)||
                                   'Pedido Winthor: ' || vnnumped||CHR(13)||
                                   'Total         : ' || vnvltotal||CHR(13)||
                                   'Atendido      : ' || vnvlatend||CHR(13)||
                                   'Tot. Itens    : ' || vnqtpedida||CHR(13)||
                                   'Tot. Atend    : ' || vnqtatendped;

               -- MED-2079 - Informação da Margem do Pedido
               IF (gvet_regpedido(i).margempedido IS NOT NULL) OR
                  (gvet_regpedido(i).margemminaplicada IS NOT NULL) THEN
                 vsobsfinalpedido := vsobsfinalpedido || CHR(13)||
                                     'Margem Minima : ' || gvet_regpedido(i).margemminaplicada||CHR(13)||
                                     'Margem Pedido : ' || gvet_regpedido(i).margempedido;
               END IF;


        END;

       if gvet_regpedido(i).orcamento = 'S' then

         begin
          select sum(numitens)
          into vnqtatendtotped
          from pcorcavendac
          where numorca in (select numorca from pcorcavendac
                           where numpedrca = gvet_regpedido(i).numpedrca
                           and   codusur   = gvet_regpedido(i).codusur
                           and   codcli    = gvet_regpedido(i).codcli
                           and   data      = trunc(sysdate));
          exception when others then

             vnqtatendtotped := 0;

          end;


             viexistecorte := 0;




       else

       -- tarefa 154935
         begin
          select sum(numitens)
          into vnqtatendtotped
          from pcpedc
          where numped in (select numped from pcpedc
                           where numpedrca = gvet_regpedido(i).numpedrca
                           and   codusur   = gvet_regpedido(i).codusur
                           and   codcli    = gvet_regpedido(i).codcli
                           and   data      = trunc(sysdate));
          exception when others then

             vnqtatendtotped := 0;

          end;

          begin
          select count(*)
          into viexistecorte
          from pcpedi
          where numped in (select numped from pcpedc
                           where numpedrca = gvet_regpedido(i).numpedrca
                           and   codusur   = gvet_regpedido(i).codusur
                           and   codcli    = gvet_regpedido(i).codcli
                           and   data      = trunc(sysdate))
          and pcpedi.qtfalta > 0    ;
          exception when others then

             viexistecorte := 0;

          end;

         end if;

          if vnqtpedida > vnqtatendtotped then -- se teve corte de itens
            vsatendido := 'P';

          end if;

          if nvl(viexistecorte,0) > 0 then
             vsatendido := 'P';

          end if;


        BEGIN
          --- atualiza cabecalho do pedido.
          UPDATE pcpedcfv
             SET importado        = 2,
                 retorno          = 2,
                 numped           = gvet_regpedido(i).numped,
                 observacao_pc    = substr(vsobsfinalpedido||CHR(13)||vsobservacaopedcab, 1, 4000),
                 posicao_atual    = gvet_regpedido(i).posicao,
                 atendido         = vsatendido
               , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
           WHERE numpedrca        = gvet_regpedido(i).numpedrca
           and   cgccli           = gvet_regpedido(i).cgccli
           and   codusur          = gvet_regpedido(i).codusur
           and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm;

          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            ROLLBACK;
        END;





        BEGIN
          --- atualiza tabela de retorno do pedido.
          UPDATE pcpedretorno
             SET numped           = gvet_regpedido(i).numped,
                 vllimitecredcli  = gvet_Regpedido(i).vlsaldodisponivelcli
           WHERE numpedrca        = gvet_regpedido(i).numpedrca
           and   cgccli           = gvet_regpedido(i).cgccli
           and   codusur          = gvet_regpedido(i).codusur
           and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm;

          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            ROLLBACK;
        END;


        -- Gravar log de processamento de pedidos
        BEGIN
          INSERT INTO pclogfv
            (arquivo, codcli, DATA, motivo, numped, numpedcli, numpedrca, status)
          VALUES
            ('PCPEDCFV/PCPEDIFV',
             gvet_regpedido(i).codcli,
             SYSDATE,
             SUBSTR(vsobservacaopedcab, 1, 100),
             gvet_regpedido(i).numped,
             gvet_regpedido(i).numpedcli,
             gvet_regpedido(i).numpedrca,
             gvet_regpedido(i).posicao);

          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            ROLLBACK;
        END;

        FOR cr_pedcorp IN (SELECT pcpedifv.codprod,nvl(pcpedifv.codauxiliar,pcprodut.codauxiliar) codauxiliar,pcpedifv.qt
                                 ,pcpedifv.numseq as numseqifv -- DDMEDICA-198
                                 ,pcpedifv.numseqitempedmed -- DDMEDICA-198
                             FROM pcpedifv, pcprodut
                            WHERE numpedrca         = gvet_regpedido(i).numpedrca
                            AND   cgccli            = gvet_regpedido(i).cgccli
                            AND   codusur           = gvet_regpedido(i).codusur
                            and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm
                            and   pcpedifv.codprod = pcprodut.codprod(+)) LOOP

          -- recupera critica do item
          vncontlog           := gvetregistralog.COUNT;
          vsobservacaopedcorp := '';

          FOR j IN 1 .. vncontlog LOOP
            vncodmotanaoatenditem := null;
            IF (gvetregistralog(j).tiporeg = 3) AND
               ((gvetregistralog(j).numped    = gvet_regpedido(i).numped) OR
               (gvetregistralog(j).numped     IS NULL)) AND
               (gvetregistralog(j).numpedrca  = gvet_regpedido(i).numpedrca) AND
               (gvetregistralog(j).cgcent     = gvet_regpedido(i).cgccli) AND
               (gvetregistralog(j).codusur    = gvet_regpedido(i).codusur) AND
               (gvetregistralog(j).data       = gvet_regpedido(i).dtaberturapedpalm)  AND
               (gvetregistralog(j).codprod    = cr_pedcorp.codprod) AND
               (gvetregistralog(j).codauxiliar is null or gvetregistralog(j).codauxiliar = cr_pedcorp.codauxiliar) AND
               (gvetregistralog(j).numseqifv  = cr_pedcorp.numseqifv) -- DDMEDICA-198 - NUMSEQ DA PCPEDIFV
            THEN
             if length(vsobservacaopedcorp) <= 3000 or vsobservacaopedcorp is null then
              vsobservacaopedcorp := vsobservacaopedcorp ||
                                     replace(replace(gvetregistralog(j).erro, '#', ' '),';',CHR(13));
              end if;
            END IF;
          END LOOP;

          -- DDMEDICA-198 - Se não achar pelo numseqifv, mantém regra anterior
          IF (vsobservacaopedcorp IS NULL) THEN
            IF (NVL(gvet_regpedido(i).existemprodutosrepetidos,'N') <> 'S') THEN -- Somente se não existirem itens repeditos mantém regra anterior
              FOR j IN 1 .. vncontlog LOOP
                vncodmotanaoatenditem := null;
                IF (gvetregistralog(j).tiporeg = 3) AND
                   ((gvetregistralog(j).numped    = gvet_regpedido(i).numped) OR
                   (gvetregistralog(j).numped     IS NULL)) AND
                   (gvetregistralog(j).numpedrca  = gvet_regpedido(i).numpedrca) AND
                   (gvetregistralog(j).cgcent     = gvet_regpedido(i).cgccli) AND
                   (gvetregistralog(j).codusur    = gvet_regpedido(i).codusur) AND
                   (gvetregistralog(j).data       = gvet_regpedido(i).dtaberturapedpalm)  AND
                   (gvetregistralog(j).codprod    = cr_pedcorp.codprod) AND
                   (gvetregistralog(j).codauxiliar is null or gvetregistralog(j).codauxiliar = cr_pedcorp.codauxiliar)
                THEN
                 if length(vsobservacaopedcorp) <= 3000 or vsobservacaopedcorp is null then
                  vsobservacaopedcorp := vsobservacaopedcorp ||
                                         replace(replace(gvetregistralog(j).erro, '#', ' '),';',CHR(13));
                  end if;
                END IF;
              END LOOP;
            END IF;
          END IF;

         if gvet_regpedido(i).tipofv in ('OL','PE') then

          if upper(vsobservacaopedcorp) like '%ESTOQUE%' then
             vncodmotanaoatenditem := 32;
          elsif upper(vsobservacaopedcorp) like '%RCA SEM CREDITO DISPONIVEL%' then
            vncodmotanaoatenditem := 38;
          end if;
         end if;

         vnqtatend := 0;

         if gvet_regpedido(i).orcamento = 'S' then

            SELECT COUNT(*)
            INTO vicontador
            FROM pcorcavendai
           WHERE numorca = gvet_regpedido(i).numped
             AND codprod = cr_pedcorp.codprod
             and (codauxiliar = cr_pedcorp.codauxiliar or codauxiliar is null);



         else

          SELECT COUNT(*)
            INTO vicontador
            FROM pcpedi
           WHERE pcpedi.numped = gvet_regpedido(i).numped
             AND pcpedi.codprod = cr_pedcorp.codprod
             and (pcpedi.codauxiliar = cr_pedcorp.codauxiliar or codauxiliar is null);

          end if;

          IF vicontador > 0
          THEN

           if gvet_regpedido(i).orcamento = 'S' then

            SELECT qt/nvl(qtunitemb,1)
              INTO vnqtatend
              FROM pcorcavendai
             WHERE numorca = gvet_regpedido(i).numped
               AND codprod = cr_pedcorp.codprod
               and (codauxiliar    = cr_pedcorp.codauxiliar or codauxiliar is null)
               and rownum = 1;


            else


            -- DDMEDICA-198 - Pequisa diretamente pelo NUMSEQ da PCPEDI através do valor armazenado na PCPEDIFV
            BEGIN
              SELECT qt/nvl(pcpedi.qtunitemb,1)
                INTO vnqtatend
                FROM pcpedi
               WHERE pcpedi.numped     = gvet_regpedido(i).numped
                 AND pcpedi.codprod    = cr_pedcorp.codprod
                 and (codauxiliar      = cr_pedcorp.codauxiliar or codauxiliar is null)
                 and numseq            = cr_pedcorp.numseqitempedmed -->> NUMSEQ DA PCPEDI
                 and rownum = 1;
             EXCEPTION
               WHEN NO_DATA_FOUND THEN
                 vnqtatend := 0;
             END;
           end if;

          END IF;

          vscorte := 'N';

          if cr_pedcorp.qt > vnqtatend then
             vscorte := 'S';
          end if;

          BEGIN
            UPDATE pcpedifv
               SET observacao_pc          = SUBSTR(vsobservacaopedcorp, 1, 4000),
                   qt_faturada            = vnqtatend,
                   codmotivonaoatend      = nvl(codmotivonaoatend,vncodmotanaoatenditem),
                   corte                  = vscorte
             WHERE numpedrca              = gvet_regpedido(i).numpedrca
               AND cgccli                 = gvet_regpedido(i).cgccli
               and codusur                = gvet_regpedido(i).codusur
               and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
               AND codprod                = cr_pedcorp.codprod
               AND (codauxiliar           = cr_pedcorp.codauxiliar or codauxiliar is null)
               AND numseq                 = cr_pedcorp.numseqifv; -- DDMEDICA-198 - NUMSEQ DA PCPEDIFV
            -- DDMEDICA-198
            IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
              UPDATE pcpedifv
                 SET observacao_pc          = SUBSTR(vsobservacaopedcorp, 1, 4000),
                     qt_faturada            = vnqtatend,
                     codmotivonaoatend      = nvl(codmotivonaoatend,vncodmotanaoatenditem),
                     corte                  = vscorte
               WHERE numpedrca              = gvet_regpedido(i).numpedrca
                 AND cgccli                 = gvet_regpedido(i).cgccli
                 and codusur                = gvet_regpedido(i).codusur
                 and dtaberturapedpalm      = gvet_Regpedido(i).dtaberturapedpalm
                 AND codprod                = cr_pedcorp.codprod
                 AND (codauxiliar           = cr_pedcorp.codauxiliar or codauxiliar is null);
            END IF;

            COMMIT;
          EXCEPTION
            WHEN OTHERS THEN
              ROLLBACK;
          END;
        END LOOP;
      END IF;
    END LOOP;

    -- Retorna pedidos nao gravados
    vncontped := gvet_regpedido.COUNT;

      FOR i IN 1 .. vncontped LOOP

      IF gvet_regpedido(i).valido = FALSE
      THEN
        -- recupera critica do cabecalho.
        vncontlog          := gvetregistralog.COUNT;
        vsobservacaopedcab := '';

        FOR j IN 1 .. vncontlog LOOP
          IF (gvetregistralog(j).tiporeg = 2) AND
             ((gvetregistralog(j).numped = gvet_regpedido(i).numped) OR
             (gvetregistralog(j).numped IS NULL)) AND
             (gvetregistralog(j).numpedrca  = gvet_regpedido(i).numpedrca) AND
             (gvetregistralog(j).cgcent     = gvet_regpedido(i).cgccli) AND
             (gvetregistralog(j).codusur    = gvet_regpedido(i).codusur) AND
             (gvetregistralog(j).data       = gvet_regpedido(i).dtaberturapedpalm)

          THEN

            if length(vsobservacaopedcab) <= 3000 or vsobservacaopedcab is null then
              -- Não Duplicar Críticas - DDMEDICA-6533
              BEGIN
                if (NVL(INSTR(vsobservacaopedcab, 
                              replace(replace(gvetregistralog(j).erro, '#', ' '),';',CHR(13))),0) = 0) THEN 
                  vsobservacaopedcab := vsobservacaopedcab ||
                                        replace(replace(gvetregistralog(j).erro, '#', ' '),';',CHR(13));
                end if;
              EXCEPTION
                WHEN OTHERS THEN
                  vsobservacaopedcab := vsobservacaopedcab ||
                                        replace(replace(gvetregistralog(j).erro, '#', ' '),';',CHR(13));
              END;                                        
            end if;
          END IF;
        END LOOP;



        BEGIN

          -- 2438.022821.2017 - Tratamento para não colocar como Rejeitado para não afetar os retornos (Somente ignorar a importação)
          IF (NVL(gvet_regpedido(i).pedidoJaExistente,'N') = 'S') THEN

            --- atualiza cabecalho do pedido.
            IF (NVL(gvet_regpedido(i).tipofv,'FV') IN ('OL','PE')) THEN
              UPDATE pcpedcfv
                 SET observacao_pc    = substr(observacao_pc || '; Importação Ignorada: ' || gvet_regpedido(i).msgPedidoJaExistente, 1, 4000)
                   , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
               WHERE numpedrca        = gvet_regpedido(i).numpedrca
               and   cgccli           = gvet_regpedido(i).cgccli
               and   codusur          = gvet_regpedido(i).codusur
               and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm;
            ELSE
              -- MED-2567 - Força de Vendas manter a Validação Anterior de importado = 3
              UPDATE pcpedcfv
                 SET observacao_pc    = substr(observacao_pc || '; Importação Ignorada: ' || gvet_regpedido(i).msgPedidoJaExistente, 1, 4000),
                     importado        = 3
                   , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
               WHERE numpedrca        = gvet_regpedido(i).numpedrca
               and   cgccli           = gvet_regpedido(i).cgccli
               and   codusur          = gvet_regpedido(i).codusur
               and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm;
            END IF;

          ELSE

            --- atualiza cabecalho do pedido.
            IF (NVL(gvet_regpedido(i).errolockestoque,'N') = 'S') THEN
              UPDATE pcpedcfv
                 SET importado        = 9, -->> Lock de Estoque, indicador para processar novamente na Rotina 2302
                     retorno          = 2,
                     numped           = NULL,
                     observacao_pc    = substr(vsobservacaopedcab, 1, 4000),
                     posicao_atual    = 'R'
                   , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
               WHERE numpedrca        = gvet_regpedido(i).numpedrca
               and   cgccli           = gvet_regpedido(i).cgccli
               and   codusur          = gvet_regpedido(i).codusur
               and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm;
            ELSE
              UPDATE pcpedcfv
                 SET importado        = 3,
                     retorno          = 2,
                     numped           = NULL,
                     observacao_pc    = substr(vsobservacaopedcab, 1, 4000),
                     posicao_atual     = 'R',
                     codmotivonaoatend = NVL(codmotivonaoatend,nvl(gvet_regpedido(i).codmotivonaoatend,34)) -- DDMEDICA-1835 - Garantir que um pedido rejeitado fique pelo menos com motivo não atingiu valor mínimo
                   , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
               WHERE numpedrca        = gvet_regpedido(i).numpedrca
               and   cgccli           = gvet_regpedido(i).cgccli
               and   codusur          = gvet_regpedido(i).codusur
               and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm;
            END IF;

          END IF;

          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            ROLLBACK;
        END;

        -- Gravar log de processamento de pedidos
        BEGIN
          INSERT INTO pclogfv
            (arquivo, codcli, DATA, motivo, numped, numpedcli, numpedrca, status)
          VALUES
            ('PCPEDCFV/PCPEDIFV',
             gvet_regpedido(i).codcli,
             SYSDATE,
             SUBSTR(vsobservacaopedcab, 1, 100),
             gvet_regpedido(i).numped,
             gvet_regpedido(i).numpedcli,
             gvet_regpedido(i).numpedrca,
             'R');

          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            ROLLBACK;
        END;


        BEGIN
          --- atualiza tabela de retorno do pedido.
          UPDATE pcpedretorno
             --SET numped           = NULL, -- MED-1600
             SET numped           = (SELECT PCPEDC.NUMPED FROM PCPEDC WHERE PCPEDC.NUMPEDRCA = gvet_regpedido(i).numpedrca AND PCPEDC.DTABERTURAPEDPALM = gvet_regpedido(i).dtaberturapedpalm AND ROWNUM = 1), -- DDMEDICA-380 - Não pode matar a referencia do número do pedido que existe na PCPEDC, soemnte se não achar poderá ficar NULL
                 vllimitecredcli  = gvet_Regpedido(i).vlsaldodisponivelcli
           WHERE numpedrca        = gvet_regpedido(i).numpedrca
           and   cgccli           = gvet_regpedido(i).cgccli
           and   codusur          = gvet_regpedido(i).codusur
           and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm;

          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            ROLLBACK;
        END;


        FOR cr_pedcorp IN (SELECT pcpedifv.codprod,nvl(pcpedifv.codauxiliar,pcprodut.codauxiliar) codauxiliar,pcpedifv.qt
                                 ,pcpedifv.numseq as numseqifv -- DDMEDICA-198
                                 ,pcpedifv.numseqitempedmed -- DDMEDICA-198
                             FROM pcpedifv,pcprodut
                            WHERE numpedrca   = gvet_regpedido(i).numpedrca AND
                                  cgccli      = gvet_regpedido(i).cgccli    AND
                                  codusur     = gvet_regpedido(i).codusur   AND
                                  dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm AND
                                  pcpedifv.codprod = pcprodut.codprod(+)) LOOP

          -- recupera critica do item
          vncontlog           := gvetregistralog.COUNT;
          vsobservacaopedcorp := '';

          vncodmotanaoatenditem := null;

          -- 1º Laço - Busca o Produto x Ean
          FOR j IN 1 .. vncontlog LOOP

            IF (gvetregistralog(j).tiporeg = 3) AND
               ((gvetregistralog(j).numped     = gvet_regpedido(i).numped) OR
               (gvetregistralog(j).numped IS NULL)) AND
               (gvetregistralog(j).numpedrca   = gvet_regpedido(i).numpedrca) AND
               (gvetregistralog(j).cgcent      = gvet_regpedido(i).cgccli) AND
               (gvetregistralog(j).codusur     = gvet_regpedido(i).codusur) AND
               (gvetregistralog(j).data        = gvet_regpedido(i).dtaberturapedpalm) AND
               (gvetregistralog(j).codprod     = cr_pedcorp.codprod) AND
               (gvetregistralog(j).codauxiliar = cr_pedcorp.codauxiliar or gvetregistralog(j).codauxiliar is null) AND
               (gvetregistralog(j).numseqifv   = cr_pedcorp.numseqifv) -- DDMEDICA-198 - NUMSEQ DA PCPEDIFV
            THEN

             if length(vsobservacaopedcorp) <= 3000 or vsobservacaopedcorp is null then

              vsobservacaopedcorp := vsobservacaopedcorp ||
                                     replace(replace(gvetregistralog(j).erro, '#', ' '),';',CHR(13));
              end if;
            END IF;
          END LOOP;

          -- 2º Laço - Busca somente o Produto
          -- (por exemplo se o Ean recebido no Pedido divergir do Ean do Produto não casa no Laço acima)
          IF (vsobservacaopedcorp IS NULl) THEN
            FOR j IN 1 .. vncontlog LOOP

              IF (gvetregistralog(j).tiporeg = 3) AND
                 ((gvetregistralog(j).numped     = gvet_regpedido(i).numped) OR
                 (gvetregistralog(j).numped IS NULL)) AND
                 (gvetregistralog(j).numpedrca   = gvet_regpedido(i).numpedrca) AND
                 (gvetregistralog(j).cgcent      = gvet_regpedido(i).cgccli) AND
                 (gvetregistralog(j).codusur     = gvet_regpedido(i).codusur) AND
                 (gvetregistralog(j).data        = gvet_regpedido(i).dtaberturapedpalm) AND
                 (gvetregistralog(j).codprod     = cr_pedcorp.codprod) AND
                 (gvetregistralog(j).codprod     > 0) AND -->> Aqui somente se o Produto existir no Winthor
                 (gvetregistralog(j).numseqifv   = cr_pedcorp.numseqifv) -- DDMEDICA-198 - NUMSEQ DA PCPEDIFV
              THEN

               if length(vsobservacaopedcorp) <= 3000 or vsobservacaopedcorp is null then

                vsobservacaopedcorp := vsobservacaopedcorp ||
                                       replace(replace(gvetregistralog(j).erro, '#', ' '),';',CHR(13));
                end if;
              END IF;
            END LOOP;
          END IF;

          -- 3º Laço - Busca sem o numseqifv -- DDMEDICA-198
          -- DDMEDICA-198 - Se não achar pelo numseqifv, mantém regra anterior
          IF (vsobservacaopedcorp IS NULl) THEN
            IF (NVL(gvet_regpedido(i).existemprodutosrepetidos,'N') <> 'S') THEN -- Somente se não existirem itens repeditos mantém regra anterior
              FOR j IN 1 .. vncontlog LOOP
                IF (gvetregistralog(j).tiporeg = 3) AND
                   ((gvetregistralog(j).numped     = gvet_regpedido(i).numped) OR
                   (gvetregistralog(j).numped IS NULL)) AND
                   (gvetregistralog(j).numpedrca   = gvet_regpedido(i).numpedrca) AND
                   (gvetregistralog(j).cgcent      = gvet_regpedido(i).cgccli) AND
                   (gvetregistralog(j).codusur     = gvet_regpedido(i).codusur) AND
                   (gvetregistralog(j).data        = gvet_regpedido(i).dtaberturapedpalm) AND
                   (gvetregistralog(j).codprod     = cr_pedcorp.codprod) AND
                   (gvetregistralog(j).codauxiliar = cr_pedcorp.codauxiliar or gvetregistralog(j).codauxiliar is null)
                  THEN
                   if length(vsobservacaopedcorp) <= 3000 or vsobservacaopedcorp is null then
                    vsobservacaopedcorp := vsobservacaopedcorp ||
                                           replace(replace(gvetregistralog(j).erro, '#', ' '),';',CHR(13));
                   end if;
                  END IF;
              END LOOP;
            END IF;
          END IF;

        if gvet_regpedido(i).tipofv in ('OL','PE') then

          if upper(vsobservacaopedcorp) like '%ESTOQUE%' then
             vncodmotanaoatenditem := 32;
          elsif upper(vsobservacaopedcorp) like '%RCA SEM CREDITO DISPONIVEL%' then
            vncodmotanaoatenditem := 38;

          end if;
       end if;

          -- DDMEDICA-198 - Aqui está num laço de pedidos não gravados, esta inicialização evita lixo do laço anterior de pedidos gravados
          vnqtatend := 0;

          vscorte := 'N';

          if cr_pedcorp.qt > vnqtatend then
             vscorte := 'S';
          end if;


          BEGIN
            UPDATE pcpedifv
               SET observacao_pc    = SUBSTR(vsobservacaopedcorp, 1, 4000),
                   codmotivonaoatend = nvl(codmotivonaoatend,vncodmotanaoatenditem),
                   corte             = vscorte
            WHERE numpedrca         = gvet_regpedido(i).numpedrca
            and   cgccli            = gvet_regpedido(i).cgccli
            and   codusur           = gvet_regpedido(i).codusur
            and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm
            AND   codprod           = cr_pedcorp.codprod
            and   (codauxiliar      = cr_pedcorp.codauxiliar or codauxiliar is null)
            AND   numseq            = cr_pedcorp.numseqifv; -- DDMEDICA-198 - NUMSEQ DA PCPEDIFV
            -- DDMEDICA-198
            IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
              UPDATE pcpedifv
                 SET observacao_pc    = SUBSTR(vsobservacaopedcorp, 1, 4000),
                     codmotivonaoatend = nvl(codmotivonaoatend,vncodmotanaoatenditem),
                     corte             = vscorte
              WHERE numpedrca         = gvet_regpedido(i).numpedrca
              and   cgccli            = gvet_regpedido(i).cgccli
              and   codusur           = gvet_regpedido(i).codusur
              and   dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm
              AND   codprod           = cr_pedcorp.codprod
              and   (codauxiliar      = cr_pedcorp.codauxiliar or codauxiliar is null);
            END IF;

            COMMIT;
          EXCEPTION
            WHEN OTHERS THEN
              ROLLBACK;
          END;
        END LOOP;
      END IF;
    END LOOP;

    -- HIS.03536.2016 - Atualização da Observação do COMBO
    vncontlog := gvet_regcombo.COUNT;
    FOR i IN 1 .. vncontlog LOOP
      IF (gvet_regcombo(i).observacao_pc IS NOT NULL) THEN
        BEGIN
          --- atualiza combo
          UPDATE pcpedcombopromocaomedfv
             SET observacao_pc    = SUBSTR(replace(replace(gvet_regcombo(i).observacao_pc, '#', ' '),';',CHR(13)),
                                           1,
                                           4000)
           WHERE numpedrca         = gvet_regcombo(i).numpedrca
           and   cgccli            = gvet_regcombo(i).cgccli
           and   codusur           = gvet_regcombo(i).codusur
           and   dtaberturapedpalm = gvet_regcombo(i).dtaberturapedpalm
           and   codpromocaomed    = gvet_regcombo(i).codpromocaomed;

          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            ROLLBACK;
        END;
      END IF;
    END LOOP;


    ---------------------------------------------------------------------------
    -- 4954.149614.2017 - Atualiza o Corte dos Pedidos FV que foram Processados
    ---------------------------------------------------------------------------
    vncontped := gvet_regpedido.COUNT;
    FOR i IN 1 .. vncontped LOOP
      IF (gvet_regpedido(i).origemped = 'F')                        AND
         (NVL(gvet_regpedido(i).origemped,'FV') NOT IN ('OL','PE')) AND
         (gvet_regpedido(i).numped > 0)                             THEN

        -- Laço de Itens do Pedido FV
        FOR cr_pedcorp IN (SELECT numpedrca
                                , codusur
                                , cgccli
                                , dtaberturapedpalm
                                , codprod
                                , numseq as numseqifv -- DDMEDICA-198
                                , pvenda
                                , codpromocaomed
                                , numseqitempedmed -- DDMEDICA-198
                             FROM pcpedifv
                            WHERE (numpedrca         = gvet_regpedido(i).numpedrca)
                              AND (cgccli            = gvet_regpedido(i).cgccli)
                              AND (codusur           = gvet_regpedido(i).codusur)
                              AND (dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm)) LOOP

          -- DDMEDICA-19 - Pesquisa diretamente pelo NUMSEQ da PCPEDI armazenado na tabela PCPEDIFV
          BEGIN
            SELECT 'N'
              INTO vscorte
              FROM PCPEDI
             WHERE (PCPEDI.NUMPED  = gvet_regpedido(i).numped)
               AND (PCPEDI.CODPROD = cr_pedcorp.codprod)
               AND (PCPEDI.NUMSEQ  = cr_pedcorp.numseqitempedmed)
               AND (ROWNUM         = 1); -- DDMEDICA-198
          EXCEPTION
            WHEN NO_DATA_FOUND THEN
               vscorte := 'S';
          END;

          IF (vscorte IN ('S','N')) THEN

            BEGIN
              UPDATE pcpedifv
                 SET corte = vscorte
               WHERE numpedrca         = gvet_regpedido(i).numpedrca
                 and cgccli            = gvet_regpedido(i).cgccli
                 and codusur           = gvet_regpedido(i).codusur
                 and dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm
                 and codprod           = cr_pedcorp.codprod
                 and numseq            = cr_pedcorp.numseqifv; -- DDMEDICA-198 - NUMSEQ DA PCPEDIFV
              -- DDMEDICA-198
              IF (NVL(SQL%ROWCOUNT,0) = 0) THEN
                UPDATE pcpedifv
                   SET corte = vscorte
                 WHERE numpedrca         = gvet_regpedido(i).numpedrca
                   and cgccli            = gvet_regpedido(i).cgccli
                   and codusur           = gvet_regpedido(i).codusur
                   and dtaberturapedpalm = gvet_regpedido(i).dtaberturapedpalm
                   and codprod           = cr_pedcorp.codprod;
              END IF;
              COMMIT;
            EXCEPTION
              WHEN OTHERS THEN
                ROLLBACK;
            END;

          END IF; -- Fim: (vscorte IN ('S','N'))

        END LOOP;

      END IF;
    END LOOP;


    -- Retorna pedidos rejeitados durante a leitura
    vncontlog := gvetregistralog.COUNT;

    FOR i IN 1 .. vncontlog LOOP
      IF (gvetregistralog(i).tiporeg = 2) AND (gvetregistralog(i).linhareg IS NOT NULL)
      THEN
        BEGIN
          --- atualiza cabecalho do pedido.
          IF (NVL(gvet_regpedido(i).errolockestoque,'S') = 'S') THEN
            UPDATE pcpedcfv
               SET importado        = 9, -->> Lock de Estoque, indicador para processar novamente na Rotina 2302
                   retorno          = 2,
                   numped           = NULL,
                   observacao_pc    = SUBSTR(replace(replace(gvetregistralog(i).erro, '#', ' '),';',CHR(13)),
                                             1,
                                             4000),
                   posicao_Atual    = 'R'
                 , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
             WHERE numpedrca         = gvetregistralog(i).numpedrca
             and   cgccli            = gvetregistralog(i).cgcent
             and   codusur           = gvetregistralog(i).codusur
             and   dtaberturapedpalm = gvetregistralog(i).data;
          ELSE
            UPDATE pcpedcfv
               SET importado        = 3,
                   retorno          = 2,
                   numped           = NULL,
                   observacao_pc    = SUBSTR(replace(replace(gvetregistralog(i).erro, '#', ' '),';',CHR(13)),
                                             1,
                                             4000),
                   posicao_Atual    = 'R'
                 , VERSAOPKG = CASE WHEN VERSAOPKG IS NULL THEN vvVersionamentoPkg ELSE VERSAOPKG END
             WHERE numpedrca         = gvetregistralog(i).numpedrca
             and   cgccli            = gvetregistralog(i).cgcent
             and   codusur           = gvetregistralog(i).codusur
             and   dtaberturapedpalm = gvetregistralog(i).data;
          END IF;

          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            ROLLBACK;
        END;

        -- Gravar log de processamento de pedidos
        BEGIN
          INSERT INTO pclogfv
            (arquivo, codcli, DATA, motivo, numped, numpedcli, numpedrca, status)
          VALUES
            ('PCPEDCFV/PCPEDIFV',
             null,
             SYSDATE,
             SUBSTR(replace(replace(gvetregistralog(i).erro, '#', ' '),';',CHR(13)), 1, 100),
             gvetregistralog(i).numped,
             null,
             gvetregistralog(i).numpedrca,
             'N');

          COMMIT;
        EXCEPTION
          WHEN OTHERS THEN
            ROLLBACK;
        END;
      END IF;
    END LOOP;

   enviarmensagensrca;

  EXCEPTION
    WHEN OTHERS THEN
      NULL;
  END proc_processaretornotab;


  PROCEDURE importarpedido(p_tipoleitura IN NUMBER DEFAULT 1,
                           p_tipofv      IN VARCHAR2 DEFAULT 'FV' ,
                           p_datainicial IN DATE DEFAULT TRUNC(SYSDATE),
                           p_datafinal   IN DATE DEFAULT TRUNC(SYSDATE),
                           p_numpedrca   IN NUMBER default null ,
                           p_codusur     IN NUMBER default null,
                           p_codfilial   IN VARCHAR2 DEFAULT '99' ) IS

    vbexisterro     boolean;
    vddatafinal     date;
    vddatainicial   date;
    vscodfilial     pcfilial.codigo%type;





  begin
    -- Remove todos os elementos das tabelas.
    gvetregistralog.delete;
    gvet_regpedido.delete;
    gvet_regitem.delete;
    gvet_regitenscesta.delete;
    gvet_regprodconvestoque.delete;
    gvet_regorigemcomiss.delete;
    gvet_regorigemdesc.delete;

    vscodfilial := nvl(p_codfilial,'99');

    vngcontador := 0;

    vngtipoleitura := p_tipoleitura;
    vsgtipofv      := nvl(p_tipofv,'FV');

    vbexisterro := false;

     -- leitura dos parametros do sistema (PCCONSUM).
    if not vbexisterro then
      proc_lerparametros(vbexisterro);
    end if;

    -- leitura dos pedidos
    if not vbexisterro
    then
      -- leitura de tabelas contendo os pedidos.
      proc_processarleitura(vbexisterro
                           ,p_tipoleitura
                           ,vsgtipofv
                           ,p_datainicial
                           ,p_datafinal
                           ,vscodfilial
                           ,p_codusur
                           ,p_numpedrca);
    end if;

    if not vbexisterro then
      -- processamento dos pedidos.
      proc_processarpedidos(vbexisterro);
    end if;

  /*
  if p_tipofv = 'FV' then

    if not vbexisterro then
      -- processamento das notas.
            importarprontaentrega.importarpedido(p_tipoleitura,
                                           p_datainicial,
                                           p_datafinal);

    end if;


   if not vbexisterro then
      -- processamento das notas.
      importarindenizacoes.importarpedido(p_tipoleitura,
                                           p_datainicial,
                                           p_datafinal,
                                           null ,--p_codfilial,
                                           null,--p_tiporeg,
                                           null --p_codusur
                                           );
    end if;


  end if;
  */

    -- processamento do retorno.
    proc_processaretornotab(vbexisterro);
    -- Remove todos os elementos das tabelas.
    gvetregistralog.delete;
    gvet_regpedido.delete;
    gvet_regitem.delete;
    gvetregistralog.delete;
    gvet_regitenscesta.delete;
    gvet_regprodconvestoque.delete;
    gvet_regorigemcomiss.delete;
    gvet_regorigemdesc.delete;


    -- Deixo a Importação dos Cadastros para o Final
    if p_tipoleitura = 1
    then
      vddatainicial := TRUNC(sysdate) - 365;
      vddatafinal   := TRUNC(sysdate);
    else
      vddatainicial := p_datainicial;
      vddatafinal   := p_datafinal;
    end if;

    if nvl(p_tipofv,'FV') NOT IN ('OL','PE') then
    --if p_tipofv = 'FV' then
      if not vbexisterro then
        BEGIN
          -- processamento de cadastros
          importarcadastros.importar(p_tipoleitura,p_datainicial,p_datafinal);
        EXCEPTION
          WHEN OTHERS THEN
            NULL;
        END;
      end if;
    end if;


  end importarpedido;

  -- DDMEDICA-585 - Chamada Especial para Importar Pedido da Rotina 2302
  PROCEDURE importarpedidos2302(p_tipoleitura IN NUMBER,
                                p_tipofv      IN VARCHAR2,
                                p_integradora IN NUMBER,
                                p_datainicial IN DATE DEFAULT TRUNC(SYSDATE),
                                p_datafinal   IN DATE DEFAULT TRUNC(SYSDATE)) IS
    vbexisterro     boolean;
    vddatafinal     date;
    vddatainicial   date;
    vscodfilial     pcfilial.codigo%type;

  begin

    -- Remove todos os elementos das tabelas.
    gvetregistralog.delete;
    gvet_regpedido.delete;
    gvet_regitem.delete;
    gvet_regitenscesta.delete;
    gvet_regprodconvestoque.delete;
    gvet_regorigemcomiss.delete;
    gvet_regorigemdesc.delete;

    vscodfilial := '99';

    vngcontador := 0;

    vngtipoleitura := p_tipoleitura;
    vsgtipofv      := nvl(p_tipofv,'FV');

    vbexisterro := false;

     -- leitura dos parametros do sistema (PCCONSUM).
    if not vbexisterro then
      proc_lerparametros(vbexisterro);
    end if;

    -- leitura dos pedidos
    if not vbexisterro
    then
      -- leitura de tabelas contendo os pedidos.
      proc_processarleitura(vbexisterro
                           ,p_tipoleitura
                           ,vsgtipofv
                           ,p_datainicial
                           ,p_datafinal
                           ,vscodfilial
                           ,NULL -- codusur
                           ,NULL -- numpedrca
                           ,p_integradora);
    end if;

    if p_tipoleitura = 1
    then
      vddatainicial := TRUNC(sysdate) - 365;
      vddatafinal   := TRUNC(sysdate);
    else
      vddatainicial := p_datainicial;
      vddatafinal   := p_datafinal;
    end if;

    if not vbexisterro then
      -- processamento dos pedidos.
      proc_processarpedidos(vbexisterro);
    end if;

    -- processamento do retorno.
    proc_processaretornotab(vbexisterro);
    -- Remove todos os elementos das tabelas.
    gvetregistralog.delete;
    gvet_regpedido.delete;
    gvet_regitem.delete;
    gvetregistralog.delete;
    gvet_regitenscesta.delete;
    gvet_regprodconvestoque.delete;
